AI_ANALYSIS_INTERVAL   = 5.0
AI_FEATURE_DIM         = 14           # stable content-agnostic features (reduced from 20)
AI_HIDDEN_DIM          = 7
ANOMALY_WARN_THRESHOLD  = 3.2          # z-score → WARN (raised to reduce music/speech false positives)
ANOMALY_ALERT_THRESHOLD = 5.5          # z-score → ALERT
AI_CONFIRM_WINDOWS      = 3            # consecutive high-z windows required before alerting
MIN_TRAINING_SAMPLES    = 60
AI_FEEDBACK_BIAS_STEP   = 0.35         # σ rise per confirmed false-alarm label (temporary, until retrain)
AI_FEEDBACK_MAX_BIAS    = 5.0          # maximum per-stream threshold shift (σ)
AI_CLEAN_BUFFER_MAX     = 8000         # max clean feature vectors kept for retraining
AI_CLEAN_BUFFER_FLUSH   = 250          # flush clean buffer to disk every N new samples
AI_RETRAIN_FEEDBACK_N   = 5            # retrain after this many new false-alarm labels
AI_RETRAIN_MIN_SAMPLES  = 500          # minimum clean samples before retraining is allowed
AI_INITIAL_SAMPLES_MAX  = 200_000      # cap on persisted 24h initial samples (~11 MB/stream)

# ─── RTP / comparison / report constants ─────────────────────────────────────

RTP_LOSS_WARN_PCT       = 0.5           # % packet loss → warn
RTP_LOSS_ALERT_PCT      = 2.0           # % packet loss → alert
COMPARE_SEARCH_SECS     = 12.0          # cross-correlation search window (s)
COMPARE_INTERVAL        = 10.0          # how often to re-align (s)
COMPARE_SILENCE_THRESH  = -55.0         # dBFS below which stream counts as silent

# ─── Hub / multi-site constants ───────────────────────────────────────────────

HUB_HEARTBEAT_INTERVAL  = 5.0           # seconds between client→hub pushes
HUB_SITE_TIMEOUT        = 30.0          # seconds before a site is marked offline
HUB_PORT                = 5001          # hub dashboard port
HUB_API_VERSION         = "v1"
HUB_TIMESTAMP_TOLERANCE = 30    # max age (s) of a signed request
HUB_RATE_LIMIT_RPM      = 60    # max heartbeats per minute per site key
# Semaphore that caps concurrent clip uploads from one client to the hub.
# Kept at 1 (serial) — simultaneous WAV→MP3 compression is CPU-heavy and
# can spike load enough to cause RTP packet loss, which triggers more chain
# faults and creates a cascade.  Clips are small and upload quickly in
# sequence; the extra few seconds of latency is preferable to a storm.
_clip_upload_sem        = threading.Semaphore(1)   # serial — one at a time

# Per-position stagger added to clip save delays when a chain fires.
# Spreads the save+compress burst across multiple seconds instead of hitting
# all nodes simultaneously.  Pos 0 → no extra wait; pos 1 → +1.5 s; etc.
_CLIP_SAVE_STAGGER      = 1.5   # seconds per chain position

