if getattr(sys, "frozen", False):
    BASE_DIR = os.path.dirname(sys.executable)
else:
    BASE_DIR = os.path.dirname(os.path.abspath(__file__))

CONFIG_PATH = os.path.join(BASE_DIR, "lwai_config.json")
MODELS_DIR  = os.path.join(BASE_DIR, "ai_models")
STATIC_DIR  = os.path.join(BASE_DIR, "static")
LOGO_FILE   = "signalscope_logo.png"
ICON_FILE   = "signalscope_icon.png"
ICON_PNG    = "signalscope_icon.png"
os.makedirs(MODELS_DIR, exist_ok=True)

# ─── Config models ────────────────────────────────────────────────────────────

@dataclass
class InputConfig:
    name: str
    device_index: str

    enabled: bool = True
    alert_on_silence: bool = True
    alert_on_hiss:    bool = True
    alert_on_clip:    bool = True
    ai_monitor:       bool = True

    silence_threshold_dbfs: float = -55.0
    silence_min_duration:   float = 3.0
    hiss_hf_band_hz:        float = 6000.0
    hiss_rise_db:           float = 12.0
    hiss_min_duration:      float = 3.0
    clip_threshold_dbfs:    float = -1.0
    clip_window_seconds:    float = 2.0
    clip_count_threshold:   int   = 3
    alert_wav_duration:     float = 10.0
    cascade_parent:          Optional[str] = None
    cascade_suppress_alerts: bool          = False
    compare_peer:            Optional[str] = None
    compare_role:            str           = ""
    compare_gain_alert_db:   float         = 3.0   # alert if gain drifts more than this from baseline
    nowplaying_station_id:   str           = ""   # Planet Radio station rpuid

    # EBU R128 / loudness alerting
    alert_on_lufs_tp:         bool  = False
    lufs_tp_threshold:        float = -1.0       # dBTP — true peak alert threshold
    alert_on_lufs_integrated: bool  = False
    lufs_target:              float = -23.0      # target integrated loudness (LUFS, EBU R128)
    lufs_tolerance_db:        float = 3.0        # alert if I-LUFS deviates more than this (LU)
    escalation_minutes:       int   = 0          # re-notify for unacked alerts after N minutes (0 = off)

    # Audio flatness / static detection
    flatness_detect:          bool  = False      # enable flatness detection
    flatness_min_range_db:    float = 2.0        # level must vary by at least this much (dB)
    flatness_min_seconds:     int   = 300        # must persist this long before firing alert

    # Short drop / glitch detection
    glitch_detect:                bool  = False   # enable glitch detection
    glitch_drop_db:               float = 18.0   # drop must be this many dB below rolling mean
    glitch_max_seconds:           float = 4.0    # drop lasting longer counts as silence, not glitch
    glitch_alert_count:           int   = 3      # N glitches in window triggers first alert
    glitch_alert_window_min:      int   = 5      # sliding window for first alert (minutes)
    # Sustained glitching — fires a louder alert when hammering continues
    glitch_sustained_count:       int   = 10     # N glitches in sustained window triggers escalation
    glitch_sustained_window_min:  int   = 10     # sustained window length (minutes)
    # Fade vs glitch discrimination: require a minimum approach rate, measured
    # over the 0.5–3 s window before the threshold crossing.
    # Song fades: 2–10 dBFS/s.  Real glitches (packet loss, STL): 40–200+ dBFS/s.
    # 0 = disabled (count all dips regardless of slope).
    glitch_min_drop_rate_dbfs_s:  float = 22.0  # minimum dBFS/s fall rate to count as a glitch (onset AND recovery)
    glitch_floor_db:              float = 15.0   # dip must reach within this many dB of silence threshold (0=disabled)
    glitch_pre_trend_db:          float = 4.0    # reject if level already fell this many dB in 2-5 s before onset (0=disabled)

    # Expected identity — alert when actual name differs or changes
    expected_fm_rds_ps:   str = ""   # expected RDS Programme Service name; blank = alert on any change
    expected_dab_service: str = ""   # expected DAB service name; blank = alert on any change

    # RTP tracking (runtime)
    _rtp_last_seq:      int   = field(default=-1,   init=False, repr=False)
    _rtp_total:         int   = field(default=0,    init=False, repr=False)
    _rtp_lost:          int   = field(default=0,    init=False, repr=False)
    _rtp_loss_pct:      float = field(default=0.0,  init=False, repr=False)
    _rtp_loss_window:   int   = field(default=0,    init=False, repr=False)
    _rtp_total_window:  int   = field(default=0,    init=False, repr=False)
    _rtp_jitter_ms:     float = field(default=0.0,  init=False, repr=False)  # running jitter estimate (ms)
    _rtp_jitter_acc:    float = field(default=0.0,  init=False, repr=False)  # EWMA of inter-arrival time
    _rtp_last_arrival:  float = field(default=0.0,  init=False, repr=False)  # monotonic time of last packet
    # DAB status (populated for dab:// sources)
    _dab_snr:           float = field(default=0.0,  init=False, repr=False)
    _dab_sig:           float = field(default=0.0,  init=False, repr=False)
    _dab_ensemble:      str   = field(default="",   init=False, repr=False)
    _dab_service:       str   = field(default="",   init=False, repr=False)
    _dab_ok:            bool  = field(default=False, init=False, repr=False)
    _dab_mode:          str   = field(default="",   init=False, repr=False)  # "DAB" or "DAB+"
    _dab_bitrate:       int   = field(default=0,    init=False, repr=False)  # kbps
    _dab_stereo:        bool  = field(default=False, init=False, repr=False)
    _dab_dls:           str   = field(default="",   init=False, repr=False)  # Dynamic Label (now playing)
    # FM status (populated for fm:// sources)
    _fm_freq_mhz:       float = field(default=0.0,  init=False, repr=False)
    _fm_signal_dbm:     float = field(default=-120.0, init=False, repr=False)
