# ─── Helpers ──────────────────────────────────────────────────────────────────

def dbfs(rms: float) -> float:
    return 20.0 * math.log10(max(float(rms), 1e-10))

# ─── EBU R128 / ITU-R BS.1770 K-weighting filter (48 kHz) ────────────────────
# Stage 1: pre-filter (high-shelf, +4 dB @ ~2 kHz)
_KW_B1 = np.array([1.53512485958697, -2.69169618940638, 1.19839281085285])
_KW_A1 = np.array([1.0, -1.69065929318241, 0.73248077421585])
# Stage 2: RLB weighting filter (high-pass)
_KW_B2 = np.array([1.0, -2.0, 1.0])
_KW_A2 = np.array([1.0, -1.99004745483398, 0.99007225036919])
_LUFS_GATE_ABS = -70.0   # absolute gating threshold (LUFS)
_LUFS_S_BLOCKS  = 6      # 6 × 0.5 s chunks = 3 s short-term window
_LUFS_I_BLOCKS  = 60     # 60 × 0.5 s = 30 s rolling integrated window

def _kweight(data: np.ndarray, zi1, zi2):
    """Apply BS.1770 K-weighting two-stage biquad filter, preserving state."""
    try:
        from scipy.signal import lfilter, lfilter_zi
        if zi1 is None: zi1 = lfilter_zi(_KW_B1, _KW_A1)
        if zi2 is None: zi2 = lfilter_zi(_KW_B2, _KW_A2)
        y1, zf1 = lfilter(_KW_B1, _KW_A1, data.astype(np.float64), zi=zi1)
        y2, zf2 = lfilter(_KW_B2, _KW_A2, y1, zi=zi2)
        return y2, zf1, zf2
    except Exception:
        return data.astype(np.float64), zi1, zi2

def _ms_to_lufs(ms: float) -> float:
    """Convert mean-square power of K-weighted signal to LUFS."""
    return -0.691 + 10.0 * math.log10(max(ms, 1e-12))

def _true_peak_dbtp(data: np.ndarray) -> float:
    """Estimate true peak dBTP via 4× oversampling (BS.1770-4)."""
    try:
        from scipy.signal import resample_poly
        up = resample_poly(data.astype(np.float64), 4, 1)
        return 20.0 * math.log10(max(float(np.max(np.abs(up))), 1e-12))
    except Exception:
        return 20.0 * math.log10(max(float(np.max(np.abs(data))), 1e-12))

# Registry mapping raw stream/site names to their safe directory names.
# Prevents different raw names that produce the same stripped string from
# colliding on disk (e.g. "BBC Radio 1" and "BBC.Radio.1" → both "BBCRadio1").
_safe_name_registry: dict = {}   # raw_name → safe_name

def _safe_name(name: str) -> str:
    global _safe_name_registry
    # Return cached mapping if this name was already registered
    if name in _safe_name_registry:
        return _safe_name_registry[name]
    base = "".join(c for c in name if c.isalnum() or c in "-_").strip() or "stream"
    # Check for collision with an existing registration from a different raw name
    used = set(_safe_name_registry.values())
    candidate = base
    if candidate in used:
        for suffix in range(2, 10):
            candidate = f"{base}_{suffix}"
            if candidate not in used:
                break
    _safe_name_registry[name] = candidate
    return candidate

def _model_path(name: str) -> str:
    return os.path.join(MODELS_DIR, f"{_safe_name(name)}.onnx")

def _stats_path(name: str) -> str:
    return os.path.join(MODELS_DIR, f"{_safe_name(name)}_stats.json")

def _feedback_path(name: str) -> str:
    """Per-stream AI feedback state: threshold bias + feedback counts."""
    return os.path.join(MODELS_DIR, f"{_safe_name(name)}_feedback.json")

def _clean_buffer_path(name: str) -> str:
    """Rolling numpy array of confirmed-clean feature vectors used for retraining."""
    return os.path.join(MODELS_DIR, f"{_safe_name(name)}_clean.npy")

def _initial_samples_path(name: str) -> str:
    """Permanent record of the original 24 h training corpus.
    Written once after the first successful training phase and never overwritten.
    Every future feedback-triggered retrain loads this alongside the clean buffer
    so the model always trains on its full knowledge base, not just recent windows.
    """
    return os.path.join(MODELS_DIR, f"{_safe_name(name)}_initial.npy")

ALERT_LOG_PATH      = os.path.join(BASE_DIR, "alert_log.json")
ALERT_ACKS_PATH     = os.path.join(BASE_DIR, "alert_acks.json")
ALERT_FEEDBACK_PATH = os.path.join(BASE_DIR, "alert_feedback.json")
CHAIN_NOTES_PATH    = os.path.join(BASE_DIR, "chain_notes.json")
_chain_notes_lock   = threading.Lock()
_alert_feedback_lock = threading.Lock()
HUB_STATE_PATH  = os.path.join(BASE_DIR, "hub_state.json")  # persists site data across hub restarts
METRICS_DB_PATH  = os.path.join(BASE_DIR, "metrics_history.db")
HUB_BACKUP_DIR   = os.path.join(BASE_DIR, "hub_backups")   # one sub-dir per site
_alert_log_lock = threading.Lock()
_alert_acks: Dict[str, dict] = {}
_alert_acks_lock = threading.Lock()
# On-demand comparator request tracking — prevents flooding the command queue.
# Key: (site, pre_name, post_name). Value: unix ts of last push.
_cmp_pair_requested: Dict[tuple, float] = {}
_CMP_PAIR_RECHECK_SECS = 300  # re-push if comparator vanishes for 5+ minutes

def _alert_log_append(event: dict):
    """Append one event to the alert log, pruning if over the configured limit."""
    try:
        with _alert_log_lock:
            with open(ALERT_LOG_PATH, "a", encoding="utf-8") as f:
                f.write(json.dumps(event) + "\n")
        # Prune if over limit (read current size without the lock held)
        _alert_log_prune()
    except Exception:
        pass

_alert_log_last_prune = 0.0

def _alert_log_prune():
    """Trim alert_log.json to cfg.alert_log_max lines. Runs at most once per minute."""
    global _alert_log_last_prune
    if time.time() - _alert_log_last_prune < 60:
        return
    try:
        cfg = monitor.app_cfg
        limit = cfg.alert_log_max if cfg.alert_log_max > 0 else 10000
        with _alert_log_lock:
            if not os.path.exists(ALERT_LOG_PATH): return
            with open(ALERT_LOG_PATH, "r", encoding="utf-8") as f:
                lines = f.readlines()
            if len(lines) > limit:
                with open(ALERT_LOG_PATH, "w", encoding="utf-8") as f:
                    f.writelines(lines[-limit:])
        _alert_log_last_prune = time.time()
    except Exception as e:
        print(f"[AlertLog] Prune failed: {e}")

def _alert_log_load(limit: int = 2000) -> List[dict]:
    """Read the last `limit` events from the alert log."""
    if not os.path.exists(ALERT_LOG_PATH):
        return []
    try:
        with _alert_log_lock:
            with open(ALERT_LOG_PATH, "r", encoding="utf-8") as f:
                lines = f.readlines()
        events = []
        for line in lines[-limit:]:
            line = line.strip()
            if line:
                try: events.append(json.loads(line))
                except: pass
        return list(reversed(events))   # newest first
    except Exception:
        return []

def _add_history(cfg: InputConfig, kind: str, msg: str, clip_path: str = ""):
    """Append a rich event record to per-input history and persistent alert log."""
    ptp = monitor.ptp if (monitor and hasattr(monitor, 'ptp')) else None
    event = {
        "id":            str(uuid.uuid4()),
        "ts":            time.strftime("%Y-%m-%d %H:%M:%S"),
        "stream":        cfg.name,
        "type":          kind,
        "message":       msg,
        "level_dbfs":    round(cfg._last_level_dbfs, 1),
        "rtp_loss_pct":  round(cfg._rtp_loss_pct, 2),
        "rtp_jitter_ms": round(cfg._rtp_jitter_ms, 2),
        "clip":          os.path.basename(clip_path) if clip_path else "",
        "ptp_state":     ptp.state       if ptp else "",
        "ptp_offset_us": round(ptp.offset_us, 1)  if ptp else 0,
        "ptp_drift_us":  round(ptp.drift_us,  1)  if ptp else 0,
        "ptp_jitter_us": round(ptp.jitter_us, 1)  if ptp else 0,
        "ptp_gm":        ptp.gm_id       if ptp else "",
        "feedback":      None,   # user label: "normal" (false alarm) | "abnormal" | None
    }
    cfg._history.append(event)
    if len(cfg._history) > 300:
        cfg._history = cfg._history[-300:]
    _alert_log_append(event)


def _load_acks():
    """Load persisted acknowledgements from disk into memory."""
    global _alert_acks
    if not os.path.exists(ALERT_ACKS_PATH):
        return
    try:
        with _alert_acks_lock:
            with open(ALERT_ACKS_PATH, "r", encoding="utf-8") as f:
                _alert_acks = json.load(f)
    except Exception:
        _alert_acks = {}


def _save_ack(alert_id: str, ack_by: str) -> dict:
    """Record an acknowledgement both in memory and on disk."""
    record = {"by": ack_by, "ts": time.strftime("%Y-%m-%d %H:%M:%S")}
    with _alert_acks_lock:
        _alert_acks[alert_id] = record
        snapshot = dict(_alert_acks)
    try:
        with open(ALERT_ACKS_PATH, "w", encoding="utf-8") as f:
            json.dump(snapshot, f)
    except Exception:
        pass
    return record

# ─── Alert feedback helpers ───────────────────────────────────────────────────

def _load_alert_feedback() -> dict:
    """Return dict of alert_id → {feedback, by, ts}."""
    if not os.path.exists(ALERT_FEEDBACK_PATH):
        return {}
    try:
        with _alert_feedback_lock:
            with open(ALERT_FEEDBACK_PATH, "r", encoding="utf-8") as f:
                return json.load(f)
    except Exception:
        return {}


def _save_alert_feedback_map(fb_map: dict):
    """Persist the full feedback map to disk (thread-safe)."""
    with _alert_feedback_lock:
        with open(ALERT_FEEDBACK_PATH, "w", encoding="utf-8") as f:
            json.dump(fb_map, f)


def _load_chain_notes() -> dict:
    """Return the full chain-notes map {fault_log_id: {text, by, ts, edited_at}}."""
    with _chain_notes_lock:
        if not os.path.exists(CHAIN_NOTES_PATH):
            return {}
        try:
            with open(CHAIN_NOTES_PATH, "r", encoding="utf-8") as f:
                return json.load(f)
        except Exception:
            return {}


def _save_chain_note(fault_log_id: str, text: str, by: str = "admin") -> dict:
    """Write or update one note entry; returns the saved record."""
    with _chain_notes_lock:
        try:
            with open(CHAIN_NOTES_PATH, "r", encoding="utf-8") as f:
                notes = json.load(f)
        except Exception:
            notes = {}
        existing = notes.get(fault_log_id)
        now_str = time.strftime("%Y-%m-%d %H:%M:%S")
        if existing:
            existing["text"]      = text
            existing["by"]        = by
            existing["edited_at"] = now_str
            record = existing
        else:
            record = {"text": text, "by": by, "ts": now_str, "edited_at": None}
        notes[fault_log_id] = record
        with open(CHAIN_NOTES_PATH, "w", encoding="utf-8") as f:
            json.dump(notes, f)
        return record


def _alert_log_load_with_feedback(limit: int = 2000) -> List[dict]:
    """Load alert events and merge in any stored user feedback labels."""
    events = _alert_log_load(limit)
    try:
        fb_map = _load_alert_feedback()
        if fb_map:
            for e in events:
                aid = e.get("id", "")
                if aid and aid in fb_map:
                    e["feedback"] = fb_map[aid]["feedback"]
    except Exception:
        pass
    return events


def _apply_feedback_label(alert_id: str, stream: str, feedback: str,
                           by: str = "admin") -> dict:
    """Record a user feedback label and adapt the per-stream AI threshold bias.

    feedback: "normal"   → false alarm, raise threshold so it doesn't repeat
              "abnormal" → confirmed real fault, nudge threshold back down
    Returns the updated per-stream feedback dict.
    """
    # 1. Persist label in alert_feedback.json (keyed by alert UUID)
    fb_map = _load_alert_feedback()
    fb_map[alert_id] = {
        "feedback": feedback,
        "by":       by,
        "ts":       time.strftime("%Y-%m-%d %H:%M:%S"),
    }
    try:
        _save_alert_feedback_map(fb_map)
    except Exception:
        pass

    # 2. Update per-stream AI feedback file
    fp = _feedback_path(stream)
    try:
        with open(fp) as f:
            fb_data = json.load(f)
    except Exception:
        fb_data = {}

    fb_data.setdefault("threshold_bias",              0.0)
    fb_data.setdefault("normal_count",                0)
    fb_data.setdefault("abnormal_count",              0)
    fb_data.setdefault("false_alarms_since_retrain",  0)

    if feedback == "normal":
        fb_data["normal_count"] += 1
        # Each false-alarm label lifts the effective threshold by BIAS_STEP, capped at MAX.
        fb_data["threshold_bias"] = min(
            fb_data["threshold_bias"] + AI_FEEDBACK_BIAS_STEP,
            AI_FEEDBACK_MAX_BIAS,
        )
    elif feedback == "abnormal":
        fb_data["abnormal_count"] += 1
        # Confirmed real fault → small downward nudge (never below 0).
        fb_data["threshold_bias"] = max(fb_data["threshold_bias"] - 0.10, 0.0)

    # 3. For false-alarm labels: extract feature vectors from the clip audio,
    #    add them to the clean buffer so the retrain gets this audio as "normal".
    #    Also count false alarms since the last retrain and trigger one when
    #    AI_RETRAIN_FEEDBACK_N threshold is reached.
    if feedback == "normal" and monitor:
        fb_data.setdefault("false_alarms_since_retrain", 0)
        fb_data["false_alarms_since_retrain"] += 1
        # Locate the clip for this alert (keyed on stream/alert_id via snippet dir)
        _snip_dir = os.path.join(BASE_DIR, "alert_snippets", _safe_name(stream))
        _clip_feats: List[np.ndarray] = []
        try:
            if os.path.isdir(_snip_dir):
                # All wav files sorted by mtime — we pick the most recent as a
                # best-effort match (the alert just fired, so its clip is newest)
                _wavs = sorted(
                    [w for w in os.listdir(_snip_dir) if w.endswith(".wav")],
                    key=lambda n: os.path.getmtime(os.path.join(_snip_dir, n))
                )
                if _wavs:
                    import wave as _wave, array as _array
                    _wpath = os.path.join(_snip_dir, _wavs[-1])
                    with _wave.open(_wpath, "rb") as _wf:
                        _frames = _wf.readframes(_wf.getnframes())
                        _ch = _wf.getnchannels(); _sw = _wf.getsampwidth()
                    _fmt  = {1: "b", 2: "h", 4: "i"}.get(_sw, "h")
                    _raw  = _array.array(_fmt, _frames)
                    _aud  = np.array(_raw, dtype=np.float32) / (2 ** (_sw * 8 - 1))
                    if _ch > 1: _aud = _aud[::_ch]
                    # Chop clip into 0.5 s windows (same as live inference windows)
                    _wsz = int(SAMPLE_RATE * 0.5)
                    for _i in range(0, len(_aud) - _wsz + 1, _wsz):
                        _clip_feats.append(extract_features(_aud[_i:_i + _wsz]))
        except Exception:
            pass

        # Append the labeled clip's feature windows directly to the on-disk
        # clean buffer so the next retrain treats this audio as normal.
        if _clip_feats:
            _cbp = _clean_buffer_path(stream)
            try:
                _existing = np.load(_cbp) if os.path.exists(_cbp) else np.empty(
                    (0, AI_FEATURE_DIM), dtype=np.float32)
                _combined = np.vstack([_existing,
                                       np.array(_clip_feats, dtype=np.float32)])
                # Trim to max buffer size
                if len(_combined) > AI_CLEAN_BUFFER_MAX:
                    _combined = _combined[-AI_CLEAN_BUFFER_MAX:]
                np.save(_cbp, _combined)
                # Also inject into the live in-memory clean buf
                for _inp in (monitor.app_cfg.inputs if monitor else []):
                    if _inp.name == stream:
                        if not hasattr(_inp, '_ai_clean_buf'): _inp._ai_clean_buf = []
                        _inp._ai_clean_buf.extend(_clip_feats)
                        if len(_inp._ai_clean_buf) > AI_CLEAN_BUFFER_MAX:
                            _inp._ai_clean_buf = _inp._ai_clean_buf[-AI_CLEAN_BUFFER_MAX:]
                        break
            except Exception:
                pass

        # Check if we have enough material to actually retrain the model
        _cbp = _clean_buffer_path(stream)
        _n_clean = 0
        try:
            if os.path.exists(_cbp):
                _n_clean = np.load(_cbp).shape[0]
        except Exception:
            pass
        # Also check in-memory buffer
        if monitor:
            for _inp in monitor.app_cfg.inputs:
                if _inp.name == stream:
                    _n_clean = max(_n_clean, len(getattr(_inp, '_ai_clean_buf', [])))
                    break

        _should_retrain = (
            fb_data["false_alarms_since_retrain"] >= AI_RETRAIN_FEEDBACK_N
            and _n_clean >= AI_RETRAIN_MIN_SAMPLES
        )
        if _should_retrain:
            # Gather the full clean sample set (prefer in-memory, fall back to disk)
            _all_clean: Optional[np.ndarray] = None
            if monitor:
                for _inp in monitor.app_cfg.inputs:
                    if _inp.name == stream and hasattr(_inp, '_ai_clean_buf') and _inp._ai_clean_buf:
                        _all_clean = np.array(_inp._ai_clean_buf, dtype=np.float32)
                        break
            if _all_clean is None or len(_all_clean) < AI_RETRAIN_MIN_SAMPLES:
                try:
                    if os.path.exists(_cbp):
                        _all_clean = np.load(_cbp)
                except Exception:
                    pass
            if _all_clean is not None and len(_all_clean) >= AI_RETRAIN_MIN_SAMPLES:
                threading.Thread(
                    target=_retrain_model,
                    args=(stream, _all_clean),
                    daemon=True,
                    name=f"AIRetrain-{stream}",
                ).start()

    # 4. Persist updated per-stream feedback state
    try:
        os.makedirs(MODELS_DIR, exist_ok=True)
        with open(fp, "w") as f:
            json.dump(fb_data, f)
    except Exception:
        pass

    # 5. Update in-memory InputConfig immediately so next window uses new bias
    if monitor:
        for _inp in monitor.app_cfg.inputs:
            if _inp.name == stream:
                _inp._ai_threshold_bias = fb_data["threshold_bias"]
                break

    return fb_data


# ─── Auth helpers ─────────────────────────────────────────────────────────────

def _safe_next() -> str:
    """Return the next= redirect target only if it is a safe relative path.
    Prevents open redirect attacks via crafted login URLs.
    """
    from urllib.parse import urlparse
    target = request.args.get("next", "")
    if not target:
        return url_for("index")
    parsed = urlparse(target)
    # Reject anything with a scheme or netloc — must be relative path only
    if parsed.scheme or parsed.netloc:
        _log_security(f"Open redirect attempt blocked: {target!r} from {request.remote_addr}")
        return url_for("index")
    return target


def _hash_password(pw: str) -> str:
    """Hash a password using werkzeug pbkdf2-sha256 (salted, slow, safe)."""
    from werkzeug.security import generate_password_hash
    return generate_password_hash(pw, method="pbkdf2:sha256:260000")


def _check_password(pw: str, hashed: str) -> bool:
    """Verify a password against its hash.
    Handles both new werkzeug pbkdf2 hashes and legacy plain SHA-256 hashes
    so existing users are not locked out on upgrade. Legacy hashes are
    automatically re-hashed with pbkdf2 on next successful login.
    """
    from werkzeug.security import check_password_hash
    # New-style: werkzeug hash (starts with "pbkdf2:" or "scrypt:" etc.)
    if hashed.startswith("pbkdf2:") or hashed.startswith("scrypt:"):
        return check_password_hash(hashed, pw)
    # Legacy: plain SHA-256 hex (64 lowercase hex chars)
    if len(hashed) == 64 and all(c in "0123456789abcdef" for c in hashed):
        return hashlib.sha256(pw.encode()).hexdigest() == hashed
    return False

# ─── CSRF protection ─────────────────────────────────────────────────────────

def _csrf_token() -> str:
    """Generate (or retrieve) a per-session CSRF token."""
    from flask import session
    if "_csrf" not in session:
        session["_csrf"] = hashlib.sha256(os.urandom(32)).hexdigest()
    return session["_csrf"]


def _csrf_valid() -> bool:
    """Check the CSRF token submitted with a POST request."""
    from flask import session, request
    token = session.get("_csrf", "")
    if not token:
        return False
    # Accept token from form field OR X-CSRFToken header (for AJAX)
    submitted = request.form.get("_csrf_token","") or request.headers.get("X-CSRFToken","")
    return _hmac.compare_digest(token, submitted)


def csrf_protect(f):
    """Decorator that validates CSRF token on POST/PUT/DELETE requests."""
    @functools.wraps(f)
    def decorated(*args, **kwargs):
        from flask import session
        cfg = monitor.app_cfg
        # Only enforce when auth is enabled — unauthenticated instances are
        # LAN-only so CSRF is less critical, but still generate tokens
        if request.method in ("POST","PUT","DELETE","PATCH"):
            if not _csrf_valid():
                _log_security(f"CSRF validation failed for {request.path} from {request.remote_addr}")
                return jsonify({"error": "CSRF validation failed"}), 403
        return f(*args, **kwargs)
    return decorated


def login_required(f):
    @functools.wraps(f)
    def decorated(*args, **kwargs):
        from flask import session
        cfg = monitor.app_cfg

        # During first-run setup, allow the setup wizard endpoints to finish
        # even if authentication was enabled part-way through the wizard.
        # This prevents the final POST to /setup/complete from being
        # interrupted by a login redirect before wizard_done is saved.
        if not cfg.wizard_done and (
            request.path == "/setup"
            or request.path == "/setup/complete"
            or request.path.startswith("/api/setup/")
        ):
            return f(*args, **kwargs)

        if not cfg.auth.enabled:
            return f(*args, **kwargs)
        if not session.get("logged_in"):
            return redirect(url_for("login", next=request.path))
        # Session timeout check
        timeout_hrs = cfg.session_timeout_hrs or 12
        login_ts = session.get("login_ts", 0)
        if time.time() - login_ts > timeout_hrs * 3600:
            session.clear()
            flash(f"Session expired after {timeout_hrs}h. Please log in again.")
            return redirect(url_for("login", next=request.path))
        return f(*args, **kwargs)
    return decorated


def admin_required(f):
    """Restrict route to admin-role users only."""
    @functools.wraps(f)
    def decorated(*args, **kwargs):
        cfg = monitor.app_cfg
        if cfg.auth.enabled:
            if not session.get("logged_in"):
                return redirect(url_for("login", next=request.path))
            if _current_user_role() != "admin":
                if request.path.startswith("/api/") or request.is_json:
                    return jsonify({"error": "Administrator access required"}), 403
                flash("Administrator access required.")
                return redirect(url_for("index"))
        return f(*args, **kwargs)
    return decorated


def _rbac_enforce_readonly():
    """Block viewer-role users from all write operations."""
    cfg = monitor.app_cfg
    if not cfg.auth.enabled:
        return None
    if not session.get("logged_in"):
        return None
    if _current_user_role() != "viewer":
        return None
    if request.method not in ("POST", "PUT", "DELETE", "PATCH"):
        return None
    # Viewers may always POST to /logout
    if request.path in ("/logout",):
        return None
    # Block all other writes
    if request.path.startswith("/api/") or request.is_json:
        return jsonify({"error": "Read-only access — contact your administrator"}), 403
    flash("This action requires write access. Your account is view-only.")
    return redirect(request.referrer or url_for("index"))


def _mobile_api_token() -> str:
    try:
        return str(getattr(getattr(monitor.app_cfg, "mobile_api", None), "token", "") or "").strip()
    except Exception:
        return ""


def _mobile_api_enabled() -> bool:
    try:
        return bool(getattr(getattr(monitor.app_cfg, "mobile_api", None), "enabled", False))
    except Exception:
        return False


def _make_mobile_api_token() -> str:
    return uuid.uuid4().hex + uuid.uuid4().hex


def mobile_api_required(f):
    @functools.wraps(f)
    def decorated(*args, **kwargs):
        if not _mobile_api_enabled():
            return jsonify({"ok": False, "error": "mobile api disabled"}), 403

        expected = _mobile_api_token()
        if not expected:
            return jsonify({"ok": False, "error": "mobile api token not configured"}), 403

        supplied = ""
        authz = request.headers.get("Authorization", "").strip()
        if authz.lower().startswith("bearer "):
            supplied = authz[7:].strip()
        if not supplied:
            supplied = request.headers.get("X-API-Key", "").strip()
        if not supplied:
            supplied = request.args.get("token", "").strip()
        if not supplied:
            supplied = request.args.get("api_key", "").strip()

        if not supplied or not _hmac.compare_digest(expected, supplied):
            return jsonify({"ok": False, "error": "unauthorized"}), 401
        return f(*args, **kwargs)
    return decorated


# ── APNs push notifications ───────────────────────────────────────────────────
try:
    import httpx as _httpx
    _HTTPX_HTTP2 = True
except ImportError:
    _httpx = None
    _HTTPX_HTTP2 = False

# Cache the JWT so we don't regenerate it on every push (valid 55 min)
_apns_jwt_cache: dict = {"token": "", "generated_at": 0.0}

# Lock to serialise concurrent token-list mutations across push threads
_apns_tokens_lock = threading.Lock()

# FCM OAuth2 access-token cache (tokens last 60 min; refresh at 55 min)
_fcm_token_cache: dict = {"token": "", "generated_at": 0.0, "cache_key": ""}
_fcm_tokens_lock = threading.Lock()

def _apns_make_jwt(key_id: str, team_id: str, key_pem: str) -> str:
    """Generate an ES256 JWT suitable for APNs provider authentication."""
    import base64, json as _json
    from cryptography.hazmat.primitives import hashes as _ch, serialization as _cs
    from cryptography.hazmat.primitives.asymmetric import ec as _ec
    from cryptography.hazmat.primitives.asymmetric.utils import decode_dss_signature as _dds

    hdr = base64.urlsafe_b64encode(_json.dumps({"alg": "ES256", "kid": key_id}).encode()).rstrip(b"=").decode()
    pay = base64.urlsafe_b64encode(_json.dumps({"iss": team_id, "iat": int(time.time())}).encode()).rstrip(b"=").decode()
    msg = f"{hdr}.{pay}".encode()

    priv = _cs.load_pem_private_key(key_pem.encode(), password=None)
    sig_der = priv.sign(msg, _ec.ECDSA(_ch.SHA256()))
    r, s = _dds(sig_der)
    raw_sig = r.to_bytes(32, "big") + s.to_bytes(32, "big")
    sig = base64.urlsafe_b64encode(raw_sig).rstrip(b"=").decode()
    return f"{hdr}.{pay}.{sig}"


def _get_apns_jwt(ma) -> str:
    """Return a cached JWT, regenerating if older than 55 minutes or if credentials changed."""
    now = time.time()
    cache_key = f"{ma.apns_key_id}:{ma.apns_team_id}"
    if (now - _apns_jwt_cache["generated_at"] > 55 * 60
            or not _apns_jwt_cache["token"]
            or _apns_jwt_cache.get("cache_key") != cache_key):
        _apns_jwt_cache["token"] = _apns_make_jwt(ma.apns_key_id, ma.apns_team_id, ma.apns_key_pem)
        _apns_jwt_cache["generated_at"] = now
        _apns_jwt_cache["cache_key"] = cache_key
    return _apns_jwt_cache["token"]


def _apns_token_str(entry) -> str:
    """Return the raw hex token string regardless of whether entry is a str or dict."""
    return entry if isinstance(entry, str) else entry.get("token", "")


def _apns_token_is_sandbox(entry) -> bool:
    """Return True if this token entry targets the APNs sandbox (development) environment."""
    if isinstance(entry, str):
        # Legacy plain-string tokens — assume sandbox (old behaviour)
        return True
    return bool(entry.get("sandbox", True))


def _send_apns_push(title: str, body: str, data: "dict|None" = None, badge: "int|None" = None):
    """Send an APNs push notification to all registered device tokens.

    Each token entry can be a plain string (legacy, treated as sandbox) or a dict
    ``{"token": "<hex>", "sandbox": bool}``.  Tokens are routed to the correct
    APNs endpoint (sandbox vs production) based on the per-token flag so that both
    Xcode debug builds (sandbox) and TestFlight/App Store builds (production) receive
    notifications.

    Requires ``httpx[http2]`` (``pip install httpx[http2]``) to be installed.
    Silent no-op if APNs is not configured or the library is missing.
    """
    monitor.log(f"[APNs] _send_apns_push called: title='{title}'")
    ma = getattr(monitor.app_cfg, "mobile_api", None)
    if not ma:
        monitor.log("[APNs] Early exit: mobile_api config not found")
        return
    with _apns_tokens_lock:
        tokens = list(getattr(ma, "apns_device_tokens", []))
    if not tokens:
        monitor.log("[APNs] Early exit: no device tokens registered")
        return
    key_id   = getattr(ma, "apns_key_id", "").strip()
    team_id  = getattr(ma, "apns_team_id", "").strip()
    bundle   = getattr(ma, "apns_bundle_id", "").strip()
    key_pem  = getattr(ma, "apns_key_pem", "").strip()
    if not (key_id and team_id and bundle and key_pem):
        monitor.log(f"[APNs] Early exit: incomplete config — key_id={bool(key_id)} team_id={bool(team_id)} bundle={bool(bundle)} key_pem={bool(key_pem)}")
        return
    if not _HTTPX_HTTP2:
        monitor.log("[APNs] httpx[http2] not installed — push notifications unavailable. "
                    "Run: pip install 'httpx[http2]'")
        return
    monitor.log(f"[APNs] Config OK — {len(tokens)} token(s), bundle={bundle}, spawning push thread")

    payload: dict = {"aps": {"alert": {"title": title, "body": body}, "sound": "default"}}
    if badge is not None:
        payload["aps"]["badge"] = badge
    if data:
        payload.update(data)

    jwt_sandbox    = _get_apns_jwt(ma)   # JWT is the same for both environments
    jwt_production = jwt_sandbox

    def _push_thread():
        import json as _json
        to_remove = []
        monitor.log(f"[APNs] Sending push to {len(tokens)} token(s): title='{title}'")
        to_flip = []   # list of (entry, correct_sandbox_bool) — env auto-corrected
        try:
            with _httpx.Client(http2=True, timeout=10.0) as client:
                def _post(host, tok, jwt):
                    return client.post(
                        f"https://{host}/3/device/{tok}",
                        headers={
                            "authorization":   f"bearer {jwt}",
                            "apns-topic":      bundle,
                            "apns-priority":   "10",
                            "apns-push-type":  "alert",
                            "apns-expiration": str(int(time.time()) + 3600),
                            "apns-thread-id":  (data.get("chain_id", "") if data else ""),
                            "content-type":    "application/json",
                        },
                        content=_json.dumps(payload).encode(),
                    )
                for entry in tokens:
                    token = _apns_token_str(entry)
                    if not token:
                        continue
                    is_sb = _apns_token_is_sandbox(entry)
                    host  = ("api.sandbox.push.apple.com" if is_sb else "api.push.apple.com")
                    env   = "sandbox" if is_sb else "production"
                    monitor.log(f"[APNs] → token {token[:12]}… env={env} host={host}")
                    try:
                        resp = _post(host, token, jwt_sandbox)
                        if resp.status_code == 200:
                            monitor.log(f"[APNs] ✔ Delivered to {token[:12]}… ({env})")
                        elif resp.status_code == 410:
                            monitor.log(f"[APNs] Token {token[:12]}… expired/unregistered (410) — removing")
                            to_remove.append(entry)
                        elif resp.status_code == 403:
                            try:
                                reason = resp.json().get("reason", "")
                            except Exception:
                                reason = resp.text[:80]
                            if reason == "BadEnvironmentKeyInToken":
                                # Token is for the opposite environment — flip and retry
                                flip_sb   = not is_sb
                                flip_host = ("api.sandbox.push.apple.com" if flip_sb else "api.push.apple.com")
                                flip_env  = "sandbox" if flip_sb else "production"
                                monitor.log(f"[APNs] BadEnvironmentKeyInToken for {token[:12]}… — retrying as {flip_env}")
                                try:
                                    resp2 = _post(flip_host, token, jwt_sandbox)
                                    if resp2.status_code == 200:
                                        monitor.log(f"[APNs] ✔ Delivered to {token[:12]}… ({flip_env}) — correcting stored environment")
                                        to_flip.append((entry, flip_sb))
                                    elif resp2.status_code == 410:
                                        monitor.log(f"[APNs] Token {token[:12]}… unregistered (410) on retry — removing")
                                        to_remove.append(entry)
                                    else:
                                        try:
                                            r2 = resp2.json().get("reason", "")
                                        except Exception:
                                            r2 = resp2.text[:80]
                                        if r2 == "BadDeviceToken":
                                            # Token failed on both endpoints — it is genuinely dead.
                                            # Remove it so the device re-registers a fresh token on
                                            # next app launch.
                                            monitor.log(f"[APNs] Token {token[:12]}… dead on both endpoints (BadDeviceToken) — removing")
                                            to_remove.append(entry)
                                        else:
                                            monitor.log(f"[APNs] ✘ Retry {resp2.status_code} for {token[:12]}… ({flip_env}): {r2 or resp2.text[:200]}")
                                except Exception as e2:
                                    monitor.log(f"[APNs] Retry error for {token[:12]}…: {e2}")
                            else:
                                monitor.log(f"[APNs] ✘ Push 403 for {token[:12]}… ({env}): {reason or resp.text[:200]}")
                        else:
                            try:
                                _r = resp.json().get("reason", "")
                            except Exception:
                                _r = ""
                            if _r == "BadDeviceToken":
                                monitor.log(f"[APNs] Token {token[:12]}… BadDeviceToken ({resp.status_code}) — removing")
                                to_remove.append(entry)
                            else:
                                monitor.log(f"[APNs] ✘ Push {resp.status_code} for {token[:12]}… ({env}): {resp.text[:200]}")
                    except Exception as e:
                        monitor.log(f"[APNs] Push error for {token[:12]}… ({env}): {e}")
        except Exception as e:
            monitor.log(f"[APNs] HTTP client error: {e}")
        changed = False
        with _apns_tokens_lock:
            if to_remove:
                for entry in to_remove:
                    try:
                        ma.apns_device_tokens.remove(entry)
                        changed = True
                    except ValueError:
                        pass
            if to_flip:
                for entry, correct_sb in to_flip:
                    tok = _apns_token_str(entry)
                    ma.apns_device_tokens = [
                        {"token": tok, "sandbox": correct_sb} if _apns_token_str(e) == tok else e
                        for e in ma.apns_device_tokens
                    ]
                    changed = True
        if changed:
            save_config(monitor.app_cfg)

    threading.Thread(target=_push_thread, daemon=True).start()


def _send_apns_push_targeted(entries: list, title: str, body: str, data: "dict|None" = None):
    """Send an APNs push notification to a specific list of token entries.

    Same as ``_send_apns_push`` but only delivers to the supplied ``entries``
    list rather than every registered token.  Used for per-node silence/down
    alerts that should only go to devices that have subscribed to that node.
    """
    if not entries:
        return
    ma = getattr(monitor.app_cfg, "mobile_api", None)
    if not ma:
        return
    key_id  = getattr(ma, "apns_key_id", "").strip()
    team_id = getattr(ma, "apns_team_id", "").strip()
    bundle  = getattr(ma, "apns_bundle_id", "").strip()
    key_pem = getattr(ma, "apns_key_pem", "").strip()
    if not (key_id and team_id and bundle and key_pem):
        return
    if not _HTTPX_HTTP2:
        return

    payload: dict = {"aps": {"alert": {"title": title, "body": body}, "sound": "default"}}
    if data:
        payload.update(data)

    jwt_token = _get_apns_jwt(ma)
    # Take a snapshot of only the targeted entries
    target_entries = list(entries)

    def _push_thread():
        import json as _json
        try:
            import httpx
            sandbox_host    = "https://api.sandbox.push.apple.com"
            production_host = "https://api.push.apple.com"
            headers_base = {
                "apns-topic":    bundle,
                "apns-push-type": "alert",
                "authorization":  f"bearer {jwt_token}",
            }
            payload_bytes = _json.dumps(payload).encode()
            with httpx.Client(http2=True, timeout=10) as client:
                for entry in target_entries:
                    token = _apns_token_str(entry)
                    is_sb = _apns_token_is_sandbox(entry)
                    host  = sandbox_host if is_sb else production_host
                    env   = "sandbox" if is_sb else "production"
                    url   = f"{host}/3/device/{token}"
                    try:
                        resp = client.post(url, content=payload_bytes, headers=headers_base)
                        if resp.status_code == 200:
                            monitor.log(f"[APNs] ✔ Targeted push to {token[:12]}… ({env}): {title!r}")
                        else:
                            monitor.log(f"[APNs] ✘ Targeted push {resp.status_code} for {token[:12]}… ({env}): {resp.text[:200]}")
                    except Exception as e:
                        monitor.log(f"[APNs] Targeted push error for {token[:12]}…: {e}")
        except Exception as e:
            monitor.log(f"[APNs] Targeted push client error: {e}")

    threading.Thread(target=_push_thread, daemon=True).start()


# ── FCM push (Android) ───────────────────────────────────────────────────────

def _fcm_make_jwt(client_email: str, private_key_pem: str) -> str:
    """Create a signed RS256 JWT for Google OAuth2 token exchange."""
    import json as _json, base64 as _b64, time as _t
    header  = {"alg": "RS256", "typ": "JWT"}
    now     = int(_t.time())
    payload = {
        "iss":   client_email,
        "scope": "https://www.googleapis.com/auth/firebase.messaging",
        "aud":   "https://oauth2.googleapis.com/token",
        "iat":   now,
        "exp":   now + 3600,
    }
    def _b64url(d):
        return _b64.urlsafe_b64encode(
            _json.dumps(d, separators=(",", ":")).encode()
        ).rstrip(b"=").decode()
    unsigned = f"{_b64url(header)}.{_b64url(payload)}".encode()
    from cryptography.hazmat.primitives import serialization as _sl, hashes as _h
    from cryptography.hazmat.primitives.asymmetric import padding as _pad
    key = _sl.load_pem_private_key(private_key_pem.encode(), password=None)
    sig = key.sign(unsigned, _pad.PKCS1v15(), _h.SHA256())
    return f"{unsigned.decode()}.{_b64.urlsafe_b64encode(sig).rstrip(b'=').decode()}"


def _get_fcm_access_token(ma) -> str:
    """Return a cached (55-min) OAuth2 access token for FCM HTTP v1 API."""
    import json as _json, urllib.request as _ur, urllib.parse as _up, time as _t
    sa_json_str = getattr(ma, "fcm_service_account_json", "").strip()
    if not sa_json_str:
        raise ValueError("fcm_service_account_json not configured")
    sa = _json.loads(sa_json_str)
    client_email = sa.get("client_email", "")
    private_key  = sa.get("private_key",  "")
    cache_key = client_email
    now = _t.time()
    if (_fcm_token_cache.get("token")
            and _fcm_token_cache.get("cache_key") == cache_key
            and now - _fcm_token_cache.get("generated_at", 0) < 55 * 60):
        return _fcm_token_cache["token"]
    jwt_str = _fcm_make_jwt(client_email, private_key)
    data = _up.urlencode({
        "grant_type": "urn:ietf:params:oauth:grant-type:jwt-bearer",
        "assertion":  jwt_str,
    }).encode()
    req  = _ur.Request("https://oauth2.googleapis.com/token", data=data, method="POST")
    resp = _ur.urlopen(req, timeout=15)
    tok  = _json.loads(resp.read()).get("access_token", "")
    _fcm_token_cache.update({"token": tok, "generated_at": now, "cache_key": cache_key})
    return tok


def _send_fcm_push(title: str, body: str, data: "dict|None" = None):
    """Send an FCM push to every registered Android device token."""
    ma = getattr(monitor.app_cfg, "mobile_api", None)
    if not ma:
        return
    with _fcm_tokens_lock:
        tokens = list(getattr(ma, "fcm_device_tokens", []))
    if not tokens:
        return
    project_id = getattr(ma, "fcm_project_id", "").strip()
    sa_json    = getattr(ma, "fcm_service_account_json", "").strip()
    if not (project_id and sa_json):
        monitor.log("[FCM] Not configured — skipping push")
        return
    _send_fcm_push_targeted(tokens, title, body, data)


def _send_fcm_push_targeted(entries: list, title: str, body: str, data: "dict|None" = None):
    """Send FCM push to a specific subset of Android device token entries."""
    if not entries:
        return
    ma = getattr(monitor.app_cfg, "mobile_api", None)
    if not ma:
        return
    project_id = getattr(ma, "fcm_project_id", "").strip()
    sa_json    = getattr(ma, "fcm_service_account_json", "").strip()
    if not (project_id and sa_json):
        return
    target_entries = list(entries)

    def _push_thread():
        import json as _json, urllib.request as _ur
        try:
            access_token = _get_fcm_access_token(ma)
        except Exception as e:
            monitor.log(f"[FCM] Failed to get access token: {e}")
            return
        url = f"https://fcm.googleapis.com/v1/projects/{project_id}/messages:send"
        to_remove = []
        for entry in target_entries:
            token = entry.get("token", "") if isinstance(entry, dict) else str(entry)
            if not token:
                continue
            payload = _json.dumps({
                "message": {
                    "token": token,
                    "notification": {"title": title, "body": body},
                    "data": {k: str(v) for k, v in (data or {}).items()},
                    "android": {"priority": "high",
                                "notification": {"channel_id": "faults"}},
                }
            }).encode()
            req = _ur.Request(url, data=payload, method="POST", headers={
                "Authorization": f"Bearer {access_token}",
                "Content-Type":  "application/json",
            })
            try:
                resp = _ur.urlopen(req, timeout=10)
                monitor.log(f"[FCM] ✔ Push to {token[:12]}…: {title!r}")
            except _ur.HTTPError as e:
                err_body = e.read().decode(errors="replace")[:200]
                monitor.log(f"[FCM] ✘ Push {e.code} for {token[:12]}…: {err_body}")
                if e.code in (400, 404):     # UNREGISTERED or INVALID_ARGUMENT
                    to_remove.append(entry)
            except Exception as e:
                monitor.log(f"[FCM] Push error for {token[:12]}…: {e}")
        if to_remove:
            with _fcm_tokens_lock:
                for entry in to_remove:
                    try:
                        ma.fcm_device_tokens.remove(entry)
                    except ValueError:
                        pass
            save_config(monitor.app_cfg)

    threading.Thread(target=_push_thread, daemon=True).start()


# ── Push server relay ─────────────────────────────────────────────────────────

_PUSH_SERVER_API_PATH = "/api/push/v1/send"


def _send_via_push_server(server_url: str, ios_tokens: list, android_tokens: list,
                          title: str, body: str, data: dict):
    """POST alert + device tokens to a remote push server (e.g. hub.signalscope.site).
    The server holds APNs/FCM credentials and does the actual delivery.
    Dead tokens returned in the response are removed from local config.
    """
    if not ios_tokens and not android_tokens:
        return

    def _run():
        import json as _json, urllib.request as _ur
        try:
            payload = _json.dumps({
                "title":           title,
                "body":            body,
                "data":            {k: str(v) for k, v in (data or {}).items()},
                "tokens_ios":      ios_tokens,
                "tokens_android":  android_tokens,
            }).encode()
            url = server_url.rstrip("/") + _PUSH_SERVER_API_PATH
            req = _ur.Request(url, data=payload, method="POST",
                              headers={"Content-Type": "application/json"})
            resp   = _ur.urlopen(req, timeout=15)
            result = _json.loads(resp.read())
            dead   = result.get("dead_tokens", [])
            if dead:
                ma = getattr(monitor.app_cfg, "mobile_api", None)
                if ma:
                    changed = False
                    with _apns_tokens_lock:
                        before = len(ma.apns_device_tokens)
                        ma.apns_device_tokens = [
                            e for e in ma.apns_device_tokens
                            if _apns_token_str(e) not in dead
                        ]
                        if len(ma.apns_device_tokens) < before:
                            changed = True
                    with _fcm_tokens_lock:
                        before = len(ma.fcm_device_tokens)
                        ma.fcm_device_tokens = [
                            e for e in ma.fcm_device_tokens
                            if (e.get("token", "") if isinstance(e, dict) else e) not in dead
                        ]
                        if len(ma.fcm_device_tokens) < before:
                            changed = True
                    if changed:
                        save_config(monitor.app_cfg)
                monitor.log(f"[Push] Cleaned up {len(dead)} dead token(s) from server response")
            monitor.log(f"[Push] ✔ Server delivery: ios={result.get('sent_ios',0)} "
                        f"android={result.get('sent_android',0)}")
        except Exception as exc:
            monitor.log(f"[Push] ✘ Server send error ({server_url}): {exc}")

    threading.Thread(target=_run, daemon=True).start()


def _dispatch_push(title: str, body: str, data: "dict|None" = None,
                   ios_entries: "list|None" = None,
                   android_entries: "list|None" = None):
    """Send a push notification via the configured route.

    If ``push_server_url`` is set on mobile_api config, the notification is
    forwarded to that server (which holds APNs/FCM credentials).  Otherwise
    APNs/FCM are called directly using local credentials.

    ``ios_entries`` / ``android_entries`` are for targeted sends (watched-node
    alerts); pass None to broadcast to all registered tokens.
    """
    ma = getattr(monitor.app_cfg, "mobile_api", None)
    if not ma:
        return
    push_url = getattr(ma, "push_server_url", "").strip()
    if push_url:
        with _apns_tokens_lock:
            ios_toks = list(ios_entries if ios_entries is not None
                            else getattr(ma, "apns_device_tokens", []))
        with _fcm_tokens_lock:
            android_toks = list(android_entries if android_entries is not None
                                else getattr(ma, "fcm_device_tokens", []))
        _send_via_push_server(push_url, ios_toks, android_toks, title, body, data or {})
    else:
        # Direct APNs/FCM using local credentials
        if ios_entries is not None:
            _send_apns_push_targeted(ios_entries, title, body, data)
        else:
            _send_apns_push(title, body, data)
        if android_entries is not None:
            _send_fcm_push_targeted(android_entries, title, body, data)
        else:
            _send_fcm_push(title, body, data)


# ── Per-request CSP nonce ────────────────────────────────────────────────────

def _csp_nonce() -> str:
    """Return (or generate) the CSP nonce for the current request.
    Stored in Flask's request context so it's consistent within one response.
    """
    from flask import g
    if not hasattr(g, "_csp_nonce"):
        g._csp_nonce = base64.b64encode(os.urandom(16)).decode()
    return g._csp_nonce


def _apply_security_headers(response):
    """Add security headers to all HTML responses."""
    cfg = monitor.app_cfg
    response.headers["X-Frame-Options"]        = "SAMEORIGIN"
    response.headers["X-Content-Type-Options"] = "nosniff"
    response.headers["Referrer-Policy"]         = "strict-origin-when-cross-origin"
    # X-XSS-Protection is legacy — CSP is the modern replacement
    # Only set CSP on HTML responses to avoid breaking JSON/audio/binary endpoints
    ct = response.content_type or ""
    if "html" in ct:
        nonce = _csp_nonce()
        csp = (
            "default-src 'self'; "
            f"script-src 'self' 'nonce-{nonce}'; "
            "style-src 'self' 'unsafe-inline'; "
            # unsafe-inline for style= attributes; nonce covers <style nonce="{{csp_nonce()}}"> blocks
            "script-src-attr 'unsafe-inline'; "
            "img-src 'self' data: https://listenapi.planetradio.co.uk; "
            "media-src 'self' blob:; "
            "connect-src 'self'; "
            "font-src 'self'; "
            "frame-ancestors 'self'; "
            "form-action 'self'"
        )
        response.headers["Content-Security-Policy"] = csp
    if cfg.tls_enabled:
        response.headers["Strict-Transport-Security"] = "max-age=31536000; includeSubDomains"
    return response

# ─── Now Playing poller ───────────────────────────────────────────────────────

def _normalize_nowplaying_artwork_url(url: str) -> str:
    url = str(url or "").strip()
    if not url:
        return ""
    if url.startswith("//"):
        return "https:" + url
    if url.startswith("http://"):
        return "https://" + url[len("http://"):]
    return url

def _fetch_nowplaying_artwork_bytes(url: str):
    url = _normalize_nowplaying_artwork_url(url)
    if not url:
        return None, None
    try:
        req = urllib.request.Request(url, headers={"User-Agent": "SignalScope/2.5.37"})
        with urllib.request.urlopen(req, timeout=10) as resp:
            data = resp.read()
            ctype = resp.headers.get_content_type() or "image/jpeg"
        return data, ctype
    except Exception:
        return None, None

class NowPlayingPoller:
    """Polls Planet Radio API every 30s and caches results."""
    INTERVAL = 30.0

    def __init__(self):
        self._stations: List[dict] = []
        self._nowplaying: dict = {}
        self._lock = threading.Lock()
        self._thread: Optional[threading.Thread] = None
        self._stop = threading.Event()
        self._country = "GB"
        self._last_error = ""
        self._last_raw_keys: List[str] = []
        self._last_fetch_at = ""

    def start(self, country="GB"):
        self._country = country
        self._stop.clear()
        self._thread = threading.Thread(target=self._loop, daemon=True, name="NowPlaying")
        self._thread.start()

    def stop(self):
        self._stop.set()

    def get_stations(self) -> List[dict]:
        with self._lock: return list(self._stations)

    def get_nowplaying(self, rpuid: str) -> dict:
        with self._lock: return dict(self._nowplaying.get(rpuid, {}))

    # Known Planet Radio station codes → human readable names
    STATION_NAMES = {
        "abr": "Absolute Radio", "ab7": "Absolute Radio 70s", "ab8": "Absolute Radio 80s (Scotland)",
        "ab9": "Absolute Radio 90s (Scotland)", "ab0": "Absolute Radio 00s (Scotland)",
        "ab1": "Absolute Radio 10s", "ab2": "Absolute Radio 20s",
        "abc": "Absolute Radio Classic Rock", "abk": "Absolute Radio UK",
        "cl1": "Clyde 1", "cay": "Clyde 2", "coo": "Cool FM",
        "cwf": "Country Hits Radio", "dra": "Downtown Radio",
        "dco": "Downtown Country", "fo1": "Forth 1", "fo2": "Forth 2",
        "gh0": "Greatest Hits Radio", "gnw": "Greatest Hits Radio (Network)",
        "g6s": "Greatest Hits Radio 60s", "70s": "Greatest Hits Radio 70s",
        "80s": "Greatest Hits Radio 80s", "ghz": "Greatest Hits Radio (Scotland)",
        "gni": "Greatest Hits Radio (NI)", "ghm": "Greatest Hits Radio (Manchester)",
        "gde": "Greatest Hits Radio (Devon)", "ghg": "Greatest Hits Radio (Glasgow)",
        "ghd": "Greatest Hits Radio (Dundee)", "ghn": "Greatest Hits Radio (Newcastle)",
        "ghp": "Greatest Hits Radio (Plymouth)", "gwd": "Greatest Hits Radio (Wales)",
        "htr": "Heat Radio", "hit": "Hits Radio", "hed": "Hits Radio (Edinburgh)",
        "h90": "Hits Radio 90s", "h00": "Hits Radio 00s", "hch": "Hits Radio Chilled",
        "hi4": "Hits Radio Pride", "hrt": "Hits Radio (Manchester)",
        "hra": "Hits Radio (Aberdeen)", "hrk": "Hits Radio (Kent)",
        "hrb": "Hits Radio Bauer", "hrq": "Hits Radio (Leeds)",
        "jaz": "Jazz FM", "ker": "Kerrang! Radio",
        "ki1": "KISS", "ki2": "KISS Dance", "ki3": "KISS Fresh",
        "ki5": "KISS Extra", "ktb": "KISSTORY",
        "mag": "Magic", "mel": "Magic Mellow", "mso": "Magic Soul",
        "mmu": "Magic at the Movies", "mrs": "Magic Radio Scotland",
        "mf1": "Metro Radio", "no1": "Nation Radio Scotland",
        "pln": "Planet Rock", "ta1": "TFM",
    }

    def _fetch(self):
        url = f"https://listenapi.planetradio.co.uk/api9.2/stations_nowplaying/{self._country}"
        try:
            req = urllib.request.Request(url, headers={"User-Agent": "SignalScope/2.5.37"})
            with urllib.request.urlopen(req, timeout=10) as resp:
                raw_bytes = resp.read()
            data = json.loads(raw_bytes.decode())
            self._last_fetch_at = time.strftime("%H:%M:%S")

            items = data if isinstance(data, list) else data.get("data", data.get("stations", [data]))
            if items:
                self._last_raw_keys = list(items[0].keys()) if isinstance(items[0], dict) else []

            stations = []
            nowplaying = {}
            for s in items:
                if not isinstance(s, dict): continue
                code = str(s.get("stationCode","")).strip()
                if not code: continue
                # Use known name map, fall back to uppercased code
                name = self.STATION_NAMES.get(code, code.upper())
                stations.append({"rpuid": code, "name": name})

                np  = s.get("stationNowPlaying") or {}
                air = s.get("stationOnAir") or {}
                nowplaying[code] = {
                    "artist":  str(np.get("nowPlayingArtist","")).strip(),
                    "title":   str(np.get("nowPlayingTrack","")).strip(),
                    "show":    str(air.get("episodeTitle","")).strip(),
                    "artwork": _normalize_nowplaying_artwork_url(np.get("nowPlayingImage","")),
                }

            with self._lock:
                if stations:
                    self._stations  = sorted(stations, key=lambda x: x["name"])
                    self._nowplaying = nowplaying
                    self._last_error = ""
                else:
                    self._last_error = f"0 stations parsed. Keys: {self._last_raw_keys}"

        except Exception as e:
            self._last_error = f"{type(e).__name__}: {e}"

    def _loop(self):
        self._fetch()
        while not self._stop.wait(self.INTERVAL):
            self._fetch()

nowplaying_poller = NowPlayingPoller()

# ─── SLA tracker ─────────────────────────────────────────────────────────────

SLA_PATH = os.path.join(BASE_DIR, "sla_data.json")

def _sla_load() -> dict:
    try:
        if os.path.exists(SLA_PATH):
            with open(SLA_PATH) as f: return json.load(f)
    except: pass
    return {}

def _sla_save(data: dict):
    try:
        with open(SLA_PATH,"w") as f: json.dump(data, f, indent=2)
    except: pass

def _sla_update(cfg: InputConfig, elapsed_s: float, in_alert: bool):
    """Called every chunk from analyse_chunk to accumulate SLA data."""
    month = time.strftime("%Y-%m")
    if cfg._sla_month != month:
        cfg._sla_month = month
        cfg._sla_monitored_s = 0.0
        cfg._sla_alert_s     = 0.0
        cfg._sla_events      = []
    cfg._sla_monitored_s += elapsed_s
    if in_alert: cfg._sla_alert_s += elapsed_s

def sla_pct(cfg: InputConfig) -> float:
    if cfg._sla_monitored_s < 1.0: return 100.0
    return 100.0 * (1.0 - cfg._sla_alert_s / cfg._sla_monitored_s)
    if len(cfg._history) > 300:
        cfg._history = cfg._history[-300:]

# ─── SQLite metric history ────────────────────────────────────────────────────
#
# metrics_history.db is created automatically on first start — existing installs
# need no manual migration step.  The schema uses CREATE TABLE IF NOT EXISTS so
# it is safe to run against both a fresh file and one already populated.
#
# Retention default: 90 days.  Old rows are pruned once per day from _ai_loop.
#
# Logged metrics (written once per minute per stream):
#   level_dbfs      — audio level (all stream types)
#   lufs_m          — momentary LUFS (all)
#   lufs_s          — short-term LUFS (all)
#   lufs_i          — integrated LUFS (all)
#   fm_signal_dbm   — FM carrier strength (FM streams only)
#   dab_snr         — DAB signal-to-noise ratio (DAB streams only)
#   dab_ok          — DAB service present: 1.0 = up, 0.0 = missing (DAB streams)
#   rtp_loss_pct    — RTP packet loss % (Livewire/AES67 streams only)
#   rtp_jitter_ms   — RTP inter-arrival jitter ms (Livewire/AES67 streams only)

import sqlite3 as _sqlite3

METRICS_RETENTION_DAYS = 90   # rows older than this are pruned

class MetricsDB:
    """Thread-safe SQLite wrapper for time-series metric history."""

    def __init__(self, path: str):
        self._path = path
        self._lock = threading.Lock()
        self._conn: Optional[_sqlite3.Connection] = None
        self._init_db()

    def _connect(self) -> _sqlite3.Connection:
        conn = _sqlite3.connect(self._path, check_same_thread=False, timeout=10)
        conn.execute("PRAGMA journal_mode=WAL")
        conn.execute("PRAGMA synchronous=NORMAL")
        return conn

    def _init_db(self):
        try:
            with self._lock:
                conn = self._connect()
                conn.executescript("""
                    CREATE TABLE IF NOT EXISTS metric_history (
                        stream  TEXT    NOT NULL,
                        metric  TEXT    NOT NULL,
                        ts      REAL    NOT NULL,
                        value   REAL    NOT NULL
                    );
                    CREATE INDEX IF NOT EXISTS idx_mh_lookup
                        ON metric_history(stream, metric, ts);
                    CREATE TABLE IF NOT EXISTS chain_fault_log (
                        id               TEXT PRIMARY KEY,
                        chain_id         TEXT NOT NULL,
                        ts_start         REAL NOT NULL,
                        fault_node_label TEXT,
                        fault_site       TEXT,
                        fault_stream     TEXT,
                        rtp_loss_pct     REAL,
                        ts_recovered     REAL,
                        clips            TEXT
                    );
                    CREATE INDEX IF NOT EXISTS idx_cfl_chain
                        ON chain_fault_log(chain_id, ts_start);
                """)
                conn.execute("""
                    CREATE TABLE IF NOT EXISTS adbreak_history (
                        id       INTEGER PRIMARY KEY AUTOINCREMENT,
                        chain_id TEXT NOT NULL,
                        ts_start REAL NOT NULL,
                        duration REAL NOT NULL,
                        minute_of_day INTEGER NOT NULL
                    )
                """)
                conn.execute("CREATE INDEX IF NOT EXISTS idx_adbreak_chain ON adbreak_history(chain_id, ts_start)")
                conn.commit()
                # Migration: add clips column to chain_fault_log if absent
                # (DBs created before clips support was added won't have it)
                try:
                    conn.execute("ALTER TABLE chain_fault_log ADD COLUMN clips TEXT")
                    conn.commit()
                    print("[MetricsDB] Migrated chain_fault_log: added clips column")
                except _sqlite3.OperationalError:
                    pass  # column already exists — normal path
                # Migration: add adbreak_overshoot column (Change 8)
                try:
                    conn.execute("ALTER TABLE chain_fault_log ADD COLUMN adbreak_overshoot INTEGER DEFAULT 0")
                    conn.commit()
                    print("[MetricsDB] Migrated chain_fault_log: added adbreak_overshoot column")
                except _sqlite3.OperationalError:
                    pass
                # Migration: add cascaded_from column (Change 8 / Change 7)
                try:
                    conn.execute("ALTER TABLE chain_fault_log ADD COLUMN cascaded_from TEXT DEFAULT ''")
                    conn.commit()
                    print("[MetricsDB] Migrated chain_fault_log: added cascaded_from column")
                except _sqlite3.OperationalError:
                    pass
                # Migration: add message column (Change 8)
                try:
                    conn.execute("ALTER TABLE chain_fault_log ADD COLUMN message TEXT DEFAULT ''")
                    conn.commit()
                    print("[MetricsDB] Migrated chain_fault_log: added message column")
                except _sqlite3.OperationalError:
                    pass
                self._conn = conn
        except Exception as e:
            print(f"[MetricsDB] Init error: {e}")

    # ── Chain fault log persistence ───────────────────────────────────────────

    def fault_log_insert(self, entry: dict):
        """Insert a new chain fault log entry. entry must have an 'id' field."""
        try:
            with self._lock:
                if self._conn is None:
                    self._conn = self._connect()
                self._conn.execute(
                    "INSERT OR IGNORE INTO chain_fault_log"
                    "(id, chain_id, ts_start, fault_node_label, fault_site,"
                    " fault_stream, rtp_loss_pct, ts_recovered, clips,"
                    " adbreak_overshoot, cascaded_from, message)"
                    " VALUES(?,?,?,?,?,?,?,?,?,?,?,?)",
                    (
                        entry.get("id"),
                        entry.get("chain_id", ""),
                        entry.get("ts_start"),
                        entry.get("fault_node_label"),
                        entry.get("fault_site"),
                        entry.get("fault_stream"),
                        entry.get("rtp_loss_pct"),
                        entry.get("ts_recovered"),
                        json.dumps(entry.get("clips") or []),
                        1 if entry.get("adbreak_overshoot") else 0,
                        entry.get("cascaded_from", ""),
                        entry.get("message", ""),
                    ),
                )
                self._conn.commit()
        except Exception as e:
            print(f"[MetricsDB] fault_log_insert error: {e}")
            self._conn = None

    def fault_log_set_recovered(self, entry_id: str, ts_recovered: float):
        """Mark a fault log entry as recovered."""
        try:
            with self._lock:
                if self._conn is None:
                    self._conn = self._connect()
                self._conn.execute(
                    "UPDATE chain_fault_log SET ts_recovered=? WHERE id=?",
                    (ts_recovered, entry_id),
                )
                self._conn.commit()
        except Exception as e:
            print(f"[MetricsDB] fault_log_set_recovered error: {e}")
            self._conn = None

    def fault_log_update_clips(self, entry_id: str, clips: list):
        """Overwrite the clips JSON for a fault log entry."""
        try:
            with self._lock:
                if self._conn is None:
                    self._conn = self._connect()
                self._conn.execute(
                    "UPDATE chain_fault_log SET clips=? WHERE id=?",
                    (json.dumps(clips), entry_id),
                )
                self._conn.commit()
        except Exception as e:
            print(f"[MetricsDB] fault_log_update_clips error: {e}")
            self._conn = None

    def fault_log_update_meta(self, entry_id: str, message: str = "", cascaded_from: str = "",
                              adbreak_overshoot: bool = False):
        """Update message, cascaded_from and adbreak_overshoot fields for a fault entry."""
        try:
            with self._lock:
                if self._conn is None:
                    self._conn = self._connect()
                self._conn.execute(
                    "UPDATE chain_fault_log SET message=?, cascaded_from=?, adbreak_overshoot=? WHERE id=?",
                    (message, cascaded_from, 1 if adbreak_overshoot else 0, entry_id),
                )
                self._conn.commit()
        except Exception as e:
            print(f"[MetricsDB] fault_log_update_meta error: {e}")
            self._conn = None

    def adbreak_log(self, chain_id: str, ts_start: float, duration: float) -> None:
        """Record a confirmed ad-break event for learning."""
        import datetime as _dt
        minute_of_day = int(_dt.datetime.fromtimestamp(ts_start).hour * 60
                            + _dt.datetime.fromtimestamp(ts_start).minute)
        try:
            with sqlite3.connect(self._path, timeout=10) as conn:
                conn.execute(
                    "INSERT INTO adbreak_history(chain_id,ts_start,duration,minute_of_day) VALUES(?,?,?,?)",
                    (chain_id, ts_start, duration, minute_of_day)
                )
                # Keep only last 500 breaks per chain
                conn.execute(
                    "DELETE FROM adbreak_history WHERE chain_id=? AND id NOT IN "
                    "(SELECT id FROM adbreak_history WHERE chain_id=? ORDER BY ts_start DESC LIMIT 500)",
                    (chain_id, chain_id)
                )
        except Exception:
            pass

    def adbreak_stats(self, chain_id: str, window_days: int = 60) -> dict:
        """Return {p95: float, common_minutes: list[int], count: int} for a chain.
        common_minutes contains minute_of_day values that appear >= 2 times within
        a +-4-minute window (i.e. recurring break start times)."""
        cutoff = time.time() - window_days * 86400
        try:
            with sqlite3.connect(self._path, timeout=10) as conn:
                rows = conn.execute(
                    "SELECT duration, minute_of_day FROM adbreak_history "
                    "WHERE chain_id=? AND ts_start>? ORDER BY duration",
                    (chain_id, cutoff)
                ).fetchall()
        except Exception:
            return {"p95": 0.0, "common_minutes": [], "count": 0}
        if not rows:
            return {"p95": 0.0, "common_minutes": [], "count": 0}
        durations = [r[0] for r in rows]
        n = len(durations)
        p95_idx = min(int(n * 0.95), n - 1)
        p95 = durations[p95_idx]
        # Find recurring break windows: cluster minute_of_day values
        minutes = [r[1] for r in rows]
        from collections import Counter as _Counter
        freq = _Counter(minutes)
        common = []
        checked = set()
        for m, cnt in freq.most_common():
            if m in checked:
                continue
            # Sum counts within +-4 minutes (wrapping at 1440)
            total = sum(freq.get((m + d) % 1440, 0) for d in range(-4, 5))
            if total >= 2:
                common.append(m)
            for d in range(-4, 5):
                checked.add((m + d) % 1440)
        return {"p95": p95, "common_minutes": common, "count": n}

    def fault_log_load(self, chain_id: str, limit: int = 25) -> list:
        """Return the most recent `limit` fault log entries for a chain, oldest first."""
        try:
            with self._lock:
                if self._conn is None:
                    self._conn = self._connect()
                cur = self._conn.execute(
                    "SELECT id, chain_id, ts_start, fault_node_label, fault_site,"
                    " fault_stream, rtp_loss_pct, ts_recovered, clips,"
                    " adbreak_overshoot, cascaded_from, message"
                    " FROM chain_fault_log WHERE chain_id=?"
                    " ORDER BY ts_start DESC LIMIT ?",
                    (chain_id, limit),
                )
                rows = cur.fetchall()
        except Exception as e:
            print(f"[MetricsDB] fault_log_load error: {e}")
            self._conn = None
            return []
        entries = []
        for r in reversed(rows):   # oldest first so in-memory list matches append order
            try:
                clips = json.loads(r[8]) if r[8] else []
            except Exception:
                clips = []
            entries.append({
                "id":               r[0],
                "chain_id":         r[1],
                "ts_start":         r[2],
                "fault_node_label": r[3] or "?",
                "fault_site":       r[4] or "?",
                "fault_stream":     r[5] or "?",
                "rtp_loss_pct":     r[6],
                "ts_recovered":     r[7],
                "clips":            clips,
                "adbreak_overshoot": bool(r[9]) if len(r) > 9 else False,
                "cascaded_from":    r[10] or "" if len(r) > 10 else "",
                "message":          r[11] or "" if len(r) > 11 else "",
            })
        return entries

    def fault_log_prune(self, days: int = METRICS_RETENTION_DAYS):
        """Delete chain fault log entries older than `days` days."""
        cutoff = time.time() - days * 86400
        try:
            with self._lock:
                if self._conn is None:
                    self._conn = self._connect()
                self._conn.execute(
                    "DELETE FROM chain_fault_log WHERE ts_start<?", (cutoff,)
                )
                self._conn.commit()
        except Exception as e:
            print(f"[MetricsDB] fault_log_prune error: {e}")
            self._conn = None

    def write(self, rows: list):
        """Insert a list of (stream, metric, ts, value) tuples."""
        if not rows:
            return
        try:
            with self._lock:
                if self._conn is None:
                    self._conn = self._connect()
                self._conn.executemany(
                    "INSERT INTO metric_history(stream, metric, ts, value) VALUES(?,?,?,?)",
                    rows
                )
                self._conn.commit()
        except Exception as e:
            print(f"[MetricsDB] Write error: {e}")
            self._conn = None   # force reconnect next time

    def query(self, stream: str, metric: str, hours: float = 24.0) -> list:
        """Return [(ts, value), ...] for the given stream/metric over the last N hours."""
        since = time.time() - hours * 3600
        try:
            with self._lock:
                if self._conn is None:
                    self._conn = self._connect()
                cur = self._conn.execute(
                    "SELECT ts, value FROM metric_history "
                    "WHERE stream=? AND metric=? AND ts>=? ORDER BY ts ASC",
                    (stream, metric, since)
                )
                return cur.fetchall()
        except Exception as e:
            print(f"[MetricsDB] Query error: {e}")
            self._conn = None
            return []

    def available_metrics(self, stream: str) -> list:
        """Return list of metric names that have data for the given stream."""
        try:
            with self._lock:
                if self._conn is None:
                    self._conn = self._connect()
                cur = self._conn.execute(
                    "SELECT DISTINCT metric FROM metric_history WHERE stream=?",
                    (stream,)
                )
                return [r[0] for r in cur.fetchall()]
        except Exception as e:
            print(f"[MetricsDB] available_metrics error: {e}")
            self._conn = None
            return []

    def prune(self, days: int = METRICS_RETENTION_DAYS):
        """Delete rows older than `days` days. Called once per day from _ai_loop."""
        cutoff = time.time() - days * 86400
        try:
            with self._lock:
                if self._conn is None:
                    self._conn = self._connect()
                self._conn.execute(
                    "DELETE FROM metric_history WHERE ts<?", (cutoff,)
                )
                self._conn.execute(
                    "DELETE FROM chain_fault_log WHERE ts_start<?", (cutoff,)
                )
                self._conn.execute("PRAGMA wal_checkpoint(PASSIVE)")
                self._conn.commit()
        except Exception as e:
            print(f"[MetricsDB] Prune error: {e}")
            self._conn = None

    def hourly_baseline(self, stream: str, metric: str, days: int = 14) -> dict:
        """Return {hour: {"mean": float, "std": float, "n": int}} grouped by local hour-of-day.

        Only non-silence values (> -80 dBFS / equivalent) are included so that
        scheduled off-air periods don't skew the baseline downward.
        Uses the computational variance formula (no STDDEV in SQLite built-ins):
            std = sqrt(E[x²] - E[x]²)
        """
        since = time.time() - days * 86400
        try:
            with self._lock:
                if self._conn is None:
                    self._conn = self._connect()
                cur = self._conn.execute(
                    """SELECT
                           CAST(strftime('%H', datetime(ts, 'unixepoch', 'localtime')) AS INTEGER) AS h,
                           AVG(value)                                                               AS mean,
                           AVG(value * value) - AVG(value) * AVG(value)                            AS variance,
                           COUNT(*)                                                                 AS n
                       FROM metric_history
                       WHERE stream=? AND metric=? AND ts>=? AND value>-80
                       GROUP BY h""",
                    (stream, metric, since)
                )
                result = {}
                for h, mean, variance, n in cur.fetchall():
                    std = float(variance ** 0.5) if variance and variance > 0 else 0.0
                    result[int(h)] = {
                        "mean": round(float(mean), 1),
                        "std":  round(std, 2),
                        "n":    int(n),
                    }
                return result
        except Exception as e:
            print(f"[MetricsDB] hourly_baseline error: {e}")
            self._conn = None
            return {}

    def dow_hourly_baseline(self, stream: str, metric: str, days: int = 28) -> dict:
        """Return {(dow, hour): {"mean", "std", "n"}} grouped by (day-of-week, hour).

        Uses 28 days by default so each (dow, hour) cell has ~4 weeks of samples.
        dow: 0=Sunday … 6=Saturday (SQLite strftime('%w')).
        Falls back gracefully — the caller should prefer this over hourly_baseline
        when n >= MIN_SAMPLES, otherwise fall back to hour-only.
        """
        since = time.time() - days * 86400
        try:
            with self._lock:
                if self._conn is None:
                    self._conn = self._connect()
                cur = self._conn.execute(
                    """SELECT
                           CAST(strftime('%w', datetime(ts, 'unixepoch', 'localtime')) AS INTEGER) AS dow,
                           CAST(strftime('%H', datetime(ts, 'unixepoch', 'localtime')) AS INTEGER) AS h,
                           AVG(value)                                                               AS mean,
                           AVG(value * value) - AVG(value) * AVG(value)                            AS variance,
                           COUNT(*)                                                                 AS n
                       FROM metric_history
                       WHERE stream=? AND metric=? AND ts>=? AND value>-80
                       GROUP BY dow, h""",
                    (stream, metric, since)
                )
                result = {}
                for dow, h, mean, variance, n in cur.fetchall():
                    std = float(variance ** 0.5) if variance and variance > 0 else 0.0
                    result[(int(dow), int(h))] = {
                        "mean": round(float(mean), 1),
                        "std":  round(std, 2),
                        "n":    int(n),
                    }
                return result
        except Exception as e:
            print(f"[MetricsDB] dow_hourly_baseline error: {e}")
            self._conn = None
            return {}

    def recent_values(self, stream: str, metric: str, minutes: int = 30) -> list:
        """Return [(ts, value), ...] for the last `minutes` minutes, newest first.

        Used for sustained-deviation scoring — check whether a deviation has
        been present for an extended period rather than just the latest point.
        """
        since = time.time() - minutes * 60
        try:
            with self._lock:
                if self._conn is None:
                    self._conn = self._connect()
                cur = self._conn.execute(
                    "SELECT ts, value FROM metric_history "
                    "WHERE stream=? AND metric=? AND ts>=? ORDER BY ts DESC",
                    (stream, metric, since)
                )
                return cur.fetchall()
        except Exception as e:
            print(f"[MetricsDB] recent_values error: {e}")
            self._conn = None
            return []

    def last_value(self, stream: str, metric: str) -> "Optional[float]":
        """Return the most recent stored value for stream/metric, or None."""
        try:
            with self._lock:
                if self._conn is None:
                    self._conn = self._connect()
                cur = self._conn.execute(
                    "SELECT value FROM metric_history WHERE stream=? AND metric=? "
                    "ORDER BY ts DESC LIMIT 1",
                    (stream, metric)
                )
                row = cur.fetchone()
                return float(row[0]) if row else None
        except Exception as e:
            print(f"[MetricsDB] last_value error: {e}")
            self._conn = None
            return None

# Module-level singleton — created once, shared across all threads.
metrics_db = MetricsDB(METRICS_DB_PATH)


def _metrics_flush(inputs: list):
    """Snapshot current metric values for all enabled inputs and write to SQLite.

    Called once per minute from _ai_loop.  Only metrics whose values are
    meaningful for the stream type are written (e.g. fm_signal_dbm is only
    written for fm:// streams; dab_snr only for dab:// streams).
    """
    now = time.time()
    rows = []
    for cfg in inputs:
        if not cfg.enabled:
            continue
        name = cfg.name
        dev  = (cfg.device_index or "").lower()

        # Universal metrics — every stream type
        rows.append((name, "level_dbfs",    now, cfg._last_level_dbfs))
        rows.append((name, "lufs_m",        now, cfg._lufs_m))
        rows.append((name, "lufs_s",        now, cfg._lufs_s))
        rows.append((name, "lufs_i",        now, cfg._lufs_i))
        # silence_flag: 1.0 = currently silent (level at or below threshold)
        rows.append((name, "silence_flag",  now, 1.0 if cfg._last_level_dbfs <= cfg.silence_threshold_dbfs else 0.0))
        # clip_count: clipping events per monitoring chunk (reset by monitor loop)
        rows.append((name, "clip_count",    now, float(cfg._clip_count)))
        # glitch_rate: glitch events detected in the last 5 minutes (0 if feature off)
        if cfg.glitch_detect and cfg._glitch_timestamps:
            _g_win_cutoff = now - 300.0
            _g_recent = sum(1 for t in cfg._glitch_timestamps if t >= _g_win_cutoff)
            rows.append((name, "glitch_count", now, float(_g_recent)))
        # flatness_flag: 1.0 if flatness is currently active
        if cfg.flatness_detect:
            rows.append((name, "flatness_flag", now, 1.0 if cfg._flatness_active else 0.0))

        # FM-specific
        if dev.startswith("fm://"):
            rows.append((name, "fm_signal_dbm", now, cfg._fm_signal_dbm))
            rows.append((name, "fm_snr_db",     now, cfg._fm_snr_db))
            rows.append((name, "fm_stereo",     now, 1.0 if cfg._fm_stereo else 0.0))
            rows.append((name, "fm_rds_ok",     now, 1.0 if cfg._fm_rds_ok else 0.0))

        # DAB-specific
        if dev.startswith("dab://"):
            rows.append((name, "dab_snr",     now, cfg._dab_snr))
            rows.append((name, "dab_ok",      now, 1.0 if cfg._dab_ok else 0.0))
            rows.append((name, "dab_sig",     now, cfg._dab_sig))
            rows.append((name, "dab_bitrate", now, float(cfg._dab_bitrate or 0)))

        # Livewire / AES67 / RTP (not FM or DAB or HTTP)
        if not dev.startswith("fm://") and not dev.startswith("dab://") \
                and not dev.startswith("http://") and not dev.startswith("https://"):
            rows.append((name, "rtp_loss_pct",  now, cfg._rtp_loss_pct))
            rows.append((name, "rtp_jitter_ms", now, cfg._rtp_jitter_ms))

    if rows:
        metrics_db.write(rows)


def _make_wav_bytes(audio: np.ndarray) -> bytes:
    pcm = (np.clip(audio.astype(np.float32), -1.0, 1.0) * 32767).astype(np.int16)
    buf = io.BytesIO()
    with wave.open(buf, "wb") as wf:
        wf.setnchannels(1); wf.setsampwidth(2)
        wf.setframerate(SAMPLE_RATE); wf.writeframes(pcm.tobytes())
    return buf.getvalue()

def _safe_label(label: str) -> str:
    """Strip any characters that are not safe in a Windows/Linux filename."""
    return "".join(c if c.isalnum() or c in "-_" else "_" for c in label).strip("_")[:40]

def _clip_cleanup(stream_name: str):
    """Prune old/excess clips for a stream based on config limits.

    Never deletes a clip that has not yet been confirmed uploaded to the hub
    (i.e. no .hub sidecar).  Unconfirmed clips are still pending upload and
    must not be removed — _sync_pending_clips needs them to retry.
    """
    try:
        cfg = monitor.app_cfg
        max_age  = cfg.clip_max_age_days
        max_clip = cfg.clip_max_per_stream
        clip_dir = os.path.join(BASE_DIR, "alert_snippets", _safe_name(stream_name))
        if not os.path.exists(clip_dir): return
        clips = sorted(
            [os.path.join(clip_dir, f) for f in os.listdir(clip_dir)
             if f.endswith(".wav") or f.endswith(".mp3")],
            key=os.path.getmtime
        )
        # Only consider clips that are confirmed on the hub (.hub marker present)
        # Unconfirmed clips are still queued for upload — never delete them here.
        def _confirmed(p):
            stem = os.path.splitext(p)[0]
            return os.path.exists(stem + ".hub")
        confirmed = [p for p in clips if _confirmed(p)]
        # Prune confirmed clips by age
        if max_age > 0:
            cutoff = time.time() - max_age * 86400
            for p in confirmed:
                if os.path.getmtime(p) < cutoff:
                    stem = os.path.splitext(p)[0]
                    for ext in (".wav", ".mp3", ".hub", ".meta"):
                        try: os.remove(stem + ext)
                        except: pass
                else:
                    break
            confirmed = [p for p in confirmed if os.path.exists(p)]
        # Prune confirmed clips by count (keep newest max_clip)
        if max_clip > 0 and len(confirmed) > max_clip:
            for p in confirmed[:len(confirmed) - max_clip]:
                stem = os.path.splitext(p)[0]
                for ext in (".wav", ".mp3", ".hub", ".meta"):
                    try: os.remove(stem + ext)
                    except: pass
    except Exception:
        pass

def _alert_buffer_chunk_count(seconds: float) -> int:
    """Return deque length needed to retain at least `seconds` of chunked audio."""
    try:
        secs = max(1.0, float(seconds))
    except Exception:
        secs = ALERT_BUFFER_SECONDS
    return max(3, int(math.ceil((SAMPLE_RATE * secs) / CHUNK_SIZE)) + 2)


def _ensure_alert_buffer_capacity(cfg: InputConfig, seconds: Optional[float] = None) -> None:
    """Grow/shrink a stream's alert buffer to match the configured clip length."""
    target_secs = seconds if seconds is not None else getattr(cfg, "alert_wav_duration", ALERT_BUFFER_SECONDS)
    maxlen = _alert_buffer_chunk_count(target_secs)
    cur = getattr(cfg, "_audio_buffer", None)
    if cur is None:
        cfg._audio_buffer = collections.deque(maxlen=maxlen)
        return
    if getattr(cur, "maxlen", None) != maxlen:
        cfg._audio_buffer = collections.deque(list(cur)[-maxlen:], maxlen=maxlen)


def _try_encode_mp3(pcm_int16: "np.ndarray") -> "Optional[bytes]":
    """Encode 16-bit signed mono PCM to MP3 bytes.

    Tries lameenc (pure Python, ``pip install lameenc``) first, then falls
    back to spawning ffmpeg.  Returns None if neither encoder is available.
    """
    # --- lameenc ---
    try:
        import lameenc  # type: ignore
        enc = lameenc.Encoder()
        enc.set_bit_rate(96)
        enc.set_in_sample_rate(SAMPLE_RATE)
        enc.set_channels(1)
        enc.set_quality(7)   # 2 = highest quality, 7 = fastest
        return enc.encode(pcm_int16.tobytes()) + enc.flush()
    except ImportError:
        pass
    except Exception as _e:
        print(f"[WARN] lameenc MP3 encode failed: {_e}")
    # --- ffmpeg ---
    try:
        import subprocess as _sp
        result = _sp.run(
            ["ffmpeg", "-y",
             "-f", "s16le", "-ar", str(SAMPLE_RATE), "-ac", "1", "-i", "pipe:0",
             "-codec:a", "libmp3lame", "-q:a", "4", "-f", "mp3", "pipe:1"],
            input=pcm_int16.tobytes(), capture_output=True, timeout=30,
        )
        if result.returncode == 0 and result.stdout:
            return result.stdout
    except FileNotFoundError:
        pass   # ffmpeg not installed
    except Exception as _e:
        print(f"[WARN] ffmpeg MP3 encode failed: {_e}")
    return None


def _save_alert_wav(cfg: InputConfig, label: str, duration: float = 5.0,
                    _skip_hub_queue: bool = False,
                    _chunks: Optional[list] = None) -> Optional[str]:
    """Save an alert audio clip to disk as WAV.

    Local clips are always saved as WAV for maximum compatibility.
    Upload compression (WAV→MP3) is handled automatically by ``_upload_clip_inner``
    when the file exceeds the size threshold.
    Returns the saved file path, or None if the buffer was empty.

    ``_chunks`` — optional pre-captured list of float32 arrays to use instead of
    ``cfg._audio_buffer``.  Pass ``list(cfg._stream_buffer)`` at the moment of
    silence detection to include pre-fault audio so the fault point is audible
    rather than the clip starting mid-silence.
    """
    # Prune old clips before saving a new one
    threading.Thread(target=_clip_cleanup, args=(cfg.name,), daemon=True).start()
    out = os.path.join(BASE_DIR, "alert_snippets", _safe_name(cfg.name))
    os.makedirs(out, exist_ok=True)
    duration = max(1.0, float(duration or getattr(cfg, "alert_wav_duration", ALERT_BUFFER_SECONDS)))
    if _chunks is None:
        _ensure_alert_buffer_capacity(cfg, duration)
        if not cfg._audio_buffer: return None
        chunks = list(cfg._audio_buffer)
    else:
        chunks = _chunks
    if not chunks: return None
    audio = np.concatenate(chunks)[-int(SAMPLE_RATE * duration):]
    safe_lbl    = _safe_label(label)
    safe_stream = _safe_name(cfg.name)
    ts_str      = time.strftime("%Y%m%d-%H%M%S")
    # Format: YYYYMMDD-HHMMSS_StreamName_alerttype
    # Stream name in the filename makes downloaded clips self-identifying without
    # needing to look at the folder they came from.
    base_name = f"{ts_str}_{safe_stream}_{safe_lbl}"
    pcm       = (np.clip(audio, -1.0, 1.0) * 32767).astype(np.int16)

    path = os.path.join(out, f"{base_name}.wav")
    try:
        with wave.open(path, "wb") as wf:
            wf.setnchannels(1); wf.setsampwidth(2)
            wf.setframerate(SAMPLE_RATE); wf.writeframes(pcm.tobytes())
    except Exception as e:
        print(f"[WARN] Could not save alert WAV: {e}")
        return None

    # Auto-queue for hub upload unless the caller (e.g. _cmd_save_clip) will
    # handle the upload itself to avoid sending the same clip twice.
    if not _skip_hub_queue:
        try:
            _hub_cfg = getattr(getattr(monitor, "app_cfg", None), "hub", None)
            if (_hub_cfg and getattr(_hub_cfg, "hub_url", "")
                    and getattr(_hub_cfg, "clip_auto_upload", True)):
                monitor._hub_clip_queue.put_nowait(
                    (cfg.name, label, path, round(cfg._last_level_dbfs, 1)))
        except Exception:
            pass
    return path

# ─── Feature extraction ───────────────────────────────────────────────────────

def extract_features(audio: np.ndarray) -> np.ndarray:
    """Extract 14 content-agnostic features for the autoencoder.

    Key design principle: features must be STABLE across normal content variation
    (music vs speech vs jingles) and only deviate on genuine faults.

    Removed from v1: raw spectral band ratios (sub/lo/mid/hi/air) — these shift
    dramatically between music and speech and cause constant false positives.
    Kept: level, dynamics, DC, clipping, spectral flatness (fault indicator),
    rolloff variance (content-stable shape descriptor), and noise floor estimate.
    """
    n = len(audio)
    if n < 64:
        return np.zeros(AI_FEATURE_DIM, dtype=np.float32)

    rms  = float(np.sqrt(np.mean(audio**2) + 1e-12))
    peak = float(np.max(np.abs(audio)))
    lvl  = float(np.clip((dbfs(rms)  + 80.0) / 80.0, 0.0, 1.0))
    pk   = float(np.clip((dbfs(peak) + 80.0) / 80.0, 0.0, 1.0))
    # Crest factor: high = transient/music, moderate = speech, very high = distortion
    crest = float(np.clip(peak / (rms + 1e-10) / 30.0, 0.0, 1.0))
    dc    = float(np.clip(abs(np.mean(audio)) / 0.05, 0.0, 1.0))   # DC offset (fault)
    clip_frac = float(np.clip(np.mean(np.abs(audio) >= 0.98) / 0.01, 0.0, 1.0))  # clipping

    # Short-term level variance (dropout / intermittent fault detection)
    frame = 480; nf = n // frame
    if nf > 1:
        frames = audio[:nf*frame].reshape(nf, frame)
        frms   = np.sqrt(np.mean(frames**2, axis=1) + 1e-12)
        rms_var  = float(np.clip(np.std(frms) / (np.mean(frms) + 1e-12) / 2.0, 0.0, 1.0))
        # Minimum sub-frame level — detects dropout within a chunk even if average is OK
        min_frm  = float(np.clip((dbfs(float(np.min(frms))) + 80.0) / 80.0, 0.0, 1.0))
    else:
        rms_var = 0.0; min_frm = lvl

    # Spectral features — computed on log-PSD to be more content-agnostic
    win  = np.hanning(n).astype(np.float32)
    X    = np.abs(np.fft.rfft(audio * win))
    freq = np.fft.rfftfreq(n, d=1.0/SAMPLE_RATE)
    psd  = (X**2).astype(np.float64)
    tot  = float(np.sum(psd) + 1e-12)

    # Spectral flatness: near 0 = tonal/sine wave or silence, near 1 = white noise.
    # Genuine faults (tone injection, hiss) push this to extremes. Normal content is stable.
    psd_nz = np.maximum(psd[psd > 0], 1e-20)
    flat   = float(np.clip(
        np.exp(np.mean(np.log(psd_nz))) / (np.mean(psd_nz) + 1e-12), 0.0, 1.0))

    # 85th-percentile rolloff frequency — content type shifts this but it's
    # still useful as a fault indicator when normalised to the stream's own baseline.
    cum     = np.cumsum(psd)
    ri      = np.searchsorted(cum, 0.85 * tot)
    rolloff = float(freq[min(ri, len(freq)-1)]) / 24000.0

    # Noise floor estimate: median of the bottom 10% of spectral bins (fault = elevated)
    low_psd    = np.sort(psd)[:max(1, len(psd)//10)]
    noise_floor= float(np.clip(10.0 * np.log10(np.mean(low_psd) + 1e-20) / -100.0, 0.0, 1.0))

    # Very low frequency energy ratio (hum / mains buzz detector)
    hum = float(np.sum(psd[(freq >= 40) & (freq < 130)]) / tot)
    hum = float(np.clip(hum / 0.3, 0.0, 1.0))

    # High-frequency energy ratio (hiss detector) — normalised so normal HF doesn't trigger
    hf  = float(np.sum(psd[freq >= 10000]) / tot)
    hf  = float(np.clip(hf / 0.5, 0.0, 1.0))

    # Zero-crossing rate — very high = distortion/clipping artefact, very low = silence/DC
    zcr = float(np.mean(np.diff(np.sign(audio)) != 0))

    return np.array([
        lvl, pk, crest, dc, clip_frac,      # [0-4]  level / dynamics / fault indicators
        rms_var, min_frm,                    # [5-6]  short-term stability
        flat, rolloff, noise_floor,          # [7-9]  spectral shape (content-agnostic)
        hum, hf, zcr,                        # [10-12] specific fault signatures
        lvl * (1.0 - flat),                  # [13]   active signal sanity (0 if silence or pure noise)
    ], dtype=np.float32)

# ─── Autoencoder: train (pure numpy Adam) + export as ONNX ────────────────────

def _relu(x): return np.maximum(0.0, x)


def _train_autoencoder(samples: np.ndarray, log_fn):
    N = len(samples)
    log_fn(f"[AI] Training autoencoder on {N} samples…")
    rng = np.random.default_rng(42)
    W1 = rng.normal(0, 0.1, (AI_FEATURE_DIM, AI_HIDDEN_DIM)).astype(np.float32)
    b1 = np.zeros(AI_HIDDEN_DIM, dtype=np.float32)
    W2 = rng.normal(0, 0.1, (AI_HIDDEN_DIM, AI_FEATURE_DIM)).astype(np.float32)
    b2 = np.zeros(AI_FEATURE_DIM, dtype=np.float32)

    lr=1e-3; beta1=0.9; beta2=0.999; eps=1e-8; t=0
    ms = [np.zeros_like(p) for p in (W1,b1,W2,b2)]
    vs = [np.zeros_like(p) for p in (W1,b1,W2,b2)]
    idx = np.arange(N); bsz = min(64, N)

    for ep in range(200):
        rng.shuffle(idx)
        total = 0.0
        for s in range(0, N, bsz):
            batch = samples[idx[s:s+bsz]]; B = len(batch)
            h_pre = batch @ W1 + b1
            h     = _relu(h_pre)
            out   = h @ W2 + b2
            diff  = out - batch
            loss  = float(np.mean(diff**2)); total += loss
            t += 1
            dout = (2.0/(B*AI_FEATURE_DIM)) * diff
            dW2  = h.T @ dout;    db2 = dout.sum(0)
            dh   = dout @ W2.T;   dh_pre = dh * (h_pre > 0).astype(np.float32)
            dW1  = batch.T @ dh_pre; db1 = dh_pre.sum(0)
            for i,(p,g) in enumerate(zip([W1,b1,W2,b2],[dW1,db1,dW2,db2])):
                ms[i] = beta1*ms[i] + (1-beta1)*g
                vs[i] = beta2*vs[i] + (1-beta2)*g**2
                mh = ms[i]/(1-beta1**t); vh = vs[i]/(1-beta2**t)
                p -= lr * mh / (np.sqrt(vh)+eps)
        if ep % 50 == 0:
            log_fn(f"[AI]   epoch {ep:3d}  loss={total:.5f}")

    log_fn("[AI] Training complete.")
    return W1, b1, W2, b2


def _build_onnx(W1, b1, W2, b2) -> bytes:
    """
    Build ONNX model bytes using the onnx library.
    onnxruntime ships with onnx as a dependency so this is always available
    when onnxruntime is installed — including inside a PyInstaller exe.
    """
    from onnx import numpy_helper, TensorProto, helper
    X   = helper.make_tensor_value_info("X",   TensorProto.FLOAT, [1, AI_FEATURE_DIM])
    Out = helper.make_tensor_value_info("Out", TensorProto.FLOAT, [1, AI_FEATURE_DIM])
    def _t(name, arr):
        return numpy_helper.from_array(arr.astype(np.float32), name=name)
    nodes = [
        helper.make_node("MatMul", ["X",     "W1"], ["h_pre"]),
        helper.make_node("Add",    ["h_pre", "b1"], ["h_b"]),
        helper.make_node("Relu",   ["h_b"],         ["h"]),
        helper.make_node("MatMul", ["h",     "W2"], ["o_pre"]),
        helper.make_node("Add",    ["o_pre", "b2"], ["Out"]),
    ]
    graph = helper.make_graph(nodes, "ae", [X], [Out],
                              [_t("W1",W1), _t("b1",b1), _t("W2",W2), _t("b2",b2)])
    model = helper.make_model(graph, opset_imports=[helper.make_opsetid("", 13)])
    model.ir_version = 8
    return model.SerializeToString()


def _infer(sess, feats: np.ndarray) -> np.ndarray:
    return sess.run(None, {"X": feats.reshape(1,-1).astype(np.float32)})[0].reshape(-1)


def _recon_error(sess, feats: np.ndarray) -> float:
    return float(np.mean((feats - _infer(sess, feats))**2))


def _classify(feats: np.ndarray, recon: np.ndarray) -> str:
    """Classify anomaly type from feature deviations.
    Feature indices: [0]lvl [1]pk [2]crest [3]dc [4]clip_frac
                     [5]rms_var [6]min_frm [7]flat [8]rolloff [9]noise_floor
                     [10]hum [11]hf [12]zcr [13]sanity
    """
    diff = np.abs(feats - recon)
    # Hard fault checks first (feature value, not just deviation)
    if feats[6] < 0.05 and feats[0] < 0.15:   return "dropout"
    if feats[0] < 0.05:                         return "silence / very low level"
    if feats[4] > 0.3 or diff[4] > 0.2:        return "clipping / distortion"
    if feats[3] > 0.5 or diff[3] > 0.3:        return "DC offset"
    if feats[10] > 0.6 and diff[10] > 0.2:     return "mains hum"
    if feats[11] > 0.7 and diff[11] > 0.2:     return "hiss / HF noise"
    if diff[5] > 0.3 or diff[6] > 0.3:         return "level instability"
    if diff[9] > 0.25:                          return "elevated noise floor"
    if diff[7] > 0.2:                           return "unusual spectral texture"
    if diff[2] > 0.25:                          return "dynamic range anomaly"
    return "audio characteristic change"       # vague by design — not "anomaly"


def _flush_clean_buffer(stream_name: str, samples: list):
    """Save the rolling clean-sample buffer to disk as a numpy array.
    Called in a daemon thread — never blocks the inference path.
    """
    try:
        arr = np.array(samples[-AI_CLEAN_BUFFER_MAX:], dtype=np.float32)
        np.save(_clean_buffer_path(stream_name), arr)
    except Exception:
        pass


def _retrain_model(stream_name: str, clean_samples: np.ndarray):
    """Retrain the autoencoder on the full knowledge base.

    Training corpus = original 24 h samples (preserved on disk) PLUS the
    updated rolling clean buffer (which now includes labeled false-alarm clips).
    This ensures the model never forgets what it learned during the initial
    24 h phase — feedback only *adds* knowledge, never replaces it.

    Called in a daemon thread after sufficient user feedback has accumulated.
    On success:
      - Overwrites ai_models/<stream>.onnx and <stream>_stats.json with new weights
      - Hot-swaps the live InferenceSession in the running InputConfig
      - Resets the threshold bias to 0 (model now knows this audio is normal)
      - Logs progress through monitor.log if available
    """
    def _log(m):
        if monitor:
            try: monitor.log(m)
            except Exception: print(m)
        else:
            print(m)

    # ── Combine initial 24 h corpus + new clean/labeled samples ───────────────
    _initial_path = _initial_samples_path(stream_name)
    _initial: np.ndarray = np.empty((0, AI_FEATURE_DIM), dtype=np.float32)
    if os.path.exists(_initial_path):
        try:
            _initial = np.load(_initial_path)
            _log(f"[AI:{stream_name}] Loaded {len(_initial)} original training samples from disk")
        except Exception as _e:
            _log(f"[AI:{stream_name}] Warning: could not load initial corpus ({_e}) — "
                 f"retraining on clean buffer only")

    if len(_initial) > 0:
        all_samples = np.vstack([_initial, clean_samples])
    else:
        all_samples = clean_samples

    # Shuffle so the Adam optimiser doesn't see old vs new samples in blocks
    rng = np.random.default_rng()
    rng.shuffle(all_samples)

    _log(f"[AI:{stream_name}] ▶ Retraining on {len(all_samples)} samples total "
         f"({len(_initial)} original + {len(clean_samples)} new clean/labeled)…")
    try:
        W1, b1, W2, b2 = _train_autoencoder(all_samples, _log)
        onnx_bytes = _build_onnx(W1, b1, W2, b2)
        mp = _model_path(stream_name)
        with open(mp, "wb") as f:
            f.write(onnx_bytes)
        ort  = _try_import("onnxruntime")
        sess = ort.InferenceSession(mp)
        # Compute baseline stats from the full combined corpus so the z-score
        # distribution correctly reflects everything the model was trained on.
        errs = [_recon_error(sess, s) for s in all_samples]
        mean_e = float(np.mean(errs))
        std_e  = max(float(np.std(errs)), 1e-6)
        with open(_stats_path(stream_name), "w") as f:
            json.dump({"mean": mean_e, "std": std_e, "n": len(all_samples)}, f)

        # Hot-swap live session and stats
        if monitor:
            for inp in monitor.app_cfg.inputs:
                if inp.name == stream_name:
                    inp._ai_session    = sess
                    inp._ai_error_mean = mean_e
                    inp._ai_error_std  = std_e
                    if hasattr(inp, '_ai_error_var'):
                        inp._ai_error_var = std_e ** 2
                    # Model now knows this audio is normal — threshold bias resets to 0
                    inp._ai_threshold_bias = 0.0
                    inp._ai_status = (f"Retrained ({len(all_samples)} samples) — monitoring"
                                      f" · baseline {mean_e:.5f} ± {std_e:.5f}")
                    break

        # Persist updated feedback state: bias reset, retrain count bumped
        fp = _feedback_path(stream_name)
        try:
            with open(fp) as f: fb = json.load(f)
        except Exception:
            fb = {}
        fb["threshold_bias"]           = 0.0
        fb["false_alarms_since_retrain"] = 0
        fb["last_retrain"]             = time.time()
        fb["retrain_sample_count"]     = len(all_samples)
        fb["retrain_count"]            = fb.get("retrain_count", 0) + 1
        try:
            with open(fp, "w") as f: json.dump(fb, f)
        except Exception:
            pass

        _log(f"[AI:{stream_name}] ✓ Retrain complete. New baseline {mean_e:.5f} ± {std_e:.5f}  "
             f"(retrain #{fb['retrain_count']})")
    except Exception as e:
        _log(f"[AI:{stream_name}] Retrain failed: {e}")


# ─── Per-stream AI lifecycle ──────────────────────────────────────────────────

class StreamAI:
    def __init__(self, cfg: InputConfig, log_fn, sender):
        self.cfg=cfg; self.log=log_fn; self.sender=sender

    def _load(self) -> bool:
        ort = _try_import("onnxruntime")
        if not ort: self.cfg._ai_phase="no_onnx"; self.cfg._ai_status="Install onnxruntime to enable AI"; return False
        mp=_model_path(self.cfg.name); sp=_stats_path(self.cfg.name)
        if not (os.path.exists(mp) and os.path.exists(sp)): return False
        try:
            self.cfg._ai_session = ort.InferenceSession(mp)
            with open(sp) as f: st=json.load(f)
            self.cfg._ai_error_mean=st["mean"]; self.cfg._ai_error_std=st["std"]
            # Load per-stream feedback bias so it persists across restarts
            fp = _feedback_path(self.cfg.name)
            try:
                with open(fp) as f: fb=json.load(f)
                self.cfg._ai_threshold_bias = float(fb.get("threshold_bias", 0.0))
            except Exception:
                self.cfg._ai_threshold_bias = 0.0
            self.cfg._ai_phase="ready"; self.cfg._ai_status="Model loaded — monitoring"
            self.log(f"[AI:{self.cfg.name}] Loaded existing model. Threshold bias={self.cfg._ai_threshold_bias:+.2f}σ")
            return True
        except Exception as e:
            self.log(f"[AI:{self.cfg.name}] Load failed: {e}"); return False

    def start(self):
        if _try_import("onnxruntime") is None:
            self.cfg._ai_phase="no_onnx"
            self.cfg._ai_status="ⓘ pip install onnxruntime  to enable AI"
            return
        if self.cfg._ai_retrain_flag:
            self.cfg._ai_retrain_flag=False; self._begin_learn(); return
        if not self._load(): self._begin_learn()

    def _begin_learn(self):
        self.cfg._ai_phase="learning"
        self.cfg._ai_learn_start=time.time()
        self.cfg._ai_learn_samples=[]
        self.cfg._ai_status=f"Learning baseline… (0/{int(LEARN_DURATION_SECONDS//3600)}h {int((LEARN_DURATION_SECONDS%3600)//60)}m)"
        self.log(f"[AI:{self.cfg.name}] Learning phase started.")

    def feed(self, audio: np.ndarray):
        if not self.cfg.ai_monitor: return
        p = self.cfg._ai_phase
        if p == "no_onnx": return
        if p == "learning": self._feed_learn(audio)
        elif p == "ready":  self._feed_infer(audio)

    def _feed_learn(self, audio: np.ndarray):
        self.cfg._ai_learn_samples.append(extract_features(audio))
        elapsed = time.time() - self.cfg._ai_learn_start
        pct = min(100, int(elapsed / LEARN_DURATION_SECONDS * 100))
        self.cfg._ai_status = f"Learning baseline… {pct}% ({int(elapsed//60)}/{int(LEARN_DURATION_SECONDS//60)} min)"
        if elapsed >= LEARN_DURATION_SECONDS:
            self._finish_learn()

    def _finish_learn(self):
        samples = np.array(self.cfg._ai_learn_samples, dtype=np.float32)
        if len(samples) < MIN_TRAINING_SAMPLES:
            self.log(f"[AI:{self.cfg.name}] Too few samples ({len(samples)}), restarting.")
            self._begin_learn(); return
        try:
            W1,b1,W2,b2 = _train_autoencoder(samples, self.log)
            onnx_bytes   = _build_onnx(W1,b1,W2,b2)
            mp = _model_path(self.cfg.name)
            with open(mp,"wb") as f: f.write(onnx_bytes)
            ort  = _try_import("onnxruntime")
            sess = ort.InferenceSession(mp)
            errs = [_recon_error(sess, s) for s in samples]
            mean_e = float(np.mean(errs))
            std_e  = max(float(np.std(errs)), 1e-6)
            with open(_stats_path(self.cfg.name),"w") as f:
                json.dump({"mean":mean_e,"std":std_e,"n":len(samples)},f)
            self.cfg._ai_session=sess; self.cfg._ai_error_mean=mean_e
            self.cfg._ai_error_std=std_e; self.cfg._ai_phase="ready"
            self.cfg._ai_status="Model trained — monitoring"
            self.log(f"[AI:{self.cfg.name}] Ready. Baseline {mean_e:.5f} ± {std_e:.5f}")

            # ── Persist the full 24 h corpus so future feedback-retrains can
            # build on top of it rather than starting from a tiny clean buffer.
            # Written in a background thread so it never delays model activation.
            _isp = _initial_samples_path(self.cfg.name)
            if not os.path.exists(_isp):
                # Only write once — if the file already exists (e.g. after a
                # manual retrain triggered a new learning phase) keep the
                # original so history is never lost.
                _save_samples = samples[:AI_INITIAL_SAMPLES_MAX]
                _name_snap    = self.cfg.name
                def _persist():
                    try:
                        np.save(_isp, _save_samples)
                        self.log(f"[AI:{_name_snap}] Initial corpus saved "
                                 f"({len(_save_samples)} samples → {os.path.basename(_isp)})")
                    except Exception as _e:
                        self.log(f"[AI:{_name_snap}] Warning: could not save initial corpus: {_e}")
                threading.Thread(target=_persist, daemon=True,
                                 name=f"AIInitSave-{self.cfg.name}").start()
        except Exception as e:
            self.cfg._ai_status=f"Training failed: {e}"
            self.log(f"[AI:{self.cfg.name}] Training error: {e}")

    def _feed_infer(self, audio: np.ndarray):
        cfg = self.cfg
        if not cfg._ai_session: return
        feats = extract_features(audio)
        err   = _recon_error(cfg._ai_session, feats)
        z     = (err - cfg._ai_error_mean) / (cfg._ai_error_std + 1e-10)

        # ── Sustained-window confirmation ──────────────────────────────────────
        # Single-window spikes from content transitions should not alert.
        # We require AI_CONFIRM_WINDOWS consecutive windows above threshold.
        if not hasattr(cfg, '_ai_consec_warn'):  cfg._ai_consec_warn  = 0
        if not hasattr(cfg, '_ai_consec_alert'): cfg._ai_consec_alert = 0

        # Per-stream sensitivity bias: raised when user labels alerts as false alarms,
        # lowered slightly when confirmed as real faults.
        _bias = getattr(cfg, '_ai_threshold_bias', 0.0)
        _eff_warn  = ANOMALY_WARN_THRESHOLD  + _bias
        _eff_alert = ANOMALY_ALERT_THRESHOLD + _bias

        if z >= _eff_alert:
            cfg._ai_consec_alert += 1
            cfg._ai_consec_warn  += 1
        elif z >= _eff_warn:
            cfg._ai_consec_alert  = 0
            cfg._ai_consec_warn  += 1
        else:
            cfg._ai_consec_alert  = 0
            cfg._ai_consec_warn   = 0

        if cfg._ai_consec_alert >= AI_CONFIRM_WINDOWS:
            status = "ALERT"
            reason = _classify(feats, _infer(cfg._ai_session, feats))
        elif cfg._ai_consec_warn >= AI_CONFIRM_WINDOWS:
            status = "WARN"
            reason = _classify(feats, _infer(cfg._ai_session, feats))
        else:
            status = "OK"; reason = ""

        _bias_tag = f" bias={_bias:+.2f}σ" if _bias else ""
        cfg._ai_status = f"[{status}] z={z:.1f}{_bias_tag}{' — '+reason if reason else ''}"

        if status in ("ALERT", "WARN"):
            # Only fire once per sustained event, not every window
            if cfg._ai_consec_warn == AI_CONFIRM_WINDOWS or cfg._ai_consec_alert == AI_CONFIRM_WINDOWS:
                key = f"AI_{reason}"; now = time.time()
                cd  = ALERT_COOLDOWN if status == "ALERT" else ALERT_COOLDOWN * 2
                if now - cfg._last_alerts.get(key, 0) >= cd:
                    cfg._last_alerts[key] = now
                    msg = f"AI {status} on '{cfg.name}': {reason} (score {z:.1f}σ)"
                    snippet = _save_alert_wav(cfg, f"ai_{_safe_label(reason)}")
                    _add_history(cfg, f"AI_{status}", msg, clip_path=snippet or "")
                    self.log(f"[AI:{cfg.name}] {msg}")
                    self.sender.send(f"AI {status} — {cfg.name}: {reason}", msg, snippet,
                             alert_type=f"AI_{status}", stream=cfg.name,
                             level_dbfs=float(cfg._last_level_dbfs))
        else:
            # Adaptive baseline: update mean AND std continuously on clean windows.
            # Using a faster adapt rate than before so the baseline tracks slow
            # long-term drift in the stream's normal characteristics.
            alpha = 0.002   # ~500-window half-life (~41 min at 5s intervals)
            cfg._ai_error_mean = (1-alpha) * cfg._ai_error_mean + alpha * err
            # Online std via exponential moving variance
            if not hasattr(cfg, '_ai_error_var'): cfg._ai_error_var = cfg._ai_error_std**2
            cfg._ai_error_var = (1-alpha) * cfg._ai_error_var + alpha * (err - cfg._ai_error_mean)**2
            cfg._ai_error_std = max(float(np.sqrt(cfg._ai_error_var)), 1e-6)

            # ── Accumulate clean-window features for future retraining ───────
            # Only collect windows that are confidently normal (z < 1.0) so
            # edge-case near-threshold audio never pollutes the clean buffer.
            if z < 1.0:
                if not hasattr(cfg, '_ai_clean_buf'):     cfg._ai_clean_buf     = []
                if not hasattr(cfg, '_ai_clean_buf_new'): cfg._ai_clean_buf_new = 0
                cfg._ai_clean_buf.append(feats)
                cfg._ai_clean_buf_new += 1
                # Trim in-memory buffer to max size (keep newest)
                if len(cfg._ai_clean_buf) > AI_CLEAN_BUFFER_MAX:
                    cfg._ai_clean_buf = cfg._ai_clean_buf[-AI_CLEAN_BUFFER_MAX:]
                # Flush to disk periodically (daemon thread, no impact on timing)
                if cfg._ai_clean_buf_new >= AI_CLEAN_BUFFER_FLUSH:
                    cfg._ai_clean_buf_new = 0
                    threading.Thread(
                        target=_flush_clean_buffer,
                        args=(cfg.name, list(cfg._ai_clean_buf)),
                        daemon=True, name="CleanBufFlush",
                    ).start()

# ─── Alerting ─────────────────────────────────────────────────────────────────

def _hub_is_connected() -> bool:
    """Return True if the hub client has an active, recently confirmed connection.
    Used by AlertSender to suppress local notifications when the hub is handling them.
    """
    try:
        hc = monitor._hub_client
        if hc is None:
            return False
        return hc.state == "connected" and (time.time() - hc.last_ack) < 30.0
    except Exception:
        return False


class AlertSender:
    def __init__(self, cfg: AppConfig, log_fn):
        self.cfg=cfg; self.log=log_fn

    def send(self, subject, body, attachment=None, priority=None,
             alert_type: str = "", stream: str = "",
             level_dbfs: float = None, ptp_state: str = ""):
        self.log(f"[ALERT] {subject}")
        if getattr(self.cfg, "suppress_local_notifications", False) and _hub_is_connected():
            self.log(f"[ALERT] Local notifications suppressed — delegated to hub")
            return
        self._email(subject, body, attachment)
        self._webhook(subject, body, alert_type=alert_type, stream=stream,
                      level_dbfs=level_dbfs, ptp_state=ptp_state)
        self._pushover(subject, body, priority)

    def send_warn(self, subject, body, attachment=None):
        self.send(subject, body, attachment, priority=self.cfg.pushover.priority_warn)

    def send_alert(self, subject, body, attachment=None):
        self.send(subject, body, attachment, priority=self.cfg.pushover.priority_alert)

    def _email(self, subject, body, attachment):
        ec=self.cfg.email
        if not ec.enabled or not ec.smtp_host: return
        try:
            import smtplib
            from email.mime.multipart import MIMEMultipart
            from email.mime.text import MIMEText
            from email.mime.application import MIMEApplication
            msg=MIMEMultipart(); msg["Subject"]=subject
            msg["From"]=ec.from_addr; msg["To"]=ec.to_addr
            msg.attach(MIMEText(body))
            if attachment and os.path.exists(attachment):
                with open(attachment,"rb") as f:
                    p=MIMEApplication(f.read(),Name=os.path.basename(attachment))
                p["Content-Disposition"]=f'attachment; filename="{os.path.basename(attachment)}"'
                msg.attach(p)
            mgmt=self.cfg.network.management_interface_ip
            src=(mgmt,0) if mgmt!="0.0.0.0" else None
            with smtplib.SMTP(ec.smtp_host,ec.smtp_port,source_address=src) as s:
                if ec.use_tls: s.starttls()
                if ec.username: s.login(ec.username,ec.password)
                s.sendmail(ec.from_addr,[ec.to_addr],msg.as_string())
        except Exception as e: self.log(f"[EMAIL] {e}")

    def _webhook(self, subject: str, body: str, alert_type: str = "",
                  stream: str = "", level_dbfs: float = None, ptp_state: str = ""):
        wc = self.cfg.webhook
        if not wc.enabled: return
        site = self.cfg.hub.site_name or ""
        routes = wc.matching_routes(stream, alert_type, site)
        if not routes: return
        for route in routes:
            try:
                if route.teams_style:
                    payload = self._build_teams_card(subject, body, alert_type,
                                                     stream, level_dbfs, ptp_state)
                else:
                    payload = {"text": f"**{subject}**\n\n{body}"}
                data = json.dumps(payload, separators=(",", ":")).encode("utf-8")
                urllib.request.urlopen(
                    urllib.request.Request(route.url, data=data,
                        headers={"Content-Type": "application/json"}), timeout=10)
                self.log(f"[WEBHOOK→{route.name or route.url[:40]}] {subject}")
            except Exception as e:
                self.log(f"[WEBHOOK→{route.name or 'default'}] {e}")

    @staticmethod
    def _build_teams_card(subject: str, body: str, alert_type: str = "",
                          stream: str = "", level_dbfs: float = None, ptp_state: str = "") -> dict:
        """Build an MS Teams Adaptive Card payload.

        Mirrors the card structure used by notify-msteams.py but built in pure
        Python rather than Jinja templates, so no extra dependencies needed.
        Uses the Workflow/Power Automate webhook format which expects:
          { "type": "message", "attachments": [{ "contentType": "application/vnd.microsoft.card.adaptive", ... }] }
        """
        # ── Severity colour (matches Teams theme colours) ──────────────────────
        tl = alert_type.lower()
        if any(x in tl for x in ("alert", "silence", "clip", "rtp_loss", "ptp_lost", "cmp")):
            colour = "attention"   # red
        elif any(x in tl for x in ("warn", "hiss", "rtp_loss_warn")):
            colour = "warning"     # amber
        else:
            colour = "good"        # green

        colour_hex = {"attention": "FF3B30", "warning": "FF9500", "good": "34C759"}.get(colour, "4F9CF9")

        # ── Header icon by type ────────────────────────────────────────────────
        icon = "🔔"
        if "silence"  in tl: icon = "🔇"
        elif "clip"   in tl: icon = "📈"
        elif "hiss"   in tl: icon = "〰️"
        elif "ai"     in tl: icon = "🤖"
        elif "rtp"    in tl: icon = "📦"
        elif "ptp"    in tl: icon = "🕐"
        elif "cmp"    in tl: icon = "🔀"

        # ── Build fact rows ────────────────────────────────────────────────────
        facts = []
        if stream:
            facts.append({"title": "Stream", "value": stream})
        if alert_type:
            facts.append({"title": "Type", "value": alert_type})
        if level_dbfs is not None and level_dbfs > -120:
            facts.append({"title": "Level", "value": f"{level_dbfs:.1f} dBFS"})
        if ptp_state:
            facts.append({"title": "PTP", "value": ptp_state})
        facts.append({"title": "Detail", "value": body})
        facts.append({"title": "Time", "value": time.strftime("%Y-%m-%d %H:%M:%S")})

        # ── Adaptive Card body ─────────────────────────────────────────────────
        card_body = [
            {
                "type": "Container",
                "style": colour,
                "items": [
                    {
                        "type": "ColumnSet",
                        "columns": [
                            {
                                "type": "Column",
                                "width": "auto",
                                "items": [{"type": "TextBlock", "text": icon, "size": "Large"}]
                            },
                            {
                                "type": "Column",
                                "width": "stretch",
                                "items": [
                                    {
                                        "type": "TextBlock",
                                        "text": subject,
                                        "weight": "Bolder",
                                        "size": "Medium",
                                        "wrap": True,
                                        "color": colour
                                    },
                                    {
                                        "type": "TextBlock",
                                        "text": f"SignalScope  •  {time.strftime('%H:%M:%S')}",
                                        "size": "Small",
                                        "isSubtle": True
                                    }
                                ]
                            }
                        ]
                    }
                ]
            },
            {
                "type": "FactSet",
                "facts": facts
            }
        ]

        adaptive_card = {
            "type": "AdaptiveCard",
            "$schema": "http://adaptivecards.io/schemas/adaptive-card.json",
            "version": "1.4",
            "body": card_body
        }

        # Workflow webhook format (replaces legacy Office 365 connector format)
        return {
            "type": "message",
            "attachments": [
                {
                    "contentType": "application/vnd.microsoft.card.adaptive",
                    "contentUrl": None,
                    "content": adaptive_card
                }
            ]
        }

    def _pushover(self, subject, body, priority=None):
        pc = self.cfg.pushover
        if not pc.enabled or not pc.user_key or not pc.app_token: return
        if priority is None: priority = pc.priority_alert
        try:
            # Emergency priority requires retry/expire params
            params = {
                "token":   pc.app_token,
                "user":    pc.user_key,
                "title":   subject[:250],
                "message": body[:1024],
                "priority": str(priority),
            }
            if priority == 2:  # emergency — must have retry + expire
                params["retry"]  = "60"
                params["expire"] = "3600"
            data = urllib.parse.urlencode(params).encode()
            urllib.request.urlopen(
                urllib.request.Request(
                    "https://api.pushover.net/1/messages.json",
                    data=data,
                    headers={"Content-Type":"application/x-www-form-urlencoded"},
                ), timeout=10)
            self.log(f"[PUSHOVER] Sent: {subject}")
        except Exception as e: self.log(f"[PUSHOVER] {e}")

# ─── Rule-based analysis ──────────────────────────────────────────────────────

def _check_rds_name(cfg, sender, log_fn, now: float):
    """Check RDS PS name vs expected (or detect change). Call after a stable PS update."""
    if not cfg._fm_rds_ok:
        return
    ps = (cfg._fm_rds_ps or "").strip()
    if len(ps) < 4:
        return   # too short / still decoding
    prev     = (cfg._fm_rds_ps_prev or "").strip()
    expected = (cfg.expected_fm_rds_ps or "").strip().upper()
    fired    = False
    if expected:
        if ps.upper() != expected:
            key = "FM_RDS_MISMATCH"
            if now - cfg._last_alerts.get(key, 0) >= ALERT_COOLDOWN * 2:
                cfg._last_alerts[key] = now
                msg = (f"RDS name mismatch on '{cfg.name}' — "
                       f"expected '{expected}', receiving '{ps}'")
                _add_history(cfg, key, msg)
                sender.send(f"RDS MISMATCH — {cfg.name}", msg, None,
                            alert_type=key, stream=cfg.name,
                            level_dbfs=float(cfg._last_level_dbfs))
                log_fn(f"[ALERT] {msg}")
                fired = True
    else:
        # Change detection when no expected name is configured
        if prev and ps != prev:
            key = "FM_RDS_MISMATCH"
            if now - cfg._last_alerts.get(key, 0) >= ALERT_COOLDOWN * 2:
                cfg._last_alerts[key] = now
                msg = (f"RDS name changed on '{cfg.name}' — "
                       f"was '{prev}', now '{ps}'")
                _add_history(cfg, key, msg)
                sender.send(f"RDS NAME CHANGED — {cfg.name}", msg, None,
                            alert_type=key, stream=cfg.name,
                            level_dbfs=float(cfg._last_level_dbfs))
                log_fn(f"[ALERT] {msg}")
                fired = True
    # Always update prev so the next check has the latest baseline
    if ps:
        cfg._fm_rds_ps_prev = ps


def _check_dab_service_name(cfg, sender, log_fn, now: float):
    """Check DAB service name vs expected (or detect change). Call after service is set."""
    if not cfg._dab_ok:
        return
    svc = (cfg._dab_service or "").strip()
    if not svc:
        return
    prev     = (cfg._dab_service_prev or "").strip()
    expected = (cfg.expected_dab_service or "").strip()
    if expected:
        if svc.lower() != expected.lower():
            key = "DAB_SERVICE_MISMATCH"
            if now - cfg._last_alerts.get(key, 0) >= ALERT_COOLDOWN * 2:
                cfg._last_alerts[key] = now
                msg = (f"DAB service mismatch on '{cfg.name}' — "
                       f"expected '{expected}', receiving '{svc}'")
                _add_history(cfg, key, msg)
                sender.send(f"DAB SERVICE MISMATCH — {cfg.name}", msg, None,
                            alert_type=key, stream=cfg.name,
                            level_dbfs=float(cfg._last_level_dbfs))
                log_fn(f"[ALERT] {msg}")
    else:
        if prev and svc != prev:
            key = "DAB_SERVICE_MISMATCH"
            if now - cfg._last_alerts.get(key, 0) >= ALERT_COOLDOWN * 2:
                cfg._last_alerts[key] = now
                msg = (f"DAB service name changed on '{cfg.name}' — "
                       f"was '{prev}', now '{svc}'")
                _add_history(cfg, key, msg)
                sender.send(f"DAB SERVICE CHANGED — {cfg.name}", msg, None,
                            alert_type=key, stream=cfg.name,
                            level_dbfs=float(cfg._last_level_dbfs))
                log_fn(f"[ALERT] {msg}")
    if svc:
        cfg._dab_service_prev = svc


def _stream_in_any_chain(stream_name: str, app_cfg) -> bool:
    """Return True if stream_name is a node in any configured signal chain.
    Used to suppress redundant individual-stream notifications when a chain
    fault covers the same event — the chain alert provides richer context."""
    for chain in getattr(app_cfg, "signal_chains", None) or []:
        for node in chain.get("nodes", []):
            if node.get("type") == "stack":
                for sub in node.get("nodes", []):
                    if sub.get("stream") == stream_name:
                        return True
            elif node.get("stream") == stream_name:
                return True
    return False


def _classify_silence_alert(cfg, lev: float):
    """Return (alert_key, title, message) for a silence event.

    Composite fault classification by source type:
      FM:
        STUDIO_FAULT    — carrier and RDS present, only audio silent (playout failure)
        STL_FAULT       — carrier healthy but RDS gone (STL/link failure)
        TX_DOWN         — weak/no carrier and no RDS (transmitter or RF problem)
      DAB:
        DAB_AUDIO_FAULT — mux locked, SNR healthy, but audio silent (studio/playout fault)
        DAB_SERVICE_MISSING — service gone from mux (separate alert, in _run_dab)
      RTP/Livewire:
        RTP_FAULT       — ≥10% packet loss is causing the silence (network fault)
      All other sources:
        SILENCE         — generic content silence
    """
    name  = cfg.name
    sil_s = cfg._silence_secs
    # FM composite: only when the FM thread has populated real signal data
    if cfg._fm_freq_mhz > 0.0 and cfg._fm_signal_dbm > -119.0:
        rds_alive  = cfg._fm_rds_ok and bool(cfg._fm_rds_ps)
        carrier_ok = cfg._fm_signal_dbm >= -85.0
        if rds_alive:
            key = "STUDIO_FAULT"
            msg = (f"Studio fault on '{name}' — silence {sil_s:.1f}s, "
                   f"carrier and RDS active (PS: {cfg._fm_rds_ps}, "
                   f"RSSI {cfg._fm_signal_dbm:.0f} dBm)")
            return key, f"STUDIO FAULT — {name}", msg
        elif carrier_ok:
            key = "STL_FAULT"
            msg = (f"STL fault on '{name}' — silence {sil_s:.1f}s, "
                   f"RDS absent, carrier OK ({cfg._fm_signal_dbm:.0f} dBm)")
            return key, f"STL FAULT — {name}", msg
        else:
            key = "TX_DOWN"
            msg = (f"TX down on '{name}' — silence {sil_s:.1f}s, "
                   f"no RDS, weak/no carrier ({cfg._fm_signal_dbm:.0f} dBm)")
            return key, f"TX DOWN — {name}", msg
    # DAB composite: mux locked and SNR healthy but audio is silent → studio/playout fault
    if cfg._dab_ensemble and cfg._dab_ok and cfg._dab_snr >= 5.0:
        key = "DAB_AUDIO_FAULT"
        msg = (f"DAB audio fault on '{name}' — silence {sil_s:.1f}s, "
               f"service present in mux (SNR {cfg._dab_snr:.1f} dB, "
               f"ensemble: {cfg._dab_ensemble})")
        return key, f"DAB AUDIO FAULT — {name}", msg

    # RTP-linked silence: high packet loss is causing the silence (network fault, not content)
    dev = (cfg.device_index or "").strip().lower()
    if (not dev.startswith(("fm://", "dab://", "http://", "https://", "sound://"))
            and cfg._rtp_loss_pct >= 10.0):
        key = "RTP_FAULT"
        msg = (f"RTP fault on '{name}' — silence {sil_s:.1f}s "
               f"with {cfg._rtp_loss_pct:.1f}% packet loss")
        return key, f"RTP FAULT — {name}", msg

    # Generic silence (Livewire, AES67, HTTP, DAB audio path, etc.)
    msg = f"Silence on '{name}' for {sil_s:.1f}s ({lev:.1f} dBFS)"
    return "SILENCE", f"SILENCE on {name}", msg


def analyse_chunk(cfg: InputConfig, sender: AlertSender, log_fn,
                  data: np.ndarray, elapsed: float, wav_dur: float,
                  all_inputs: List[InputConfig]):
    if not data.size: return
    rms=float(np.sqrt(np.mean(data**2))); lev=dbfs(rms)
    cfg._last_level_dbfs=lev
    cfg._last_peak_dbfs=dbfs(float(np.max(np.abs(data))))
    if not cfg.enabled: return
    in_alert = lev <= cfg.silence_threshold_dbfs
    _sla_update(cfg, elapsed, in_alert)

    # ── Rolling level buffer (shared by flatness + glitch detectors) ──────────
    _buf_now = time.time()
    cfg._level_buf.append((_buf_now, lev))
    # Prune to last 10 minutes — enough for longest flatness window
    _buf_cutoff = _buf_now - 600.0
    cfg._level_buf = [(t, v) for (t, v) in cfg._level_buf if t >= _buf_cutoff]

    # EBU R128 loudness
    _lufs_update(cfg, sender, log_fn, data, elapsed)

    # Escalation check (rate-limited to once per minute per stream)
    if cfg.escalation_minutes > 0:
        _now_e = time.time()
        if _now_e - cfg._last_alerts.get("_escalation_check", 0) >= 60.0:
            cfg._last_alerts["_escalation_check"] = _now_e
            _check_escalation(cfg, sender, log_fn)

    if cfg.cascade_suppress_alerts and cfg.cascade_parent and all_inputs:
        parent=next((i for i in all_inputs if i.name==cfg.cascade_parent),None)
        if parent and parent._last_level_dbfs<=parent.silence_threshold_dbfs:
            cfg._silence_secs=0.0; cfg._silence_active=False; cfg._silence_alert_key=""
            cfg._flatness_since=0.0; cfg._glitch_dip_start=0.0; return

    # Silence / composite fault classification
    if cfg.alert_on_silence:
        cfg._silence_secs = cfg._silence_secs+elapsed if lev<=cfg.silence_threshold_dbfs else 0.0
        if cfg._silence_secs>=cfg.silence_min_duration:
            now=time.time()
            alert_key, alert_title, alert_msg = _classify_silence_alert(cfg, lev)
            if now-cfg._last_alerts.get(alert_key,0)>=ALERT_COOLDOWN:
                cfg._last_alerts[alert_key]=now
                # Use _stream_buffer snapshot so the clip starts with pre-fault
                # audio rather than mid-silence — makes the fault point audible.
                _sb_chunks = list(cfg._stream_buffer) if cfg._stream_buffer else None
                clip=_save_alert_wav(cfg,"silence",cfg.alert_wav_duration,
                                     _chunks=_sb_chunks)
                _add_history(cfg,alert_key,alert_msg,clip_path=clip or "")
                # If this stream is covered by a broadcast chain, suppress the
                # individual notification — the CHAIN_FAULT alert provides
                # richer context (fault location, downstream impact). Still logged above.
                if not _stream_in_any_chain(cfg.name, monitor.app_cfg):
                    sender.send(alert_title, alert_msg, clip,
                        alert_type=alert_key, stream=cfg.name, level_dbfs=lev)
                log_fn(f"[ALERT] {alert_msg}")
            # Track that silence is active so we can save a recovery clip when audio returns
            if not cfg._silence_active:
                cfg._silence_active    = True
                cfg._silence_alert_key = alert_key
            cfg._silence_secs=0.0
        elif cfg._silence_active and lev>cfg.silence_threshold_dbfs:
            # Audio has just resumed. Reset state immediately to avoid re-triggering,
            # then wait _POST_SILENCE_SECS so the rolling buffer fills with restored
            # audio before saving — the clip will show [tail of silence + recovery].
            _post_key  = cfg._silence_alert_key or "SILENCE"
            _post_dur  = cfg.alert_wav_duration
            _post_name = cfg.name
            # Wait 85 % of clip length so the clip ends well into the restored
            # audio — the first ~15 % gives a short tail of silence for context.
            _post_wait = _post_dur * 0.85
            cfg._silence_active=False
            cfg._silence_alert_key=""
            def _save_silence_end(_cfg=cfg, _dur=_post_dur, _key=_post_key,
                                  _name=_post_name, _wait=_post_wait, _log=log_fn):
                time.sleep(_wait)
                clip=_save_alert_wav(_cfg,"silence_end",_dur)
                _add_history(_cfg, _key, f"Audio restored on '{_name}'",
                             clip_path=clip or "")
                _log(f"[Alert] Silence ended on '{_name}'")
            threading.Thread(target=_save_silence_end, daemon=True,
                             name="SilenceEndClip").start()

    # Clip
    if cfg.alert_on_clip:
        peak_db=dbfs(float(np.max(np.abs(data)))); now=time.time()
        if peak_db>=cfg.clip_threshold_dbfs:
            if now-cfg._clip_window_start>cfg.clip_window_seconds:
                cfg._clip_count=0; cfg._clip_window_start=now
            cfg._clip_count+=1
            if cfg._clip_count>=cfg.clip_count_threshold:
                if now-cfg._last_alerts.get("CLIP",0)>=ALERT_COOLDOWN:
                    cfg._last_alerts["CLIP"]=now
                    msg=f"Clipping on '{cfg.name}' — {cfg._clip_count}x in {cfg.clip_window_seconds}s (peak {peak_db:.1f} dBFS)"
                    clip=_save_alert_wav(cfg,"clip",cfg.alert_wav_duration)
                    _add_history(cfg,"CLIP",msg,clip_path=clip or "")
                    sender.send(f"CLIP on {cfg.name}", msg, clip,
                    alert_type="CLIP", stream=cfg.name, level_dbfs=peak_db)
                    log_fn(f"[ALERT] {msg}")
                cfg._clip_count=0

    # Hiss
    if cfg.alert_on_hiss:
        n=len(data); win=np.hanning(n); psd=np.abs(np.fft.rfft(data*win))**2
        freq=np.fft.rfftfreq(n,d=1.0/SAMPLE_RATE); tot=float(np.sum(psd)+1e-12)
        hf =float(np.sum(psd[freq>=cfg.hiss_hf_band_hz])/tot)
        mid=float(np.sum(psd[(freq>=1000)&(freq<cfg.hiss_hf_band_hz)])/tot)
        if cfg._baseline_learning_remaining>0:
            cfg._hf_baseline  = hf  if cfg._hf_baseline  is None else 0.9*cfg._hf_baseline +0.1*hf
            cfg._mid_baseline = mid if cfg._mid_baseline is None else 0.9*cfg._mid_baseline+0.1*mid
            cfg._baseline_learning_remaining=max(0.0,cfg._baseline_learning_remaining-elapsed)
        elif cfg._hf_baseline and cfg._hf_baseline>1e-10:
            hf_db =20*math.log10(max(hf, 1e-10)/max(cfg._hf_baseline, 1e-10))
            mid_db=20*math.log10(max(mid,1e-10)/max(cfg._mid_baseline,1e-10))
            if hf_db>=cfg.hiss_rise_db and mid_db<0.5:
                cfg._hiss_secs=min(cfg._hiss_secs+elapsed,cfg.hiss_min_duration*2)
            else:
                cfg._hiss_secs=max(0.0,cfg._hiss_secs-elapsed)
            if cfg._hiss_secs>=cfg.hiss_min_duration:
                now=time.time()
                if now-cfg._last_alerts.get("HISS",0)>=ALERT_COOLDOWN:
                    cfg._last_alerts["HISS"]=now
                    msg=f"Hiss/HF noise on '{cfg.name}' — HF up {hf_db:.1f}dB for {cfg._hiss_secs:.1f}s"
                    clip=_save_alert_wav(cfg,"hiss",cfg.alert_wav_duration)
                    _add_history(cfg,"HISS",msg,clip_path=clip or "")
                    sender.send(f"HISS on {cfg.name}", msg, clip,
                    alert_type="HISS", stream=cfg.name,
                    level_dbfs=float(cfg._last_level_dbfs))
                    log_fn(f"[ALERT] {msg}")
                cfg._hiss_secs=0.0

    # ── Glitch / short dropout detection ─────────────────────────────────────
    # A glitch is a level dip that is significantly below the recent rolling mean
    # but shorter than glitch_max_seconds (longer = silence, handled above).
    if cfg.glitch_detect:
        _gn = time.time()
        # Rolling mean reference: last 60 s, excluding the current glitch_max_seconds
        # window so an ongoing dip doesn't poison its own reference.
        _ref_window_end = _gn - max(0.5, cfg.glitch_max_seconds)
        _ref_samples = [v for (t, v) in cfg._level_buf
                        if (_gn - 60.0) <= t <= _ref_window_end
                        and v > cfg.silence_threshold_dbfs]
        if len(_ref_samples) >= 5:
            _rolling_mean = sum(_ref_samples) / len(_ref_samples)
            # A dip: significantly below rolling mean but not complete silence
            _is_dip = (lev < _rolling_mean - cfg.glitch_drop_db
                       and lev > cfg.silence_threshold_dbfs - 15.0)
            if _is_dip and cfg._glitch_dip_start == 0.0:
                # ── Pre-dip trend check (#4) ─────────────────────────────────
                # If the level was already declining for 2-5 s before the crossing
                # this is a content fade-out, not an abrupt fault. Reject early.
                _p_early = [v for (t, v) in cfg._level_buf
                            if _gn - 5.0 <= t <= _gn - 3.0
                            and v > cfg.silence_threshold_dbfs]
                _p_late  = [v for (t, v) in cfg._level_buf
                            if _gn - 2.5 <= t <= _gn - 0.5
                            and v > cfg.silence_threshold_dbfs]
                _pre_trend_db = 0.0
                if _p_early and _p_late:
                    _pre_trend_db = ((sum(_p_early) / len(_p_early))
                                     - (sum(_p_late)  / len(_p_late)))
                if cfg.glitch_pre_trend_db > 0 and _pre_trend_db >= cfg.glitch_pre_trend_db:
                    pass   # level was already declining — treat as fade, not glitch
                else:
                    cfg._glitch_dip_start = _gn
                    cfg._glitch_dip_floor = lev   # initialise floor tracker
                    # ── Approach rate (onset) ─────────────────────────────────
                    # Measure over 0.5–3 s before crossing so gradual fades
                    # are not inflated to 60+ dBFS/s at the threshold instant.
                    _pre = [(t, v) for (t, v) in cfg._level_buf
                            if _gn - 3.0 <= t <= _gn - 0.5
                            and v > cfg.silence_threshold_dbfs]
                    if _pre:
                        _pt, _pv = _pre[-1]
                        _dt = max(0.1, _gn - _pt)
                        cfg._glitch_entry_rate = (_pv - lev) / _dt
                    else:
                        cfg._glitch_entry_rate = 999.0   # no ref — treat as abrupt
            elif _is_dip and cfg._glitch_dip_start > 0.0:
                # ── Track minimum level during the dip (#3) ──────────────────
                if lev < cfg._glitch_dip_floor:
                    cfg._glitch_dip_floor = lev
            elif not _is_dip and cfg._glitch_dip_start > 0.0:
                _dip_dur    = _gn - cfg._glitch_dip_start
                _entry_rate = cfg._glitch_entry_rate
                _dip_floor  = cfg._glitch_dip_floor
                cfg._glitch_dip_start  = 0.0
                cfg._glitch_entry_rate = 0.0
                cfg._glitch_dip_floor  = 0.0
                _min_rate = cfg.glitch_min_drop_rate_dbfs_s
                _reject   = False
                # Filter A — onset too gradual
                if _min_rate > 0 and _entry_rate < _min_rate:
                    _reject = True
                # Filter B — dip never reached close enough to silence (#2/#3)
                if not _reject and cfg.glitch_floor_db > 0:
                    if _dip_floor > cfg.silence_threshold_dbfs + cfg.glitch_floor_db:
                        _reject = True
                # Filter C — recovery too gradual (#1 recovery rate)
                if not _reject and _min_rate > 0:
                    _post = [(t, v) for (t, v) in cfg._level_buf
                             if _gn - 3.0 <= t <= _gn - 0.5]
                    if _post:
                        _rpt, _rpv = _post[-1]
                        _rdt = max(0.1, _gn - _rpt)
                        _recovery_rate = (lev - _rpv) / _rdt
                        if _recovery_rate < _min_rate:
                            _reject = True
                if not _reject and 0.0 < _dip_dur < cfg.glitch_max_seconds:
                    # Count it
                    cfg._glitch_timestamps.append(_gn)
                    cfg._glitch_count_total += 1
                    # Prune to the longest window we need so both alert
                    # levels can look back as far as they require.
                    _g_cutoff = _gn - max(cfg.glitch_alert_window_min,
                                          cfg.glitch_sustained_window_min) * 60.0
                    cfg._glitch_timestamps = [t for t in cfg._glitch_timestamps if t >= _g_cutoff]

                    # ── Per-glitch clip capture ───────────────────────────
                    # Every glitch saves a short audio clip and logs it to
                    # Reports — no external notification fires here.
                    # Rate-limited to one clip every 30 s so rapid bursts
                    # don't flood the clip store.
                    _GLITCH_CLIP_COOLDOWN = 30.0
                    if _gn - cfg._last_alerts.get("_glitch_clip", 0) >= _GLITCH_CLIP_COOLDOWN:
                        cfg._last_alerts["_glitch_clip"] = _gn
                        _gcmsg = (f"Audio glitch on '{cfg.name}' — "
                                  f"{_dip_dur:.1f}s dropout "
                                  f"({lev:.1f} dBFS, ref {_rolling_mean:.1f} dBFS)")
                        _gcclip_dur = min(cfg.alert_wav_duration, 12.0)
                        _gcclip = _save_alert_wav(cfg, "glitch", _gcclip_dur)
                        _add_history(cfg, "AUDIO_GLITCH", _gcmsg,
                                     clip_path=_gcclip or "")
                        log_fn(f"[Glitch] {_gcmsg}")

                    # ── Notification: N glitches in short window ──────────
                    _gw_cutoff = _gn - cfg.glitch_alert_window_min * 60.0
                    _gw_count  = sum(1 for t in cfg._glitch_timestamps if t >= _gw_cutoff)
                    if _gw_count >= cfg.glitch_alert_count:
                        if _gn - cfg._last_glitch_alert_ts >= ALERT_COOLDOWN:
                            cfg._last_glitch_alert_ts = _gn
                            _gnmsg = (f"Audio glitching on '{cfg.name}' — "
                                      f"{_gw_count} dropout(s) in "
                                      f"{cfg.glitch_alert_window_min} min")
                            if not _stream_in_any_chain(cfg.name, monitor.app_cfg):
                                sender.send(f"GLITCH on {cfg.name}", _gnmsg, None,
                                            alert_type="AUDIO_GLITCH", stream=cfg.name,
                                            level_dbfs=lev)
                            log_fn(f"[ALERT] {_gnmsg}")

                    # ── Notification: sustained hammering ─────────────────
                    # Fires a louder escalation when glitches keep piling up
                    # over the longer sustained window. 10-minute cooldown so
                    # it re-alerts if the problem persists but doesn't spam.
                    _sw_cutoff = _gn - cfg.glitch_sustained_window_min * 60.0
                    _sw_count  = sum(1 for t in cfg._glitch_timestamps if t >= _sw_cutoff)
                    _SUSTAINED_COOLDOWN = 600.0   # 10 minutes
                    if _sw_count >= cfg.glitch_sustained_count:
                        if _gn - cfg._last_sustained_alert_ts >= _SUSTAINED_COOLDOWN:
                            cfg._last_sustained_alert_ts = _gn
                            _sclip = _save_alert_wav(cfg, "glitch_sustained",
                                                     min(cfg.alert_wav_duration, 12.0))
                            _smsg = (f"Sustained glitching on '{cfg.name}' — "
                                     f"{_sw_count} dropouts in "
                                     f"{cfg.glitch_sustained_window_min} min "
                                     f"(total session: {cfg._glitch_count_total})")
                            _add_history(cfg, "AUDIO_GLITCH_SUSTAINED", _smsg,
                                         clip_path=_sclip or "")
                            sender.send(f"⚠ SUSTAINED GLITCH on {cfg.name}", _smsg,
                                        _sclip, alert_type="AUDIO_GLITCH_SUSTAINED",
                                        stream=cfg.name, level_dbfs=lev)
                            log_fn(f"[ALERT] {_smsg}")
            elif cfg._glitch_dip_start > 0.0 and (_gn - cfg._glitch_dip_start) >= cfg.glitch_max_seconds:
                # Dip has become a silence event — hand off to silence detection, reset glitch tracker
                cfg._glitch_dip_start = 0.0

    # ── Audio flatness / static detection ────────────────────────────────────
    # Detects constant static, frozen audio, or looping: the level stays above
    # the silence threshold but has almost no dynamic variation.
    if cfg.flatness_detect:
        _fn = time.time()
        _flat_cutoff = _fn - float(cfg.flatness_min_seconds)
        # Only use samples where the stream is actually carrying audio
        _flat_samples = [v for (t, v) in cfg._level_buf
                         if t >= _flat_cutoff and v > cfg.silence_threshold_dbfs]
        if len(_flat_samples) >= 10 and lev > cfg.silence_threshold_dbfs:
            _flat_range = max(_flat_samples) - min(_flat_samples)
            _is_flat = _flat_range < cfg.flatness_min_range_db
            if _is_flat:
                if cfg._flatness_since == 0.0:
                    cfg._flatness_since = _fn  # start timing
                elif (not cfg._flatness_active
                      and (_fn - cfg._flatness_since) >= cfg.flatness_min_seconds):
                    cfg._flatness_active = True
                    _fmsg = (f"Audio flatness on '{cfg.name}' — "
                             f"level range only {_flat_range:.1f} dB over "
                             f"{cfg.flatness_min_seconds}s (static or frozen audio?)")
                    _add_history(cfg, "AUDIO_FLATNESS", _fmsg)
                    if not _stream_in_any_chain(cfg.name, monitor.app_cfg):
                        sender.send(f"FLATNESS on {cfg.name}", _fmsg, None,
                                    alert_type="AUDIO_FLATNESS", stream=cfg.name,
                                    level_dbfs=lev)
                    log_fn(f"[ALERT] {_fmsg}")
            else:
                if cfg._flatness_active:
                    _add_history(cfg, "AUDIO_FLATNESS",
                                 f"Audio dynamics restored on '{cfg.name}' "
                                 f"(range now {_flat_range:.1f} dB)")
                    log_fn(f"[Alert] Flatness ended on '{cfg.name}'")
                cfg._flatness_active = False
                cfg._flatness_since = 0.0

def _lufs_update(cfg: InputConfig, sender: AlertSender, log_fn, data: np.ndarray, elapsed: float):
    """Update EBU R128 loudness measurements and fire threshold alerts."""
    mono = data if data.ndim == 1 else data.mean(axis=1)

    # Apply BS.1770-4 K-weighting filter (state preserved across chunks)
    kw, cfg._lufs_kw_zi1, cfg._lufs_kw_zi2 = _kweight(mono, cfg._lufs_kw_zi1, cfg._lufs_kw_zi2)
    ms = float(np.mean(kw ** 2))

    # Momentary LUFS — current chunk (~400–500 ms, close to spec 400 ms gate)
    cfg._lufs_m = _ms_to_lufs(ms)

    # Short-term LUFS — rolling 3 s window
    cfg._lufs_s_buf.append(ms)
    if len(cfg._lufs_s_buf) > _LUFS_S_BLOCKS:
        cfg._lufs_s_buf = cfg._lufs_s_buf[-_LUFS_S_BLOCKS:]
    cfg._lufs_s = _ms_to_lufs(float(np.mean(cfg._lufs_s_buf)))

    # Integrated LUFS — rolling 30 s window with absolute + relative gating
    if cfg._lufs_m > _LUFS_GATE_ABS:
        cfg._lufs_i_buf.append(ms)
        if len(cfg._lufs_i_buf) > _LUFS_I_BLOCKS:
            cfg._lufs_i_buf = cfg._lufs_i_buf[-_LUFS_I_BLOCKS:]
    if cfg._lufs_i_buf:
        ungated = _ms_to_lufs(float(np.mean(cfg._lufs_i_buf)))
        rel_gate = ungated - 10.0
        gated = [m for m in cfg._lufs_i_buf if _ms_to_lufs(m) > rel_gate]
        if gated:
            cfg._lufs_i = _ms_to_lufs(float(np.mean(gated)))

    # True peak dBTP
    cfg._lufs_tp = _true_peak_dbtp(mono)

    # ── Alerts ──────────────────────────────────────────────────────────────
    now = time.time()

    if cfg.alert_on_lufs_tp and cfg._lufs_tp > cfg.lufs_tp_threshold:
        if now - cfg._last_alerts.get("LUFS_TP", 0) >= ALERT_COOLDOWN:
            cfg._last_alerts["LUFS_TP"] = now
            msg = (f"True peak on '{cfg.name}': {cfg._lufs_tp:.1f} dBTP "
                   f"(threshold {cfg.lufs_tp_threshold:.1f} dBTP)")
            clip = _save_alert_wav(cfg, "lufs_tp", cfg.alert_wav_duration)
            _add_history(cfg, "LUFS_TP", msg, clip_path=clip or "")
            sender.send(f"TRUE PEAK on {cfg.name}", msg, clip,
                alert_type="LUFS_TP", stream=cfg.name, level_dbfs=float(cfg._last_level_dbfs))
            log_fn(f"[ALERT] {msg}")

    if cfg.alert_on_lufs_integrated and len(cfg._lufs_i_buf) >= _LUFS_S_BLOCKS:
        deviation = abs(cfg._lufs_i - cfg.lufs_target)
        if deviation > cfg.lufs_tolerance_db:
            if now - cfg._last_alerts.get("LUFS_I", 0) >= ALERT_COOLDOWN:
                cfg._last_alerts["LUFS_I"] = now
                msg = (f"Integrated loudness on '{cfg.name}': {cfg._lufs_i:.1f} LUFS "
                       f"(target {cfg.lufs_target:.1f} ±{cfg.lufs_tolerance_db:.1f} LU)")
                clip = _save_alert_wav(cfg, "lufs_i", cfg.alert_wav_duration)
                _add_history(cfg, "LUFS_I", msg, clip_path=clip or "")
                sender.send(f"LOUDNESS on {cfg.name}", msg, clip,
                    alert_type="LUFS_I", stream=cfg.name, level_dbfs=float(cfg._last_level_dbfs))
                log_fn(f"[ALERT] {msg}")


def _check_escalation(cfg: InputConfig, sender: AlertSender, log_fn):
    """Re-notify for unacknowledged alerts that have exceeded the escalation window."""
    if cfg.escalation_minutes <= 0:
        return
    cutoff = time.time() - cfg.escalation_minutes * 60.0
    with _alert_acks_lock:
        acked = set(_alert_acks.keys())
    for ev in list(cfg._history):
        aid = ev.get("id", "")
        if not aid or aid in acked:
            continue
        # Skip info / escalation events themselves
        if ev.get("type", "") in ("ESCALATION",):
            continue
        try:
            ev_ts = time.mktime(time.strptime(ev["ts"], "%Y-%m-%d %H:%M:%S"))
        except Exception:
            continue
        if ev_ts < cutoff:
            esc_key = f"_esc_{aid}"
            if esc_key not in cfg._last_alerts:
                cfg._last_alerts[esc_key] = time.time()
                msg = f"[ESCALATION] Unacknowledged alert on '{cfg.name}': {ev['message']}"
                _add_history(cfg, "ESCALATION", msg)
                sender.send(f"ESCALATION: {cfg.name}", msg, None,
                    alert_type="ESCALATION", stream=cfg.name,
                    level_dbfs=float(cfg._last_level_dbfs))
                log_fn(f"[ESCALATION] {msg}")


# ─── RTP / Livewire receive ───────────────────────────────────────────────────

def _lw_ip(sid: int) -> str:
    return f"239.192.{(sid>>8)&0xFF}.{sid&0xFF}"

def _parse_device(dev: str) -> Tuple[str,int]:
    s=dev.strip()
    if "." in s:
        if ":" in s: ip,p=s.rsplit(":",1); return ip,int(p)
        return s,5004
    return _lw_ip(int(s)),5004

def _detect_fmt(psz,pt):
    if pt in (10,11):
        ch=2 if pt==10 else 1; return "L16",2,ch,f"AES67 L16 {'stereo' if ch==2 else 'mono'}"
    KNOWN={72:("LIVEWIRE",3,2,"Native Livewire 0.25ms"),144:("LIVEWIRE",3,2,"Native Livewire 0.5ms"),
           288:("AES67",3,2,"AES67 1ms"),1440:("LIVEWIRE",3,2,"Standard Livewire 5ms"),
           576:("LIVEWIRE",3,4,"Native Livewire 4ch"),864:("LIVEWIRE",3,6,"Native Livewire 6ch"),
           1152:("LIVEWIRE",3,8,"Native Livewire 8ch")}
    if psz in KNOWN: return KNOWN[psz]
    if psz%6==0: return "LIVEWIRE",3,2,f"Native Livewire {psz//6/48:.2f}ms"
    if psz%4==0: return "L16",2,2,f"AES67 L16 {psz//4/48:.2f}ms"
    if psz%2==0: return "L16",2,2,"L16 (inferred)"
    return "LIVEWIRE",3,2,"Unknown (defaulted)"

def _decode(payload,fmt,ch):
    try:
        if fmt in ("LIVEWIRE","L24","AES67"):
            raw=bytearray(payload); ns=len(raw)//(3*ch); vals=[]
            for i in range(ns*ch):
                b0,b1,b2=raw[i*3],raw[i*3+1],raw[i*3+2]
                v=(b0<<16)|(b1<<8)|b2
                if v&0x800000: v-=0x1000000
                vals.append(v/8388608.0)
            samp=np.array(vals,dtype=np.float32)
        else:
            samp=np.frombuffer(payload,dtype=">i2").astype(np.float32)/32768.0
        if ch>1:
            if samp.size%ch!=0: return None
            samp=samp.reshape(-1,ch).mean(axis=1)
        return samp
    except: return None

# ─── Monitor manager ──────────────────────────────────────────────────────────

# ─── PTP Monitor ─────────────────────────────────────────────────────────────

class PTPMonitor:
    """
    Listens to PTP (IEEE 1588 / AES67) multicast on 224.0.1.129.
    Parses Sync + Follow_Up messages to measure offset and jitter.
    Does NOT require linuxptp or any external tool — pure raw socket.

    Offset calculation:
      When we receive a Sync (or Follow_Up with precise originTimestamp),
      we compare the PTP origin timestamp to our local wall clock.
      This gives a rough offset — not as accurate as a full PTP slave
      implementation (we don't send Delay_Req) but good enough to detect
      drift, jitter and sync loss.
    """

    def __init__(self, log_fn, sender):
        self.log    = log_fn
        self.sender = sender

        # Status visible to the dashboard
        self.status:       str   = "Waiting for PTP…"
        self.state:        str   = "idle"   # idle | ok | warn | alert | lost
        self.gm_id:        str   = ""       # grandmaster clock identity (hex)
        self.domain:       int   = 0
        self.offset_us:    float = 0.0      # latest offset µs
        self.jitter_us:    float = 0.0      # rolling std-dev of offset
        self.last_sync:    float = 0.0      # time.time() of last Sync received
        self.history:      List[Dict] = []
        # pmc_mode=True when data comes from the linuxptp pmc tool (accurate,
        # includes path delay compensation).  False = passive raw-socket listener
        # (offset includes uncompensated one-way path delay — not a true PTP offset).
        self.pmc_mode:     bool  = False
        self.path_delay_us: float = 0.0    # meanPathDelay from pmc (informational)

        self._offsets: collections.deque = collections.deque(maxlen=PTP_HISTORY_LEN)
        self._offset_baseline: Optional[float] = None
        self.drift_us: float = 0.0
        self._last_alerts: Dict[str,float] = {}
        self._pending_sync: Dict[int, float] = {}  # seq_id → local rx time
        self._seq_origin:   Dict[int, int]   = {}  # seq_id → origin ns (Follow_Up)

    # ── PTP packet parsing ────────────────────────────────────────────────────

    @staticmethod
    def _parse_header(data: bytes):
        """Parse the 44-byte PTP v2 common header. Returns dict or None."""
        if len(data) < 44:
            return None
        msg_type   = data[0] & 0x0F
        version    = data[1] & 0x0F
        if version != 2:
            return None
        msg_len    = struct.unpack_from(">H", data, 2)[0]
        domain     = data[4]
        flags      = struct.unpack_from(">H", data, 6)[0]
        correction = struct.unpack_from(">q", data, 8)[0]   # ns << 16
        src_id     = data[20:28].hex()   # clockIdentity
        src_port   = struct.unpack_from(">H", data, 28)[0]
        seq_id     = struct.unpack_from(">H", data, 30)[0]
        ctrl       = data[32]
        return {
            "type": msg_type, "domain": domain, "flags": flags,
            "correction_ns": correction >> 16,
            "src_id": src_id, "src_port": src_port,
            "seq_id": seq_id, "ctrl": ctrl,
        }

    @staticmethod
    def _parse_timestamp(data: bytes, offset: int) -> int:
        """
        Parse a 10-byte PTP v2 timestamp at offset → nanoseconds since epoch.
        Layout: [4 bytes seconds-high][2 bytes seconds-low][4 bytes nanoseconds]
        """
        if len(data) < offset + 10:
            return 0
        secs  = struct.unpack_from(">IH", data, offset)
        secs_val = (secs[0] << 16) | secs[1]
        ns    = struct.unpack_from(">I", data, offset + 6)[0]
        return secs_val * 1_000_000_000 + ns

    @staticmethod
    def _parse_clock_id(data: bytes, offset: int) -> str:
        if len(data) < offset + 8:
            return ""
        return data[offset:offset+8].hex()

    # ── Core analysis ─────────────────────────────────────────────────────────

    def _process_offset(self, origin_ns: int, correction_ns: int, gm_id: str, domain: int):
        """Called with a known origin timestamp — compute offset vs local clock."""
        if origin_ns <= 0:
            return
        local_ns  = int(time.time() * 1e9)
        # PTP can carry TAI (Axia/Livewire) or UTC (linuxptp/ptp4l).
        # TAI is currently 37 seconds ahead of UTC.
        # Auto-detect: try with TAI correction first; if the result is still
        # huge (~37 s off), the source is already UTC — use raw offset instead.
        TAI_OFFSET_NS = 37 * 1_000_000_000
        offset_tai_ns = local_ns - (origin_ns - TAI_OFFSET_NS) - correction_ns
        offset_raw_ns = local_ns - origin_ns - correction_ns
        # Pick whichever interpretation gives the smaller offset
        if abs(offset_raw_ns) < abs(offset_tai_ns):
            offset_ns = offset_raw_ns   # source sends UTC (e.g. ptp4l)
        else:
            offset_ns = offset_tai_ns   # source sends TAI (e.g. Axia)
        offset_us = offset_ns / 1000.0
        # Sanity guard — >5s means something is wrong
        if abs(offset_us) > 5_000_000:
            self.log(f"[PTP] Offset {offset_us/1e6:.2f}s out of range — skipping")
            return
        # We are not a PTP slave so the absolute offset vs local clock is meaningless.
        # Instead we track a slow-moving baseline and alert on DRIFT from that baseline.
        if not hasattr(self, '_offset_baseline') or self._offset_baseline is None:
            self._offset_baseline = offset_us   # seed baseline on first sample
        # EMA baseline — alpha=0.05 adapts over ~20 samples, fast enough
        # to track NTP corrections without false drift alarms
        self._offset_baseline = 0.95 * self._offset_baseline + 0.05 * offset_us
        # drift = deviation from rolling baseline
        self.drift_us = offset_us - self._offset_baseline
        self.offset_us = offset_us
        self.domain    = domain
        self.last_sync = time.time()

        # Grandmaster change detection — also re-seeds baseline
        if self.gm_id and self.gm_id != gm_id:
            self.log(f"[PTP] Grandmaster changed: {self.gm_id} → {gm_id}")
            self._add_history("PTP_GM_CHANGE",
                f"Grandmaster changed from {self.gm_id} to {gm_id}")
            self._offset_baseline = offset_us  # re-seed on GM change
        self.gm_id = gm_id

        self._offsets.append(offset_us)
        if len(self._offsets) >= 3:
            self.jitter_us = float(np.std(list(self._offsets)))

        self._evaluate()

    def _evaluate(self):
        """Check thresholds and alert on DRIFT from baseline and jitter.
        In pmc_mode the offset is accurate (path delay compensated) so both
        drift and jitter thresholds apply normally.
        In passive mode the offset includes uncompensated one-way path delay
        so jitter is dominated by path-delay variance (not clock jitter) —
        only alert on very large changes; suppress jitter warn entirely."""
        drift   = abs(getattr(self, 'drift_us', 0.0))
        jitter  = self.jitter_us
        now     = time.time()

        cfg = monitor.app_cfg
        o_warn  = cfg.ptp_offset_warn_us
        o_alert = cfg.ptp_offset_alert_us
        if self.pmc_mode:
            # Accurate data: use configured jitter thresholds
            j_warn  = cfg.ptp_jitter_warn_us
            j_alert = cfg.ptp_jitter_alert_us
        else:
            # Passive listener: jitter reflects path-delay variance, not clock
            # instability — raise thresholds to avoid false alarms
            j_warn  = 50_000   # 50 ms — only warn on severe instability
            j_alert = 200_000  # 200 ms — only alert on very severe
        if drift >= o_alert or jitter >= j_alert:
            new_state = "alert"
        elif drift >= o_warn or jitter >= j_warn:
            new_state = "warn"
        else:
            new_state = "ok"

        self.state = new_state

        off_sign = "+" if self.offset_us >= 0 else ""
        drift_sign = "+" if getattr(self,'drift_us',0) >= 0 else ""
        self.status = (
            f"[{new_state.upper()}] "
            f"Offset: {off_sign}{self.offset_us/1000:.3f} ms  "
            f"Drift: {drift_sign}{getattr(self,'drift_us',0)/1000:.3f} ms  "
            f"Jitter: {jitter/1000:.3f} ms  "
            f"GM: {self.gm_id[:16]}  Domain: {self.domain}"
        )

        if new_state in ("alert", "warn"):
            reasons = []
            if drift >= o_warn:
                reasons.append(f"drift {getattr(self,'drift_us',0)/1000:.2f} ms")
            if jitter >= j_warn:
                reasons.append(f"jitter {jitter/1000:.2f} ms")

            key = f"PTP_{new_state}"
            cd  = ALERT_COOLDOWN if new_state == "alert" else ALERT_COOLDOWN * 2
            if now - self._last_alerts.get(key, 0) >= cd:
                self._last_alerts[key] = now
                msg = f"PTP {new_state.upper()}: {', '.join(reasons)}"
                self._add_history(f"PTP_{new_state.upper()}", msg)
                self.log(f"[PTP] {msg}")
                self.sender.send(f"PTP {new_state.upper()} — clock issue", msg,
                             alert_type=f"PTP_{new_state.upper()}", ptp_state=new_state)

    def _check_sync_loss(self):
        """Called periodically — fires alert if no Sync seen recently."""
        if self.last_sync == 0:
            return   # haven't seen any PTP yet
        gap = time.time() - self.last_sync
        if gap > PTP_SYNC_TIMEOUT:
            self.state  = "lost"
            self.status = f"[LOST] No PTP Sync for {gap:.0f}s"
            key = "PTP_LOST"
            now = time.time()
            if now - self._last_alerts.get(key, 0) >= ALERT_COOLDOWN:
                self._last_alerts[key] = now
                msg = f"PTP Sync loss — no message for {gap:.0f}s"
                self._add_history("PTP_LOST", msg)
                self.log(f"[PTP] {msg}")
                self.sender.send("PTP SYNC LOSS", msg,
                             alert_type="PTP_LOST", ptp_state="lost")

    def _add_history(self, kind: str, msg: str):
        self.history.append({
            "timestamp": time.strftime("%H:%M:%S"),
            "type": kind, "message": msg,
        })
        if len(self.history) > 200:
            self.history = self.history[-200:]

    # ── Receive loop ──────────────────────────────────────────────────────────

    def _try_pmc(self) -> bool:
        """Read accurate PTP slave data from the linuxptp pmc tool.

        pmc queries the running ptp4l daemon for CURRENT_DATA_SET, which
        contains the actual offsetFromMaster (path-delay compensated) and
        meanPathDelay.  Returns True if offset was obtained.

        Falls back to passive-listener data if pmc is not installed or
        ptp4l is not running.
        """
        import shutil as _sh, subprocess as _sp, re as _re
        pmc = _sh.which("pmc")
        if not pmc:
            return False
        try:
            out = _sp.check_output(
                [pmc, "-u", "-b", "0", "GET CURRENT_DATA_SET"],
                timeout=3, stderr=_sp.DEVNULL,
            ).decode(errors="replace")
            m = _re.search(r'offsetFromMaster\s+(-?\d+)', out)
            if not m:
                return False
            offset_ns = int(m.group(1))
            offset_us = offset_ns / 1000.0
            # meanPathDelay (ns → µs, informational)
            md = _re.search(r'meanPathDelay\s+(-?\d+)', out)
            if md:
                self.path_delay_us = int(md.group(1)) / 1000.0
            # Seed / advance baseline
            if self._offset_baseline is None:
                self._offset_baseline = offset_us
            self._offset_baseline = 0.95 * self._offset_baseline + 0.05 * offset_us
            self.drift_us  = offset_us - self._offset_baseline
            self.offset_us = offset_us
            self.last_sync = time.time()
            self._offsets.append(offset_us)
            if len(self._offsets) >= 3:
                self.jitter_us = float(np.std(list(self._offsets)))
            if not self.pmc_mode:
                self.log("[PTP] pmc available — switching to accurate slave-mode data")
                self.pmc_mode = True
            self._evaluate()
            return True
        except Exception:
            return False

    def _pmc_poller(self, stop_evt: threading.Event):
        """Background thread: poll pmc every 10 s for accurate PTP data."""
        # Stagger first poll by 5 s to let the passive listener start first
        stop_evt.wait(5)
        while not stop_evt.is_set():
            self._try_pmc()
            stop_evt.wait(10)

    def run(self, stop_evt: threading.Event, iface_ip: str = "0.0.0.0"):
        """Main receive loop — runs in its own thread."""
        self.log("[PTP] Starting monitor on 224.0.1.129:319/320")
        # Start pmc poller alongside passive listener — whichever provides data wins
        _pmc_t = threading.Thread(target=self._pmc_poller, args=(stop_evt,),
                                  daemon=True, name="PTPpmc")
        _pmc_t.start()

        # We listen on the event port (319) for Sync,
        # and general port (320) for Follow_Up / Announce
        socks = []
        for port in (PTP_EVENT_PORT, PTP_GENERAL_PORT):
            try:
                s = socket.socket(socket.AF_INET, socket.SOCK_DGRAM, socket.IPPROTO_UDP)
                s.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
                try: s.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEPORT, 1)
                except AttributeError: pass
                s.bind(("", port))
                mreq = struct.pack("4s4s",
                    socket.inet_aton(PTP_MULTICAST_IP),
                    socket.inet_aton(iface_ip))
                s.setsockopt(socket.IPPROTO_IP, socket.IP_ADD_MEMBERSHIP, mreq)
                s.settimeout(1.0)
                socks.append(s)
                self.log(f"[PTP] Joined {PTP_MULTICAST_IP}:{port}")
            except Exception as e:
                self.log(f"[PTP] Socket {port} failed: {e}")

        if not socks:
            self.state  = "lost"
            self.status = "Could not open PTP sockets — check network interface"
            return

        last_loss_check = time.time()

        while not stop_evt.is_set():
            import select as _select
            try:
                readable, _, _ = _select.select(socks, [], [], 1.0)
            except Exception:
                time.sleep(0.5); continue

            for s in readable:
                try:
                    data, addr = s.recvfrom(1024)
                except Exception:
                    continue

                hdr = self._parse_header(data)
                if hdr is None:
                    continue

                msg_type = hdr["type"]
                seq_id   = hdr["seq_id"]
                domain   = hdr["domain"]

                # MSG_TYPE 0x0 = Sync, 0x8 = Follow_Up, 0xB = Announce


                if msg_type == 0x0:   # Sync
                    self.last_sync = time.time()
                    self.gm_id = hdr["src_id"]
                    if self.state == "idle":
                        self.state  = "ok"
                        self.status = f"PTP Sync received — GM: {hdr['src_id'][:16]}"
                    two_step = bool(hdr["flags"] & 0x0200)
                    if two_step:
                        self._pending_sync[seq_id] = time.time()
                    else:
                        origin_ns  = self._parse_timestamp(data, 44)
                        correction = hdr["correction_ns"]
                        self._process_offset(origin_ns, correction, hdr["src_id"], domain)

                elif msg_type == 0x8:  # Follow_Up
                    # Axia Mix Engine: originTimestamp at byte 34 (immediately after 34-byte header)
                    origin_ns  = self._parse_timestamp(data, 34)
                    correction = hdr["correction_ns"]
                    gm_id      = hdr["src_id"]
                    if seq_id in self._pending_sync:
                        del self._pending_sync[seq_id]
                    self._process_offset(origin_ns, correction, gm_id, domain)

                elif msg_type == 0xB:  # Announce — update GM from grandmasterIdentity
                    # grandmasterIdentity is at byte 44+20 = 64 in Announce body
                    gm_id = self._parse_clock_id(data, 64)
                    if gm_id and gm_id != self.gm_id:
                        if self.gm_id:
                            msg = f"Grandmaster changed: {self.gm_id} → {gm_id}"
                            self._add_history("PTP_GM_CHANGE", msg)
                            self.log(f"[PTP] {msg}")
                        self.gm_id = gm_id

            # Expire stale pending syncs
            now = time.time()
            self._pending_sync = {k: v for k,v in self._pending_sync.items()
                                  if now - v < 2.0}

            # Periodic sync-loss check
            if now - last_loss_check >= 2.0:
                self._check_sync_loss()
                last_loss_check = now

        for s in socks:
            try: s.close()
            except: pass
        self.log("[PTP] Monitor stopped.")


# ─── Stream Comparator (pre/post with cross-correlation alignment) ─────────────

class StreamComparator:
    """
    Compares two audio streams (pre/post) using block-level RMS analysis.

    ALL correlation and delay work operates on 100 ms RMS blocks rather than
    raw samples.  This makes every step robust through any kind of processing
    (AGC, compression, limiting, multiband, EQ) because programme structure
    (speech/music events, silence, transitions) is preserved in the RMS
    envelope even when the waveform is completely transformed.

    Delay detection: cross-correlate RMS block sequences (not waveforms).
    The block xcorr gives a clean, unambiguous peak for both clean and heavily
    processed paths, and searches both ±directions so it doesn’t matter which
    way round the pre/post assignment is.

    Correlation score: Pearson of aligned RMS block sequences.
    With 150 × 100 ms blocks (~15 seconds), n = 150 independent data points →
    standard error ≈ 0.08.  Far more stable than previous 2-second sub-window
    approach which had n_eff ≈ 10–15 and produced wildly variable estimates.

    Processor auto-detection:
    1. Gain gap |pre_dBFS − post_dBFS| > _PROC_GAIN_GAP_DB (8 dB)
    2. Block RMS std ratio outside [_PROC_DYN_LO, _PROC_DYN_HI] — the ratio
       can go either way (processor could make the output more OR less dynamic
       than the input depending on where in the chain you monitor).
    """

    _PROC_GAIN_GAP_DB = 8.0    # level gap (dB) → processor likely in path
    _PROC_DYN_LO      = 0.35   # block_std ratio below this → heavy compression
    _PROC_DYN_HI      = 2.80   # block_std ratio above this → unusual, flag anyway
    _BLOCK_SZ         = 4800   # 100 ms @ 48 kHz — one RMS block
    _CORR_BLOCKS      = 150    # blocks used for Pearson score (15 seconds)
    _MIN_BLOCKS       = 30     # minimum blocks needed before computing anything

    def __init__(self, pre: InputConfig, post: InputConfig, log_fn, sender):
        self.pre    = pre
        self.post   = post
        self.log    = log_fn
        self.sender = sender
        self.delay_samples: int   = 0
        self.aligned:       bool  = False
        self.status:        str   = "Finding delay…"
        self._last_alerts:  Dict[str,float] = {}
        self._last_align:   float = 0.0
        self._started_at:        float         = time.monotonic()
        self._baseline_gain_diff: Optional[float] = None  # set after warmup
        # Live metrics updated every COMPARE_INTERVAL
        self.delay_ms:          float = 0.0
        self.correlation:       float = 0.0
        self.pre_dbfs:          float = -80.0
        self.post_dbfs:         float = -80.0
        self.gain_diff_db:      float = 0.0
        self.cmp_history:       list  = []
        # Processor detection
        self.processed:         bool  = False
        self.compression_ratio: float = 1.0

    # ── Block RMS helper ──────────────────────────────────────────────────────

    @classmethod
    def _block_rms(cls, audio: np.ndarray) -> np.ndarray:
        """Return array of RMS values for each 100 ms block.

        Reshapes audio into (n_blocks, _BLOCK_SZ) and computes RMS per row.
        Fast vectorised operation — no Python loops.
        """
        n = len(audio) // cls._BLOCK_SZ
        if n == 0:
            return np.array([], dtype=np.float64)
        frames = audio[:n * cls._BLOCK_SZ].reshape(n, cls._BLOCK_SZ).astype(np.float64)
        return np.sqrt(np.mean(frames ** 2, axis=1))

    # ── Delay detection via block xcorr ──────────────────────────────────────

    @classmethod
    def _block_delay(cls, pre_blocks: np.ndarray,
                     post_blocks: np.ndarray) -> int:
        """Find delay (in blocks) via block RMS cross-correlation.

        Cross-correlation convention: R[lag] = sum(pre[t] * post[t+lag]).
        Peak at +L means pre[t] best matches post[t+L] — post is delayed by L
        blocks.  Searching both positive and negative halves handles the case
        where the pre/post assignment is opposite to the signal-flow direction.

        Returns signed lag in blocks: +L → post delayed, −L → pre delayed.
        """
        nm = min(len(pre_blocks), len(post_blocks))
        if nm < 4:
            return 0
        pre_n  = pre_blocks[:nm].copy().astype(np.float64)
        post_n = post_blocks[:nm].copy().astype(np.float64)
        # Zero-mean, unit variance
        pre_n  = (pre_n  - pre_n.mean())  / (pre_n.std()  + 1e-10)
        post_n = (post_n - post_n.mean()) / (post_n.std() + 1e-10)

        # Full circular xcorr — pad to ≥ 2*nm−1 to avoid aliasing
        nfft = 1 << (2 * nm - 1).bit_length()
        xcorr = np.fft.irfft(
            np.conj(np.fft.rfft(pre_n, nfft)) * np.fft.rfft(post_n, nfft),
            nfft
        )
        # Limit search to ±COMPARE_SEARCH_SECS
        max_lag = min(int(COMPARE_SEARCH_SECS * 1000 / 100), nm // 2)

        # Positive lags  xcorr[0 .. max_lag]  (post delayed)
        best_pos = int(np.argmax(xcorr[:max_lag + 1]))

        # Negative lags live at the TAIL of the circular buffer:
        #   xcorr[nfft − k]  ==  lag −k   for k = 1 … max_lag
        # neg_vals[i] = xcorr[nfft − max_lag + i]  ==  lag −(max_lag − i)
        neg_vals    = xcorr[nfft - max_lag : nfft]      # length = max_lag
        best_neg_i  = int(np.argmax(neg_vals))
        best_neg_lag = -(max_lag - best_neg_i)           # convert index → signed lag

        if xcorr[best_pos] >= neg_vals[best_neg_i]:
            return best_pos
        else:
            return best_neg_lag

    # ── Pearson of aligned block sequences ───────────────────────────────────

    @staticmethod
    def _block_pearson(pre_blocks: np.ndarray,
                       post_blocks: np.ndarray,
                       lag: int,
                       n_blocks: int) -> float:
        """Pearson of the most recent n_blocks aligned block pairs.

        XCorr peak at +L means R[L]=sum(pre[t]*post[t+L]) is maximum, so
        pre[t] matches post[t+L].  The aligned pairs for the most recent
        n_blocks of POST are:

            a = pre_blocks[-(n_blocks + L) : -L]   (or pre[-n:] when L=0)
            b = post_blocks[-n_blocks:]

        For negative lag (−L, pre delayed):

            a = pre_blocks[-n_blocks:]
            b = post_blocks[-(n_blocks + L) : -L]
        """
        np_pre, np_post = len(pre_blocks), len(post_blocks)
        if lag > 0:
            n = min(n_blocks, np_pre - lag, np_post)
            if n < 10:
                return 0.0
            a = pre_blocks[-(n + lag): -lag]
            b = post_blocks[-n:]
        elif lag < 0:
            k = -lag
            n = min(n_blocks, np_pre, np_post - k)
            if n < 10:
                return 0.0
            a = pre_blocks[-n:]
            b = post_blocks[-(n + k): -k]
        else:
            n = min(n_blocks, np_pre, np_post)
            if n < 10:
                return 0.0
            a = pre_blocks[-n:]
            b = post_blocks[-n:]
        ml = min(len(a), len(b))
        if ml < 10:
            return 0.0
        a = a[:ml].astype(np.float64)
        b = b[:ml].astype(np.float64)
        sa = float(np.std(a) + 1e-12)
        sb = float(np.std(b) + 1e-12)
        r  = float(np.mean((a - a.mean()) * (b - b.mean())) / (sa * sb))
        return float(np.clip(r, 0.0, 1.0))

    # ── Logging helper ────────────────────────────────────────────────────────

    def _log_cmp_event(self, msg: str):
        ts = time.strftime("%H:%M:%S")
        self.cmp_history.append({"ts": ts, "msg": msg})
        if len(self.cmp_history) > 8:
            self.cmp_history.pop(0)

    # ── Main update loop ──────────────────────────────────────────────────────

    def update(self):
        """Call periodically.  Re-aligns if needed, then measures correlation."""
        now = time.time()

        # ── Collect audio and convert to RMS blocks ────────────────────────
        pre_chunks  = list(self.pre._stream_buffer)  if self.pre._stream_buffer  else []
        post_chunks = list(self.post._stream_buffer) if self.post._stream_buffer else []
        if not pre_chunks or not post_chunks:
            self.status = "Waiting for audio buffers…"
            return
        pre_audio  = np.concatenate(pre_chunks).astype(np.float32)
        post_audio = np.concatenate(post_chunks).astype(np.float32)

        pre_blocks  = self._block_rms(pre_audio)
        post_blocks = self._block_rms(post_audio)
        if len(pre_blocks) < self._MIN_BLOCKS or len(post_blocks) < self._MIN_BLOCKS:
            self.status = "Buffering…"
            return

        # ── Level metrics (from full available blocks) ─────────────────────
        nm = min(len(pre_blocks), len(post_blocks))
        pre_rms_mean  = max(float(np.mean(pre_blocks[-nm:])),  1e-10)
        post_rms_mean = max(float(np.mean(post_blocks[-nm:])), 1e-10)
        self.pre_dbfs     = 20 * math.log10(pre_rms_mean)
        self.post_dbfs    = 20 * math.log10(post_rms_mean)
        self.gain_diff_db = round(self.post_dbfs - self.pre_dbfs, 1)
        pre_has_audio     = self.pre_dbfs  > COMPARE_SILENCE_THRESH
        post_has_audio    = self.post_dbfs > COMPARE_SILENCE_THRESH

        # ── Delay detection and processor check (every COMPARE_INTERVAL) ──
        if now - self._last_align > COMPARE_INTERVAL or not self.aligned:
            lag_blocks = self._block_delay(pre_blocks, post_blocks)
            self.delay_samples = lag_blocks * self._BLOCK_SZ
            self.delay_ms      = abs(self.delay_samples) / SAMPLE_RATE * 1000
            self.aligned       = True
            self._last_align   = now

            # Processor detection via gain gap AND block-std ratio
            gain_gap    = abs(self.gain_diff_db)
            pre_bstd    = float(np.std(pre_blocks[-nm:])  + 1e-10)
            post_bstd   = float(np.std(post_blocks[-nm:]) + 1e-10)
            comp_ratio  = post_bstd / pre_bstd
            is_proc = (gain_gap > self._PROC_GAIN_GAP_DB
                       or comp_ratio < self._PROC_DYN_LO
                       or comp_ratio > self._PROC_DYN_HI)
            if is_proc and not self.processed:
                reason = (f"gain gap {gain_gap:.1f} dB" if gain_gap > self._PROC_GAIN_GAP_DB
                          else f"comp ratio {comp_ratio:.2f}")
                self.log(f"[CMP:{self.pre.name}→{self.post.name}] "
                         f"Audio processor detected ({reason})")
                self._log_cmp_event(
                    f"⚙ Processor detected ({reason}) — block RMS correlation"
                )
            self.processed         = is_proc
            self.compression_ratio = round(comp_ratio, 3)
            mode = "block-RMS" + (" processed" if is_proc else " clean")
            self.log(f"[CMP:{self.pre.name}→{self.post.name}] "
                     f"Lag {lag_blocks:+d} blocks ({self.delay_ms:.0f} ms)  "
                     f"mode={mode}  comp_ratio={comp_ratio:.2f}")

        # ── Correlation: Pearson of aligned block sequences ────────────────
        lag_blocks = self.delay_samples // self._BLOCK_SZ
        self.correlation = self._block_pearson(
            pre_blocks, post_blocks, lag_blocks, self._CORR_BLOCKS
        )

        # ── Silence / dropout alerts ───────────────────────────────────────
        proc_note = (f" (processor detected, comp ratio {self.compression_ratio:.2f})"
                     if self.processed else "")

        if pre_has_audio and not post_has_audio:
            key = "CMP_POST_SILENT"
            if now - self._last_alerts.get(key, 0) >= ALERT_COOLDOWN:
                self._last_alerts[key] = now
                msg = (f"POST ‘{self.post.name}’ silent while PRE ‘{self.pre.name}’ "
                       f"has audio ({self.pre_dbfs:.1f} dBFS) — possible processor failure{proc_note}")
                self.status = "⚠ POST SILENT"
                _add_history(self.pre, "CMP_ALERT", msg)
                self._log_cmp_event("⚠ POST silent / processor failure")
                self.log(f"[CMP] {msg}")
                snippet = _save_alert_wav(self.post, "compare_post_silent")
                self.sender.send(f"Stream Compare ALERT — {self.post.name} silent", msg, snippet,
                                 alert_type="CMP_ALERT", stream=self.post.name,
                                 level_dbfs=self.post_dbfs)

        elif post_has_audio and not pre_has_audio:
            key = "CMP_PRE_SILENT"
            if now - self._last_alerts.get(key, 0) >= ALERT_COOLDOWN:
                self._last_alerts[key] = now
                msg = (f"PRE ‘{self.pre.name}’ silent/dropout while POST "
                       f"’{self.post.name}’ has audio — possible RTP loss on pre path{proc_note}")
                self.status = "⚠ PRE DROPOUT"
                _add_history(self.post, "CMP_ALERT", msg)
                self._log_cmp_event("⚠ PRE dropout / RTP loss")
                self.log(f"[CMP] {msg}")
                snippet = _save_alert_wav(self.pre, "compare_pre_dropout")
                self.sender.send(f"Stream Compare ALERT — {self.pre.name} dropout", msg, snippet,
                                 alert_type="CMP_ALERT", stream=self.pre.name,
                                 level_dbfs=self.pre_dbfs)

        else:
            # Grace period: suppress all startup alerts until the Pearson and
            # level estimates have fully warmed up.  35 s covers the 15 s block
            # accumulation window plus the gain/delay settling time.
            _grace_secs = self._CORR_BLOCKS * 0.1 + 20.0   # 35 s
            _warmed_up  = (time.monotonic() - self._started_at) >= _grace_secs

            # ── Gain-shift detection ───────────────────────────────────────
            # Baseline is set only after warmup so an unstable early reading
            # can’t lock in a wrong reference and immediately fire a false alert.
            if _warmed_up and self._baseline_gain_diff is None:
                self._baseline_gain_diff = self.gain_diff_db
            if _warmed_up and self._baseline_gain_diff is not None:
                gain_drift = abs(self.gain_diff_db - self._baseline_gain_diff)
                gain_alert_thresh = getattr(self.pre, "compare_gain_alert_db", 3.0)
                if gain_drift > gain_alert_thresh:
                    key = "CMP_GAIN_SHIFT"
                    if now - self._last_alerts.get(key, 0) >= ALERT_COOLDOWN * 4:
                        self._last_alerts[key] = now
                        msg = (f"Gain shift on ‘{self.post.name}’: "
                               f"{self.gain_diff_db:+.1f} dB vs baseline "
                               f"{self._baseline_gain_diff:+.1f} dB{proc_note}")
                        self._log_cmp_event(f"⚠ Gain shift {self.gain_diff_db:+.1f} dB")
                        _add_history(self.pre, "CMP_ALERT", msg)
                        self.log(f"[CMP] {msg}")
                        self.sender.send(f"Stream Compare — Gain shift on {self.post.name}", msg, None,
                                         alert_type="CMP_ALERT", stream=self.post.name,
                                         level_dbfs=self.post_dbfs)
                elif gain_drift < 1.0:
                    self._baseline_gain_diff = (0.98 * self._baseline_gain_diff
                                                + 0.02 * self.gain_diff_db)

            # ── Low correlation alert ──────────────────────────────────────
            # Processed paths have inherently lower envelope correlation due to
            # AGC/limiting squashing dynamics — use relaxed thresholds.
            if self.processed:
                corr_label = (
                    "excellent" if self.correlation >= 0.75 else
                    "good"      if self.correlation >= 0.50 else
                    "weak"      if self.correlation >= 0.30 else
                    "poor"
                )
                corr_alert_thresh = 0.30
            else:
                corr_label = (
                    "excellent" if self.correlation >= 0.85 else
                    "good"      if self.correlation >= 0.65 else
                    "weak"      if self.correlation >= 0.40 else
                    "poor"
                )
                corr_alert_thresh = 0.40
            mode_label = "block-RMS" + (" processed" if self.processed else "")
            self.status = f"OK ({corr_label} {mode_label} corr)"
            if self.correlation < corr_alert_thresh and pre_has_audio and post_has_audio and _warmed_up:
                key = "CMP_LOW_CORR"
                if now - self._last_alerts.get(key, 0) >= ALERT_COOLDOWN * 6:
                    self._last_alerts[key] = now
                    msg = (f"Low correlation ({self.correlation:.2f}) between "
                           f"’{self.pre.name}’ and ‘{self.post.name}’ — "
                           f"streams may have diverged{proc_note}")
                    self._log_cmp_event(f"⚠ Low corr {self.correlation:.2f} ({mode_label})")
                    _add_history(self.pre, "CMP_ALERT", msg)
                    self.log(f"[CMP] {msg}")
                    self.sender.send(f"Stream Compare — Low correlation {self.post.name}", msg, None,
                                     alert_type="CMP_ALERT", stream=self.post.name)


@dataclass
class DabSharedSession:
    key: tuple
    serial: Optional[str]
    device_idx: int
    channel: str
    dab_port: int
    ppm: int = 0
    gain: int = -1             # RTL-SDR gain in tenths of dB; -1 = hardware AGC
    proc: Any = None
    lease: Any = None
    ready: threading.Event = field(default_factory=threading.Event)
    stop_evt: threading.Event = field(default_factory=threading.Event)
    mux: dict = field(default_factory=dict)
    failed: bool = False
    refcount: int = 0
    consumers: set = field(default_factory=set)
    stderr_thread: Any = None
    poll_thread: Any = None


class MonitorManager:
    def __init__(self):
        self.app_cfg=load_config()
        self._lock=threading.Lock(); self._running=False
        self._threads: List[threading.Thread]=[]
        self._stop_flags: List[threading.Event]=[]
        self._log=collections.deque(maxlen=2000)
        self._stream_ais: Dict[str,StreamAI]={}
        self.ptp: Optional[PTPMonitor]=None
        self._comparators: List[StreamComparator]=[]
        self._report_sent_date: str=""
        self._metrics_last_flush: float = 0.0   # unix ts of last metrics write
        self._metrics_last_prune: str   = ""    # date string "YYYY-MM-DD" of last prune
        self._hub_client: Optional[HubClient]=None
        self._dab_sessions: Dict[tuple, DabSharedSession]={}
        self._dab_sessions_lock=threading.Lock()
        # Per-device USB backoff: when usb_claim_interface error is seen, all
        # streams for that device index wait until this timestamp before retrying.
        # Prevents rapid-fire welle-cli crash loops from locking up the USB bus.
        self._dab_usb_backoffs: Dict[int, float] = {}
        # Queue of (stream_name, label, clip_path, level_dbfs) tuples waiting
        # to be uploaded to the hub.  Drained by HubClient._loop() after each
        # successful heartbeat so clips reach the hub within one heartbeat cycle.
        self._hub_clip_queue: queue.Queue = queue.Queue(maxsize=500)

    def log(self,msg):
        line=f"[{time.strftime('%H:%M:%S')}] {msg}"
        self._log.append(line); print(line,flush=True)

    def get_logs(self,n=200): return list(self._log)[-n:]
    def is_running(self):
        with self._lock: return self._running

    def start_hub_client(self):
        """Start (or restart) the hub heartbeat client, independent of the monitor loop.

        Safe to call multiple times — if the client is already running and the
        hub URL/mode haven't changed it is a no-op.  If the URL or mode changed
        (e.g. user just saved settings) the old client is stopped and a new one
        started with the current configuration.
        """
        cfg = self.app_cfg
        if cfg.hub.mode in ("client", "both") and cfg.hub.hub_url:
            # Check if the running client is already pointing at the right URL
            if self._hub_client is not None:
                if getattr(self._hub_client, '_hub_url_at_start', None) == cfg.hub.hub_url:
                    return  # already running for this URL — nothing to do
                # URL or mode changed — stop the old client and start fresh
                self.log(f"[Hub] Hub URL changed — restarting client → {cfg.hub.hub_url}")
                self._hub_client.stop()
                self._hub_client = None
            self._hub_client = HubClient(lambda: self.app_cfg, self)
            self._hub_client._hub_url_at_start = cfg.hub.hub_url
            self._hub_client.start()
            self.log(f"[Hub] Client started → {cfg.hub.hub_url}")
        elif self._hub_client is not None:
            # Mode changed to non-client — stop the hub client
            self.log("[Hub] Hub client mode disabled — stopping client")
            self._hub_client.stop()
            self._hub_client = None

    def start_monitoring(self):
        with self._lock:
            if self._running: self.log("Already running."); return
            self._threads.clear(); self._stop_flags.clear(); self._stream_ais.clear()
            sender=AlertSender(self.app_cfg,self.log)

            udp_inputs=[]
            for cfg in self.app_cfg.inputs:
                if not cfg.enabled: continue
                _ensure_alert_buffer_capacity(cfg)
                cfg._stream_buffer=collections.deque(maxlen=int(SAMPLE_RATE*STREAM_BUFFER_SECONDS/CHUNK_SIZE)+2)
                cfg._baseline_learning_remaining=5.0; cfg._hf_baseline=None
                cfg._silence_secs=0.0; cfg._silence_active=False; cfg._silence_alert_key=""
                cfg._hiss_secs=0.0
                cfg._ai_status=""; cfg._ai_phase="idle"; cfg._ai_learn_samples=[]

                ai=StreamAI(cfg,self.log,sender); self._stream_ais[cfg.name]=ai; ai.start()
                dev=(cfg.device_index or '').strip().lower()
                if dev.startswith('dab://') or dev.startswith('fm://') or dev.startswith('http://') or dev.startswith('https://') or dev.startswith('sound://'):
                    stop=threading.Event(); self._stop_flags.append(stop)
                    t=threading.Thread(target=self._run_input,args=(cfg,sender,stop),daemon=True)
                    self._threads.append(t)
                else:
                    udp_inputs.append(cfg)

            if udp_inputs:
                udp_stop=threading.Event(); self._stop_flags.append(udp_stop)
                udp_t=threading.Thread(target=self._run_udp_inputs,args=(udp_inputs,sender,udp_stop),daemon=True)
                self._threads.append(udp_t)

            ai_stop=threading.Event(); self._stop_flags.append(ai_stop)
            ai_t=threading.Thread(target=self._ai_loop,args=(ai_stop,),daemon=True)
            self._threads.append(ai_t)
            # PTP monitor thread
            sender2=AlertSender(self.app_cfg,self.log)
            self.ptp=PTPMonitor(self.log, sender2)
            ptp_stop=threading.Event(); self._stop_flags.append(ptp_stop)
            ptp_t=threading.Thread(
                target=self.ptp.run,
                args=(ptp_stop, self.app_cfg.network.audio_interface_ip or "0.0.0.0"),
                daemon=True)
            self._threads.append(ptp_t)

            # Build stream comparators from compare_peer / compare_role config
            self._comparators.clear()
            _enabled_by_name = {c.name: c for c in self.app_cfg.inputs if c.enabled}
            for cfg in self.app_cfg.inputs:
                if not cfg.enabled: continue
                if cfg.compare_role == "pre" and cfg.compare_peer:
                    _peer = _enabled_by_name.get(cfg.compare_peer)
                    if _peer and _peer.compare_role == "post":
                        self._comparators.append(StreamComparator(cfg, _peer, self.log, sender))
                        self.log(f"[CMP] Comparator registered: '{cfg.name}' (pre) → '{_peer.name}' (post)")
                    elif _peer is None:
                        self.log(f"[CMP] Warning: peer '{cfg.compare_peer}' for '{cfg.name}' not found or disabled — comparator skipped")

            for t in self._threads: t.start()
            self._running=True
            self.log(f"[Monitor] Started — {sum(1 for i in self.app_cfg.inputs if i.enabled)} stream(s).")
            # Hub client runs independently of monitoring — started at app startup
            # and kept alive across stop/start cycles. Only launch it here if it
            # somehow never got started (e.g. app_cfg wasn't ready at boot time).
            if self._hub_client is None:
                self.start_hub_client()

    def stop_monitoring(self):
        with self._lock:
            if not self._running: return
            for e in self._stop_flags: e.set()
            for t in self._threads: t.join(timeout=2.0)
            self._threads.clear(); self._stop_flags.clear()
            self._comparators.clear()
            self._running=False; self.log("[Monitor] Stopped.")
            # Reset per-input metrics so the hub heartbeat immediately reports
            # silence/down for all streams rather than keeping stale healthy levels.
            for _inp in self.app_cfg.inputs:
                _inp._last_level_dbfs  = -120.0
                _inp._silence_secs     = 0.0
                _inp._silence_active   = False
                _inp._silence_alert_key= ""
                _inp._dab_ok           = False
                _inp._rtp_loss_pct    = 0.0

    def request_retrain(self, name: str):
        for inp in self.app_cfg.inputs:
            if inp.name==name:
                inp._ai_retrain_flag=True
                for p in (_model_path(name),_stats_path(name)):
                    try:
                        if os.path.exists(p): os.remove(p)
                    except: pass
                self.log(f"[AI] Retrain flagged for '{name}'.")
                return

    def _dab_session_key(self, serial, device_idx, channel):
        return (serial or f"idx:{device_idx}", str(channel).upper())

    def _copy_dab_metrics_from_mux(self, cfg, mux, service: str = ""):
        try:
            demod = mux.get("demodulator", {})
            cfg._dab_snr = float(demod.get("snr", cfg._dab_snr))
        except Exception:
            pass
        try:
            sig = mux.get("demodulator", {}).get("sigLevel")
            if sig is not None:
                cfg._dab_sig = float(sig)
        except Exception:
            pass
        try:
            ens = mux.get("ensemble", {})
            lbl = ens.get("label", {})
            cfg._dab_ensemble = (lbl.get("label", "") or lbl.get("shortlabel", "")).strip()
        except Exception:
            pass
        # Service-level metadata (mode, bitrate, stereo, DLS)
        if service:
            service_l = service.strip().lower()
            try:
                for svc in mux.get("services", []):
                    svc_lbl = svc.get("label", {})
                    svc_name = (svc_lbl.get("label", "") or svc_lbl.get("shortlabel", "")).strip()
                    if not (svc_name.lower() == service_l or service_l in svc_name.lower()):
                        continue
                    cfg._dab_mode   = svc.get("mode", cfg._dab_mode)
                    cfg._dab_stereo = svc.get("channels", 1) > 1
                    dls = svc.get("dynamicLabel", "") or svc.get("dls", "")
                    if dls:
                        # welle-cli returns dynamicLabel as a dict
                        # e.g. {'label': 'Now playing...', 'lastchange': 0, 'time': 1234567890}
                        # Extract just the label text; fall back to str() for plain strings.
                        if isinstance(dls, dict):
                            dls = dls.get("label", "") or dls.get("text", "") or ""
                        cfg._dab_dls = str(dls).strip()
                    for comp in svc.get("components", []):
                        if comp.get("transportmode") == "audio":
                            br = comp.get("subchannel", {}).get("bitrate", 0)
                            if br:
                                cfg._dab_bitrate = int(br)
                            break
                    break
            except Exception:
                pass

    def _find_dab_service_in_mux(self, mux, service):
        service_l = (service or "").strip().lower()
        for svc in mux.get("services", []):
            svc_lbl = svc.get("label", {})
            svc_name = (svc_lbl.get("label", "") or svc_lbl.get("shortlabel", "")).strip()
            if svc_name.lower() == service_l or service_l in svc_name.lower():
                return str(svc.get("sid", "")), svc_name
        return None, None

    def _start_dab_session(self, session, owner_name):
        import socket as _sock
        import subprocess
        import urllib.request as _ur
        import os as _os

        name = owner_name
        with _sock.socket() as _s:
            _s.bind(("", 0))
            session.dab_port = _s.getsockname()[1]

        _wb = _find_binary("welle-cli") or "welle-cli"

        # Kill any stale welle-cli processes that still hold the USB device from a
        # previous monitor run.  The USB kernel interface isn't released until the
        # process fully exits; without this, the new launch gets LIBUSB_ERROR_BUSY
        # (-6 / usb_claim_interface error) if the monitor is restarted quickly.
        try:
            import subprocess as _sp2, signal as _sig
            result = _sp2.run(["pgrep", "-a", "welle-cli"], capture_output=True, text=True)
            _driver_tag = f"rtl_sdr,{int(session.device_idx)}"
            for line in result.stdout.splitlines():
                if _driver_tag in line:
                    pid = int(line.split()[0])
                    self.log(f"[DAB {session.channel}] Killing stale welle-cli PID {pid} (device {session.device_idx})")
                    try:
                        _os.kill(pid, _sig.SIGKILL)
                    except Exception:
                        pass
            if result.stdout.strip():
                time.sleep(1.2)   # let USB stack fully release the interface
        except Exception:
            pass

        # Always pin the device index so two dongles on the same machine don't
        # conflict.  "rtl_sdr,0" is identical to "rtl_sdr" for a single dongle
        # but is essential when a second dongle (e.g. an FM rtl_fm stream) is
        # also running — previously index 0 was omitted, causing welle-cli to
        # open "first available" and race with rtl_fm for the same device.
        driver = f"rtl_sdr,{int(session.device_idx)}"
        # Register the DAB device claim so FM streams can detect the conflict.
        # Raises SdrBusyError if an FM stream already holds this device index.
        sdr_manager.claim_dab_device(session.device_idx, owner_name)
        _gain_val = str(getattr(session, "gain", -1))
        cmd = [_wb, "-w", str(session.dab_port), "-c", session.channel, "-C", "1", "-g", _gain_val, "-F", driver]
        if session.ppm:
            cmd += ["-p", str(session.ppm)]
        self.log(f"[{name}] DAB shared: launching {' '.join(cmd)}")

        try:
            import os as _os
            def _elevate_priority():
                try: _os.nice(-10)
                except Exception: pass
            session.proc = subprocess.Popen(cmd, stdout=subprocess.PIPE, stderr=subprocess.PIPE,
                                            bufsize=0, preexec_fn=_elevate_priority)
        except Exception as e:
            session.failed = True
            session.ready.set()
            self.log(f"[{name}] Failed to launch welle-cli: {e}")
            raise

        def _read_stderr():
            fatal_markers = (
                "usb_claim_interface error",
                "opening rtl-sdr failed",
                "error while opening device",
                "inputfactory:error while opening device",
            )
            try:
                for raw in session.proc.stderr:
                    try:
                        line = raw.decode(errors="ignore").strip()
                    except Exception:
                        line = str(raw).strip()
                    if not line:
                        continue
                    lower = line.lower()
                    # Suppress high-frequency welle-cli noise that appears on
                    # every OFDM sync cycle under marginal signal conditions.
                    # These are normal and do not indicate a broken stream:
                    #  SyncOnPhase failed    — OFDM carrier-phase jitter
                    #  SyncOnEndNull failed  — null-symbol timing missed
                    #  Failed to send audio for — HTTP push when no consumer
                    #  Removing mp3 sender   — welle-cli housekeeping on drop
                    if (
                        "synconphase failed"    in lower or
                        "syncOnEndNull failed".lower() in lower or
                        "failed to send audio for" in lower or
                        "removing mp3 sender"   in lower
                    ):
                        continue
                    if "error" in lower or "failed" in lower or "pll not locked" in lower:
                        self.log(f"[DAB {session.channel}] {line}")
                    if any(marker in lower for marker in fatal_markers):
                        if "usb_claim_interface error" in lower:
                            # Set a shared backoff so all streams for this
                            # device index wait 3 s before the next attempt,
                            # preventing rapid-fire crash loops that lock up
                            # the USB bus entirely.
                            self._dab_usb_backoffs[session.device_idx] = time.time() + 3.0
                        session.failed = True
                        session.ready.set()
                        try:
                            session.stop_evt.set()
                        except Exception:
                            pass
                        return
            except Exception as e:
                try:
                    out_q.put_nowait({"diag": f"RDS proc error: {e}"})
                except Exception:
                    pass

        def _poll_mux():
            deadline = time.time() + 45
            announced = False
            while not session.stop_evt.is_set():
                if session.proc.poll() is not None:
                    session.failed = True
                    session.ready.set()
                    if not announced:
                        self.log(f"[DAB {session.channel}] welle-cli exited unexpectedly")
                    return
                if session.failed:
                    return
                try:
                    with _ur.urlopen(f"http://localhost:{session.dab_port}/mux.json", timeout=2) as r:
                        mux = json.loads(r.read())
                    if not isinstance(mux, dict):
                        raise ValueError("invalid mux payload")
                    services = mux.get("services", []) or []
                    session.mux = mux
                    if services:
                        if not session.ready.is_set():
                            # Wait for the service count to stabilise across two consecutive polls
                            # before announcing ready — ensures the full ensemble is enumerated.
                            # Inter-poll sleep is 2s (not 5s) so ready fires before the 25s
                            # consumer timeout on marginal-signal sites.
                            prev_count = getattr(session, "_prev_svc_count", None)
                            cur_count  = len(services)
                            if prev_count is None:
                                # First non-empty poll — record and wait one more cycle
                                session._prev_svc_count = cur_count
                            elif cur_count == prev_count:
                                # Count identical across two consecutive polls — stable, announce
                                session.ready.set()
                                announced = True
                                self.log(f"[DAB {session.channel}] shared mux ready on port {session.dab_port} ({cur_count} services)")
                            else:
                                # Count still changing — update and wait another cycle
                                session._prev_svc_count = cur_count
                        time.sleep(2)
                        continue
                    if time.time() >= deadline and not announced:
                        session.failed = True
                        session.ready.set()
                        self.log(f"[DAB {session.channel}] mux endpoint came up but no services appeared before timeout")
                        return
                except Exception:
                    if time.time() >= deadline and not announced:
                        session.failed = True
                        session.ready.set()
                        self.log(f"[DAB {session.channel}] shared mux session timed out waiting for services")
                        return
                time.sleep(1)

        session.stderr_thread = threading.Thread(target=_read_stderr, daemon=True)
        session.stderr_thread.start()
        session.poll_thread = threading.Thread(target=_poll_mux, daemon=True)
        session.poll_thread.start()

    def _get_or_create_dab_session(self, serial, device_idx, channel, ppm, owner_name, gain: int = -1):
        key = self._dab_session_key(serial, device_idx, channel)
        with self._dab_sessions_lock:
            session = self._dab_sessions.get(key)
            if session is not None:
                session.refcount += 1
                session.consumers.add(owner_name)
                return session

            # Important: do not claim/open the SDR in Python for DAB.
            # welle-cli must open the dongle itself.
            session = DabSharedSession(key=key, serial=serial, device_idx=int(device_idx),
                                       channel=str(channel).upper(), dab_port=0,
                                       ppm=int(ppm or 0), gain=int(gain))
            self._dab_sessions[key] = session
            session.refcount = 1
            session.consumers.add(owner_name)

        try:
            self._start_dab_session(session, owner_name)
            return session
        except Exception:
            with self._dab_sessions_lock:
                self._dab_sessions.pop(key, None)
            raise

    def _stop_dab_session(self, session):
        try:
            session.stop_evt.set()
        except Exception:
            pass
        for p in [getattr(session, 'proc', None)]:
            if not p:
                continue
            try:
                p.terminate()
                p.wait(timeout=2)
            except Exception:
                try:
                    p.kill()
                except Exception:
                    pass
        # Give the USB stack a moment to fully release the device interface.
        # Without this, a monitor restart can hit LIBUSB_ERROR_BUSY (-6) on the
        # very next welle-cli launch because the kernel hasn't yet released the
        # USB claim even though the process has exited.
        time.sleep(0.5)
        # Release the SDR device claim so FM/scanner streams can use it again
        try:
            sdr_manager.release_dab_device(session.device_idx)
        except Exception:
            pass

    def _release_dab_session(self, session, owner_name):
        stop_now = False
        with self._dab_sessions_lock:
            cur = self._dab_sessions.get(session.key)
            if cur is not session:
                return
            session.consumers.discard(owner_name)
            session.refcount = max(0, session.refcount - 1)
            if session.refcount == 0:
                self._dab_sessions.pop(session.key, None)
                stop_now = True
        if stop_now:
            self.log(f"[DAB {session.channel}] stopping shared mux session")
            self._stop_dab_session(session)

    def _run_dab(self, cfg, sender, stop_evt):
        """
        Decode a DAB service via a shared welle-cli mux session.
        Multiple inputs on the same serial+channel reuse one tuner/process.
        """
        import urllib.request as _ur
        import subprocess as _sp

        name = cfg.name
        self.log(f"[{name}] DAB: starting — device_index={cfg.device_index!r}")
        import urllib.parse as _urlparse
        spec = cfg.device_index.strip()[6:]
        service = _urlparse.unquote(spec.split("?", 1)[0].strip())

        freq = None
        channel_name = None
        serial = None
        ppm = 0
        if "?" in spec:
            for part in spec.split("?", 1)[1].split("&"):
                if part.startswith("freq="):
                    freq = part.split("=", 1)[1]
                elif part.startswith("channel="):
                    channel_name = part.split("=", 1)[1].strip()
                elif part.startswith("serial="):
                    serial = part.split("=", 1)[1].strip()
                elif part.startswith("ppm="):
                    try:
                        ppm = int(part.split("=", 1)[1])
                    except Exception:
                        pass

        if not _find_binary("welle-cli"):
            self.log(f"[{name}] welle-cli not found on PATH. Install welle.io to use DAB sources.")
            cfg._livewire_mode = "DAB (welle-cli missing)"
            cfg._dab_ok = False
            return

        if not serial:
            self.log(f"[{name}] DAB: no dongle serial configured — edit this input and assign a dedicated RTL-SDR dongle.")
            cfg._livewire_mode = "DAB (no dongle configured)"
            cfg._dab_ok = False
            return

        device_idx = 0
        try:
            device_idx = int(sdr_manager.resolve_index(serial))
            self.log(f"[{name}] DAB: resolved serial {serial!r} → device {device_idx}")
        except SdrNotFoundError as e:
            self.log(f"[{name}] DAB: {e}")
            cfg._livewire_mode = "DAB (dongle not found)"
            cfg._dab_ok = False
            return

        # Early conflict check: refuse to start if an FM stream already holds this device index.
        # (The full bidirectional lock is enforced again inside _start_dab_session via
        #  sdr_manager.claim_dab_device, but an early bail-out here gives a clearer log message.)
        with sdr_manager._lock:
            for _fm_serial, _fm_owner in sdr_manager._owners.items():
                if sdr_manager._index_cache.get(_fm_serial) == device_idx:
                    self.log(
                        f"[{name}] DAB: device index {device_idx} (serial {_fm_serial!r}) is already "
                        f"in use by FM stream '{_fm_owner}'. Assign a dedicated dongle serial to each "
                        "stream to avoid conflicts."
                    )
                    cfg._livewire_mode = "DAB (device conflict — see logs)"
                    cfg._dab_ok = False
                    return

        gain = -1
        if serial:
            for dev in self.app_cfg.sdr_devices:
                if dev.serial == serial:
                    if not ppm:
                        ppm = dev.ppm
                    gain = getattr(dev, "gain", -1)
                    break

        _FREQ_TO_CHANNEL = {
            "174928":"5A","177008":"5B","178352":"5C","179200":"5D",
            "183648":"6A","185360":"6B","187072":"6C","188928":"6D",
            "194064":"7A","195776":"7B","197648":"7C","199360":"7D",
            "202928":"8A","204640":"8B","206352":"8C","208064":"8D",
            "211280":"9A","213360":"9B","214928":"9C","216928":"9D",
            "220352":"10A","222064":"10B","223936":"10C","225648":"10D",
            "229072":"11A","230784":"11B","232496":"11C","234208":"11D",
            "237488":"12A","239200":"12B","240912":"12C","242624":"12D",
        }
        if channel_name:
            channel = channel_name
        elif freq:
            channel = _FREQ_TO_CHANNEL.get(str(freq), freq)
        else:
            channel = "5C"

        cfg._livewire_mode = f"DAB: {service}"
        session = None
        try:
            # DAB inputs can start at the same time. Be patient and retry so a
            # consumer can attach to the mux session that eventually wins.
            startup_deadline = time.time() + 120
            sid = None
            svc_name = None
            audio_url = None
            attempt = 0
            while time.time() < startup_deadline and not stop_evt.is_set():
                attempt += 1
                if attempt > 1:
                    self.log(f"[{name}] DAB: retrying shared mux attach (attempt {attempt})")
                    time.sleep(1.0)
                # Honour the shared USB backoff — if another stream already hit
                # usb_claim_interface error for this device, wait together rather
                # than hammering the USB bus with independent rapid retries.
                backoff_until = self._dab_usb_backoffs.get(device_idx, 0)
                if backoff_until > time.time():
                    wait_s = backoff_until - time.time()
                    self.log(f"[{name}] DAB: USB busy backoff — waiting {wait_s:.1f}s before retry")
                    if stop_evt.wait(timeout=wait_s):
                        return
                try:
                    session = self._get_or_create_dab_session(serial, device_idx, channel, ppm, name, gain=gain)
                except SdrNotFoundError as e:
                    self.log(f"[{name}] DAB: {e}")
                    cfg._livewire_mode = "DAB (dongle not found)"
                    cfg._dab_ok = False
                    return
                except SdrBusyError as e:
                    self.log(f"[{name}] DAB: {e}")
                    cfg._livewire_mode = "DAB (dongle in use)"
                    cfg._dab_ok = False
                    return

                if not session.ready.wait(timeout=min(25, max(1, int(startup_deadline - time.time())))) or session.failed:
                    self.log(f"[{name}] DAB: shared mux session did not become ready")
                    try:
                        self._release_dab_session(session, name)
                    except Exception:
                        pass
                    session = None
                    continue

                mux = session.mux or {}
                self._copy_dab_metrics_from_mux(cfg, mux, service)
                sid, svc_name = self._find_dab_service_in_mux(mux, service)
                if not sid:
                    # Give the mux a little extra time to populate services.
                    deadline = time.time() + 20
                    while time.time() < deadline and not stop_evt.is_set():
                        mux = session.mux or {}
                        self._copy_dab_metrics_from_mux(cfg, mux, service)
                        sid, svc_name = self._find_dab_service_in_mux(mux, service)
                        if sid:
                            break
                        time.sleep(1)
                if sid:
                    cfg._dab_service = svc_name or service
                    cfg._dab_ok = True
                    audio_url = f"http://localhost:{session.dab_port}/mp3/{sid}"
                    self.log(f"[{name}] DAB: streaming audio from {audio_url} (shared mux {channel})")
                    # Log initial availability and write immediate metric row
                    _now_avail = time.time()
                    metrics_db.write([(name, "dab_ok", _now_avail, 1.0)])
                    _add_history(cfg, "DAB_AVAILABLE",
                                 f"DAB service '{cfg._dab_service}' available on '{name}' "
                                 f"(ensemble: {cfg._dab_ensemble}, SNR {cfg._dab_snr:.1f} dB)")
                    _check_dab_service_name(cfg, sender, self.log, _now_avail)
                    break

                self.log(f"[{name}] DAB: could not find service {service!r} in mux {channel}; will retry")
                try:
                    self._release_dab_session(session, name)
                except Exception:
                    pass
                session = None

            if not session or not sid or not audio_url:
                self.log(f"[{name}] DAB: failed to attach to shared mux {channel}")
                cfg._dab_ok = False
                return

            # ── Initial probe: wait for the audio endpoint to serve data ────────
            # 35s deadline: welle-cli initialises individual service endpoints
            # after the mux is declared ready, and slower/heavier services (e.g.
            # Absolute 80s) can take 20-25s after mux ready before their /mp3/
            # endpoint serves enough bytes.  The 3.3.55 stability-poll change
            # caused mux ready to fire ~3s earlier, which compounded this.
            stream_ready = False
            ready_deadline = time.time() + 35
            while time.time() < ready_deadline and not stop_evt.is_set():
                if session.proc.poll() is not None:
                    self.log(f"[{name}] DAB: welle-cli exited before audio stream became ready")
                    return
                try:
                    with _ur.urlopen(audio_url, timeout=3) as _trig:
                        probe = _trig.read(32768)
                        if probe and len(probe) >= 4096:
                            stream_ready = True
                            self.log(f"[{name}] DAB: audio endpoint ready ({len(probe)} bytes)")
                            break
                except Exception as e:
                    self.log(f"[{name}] DAB: waiting for audio endpoint: {e}")
                time.sleep(0.5)

            if not stream_ready or stop_evt.is_set():
                self.log(f"[{name}] DAB: audio stream never became ready")
                return

            ffmpeg_bin = _find_binary("ffmpeg") or "ffmpeg"
            ff_cmd = [ffmpeg_bin, "-loglevel", "warning", "-i", audio_url,
                      "-f", "s16le", "-ar", str(SAMPLE_RATE),
                      "-ac", "1", "-"]
            CHUNK_BYTES = int(SAMPLE_RATE * CHUNK_DURATION) * 2

            # ── Outer reconnect loop — retries ffmpeg when the audio stream drops ─
            # welle-cli may briefly remove an MP3 sender during signal loss/SyncOnPhase
            # events.  Instead of propagating the failure up and releasing the entire
            # shared session (which kills welle-cli for all consumers), we hold the
            # session reference and retry the HTTP connection once the endpoint comes
            # back up.
            _MAX_AUDIO_FAILURES = 8
            _audio_fail_count = 0

            while not stop_evt.is_set():
                # ── Check welle-cli is still alive ───────────────────────────────
                if session.proc.poll() is not None:
                    self.log(f"[{name}] DAB: welle-cli process exited")
                    break
                if session.failed:
                    self.log(f"[{name}] DAB: shared mux session failed")
                    break

                # ── (Re)launch ffmpeg ────────────────────────────────────────────
                try:
                    ff_proc = _sp.Popen(ff_cmd, stdout=_sp.PIPE, stderr=_sp.PIPE, bufsize=0)
                except Exception as e:
                    self.log(f"[{name}] DAB: ffmpeg launch failed: {e}")
                    _audio_fail_count += 1
                    if _audio_fail_count >= _MAX_AUDIO_FAILURES:
                        self.log(f"[{name}] DAB: too many ffmpeg failures, giving up")
                        break
                    time.sleep(3)
                    continue

                def _read_ffmpeg_stderr(proc=ff_proc):
                    try:
                        for raw in proc.stderr:
                            line = raw.decode(errors="ignore").strip()
                            if line:
                                self.log(f"[{name}] DAB/ffmpeg: {line}")
                    except Exception:
                        pass

                ff_stderr_t = threading.Thread(target=_read_ffmpeg_stderr, daemon=True)
                ff_stderr_t.start()

                buf = bytearray()
                pcm_started = False
                pcm_deadline = time.time() + 15
                audio_lost = False

                # ── Inner audio read loop ────────────────────────────────────────
                while not stop_evt.is_set():
                    try:
                        if session.proc.poll() is not None:
                            self.log(f"[{name}] DAB: welle-cli stopped")
                            audio_lost = True
                            break
                        if ff_proc.poll() is not None:
                            self.log(f"[{name}] DAB: ffmpeg stopped — will reconnect")
                            audio_lost = True
                            break
                        chunk = ff_proc.stdout.read(4096)
                        if not chunk:
                            if (not pcm_started) and time.time() > pcm_deadline:
                                self.log(f"[{name}] DAB: ffmpeg connected but no PCM arrived")
                                audio_lost = True
                                break
                            time.sleep(0.1)
                            continue
                        pcm_started = True
                        _audio_fail_count = 0   # reset on successful data
                        buf.extend(chunk)
                        while len(buf) >= CHUNK_BYTES:
                            raw = bytes(buf[:CHUNK_BYTES])
                            del buf[:CHUNK_BYTES]
                            samp = np.frombuffer(raw, dtype="<i2").astype(np.float32) / 32768.0
                            samp = np.clip(samp - np.mean(samp), -1.0, 1.0)
                            cfg._stream_buffer.append(samp.copy())
                            cfg._audio_buffer.append(samp.copy())
                            cfg._live_chunk_seq = getattr(cfg, "_live_chunk_seq", 0) + 1
                            analyse_chunk(cfg, sender,
                                          lambda m, n=name: self.log(f"[{n}] {m}"),
                                          samp, CHUNK_DURATION,
                                          cfg.alert_wav_duration,
                                          self.app_cfg.inputs)
                        if int(time.time()) % 10 == 0:
                            mux = session.mux or {}
                            self._copy_dab_metrics_from_mux(cfg, mux, service)
                            # DAB availability tracking: log state transitions + immediate metric writes
                            if cfg._dab_ensemble and mux:
                                _sid_chk, _ = self._find_dab_service_in_mux(mux, service)
                                _was_ok = cfg._dab_ok
                                if not _sid_chk:
                                    # Service missing from mux
                                    if _was_ok:
                                        # Transition: available → unavailable
                                        cfg._dab_ok = False
                                        _ts_tr = time.time()
                                        metrics_db.write([(name, "dab_ok", _ts_tr, 0.0)])
                                        _add_history(cfg, "DAB_UNAVAILABLE",
                                                     f"DAB service '{service}' left mux on '{name}' "
                                                     f"(ensemble: {cfg._dab_ensemble}, "
                                                     f"SNR {cfg._dab_snr:.1f} dB)")
                                        self.log(f"[{name}] DAB: service '{service}' no longer in mux")
                                    # Alert (rate-limited separately from the state log)
                                    _now_dab = time.time()
                                    _key_dab = "DAB_SERVICE_MISSING"
                                    if _now_dab - cfg._last_alerts.get(_key_dab, 0) >= ALERT_COOLDOWN * 2:
                                        cfg._last_alerts[_key_dab] = _now_dab
                                        _msg_dab = (
                                            f"DAB service '{service}' missing from mux on '{name}' "
                                            f"(ensemble: {cfg._dab_ensemble}, SNR {cfg._dab_snr:.1f} dB)"
                                        )
                                        _add_history(cfg, _key_dab, _msg_dab)
                                        sender.send(
                                            f"DAB SERVICE MISSING — {name}", _msg_dab, None,
                                            alert_type=_key_dab, stream=name,
                                            level_dbfs=float(cfg._last_level_dbfs)
                                        )
                                        self.log(f"[ALERT] {_msg_dab}")
                                else:
                                    # Service present in mux
                                    if not _was_ok:
                                        # Transition: unavailable → available (recovery)
                                        cfg._dab_ok = True
                                        _ts_tr = time.time()
                                        metrics_db.write([(name, "dab_ok", _ts_tr, 1.0)])
                                        _msg_rec = (
                                            f"DAB service '{service}' restored on '{name}' "
                                            f"(ensemble: {cfg._dab_ensemble}, SNR {cfg._dab_snr:.1f} dB)"
                                        )
                                        _add_history(cfg, "DAB_AVAILABLE", _msg_rec)
                                        self.log(f"[{name}] DAB: service '{service}' restored in mux")
                                        _check_dab_service_name(cfg, sender, self.log, _ts_tr)
                    except Exception as e:
                        self.log(f"[{name}] DAB: audio loop error: {e}")
                        time.sleep(0.25)

                # ── Clean up this ffmpeg instance ────────────────────────────────
                try:
                    ff_proc.terminate()
                    ff_proc.wait(timeout=2)
                except Exception:
                    try:
                        ff_proc.kill()
                    except Exception:
                        pass

                if stop_evt.is_set():
                    break

                # welle-cli itself died — no point retrying the audio stream
                if session.proc.poll() is not None or session.failed:
                    break

                if audio_lost:
                    _audio_fail_count += 1
                    if _audio_fail_count >= _MAX_AUDIO_FAILURES:
                        self.log(f"[{name}] DAB: too many consecutive audio failures, giving up")
                        break

                    # Wait for the audio endpoint to come back before relaunching ffmpeg
                    self.log(f"[{name}] DAB: audio stream lost, waiting for endpoint to recover (attempt {_audio_fail_count}/{_MAX_AUDIO_FAILURES})...")
                    recover_deadline = time.time() + 20
                    recovered = False
                    while time.time() < recover_deadline and not stop_evt.is_set():
                        if session.proc.poll() is not None or session.failed:
                            break
                        try:
                            with _ur.urlopen(audio_url, timeout=3) as _trig:
                                probe = _trig.read(8192)
                                if probe and len(probe) >= 2048:
                                    recovered = True
                                    break
                        except Exception:
                            pass
                        time.sleep(2)

                    if not recovered:
                        if session.proc.poll() is not None or session.failed:
                            self.log(f"[{name}] DAB: welle-cli not recovering, stopping")
                        else:
                            self.log(f"[{name}] DAB: audio endpoint did not recover within 20s")
                        break
                    self.log(f"[{name}] DAB: audio endpoint recovered, restarting stream")
        finally:
            if session is not None:
                self._release_dab_session(session, name)
            self.log(f"[{name}] DAB thread stopped.")

    def _run_fm(self, cfg, sender, stop_evt):
        """
        Receive and demodulate an FM broadcast stream.

        Source format:
            fm://96.7                          any available FM dongle
            fm://96.7?serial=FM_DONGLE_1               specific dongle by serial
            fm://96.7?serial=FM_DONGLE_1&ppm=5         with explicit PPM override
            fm://96.7?serial=FM_DONGLE_1&gain=35.4     with manual tuner gain (dB)
            fm://96.7?serial=FM_DONGLE_1&backend=rtl_fm   force rtl_fm backend

        Audio output: 48kHz mono float32 into existing analyse_chunk pipeline.
        """
        import shutil
        name = cfg.name
        self.log(f"[{name}] FM: starting — device_index={cfg.device_index!r}")
        spec = cfg.device_index.strip()[5:]   # strip "fm://"
        freq_str = spec.split("?")[0].strip()

        try:
            cfg._fm_freq_mhz = float(freq_str)
        except ValueError:
            self.log(f"[{name}] FM: invalid frequency {freq_str!r}")
            return

        freq_hz = int(cfg._fm_freq_mhz * 1e6)
        cfg._livewire_mode = f"FM: {cfg._fm_freq_mhz:.1f} MHz"

        # Parse query params
        serial = None
        ppm    = 0
        gain   = None
        backend = "auto"
        for part in (spec.split("?", 1)[1].split("&") if "?" in spec else []):
            if part.startswith("serial="):
                serial = part.split("=", 1)[1].strip()
            elif part.startswith("ppm="):
                try: ppm = int(part.split("=", 1)[1])
                except: pass
            elif part.startswith("gain="):
                try: gain = float(part.split("=", 1)[1])
                except: pass
            elif part.startswith("backend="):
                try: backend = urllib.parse.unquote_plus(part.split("=", 1)[1]).strip().lower()
                except Exception: pass

        if backend not in ("rtl_fm",):
            backend = "rtl_fm"

        # Resolve PPM from device registry if not overridden
        if not ppm and serial:
            for dev in monitor.app_cfg.sdr_devices:
                if dev.serial == serial:
                    ppm = dev.ppm; break

        if not serial:
            self.log(f"[{name}] FM: no dongle serial configured — edit this input and assign a dedicated RTL-SDR dongle.")
            cfg._livewire_mode = "FM (no dongle configured)"
            return

        lease      = None
        device_idx = 0
        try:
            lease = sdr_manager.claim(serial, owner=f"FM:{name}")
            device_idx = lease.index
            self.log(f"[{name}] FM: claimed dongle {serial!r} → index {device_idx}")
        except SdrNotFoundError as e:
            self.log(f"[{name}] FM: {e}")
            cfg._livewire_mode = "FM (dongle not found)"
            return
        except SdrBusyError as e:
            self.log(f"[{name}] FM: {e}")
            cfg._livewire_mode = "FM (dongle in use)"
            return

        try:
            if not _find_binary("rtl_fm"):
                self.log(f"[{name}] FM: rtl_fm not found — install rtl-sdr tools")
                cfg._livewire_mode = "FM (rtl_fm not found)"
                return
            self._run_fm_rtlsdr(cfg, sender, stop_evt, freq_hz, device_idx, ppm, gain)
        finally:
            if lease:
                lease.__exit__(None, None, None)



    def _fm_rds_detect_light(self, demod, sdr_fs, cfg):
        """
        Lightweight RDS detector for subprocess use.
        Detects 57 kHz subcarrier presence and a rough symbol-phase metric
        without attempting full group parsing, so it cannot stall audio.
        """
        import numpy as np
        x = np.asarray(demod, dtype=np.float32).reshape(-1)
        fs = float(max(sdr_fs, 1))
        if x.size < 4096:
            cfg._fm_rds_status = "No lock"
            cfg._fm_rds_metric = 0.0
            cfg._fm_rds_best_phase = -1
            cfg._fm_rds_bp_rms = 0.0
            cfg._fm_rds_bb_rms = 0.0
            cfg._fm_rds_sym_metric = 0.0
            return

        # Mix the 57 kHz RDS region to baseband.
        n = np.arange(x.size, dtype=np.float64)
        osc = np.exp(-1j * 2.0 * np.pi * 57000.0 * n / fs)
        bb = x.astype(np.float64, copy=False) * osc

        # Very cheap LPF via moving average.
        taps = 96
        k = np.ones(taps, dtype=np.float64) / float(taps)
        bb_i = np.convolve(bb.real, k, mode="same")
        bb_q = np.convolve(bb.imag, k, mode="same")
        bb_lp = bb_i + 1j * bb_q

        # Diagnostics.
        cfg._fm_rds_bp_rms = float(np.sqrt(np.mean(np.square(x))) + 1e-12)
        cfg._fm_rds_bb_rms = float(np.sqrt(np.mean(np.abs(bb_lp) ** 2)) + 1e-12)
        cfg._fm_rds_metric = cfg._fm_rds_bb_rms

        # Crude phase/symbol metric: examine several phases at ~202 samples/symbol.
        sps = max(8, int(round(fs / 1187.5)))
        best_phase = -1
        best_metric = 0.0
        for ph in range(min(sps, 32)):
            sy = bb_lp[ph::sps]
            if sy.size < 8:
                continue
            d = sy[1:] * np.conj(sy[:-1])
            score = float(np.mean(np.abs(np.real(d))))
            if score > best_metric:
                best_metric = score
                best_phase = ph
        cfg._fm_rds_sym_metric = float(best_metric)
        cfg._fm_rds_best_phase = int(best_phase)

        # Conservative statusing only. Do not invent PS/RT without real group decode.
        if cfg._fm_rds_bb_rms > 0.003 or best_metric > 0.003:
            cfg._fm_rds_status = "Carrier seen, no valid groups"
        else:
            cfg._fm_rds_status = "No lock"


    def _fm_rds_decode_bounded(self, demod, sdr_fs, rds_bits, cfg):
        """
        Try full RDS decode on a small slice without using signal-based timeouts.
        This avoids corrupting SciPy internals while still keeping heavy work modest.
        """
        import numpy as np
        try:
            demod = np.asarray(demod, dtype=np.float32)
            return self._fm_decode_rds(demod, int(sdr_fs), rds_bits, cfg)
        except Exception as e:
            try:
                # Keep the light-detector status rather than forcing hard errors into
                # the UI every time a speculative full-decode pass fails.
                cfg._fm_rds_status = getattr(cfg, "_fm_rds_status", "Carrier seen, no valid groups") or "Carrier seen, no valid groups"
                self.log(f"[{getattr(cfg, 'name', 'FM')}] RDS bounded decode error: {e}")
            except Exception:
                pass
            return rds_bits

    def _fm_rds_proc_worker(self, in_q, out_q):
        """
        Separate-process RDS worker.
        Receives (demod, fs) tuples, decodes best-effort RDS, emits latest status/state dict.
        """
        import time
        import numpy as np
        class _Cfg: pass
        cfg = _Cfg()
        cfg.name = "FM"
        rds_bits = []
        _last_diag = 0.0
        _decode_every = 10
        _decode_ctr = 0
        while True:
            item = in_q.get()
            if item is None:
                break
            try:
                demod, fs = item
                now = time.time()
                if (now - _last_diag) >= 2.0:
                    out_q.put_nowait({"diag": f"RDS proc recv: n={len(demod)} fs={int(fs)}"})
                    _last_diag = now

                # Always run the lightweight detector so UI remains responsive.
                self._fm_rds_detect_light(np.asarray(demod, dtype=np.float32), int(fs), cfg)

                # Only attempt full group parsing occasionally, and only when the
                # light detector says there is enough 57 kHz energy to be worth trying.
                _decode_ctr += 1
                if (getattr(cfg, "_fm_rds_metric", 0.0) or 0.0) > 0.0035 and _decode_ctr >= _decode_every:
                    _decode_ctr = 0
                    # Smaller bounded slice for the heavy parser.
                    rds_bits = self._fm_rds_decode_bounded(np.asarray(demod[-6144:], dtype=np.float32),
                                                           int(fs), rds_bits, cfg, timeout_s=0.20)
                    if len(rds_bits) > 6000:
                        rds_bits = rds_bits[-3000:]

                out_q.put_nowait({
                    "status": getattr(cfg, "_fm_rds_status", ""),
                    "metric": float(getattr(cfg, "_fm_rds_metric", 0.0) or 0.0),
                    "phase": int(getattr(cfg, "_fm_rds_best_phase", -1) or -1),
                    "valid": int(getattr(cfg, "_fm_rds_valid_groups", 0) or 0),
                    "ps": getattr(cfg, "_fm_rds_ps", "") or "",
                    "rt": getattr(cfg, "_fm_rds_rt", "") or "",
                    "last_good": float(getattr(cfg, "_fm_rds_last_good", 0.0) or 0.0),
                    "bp": float(getattr(cfg, "_fm_rds_bp_rms", 0.0) or 0.0),
                    "bb": float(getattr(cfg, "_fm_rds_bb_rms", 0.0) or 0.0),
                    "sym": float(getattr(cfg, "_fm_rds_sym_metric", 0.0) or 0.0),
                })
            except Exception:
                pass

    def _fm_rds_worker(self, cfg, stop_evt):
        """
        Background RDS worker for FM inputs.
        Consumes only the latest demod slice so audio never blocks on RDS.
        """
        import time
        rds_bits = list(getattr(cfg, "_fm_rds_bits", []) or [])
        while not stop_evt.is_set():
            demod = getattr(cfg, "_fm_rds_buf", None)
            fs = getattr(cfg, "_fm_rds_fs", 0)
            cfg._fm_rds_buf = None
            if demod is None or not fs:
                time.sleep(0.05)
                continue
            try:
                rds_bits = self._fm_decode_rds(demod, int(fs), rds_bits, cfg)
                cfg._fm_rds_bits = rds_bits[-6000:]
                time.sleep(0.02)
            except Exception as e:
                try:
                    cfg._fm_rds_status = f"RDS err: {e}"
                    self.log(f"[{getattr(cfg, 'name', 'FM')}] RDS worker error: {e}")
                except Exception:
                    pass
                time.sleep(0.1)

    def _fm_decode_rds(self, demod: np.ndarray, sdr_fs: int,
                        rds_bits: list, cfg) -> list:
        """
        More robust best-effort RDS decoder.

        Pipeline:
          discriminator/composite -> 57 kHz band-pass -> complex mix-down
          -> ~2.4 kHz LPF -> resample to 19 kHz
          -> differential BPSK symbol extraction at 16 samples/symbol
          -> CRC/offset checked group parsing.

        The UI is only updated after repeated agreement so junk text is suppressed.
        """
        try:
            from scipy.signal import butter, lfilter, lfilter_zi, resample_poly
            import numpy as np
            import math
            import time
        except Exception as e:
            try:
                cfg._fm_rds_status = f"RDS err: {e}"
                cfg._fm_rds_metric = 0.0
                cfg._fm_rds_best_phase = -1
                self.log(f"[{getattr(cfg, 'name', 'FM')}] RDS decode error: {e}")
            except Exception:
                pass
            return rds_bits

        try:
            fs = float(max(sdr_fs, 1))

            if not hasattr(cfg, "_fm_rds_phase"):
                cfg._fm_rds_phase = 0.0

            # Persistent pre-mix 57 kHz band-pass.
            if (not hasattr(cfg, "_fm_rds_bp_b") or not hasattr(cfg, "_fm_rds_bp_a") or
                    getattr(cfg, "_fm_rds_bp_fs", None) != int(round(fs))):
                nyq = max(fs / 2.0, 1.0)
                lo = max(54000.0 / nyq, 1e-4)
                hi = min(60000.0 / nyq, 0.999)
                if hi <= lo:
                    cfg._fm_rds_status = "No lock"
                    cfg._fm_rds_metric = 0.0
                    cfg._fm_rds_best_phase = -1
                    return rds_bits
                b_bp, a_bp = butter(4, [lo, hi], btype="bandpass")
                cfg._fm_rds_bp_b = np.asarray(b_bp, dtype=np.float64)
                cfg._fm_rds_bp_a = np.asarray(a_bp, dtype=np.float64)
                zi_bp = lfilter_zi(cfg._fm_rds_bp_b, cfg._fm_rds_bp_a)
                cfg._fm_rds_bp_zi = zi_bp.astype(np.float64)
                cfg._fm_rds_bp_fs = int(round(fs))

            # Baseband LPF after mix-down.
            if (not hasattr(cfg, "_fm_rds_b") or not hasattr(cfg, "_fm_rds_a") or
                    getattr(cfg, "_fm_rds_lp_fs", None) != int(round(fs))):
                nyq = max(fs / 2.0, 1.0)
                cutoff = min(2400.0, nyq * 0.45)
                b, a = butter(4, cutoff / nyq, btype="low")
                cfg._fm_rds_b = np.asarray(b, dtype=np.float64)
                cfg._fm_rds_a = np.asarray(a, dtype=np.float64)
                zi = lfilter_zi(cfg._fm_rds_b, cfg._fm_rds_a)
                cfg._fm_rds_zi_i = zi.astype(np.float64)
                cfg._fm_rds_zi_q = zi.astype(np.float64)
                cfg._fm_rds_lp_fs = int(round(fs))

            # UI/diagnostic state.
            if not hasattr(cfg, "_fm_rds_ps_counts"):
                cfg._fm_rds_ps_counts = {}
            if not hasattr(cfg, "_fm_rds_rt_counts"):
                cfg._fm_rds_rt_counts = {}
            if not hasattr(cfg, "_fm_rds_last_good"):
                cfg._fm_rds_last_good = 0.0
            if not hasattr(cfg, "_fm_rds_ok"):
                cfg._fm_rds_ok = False
            if not hasattr(cfg, "_fm_rds_ps"):
                cfg._fm_rds_ps = ""
            if not hasattr(cfg, "_fm_rds_rt"):
                cfg._fm_rds_rt = ""
            if not hasattr(cfg, "_fm_rds_valid_groups"):
                cfg._fm_rds_valid_groups = 0
            if not hasattr(cfg, "_fm_rds_candidates"):
                cfg._fm_rds_candidates = 0
            if not hasattr(cfg, "_fm_rds_status"):
                cfg._fm_rds_status = "No lock"
            if not hasattr(cfg, "_fm_rds_metric"):
                cfg._fm_rds_metric = 0.0
            if not hasattr(cfg, "_fm_rds_best_phase"):
                cfg._fm_rds_best_phase = -1
            if not hasattr(cfg, "_fm_rds_bp_rms"):
                cfg._fm_rds_bp_rms = 0.0

            x = np.asarray(demod, dtype=np.float64).reshape(-1)
            if x.size < 512:
                cfg._fm_rds_status = "No lock"
                cfg._fm_rds_metric = 0.0
                cfg._fm_rds_best_phase = -1
                return rds_bits

            # Isolate the 57 kHz RDS region before mixing.
            x_bp, cfg._fm_rds_bp_zi = lfilter(cfg._fm_rds_bp_b, cfg._fm_rds_bp_a, x, zi=cfg._fm_rds_bp_zi)
            cfg._fm_rds_bp_rms = float(np.sqrt(np.mean(np.square(x_bp))) + 0.0)

            # Downconvert 57 kHz to baseband with phase continuity.
            n = np.arange(len(x_bp), dtype=np.float64)
            w = 2.0 * np.pi * 57000.0 / fs
            phase0 = float(cfg._fm_rds_phase)
            osc = np.exp(-1j * (phase0 + w * n))
            cfg._fm_rds_phase = float((phase0 + w * len(x_bp)) % (2.0 * np.pi))
            bb = x_bp * osc

            # LPF I/Q to recover BPSK baseband.
            i_filt, cfg._fm_rds_zi_i = lfilter(cfg._fm_rds_b, cfg._fm_rds_a, bb.real, zi=cfg._fm_rds_zi_i)
            q_filt, cfg._fm_rds_zi_q = lfilter(cfg._fm_rds_b, cfg._fm_rds_a, bb.imag, zi=cfg._fm_rds_zi_q)
            bb_lp = i_filt + 1j * q_filt

            metric = float(np.sqrt(np.mean(np.abs(bb_lp) ** 2))) if bb_lp.size else 0.0
            cfg._fm_rds_metric = metric

            # Resample to 19 kHz so we get exactly 16 samples/symbol.
            fs_in = int(round(fs))
            g = math.gcd(fs_in, 19000)
            up = 19000 // g
            down = fs_in // g
            bb19 = resample_poly(bb_lp, up, down)
            if bb19.size < 64:
                cfg._fm_rds_status = "No lock" if metric < 0.002 else "Carrier seen"
                cfg._fm_rds_best_phase = -1
                return rds_bits

            # Choose the best 16-sample symbol phase.
            SPS = 16
            best_phase = -1
            best_metric = -1.0
            best_sy = None
            for ph in range(SPS):
                sy = bb19[ph::SPS]
                if sy.size < 16:
                    continue
                d = sy[1:] * np.conj(sy[:-1])
                score = float(np.mean(np.abs(np.real(d))))
                if score > best_metric:
                    best_metric = score
                    best_phase = ph
                    best_sy = sy

            cfg._fm_rds_best_phase = int(best_phase)
            cfg._fm_rds_candidates += 1

            if best_sy is None or best_metric <= 0:
                cfg._fm_rds_status = "No lock" if metric < 0.002 else "Carrier seen, no valid groups"
                return rds_bits

            if metric < 0.002 and best_metric < 0.002:
                cfg._fm_rds_status = "No lock"
            elif best_metric < 0.01:
                cfg._fm_rds_status = "Carrier seen, no valid groups"
            else:
                cfg._fm_rds_status = f"Detecting… ({cfg._fm_rds_candidates} candidates)"

            # Differential BPSK decode.
            d = best_sy[1:] * np.conj(best_sy[:-1])
            bits = (np.real(d) < 0.0).astype(np.uint8).tolist()
            rds_bits.extend(bits)

            if len(rds_bits) > 12000:
                rds_bits = rds_bits[-6000:]

            # CRC / offset checked group parsing.
            POLY = 0x5B9
            OFF_A = 0x0FC
            OFF_B = 0x198
            OFF_C = 0x168
            OFF_CP = 0x350
            OFF_D = 0x1B4
            allowed = set("ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789 .,/?:;!+-&'()[]")

            def bits_to_int(bitseq):
                v = 0
                for b in bitseq:
                    v = (v << 1) | int(b)
                return v

            def crc10(word16):
                reg = word16 << 10
                top = 1 << 25
                while reg >= top:
                    shift = reg.bit_length() - 26
                    reg ^= (POLY << (shift + 10))
                return reg & 0x3FF

            def check_block(bits26):
                if len(bits26) != 26:
                    return (False, None, None)
                raw = bits_to_int(bits26)
                data = (raw >> 10) & 0xFFFF
                check = raw & 0x3FF
                synd = crc10(data) ^ check
                if synd == OFF_A:  return (True, 'A', data)
                if synd == OFF_B:  return (True, 'B', data)
                if synd == OFF_C:  return (True, 'C', data)
                if synd == OFF_CP: return (True, "C'", data)
                if synd == OFF_D:  return (True, 'D', data)
                return (False, None, None)

            now = time.time()
            valid_this_call = 0
            i = 0
            max_scan = max(0, len(rds_bits) - 104)
            while i <= max_scan:
                okA, typA, blkA = check_block(rds_bits[i:i+26])
                okB, typB, blkB = check_block(rds_bits[i+26:i+52])
                okC, typC, blkC = check_block(rds_bits[i+52:i+78])
                okD, typD, blkD = check_block(rds_bits[i+78:i+104])

                if okA and okB and okD and typA == 'A' and typB == 'B' and typD == 'D' and typC in ('C', "C'"):
                    valid_this_call += 1
                    cfg._fm_rds_valid_groups += 1
                    cfg._fm_rds_last_good = now
                    cfg._fm_rds_ok = True
                    group_type = (blkB >> 12) & 0xF
                    ver_b = (blkB >> 11) & 0x1

                    if group_type == 0:
                        idx = blkB & 0x3
                        c1 = chr((blkD >> 8) & 0xFF)
                        c2 = chr(blkD & 0xFF)
                        if c1 in allowed and c2 in allowed:
                            current = list((cfg._fm_rds_ps or " " * 8).ljust(8)[:8])
                            pos = idx * 2
                            if pos + 1 < 8:
                                current[pos] = c1
                                current[pos + 1] = c2
                                cand = "".join(current).strip()
                                if cand:
                                    cfg._fm_rds_ps_counts[cand] = cfg._fm_rds_ps_counts.get(cand, 0) + 1
                                    if cfg._fm_rds_ps_counts[cand] >= 2:
                                        cfg._fm_rds_ps = cand
                                        cfg._fm_rds_status = f"Locked ({cfg._fm_rds_valid_groups} valid)"

                    if group_type == 2:
                        seg = blkB & 0xF
                        chars = []
                        if ver_b == 0:
                            chars.extend([chr((blkC >> 8) & 0xFF), chr(blkC & 0xFF),
                                          chr((blkD >> 8) & 0xFF), chr(blkD & 0xFF)])
                        else:
                            chars.extend([chr((blkD >> 8) & 0xFF), chr(blkD & 0xFF)])
                        if all(ch in allowed for ch in chars):
                            cur = list((cfg._fm_rds_rt or " " * 64).ljust(64)[:64])
                            base = seg * (4 if ver_b == 0 else 2)
                            for j, ch in enumerate(chars):
                                if base + j < len(cur):
                                    cur[base + j] = ch
                            cand = "".join(cur).rstrip()
                            if cand:
                                cfg._fm_rds_rt_counts[cand] = cfg._fm_rds_rt_counts.get(cand, 0) + 1
                                if cfg._fm_rds_rt_counts[cand] >= 2:
                                    cfg._fm_rds_rt = cand
                                    cfg._fm_rds_status = f"Locked ({cfg._fm_rds_valid_groups} valid)"

                    i += 104
                else:
                    i += 1

            if valid_this_call == 0:
                age = (now - float(cfg._fm_rds_last_good)) if getattr(cfg, "_fm_rds_last_good", 0) else None
                if cfg._fm_rds_metric < 0.002 and cfg._fm_rds_bp_rms < 0.002:
                    cfg._fm_rds_status = "No lock"
                elif age is not None and age < 10:
                    cfg._fm_rds_status = "Carrier seen, no valid groups"
                elif cfg._fm_rds_metric >= 0.002 or cfg._fm_rds_bp_rms >= 0.002:
                    cfg._fm_rds_status = "Carrier seen"
                else:
                    cfg._fm_rds_status = "No lock"

            return rds_bits

        except Exception:
            try:
                cfg._fm_rds_status = "No lock"
                cfg._fm_rds_metric = 0.0
                cfg._fm_rds_best_phase = -1
            except Exception:
                pass
            return rds_bits
    def _run_fm_rtlsdr(self, cfg, sender, stop_evt,
                        freq_hz: int, device_idx: int, ppm: int,
                        gain: float | None = None):
        """
        FM demodulation via rtl_fm subprocess with redsea RDS decode.

        Audio path:
            rtl_fm (171 kHz MPX S16LE) -> Python resample -> 48 kHz monitor audio

        RDS path:
            rtl_fm (same MPX) -> redsea -r 171000 -> newline-delimited JSON
        """
        import subprocess, threading, json
        name = cfg.name

        if not _find_binary("rtl_fm"):
            self.log(f"[{name}] FM: rtl_fm not found. Install rtl-sdr.")
            cfg._livewire_mode = "FM (no backend)"
            return

        redsea_bin = _find_binary("redsea")
        if not redsea_bin:
            self.log(f"[{name}] FM: redsea not found. Install redsea for RDS decoding.")

        rtl_cmd = [
            "rtl_fm",
            "-f", str(freq_hz),
            "-M", "fm",
            "-l", "0",
            "-A", "std",
            "-s", "171000",
            "-F", "9",
            "-d", str(device_idx),
            "-"
        ]
        if ppm:
            rtl_cmd += ["-p", str(ppm)]
        rtl_cmd += ["-g", str(gain if gain is not None else 38.0)]

        self.log(f"[{name}] FM rtl_fm: {' '.join(rtl_cmd)}")

        try:
            proc = subprocess.Popen(
                rtl_cmd,
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                bufsize=0,
            )
        except Exception as e:
            self.log(f"[{name}] FM: failed to launch rtl_fm: {e}")
            return

        # Drain rtl_fm stderr in a background thread so it doesn't block and
        # we can log anything useful (device errors, USB failures, etc.)
        def _log_rtlsdr_stderr():
            try:
                for raw in proc.stderr:
                    line = raw.decode(errors="ignore").strip()
                    if line:
                        self.log(f"[{name}] FM rtl_fm: {line}")
            except Exception:
                pass
        threading.Thread(target=_log_rtlsdr_stderr, daemon=True,
                         name=f"rtlfm-stderr-{name}").start()

        redsea_proc = None
        redsea_thread = None

        def _apply_redsea_json(obj):
            try:
                from collections import Counter

                ps = str(obj.get("ps") or obj.get("partial_ps") or "").strip()
                rt = str(obj.get("radiotext") or obj.get("partial_radiotext") or "").strip()
                pi = obj.get("pi") or ""
                group = obj.get("group") or ""

                # ---- Stabilise PS (prefer longer full names, ignore short partials) ----
                if not hasattr(cfg, "_fm_ps_hist"):
                    cfg._fm_ps_hist = []
                if ps:
                    current_ps = str(getattr(cfg, "_fm_rds_ps", "") or "").strip()
                    if not (current_ps and len(ps) < len(current_ps)):
                        cfg._fm_ps_hist.append(ps)
                        cfg._fm_ps_hist = cfg._fm_ps_hist[-12:]
                        stable_ps, count = Counter(cfg._fm_ps_hist).most_common(1)[0]
                        if count >= 3 and len(stable_ps) >= max(6, len(current_ps)):
                            cfg._fm_rds_ps = stable_ps
                            _check_rds_name(cfg, sender, self.log, time.time())

                # ---- Stabilise RadioText ----
                if not hasattr(cfg, "_fm_rt_hist"):
                    cfg._fm_rt_hist = []
                if rt:
                    current_rt = str(getattr(cfg, "_fm_rds_rt", "") or "").strip()
                    if not (current_rt and len(rt) < max(8, len(current_rt)//2)):
                        cfg._fm_rt_hist.append(rt)
                        cfg._fm_rt_hist = cfg._fm_rt_hist[-10:]
                        stable_rt, count = Counter(cfg._fm_rt_hist).most_common(1)[0]
                        if count >= 2 or len(stable_rt) >= 12:
                            cfg._fm_rds_rt = stable_rt
                if pi:
                    cfg._fm_rds_pi = str(pi).strip()
                if group:
                    cfg._fm_rds_group = str(group).strip()

                cfg._fm_rds_status = "RDS decoded"
                cfg._fm_rds_ok = True
                cfg._fm_rds_metric = 1.0
                cfg._fm_rds_best_phase = 0
                cfg._fm_rds_valid_groups = int(getattr(cfg, "_fm_rds_valid_groups", 0) or 0) + 1
                cfg._fm_rds_last_good = time.time()
            except Exception:
                pass

        def _redsea_reader():
            try:
                for raw in iter(redsea_proc.stdout.readline, b""):
                    if stop_evt.is_set():
                        break
                    line = raw.decode("utf-8", errors="replace").strip()
                    if not line:
                        continue
                    try:
                        obj = json.loads(line)
                        _apply_redsea_json(obj)
                    except Exception:
                        # Keep stderr/json oddities visible but compact.
                        try:
                            self.log(f"[{name}] redsea: {line[:200]}")
                        except Exception:
                            pass
            except Exception as e:
                try:
                    self.log(f"[{name}] redsea reader stopped: {e}")
                except Exception:
                    pass

        if redsea_bin:
            try:
                redsea_cmd = [redsea_bin, "-r", "171000", "-o", "json", "-p"]
                redsea_proc = subprocess.Popen(
                    redsea_cmd,
                    stdin=subprocess.PIPE,
                    stdout=subprocess.PIPE,
                    stderr=subprocess.STDOUT,
                    bufsize=0,
                )
                redsea_thread = threading.Thread(target=_redsea_reader, daemon=True)
                redsea_thread.start()
                cfg._fm_rds_status = "redsea started"
                self.log(f"[{name}] redsea: {' '.join(redsea_cmd)}")
            except Exception as e:
                self.log(f"[{name}] redsea launch failed: {e}")
                redsea_proc = None
                cfg._fm_rds_status = "redsea launch failed"
                cfg._fm_rds_ok = False
        else:
            cfg._fm_rds_status = "redsea not installed"
            cfg._fm_rds_ok = False

        IN_RATE = 171000
        OUT_RATE = SAMPLE_RATE
        READ_BYTES = 4096
        BLOCK_BYTES = 17100 * 2  # ~100 ms of S16LE MPX
        mux_buf = bytearray()
        out_buf = np.empty(0, dtype=np.float32)
        cfg._fm_signal_dbm = float(getattr(cfg, "_fm_signal_dbm", -120.0) or -120.0)
        cfg._fm_snr_db = float(getattr(cfg, "_fm_snr_db", 0.0) or 0.0)
        cfg._fm_stereo = bool(getattr(cfg, "_fm_stereo", False))
        cfg._fm_rds_ok = bool(getattr(cfg, "_fm_rds_ok", False))

        try:
            from scipy.signal import resample_poly
            _have_scipy_resampler = True
        except Exception:
            _have_scipy_resampler = False

        def _mpx_to_audio(samples_f32: np.ndarray) -> np.ndarray:
            x = np.asarray(samples_f32, dtype=np.float32)
            if x.size == 0:
                return x
            if _have_scipy_resampler:
                # 171000 -> 48000 exactly
                y = resample_poly(x, 16, 57).astype(np.float32, copy=False)
            else:
                n_out = max(1, int(round(x.size * OUT_RATE / float(IN_RATE))))
                src = np.arange(x.size, dtype=np.float32)
                dst = np.linspace(0, max(0, x.size - 1), n_out, dtype=np.float32)
                y = np.interp(dst, src, x).astype(np.float32, copy=False)

            if y.size:
                y = y - np.mean(y)
                peak = float(np.max(np.abs(y)) + 1e-9)
                if peak > 0.95:
                    y = y * (0.95 / peak)
                y = np.clip(y, -1.0, 1.0).astype(np.float32, copy=False)
            return y

        def _update_mpx_metrics(samples_f32: np.ndarray):
            try:
                x = np.asarray(samples_f32, dtype=np.float32)
                if x.size < 2048:
                    return
                rms = float(np.sqrt(np.mean(np.square(x))) + 1e-12)
                cfg._fm_signal_dbm = float(20.0 * np.log10(rms + 1e-12))

                # Pilot estimate from the 19 kHz tone in the MPX stream.
                win = np.hanning(x.size).astype(np.float32)
                X = np.fft.rfft(x * win)
                freqs = np.fft.rfftfreq(x.size, d=1.0 / IN_RATE)
                mag = np.abs(X)
                pilot_band = (freqs >= 18850.0) & (freqs <= 19150.0)
                noise_band = ((freqs >= 17000.0) & (freqs <= 18000.0)) | ((freqs >= 20000.0) & (freqs <= 21000.0))
                pilot = float(np.max(mag[pilot_band])) if np.any(pilot_band) else 0.0
                noise = float(np.median(mag[noise_band])) if np.any(noise_band) else 1e-9
                pilot_db = 20.0 * np.log10((pilot + 1e-12) / (noise + 1e-12))
                cfg._fm_snr_db = float(max(0.0, pilot_db))
                cfg._fm_stereo = bool(pilot_db >= 8.0)
            except Exception:
                pass

        try:
            while not stop_evt.is_set():
                chunk = proc.stdout.read(READ_BYTES)
                if not chunk:
                    if proc.poll() is not None:
                        self.log(f"[{name}] FM: rtl_fm process exited (rc={proc.returncode})")
                        break
                    time.sleep(0.05)
                    continue

                if redsea_proc and redsea_proc.stdin:
                    try:
                        redsea_proc.stdin.write(chunk)
                        redsea_proc.stdin.flush()
                    except Exception:
                        redsea_proc = None
                        cfg._fm_rds_status = "redsea stream failed"
                        cfg._fm_rds_ok = False

                mux_buf.extend(chunk)

                while len(mux_buf) >= BLOCK_BYTES:
                    raw = bytes(mux_buf[:BLOCK_BYTES])
                    del mux_buf[:BLOCK_BYTES]

                    samp = np.frombuffer(raw, dtype="<i2").astype(np.float32) / 32768.0
                    _update_mpx_metrics(samp)
                    audio = _mpx_to_audio(samp)
                    if not audio.size:
                        continue

                    if out_buf.size:
                        out_buf = np.concatenate((out_buf, audio))
                    else:
                        out_buf = audio

                    while out_buf.size >= CHUNK_SIZE:
                        frame = out_buf[:CHUNK_SIZE].copy()
                        out_buf = out_buf[CHUNK_SIZE:]
                        cfg._stream_buffer.append(frame.copy())
                        cfg._audio_buffer.append(frame.copy())
                        cfg._live_chunk_seq = getattr(cfg, "_live_chunk_seq", 0) + 1
                        analyse_chunk(
                            cfg, sender,
                            lambda m, n=name: self.log(f"[{n}] {m}"),
                            frame, CHUNK_DURATION,
                            cfg.alert_wav_duration,
                            self.app_cfg.inputs,
                        )
        except Exception as e:
            self.log(f"[{name}] FM read error: {e}")
        finally:
            try:
                proc.terminate()
            except Exception:
                pass
            try:
                proc.wait(timeout=3)
            except Exception:
                try:
                    proc.kill()
                except Exception:
                    pass

            try:
                if redsea_proc and redsea_proc.stdin:
                    redsea_proc.stdin.close()
            except Exception:
                pass
            try:
                if redsea_proc:
                    redsea_proc.terminate()
            except Exception:
                pass
            try:
                if redsea_proc:
                    redsea_proc.wait(timeout=2)
            except Exception:
                try:
                    redsea_proc.kill()
                except Exception:
                    pass

        self.log(f"[{name}] FM rtl_fm thread stopped.")
    def _run_http(self, cfg, sender, stop_evt):
        """Receive an HTTP/HTTPS audio stream (MP3, AAC, OGG, etc) via ffmpeg → PCM."""
        import subprocess, shutil
        name = cfg.name
        url  = cfg.device_index.strip()
        cfg._livewire_mode = f"HTTP: {url}"

        if not _find_binary("ffmpeg"):
            self.log(f"[{name}] ffmpeg not found on PATH — install ffmpeg to use HTTP streams.")
            cfg._livewire_mode = "HTTP (ffmpeg missing)"
            return

        # ffmpeg: read URL → raw signed-16 LE PCM, mono, 48 kHz on stdout
        cmd = [
            "ffmpeg", "-hide_banner", "-loglevel", "error",
            "-reconnect", "1", "-reconnect_streamed", "1",
            "-reconnect_delay_max", "10",
            "-i", url,
            "-vn", "-ac", "1", "-ar", str(SAMPLE_RATE), "-f", "s16le", "pipe:1",
        ]

        CHUNK_BYTES = int(SAMPLE_RATE * CHUNK_DURATION) * 2   # s16le = 2 bytes/sample

        while not stop_evt.is_set():
            proc = None
            try:
                proc = subprocess.Popen(cmd, stdout=subprocess.PIPE, stderr=subprocess.PIPE,
                                        bufsize=CHUNK_BYTES * 4)
                self.log(f"[{name}] ffmpeg connected → {url}")
                buf = bytearray()

                while not stop_evt.is_set():
                    chunk = proc.stdout.read(4096)
                    if not chunk:
                        time.sleep(0.05); continue
                    buf.extend(chunk)
                    while len(buf) >= CHUNK_BYTES:
                        raw = bytes(buf[:CHUNK_BYTES])
                        del buf[:CHUNK_BYTES]
                        samp = np.frombuffer(raw, dtype="<i2").astype(np.float32) / 32768.0
                        samp = np.clip(samp - np.mean(samp), -1.0, 1.0)
                        cfg._stream_buffer.append(samp.copy())
                        cfg._audio_buffer.append(samp.copy())
                        cfg._live_chunk_seq = getattr(cfg, '_live_chunk_seq', 0) + 1
                        analyse_chunk(cfg, sender,
                                      lambda m, n=name: self.log(f"[{n}] {m}"),
                                      samp, CHUNK_DURATION,
                                      cfg.alert_wav_duration,
                                      self.app_cfg.inputs)

            except Exception as e:
                self.log(f"[{name}] HTTP stream error: {e}")
            finally:
                if proc:
                    try: proc.kill()
                    except: pass
                    proc.wait()

            if not stop_evt.is_set():
                self.log(f"[{name}] Disconnected — reconnecting in 5s…")
                stop_evt.wait(5)

        self.log(f"[{name}] HTTP stream thread stopped.")

    def _open_udp_socket_for_cfg(self, cfg):
        name = cfg.name
        try:
            mc_ip, port = _parse_device(cfg.device_index)
        except Exception as e:
            self.log(f"[{name}] Bad device_index: {e}")
            return None
        iface = self.app_cfg.network.audio_interface_ip or "0.0.0.0"
        is_multicast = mc_ip.startswith(("224.", "225.", "226.", "239."))
        self.log(f"[{name}] {'Joining multicast' if is_multicast else 'Unicast UDP bind'} {mc_ip}:{port}")
        try:
            sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM, socket.IPPROTO_UDP)
            sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
            try:
                sock.setsockopt(socket.SOL_SOCKET, socket.SO_RCVBUF, 256 * 1024 * 1024)
            except Exception:
                pass
            if is_multicast:
                sock.bind(("", port))
                mreq = struct.pack("4s4s", socket.inet_aton(mc_ip), socket.inet_aton(iface))
                sock.setsockopt(socket.IPPROTO_IP, socket.IP_ADD_MEMBERSHIP, mreq)
                if iface != "0.0.0.0":
                    sock.setsockopt(socket.IPPROTO_IP, socket.IP_MULTICAST_IF, socket.inet_aton(iface))
            else:
                bind_ip = mc_ip if iface == "0.0.0.0" else iface
                sock.bind((bind_ip, port))
            sock.setblocking(False)
            try:
                actual = sock.getsockopt(socket.SOL_SOCKET, socket.SO_RCVBUF)
                self.log(f"[{name}] UDP receive buffer {actual}")
            except Exception:
                pass
            return sock
        except Exception as e:
            self.log(f"[{name}] Socket failed: {e}")
            return None

    def _handle_udp_packet(self, st, packet, sender):
        cfg = st['cfg']
        name = cfg.name
        if len(packet) <= 12:
            return

        # RTP jitter — inter-arrival time variance (RFC 3550 style, wall-clock)
        _arr_now = time.monotonic()
        if cfg._rtp_last_arrival > 0.0:
            _iat_ms = (_arr_now - cfg._rtp_last_arrival) * 1000.0
            if cfg._rtp_jitter_acc == 0.0:
                cfg._rtp_jitter_acc = _iat_ms
            else:
                cfg._rtp_jitter_acc = 0.9375 * cfg._rtp_jitter_acc + 0.0625 * _iat_ms
            cfg._rtp_jitter_ms += (abs(_iat_ms - cfg._rtp_jitter_acc) - cfg._rtp_jitter_ms) / 16.0
        cfg._rtp_last_arrival = _arr_now

        # Keep a short RTP sequence reorder buffer so packets are processed in
        # sequence order rather than raw arrival order. This is important on
        # Linux/VMware where small bursts or mild reordering are common.
        reorder = st.setdefault('reorder', {})
        max_reorder = int(st.get('max_reorder', 16))
        rtp_seq = struct.unpack_from(">H", packet, 2)[0]
        if st.get('expected_seq') is None:
            st['expected_seq'] = rtp_seq

        # recvfrom_into reuses the same backing buffer, so persist packet bytes.
        if rtp_seq not in reorder:
            reorder[rtp_seq] = bytes(packet)

        def _process_ordered(pkt_bytes, seqno):
            if cfg._rtp_last_seq >= 0:
                expected = (cfg._rtp_last_seq + 1) & 0xFFFF
                if seqno != expected:
                    gap = (seqno - expected) & 0xFFFF
                    if 0 < gap < 1000:
                        cfg._rtp_lost += gap
                        cfg._rtp_loss_window += gap
                cfg._rtp_total += 1
                cfg._rtp_total_window += 1
                if cfg._rtp_total_window >= 1000:
                    cfg._rtp_loss_pct = 100.0 * cfg._rtp_loss_window / cfg._rtp_total_window
                    cfg._rtp_loss_window = 0
                    cfg._rtp_total_window = 0
                    if cfg._rtp_loss_pct >= RTP_LOSS_ALERT_PCT:
                        key = "RTP_LOSS_ALERT"
                        if time.time() - cfg._last_alerts.get(key,0) >= ALERT_COOLDOWN:
                            cfg._last_alerts[key] = time.time()
                            msg = f"RTP packet loss {cfg._rtp_loss_pct:.1f}% on '{cfg.name}'"
                            clip = _save_alert_wav(cfg, "rtp_loss", cfg.alert_wav_duration)
                            _add_history(cfg, "RTP_LOSS", msg, clip_path=clip or "")
                            sender.send(f"RTP Loss — {cfg.name}", msg, clip,
                                alert_type="RTP_LOSS", stream=cfg.name,
                                level_dbfs=float(cfg._last_level_dbfs))
                    elif cfg._rtp_loss_pct >= RTP_LOSS_WARN_PCT:
                        key = "RTP_LOSS_WARN"
                        if time.time() - cfg._last_alerts.get(key,0) >= ALERT_COOLDOWN*2:
                            cfg._last_alerts[key] = time.time()
                            msg = f"RTP packet loss {cfg._rtp_loss_pct:.1f}% on '{cfg.name}'"
                            clip = _save_alert_wav(cfg, "rtp_loss_warn", cfg.alert_wav_duration)
                            _add_history(cfg, "RTP_LOSS_WARN", msg, clip_path=clip or "")
            cfg._rtp_last_seq = seqno
            rtp_cc = pkt_bytes[0] & 0x0F
            rtp_ext = (pkt_bytes[0] >> 4) & 0x01
            rtp_pt = pkt_bytes[1] & 0x7F
            hdr = 12 + rtp_cc * 4
            if rtp_ext and len(pkt_bytes) >= hdr + 4:
                hdr += 4 + (((pkt_bytes[hdr+2] << 8) | pkt_bytes[hdr+3]) * 4)
            if len(pkt_bytes) <= hdr:
                return
            payload = pkt_bytes[hdr:]
            if not st['detected']:
                fmt, bps, ch, mode = _detect_fmt(len(payload), rtp_pt)
                st['fmt'], st['bps'], st['ch'] = fmt, bps, ch
                st['needed'] = int(SAMPLE_RATE * CHUNK_DURATION) * ch * bps
                st['detected'] = True
                cfg._livewire_mode = mode
                self.log(f"[{name}] {mode} (PT={rtp_pt}, {len(payload)}B)")
            st['buf'].extend(payload)
            while len(st['buf']) >= st['needed']:
                samp = _decode(bytes(st['buf'][:st['needed']]), st['fmt'], st['ch'])
                del st['buf'][:st['needed']]
                if samp is None:
                    continue
                samp = np.clip(samp - np.mean(samp), -1.0, 1.0)
                cfg._stream_buffer.append(samp.copy())
                cfg._audio_buffer.append(samp.copy())
                cfg._live_chunk_seq = getattr(cfg, '_live_chunk_seq', 0) + 1
                analyse_chunk(cfg, sender, lambda m, n=name: self.log(f"[{n}] {m}"),
                              samp, CHUNK_DURATION, cfg.alert_wav_duration, self.app_cfg.inputs)

        # Drain contiguous packets in sequence order.
        while st['expected_seq'] in reorder:
            seqno = st['expected_seq']
            pkt = reorder.pop(seqno)
            _process_ordered(pkt, seqno)
            st['expected_seq'] = (st['expected_seq'] + 1) & 0xFFFF

        # If the reorder window fills, advance until we reach the earliest
        # packet we do have. Count the skipped sequence numbers as lost.
        if len(reorder) >= max_reorder:
            keys = list(reorder.keys())
            best_seq = min(keys, key=lambda s: ((s - st['expected_seq']) & 0xFFFF))
            gap = (best_seq - st['expected_seq']) & 0xFFFF
            if 0 < gap < 1000:
                cfg._rtp_lost += gap
                cfg._rtp_loss_window += gap
            st['expected_seq'] = best_seq
            while st['expected_seq'] in reorder:
                seqno = st['expected_seq']
                pkt = reorder.pop(seqno)
                _process_ordered(pkt, seqno)
                st['expected_seq'] = (st['expected_seq'] + 1) & 0xFFFF

    def _run_udp_inputs(self, cfgs, sender, stop_evt):
        selector = selectors.DefaultSelector()
        active = 0
        recvbuf = bytearray(4096)
        iface = self.app_cfg.network.audio_interface_ip or "0.0.0.0"

        # State for each logical stream stays separate; only the socket is shared.
        def _mk_state(cfg, sock):
            return {
                'cfg': cfg,
                'sock': sock,
                'fmt': None,
                'bps': 3,
                'ch': 2,
                'needed': 0,
                'buf': bytearray(),
                'detected': False,
                'reorder': {},
                'expected_seq': None,
                'max_reorder': 16,
            }

        def _is_multicast(ip):
            return ip.startswith(("224.", "225.", "226.", "227.", "228.", "229.", "230.", "231.", "232.", "233.", "234.", "235.", "236.", "237.", "238.", "239."))

        # Build one shared socket per UDP port for multicast groups; keep unicast one-socket-per-input.
        shared_by_port = {}
        states = {}

        for cfg in cfgs:
            try:
                mc_ip, port = _parse_device(cfg.device_index)
            except Exception as e:
                self.log(f"[{cfg.name}] Bad device_index: {e}")
                continue

            if _is_multicast(mc_ip):
                entry = shared_by_port.get(port)
                if entry is None:
                    try:
                        sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM, socket.IPPROTO_UDP)
                        sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
                        try:
                            sock.setsockopt(socket.SOL_SOCKET, socket.SO_RCVBUF, 256 * 1024 * 1024)
                        except Exception:
                            pass
                        # Required to learn which multicast group this packet was sent to.
                        try:
                            sock.setsockopt(socket.IPPROTO_IP, socket.IP_PKTINFO, 1)
                        except Exception:
                            pass
                        sock.bind(("", port))
                        sock.setblocking(False)
                        entry = {'sock': sock, 'port': port, 'by_group': {}}
                        shared_by_port[port] = entry
                        selector.register(sock, selectors.EVENT_READ, ('shared-mcast', entry))
                        active += 1
                        try:
                            actual = sock.getsockopt(socket.SOL_SOCKET, socket.SO_RCVBUF)
                            self.log(f"[RTP:{port}] Shared multicast socket receive buffer {actual}")
                        except Exception:
                            pass
                    except Exception as e:
                        self.log(f"[{cfg.name}] Shared multicast socket failed: {e}")
                        continue

                try:
                    mreq = struct.pack("4s4s", socket.inet_aton(mc_ip), socket.inet_aton(iface))
                    entry['sock'].setsockopt(socket.IPPROTO_IP, socket.IP_ADD_MEMBERSHIP, mreq)
                except OSError as e:
                    # Ignore duplicate joins for same group on restart edge cases.
                    self.log(f"[{cfg.name}] multicast join {mc_ip}:{port} → {e}")
                st = _mk_state(cfg, entry['sock'])
                entry['by_group'][mc_ip] = st
                self.log(f"[{cfg.name}] Shared multicast join {mc_ip}:{port}")
            else:
                sock = self._open_udp_socket_for_cfg(cfg)
                if not sock:
                    continue
                st = _mk_state(cfg, sock)
                states[sock] = st
                selector.register(sock, selectors.EVENT_READ, ('unicast', st))
                self.log(f"[{cfg.name}] Listening — detecting format…")
                active += 1

        if not active and not shared_by_port:
            self.log('[RTP] No UDP inputs could be opened.')
            return

        mcast_streams = sum(len(e['by_group']) for e in shared_by_port.values())
        unicast_streams = len(states)
        self.log(f"[RTP] Central receiver active for {mcast_streams + unicast_streams} UDP input(s) across {len(shared_by_port)} shared multicast port(s).")

        while not stop_evt.is_set():
            try:
                events = selector.select(timeout=1.0)
            except Exception as e:
                self.log(f"[RTP] select error: {e}")
                time.sleep(0.2)
                continue

            for key, _ in events:
                kind, data = key.data
                sock = key.fileobj
                drained = 0

                if kind == 'shared-mcast':
                    entry = data
                    while drained < 128 and not stop_evt.is_set():
                        try:
                            nbytes, ancdata, _flags, _addr = sock.recvmsg_into([recvbuf], 256)
                        except BlockingIOError:
                            break
                        except Exception as e:
                            self.log(f"[RTP:{entry['port']}] recv: {e}")
                            break
                        if nbytes <= 0:
                            break

                        dst_ip = None
                        for level, ctype, cdata in ancdata:
                            if level == socket.IPPROTO_IP and ctype == getattr(socket, 'IP_PKTINFO', -1) and len(cdata) >= 12:
                                try:
                                    _ifindex, _spec, addr = struct.unpack('I4s4s', cdata[:12])
                                    dst_ip = socket.inet_ntoa(addr)
                                except Exception:
                                    pass
                        if not dst_ip:
                            # Fallback: if only one group on this port, dispatch to it.
                            if len(entry['by_group']) == 1:
                                dst_ip = next(iter(entry['by_group']))
                        st = entry['by_group'].get(dst_ip)
                        if st is not None:
                            self._handle_udp_packet(st, memoryview(recvbuf)[:nbytes], sender)
                        drained += 1
                else:
                    st = data
                    while drained < 64 and not stop_evt.is_set():
                        try:
                            nbytes, _addr = sock.recvfrom_into(recvbuf)
                        except BlockingIOError:
                            break
                        except Exception as e:
                            self.log(f"[{st['cfg'].name}] recv: {e}")
                            break
                        if nbytes <= 0:
                            break
                        self._handle_udp_packet(st, memoryview(recvbuf)[:nbytes], sender)
                        drained += 1

        # Cleanup
        for sock, st in list(states.items()):
            try:
                selector.unregister(sock)
            except Exception:
                pass
            try:
                sock.close()
            except Exception:
                pass
            self.log(f"[{st['cfg'].name}] Thread stopped.")

        for entry in list(shared_by_port.values()):
            try:
                selector.unregister(entry['sock'])
            except Exception:
                pass
            try:
                entry['sock'].close()
            except Exception:
                pass
            for st in entry['by_group'].values():
                self.log(f"[{st['cfg'].name}] Thread stopped.")

        try:
            selector.close()
        except Exception:
            pass

    def _run_sound(self, cfg, sender, stop_evt):
        """Capture audio from a local ALSA/PulseAudio sound device via sounddevice."""
        name = cfg.name
        dev_str = cfg.device_index.strip()
        # Format: sound://<device_index_or_name>
        dev_part = dev_str[len("sound://"):]
        # Try as integer index, otherwise use as name substring
        device = int(dev_part) if dev_part.isdigit() else (dev_part or None)

        try:
            import sounddevice as sd
        except ImportError:
            self.log(f"[{name}] sounddevice not installed — run: pip install sounddevice")
            return

        self.log(f"[{name}] Opening sound device: {device!r} at {SAMPLE_RATE} Hz")
        inputs = self.app_cfg.inputs
        q = collections.deque(maxlen=8)

        def _cb(indata, frames, time_info, status):
            mono = indata.mean(axis=1).astype(np.float32)
            q.append(mono.copy())

        try:
            with sd.InputStream(device=device, channels=None, samplerate=SAMPLE_RATE,
                                dtype='float32', blocksize=CHUNK_SIZE, callback=_cb):
                self.log(f"[{name}] Sound device stream open.")
                while not stop_evt.is_set():
                    if q:
                        chunk = q.popleft()
                        analyse_chunk(cfg, sender, self.log, chunk, CHUNK_DURATION,
                                      cfg.alert_wav_duration, inputs)
                        if cfg._stream_buffer is not None:
                            cfg._stream_buffer.append(chunk.copy())
                            cfg._live_chunk_seq = getattr(cfg, '_live_chunk_seq', 0) + 1
                    else:
                        time.sleep(0.05)
        except Exception as e:
            self.log(f"[{name}] Sound device error: {e}")
        self.log(f"[{name}] Sound device thread stopped.")

    def _run_input(self, cfg, sender, stop_evt):
        name=cfg.name
        # Check for DAB source
        if cfg.device_index.strip().lower().startswith("dab://"):
            self._run_dab(cfg, sender, stop_evt)
            return
        # Check for FM source
        if cfg.device_index.strip().lower().startswith("fm://"):
            self._run_fm(cfg, sender, stop_evt)
            return
        # Check for local sound device
        if cfg.device_index.strip().lower().startswith("sound://"):
            self._run_sound(cfg, sender, stop_evt)
            return
        # Check for HTTP/HTTPS stream
        dev = cfg.device_index.strip()
        if dev.lower().startswith("http://") or dev.lower().startswith("https://"):
            self._run_http(cfg, sender, stop_evt)
            return
        try: mc_ip,port=_parse_device(cfg.device_index)
        except Exception as e: self.log(f"[{name}] Bad device_index: {e}"); return
        iface=self.app_cfg.network.audio_interface_ip or "0.0.0.0"
        # Detect unicast vs multicast
        is_multicast = mc_ip.startswith("224.") or mc_ip.startswith("225.") or \
                       mc_ip.startswith("226.") or mc_ip.startswith("239.")
        self.log(f"[{name}] {'Joining multicast' if is_multicast else 'Unicast UDP bind'} {mc_ip}:{port}")
        try:
            sock=socket.socket(socket.AF_INET,socket.SOCK_DGRAM,socket.IPPROTO_UDP)
            sock.setsockopt(socket.SOL_SOCKET,socket.SO_REUSEADDR,1)
            if is_multicast:
                sock.bind(("",port))
                mreq=struct.pack("4s4s",socket.inet_aton(mc_ip),socket.inet_aton(iface))
                sock.setsockopt(socket.IPPROTO_IP,socket.IP_ADD_MEMBERSHIP,mreq)
                if iface!="0.0.0.0":
                    sock.setsockopt(socket.IPPROTO_IP,socket.IP_MULTICAST_IF,socket.inet_aton(iface))
            else:
                # Unicast — bind to the specific IP:port
                bind_ip = mc_ip if iface=="0.0.0.0" else iface
                sock.bind((bind_ip, port))
            sock.settimeout(1.0)
        except Exception as e: self.log(f"[{name}] Socket failed: {e}"); return

        fmt=None; bps=3; ch=2; needed=0; buf=bytearray(); detected=False
        self.log(f"[{name}] Listening — detecting format…")

        while not stop_evt.is_set():
            try: packet,_=sock.recvfrom(2048)
            except socket.timeout: continue
            except Exception as e: self.log(f"[{name}] recv: {e}"); time.sleep(0.5); continue
            if len(packet)<=12: continue
            # RTP jitter — inter-arrival time variance
            _arr_now = time.monotonic()
            if cfg._rtp_last_arrival > 0.0:
                _iat_ms = (_arr_now - cfg._rtp_last_arrival) * 1000.0
                if cfg._rtp_jitter_acc == 0.0:
                    cfg._rtp_jitter_acc = _iat_ms
                else:
                    cfg._rtp_jitter_acc = 0.9375 * cfg._rtp_jitter_acc + 0.0625 * _iat_ms
                cfg._rtp_jitter_ms += (abs(_iat_ms - cfg._rtp_jitter_acc) - cfg._rtp_jitter_ms) / 16.0
            cfg._rtp_last_arrival = _arr_now
            rtp_seq = struct.unpack_from(">H", packet, 2)[0]
            # RTP packet loss tracking
            if cfg._rtp_last_seq >= 0:
                expected = (cfg._rtp_last_seq + 1) & 0xFFFF
                if rtp_seq != expected:
                    gap = (rtp_seq - expected) & 0xFFFF
                    if 0 < gap < 1000:   # ignore reorder / wrap artifacts
                        cfg._rtp_lost += gap
                        cfg._rtp_loss_window += gap
                cfg._rtp_total += 1
                cfg._rtp_total_window += 1
                if cfg._rtp_total_window >= 1000:
                    cfg._rtp_loss_pct = 100.0 * cfg._rtp_loss_window / cfg._rtp_total_window
                    cfg._rtp_loss_window = 0
                    cfg._rtp_total_window = 0
                    if cfg._rtp_loss_pct >= RTP_LOSS_ALERT_PCT:
                        key = "RTP_LOSS_ALERT"
                        if time.time() - cfg._last_alerts.get(key,0) >= ALERT_COOLDOWN:
                            cfg._last_alerts[key] = time.time()
                            msg = f"RTP packet loss {cfg._rtp_loss_pct:.1f}% on '{cfg.name}'"
                            clip = _save_alert_wav(cfg, "rtp_loss", cfg.alert_wav_duration)
                            _add_history(cfg, "RTP_LOSS", msg, clip_path=clip or "")
                            sender.send(f"RTP Loss — {cfg.name}", msg, clip,
                                alert_type="RTP_LOSS", stream=cfg.name,
                                level_dbfs=float(cfg._last_level_dbfs))
                    elif cfg._rtp_loss_pct >= RTP_LOSS_WARN_PCT:
                        key = "RTP_LOSS_WARN"
                        if time.time() - cfg._last_alerts.get(key,0) >= ALERT_COOLDOWN*2:
                            cfg._last_alerts[key] = time.time()
                            msg = f"RTP packet loss {cfg._rtp_loss_pct:.1f}% on '{cfg.name}'"
                            clip = _save_alert_wav(cfg, "rtp_loss_warn", cfg.alert_wav_duration)
                            _add_history(cfg, "RTP_LOSS_WARN", msg, clip_path=clip or "")
            cfg._rtp_last_seq = rtp_seq
            rtp_cc=packet[0]&0x0F; rtp_ext=(packet[0]>>4)&0x01; rtp_pt=packet[1]&0x7F
            hdr=12+rtp_cc*4
            if rtp_ext and len(packet)>=hdr+4:
                hdr+=4+(((packet[hdr+2]<<8)|packet[hdr+3])*4)
            if len(packet)<=hdr: continue
            payload=packet[hdr:]
            if not detected:
                fmt,bps,ch,mode=_detect_fmt(len(payload),rtp_pt)
                cfg._livewire_mode=mode; needed=int(SAMPLE_RATE*CHUNK_DURATION)*ch*bps
                detected=True; self.log(f"[{name}] {mode} (PT={rtp_pt}, {len(payload)}B)")
            buf.extend(payload)
            while len(buf)>=needed:
                samp=_decode(bytes(buf[:needed]),fmt,ch); del buf[:needed]
                if samp is None: continue
                samp=np.clip(samp-np.mean(samp),-1.0,1.0)
                cfg._stream_buffer.append(samp.copy()); cfg._audio_buffer.append(samp.copy())
                cfg._live_chunk_seq = getattr(cfg, '_live_chunk_seq', 0) + 1
                analyse_chunk(cfg,sender,lambda m,n=name:self.log(f"[{n}] {m}"),
                              samp,CHUNK_DURATION,cfg.alert_wav_duration,self.app_cfg.inputs)
        try: sock.close()
        except: pass
        self.log(f"[{name}] Thread stopped.")

    def _ai_loop(self, stop_evt):
        self.log("[AI] Loop started.")
        while not stop_evt.is_set():
            for cfg in list(self.app_cfg.inputs):
                if not cfg.enabled or not cfg.ai_monitor or cfg._audio_buffer is None: continue
                now=time.time()
                if now-cfg._ai_last_run<AI_ANALYSIS_INTERVAL: continue
                cfg._ai_last_run=now
                chunks=list(cfg._audio_buffer)
                if not chunks: continue
                audio=np.concatenate(chunks)
                target=int(SAMPLE_RATE*3.0)
                if len(audio)<int(SAMPLE_RATE*0.5): continue
                audio=audio[-target:] if len(audio)>target else audio
                ai=self._stream_ais.get(cfg.name)
                if ai:
                    try: ai.feed(audio)
                    except Exception as e: self.log(f"[AI:{cfg.name}] {e}")
            # Update stream comparators
            for comp in self._comparators:
                try: comp.update()
                except Exception as e: self.log(f"[CMP] Error: {e}")
            # Metrics flush — write a snapshot to SQLite once per minute
            _now = time.time()
            if _now - self._metrics_last_flush >= 60.0:
                self._metrics_last_flush = _now
                try:
                    _metrics_flush(list(self.app_cfg.inputs))
                except Exception as e:
                    self.log(f"[METRICS] Flush error: {e}")
                # PTP metrics — keyed as "ptp/local"
                try:
                    ptp = self.ptp
                    if ptp and ptp.state not in ("idle", ""):
                        metrics_db.write([
                            ("ptp/local", "ptp_offset_us", _now, ptp.offset_us),
                            ("ptp/local", "ptp_jitter_us", _now, ptp.jitter_us),
                            ("ptp/local", "ptp_drift_us",  _now, ptp.drift_us),
                        ])
                except Exception as e:
                    self.log(f"[METRICS] PTP flush error: {e}")
            # Daily metrics prune + report
            _today = time.strftime("%Y-%m-%d")
            if _today != self._metrics_last_prune:
                self._metrics_last_prune = _today
                try:
                    metrics_db.prune()
                    self.log(f"[METRICS] Pruned rows older than {METRICS_RETENTION_DAYS} days")
                except Exception as e:
                    self.log(f"[METRICS] Prune error: {e}")
            try: self._check_daily_report()
            except Exception as e: self.log(f"[REPORT] {e}")
            time.sleep(1.0)
        self.log("[AI] Loop stopped.")

    def _check_daily_report(self):
        if not self.app_cfg.email.enabled or not self.app_cfg.email.smtp_host: return
        now_str = time.strftime("%H:%M")
        today   = time.strftime("%Y-%m-%d")
        if now_str == self.app_cfg.daily_report_time and self._report_sent_date != today:
            self._report_sent_date = today
            self._send_daily_report(today)

    def _send_daily_report(self, date: str):
        lines = [f"SignalScope — Daily Report {date}", "="*50, ""]
        for inp in self.app_cfg.inputs:
            lines.append(f"Stream: {inp.name}")
            total = inp._rtp_total; lost = inp._rtp_lost
            pct = 100.0*lost/total if total>0 else 0.0
            lines.append(f"  RTP: {total:,} pkts  Lost: {lost:,}  Loss: {pct:.2f}%")
            lines.append(f"  AI: {inp._ai_status or 'N/A'}  Phase: {inp._ai_phase}")
            recent=[h for h in inp._history if h.get("type","") in
                    ("AI_ALERT","AI_WARN","SILENCE","CLIP","HISS","RTP_LOSS","CMP_ALERT")]
            if recent:
                lines.append(f"  Alerts ({len(recent)}):")
                for h in recent[-10:]:
                    lines.append(f"    [{h['timestamp']}] [{h['type']}] {h['message'][:80]}")
            else:
                lines.append("  No alerts")
            lines.append("")
        if self.ptp:
            lines.append("PTP Clock:")
            lines.append(f"  State: {self.ptp.state}  GM: {self.ptp.gm_id}")
            lines.append(f"  Offset: {self.ptp.offset_us/1000:.3f} ms  Jitter: {self.ptp.jitter_us/1000:.3f} ms")
            for h in self.ptp.history[-5:]:
                lines.append(f"  [{h['timestamp']}] {h['message'][:80]}")
            lines.append("")
        for comp in self._comparators:
            lines.append(f"Comparison '{comp.pre.name}' → '{comp.post.name}': {comp.status}")
        lines.append("")
        AlertSender(self.app_cfg, self.log).send(
            f"Daily Report — {date}", "\n".join(lines))
        self.log(f"[REPORT] Daily report sent for {date}")

# ─── Hub client — pushes heartbeat to central hub ─────────────────────────────

# ─── Hub security — HMAC signing, replay protection, rate limiting, encryption ─

import hmac as _hmac


def _derive_key(secret: str, purpose: str) -> bytes:
    """Derive a purpose-specific 256-bit key from the shared secret."""
    return hashlib.sha256(f"{secret}:{purpose}".encode()).digest()


def hub_sign_payload(secret: str, payload_bytes: bytes, ts: float) -> str:
    """HMAC-SHA256 over timestamp+payload. Secret never sent on wire."""
    key = _derive_key(secret, "signing")
    msg = f"{ts:.0f}:".encode() + payload_bytes
    return _hmac.new(key, msg, hashlib.sha256).hexdigest()


def hub_verify_signature(secret: str, payload_bytes: bytes,
                         sig: str, ts: float):
    """Verify HMAC signature and timestamp freshness. Returns (ok, reason)."""
    now = time.time()
    if abs(now - ts) > HUB_TIMESTAMP_TOLERANCE:
        return False, f"timestamp out of window ({abs(now-ts):.0f}s)"
    expected = hub_sign_payload(secret, payload_bytes, ts)
    if not _hmac.compare_digest(expected, sig):
        return False, "invalid signature"
    return True, ""


# ── Hub payload encryption ───────────────────────────────────────────────────
# Uses AES-256-GCM (AEAD) when the cryptography package is available.
# AES-GCM provides both confidentiality and integrity in one standard primitive,
# replacing the previous custom SHA-256 keystream XOR.
# Falls back to the keystream XOR if cryptography is not installed.
_HUB_CRYPTO_VERSION_AES = b"\x02"   # prefix byte: 0x02 = AES-GCM
_HUB_CRYPTO_VERSION_XOR = b"\x01"   # prefix byte: 0x01 = legacy XOR (no MAC — read-only compat)
_HUB_CRYPTO_VERSION_XOR_MAC = b"\x03"  # prefix byte: 0x03 = XOR + HMAC-SHA256 MAC


def hub_encrypt_payload(secret: str, plaintext: bytes) -> bytes:
    """
    Encrypt payload using AES-256-GCM (preferred) or SHA-256 keystream XOR (fallback).
    Format: [1-byte version][12-byte nonce][ciphertext+16-byte GCM tag]  (AES-GCM)
         or [1-byte version][16-byte salt][ciphertext][32-byte HMAC-SHA256 tag] (XOR)
    """
    key = _derive_key(secret, "encryption")
    try:
        from cryptography.hazmat.primitives.ciphers.aead import AESGCM
        nonce = os.urandom(12)
        ct    = AESGCM(key).encrypt(nonce, plaintext, None)
        return _HUB_CRYPTO_VERSION_AES + nonce + ct
    except ImportError:
        # Fall back to XOR + HMAC-SHA256 authentication tag.
        # Uses version \x03 so old hubs/clients (which used \x01 without MAC)
        # can still communicate during rolling upgrades — \x01 is decrypt-only.
        salt = os.urandom(16)
        ciphertext = _keystream_xor(key, salt, plaintext)
        mac_key = _derive_key(secret, "mac")
        tag = _hmac.new(mac_key, ciphertext, hashlib.sha256).digest()
        return _HUB_CRYPTO_VERSION_XOR_MAC + salt + ciphertext + tag


def hub_decrypt_payload(secret: str, data: bytes) -> bytes:
    """Decrypt payload produced by hub_encrypt_payload. Handles both versions."""
    if len(data) < 2:
        raise ValueError("payload too short")
    version = data[:1]
    key = _derive_key(secret, "encryption")
    if version == _HUB_CRYPTO_VERSION_AES:
        try:
            from cryptography.hazmat.primitives.ciphers.aead import AESGCM
            if len(data) < 29:  # 1 + 12 + 16 minimum
                raise ValueError("AES-GCM payload too short")
            nonce = data[1:13]
            ct    = data[13:]
            return AESGCM(key).decrypt(nonce, ct, None)
        except ImportError:
            raise RuntimeError("cryptography package required to decrypt AES-GCM payload")
    elif version == _HUB_CRYPTO_VERSION_XOR_MAC:
        # \x03 — XOR + HMAC-SHA256 MAC (produced by 3.4.68+)
        if len(data) < 50:   # 1 + 16 + 1 + 32 minimum (version + salt + 1 byte ct + MAC)
            raise ValueError("XOR payload too short")
        mac_key = _derive_key(secret, "mac")
        ciphertext = data[17:-32]
        tag        = data[-32:]
        expected   = _hmac.new(mac_key, ciphertext, hashlib.sha256).digest()
        if not _hmac.compare_digest(expected, tag):
            raise ValueError("MAC mismatch")
        return _keystream_xor(key, data[1:17], ciphertext)
    elif version == _HUB_CRYPTO_VERSION_XOR:
        # \x01 — legacy XOR without MAC (pre-3.4.68) — decrypt-only, no integrity check
        if len(data) < 18:
            raise ValueError("XOR payload too short")
        return _keystream_xor(key, data[1:17], data[17:])
    else:
        # Pre-versioned legacy format (no prefix byte) — treat whole thing as XOR
        if len(data) < 17:
            raise ValueError("payload too short")
        return _keystream_xor(key, data[:16], data[16:])


def _keystream_xor(key: bytes, iv: bytes, data: bytes) -> bytes:
    """Legacy XOR fallback. Kept for backward compatibility with older clients."""
    out = bytearray(len(data))
    offset = 0
    ctr = 0
    while offset < len(data):
        block = hashlib.sha256(key + iv + ctr.to_bytes(4, "big")).digest()
        for b in block:
            if offset >= len(data):
                break
            out[offset] = data[offset] ^ b
            offset += 1
        ctr += 1
    return bytes(out)


class HubRateLimiter:
    """Token-bucket rate limiter per client key.
    Keyed by site_name when available (reliable across NAT/proxies),
    falling back to IP. Allows HUB_RATE_LIMIT_RPM per minute per key.
    """
    def __init__(self):
        self._hits: Dict[str, list] = {}
        self._lock = threading.Lock()

    def allow(self, key: str) -> bool:
        now = time.time()
        with self._lock:
            hits = [t for t in self._hits.get(key, []) if now - t < 60.0]
            if len(hits) >= HUB_RATE_LIMIT_RPM:
                self._hits[key] = hits
                return False
            hits.append(now)
            self._hits[key] = hits
            return True

    def cleanup(self):
        now = time.time()
        with self._lock:
            stale = [k for k, hits in self._hits.items()
                     if not any(now - t < 60.0 for t in hits)]
            for k in stale: del self._hits[k]


class HubNonceStore:
    """Tracks recently seen nonces to block exact replays within the time window."""
    def __init__(self):
        self._seen: Dict[str, float] = {}
        self._lock = threading.Lock()

    def check_and_store(self, nonce: str) -> bool:
        """Returns True if nonce is fresh (not a replay)."""
        now = time.time()
        with self._lock:
            cutoff = now - HUB_TIMESTAMP_TOLERANCE * 2
            self._seen = {n: t for n, t in self._seen.items() if t > cutoff}
            if nonce in self._seen:
                return False
            self._seen[nonce] = now
            return True


def _find_binary(name: str) -> str:
    """Find a system binary by name, searching system PATH even when running
    inside a virtualenv where the venv bin/ directory shadows the system PATH.
    Returns the full path or empty string if not found."""
    import shutil as _sh
    # First try the normal way
    found = _sh.which(name)
    if found:
        return found
    # Search standard system paths explicitly (bypasses venv PATH restriction)
    import os as _os
    for directory in ["/usr/bin", "/usr/local/bin", "/bin",
                      "/usr/sbin", "/snap/bin"]:
        candidate = _os.path.join(directory, name)
        if _os.path.isfile(candidate) and _os.access(candidate, _os.X_OK):
            return candidate
    return ""


hub_rate_limiter = HubRateLimiter()
hub_nonce_store  = HubNonceStore()

# Background cleanup
def _security_cleanup():
    while True:
        time.sleep(120)
        hub_rate_limiter.cleanup()
threading.Thread(target=_security_cleanup, daemon=True, name="SecCleanup").start()


class HubClient:
    """Runs in a background thread on each site, POSTing status to the hub."""

    # Connection state constants
    STATE_CONNECTING   = "connecting"
    STATE_CONNECTED    = "connected"
    STATE_DEGRADED     = "degraded"     # sending but getting errors
    STATE_DISCONNECTED = "disconnected"

    def __init__(self, cfg_fn, monitor_ref):
        self._cfg_fn    = cfg_fn
        self._monitor   = monitor_ref
        self._thread    = None
        self._stop      = threading.Event()
        # Observability
        self.state      = self.STATE_CONNECTING
        self.last_ack   = 0.0     # unix timestamp of last successful ACK
        self.last_error = ""
        self.sent_total = 0
        self.fail_total = 0
        # Resilience — outage queue
        self._queue: list = []    # payloads built during hub outage (max 60)
        self._backoff   = 0       # consecutive failures → backoff multiplier
        self._lock      = threading.Lock()
        # Hub-controlled relay bitrate (0 = not set, fall back to local cfg)
        self._hub_relay_bitrate: int = 0
        # Pending DAB scan result to include in next heartbeat (set by background scan thread)
        self._dab_scan_result: Optional[dict] = None
        self._dab_scan_lock = threading.Lock()
        # Latest RDS data from the scanner (populated when redsea is running)
        self._scanner_rds: dict = {}
        self._scanner_rds_lock = threading.Lock()

    @staticmethod
    def _normalise_url(url: str) -> str:
        """Ensure hub URL has a scheme. Defaults to https for public hosts, http for IPs."""
        url = url.strip()
        if not url:
            return url
        if "://" in url:
            return url
        # No scheme — guess based on whether it looks like a hostname or IP
        import re as _re
        is_ip = bool(_re.match(r'\d+\.\d+\.\d+\.\d+', url.split(":")[0]))
        scheme = "http" if is_ip else "https"
        return f"{scheme}://{url}"

    def _pop_dab_scan_result(self) -> Optional[dict]:
        """Return and clear any pending DAB scan result (thread-safe)."""
        with self._dab_scan_lock:
            r = self._dab_scan_result
            self._dab_scan_result = None
            return r

    # ── Hub-issued command handlers ───────────────────────────────────────────

    def _cmd_add_input(self, payload: dict):
        name  = str(payload.get("name", "")).strip()
        dev   = str(payload.get("device_index", "")).strip()
        if not name or not dev:
            monitor.log("[Hub] add_input: missing name or device_index — ignored"); return
        cfg = self._cfg_fn()
        if any(i.name == name for i in cfg.inputs):
            monitor.log(f"[Hub] add_input: '{name}' already exists — ignored"); return
        new_inp = InputConfig(
            name=name, device_index=dev,
            enabled=bool(payload.get("enabled", True)),
            alert_on_silence=bool(payload.get("alert_on_silence", True)),
            alert_on_hiss=bool(payload.get("alert_on_hiss", False)),
            alert_on_clip=bool(payload.get("alert_on_clip", True)),
            silence_threshold_dbfs=float(payload.get("silence_threshold_dbfs", -55.0)),
            silence_min_duration=float(payload.get("silence_min_duration", 3.0)),
            clip_threshold_dbfs=float(payload.get("clip_threshold_dbfs", -1.0)),
            ai_monitor=bool(payload.get("ai_monitor", True)),
        )
        cfg.inputs.append(new_inp)
        save_config(cfg)
        monitor.log(f"[Hub] Remote add_input: '{name}' ({dev}) added")
        self._restart_if_running()

    def _cmd_remove_input(self, payload: dict):
        name = str(payload.get("name", "")).strip()
        cfg  = self._cfg_fn()
        before = len(cfg.inputs)
        cfg.inputs = [i for i in cfg.inputs if i.name != name]
        if len(cfg.inputs) == before:
            monitor.log(f"[Hub] remove_input: '{name}' not found — ignored"); return
        save_config(cfg)
        monitor.log(f"[Hub] Remote remove_input: '{name}' removed")
        self._restart_if_running()

    def _cmd_toggle_input(self, payload: dict, enabled: bool):
        name = str(payload.get("name", "")).strip()
        cfg  = self._cfg_fn()
        for inp in cfg.inputs:
            if inp.name == name:
                inp.enabled = enabled
                save_config(cfg)
                monitor.log(f"[Hub] Remote {'enable' if enabled else 'disable'}_input: '{name}'")
                self._restart_if_running()
                return
        monitor.log(f"[Hub] toggle_input: '{name}' not found — ignored")

    def _cmd_dab_scan(self, payload: dict):
        channel = str(payload.get("channel", "")).strip().upper()
        ppm     = int(payload.get("ppm", 0))
        serial  = str(payload.get("serial", "")).strip()
        gain    = int(payload.get("gain", -1))
        if not channel:
            monitor.log("[Hub] dab_scan: no channel specified — ignored"); return
        monitor.log(f"[Hub] Remote DAB scan: channel={channel} ppm={ppm} gain={gain}")
        def _run():
            try:
                device_idx = "0"
                _ppm  = ppm
                _gain = gain
                if serial:
                    try: device_idx = str(sdr_manager.resolve_index(serial))
                    except Exception: pass
                # Resolve PPM and gain from registry if not explicitly provided
                cfg = self._cfg_fn()
                for dev in cfg.sdr_devices:
                    if serial and dev.serial != serial:
                        continue
                    if not _ppm:
                        _ppm = getattr(dev, "ppm", 0)
                    if _gain == -1:
                        _gain = getattr(dev, "gain", -1)
                    break
                result = _dab_scan_mux(channel, device_idx, _ppm, gain=_gain)
                with self._dab_scan_lock:
                    self._dab_scan_result = result
                monitor.log(f"[Hub] DAB scan complete: {len(result.get('services',[]))} services on {channel}")
            except Exception as e:
                with self._dab_scan_lock:
                    self._dab_scan_result = {"channel": channel, "error": str(e), "services": []}
                monitor.log(f"[Hub] DAB scan failed: {e}")
        threading.Thread(target=_run, daemon=True, name="HubDabScan").start()

    def _cmd_set_expected_name(self, payload: dict):
        """Hub command: set expected_fm_rds_ps or expected_dab_service on a local stream."""
        stream = str(payload.get("stream", "")).strip()
        field  = str(payload.get("field",  "")).strip()
        value  = str(payload.get("value",  "")).strip()
        if field not in ("expected_fm_rds_ps", "expected_dab_service"):
            monitor.log(f"[Hub] set_expected_name: unknown field '{field}' — ignored"); return
        if not stream:
            monitor.log("[Hub] set_expected_name: no stream specified — ignored"); return
        cfg = monitor.app_cfg
        inp = next((i for i in cfg.inputs if i.name == stream), None)
        if inp is None:
            monitor.log(f"[Hub] set_expected_name: stream '{stream}' not found — ignored"); return
        setattr(inp, field, value)
        save_config(cfg)
        monitor.log(f"[Hub] set_expected_name: '{stream}'.{field} = '{value}'")

    def _cmd_save_clip(self, payload: dict):
        """Hub command: save an alert clip for the named local stream and upload it to the hub.

        Clip saving strategy
        --------------------
        * "last_good" clips capture the audio *before* the fault — the rolling
          buffer already contains that audio, so we save immediately.
        * "fault" clips need audio *after* the fault starts.  We defer saving
          by ``_clip_dur`` seconds so the buffer fills with post-fault content
          before we capture.  The deferral runs in a background thread so the
          heartbeat loop is never blocked.

        Auto-upload is skipped when ``cfg.hub.clip_auto_upload`` is False —
        clips are still saved locally and can be picked up by the periodic
        sync or by the hub pulling via a command.
        """
        cfg_obj    = self._cfg_fn()
        stream     = str(payload.get("stream",     "")).strip()
        label      = str(payload.get("label",      "chain_fault")).strip()
        chain_name = str(payload.get("chain_name", "")).strip()
        chain_id   = str(payload.get("chain_id",   "")).strip()
        entry_id   = str(payload.get("entry_id",   "")).strip()
        node_label = str(payload.get("node_label", "")).strip()
        pos        = payload.get("pos", None)
        status     = str(payload.get("status",     "")).strip()
        duration   = float(payload.get("duration", 0)) or 0.0
        monitor.log(f"[Hub] save_clip received: stream={stream!r} chain_id={chain_id!r} "
                    f"entry_id={entry_id!r} label={label!r} status={status!r}")
        inp = next((i for i in cfg_obj.inputs if i.name == stream and i.enabled), None)
        if inp is None:
            monitor.log(f"[Hub] save_clip: stream '{stream}' not found or disabled — ignored. "
                        f"Available inputs: {[i.name for i in cfg_obj.inputs if i.enabled]}")
            return
        _clip_dur = (max(float(inp.alert_wav_duration or 0), duration, CHAIN_CLIP_MIN_SECS)
                     if duration else max(float(inp.alert_wav_duration or 0), CHAIN_CLIP_MIN_SECS))

        # Fault clips need a delay; all other clip types (last_good, etc.) save immediately.
        # Add a per-position stagger so multiple chain nodes don't all compress and
        # upload at the same instant — that CPU burst can cause RTP packet loss which
        # triggers further faults and creates a cascade.
        _pos_int = int(pos) if pos is not None else 0
        _stagger = _pos_int * _CLIP_SAVE_STAGGER
        _delay   = (_clip_dur + _stagger) if status == "fault" else _stagger

        def _do_save():
            if _delay:
                if status == "fault":
                    monitor.log(f"[Hub] save_clip: waiting {_delay:.1f}s "
                                f"(clip_dur={_clip_dur:.0f}s + pos{_pos_int} stagger) "
                                f"for '{stream}' label={label!r}")
                time.sleep(_delay)
            # Re-fetch config in case it was updated during the delay
            _cfg = self._cfg_fn()
            _inp = next((i for i in _cfg.inputs if i.name == stream and i.enabled), None)
            if _inp is None:
                monitor.log(f"[Hub] save_clip: stream '{stream}' gone during delay — cancelled")
                return
            msg = (f"Audio clip captured at '{stream}'"
                   + (f" ('{node_label}')" if node_label else "")
                   + f" during chain fault"
                   + (f" in {repr(chain_name)}" if chain_name else "") + ".")
            clip_path = _save_alert_wav(_inp, label, _clip_dur, _skip_hub_queue=True)
            _add_history(_inp, "CHAIN_FAULT", msg, clip_path=clip_path or "")
            if clip_path:
                monitor.log(f"[Hub] save_clip: saved '{label}' for '{stream}' → "
                            f"{os.path.basename(clip_path)}")
                # Write a metadata sidecar so periodic sync can re-upload with
                # full chain context if the primary upload fails or is disabled.
                if chain_id or chain_name:
                    _meta_path = os.path.splitext(clip_path)[0] + ".meta"
                    try:
                        _meta_d = {
                            "stream":     stream,
                            "label":      label,
                            "chain_name": chain_name,
                            "chain_id":   chain_id,
                            "entry_id":   entry_id,
                            "node_label": node_label,
                            "pos":        pos,
                            "status":     status,
                            "level_dbfs": round(
                                getattr(_inp, "_last_level_dbfs", -120.0), 1),
                        }
                        with open(_meta_path, "w") as _mf:
                            json.dump(_meta_d, _mf)
                    except Exception as _me:
                        monitor.log(f"[Hub] save_clip: could not write .meta sidecar: {_me}")
            else:
                monitor.log(f"[Hub] save_clip: no audio data for '{stream}' (buffer empty?). "
                            f"Buffer length: "
                            f"{len(_inp._audio_buffer) if hasattr(_inp,'_audio_buffer') else 'N/A'}")
                return
            if _cfg.hub.clip_auto_upload:
                hub_url = _cfg.hub.hub_url.rstrip("/")
                secret  = _cfg.hub.secret_key
                site    = _cfg.hub.site_name or socket.gethostname()
                threading.Thread(
                    target=self._upload_clip,
                    args=(hub_url, secret, site, stream, label, chain_name, chain_id,
                          entry_id, clip_path, node_label, pos, status),
                    daemon=True, name="ClipUpload",
                ).start()
            else:
                monitor.log(f"[Hub] save_clip: auto-upload disabled — clip saved locally only "
                            f"({os.path.basename(clip_path)})")

        threading.Thread(target=_do_save, daemon=True,
                         name=f"ClipSave-{stream[:20]}").start()

    def _upload_clip(self, hub_url: str, secret: str, site: str,
                     stream: str, label: str, chain_name: str, chain_id: str,
                     entry_id: str = "", clip_path: str = "",
                     node_label: str = "", pos=None,
                     status: str = "", level_dbfs: float = -120.0):
        """Upload a saved clip WAV to the hub's /hub/clip_upload endpoint.

        Retries up to 3 times with 15 s / 30 s back-off so transient
        network errors or hub restarts don't silently lose clips.
        4xx responses are not retried (the request itself is wrong).
        Timeout raised to 60 s to accommodate large WAVs over WAN links.

        A module-level semaphore (_clip_upload_sem) caps concurrent uploads
        at 3.  When a chain fault fires every node tries to upload a clip
        simultaneously — without the cap this can cause hub thread exhaustion
        and upload timeouts, resulting in missing clips on the hub's reports
        page.  Threads wait here rather than hammering the hub.
        """
        with _clip_upload_sem:
            self._upload_clip_inner(hub_url, secret, site, stream, label,
                                    chain_name, chain_id, entry_id, clip_path,
                                    node_label, pos, status, level_dbfs)

    def _upload_clip_inner(self, hub_url: str, secret: str, site: str,
                           stream: str, label: str, chain_name: str, chain_id: str,
                           entry_id: str = "", clip_path: str = "",
                           node_label: str = "", pos=None,
                           status: str = "", level_dbfs: float = -120.0) -> bool:
        """Inner upload body — called after the concurrency semaphore is acquired.

        Returns True on successful upload, False on any failure.

        WAV→MP3 pre-compression
        -----------------------
        Nginx's default ``client_max_body_size`` is 1 MB.  A 30-second WAV clip
        at 48 kHz mono-16-bit is ~2.75 MB — roughly 3.7 MB after base64 — which
        nginx rejects with 413.  Before building the payload, any WAV file larger
        than 200 KB is compressed to MP3 (via ``_try_encode_mp3``).  A 30-second
        clip becomes ~350 KB as MP3, safely under the limit.  If an encoder is
        unavailable the WAV is sent as-is (a 413 is still logged with a hint to
        raise ``client_max_body_size`` in nginx).

        The hub stores the file under the compressed filename (e.g.
        ``clip.mp3`` instead of ``clip.wav``).  ``hub_proxy_alert_clip`` checks
        for both extensions when serving from its local cache so the audio player
        still works even when the alert log holds the original ``.wav`` name.
        """
        try:
            with open(clip_path, "rb") as f:
                clip_bytes = f.read()
        except Exception as e:
            monitor.log(f"[Hub] Clip upload: cannot read '{clip_path}': {e}")
            return False

        _ext = os.path.splitext(clip_path)[1].lstrip(".").lower() if clip_path else "wav"
        if _ext not in ("wav", "mp3"):
            _ext = "wav"
        _upload_filename = os.path.basename(clip_path) if clip_path else ""

        # Compress WAV→MP3 to avoid nginx 413 (default client_max_body_size=1m).
        # Only try if we have a WAV that's larger than ~200 KB (about 2 seconds).
        _MP3_UPLOAD_THRESHOLD = 200 * 1024
        if _ext == "wav" and len(clip_bytes) > _MP3_UPLOAD_THRESHOLD:
            try:
                import wave as _wave, io as _io
                with _wave.open(_io.BytesIO(clip_bytes)) as _wv:
                    _pcm_frames = _wv.readframes(_wv.getnframes())
                _pcm = np.frombuffer(_pcm_frames, dtype=np.int16)
                _mp3 = _try_encode_mp3(_pcm)
                if _mp3:
                    _prev_kb = len(clip_bytes) // 1024
                    clip_bytes = _mp3
                    _ext = "mp3"
                    _stem = os.path.splitext(_upload_filename)[0]
                    _upload_filename = f"{_stem}.mp3"
                    monitor.log(f"[Hub] Clip compressed WAV→MP3 for upload: "
                                f"{_prev_kb} KB → {len(clip_bytes)//1024} KB "
                                f"({_upload_filename})")
            except Exception as _ce:
                monitor.log(f"[Hub] Clip WAV→MP3 pre-compression skipped: {_ce}")

        data_b64 = base64.b64encode(clip_bytes).decode()
        payload_dict = {
            "site": site, "stream": stream, "label": label,
            "chain_name": chain_name, "chain_id": chain_id,
            "entry_id": entry_id,
            "node_label": node_label, "pos": pos, "status": status,
            "ts": time.time(), "data_b64": data_b64,
            "level_dbfs": level_dbfs,
            "ext": _ext,
            # Send the (possibly MP3) filename so the hub preserves it exactly.
            "filename": _upload_filename,
        }
        payload_bytes = json.dumps(payload_dict).encode()

        for attempt in range(3):
            try:
                ts  = time.time()
                sig = hub_sign_payload(secret, payload_bytes, ts) if secret else ""
                headers = {"X-Hub-Sig": sig, "X-Hub-Ts": str(ts)}
                if secret:
                    body = hub_encrypt_payload(secret, payload_bytes)
                    headers["Content-Type"] = "application/octet-stream"
                else:
                    body = payload_bytes
                    headers["Content-Type"] = "application/json"
                req = urllib.request.Request(
                    f"{hub_url}/hub/clip_upload", data=body, headers=headers, method="POST")
                with urllib.request.urlopen(req, timeout=60) as r:
                    resp_body = r.read().decode("utf-8", errors="replace")
                    monitor.log(f"[Hub] Clip uploaded OK: {site}/{stream}/{label} → "
                                f"HTTP {r.status} {resp_body[:120]}")
                # Write a marker so _sync_pending_clips skips this file
                if clip_path and (clip_path.endswith(".wav") or clip_path.endswith(".mp3")):
                    try:
                        open(os.path.splitext(clip_path)[0] + ".hub", "w").close()
                    except Exception:
                        pass
                return True   # success — stop retrying
            except urllib.error.HTTPError as e:
                err_body = e.read().decode("utf-8", errors="replace") if hasattr(e, "read") else ""
                monitor.log(f"[Hub] Clip upload HTTP {e.code} (attempt {attempt+1}) "
                            f"for '{stream}': {e.reason} — {err_body[:200]}")
                if e.code == 413:
                    monitor.log(
                        f"[Hub] Clip upload 413 — nginx body size limit exceeded "
                        f"(payload {len(payload_bytes)//1024} KB).  Add "
                        f"'client_max_body_size 20m;' in your nginx server block "
                        f"to allow larger clips without MP3 compression.")
                if e.code < 500:
                    return False  # 4xx — don't retry
            except Exception as e:
                monitor.log(f"[Hub] Clip upload failed (attempt {attempt+1}) "
                            f"for '{stream}': {type(e).__name__}: {e}")
            if attempt < 2:
                backoff = 15 * (attempt + 1)   # 15 s then 30 s
                monitor.log(f"[Hub] Clip upload retrying in {backoff}s …")
                time.sleep(backoff)
        monitor.log(f"[Hub] Clip upload gave up after 3 attempts for '{stream}/{label}'")
        return False

    def _sync_pending_clips(self):
        """Scan alert_snippets for clips not yet confirmed on the hub and re-upload them.

        Respects ``cfg.hub.clip_sync`` — when disabled this method returns immediately.

        After a successful upload _upload_clip_inner writes a zero-byte <name>.hub
        marker alongside the clip file.  Any clip without its marker either failed to
        upload or predates this version.  This method uploads them so clips are never
        permanently lost due to transient network errors or hub restarts.

        Called from the heartbeat thread every N cycles so it runs in the background
        without blocking heartbeats.
        """
        cfg_obj = self._cfg_fn()
        if not getattr(cfg_obj.hub, "clip_sync", True):
            return
        if getattr(self, "_low_bw", False) or getattr(cfg_obj.hub, "low_bw", False):
            return
        if cfg_obj.hub.mode not in ("client", "both"):
            return
        hub_url = cfg_obj.hub.hub_url.rstrip("/")
        if not hub_url:
            return
        secret = cfg_obj.hub.secret_key
        site   = (cfg_obj.hub.site_name or socket.gethostname()).strip()

        snip_dir = os.path.join(BASE_DIR, "alert_snippets")
        if not os.path.exists(snip_dir):
            return

        synced = 0
        for folder in sorted(os.listdir(snip_dir)):
            folder_path = os.path.join(snip_dir, folder)
            if not os.path.isdir(folder_path):
                continue
            for fname in sorted(os.listdir(folder_path)):
                if not (fname.endswith(".wav") or fname.endswith(".mp3")):
                    continue
                clip_path = os.path.join(folder_path, fname)
                marker    = os.path.splitext(clip_path)[0] + ".hub"
                if os.path.exists(marker):
                    continue  # already confirmed on hub
                # Defaults — folder name as stream, filename stem as label.
                label  = os.path.splitext(fname)[0]
                stream = folder
                # Read chain metadata sidecar written by _cmd_save_clip so that
                # chain clips re-uploaded by sync still appear in fault history.
                _smeta: dict = {}
                _meta_path = os.path.splitext(clip_path)[0] + ".meta"
                if os.path.exists(_meta_path):
                    try:
                        with open(_meta_path) as _mf:
                            _smeta = json.load(_mf)
                        stream = _smeta.get("stream", stream) or stream
                        label  = _smeta.get("label",  label)  or label
                    except Exception:
                        _smeta = {}
                try:
                    _ok = self._upload_clip_inner(
                        hub_url, secret, site, stream, label,
                        _smeta.get("chain_name", ""),
                        _smeta.get("chain_id",   ""),
                        _smeta.get("entry_id",   ""),
                        clip_path,
                        _smeta.get("node_label", ""),
                        _smeta.get("pos",        None),
                        _smeta.get("status",     ""),
                        float(_smeta.get("level_dbfs", -120.0)),
                    )
                    if _ok:
                        synced += 1
                        monitor.log(f"[Hub] Clip sync uploaded: {folder}/{fname}")
                    # else: failure already logged by _upload_clip_inner
                except Exception as _e:
                    monitor.log(f"[Hub] Clip sync failed for {folder}/{fname}: {_e}")
        if synced:
            monitor.log(f"[Hub] Clip sync complete — {synced} clip(s) uploaded")

    def _prune_uploaded_clips(self):
        """Delete clips older than 24 h that have a .hub upload-confirmed marker.

        Once a clip is safely on the hub it no longer needs to live on the
        client.  This keeps alert_snippets/ from growing unboundedly.

        Applies retroactively — any .hub marker written by a previous version
        is equally eligible, so clips uploaded before this update are pruned
        on the first pass without any manual action.

        Companion .hub and .meta sidecar files are removed alongside the audio
        file so no orphan files accumulate.
        """
        _PRUNE_AGE_SECS = 86400  # 24 hours
        snip_dir = os.path.join(BASE_DIR, "alert_snippets")
        if not os.path.exists(snip_dir):
            return
        cutoff  = time.time() - _PRUNE_AGE_SECS
        removed = 0
        try:
            for folder in os.listdir(snip_dir):
                folder_path = os.path.join(snip_dir, folder)
                if not os.path.isdir(folder_path):
                    continue
                for fname in list(os.listdir(folder_path)):
                    if not (fname.endswith(".wav") or fname.endswith(".mp3")):
                        continue
                    clip_path = os.path.join(folder_path, fname)
                    stem      = os.path.splitext(clip_path)[0]
                    marker    = stem + ".hub"
                    if not os.path.exists(marker):
                        continue  # not yet confirmed on hub — keep it
                    try:
                        mtime = os.path.getmtime(clip_path)
                    except OSError:
                        continue
                    if mtime >= cutoff:
                        continue  # uploaded recently — keep it
                    # Confirmed on hub and older than 24 h — safe to delete
                    for ext in (".wav", ".mp3", ".hub", ".meta"):
                        p = stem + ext
                        try:
                            if os.path.exists(p):
                                os.remove(p)
                                removed += 1
                        except Exception:
                            pass
        except Exception as _e:
            monitor.log(f"[Hub] Clip prune error: {_e}")
        if removed:
            monitor.log(f"[Hub] Pruned {removed} file(s) from uploaded clips older than 24 h")

    def _cmd_self_update(self, payload: dict):
        """Hub command: download the hub's current signalscope.py and restart."""
        hub_version = payload.get("hub_version", "?")
        monitor.log(f"[Hub] Self-update requested — hub is {hub_version}, we are {BUILD}")
        cfg_obj  = self._cfg_fn()
        hub_url  = cfg_obj.hub.hub_url.rstrip("/")
        secret   = cfg_obj.hub.secret_key
        threading.Thread(target=self._run_self_update,
                         args=(hub_url, secret, hub_version),
                         daemon=True, name="SelfUpdate").start()

    def _run_self_update(self, hub_url: str, secret: str, hub_version: str):
        """Download new signalscope.py from hub and perform an in-place restart."""
        import py_compile, tempfile
        script_path = os.path.abspath(__file__)
        script_dir  = os.path.dirname(script_path)
        monitor.log(f"[Update] Downloading update from {hub_url}/hub/update/download …")
        try:
            ts    = time.time()
            nonce = os.urandom(16).hex()
            sig   = hub_sign_payload(secret, b"", ts) if secret else ""
            headers = {
                "X-Hub-Sig":   sig,
                "X-Hub-Ts":    str(ts),
                "X-Hub-Nonce": nonce,
            }
            req = urllib.request.Request(
                f"{hub_url}/hub/update/download", headers=headers, method="GET")
            with urllib.request.urlopen(req, timeout=60) as r:
                new_code = r.read()
            monitor.log(f"[Update] Downloaded {len(new_code)//1024}KB")

            # Write to temp file and validate it's valid Python
            fd, tmp_path = tempfile.mkstemp(suffix=".py", dir=script_dir)
            try:
                with os.fdopen(fd, "wb") as f:
                    f.write(new_code)
                py_compile.compile(tmp_path, doraise=True)
                monitor.log("[Update] Syntax check passed — replacing script and restarting …")
                os.replace(tmp_path, script_path)
            except Exception as e:
                monitor.log(f"[Update] Validation failed — aborting update: {e}")
                try:
                    os.unlink(tmp_path)
                except OSError:
                    pass
                return

            # Restart: exec a fresh Python process with the same arguments
            monitor.log("[Update] Restarting process …")
            time.sleep(0.5)   # brief pause so the log line is flushed
            os.execv(sys.executable, [sys.executable] + sys.argv)

        except Exception as e:
            monitor.log(f"[Update] Self-update failed: {e}")

    def _cmd_restart(self, payload: dict):
        monitor.log("[Hub] Remote restart command received — restarting process in 1s …")
        def _do_restart():
            time.sleep(1.0)
            os.execv(sys.executable, [sys.executable] + sys.argv)
        threading.Thread(target=_do_restart, daemon=True, name="RemoteRestart").start()

    def _cmd_chain_note(self, payload: dict):
        """Apply an engineer note pushed from the hub.

        Saves the note locally on this client so it appears in the client's
        own fault history view and mobile app responses.
        """
        fault_log_id = str(payload.get("fault_log_id", "")).strip()
        text         = str(payload.get("text", "")).strip()[:2000]
        by           = str(payload.get("by", "hub")).strip()
        if not (fault_log_id and text):
            monitor.log(f"[Hub] chain_note: invalid payload (missing fault_log_id or text)")
            return
        _save_chain_note(fault_log_id, text, by=by)
        monitor.log(f"[Hub] Engineer note saved for fault {fault_log_id[:8]}… (by {by!r})")

    def _cmd_ai_feedback(self, payload: dict):
        """Apply an AI feedback label pushed from the hub.

        The hub collected the user's 👍/👎 vote and forwards it here so the
        local model can learn from it — identical to clicking the button on the
        client's own reports page.
        """
        alert_id = str(payload.get("alert_id", "")).strip()
        stream   = str(payload.get("stream",   "")).strip()
        feedback = str(payload.get("feedback", "")).strip()
        if not (alert_id and stream and feedback in ("normal", "abnormal")):
            monitor.log(f"[Hub] ai_feedback: invalid payload {payload}")
            return
        monitor.log(f"[Hub] AI feedback '{feedback}' for alert {alert_id[:8]}… on '{stream}'")
        _apply_feedback_label(alert_id, stream, feedback, by="hub")

    def _cmd_retrain_stream(self, payload: dict):
        stream = str(payload.get("stream", "")).strip()
        if stream:
            monitor.request_retrain(stream)
            monitor.log(f"[Hub] Remote retrain requested for '{stream}'")

    def _cmd_calibrate_silence(self, payload: dict):
        stream = str(payload.get("stream", "")).strip()
        headroom = float(payload.get("headroom_db", 6.0))
        cfg_obj = self._cfg_fn()
        inp = next((i for i in cfg_obj.inputs if i.name == stream and i.enabled), None)
        if inp is None:
            monitor.log(f"[Hub] calibrate_silence: stream '{stream}' not found")
            return
        new_thresh = round(inp._last_level_dbfs - headroom, 1)
        new_thresh = max(-80.0, min(-20.0, new_thresh))
        inp.silence_threshold_dbfs = new_thresh
        save_config(cfg_obj)
        monitor.log(f"[Hub] calibrate_silence: '{stream}' threshold set to {new_thresh} dBFS "
                    f"(level was {inp._last_level_dbfs:.1f}, headroom {headroom} dB)")

    def _cmd_scanner_band_scan(self, payload: dict):
        """Hub command: run an FM band scan with rtl_power and post results back."""
        threading.Thread(
            target=self._run_scanner_band_scan, args=(payload,),
            daemon=True, name="ScannerBandScan",
        ).start()

    def _run_scanner_band_scan(self, payload: dict):
        """Run rtl_power over the FM band and POST a list of peaks to the hub."""
        import subprocess, math as _math
        try:
            cfg_obj  = self._cfg_fn()
            hub_url  = cfg_obj.hub.hub_url.rstrip("/")
            secret   = cfg_obj.hub.secret_key
            site     = cfg_obj.hub.site_name or socket.gethostname()
            serial   = str(payload.get("sdr_serial", "") or "").strip()
            ppm      = int(payload.get("ppm", 0) or 0)
            gain     = float(payload.get("gain", 38.0) or 38.0)
            start_mhz = float(payload.get("start_mhz", 76.0))
            end_mhz   = float(payload.get("end_mhz", 108.0))
            step_khz  = int(payload.get("step_khz", 100))

            rtlp = _find_binary("rtl_power")
            if not rtlp:
                monitor.log("[Scanner] rtl_power not found — band scan unavailable")
                return

            device_arg = []
            if serial:
                try:
                    idx = sdr_manager.resolve_index(serial)
                    device_arg = ["-d", str(idx)]
                except Exception:
                    pass

            cmd = [rtlp,
                   "-f", f"{int(start_mhz*1e6)}:{int(end_mhz*1e6)}:{step_khz*1000}",
                   "-i", "2", "-1", "-g", str(gain)]
            if ppm:
                cmd += ["-p", str(ppm)]
            cmd += device_arg
            monitor.log(f"[Scanner] Band scan {start_mhz}–{end_mhz} MHz step {step_khz} kHz")
            result = subprocess.run(cmd, capture_output=True, text=True, timeout=90)
            # Parse rtl_power CSV: date, time, Hz_low, Hz_high, step, samples, dB, dB, ...
            peaks = []   # list of {freq_mhz, power_db}
            for line in result.stdout.splitlines():
                parts = [p.strip() for p in line.split(",")]
                if len(parts) < 7:
                    continue
                try:
                    hz_low  = float(parts[2])
                    hz_step = float(parts[4])
                    dbs     = [float(x) for x in parts[6:] if x]
                    for i, db in enumerate(dbs):
                        f_mhz = round((hz_low + hz_step * i) / 1e6, 3)
                        peaks.append({"freq_mhz": f_mhz, "power_db": round(db, 1)})
                except (ValueError, IndexError):
                    continue
            # Send results to hub
            result_dict = {"site": site, "peaks": peaks, "ts": time.time(),
                           "start_mhz": start_mhz, "end_mhz": end_mhz, "step_khz": step_khz}
            payload_bytes = json.dumps(result_dict).encode()
            ts  = time.time()
            sig = hub_sign_payload(secret, payload_bytes, ts) if secret else ""
            headers: dict = {"X-Hub-Sig": sig, "X-Hub-Ts": str(ts), "X-Hub-Site": site,
                             "Content-Type": "application/json"}
            req = urllib.request.Request(
                f"{hub_url}/hub/scanner_scan_result", data=payload_bytes,
                headers=headers, method="POST")
            with urllib.request.urlopen(req, timeout=30):
                pass
            monitor.log(f"[Scanner] Band scan complete — {len(peaks)} data points posted")
        except Exception as e:
            monitor.log(f"[Scanner] Band scan failed: {e}")

    def _cmd_backup(self, payload: dict):
        """Hub command: generate a full backup ZIP and upload it to the hub."""
        monitor.log("[Hub] Backup command received — generating ZIP …")
        threading.Thread(target=self._run_backup, daemon=True, name="BackupUpload").start()

    def _run_backup(self):
        """Build a backup ZIP and POST it to /hub/backup_upload on the hub."""
        import io as _io
        import zipfile as _zf
        import tempfile as _tf
        import sqlite3 as _sq3
        import shutil as _sh
        try:
            buf = _io.BytesIO()
            with _zf.ZipFile(buf, "w", _zf.ZIP_DEFLATED) as zf:
                if os.path.isfile(CONFIG_PATH):
                    zf.write(CONFIG_PATH, "lwai_config.json")
                if os.path.isdir(MODELS_DIR):
                    for root, _dirs, files in os.walk(MODELS_DIR):
                        for fname in files:
                            full = os.path.join(root, fname)
                            zf.write(full, os.path.relpath(full, BASE_DIR))
                if os.path.isfile(METRICS_DB_PATH):
                    tmp = None
                    try:
                        tmp_f = _tf.NamedTemporaryFile(suffix=".db", delete=False)
                        tmp_f.close()
                        tmp = tmp_f.name
                        src = _sq3.connect(METRICS_DB_PATH)
                        dst = _sq3.connect(tmp)
                        src.backup(dst)
                        dst.close()
                        src.close()
                        zf.write(tmp, "metrics_history.db")
                    except Exception:
                        zf.write(METRICS_DB_PATH, "metrics_history.db")
                    finally:
                        if tmp:
                            try:
                                os.unlink(tmp)
                            except Exception:
                                pass
                for path, name in [
                    (SLA_PATH,       "sla_data.json"),
                    (ALERT_LOG_PATH, "alert_log.json"),
                    (HUB_STATE_PATH, "hub_state.json"),
                ]:
                    if os.path.isfile(path):
                        zf.write(path, name)
            data = buf.getvalue()
            self._upload_backup(data)
        except Exception as e:
            monitor.log(f"[Hub] Backup generation failed: {e}")

    def _upload_backup(self, data: bytes):
        """POST backup ZIP to /hub/backup_upload on the hub."""
        try:
            cfg_obj = self._cfg_fn()
            hub_url = cfg_obj.hub.hub_url.rstrip("/")
            secret  = cfg_obj.hub.secret_key
            site    = cfg_obj.hub.site_name or socket.gethostname()
            payload_bytes = data
            ts  = time.time()
            sig = hub_sign_payload(secret, payload_bytes, ts) if secret else ""
            headers = {
                "X-Hub-Sig":  sig,
                "X-Hub-Ts":   str(ts),
                "X-Hub-Site": site,
                "Content-Type": "application/octet-stream",
            }
            req = urllib.request.Request(
                f"{hub_url}/hub/backup_upload", data=payload_bytes,
                headers=headers, method="POST")
            with urllib.request.urlopen(req, timeout=120) as r:
                monitor.log(f"[Hub] Backup uploaded OK: {len(data)} bytes → HTTP {r.status}")
        except Exception as e:
            monitor.log(f"[Hub] Backup upload failed: {e}")

    def _cmd_push_log(self, payload: dict):
        """Hub command: collect the recent application log and POST it back to the hub."""
        threading.Thread(
            target=self._run_push_log,
            daemon=True, name="PushLog",
        ).start()

    def _run_push_log(self):
        """Gather last 200 log lines and POST them to the hub's /hub/log_data endpoint."""
        try:
            cfg_obj  = self._cfg_fn()
            hub_url  = cfg_obj.hub.hub_url.rstrip("/")
            secret   = cfg_obj.hub.secret_key
            site     = cfg_obj.hub.site_name or socket.gethostname()
            lines    = [str(l) for l in monitor.get_logs(200)]
            result_dict = {"site": site, "lines": lines, "ts": time.time()}
            payload_bytes = json.dumps(result_dict).encode()
            ts  = time.time()
            sig = hub_sign_payload(secret, payload_bytes, ts) if secret else ""
            headers: dict = {"X-Hub-Sig": sig, "X-Hub-Ts": str(ts)}
            if secret:
                body = hub_encrypt_payload(secret, payload_bytes)
                headers["Content-Type"] = "application/octet-stream"
            else:
                body = payload_bytes
                headers["Content-Type"] = "application/json"
            req = urllib.request.Request(
                f"{hub_url}/hub/log_data", data=body,
                headers=headers, method="POST")
            with urllib.request.urlopen(req, timeout=15) as r:
                monitor.log(f"[Hub] Log dump uploaded: {len(lines)} lines HTTP {r.status}")
        except Exception as e:
            monitor.log(f"[Hub] Log dump upload failed: {e}")

    def _cmd_ping_test(self, payload: dict):
        """Hub command: run a ping test to a target and report results back to the hub."""
        target = str(payload.get("target", "")).strip()
        if not target:
            monitor.log("[Hub] ping_test: no target specified — ignored")
            return
        threading.Thread(
            target=self._run_ping_test, args=(target,),
            daemon=True, name="PingTest",
        ).start()

    def _run_ping_test(self, target: str):
        """Run subprocess ping to target and POST result to /hub/ping_result."""
        import subprocess as _sp
        try:
            if sys.platform == "win32":
                args = ["ping", "-n", "4", target]
            else:
                args = ["ping", "-c", "4", "-W", "2", target]
            result = _sp.run(args, capture_output=True, text=True, timeout=15)
            output  = (result.stdout + result.stderr)[:2000]
            success = result.returncode == 0
        except Exception as e:
            output = str(e); success = False
        try:
            cfg_obj = self._cfg_fn()
            hub_url = cfg_obj.hub.hub_url.rstrip("/")
            secret  = cfg_obj.hub.secret_key
            site    = cfg_obj.hub.site_name or socket.gethostname()
            result_dict = {
                "site": site, "target": target,
                "output": output, "success": success, "ts": time.time(),
            }
            payload_bytes = json.dumps(result_dict).encode()
            ts  = time.time()
            sig = hub_sign_payload(secret, payload_bytes, ts) if secret else ""
            headers: dict = {"X-Hub-Sig": sig, "X-Hub-Ts": str(ts)}
            if secret:
                body = hub_encrypt_payload(secret, payload_bytes)
                headers["Content-Type"] = "application/octet-stream"
            else:
                body = payload_bytes
                headers["Content-Type"] = "application/json"
            req = urllib.request.Request(
                f"{hub_url}/hub/ping_result", data=body,
                headers=headers, method="POST")
            with urllib.request.urlopen(req, timeout=15) as r:
                monitor.log(f"[Hub] Ping result uploaded: target={target} success={success} HTTP {r.status}")
        except Exception as e:
            monitor.log(f"[Hub] Ping result upload failed: {e}")

    def _cmd_cmp_pair(self, payload: dict):
        """Hub command: spawn an on-demand StreamComparator for two local streams.

        The hub issues this command when it detects that two broadcast-chain
        comparator nodes both live on this site.  A local StreamComparator
        produces real-time xcorr/delay/gain data that the hub uses in place of
        the coarser 1-minute metric_history averages.  The comparator result
        appears in the next heartbeat and the hub chain page shows the 🎧 badge.
        """
        pre_name  = str(payload.get("pre_name",  "")).strip()
        post_name = str(payload.get("post_name", "")).strip()
        if not pre_name or not post_name:
            monitor.log("[CMP] cmp_pair command missing pre_name/post_name — ignored")
            return
        enabled = {c.name: c for c in monitor.app_cfg.inputs if c.enabled}
        pre_cfg  = enabled.get(pre_name)
        post_cfg = enabled.get(post_name)
        if not pre_cfg or not post_cfg:
            monitor.log(f"[CMP] cmp_pair: stream not found: {pre_name!r} / {post_name!r}")
            return
        # Check if a comparator already exists for this pair (either direction)
        existing = any(
            (c.pre.name == pre_name  and c.post.name == post_name)
            or (c.pre.name == post_name and c.post.name == pre_name)
            for c in monitor._comparators
        )
        if existing:
            return
        monitor.log(f"[CMP] Hub-requested on-demand comparator: '{pre_name}' → '{post_name}'")
        monitor._comparators.append(
            StreamComparator(pre_cfg, post_cfg, monitor.log,
                             AlertSender(monitor.app_cfg, monitor.log))
        )

    def _restart_if_running(self):
        """Restart monitoring if it is currently active (to apply config changes)."""
        if monitor.is_running():
            monitor.stop_monitoring()
            monitor.start_monitoring()

    def start(self):
        self.state = self.STATE_CONNECTING
        self._stop.clear()
        self._thread = threading.Thread(target=self._loop, daemon=True, name="HubClient")
        self._thread.start()

    def stop(self):
        self._stop.set()
        self.state = self.STATE_DISCONNECTED

    def _build_system_health(self) -> dict:
        """Return a dict of system resource metrics for the heartbeat payload."""
        import shutil as _sh
        du = _sh.disk_usage(BASE_DIR)
        info = {
            "disk_total_gb": round(du.total / 1073741824, 2),
            "disk_used_gb":  round(du.used  / 1073741824, 2),
            "disk_free_gb":  round(du.free  / 1073741824, 2),
            "disk_pct":      round(du.used  / max(du.total, 1) * 100, 1),
            "proc_uptime_s": round(time.time() - _PROCESS_START),
            "cpu_pct":       None,
            "ram_total_gb":  None,
            "ram_used_gb":   None,
            "ram_pct":       None,
            "os_uptime_s":   None,
        }
        if _psutil is not None:
            try:
                info["cpu_pct"] = _psutil.cpu_percent(interval=None)
                vm = _psutil.virtual_memory()
                info["ram_total_gb"] = round(vm.total / 1073741824, 2)
                info["ram_used_gb"]  = round(vm.used  / 1073741824, 2)
                info["ram_pct"]      = round(vm.percent, 1)
                info["os_uptime_s"]  = round(time.time() - _psutil.boot_time())
            except Exception:
                pass
        return info

    def _get_scanner_rds(self) -> dict:
        with self._scanner_rds_lock:
            return dict(self._scanner_rds)

    def _set_scanner_rds(self, data: dict):
        with self._scanner_rds_lock:
            self._scanner_rds = dict(data)

    def _clear_scanner_rds(self):
        with self._scanner_rds_lock:
            self._scanner_rds = {}

    def _build_payload(self) -> dict:
        cfg  = self._cfg_fn()
        mon  = self._monitor
        ptp  = mon.ptp
        streams = []
        for _client_idx, inp in enumerate(cfg.inputs):
            sla_pct = None
            if inp._sla_monitored_s:
                total = inp._sla_monitored_s + inp._sla_alert_s
                sla_pct = round(inp._sla_monitored_s / max(total, 1) * 100, 3)
            streams.append({
                "_client_idx":       _client_idx,   # original cfg.inputs position — survives hub-side sorting
                "name":              inp.name,
                "enabled":           inp.enabled,
                "device_index":      inp.device_index,
                "level_dbfs":        round(inp._last_level_dbfs, 1),
                "peak_dbfs":         round(inp._last_peak_dbfs, 1),
                "silence_threshold_dbfs": inp.silence_threshold_dbfs,
                "silence_active":    bool(inp._silence_secs >= inp.silence_min_duration),
                "ai_status":         inp._ai_status,
                "ai_phase":          inp._ai_phase,
                "ai_monitor":        inp.ai_monitor,
                "ai_learn_start":    getattr(inp, "_ai_learn_start", 0),
                "rtp_loss_pct":      round(inp._rtp_loss_pct, 2),
                "rtp_jitter_ms":     round(inp._rtp_jitter_ms, 2),
                "rtp_total":         inp._rtp_total,
                "format":            inp._livewire_mode or "—",
                "sla_pct":           sla_pct,
                "alert_on_silence":  inp.alert_on_silence,
                "alert_on_hiss":     inp.alert_on_hiss,
                "alert_on_clip":     inp.alert_on_clip,
                "dab_snr":           round(inp._dab_snr, 1),
                "dab_sig":           round(inp._dab_sig, 1),
                "dab_ensemble":      inp._dab_ensemble,
                "dab_service":       inp._dab_service,
                "expected_dab_service": inp.expected_dab_service,
                "dab_ok":            inp._dab_ok,
                "dab_mode":          inp._dab_mode,
                "dab_bitrate":       inp._dab_bitrate,
                "dab_stereo":        inp._dab_stereo,
                "dab_dls":           inp._dab_dls,
                "fm_freq_mhz":       inp._fm_freq_mhz,
                "fm_signal_dbm":     round(inp._fm_signal_dbm, 1),
                "fm_snr_db":         round(inp._fm_snr_db, 1),
                "fm_stereo":         inp._fm_stereo,
                "fm_rds_ps":         inp._fm_rds_ps,
                "expected_fm_rds_ps": inp.expected_fm_rds_ps,
                "fm_rds_rt":         getattr(inp, "_fm_rds_rt", ""),
                "fm_rds_ok":         inp._fm_rds_ok,
                "fm_rds_status":     getattr(inp, "_fm_rds_status", "No lock"),
                "fm_rds_valid":      int(getattr(inp, "_fm_rds_valid_groups", 0)),
                "history":           list(inp._history)[-8:],
                "nowplaying_station_id": inp.nowplaying_station_id,
                "lufs_m":            round(inp._lufs_m, 1),
                "lufs_s":            round(inp._lufs_s, 1),
                "lufs_i":            round(inp._lufs_i, 1),
                "lufs_tp":           round(inp._lufs_tp, 1),
                # Glitch / flatness telemetry
                "glitch_count":      inp._glitch_count_total,
                "glitch_recent":     [round(t, 1) for t in inp._glitch_timestamps[-10:]],
                "flatness_active":   inp._flatness_active,
            })
        comparators = []
        for c in mon._comparators:
            comparators.append({
                "pre_name":          c.pre.name,
                "post_name":         c.post.name,
                "status":            c.status,
                "aligned":           c.aligned,
                "delay_ms":          round(c.delay_ms, 0),
                "correlation":       round(c.correlation, 3),
                "pre_dbfs":          round(c.pre_dbfs, 1),
                "post_dbfs":         round(c.post_dbfs, 1),
                "gain_diff_db":      round(c.gain_diff_db, 1),
                "gain_alert_db":     getattr(c.pre, "compare_gain_alert_db", 3.0),
                "processed":         c.processed,
                "compression_ratio": round(c.compression_ratio, 3),
                "cmp_history":       c.cmp_history[-6:],
            })
        # Recent alerts for hub reports page (last 50 — keep payload lean)
        _raw_alerts = _alert_log_load(50)
        recent_alerts = [{k: (v[:200] if isinstance(v,str) else v)
                          for k, v in e.items()} for e in _raw_alerts]
        # Clip counts per stream
        clips_dir = os.path.join(BASE_DIR, "alert_snippets")
        clip_counts = {}
        if os.path.exists(clips_dir):
            for stream_dir in os.listdir(clips_dir):
                dp = os.path.join(clips_dir, stream_dir)
                if os.path.isdir(dp):
                    clip_counts[stream_dir] = len([f for f in os.listdir(dp) if f.endswith(".wav")])
        for s in streams:
            s["clip_count"] = clip_counts.get(_safe_name(s["name"]), 0)
        # Client reports its own listen address so hub proxy routes work
        # regardless of what port the client is actually on.
        # Prefer the management IP from network config; fall back to hostname.
        mgmt_ip = cfg.network.management_interface_ip
        if not mgmt_ip or mgmt_ip == "0.0.0.0":
            try:
                # Best-effort: connect to hub and see which local IP is used
                hub_host = cfg.hub.hub_url.split("//")[-1].split(":")[0].split("/")[0]
                with socket.socket(socket.AF_INET, socket.SOCK_DGRAM) as _s:
                    _s.connect((hub_host, 80))
                    mgmt_ip = _s.getsockname()[0]
            except Exception:
                mgmt_ip = socket.gethostname()
        my_port = 5000  # client always listens on 5000 in client/both mode
        return {
            "api":         HUB_API_VERSION,
            "site":        cfg.hub.site_name or socket.gethostname(),
            "build":       BUILD,
            "ts":          time.time(),
            "running":     mon.is_running(),
            "learn_dur":   LEARN_DURATION_SECONDS,
            # self_url is always http — client sites are behind NAT/firewall
            # and never run TLS. Hub uses this to proxy audio back to the client.
            "self_url":    f"http://{mgmt_ip}:{my_port}",
            "streams":     streams,
            "comparators":  comparators,
            "recent_alerts": recent_alerts,
            "ptp": {
                "state":         ptp.state         if ptp else "idle",
                "status":        ptp.status         if ptp else "—",
                "offset_us":     ptp.offset_us      if ptp else 0,
                "drift_us":      ptp.drift_us       if ptp else 0,
                "jitter_us":     ptp.jitter_us      if ptp else 0,
                "gm_id":         ptp.gm_id          if ptp else "",
                "domain":        ptp.domain         if ptp else 0,
                "last_sync":     ptp.last_sync      if ptp else 0,
                "pmc_mode":      ptp.pmc_mode       if ptp else False,
                "path_delay_us": ptp.path_delay_us  if ptp else 0,
            } if mon.is_running() else {"state":"idle","status":"Not running","offset_us":0,"drift_us":0,"jitter_us":0,"gm_id":"","domain":0,"last_sync":0,"pmc_mode":False,"path_delay_us":0},
            "dab_scan_result": self._pop_dab_scan_result(),
            "system":          self._build_system_health(),
            "app_log":         [str(l)[:200] for l in list(self._monitor._log)[-30:]],
            "scanner_rds": self._get_scanner_rds(),
            # Dongles on this machine registered with role="scanner" — used by
            # the hub FM Scanner page to show only sites with a scanner dongle
            # and to populate the SDR dropdown with only scanner-role serials.
            "scanner_serials": [d.serial for d in cfg.sdr_devices if d.role == "scanner"],
            # Dongles with role="dab" — used by the DAB Scanner plugin to
            # populate its SDR dropdown with DAB-capable serials.
            "dab_serials":     [d.serial for d in cfg.sdr_devices if d.role == "dab"],
            # Report only the locally saved setting — not the hub-pushed value.
            # Including self._low_bw would create a feedback loop: hub pushes
            # true → client echoes true back → hub stores true forever.
            "low_bw":          getattr(cfg.hub, "low_bw", False),
        }

    def _handle_listen_requests(self, cfg, listen_requests: list):
        """
        Called when the hub ACK contains listen_requests.
        Spawns a pusher thread for each new slot that isn't already being served.
        """
        with self._lock:
            active = getattr(self, "_active_slots", set())
            if not hasattr(self, "_active_slots"):
                self._active_slots = set()
            active = self._active_slots

        # Kinds handled by this relay infrastructure.
        # Plugin-managed slots (e.g. kind="dab") post audio chunks directly
        # to /api/v1/audio_chunk/<slot_id> from their own client-side worker
        # and must NOT be intercepted here — doing so would launch an FM
        # stream that steals the RTL-SDR dongle.
        _HANDLED_KINDS = {"live", "scanner", "clip", "alert_wav"}

        for req in listen_requests:
            slot_id    = req.get("slot_id","")
            stream_idx = int(req.get("stream_idx", 0) or 0)
            kind       = req.get("kind", "live")
            if not slot_id or slot_id in active:
                continue
            if kind not in _HANDLED_KINDS:
                # Plugin manages this slot itself — do not spawn a relay thread
                continue
            with self._lock:
                self._active_slots.add(slot_id)
            print(f"[HubRelay] Starting push for slot {slot_id} kind={kind} stream {stream_idx}")
            t = threading.Thread(
                target=self._push_audio_request,
                args=(cfg, req),
                daemon=True,
                name=f"Relay-{slot_id[:6]}"
            )
            t.start()

    def _post_relay_chunk(self, cfg, chunk_url: str, data: bytes) -> dict:
        # Track per-URL RTT so the hub can auto-tune its keepalive threshold.
        # We send the RTT of the *previous* request (known only after it completes).
        if not hasattr(self, "_chunk_rtt"):
            self._chunk_rtt: dict = {}
        last_rtt = self._chunk_rtt.get(chunk_url, 0.0)

        ts_c    = time.time()
        t0      = time.monotonic()
        nonce_c = os.urandom(16).hex()
        sig_c   = hub_sign_payload(cfg.hub.secret_key, data, ts_c) if cfg.hub.secret_key else ""
        headers = {
            "Content-Type":  "application/octet-stream",
            "X-Hub-Sig":     sig_c,
            "X-Hub-Ts":      f"{ts_c:.0f}",
            "X-Hub-Nonce":   nonce_c,
        }
        if last_rtt:
            headers["X-Client-Rtt"] = f"{last_rtt:.4f}"
        req = urllib.request.Request(chunk_url, data=data, headers=headers, method="POST")
        with urllib.request.urlopen(req, timeout=5) as resp:
            self._chunk_rtt[chunk_url] = time.monotonic() - t0
            return json.loads(resp.read())

    def _push_audio_request(self, cfg, req: dict):
        """
        Fulfil one relay request from the hub. Supports:
        - live MP3 relay from stream buffer
        - on-demand WAV from current stream buffer
        - saved alert WAV file relay
        """
        import subprocess

        slot_id    = req.get("slot_id","")
        stream_idx = int(req.get("stream_idx", 0) or 0)
        kind       = req.get("kind", "live")
        seconds    = float(req.get("seconds", 10.0) or 10.0)
        stream_name= req.get("stream_name","") or ""
        filename   = req.get("filename","") or ""

        hub_url   = HubClient._normalise_url(cfg.hub.hub_url).rstrip("/")
        chunk_url = f"{hub_url}/api/{HUB_API_VERSION}/audio_chunk/{slot_id}"
        inps = cfg.inputs

        try:
            if kind == "live":
                if stream_idx < 0 or stream_idx >= len(inps):
                    print(f"[HubRelay] Invalid stream index {stream_idx}")
                    return
                inp = inps[stream_idx]
                if not _find_binary("ffmpeg"):
                    print(f"[HubRelay] ffmpeg not found, cannot relay live audio")
                    return

                sr      = SAMPLE_RATE
                bitrate = f"{self._hub_relay_bitrate or cfg.hub.relay_bitrate}k"
                cmd = [
                    "ffmpeg", "-hide_banner", "-loglevel", "error",
                    "-f", "s16le", "-ar", str(sr), "-ac", "1", "-i", "pipe:0",
                    "-f", "mp3", "-b:a", bitrate, "-reservoir", "0", "pipe:1",
                ]
                proc = subprocess.Popen(cmd,
                    stdin=subprocess.PIPE, stdout=subprocess.PIPE,
                    stderr=subprocess.DEVNULL, bufsize=0)

                stop_event = threading.Event()

                def _pcm(c):
                    return (np.clip(c, -1., 1.) * 32767).astype(np.int16).tobytes()

                def writer():
                    try:
                        if inp._stream_buffer:
                            seed_n = int(3.0 / CHUNK_DURATION)
                            for c in list(inp._stream_buffer)[-seed_n:]:
                                proc.stdin.write(_pcm(c))
                        sent_seq = getattr(inp, "_live_chunk_seq", 0)
                        while not stop_event.is_set():
                            cur = getattr(inp, "_live_chunk_seq", 0)
                            if cur > sent_seq:
                                n = min(cur - sent_seq, 50)
                                if inp._stream_buffer:
                                    for c in list(inp._stream_buffer)[-n:]:
                                        proc.stdin.write(_pcm(c))
                                sent_seq = cur
                            else:
                                time.sleep(0.02)
                    except Exception:
                        pass
                    finally:
                        try: proc.stdin.close()
                        except: pass

                wt = threading.Thread(target=writer, daemon=True)
                wt.start()

                consecutive_fails = 0
                try:
                    while not stop_event.is_set():
                        data = proc.stdout.read(4096)
                        if not data:
                            break
                        try:
                            body = self._post_relay_chunk(cfg, chunk_url, data)
                            if body.get("error") == "slot not found or expired":
                                print(f"[HubRelay] Slot {slot_id[:6]} expired, stopping")
                                break
                            consecutive_fails = 0
                        except Exception as e:
                            consecutive_fails += 1
                            if consecutive_fails >= 5:
                                print(f"[HubRelay] Too many push failures for {slot_id[:6]}: {e}")
                                break
                finally:
                    stop_event.set()
                    try: proc.kill(); proc.wait(timeout=2)
                    except: pass

            elif kind == "buffer_wav":
                if stream_idx < 0 or stream_idx >= len(inps):
                    print(f"[HubRelay] Invalid stream index {stream_idx} for WAV relay")
                    return
                inp = inps[stream_idx]
                if not inp._stream_buffer:
                    print(f"[HubRelay] No stream buffer for WAV relay {slot_id[:6]}")
                    return
                chunks = list(inp._stream_buffer)
                if not chunks:
                    print(f"[HubRelay] Empty stream buffer for WAV relay {slot_id[:6]}")
                    return
                secs = max(1.0, min(seconds, STREAM_BUFFER_SECONDS))
                audio = np.concatenate(chunks)[-int(SAMPLE_RATE * secs):]
                wav_bytes = _make_wav_bytes(audio.astype(np.float32))
                for off in range(0, len(wav_bytes), 8192):
                    body = self._post_relay_chunk(cfg, chunk_url, wav_bytes[off:off+8192])
                    if body.get("error") == "slot not found or expired":
                        print(f"[HubRelay] Slot {slot_id[:6]} expired during WAV relay")
                        break

            elif kind == "alert_wav":
                snip_dir = os.path.join(BASE_DIR, "alert_snippets")
                safe_stream   = _safe_name(stream_name) if stream_name else ""
                safe_filename = os.path.basename(filename)
                # Clips are stored in alert_snippets/<stream_name>/<filename>
                path = os.path.join(snip_dir, safe_stream, safe_filename) if safe_stream else os.path.join(snip_dir, safe_filename)
                if not os.path.abspath(path).startswith(os.path.abspath(snip_dir)):
                    print(f"[HubRelay] Refusing unsafe clip path for {slot_id[:6]}")
                    return
                if not os.path.exists(path):
                    print(f"[HubRelay] Alert clip not found for relay: {safe_filename}")
                    return
                expired = False
                with open(path, "rb") as f:
                    while True:
                        chunk = f.read(8192)
                        if not chunk:
                            break
                        body = self._post_relay_chunk(cfg, chunk_url, chunk)
                        if body.get("error") == "slot not found or expired":
                            print(f"[HubRelay] Slot {slot_id[:6]} expired during clip relay")
                            expired = True
                            break
                # Send empty EOF POST so the hub closes the slot immediately
                # (avoids the 30-second stale-timeout hold which breaks NGINX proxying)
                if not expired:
                    try:
                        self._post_relay_chunk(cfg, chunk_url, b"")
                    except Exception:
                        pass

            elif kind == "scanner":
                self._push_scanner_audio(cfg, req, slot_id, chunk_url)

            else:
                print(f"[HubRelay] Unknown relay kind '{kind}' for slot {slot_id[:6]}")
        finally:
            with self._lock:
                self._active_slots.discard(slot_id)

    def _push_scanner_audio(self, cfg, req: dict, slot_id: str, chunk_url: str):
        """Stream live FM audio from a remote SDR to a scanner relay slot.

        Audio path (raw PCM — no encoder, no WAV header):
            rtl_fm  -s 171000 -r 48000  →  48 kHz S16LE mono raw PCM
            → pipeline thread:
                  reads _BLOCK (9600 bytes = 0.1 s) at a time
                  replaces first _SKIP blocks with silence (flush USB burst)
                  puts raw PCM blocks into pcm_queue
            → main thread:
                  dequeues PCM blocks and POSTs raw bytes to hub
                  absolute-deadline clock absorbs POST network latency

        The WAV header and startup silence are generated on the hub side so
        that the browser's streaming connection is never stalled.  The client
        sends raw S16LE PCM only — the hub owns the stream framing.
        """
        import subprocess

        freq_mhz = float(req.get("freq_mhz", 96.5) or 96.5)
        serial   = str(req.get("sdr_serial", "") or "").strip()
        ppm      = int(req.get("ppm", 0) or 0)
        gain_raw = req.get("gain")
        gain     = float(gain_raw) if gain_raw is not None else 38.0

        if not _find_binary("rtl_fm"):
            monitor.log("[Scanner] rtl_fm not found — cannot start scanner")
            return

        if serial:
            try:
                device_idx = sdr_manager.resolve_index(serial)
            except Exception as e:
                monitor.log(f"[Scanner] SDR serial {serial!r} not available: {e}")
                return
        else:
            devs = sdr_manager.scan()
            if not devs:
                monitor.log("[Scanner] No SDR devices found")
                return
            device_idx = devs[0]["index"]

        _redsea_bin = _find_binary("redsea")
        _has_redsea = bool(_redsea_bin)

        freq_hz  = int(freq_mhz * 1_000_000)
        rds_tag  = " +RDS" if _has_redsea else ""
        monitor.log(f"[Scanner] {freq_mhz:.2f} MHz device={device_idx} slot={slot_id[:6]}{rds_tag}")

        _SDR_RATE = 171000
        _OUT_RATE = 171000 if _has_redsea else 48000   # 171k needed for RDS subcarrier
        _BLOCK    = _OUT_RATE * 2 // 10                # bytes per 0.1 s block
        _BLK_DUR  = 0.1
        _SKIP     = 15                                  # discard 1.5 s USB startup burst
        _AUD_BLOCK = 48000 * 2 // 10                   # 9600 bytes — 0.1 s at 48 kHz (audio)

        rtl_cmd = [
            "rtl_fm", "-f", str(freq_hz), "-M", "fm",
            "-l", "0", "-A", "std",
            "-s", str(_SDR_RATE), "-r", str(_OUT_RATE), "-F", "9",
            "-d", str(device_idx), "-",
        ]
        if ppm:
            rtl_cmd += ["-p", str(ppm)]
        rtl_cmd += ["-g", str(gain)]

        try:
            rtl_proc = subprocess.Popen(
                rtl_cmd, stdout=subprocess.PIPE, stderr=subprocess.DEVNULL, bufsize=0,
            )
        except Exception as e:
            monitor.log(f"[Scanner] rtl_fm start failed: {e}")
            return

        # ── Optional redsea subprocess for RDS ────────────────────────────────
        rds_proc = None
        if _has_redsea:
            try:
                rds_proc = subprocess.Popen(
                    [_redsea_bin, "-r", "171000", "-o", "json", "-p"],
                    stdin=subprocess.PIPE, stdout=subprocess.PIPE,
                    stderr=subprocess.DEVNULL, bufsize=0,
                )
            except Exception as _e:
                monitor.log(f"[Scanner] redsea start failed: {_e}")
                rds_proc = None

        # No WAV header — the hub generates it immediately when the browser
        # connects so the streaming connection is never stalled.

        stop_flag = threading.Event()
        pcm_queue = queue.Queue(maxsize=100)   # ~10 s safety buffer
        # Separate queue for redsea stdin so blocking pipe writes never stall
        # the audio pipeline.  Maxsize=5 (≈0.5 s) — drop oldest on overflow.
        rds_feed_q: queue.Queue = queue.Queue(maxsize=5)
        # Level computation queue: pipeline drops latest block here; a dedicated
        # thread does the numpy RMS off the hot audio path.  maxsize=1 so that
        # if the level thread falls behind, old blocks are simply skipped.
        level_q: queue.Queue = queue.Queue(maxsize=1)

        # Pre-warm scipy/numpy so the first resample_poly call in _pipeline
        # has no JIT/import overhead (avoids a 200-500 ms gap that could cause
        # Safari to drop the streaming connection).
        if _has_redsea:
            try:
                import numpy as _np_pre
                from scipy.signal import resample_poly as _rp_pre
                _rp_pre(_np_pre.zeros(17100, dtype=_np_pre.float32), 16, 57)
            except Exception:
                pass

        def _rds_feeder():
            """Drain rds_feed_q and write blocks to redsea's stdin.

            Running in its own thread so that a full OS pipe buffer never
            blocks the audio pipeline thread.  Blocks that can't be sent
            within 0.5 s are silently dropped (RDS frames are regenerated
            continuously so occasional drops are harmless).
            """
            if not rds_proc:
                return
            while not stop_flag.is_set():
                try:
                    blk = rds_feed_q.get(timeout=0.5)
                except queue.Empty:
                    continue
                try:
                    rds_proc.stdin.write(blk)
                except Exception:
                    break  # redsea died — stop feeding

        if rds_proc:
            threading.Thread(target=_rds_feeder, daemon=True,
                             name=f"ScanRDSFeed-{slot_id[:6]}").start()

        def _pipeline():
            """Read rtl_fm, replace USB startup burst with silence, queue raw PCM.

            When redsea is available the output rate is 171 kHz.  This thread
            resamples each block to 48 kHz (resample_poly 16/57) for audio and
            enqueues the raw 171 kHz block for the _rds_feeder thread (never
            writes to the pipe directly).
            Without redsea the output rate is 48 kHz and no resampling is done.
            """
            mux   = b""
            count = 0
            try:
                while not stop_flag.is_set():
                    raw = rtl_proc.stdout.read(_BLOCK)
                    if not raw:
                        break
                    mux += raw
                    while len(mux) >= _BLOCK:
                        blk   = mux[:_BLOCK]
                        mux   = mux[_BLOCK:]
                        count += 1
                        burst = (count <= _SKIP)
                        if burst:
                            aud_out = b"\x00" * _AUD_BLOCK
                        else:
                            if count == _SKIP + 1:
                                monitor.log(
                                    f"[Scanner] Burst flushed ({_SKIP} blk), "
                                    f"streaming raw PCM"
                                )
                            if _has_redsea:
                                # Enqueue raw 171 kHz block for redsea feeder
                                # (drop if feeder is behind — RDS is best-effort)
                                try:
                                    rds_feed_q.put_nowait(blk)
                                except queue.Full:
                                    try: rds_feed_q.get_nowait()
                                    except queue.Empty: pass
                                    try: rds_feed_q.put_nowait(blk)
                                    except queue.Full: pass
                                # Resample 171 kHz → 48 kHz for audio
                                import numpy as _np
                                from scipy.signal import resample_poly as _rp
                                samp = _np.frombuffer(blk, dtype='<i2').astype(_np.float32)
                                rs   = _rp(samp, 16, 57)
                                aud_out = rs.clip(-32768, 32767).astype('<i2').tobytes()
                            else:
                                aud_out = blk
                        # Feed level computer thread every ~1 s (10 blocks).
                        # Drop-if-full so the pipeline is never blocked.
                        if count % 10 == 0:
                            try: level_q.put_nowait(aud_out)
                            except queue.Full: pass
                        try:
                            pcm_queue.put(aud_out, timeout=1.0)
                        except queue.Full:
                            pass
            except Exception as e:
                monitor.log(f"[Scanner] Pipeline error: {e}")

        threading.Thread(target=_pipeline, daemon=True,
                         name=f"ScanPipe-{slot_id[:6]}").start()

        def _level_computer():
            """Drain level_q, compute RMS dBFS, write to scanner RDS dict.

            Runs off the pipeline thread so numpy work never stalls audio delivery.
            """
            import numpy as _nplc
            import math  as _mathc
            while not stop_flag.is_set():
                try:
                    blk = level_q.get(timeout=0.5)
                except queue.Empty:
                    continue
                try:
                    _s   = _nplc.frombuffer(blk, dtype='<i2').astype(_nplc.float32)
                    _rms = float(_nplc.sqrt(_nplc.mean(_s ** 2)))
                    _lvl = round(20 * _mathc.log10(_rms / 32768) if _rms > 0.5 else -96.0, 1)
                    _cur = self._get_scanner_rds()
                    _cur["_level"] = _lvl
                    self._set_scanner_rds(_cur)
                except Exception:
                    pass

        threading.Thread(target=_level_computer, daemon=True,
                         name=f"ScanLvl-{slot_id[:6]}").start()

        def _rds_reader():
            """Parse redsea JSON lines and update scanner RDS state.

            redsea -o json outputs: ps, radiotext, pi, pty, tp, ta, stereo, ct, af, group.
            We normalise all useful fields for the hub heartbeat / browser.

            PS and RadioText are stabilised with the same rolling-history / majority-vote
            algorithm used by the client FM monitor:
              • PS:  require the same candidate ≥ 3 times in the last 12 observations,
                     and never replace a longer confirmed name with a shorter partial.
              • RT:  require ≥ 2 occurrences in the last 10, or length ≥ 12 chars.
            """
            from collections import Counter as _Counter
            if not rds_proc:
                return
            _ps_hist: list = []
            _rt_hist: list = []
            for raw_line in iter(rds_proc.stdout.readline, b""):
                if stop_flag.is_set():
                    break
                line = raw_line.decode("utf-8", errors="replace").strip()
                if not line:
                    continue
                try:
                    d   = json.loads(line)
                    upd: dict = {}
                    ps  = str(d.get("ps") or d.get("partial_ps") or "").strip()
                    rt  = str(d.get("radiotext") or d.get("partial_radiotext") or "").strip()
                    pi  = str(d.get("pi") or "").strip()
                    pty = str(d.get("pty") or "").strip()
                    ct  = str(d.get("ct") or "").strip()
                    af  = d.get("af")
                    # Boolean flags — only update when explicitly present in the JSON
                    for key in ("tp", "ta", "stereo"):
                        if key in d:
                            upd[key] = bool(d[key])
                    if pi:  upd["pi"]  = pi
                    if pty: upd["pty"] = pty
                    if ct:  upd["ct"]  = ct
                    if isinstance(af, list) and af:
                        upd["af"] = [round(float(f), 2) for f in af[:20]]
                    # Read current RDS state once — used for PS/RT guards and final update
                    if ps or rt or upd:
                        cur = self._get_scanner_rds()
                    # ── Stabilise PS ──────────────────────────────────────────────
                    if ps:
                        cur_ps = (cur.get("ps") or "").strip()
                        # Don't let a shorter partial overwrite a confirmed longer name
                        if not (cur_ps and len(ps) < len(cur_ps)):
                            _ps_hist.append(ps)
                            _ps_hist[:] = _ps_hist[-12:]
                            stable_ps, cnt = _Counter(_ps_hist).most_common(1)[0]
                            if cnt >= 3 and len(stable_ps) >= max(6, len(cur_ps)):
                                upd["ps"] = stable_ps
                    # ── Stabilise RadioText ───────────────────────────────────────
                    if rt:
                        cur_rt = (cur.get("rt") or "").strip()
                        if not (cur_rt and len(rt) < max(8, len(cur_rt) // 2)):
                            _rt_hist.append(rt)
                            _rt_hist[:] = _rt_hist[-10:]
                            stable_rt, cnt = _Counter(_rt_hist).most_common(1)[0]
                            if cnt >= 2 or len(stable_rt) >= 12:
                                upd["rt"] = stable_rt
                    if upd:
                        cur.update(upd)
                        self._set_scanner_rds(cur)
                except Exception:
                    pass

        if rds_proc:
            threading.Thread(target=_rds_reader, daemon=True,
                             name=f"ScanRDS-{slot_id[:6]}").start()

        # Two-thread delivery: pacing thread + POST thread.
        #
        # Problem with a single sequential loop: when RTT > _BLK_DUR (0.1 s),
        # each iteration takes RTT seconds but the deadline only advances 0.1 s,
        # so the hub receives blocks at 0.1s/RTT of real-time rate.  At 200 ms
        # RTT that is 0.5x — the browser depletes its pre-buffer in ~2 s.
        #
        # Fix: the pacing loop enqueues blocks into post_q at real-time rate
        # (one per _BLK_DUR) without blocking on the POST.  The POST worker
        # drains post_q, batching any accumulated blocks into a single request
        # so the hub always receives real-time audio regardless of RTT.
        post_q:  queue.Queue = queue.Queue(maxsize=200)
        post_err: list       = [0]   # mutable counter shared with POST thread

        def _post_worker():
            while not stop_flag.is_set():
                try:
                    blk = post_q.get(timeout=1.0)
                except queue.Empty:
                    continue
                # Drain any additional blocks that accumulated while the
                # previous POST was in flight (RTT > _BLK_DUR case).
                batch = bytearray(blk)
                while True:
                    try:
                        batch += post_q.get_nowait()
                    except queue.Empty:
                        break
                try:
                    body = self._post_relay_chunk(cfg, chunk_url, bytes(batch))
                    if body.get("error") == "slot not found or expired":
                        monitor.log(f"[Scanner] Slot {slot_id[:6]} expired — stopping")
                        stop_flag.set()
                        return
                    post_err[0] = 0
                except Exception as e:
                    post_err[0] += 1
                    if post_err[0] >= 5:
                        monitor.log(f"[Scanner] Push failed: {e}")
                        stop_flag.set()
                        return

        threading.Thread(target=_post_worker, daemon=True,
                         name=f"ScanPost-{slot_id[:6]}").start()

        # Pacing loop: enqueue blocks at _BLK_DUR intervals.
        # out_deadline is initialised on the FIRST real block so that the
        # _SKIP=15 warm-up silence blocks don't pre-advance the clock 1.5 s.
        out_deadline: float | None = None
        try:
            while True:
                try:
                    blk = pcm_queue.get(timeout=2.0)
                except queue.Empty:
                    if stop_flag.is_set():
                        break
                    continue
                if stop_flag.is_set():
                    break
                if out_deadline is None:
                    out_deadline = time.monotonic()
                slack = out_deadline - time.monotonic()
                if slack > 0.001:
                    time.sleep(slack)
                try:
                    post_q.put_nowait(blk)
                except queue.Full:
                    pass   # hub unreachable; POST thread will detect and stop
                out_deadline += _BLK_DUR
        finally:
            stop_flag.set()
            monitor.log(f"[Scanner] Stopped {freq_mhz:.2f} MHz (slot {slot_id[:6]})")
            try: rtl_proc.kill(); rtl_proc.wait(timeout=2)
            except: pass
            with self._lock:
                self._active_slots.discard(slot_id)
            self._clear_scanner_rds()
            if rds_proc:
                try: rds_proc.kill(); rds_proc.wait(timeout=2)
                except: pass

    def _send_one(self, url: str, payload_bytes: bytes, secret: str = "") -> dict:
        """Sign, encrypt and send a payload. Returns full ACK body.
        If the URL is http:// and gets a redirect or connection error,
        automatically retries on https:// so clients survive a hub TLS upgrade.
        """
        # Auto-upgrade http → https on redirect or connection refused
        if url.startswith("http://"):
            try:
                return self._do_send(url, payload_bytes, secret)
            except Exception as e:
                err = str(e).lower()
                # Try https if http looks like it was refused or redirected
                if any(x in err for x in ("connection refused","remotedisconnected",
                                           "ssl","handshake","wrong version")):
                    https_url = "https://" + url[7:]
                    print(f"[HubClient] Retrying on HTTPS: {https_url[:60]}")
                    return self._do_send(https_url, payload_bytes, secret)
                raise
        return self._do_send(url, payload_bytes, secret)

    def _do_send(self, url: str, payload_bytes: bytes, secret: str = "") -> dict:
        """Internal: sign, encrypt and POST one payload."""
        ts    = time.time()
        nonce = os.urandom(16).hex()
        sig   = hub_sign_payload(secret, payload_bytes, ts) if secret else ""
        if secret:
            body_to_send = hub_encrypt_payload(secret, payload_bytes)
            content_type = "application/octet-stream"
        else:
            body_to_send = payload_bytes
            content_type = "application/json"
        req = urllib.request.Request(url, data=body_to_send,
            headers={
                "Content-Type":    content_type,
                "X-Hub-Sig":       sig,
                "X-Hub-Ts":        f"{ts:.0f}",
                "X-Hub-Nonce":     nonce,
                "X-Hub-Version":   HUB_API_VERSION,
            }, method="POST")
        try:
            resp_obj = urllib.request.urlopen(req, timeout=10)
        except urllib.error.HTTPError as e:
            if e.code == 429:
                raise RateLimitError("Hub rate limited (429) — backing off")
            raise
        with resp_obj as resp:
            # ACK may also be encrypted if secret is set
            raw = resp.read()
            ct  = resp.headers.get("Content-Type","")
            if secret and "octet-stream" in ct:
                raw = hub_decrypt_payload(secret, raw)
            ack = json.loads(raw)
            if not ack.get("ok"):
                raise RuntimeError(f"Hub rejected: {ack}")
        return ack

    def _loop(self):
        MAX_QUEUE   = 60          # max queued payloads during outage (~5 min at 5s)
        BASE_WAIT   = HUB_HEARTBEAT_INTERVAL
        MAX_BACKOFF = 60.0        # cap backoff at 60s

        while not self._stop.is_set():
          try:
            cfg = self._cfg_fn()
            if not cfg.hub.hub_url:
                self._stop.wait(BASE_WAIT)
                continue

            url = self._normalise_url(cfg.hub.hub_url).rstrip("/") + f"/api/{HUB_API_VERSION}/heartbeat"

            # Build current payload and enqueue it
            try:
                payload_bytes = json.dumps(self._build_payload()).encode()
                kb = len(payload_bytes) / 1024
                if kb > 50:
                    print(f"[HubClient] Warning: large payload {kb:.1f}KB")
                with self._lock:
                    self._queue.append(payload_bytes)
                    if len(self._queue) > MAX_QUEUE:
                        self._queue.pop(0)  # drop oldest
            except Exception as e:
                print(f"[HubClient] Payload build failed: {e}\n" + __import__("traceback").format_exc())
                self._stop.wait(BASE_WAIT)
                continue

            # Attempt to flush the queue
            flushed = 0
            with self._lock:
                queue_snapshot = list(self._queue)

            success   = False
            last_body = {}
            for i, pb in enumerate(queue_snapshot):
                try:
                    last_body = self._send_one(url, pb, secret=cfg.hub.secret_key)
                    flushed += 1
                    success = True
                except RateLimitError as e:
                    # 429 — jump backoff to max immediately, drop queue
                    self.last_error = str(e)
                    if self.last_error != getattr(self, "_prev_err", ""):
                        print(f"[HubClient] {e} — waiting before retry")
                        self._prev_err = self.last_error
                    self._backoff = 10  # max backoff immediately
                    break
                except Exception as e:
                    self.last_error = str(e)
                    if self.last_error != getattr(self, "_prev_err", ""):
                        print(f"[HubClient] Send failed: {self.last_error}")
                        self._prev_err = self.last_error
                    break

            with self._lock:
                if flushed:
                    self._queue = self._queue[flushed:]

            # Update state and backoff
            if success:
                if self._backoff:
                    print(f"[HubClient] Reconnected to hub after {self._backoff} consecutive failure(s)")
                self.last_ack   = time.time()
                self.sent_total += flushed
                self._backoff    = 0
                self.last_error  = ""
                self._prev_err   = ""
                self.state       = self.STATE_CONNECTED
                # Handle reverse relay requests from hub (NAT traversal)
                listen_reqs = last_body.get("listen_requests", [])
                if listen_reqs:
                    self._handle_listen_requests(cfg, listen_reqs)
                # Apply hub-controlled relay bitrate if provided
                hub_br = last_body.get("relay_bitrate")
                if isinstance(hub_br, int) and hub_br > 0:
                    self._hub_relay_bitrate = hub_br
                # Apply hub-controlled low-bandwidth mode
                hub_low_bw = last_body.get("low_bw")
                if hub_low_bw is not None:
                    self._low_bw = bool(hub_low_bw)
                # Execute hub-issued remote commands.
                # New hubs send a "commands" list (all queued cmds at once).
                # Legacy hubs send a single "command" dict — wrap in a list.
                _hub_cmd_list = last_body.get("commands")
                if _hub_cmd_list is None:
                    _single = last_body.get("command")
                    _hub_cmd_list = [_single] if _single else []
                for hub_cmd in _hub_cmd_list:
                  if not hub_cmd:
                    continue
                  if True:  # indent block to preserve existing structure
                    if isinstance(hub_cmd, str):
                        cmd_type, cmd_payload = hub_cmd.strip().lower(), {}
                    else:
                        cmd_type    = str(hub_cmd.get("type", "")).strip().lower()
                        cmd_payload = hub_cmd.get("payload") or {}
                    if cmd_type == "start" and not monitor.is_running():
                        monitor.log("[Hub] Remote start command received — starting monitoring")
                        monitor.start_monitoring()
                    elif cmd_type == "stop" and monitor.is_running():
                        monitor.log("[Hub] Remote stop command received — stopping monitoring")
                        monitor.stop_monitoring()
                    elif cmd_type == "add_input":
                        self._cmd_add_input(cmd_payload)
                    elif cmd_type == "remove_input":
                        self._cmd_remove_input(cmd_payload)
                    elif cmd_type == "enable_input":
                        self._cmd_toggle_input(cmd_payload, True)
                    elif cmd_type == "disable_input":
                        self._cmd_toggle_input(cmd_payload, False)
                    elif cmd_type == "dab_scan":
                        self._cmd_dab_scan(cmd_payload)
                    elif cmd_type == "set_expected_name":
                        self._cmd_set_expected_name(cmd_payload)
                    elif cmd_type == "save_clip":
                        self._cmd_save_clip(cmd_payload)
                    elif cmd_type == "self_update":
                        self._cmd_self_update(cmd_payload)
                    elif cmd_type == "restart":
                        self._cmd_restart(cmd_payload)
                    elif cmd_type == "chain_note":
                        self._cmd_chain_note(cmd_payload)
                    elif cmd_type == "ai_feedback":
                        self._cmd_ai_feedback(cmd_payload)
                    elif cmd_type == "retrain_stream":
                        self._cmd_retrain_stream(cmd_payload)
                    elif cmd_type == "calibrate_silence":
                        self._cmd_calibrate_silence(cmd_payload)
                    elif cmd_type == "backup":
                        self._cmd_backup(cmd_payload)
                    elif cmd_type == "ping_test":
                        self._cmd_ping_test(cmd_payload)
                    elif cmd_type == "push_log":
                        self._cmd_push_log(cmd_payload)
                    elif cmd_type == "scanner_band_scan":
                        self._cmd_scanner_band_scan(cmd_payload)
                    elif cmd_type == "cmp_pair":
                        self._cmd_cmp_pair(cmd_payload)
                # Drain auto-clip-upload queue — clips saved since the last
                # heartbeat are uploaded to the hub for the Reports page.
                # Cap at 2 per heartbeat cycle to avoid spawning a burst of
                # upload threads that spike CPU and cause RTP packet loss.
                # Remaining clips will upload on the next heartbeat (≈10 s).
                # In low-bandwidth mode the queue is left intact — clips are
                # delivered on-demand via the relay when viewed in Reports.
                _eff_low_bw = getattr(self, '_low_bw', False) or getattr(cfg.hub, 'low_bw', False)
                _cq = getattr(monitor, "_hub_clip_queue", None)
                if _cq and cfg.hub.hub_url and not _eff_low_bw:
                    _hub_url_str = cfg.hub.hub_url.rstrip("/")
                    _secret      = cfg.hub.secret_key
                    _site        = (cfg.hub.site_name or socket.gethostname()).strip()
                    _drained     = 0
                    while _drained < 2:
                        try:
                            _sn, _lbl, _cpath, _lev = _cq.get_nowait()
                            threading.Thread(
                                target=self._upload_clip,
                                args=(_hub_url_str, _secret, _site, _sn, _lbl, "", ""),
                                kwargs={"clip_path": _cpath, "level_dbfs": _lev},
                                daemon=True, name="AutoClipUpload",
                            ).start()
                            _drained += 1
                        except queue.Empty:
                            break
                # Periodic clip sync — re-upload any clips that never got their
                # .hub marker (failed uploads, pre-existing clips, etc.).
                # Runs every 10 heartbeat cycles ≈ every 100 s.
                self._hb_count = getattr(self, "_hb_count", 0) + 1
                if self._hb_count % 10 == 0:
                    threading.Thread(
                        target=self._sync_pending_clips,
                        daemon=True, name="ClipSync",
                    ).start()
                # Prune uploaded clips older than 24 h — offset by 5 cycles so
                # sync and prune don't race on the same files.
                if self._hb_count % 10 == 5:
                    threading.Thread(
                        target=self._prune_uploaded_clips,
                        daemon=True, name="ClipPrune",
                    ).start()
            else:
                self.fail_total += 1
                self._backoff    = min(self._backoff + 1, 10)
                age = time.time() - self.last_ack if self.last_ack else 999
                self.state = (self.STATE_DEGRADED if age < HUB_SITE_TIMEOUT
                              else self.STATE_DISCONNECTED)
                # Periodic retry log — first failure + every 5th after — so
                # operators can confirm the client is still actively retrying
                # rather than silently "giving up".
                if self._backoff == 1 or (self.fail_total % 5 == 0):
                    next_wait = min(BASE_WAIT * (1.5 ** self._backoff), MAX_BACKOFF)
                    print(f"[HubClient] Hub unreachable — retrying in {next_wait:.0f}s "
                          f"(consecutive: {self._backoff}/10, "
                          f"error: {self.last_error})")
                # If stuck at max backoff for a long time (>10 min), log a
                # prominent warning — this is the "client didn't self-heal"
                # scenario where a monitor restart would fix it.
                _stuck_since = getattr(self, "_max_backoff_since", 0)
                if self._backoff >= 10:
                    if not _stuck_since:
                        self._max_backoff_since = time.time()
                    elif time.time() - _stuck_since > 600:
                        print(f"[HubClient] WARNING: stuck at max backoff for "
                              f"{(time.time()-_stuck_since)/60:.0f} min — hub URL "
                              f"{cfg.hub.hub_url!r} may need checking. "
                              f"Last error: {self.last_error}. "
                              f"If hub is reachable, restarting the monitor will force reconnect.")
                        self._max_backoff_since = time.time()  # reset so it logs every 10 min
                else:
                    self._max_backoff_since = 0

            _eff_low_bw2 = getattr(self, '_low_bw', False) or getattr(cfg.hub, 'low_bw', False)
            _base = 30 if _eff_low_bw2 else BASE_WAIT
            wait = min(_base * (1.5 ** self._backoff), MAX_BACKOFF) if self._backoff else _base
            self._stop.wait(wait)
          except Exception as _top_e:
            # Safety net: prevent any uncaught exception from silently killing
            # the heartbeat thread.  Log it and keep retrying.
            print(f"[HubClient] Unexpected error in heartbeat loop "
                  f"(will retry in {BASE_WAIT}s): {_top_e}")
            import traceback as _tb; _tb.print_exc()
            self._stop.wait(BASE_WAIT)


# ─── Hub server — aggregates heartbeats from all clients ──────────────────────

class HubServer:
    """Runs on the central VPS. Receives heartbeats, serves hub dashboard."""

    def __init__(self):
        self._sites:  Dict[str, dict] = {}
        self._lock    = threading.Lock()
        self._secret: str = ""
        # Alert forwarding dedup — track event IDs already notified (max 10 000)
        self._notified_ids: "collections.OrderedDict[str, bool]" = __import__("collections").OrderedDict()
        self._notified_lock = threading.Lock()
        # Transient DAB scan results — keyed by site name, cleared after delivery
        self._dab_scan_results: Dict[str, dict] = {}
        # Chain fault state for dedup alerting — chain_id → "ok" | "pending" | "alerted"
        # "pending"  = fault detected but confirmation window not yet elapsed
        # "alerted"  = fault confirmed and notification sent
        self._chain_fault_state: dict = {}
        # When a chain entered "pending" state (epoch seconds)
        self._chain_fault_since: dict = {}
        # fault_index recorded when "pending" state was entered — used to detect
        # fault-position shifts during the confirmation window (e.g. ad-break
        # recovery where Node A comes back but Node B has a reporting lag)
        self._chain_fault_index: dict = {}
        # Flap detection — cid → list of recent fault timestamps
        self._chain_flap_events: dict = {}
        # cid → True while chain is in flapping state
        self._chain_flapping: dict = {}
        # Maintenance bypass — cid → {"site|stream": expiry_ts}
        self._chain_maintenance: dict = {}
        # Sites that have had a self_update command pushed, awaiting comeback
        # site_name → pushed_at timestamp
        self._pending_updates: dict = {}
        # Active scanner sessions — site_name → {slot_id, freq_mhz, sdr_serial, started}
        self._scanner_sessions: dict = {}
        # Band scan results — site → {peaks, ts, start_mhz, end_mhz}
        self._scanner_scan_results: dict = {}
        # Rolling PCM buffer for recording — site → deque of raw bytes (max 600 × 0.1s = 60s)
        self._scanner_pcm: dict = {}
        # Fault log — cid → list of fault dicts (max 25 in memory; persisted to DB)
        self._chain_fault_log: dict = {}
        # Predictive trend cache — stream_key → {"trend": str, "slope": float, "ts": float}
        self._chain_node_trend: dict = {}
        # Previous node status cache for watched-node push notifications — "cid/label" → "ok"|"fault"
        self._node_prev_state: dict = {}
        # SLA metric write tracker — cid → last write ts
        self._chain_sla_last_write: dict = {}
        # Tracks whether the current "alerted" fault for each chain was triggered
        # by an adbreak-candidate confirmation window timing out (long ad break
        # rather than a genuine fault).  Used to exclude these events from the
        # health-score fault-frequency count and from SLA downtime writes.
        self._chain_fault_adbreak: dict = {}
        # API-layer pre-pending fault onset — cid → epoch seconds
        # Tracks when api_chains_status first saw a fault BEFORE the monitor loop
        # had a chance to set _chain_fault_state to "pending".  Used so the
        # adbreak/pending countdown starts counting down immediately on the UI
        # rather than staying frozen at the full window until the next 10s loop tick.
        self._chain_api_pre_pending_since: dict = {}
        # Recovery confirmation — cid → epoch ts when recovery first seen
        # Used for min_recovery_seconds: chain stays "pending_recovery" until elapsed
        self._chain_recovery_since: dict = {}
        # Tracks when CHAIN_RECOVERED last fired per chain — cid → epoch ts
        # Used for post-recovery fast re-fault (Change 3) and cooldown (Change 4)
        self._chain_last_recovery: dict = {}
        # Per-chain last alert notification timestamp — cid → epoch ts
        # Used for min_alert_interval_minutes cooldown (Change 4)
        self._chain_last_alert_ts: dict = {}
        # Hysteresis: per-node silence fault active flag — "cid:node_index" → bool
        # True when that node is currently in a silence fault state (Change 2)
        self._chain_node_fault_active: dict = {}
        # Shared-fault aggregation — machine_tag → pending info dict (Change 5)
        self._chain_shared_fault_pending: dict = {}
        # Degrading alert fired flag — "cid:node_label" → bool (Change 6)
        self._chain_degrading_fired: dict = {}
        # Node offline notification sent flag — "cid:site:stream" → bool (Change 9)
        self._chain_node_offline_notified: dict = {}
        # A/B Group states — group_id → {status, a_ok, b_ok, rx_ok, since, ts}
        self._abgroup_states: dict = {}
        # Ad-break gap stitching — cid → epoch ts when brief inter-ad recovery started
        # Used to carry the original confirmation clock through badly-segued ad breaks.
        self._chain_adbreak_gap_start: dict = {}
        # Ad-break gap stitching — cid → original _chain_fault_since before brief recovery
        self._chain_adbreak_original_since: dict = {}
        # A/B Group last alert timestamp — group_id → float
        self._abgroup_alert_ts: dict = {}
        # Remote backup metadata — site_name → {"ts": float, "size": int}
        # Actual ZIP data lives on disk under HUB_BACKUP_DIR/<safe_name>/backup.zip
        self._site_backups: Dict[str, dict] = {}
        # Ping/connectivity test results — site_name → {"target": str, "output": str, "success": bool, "ts": float}
        self._ping_results: Dict[str, dict] = {}
        # On-demand log dumps — site_name → {"lines": [...], "ts": float}
        self._log_dumps: Dict[str, dict] = {}
        self._load_state()            # restore hub sites across restarts
        self._load_fault_log_from_db()  # restore chain fault history from SQLite
        self._load_backup_index()       # load backup metadata from disk
        # Start auto-daily backup thread
        threading.Thread(target=self._daily_backup_loop, daemon=True,
                         name="HubDailyBackup").start()

    def set_secret(self, secret: str):
        self._secret = secret

    # ── Per-site pending command queue (hub → client) ────────────────────────
    _CMD_QUEUE_MAX = 8   # maximum queued commands per site

    def push_pending_command(self, site_name: str, cmd: dict):
        """Append a structured command dict to the site's command queue (max _CMD_QUEUE_MAX).

        Immediately persists hub_state.json after enqueueing so that save_clip (and other
        commands) survive a hub restart that occurs before the next client heartbeat.
        Without this, any commands queued between a fault firing and the next heartbeat
        are lost on restart and remote nodes never capture or upload their audio clips.
        """
        snapshot = None
        with self._lock:
            if site_name not in self._sites:
                monitor.log(f"[Hub] push_pending_command: site {site_name!r} not found in "
                            f"_sites ({list(self._sites.keys())}) — command dropped: {cmd.get('type','?')}")
                return
            q = self._sites[site_name].setdefault("_pending_commands", [])
            if len(q) < self._CMD_QUEUE_MAX:
                q.append(cmd)
                monitor.log(f"[Hub] Queued {cmd.get('type','?')} command for site {site_name!r} "
                            f"(queue depth now {len(q)})")
                snapshot = dict(self._sites)   # capture for persistence outside lock
        # Persist outside the lock so _save_snapshot can safely re-read _sites
        if snapshot:
            threading.Thread(target=self._save_snapshot, args=(snapshot,),
                             daemon=True, name="HubSave").start()

    def set_pending_command(self, site_name: str, command: str):
        """Backward-compat: queue a simple start/stop command."""
        self.push_pending_command(site_name, {"type": command})

    def pop_pending_command(self, site_name: str) -> Optional[dict]:
        """Return and remove the next queued command dict, or None if empty."""
        with self._lock:
            site = self._sites.get(site_name)
            if not site:
                return None
            q = site.get("_pending_commands", [])
            if not q:
                return None
            cmd = q.pop(0)
            site["_pending_commands"] = q
            return cmd

    def pop_all_pending_commands(self, site_name: str) -> list:
        """Return AND remove every queued command dict for this site at once.

        Replaces the old pop_pending_command-per-heartbeat pattern so that
        all save_clip commands for a multi-node chain fault arrive at the
        client in the very next heartbeat ACK rather than trickling in one
        per 5-second cycle.
        """
        with self._lock:
            site = self._sites.get(site_name)
            if not site:
                return []
            q = site.get("_pending_commands", [])
            if not q:
                return []
            site["_pending_commands"] = []
            return list(q)

    # ── Per-site DAB scan results (client → hub, transient) ──────────────────
    def store_dab_scan_result(self, site_name: str, result: dict):
        """Store a DAB scan result received in a client heartbeat."""
        with self._lock:
            self._dab_scan_results[site_name] = result

    def pop_dab_scan_result(self, site_name: str) -> Optional[dict]:
        """Return and clear any pending DAB scan result for this site."""
        with self._lock:
            return self._dab_scan_results.pop(site_name, None)

    def peek_dab_scan_result(self, site_name: str) -> Optional[dict]:
        """Return any pending DAB scan result without clearing it."""
        with self._lock:
            return self._dab_scan_results.get(site_name)

    # ── Per-site relay bitrate (hub-controlled) ───────────────────────────────
    def get_relay_bitrate(self, site_name: str) -> int:
        with self._lock:
            return self._sites.get(site_name, {}).get("_relay_bitrate", 128)

    def set_relay_bitrate(self, site_name: str, bitrate: int):
        with self._lock:
            if site_name in self._sites:
                self._sites[site_name]["_relay_bitrate"] = bitrate
            else:
                # Site not yet seen — pre-create a stub so it persists
                self._sites[site_name] = {"_relay_bitrate": bitrate,
                                          "_received": 0, "_first_seen": time.time()}
            snapshot = dict(self._sites)
        threading.Thread(target=self._save_snapshot, args=(snapshot,),
                         daemon=True, name="HubSave").start()

    # ── Persistence ──────────────────────────────────────────────────────────
    # ── Auto-daily backup ────────────────────────────────────────────────────

    def _safe_backup_dir(self, site_name: str) -> str:
        """Return the on-disk directory for a site's backup, creating it if needed."""
        safe = re.sub(r"[^a-zA-Z0-9_\-]", "_", site_name)
        d = os.path.join(HUB_BACKUP_DIR, safe)
        os.makedirs(d, exist_ok=True)
        return d

    def _load_backup_index(self):
        """Scan HUB_BACKUP_DIR on startup and reload backup metadata into _site_backups."""
        if not os.path.isdir(HUB_BACKUP_DIR):
            return
        for entry in os.listdir(HUB_BACKUP_DIR):
            meta_path = os.path.join(HUB_BACKUP_DIR, entry, "backup_meta.json")
            zip_path  = os.path.join(HUB_BACKUP_DIR, entry, "backup.zip")
            if not (os.path.exists(meta_path) and os.path.exists(zip_path)):
                continue
            try:
                with open(meta_path) as f:
                    meta = json.load(f)
                site_name = meta.get("site") or entry
                with self._lock:
                    self._site_backups[site_name] = {
                        "ts":   float(meta["ts"]),
                        "size": int(meta["size"]),
                    }
            except Exception as e:
                print(f"[HubBackup] Could not load backup index for '{entry}': {e}")

    def save_backup_to_disk(self, site_name: str, data: bytes) -> None:
        """Write backup ZIP and metadata to disk; update in-memory index."""
        try:
            d = self._safe_backup_dir(site_name)
            zip_path  = os.path.join(d, "backup.zip")
            meta_path = os.path.join(d, "backup_meta.json")
            ts = time.time()
            with open(zip_path, "wb") as f:
                f.write(data)
            with open(meta_path, "w") as f:
                json.dump({"site": site_name, "ts": ts, "size": len(data)}, f)
            with self._lock:
                self._site_backups[site_name] = {"ts": ts, "size": len(data)}
            monitor.log(f"[Hub] Backup saved for '{site_name}': {len(data) // 1024} KB")
        except Exception as e:
            monitor.log(f"[Hub] Failed to save backup for '{site_name}': {e}")

    def get_backup_zip_path(self, site_name: str) -> "str | None":
        """Return the path to the latest backup ZIP for a site, or None if absent."""
        safe = re.sub(r"[^a-zA-Z0-9_\-]", "_", site_name)
        p = os.path.join(HUB_BACKUP_DIR, safe, "backup.zip")
        return p if os.path.exists(p) else None

    def _daily_backup_loop(self):
        """Background thread: trigger backup for any online site whose last backup
        is more than 23 hours old.  Checks immediately on startup so sites that
        have never been backed up get their first backup within one heartbeat cycle,
        then rechecks every hour."""
        first = True
        while True:
            try:
                if not first:
                    time.sleep(3600)   # check every hour after the first pass
                first = False
                now = time.time()
                with self._lock:
                    sites_snap = [
                        (name, dict(data))
                        for name, data in self._sites.items()
                        if data.get("online")
                    ]
                for site_name, _ in sites_snap:
                    bk = self._site_backups.get(site_name)
                    last_ts = bk["ts"] if bk else 0.0
                    if now - last_ts >= 23 * 3600:
                        self.push_pending_command(site_name, {"type": "backup"})
                        monitor.log(
                            f"[Hub] Auto-daily backup triggered for '{site_name}' "
                            f"(last backup: "
                            f"{'never' if last_ts == 0 else time.strftime('%Y-%m-%d %H:%M', time.localtime(last_ts))})")
            except Exception as e:
                print(f"[HubDailyBackup] Error: {e}")

    def _load_fault_log_from_db(self):
        """Restore chain fault history from SQLite into _chain_fault_log on startup.

        Called twice: once from __init__ (monitor may not exist yet — silently
        returns) and again after monitor is initialised so the full history is
        always available when the chains monitor loop starts.
        """
        try:
            cfg = monitor.app_cfg  # noqa: F821 — may raise NameError before monitor is set
        except NameError:
            return   # monitor not ready yet; will be called again after it is set
        if not cfg:
            return
        try:
            chains = cfg.signal_chains or []
            loaded = 0
            for chain in chains:
                cid = chain.get("id", "")
                if not cid:
                    continue
                entries = metrics_db.fault_log_load(cid, limit=25)
                if entries:
                    self._chain_fault_log[cid] = entries
                    loaded += len(entries)
            if loaded:
                print(f"[HubServer] Restored {loaded} chain fault log entry/entries from DB")
        except Exception as e:
            print(f"[HubServer] Could not load fault log from DB: {e}")

    def _load_state(self):
        """Load previously seen sites from disk so hub survives restarts."""
        try:
            if os.path.exists(HUB_STATE_PATH):
                with open(HUB_STATE_PATH, "r") as f:
                    saved = json.load(f)
                for name, data in saved.items():
                    # Mark as stale so they show as offline until next heartbeat
                    data["_received"] = data.get("_received", 0)
                    data.pop("_client_addr", None)   # IP may have changed
                    self._sites[name] = data
                print(f"[HubServer] Loaded {len(saved)} site(s) from state file")
                # Pre-populate notified IDs from saved alert history so that
                # existing alerts are not re-forwarded as new events after restart.
                with self._notified_lock:
                    for data in self._sites.values():
                        for evt in data.get("recent_alerts", []):
                            eid = evt.get("id", "")
                            if eid:
                                self._notified_ids[eid] = True
                print(f"[HubServer] Pre-seeded {len(self._notified_ids)} alert ID(s) to prevent restart spam")
        except Exception as e:
            print(f"[HubServer] Could not load state: {e}")

    def _save_snapshot(self, snapshot: dict):
        """Persist a snapshot of site data to disk.
        Sites are never auto-pruned — only explicit removal via the hub UI deletes a site.
        """
        try:
            save = {name: {k: v for k, v in data.items() if k not in ("_client_addr",)}
                    for name, data in snapshot.items()}
            with open(HUB_STATE_PATH, "w") as f:
                json.dump(save, f)
        except Exception as e:
            print(f"[HubServer] Could not save state: {e}")

    # ── Ingest ───────────────────────────────────────────────────────────────
    def approve_site(self, site_name: str) -> bool:
        """Mark a pending site as approved so it can send data. Returns True if site existed."""
        with self._lock:
            if site_name not in self._sites:
                return False
            self._sites[site_name]["_approved"] = True
            snapshot = dict(self._sites)
        threading.Thread(target=self._save_snapshot, args=(snapshot,),
                         daemon=True, name="HubSave").start()
        print(f"[HubServer] Site '{site_name}' approved")
        return True

    def ingest(self, payload: dict, client_ip: str = "") -> str:
        """Store a heartbeat. Signature already verified by route handler.
        Returns 'approved' for accepted sites, 'pending' for sites awaiting approval.
        """
        site = payload.get("site", "unknown")
        now  = time.time()

        # Use self_url from payload if provided, otherwise fall back to IP:5000
        self_url = payload.get("self_url","").strip()
        if not self_url and client_ip:
            self_url = f"http://{client_ip}:5000"
        # Always force http for _client_addr — client sites do not run TLS
        if self_url.startswith("https://"):
            self_url = "http://" + self_url[8:]

        with self._lock:
            prev = self._sites.get(site, {})
            is_new = not prev

            # ── New site: create a pending stub, don't process data ────────────
            if is_new:
                self._sites[site] = {
                    "site":          site,
                    "_approved":     False,
                    "_pending_since": now,
                    "_received":     now,
                    "_first_seen":   now,
                    "_client_addr":  self_url,
                    "_verified_ip":  client_ip,
                    "_total_received": 1,
                    "_total_missed":   0,
                    "_consecutive_missed": 0,
                    "_relay_bitrate": 128,
                    "_pending_commands": [],
                    # store minimal payload fields for display in pending banner
                    "build":   payload.get("build", ""),
                    "self_url": self_url,
                }
                snapshot = dict(self._sites)
                print(f"[HubServer] New site '{site}' from {client_ip} — pending approval")
            elif not prev.get("_approved", True):
                # Known but not yet approved — update heartbeat time and IP only
                self._sites[site]["_received"]    = now
                self._sites[site]["_client_addr"] = self_url
                self._sites[site]["_verified_ip"] = client_ip
                self._sites[site]["build"]        = payload.get("build", "")
                snapshot = dict(self._sites)
            else:
                # ── Approved site: full processing ────────────────────────────
                last_rx = prev.get("_received", 0)
                gap     = now - last_rx if last_rx else 0
                _hb_ivl = 30 if prev.get("low_bw") else HUB_HEARTBEAT_INTERVAL
                missed  = max(0, int(gap / _hb_ivl) - 1) if last_rx else 0
                consecutive_missed = prev.get("_consecutive_missed", 0)
                consecutive_missed = consecutive_missed + missed if missed else 0

                stored = {k: v for k, v in payload.items() if k != "secret"}
                stored.update({
                    "_approved":           True,
                    "_received":           now,
                    "_client_addr":        self_url,
                    "_verified_ip":        client_ip,
                    "_consecutive_missed": consecutive_missed,
                    "_total_missed":       prev.get("_total_missed", 0) + missed,
                    "_total_received":     prev.get("_total_received", 0) + 1,
                    "_first_seen":         prev.get("_first_seen", now),
                    "_relay_bitrate":      prev.get("_relay_bitrate", 128),
                    "_pending_commands":   prev.get("_pending_commands", []),
                })
                self._sites[site] = stored
                snapshot = dict(self._sites)

        approved = self._sites[site].get("_approved", True)

        # Persist asynchronously
        threading.Thread(target=self._save_snapshot, args=(snapshot,),
                         daemon=True, name="HubSave").start()

        if not approved:
            return "pending"

        # Forward new alert events via hub's own notification channels
        recent = payload.get("recent_alerts", [])
        if recent:
            threading.Thread(
                target=self._process_hub_alerts,
                args=(site, recent),
                daemon=True, name="HubAlerts"
            ).start()
        # Store DAB scan results reported by the client
        dab_result = payload.get("dab_scan_result")
        if dab_result and isinstance(dab_result, dict):
            self.store_dab_scan_result(site, dab_result)

        # Write stream metrics to the hub's local metrics_history.db so that
        # hub-mode-only installations accumulate history for all remote sites.
        streams_payload = payload.get("streams", [])
        if streams_payload:
            threading.Thread(
                target=self._flush_site_metrics,
                args=(site, streams_payload, time.time()),
                daemon=True, name="HubMetrics"
            ).start()

        # Write hub site health and latency metrics once per heartbeat
        try:
            _hb_now = time.time()
            tx_ts = float(payload.get("ts", 0) or 0)
            _lat = round(max(0.0, (_hb_now - tx_ts) * 1000), 1) if tx_ts else None
            with self._lock:
                _stored = self._sites.get(site, {})
            _total_rx   = _stored.get("_total_received", 1)
            _total_miss = _stored.get("_total_missed",   0)
            _hlth = round(_total_rx / max(_total_rx + _total_miss, 1) * 100, 1)
            _site_rows = [
                (f"site/{site}", "health_pct", _hb_now, _hlth),
            ]
            if _lat is not None:
                _site_rows.append((f"site/{site}", "latency_ms", _hb_now, _lat))
            metrics_db.write(_site_rows)
        except Exception:
            pass

        return "approved"

    def _flush_site_metrics(self, site_name: str, streams: list, now: float):
        """Write per-stream metric rows from a client heartbeat into metrics_history.db.

        Uses the hub's module-level metrics_db singleton — same DB used by local
        streams, but namespaced by the stream name which includes the site prefix
        if streams share names across sites.  For now, stream names are stored
        as-is (matching what the API and dashboard already use).
        """
        rows = []
        for st in streams:
            if not st.get("enabled", True):
                continue
            stream_name = st.get("name", "")
            if not stream_name:
                continue
            # Prefix with site name so streams from different sites never collide
            name = f"{site_name}/{stream_name}"
            dev = (st.get("device_index") or "").lower()

            # Universal metrics
            for metric in ("level_dbfs", "lufs_m", "lufs_s", "lufs_i"):
                val = st.get(metric)
                if val is not None:
                    rows.append((name, metric, now, float(val)))
            # silence_flag and clip_count
            lv = st.get("level_dbfs")
            if lv is not None:
                silence_thresh = st.get("silence_threshold_dbfs", -55.0)
                rows.append((name, "silence_flag", now, 1.0 if float(lv) <= float(silence_thresh) else 0.0))
            cc = st.get("clip_count")
            if cc is not None:
                rows.append((name, "clip_count", now, float(cc)))
            # Glitch / flatness from remote client
            gc = st.get("glitch_count")
            if gc is not None:
                rows.append((name, "glitch_count", now, float(gc)))
            ff = st.get("flatness_active")
            if ff is not None:
                rows.append((name, "flatness_flag", now, 1.0 if ff else 0.0))

            # FM-specific
            if dev.startswith("fm://"):
                for metric in ("fm_signal_dbm", "fm_snr_db"):
                    val = st.get(metric)
                    if val is not None:
                        rows.append((name, metric, now, float(val)))
                for bool_metric in ("fm_stereo", "fm_rds_ok"):
                    val = st.get(bool_metric)
                    if val is not None:
                        rows.append((name, bool_metric, now, 1.0 if val else 0.0))

            # DAB-specific
            if dev.startswith("dab://"):
                for metric in ("dab_snr", "dab_sig"):
                    val = st.get(metric)
                    if val is not None:
                        rows.append((name, metric, now, float(val)))
                val = st.get("dab_ok")
                if val is not None:
                    rows.append((name, "dab_ok", now, 1.0 if val else 0.0))
                val = st.get("dab_bitrate")
                if val is not None:
                    rows.append((name, "dab_bitrate", now, float(val)))

            # Livewire / AES67
            if not dev.startswith(("fm://", "dab://", "http://", "https://")):
                for metric in ("rtp_loss_pct", "rtp_jitter_ms"):
                    val = st.get(metric)
                    if val is not None:
                        rows.append((name, metric, now, float(val)))

        # PTP metrics from the client heartbeat payload
        ptp_data = self._sites.get(site_name, {}).get("ptp") if hasattr(self, "_sites") else None
        if not ptp_data:
            # Fall back: the caller passes the payload dict; we stash it on self temporarily
            # but hub heartbeat handler already stores full payload in _sites[site]
            pass
        # Write PTP rows using ptp data from stored site state
        with self._lock:
            site_data = self._sites.get(site_name, {})
        ptp_d = site_data.get("ptp") or {}
        ptp_state = ptp_d.get("state", "idle")
        if ptp_state not in ("idle", "", "Not running"):
            ptp_key = f"ptp/{site_name}"
            rows.append((ptp_key, "ptp_offset_us", now, float(ptp_d.get("offset_us", 0))))
            rows.append((ptp_key, "ptp_jitter_us", now, float(ptp_d.get("jitter_us", 0))))
            rows.append((ptp_key, "ptp_drift_us",  now, float(ptp_d.get("drift_us",  0))))

        if rows:
            metrics_db.write(rows)

    def _process_hub_alerts(self, site_name: str, alerts: list):
        """Forward new alert events from a client heartbeat using hub's notification channels."""
        try:
            cfg = monitor.app_cfg
        except Exception:
            return
        rules = cfg.hub_site_rules.get(site_name, {})
        if not rules.get("enabled", True):
            return
        fwd_types = {t.upper() for t in rules.get("forward_types", _HUB_DEFAULT_FORWARD_TYPES)}

        new_events = []
        with self._notified_lock:
            for evt in alerts:
                eid = evt.get("id", "")
                if not eid:
                    continue
                if eid not in self._notified_ids:
                    self._notified_ids[eid] = True
                    if evt.get("type", "").upper() in fwd_types:
                        new_events.append(evt)
            # Prune sliding window
            while len(self._notified_ids) > 10000:
                self._notified_ids.popitem(last=False)

        if not new_events:
            return
        try:
            sender = AlertSender(cfg, monitor.log)
            for evt in new_events:
                atype  = evt.get("type", "ALERT")
                stream = evt.get("stream", "")
                msg    = evt.get("message", "")
                subj   = f"[{site_name}] {atype} — {stream}"
                sender.send(subj, msg, alert_type=atype, stream=stream,
                            level_dbfs=evt.get("level_dbfs"))
        except Exception as e:
            try:
                monitor.log(f"[Hub] Alert forwarding error: {e}")
            except Exception:
                pass

    # ── Broadcast chain evaluation ────────────────────────────────────────────
    def _eval_one_node(self, node: dict, cfg, sites_snap: dict,
                       maintenance: "dict | None" = None,
                       hysteresis_key: "str | None" = None) -> dict:
        """Evaluate a single (non-stack) chain node and return its status dict.

        hysteresis_key: if set, use the _chain_node_fault_active dict to apply
        silence_off_threshold_dbfs hysteresis (Change 2).  Key = "cid:node_index".
        """
        site    = node.get("site", "")
        sname   = node.get("stream", "")
        label   = node.get("label") or f"{site}/{sname}"
        machine = (node.get("machine") or "").strip()
        # Maintenance bypass — return neutral status so this node is skipped in fault detection
        if maintenance:
            mkey = f"{site}|{sname}"
            mexp = maintenance.get(mkey, 0)
            if mexp > time.time():
                return {"label": label, "site": site, "stream": sname, "machine": machine,
                        "status": "maintenance", "level": None,
                        "maintenance_until": mexp}

        def _apply_hysteresis(level: float, on_thresh: float, node_cfg: dict) -> bool:
            """Return True if node should be considered 'down' (silence fault).
            Applies hysteresis band: fault enters at on_thresh, clears at off_thresh.
            off_thresh defaults to on_thresh + 10 dB if not explicitly set.
            """
            off_raw = node_cfg.get("silence_off_threshold_dbfs")
            off_thresh = float(off_raw) if off_raw is not None else (on_thresh + 10.0)
            if hysteresis_key is not None:
                currently_active = self._chain_node_fault_active.get(hysteresis_key, False)
                if currently_active:
                    # In fault — use off_thresh to clear
                    new_down = level <= off_thresh
                else:
                    # Not in fault — use on_thresh to enter fault
                    new_down = level <= on_thresh
                self._chain_node_fault_active[hysteresis_key] = new_down
                return new_down
            else:
                return level <= on_thresh

        if site == "local":
            inp = next((i for i in cfg.inputs if i.name == sname and i.enabled), None)
            if inp is None:
                return {"label": label, "site": site, "stream": sname, "machine": machine,
                        "status": "unknown", "level": None, "rtp_loss_pct": None}
            dev  = (inp.device_index or "").strip().lower()
            node_override_local = node.get("silence_threshold_dbfs")
            _local_thresh = float(node_override_local) if node_override_local is not None else inp.silence_threshold_dbfs
            down = _apply_hysteresis(inp._last_level_dbfs, _local_thresh, node)
            if dev.startswith("dab://") and not inp._dab_ok:
                down = True
            # If client-side silence detector has already confirmed silence,
            # force down regardless of instantaneous level.
            if inp._silence_secs >= inp.silence_min_duration:
                down = True
            is_rtp = not dev.startswith(("fm://", "dab://", "http://", "https://", "sound://"))
            # Recent glitches in last 5 minutes
            _g_recent_local = [t for t in inp._glitch_timestamps if t >= time.time() - 300.0]
            return {"label": label, "site": site, "stream": sname, "machine": machine,
                    "status": "down" if down else "ok",
                    "level": round(inp._last_level_dbfs, 1),
                    "rtp_loss_pct": round(inp._rtp_loss_pct, 2) if is_rtp else None,
                    "glitch_count":   inp._glitch_count_total,
                    "glitch_recent":  _g_recent_local,
                    "flatness_active": inp._flatness_active}
        else:
            site_data = sites_snap.get(site)
            if not site_data:
                return {"label": label, "site": site, "stream": sname, "machine": machine,
                        "status": "offline", "level": None, "rtp_loss_pct": None}
            if not site_data["online"]:
                offline_grace = HUB_HEARTBEAT_INTERVAL * 2
                offline_age_s = float(site_data.get("age_s", HUB_SITE_TIMEOUT) or HUB_SITE_TIMEOUT)
                return {"label": label, "site": site, "stream": sname, "machine": machine,
                        "status": "offline", "level": None, "rtp_loss_pct": None,
                        "offline_age_s": offline_age_s,
                        "offline_grace_active": offline_age_s < (HUB_SITE_TIMEOUT + offline_grace)}
            sd = next((s for s in site_data["streams"] if s.get("name") == sname), None)
            if sd is None:
                return {"label": label, "site": site, "stream": sname, "machine": machine,
                        "status": "unknown", "level": None, "rtp_loss_pct": None}
            lev  = float(sd.get("level_dbfs", -120.0))
            dev  = str(sd.get("device_index", "")).strip().lower()
            # Per-node chain override takes priority; otherwise use the remote
            # stream's own configured threshold from the heartbeat payload;
            # fall back to -55.0 dBFS for older clients that omit it.
            node_override = node.get("silence_threshold_dbfs")
            if node_override is not None:
                _silence_thresh = float(node_override)
            else:
                remote_threshold = sd.get("silence_threshold_dbfs")
                _silence_thresh  = float(remote_threshold) if remote_threshold is not None else -55.0
            down = _apply_hysteresis(lev, _silence_thresh, node)
            if dev.startswith("dab://") and not sd.get("dab_ok", True):
                down = True
            # Client-side silence detector runs continuously and catches silences
            # that start and end between heartbeat snapshots.  If the client reports
            # silence_active=True, the stream is definitively in silence regardless
            # of the instantaneous level_dbfs in this heartbeat snapshot.
            if sd.get("silence_active", False):
                down = True
            is_rtp = not dev.startswith(("fm://", "dab://", "http://", "https://", "sound://"))
            rtp_loss = sd.get("rtp_loss_pct")
            _g_recent_remote = sd.get("glitch_recent", [])
            return {"label": label, "site": site, "stream": sname, "machine": machine,
                    "status": "down" if down else "ok",
                    "level": round(lev, 1),
                    "rtp_loss_pct": round(float(rtp_loss), 2) if is_rtp and rtp_loss is not None else None,
                    "glitch_count":   sd.get("glitch_count", 0),
                    "glitch_recent":  _g_recent_remote,
                    "flatness_active": bool(sd.get("flatness_active", False))}

    def _pending_fault_meta(self, chain_id: str) -> dict:
        """Return pending-state metadata for a chain.

        Historically ``_chain_fault_index[cid]`` stored only an integer fault index.
        Newer code stores a dict so we can persist extra state such as whether the
        current confirmation window started as an ad-break candidate.
        """
        raw = self._chain_fault_index.get(chain_id)
        if isinstance(raw, dict):
            return {
                "fault_index": raw.get("fault_index"),
                "adbreak_candidate": bool(raw.get("adbreak_candidate", False)),
            }
        return {
            "fault_index": raw,
            "adbreak_candidate": False,
        }

    def _set_pending_fault_meta(self, chain_id: str, fault_index, adbreak_candidate: bool = False):
        self._chain_fault_index[chain_id] = {
            "fault_index": fault_index,
            "adbreak_candidate": bool(adbreak_candidate),
        }

    def _create_fault_log_entry(self, chain_id: str, now: float, result: dict) -> dict:
        fn_info = result.get("fault_node") or {}
        if fn_info.get("type") == "stack":
            # Stack node — synthesise label/site/stream from the silent sub-nodes
            sub_nodes  = fn_info.get("nodes", [])
            down_subs  = [n for n in sub_nodes
                          if n.get("status") in ("down", "offline")] or sub_nodes
            pos_num    = (result.get("fault_index") or 0) + 1
            _label     = fn_info.get("label") or f"Stack (position {pos_num})"
            _site      = ", ".join(dict.fromkeys(
                             n.get("site", "") for n in down_subs if n.get("site")
                         )) or "?"
            _stream    = ", ".join(
                             n.get("stream", "") for n in down_subs if n.get("stream")
                         ) or "?"
        else:
            _label     = fn_info.get("label", "?")
            _site      = fn_info.get("site", "?")
            _stream    = fn_info.get("stream", "?")
        return {
            "id":               str(uuid.uuid4()),
            "chain_id":         chain_id,
            "ts_start":         now,
            "fault_node_label": _label,
            "fault_site":       _site,
            "fault_stream":     _stream,
            "rtp_loss_pct":     fn_info.get("rtp_loss_pct"),
            "ts_recovered":     None,
            "clips":            [],
        }

    def _append_fault_log_entry(self, chain_id: str, now: float, result: dict):
        new_entry = self._create_fault_log_entry(chain_id, now, result)
        flog = self._chain_fault_log.setdefault(chain_id, [])
        flog.append(new_entry)
        if len(flog) > 25:
            flog.pop(0)
        metrics_db.fault_log_insert(new_entry)
        return new_entry

    def eval_chain(self, chain: dict, maintenance: "dict | None" = None) -> dict:
        """Evaluate a single chain and return its status dict.
        Nodes can be regular node dicts or stack dicts (type=='stack').
        maintenance: optional dict of "site|stream" → expiry_ts for bypassed nodes."""
        cfg = monitor.app_cfg
        now = time.time()
        with self._lock:
            sites_snap = {
                sname: {
                    "online": (now - data.get("_received", 0)) < HUB_SITE_TIMEOUT,
                    "age_s": max(0.0, now - float(data.get("_received", 0) or 0)),
                    "streams": data.get("streams", []),
                }
                for sname, data in self._sites.items()
            }

        nodes_out = []
        _cid = chain.get("id", "")
        for _ni, node in enumerate(chain.get("nodes", [])):
            if node.get("type") == "stack":
                mode     = node.get("mode", "all")
                sub_eval = []
                for _si, _sn in enumerate(node.get("nodes", [])):
                    _hk = f"{_cid}:{_ni}:{_si}" if _cid else None
                    sub_eval.append(self._eval_one_node(_sn, cfg, sites_snap, maintenance, hysteresis_key=_hk))
                if sub_eval:
                    if mode == "any":
                        is_down = any(
                            n.get("status") == "down"
                            or (n.get("status") == "offline" and not n.get("offline_grace_active", False))
                            for n in sub_eval
                        )
                    else:  # "all" — position only faults when every sub-node is down
                        is_down = all(
                            n.get("status") == "down"
                            or (n.get("status") == "offline" and not n.get("offline_grace_active", False))
                            for n in sub_eval
                        )
                else:
                    is_down = False
                # Best level = highest (most healthy) sub-node level
                levels = [n["level"] for n in sub_eval if n["level"] is not None]
                agg_level = round(max(levels), 1) if levels else None
                nodes_out.append({
                    "type":   "stack",
                    "mode":   mode,
                    "label":  node.get("label") or "Stack",
                    "status": "down" if is_down else "ok",
                    "level":  agg_level,
                    "nodes":  sub_eval,
                })
            else:
                _hk = f"{_cid}:{_ni}" if _cid else None
                nodes_out.append(self._eval_one_node(node, cfg, sites_snap, maintenance, hysteresis_key=_hk))

        # maintenance nodes are skipped in fault detection — they count as ok.
        # Brief remote-site heartbeat loss is also softened: an offline node within
        # a short grace period does not yet count as a chain fault.
        def _node_faults(_n: dict) -> bool:
            st = _n.get("status")
            if st == "down":
                return True
            if st == "offline":
                return not _n.get("offline_grace_active", False)
            return False

        fault_idx = next((i for i, n in enumerate(nodes_out) if _node_faults(n)), None)
        chain_status = "fault" if fault_idx is not None else ("ok" if nodes_out else "unknown")
        has_maintenance = any(
            (n.get("status") == "maintenance" or
             any(s.get("status") == "maintenance" for s in n.get("nodes", [])))
            for n in nodes_out
        )
        mixin_idx = chain.get("mixin_node_idx")
        min_fault_secs = max(0, int(chain.get("min_fault_seconds", 0) or 0))
        # Determine whether this looks like an ad break.
        #
        # Primary path: fault is pre-mixin and the mixin (ad-insert) node is still up.
        adbreak_candidate = False
        if (chain_status == "fault" and mixin_idx is not None and min_fault_secs > 0
                and fault_idx is not None and fault_idx < int(mixin_idx)):
            mixin_node = nodes_out[int(mixin_idx)] if int(mixin_idx) < len(nodes_out) else None
            if mixin_node and mixin_node.get("status") not in ("down", "offline"):
                adbreak_candidate = True
        # Secondary path: no mixin node, but the faulted position is a "fault-if-ALL-silent"
        # stack and all downstream nodes are healthy.  When both studio feeds (redundant
        # sources) go silent together while the router/TX chain is still carrying audio
        # (from an ad-insert or automation), it almost certainly means an ad break —
        # NOT a transmission failure.  Marking it as an adbreak_candidate has two effects:
        #   1. The UI badge shows "AD BREAK" instead of the alarming "CHECKING…"
        #   2. On service restart the warmup gives this chain a FRESH confirmation window
        #      instead of the backdated one used for genuine faults, preventing spurious
        #      CHAIN_FAULT alerts when SignalScope restarts mid-break.
        if (not adbreak_candidate and chain_status == "fault" and min_fault_secs > 0
                and fault_idx is not None and mixin_idx is None):
            _fn = nodes_out[fault_idx]
            if _fn.get("type") == "stack" and _fn.get("mode", "all") == "all":
                # Ad-break test: the studio-stack is silent but downstream TX is
                # still carrying audio (from automation / ad-server).
                #
                # The OLD check ("no downstream node is down") was too strict.
                # A pass-through router immediately after the codec stack naturally
                # mirrors the studio silence — it went dark too.  That caused
                # _any_post_down=True and blocked adbreak_candidate even though the
                # TX end of the chain was perfectly healthy.
                #
                # Better test: if ANY downstream node is actively "ok" (confirmed
                # carrying audio), the broadcast chain is still alive from another
                # source → ad break, not a cascading failure.
                # Only if EVERY downstream node is also dark do we treat it as a
                # genuine outage.
                _post = nodes_out[fault_idx + 1:]
                _any_post_ok = any(n.get("status") == "ok" for n in _post)
                if _any_post_ok:
                    adbreak_candidate = True
        return {
            "id":               chain.get("id", ""),
            "name":             chain.get("name", ""),
            "status":           chain_status,
            "fault_index":      fault_idx,
            "fault_node":       nodes_out[fault_idx] if fault_idx is not None else None,
            "nodes":            nodes_out,
            "mixin_node_idx":   mixin_idx,
            "min_fault_seconds": min_fault_secs,
            "adbreak_candidate": adbreak_candidate,
            "has_maintenance":  has_maintenance,
        }

    def _chains_monitor_loop(self, stop_evt):
        """Background thread: evaluate all chains every 30 s and fire CHAIN_FAULT alerts.

        Fault confirmation window (min_fault_seconds):
          Each chain can define ``min_fault_seconds`` (default 0).  A chain must
          remain in fault continuously for at least that many seconds before an
          alert is sent.  This suppresses spurious alerts during ad breaks, where
          the upstream node (playout / studio) goes silent while the TX continues
          playing spots from a separate source.

        Internal state values stored in ``_chain_fault_state``:
          "ok"      — chain is healthy (or no state yet)
          "pending" — fault detected; confirmation window not yet elapsed
          "alerted" — fault confirmed and notification already sent
        """
        _warmed_up  = False   # first pass: populate state without firing alerts
        _trend_last = 0.0    # last time node trends were computed
        # chain_state metric values written to metrics_history every ~10 s:
        #   1.0 = ok   0.5 = pending / adbreak   0.0 = alerted
        # History view reads these directly for accurate display_status reconstruction.
        _STATE_VAL = {"alerted": 0.0, "pending": 0.5, "ok": 1.0}
        while not stop_evt.is_set():
            try:
                now    = time.time()
                cfg    = monitor.app_cfg
                sender = AlertSender(cfg, monitor.log)

                # ── Predictive trend computation (every 30 s) ──────────────
                if now - _trend_last >= 30:
                    _trend_last = now
                    try:
                        import sqlite3 as _sqt
                        cutoff = now - CHAIN_TREND_WINDOW * 60
                        seen_keys: set = set()
                        for _ch in cfg.signal_chains:
                            for _nd in _ch.get("nodes", []):
                                subs = _nd.get("nodes", []) if _nd.get("type") == "stack" else [_nd]
                                for _s in subs:
                                    _site = _s.get("site", "")
                                    _strm = _s.get("stream", "")
                                    if not _strm:
                                        continue
                                    db_key = _strm if _site == "local" else f"{_site}/{_strm}"
                                    if db_key in seen_keys:
                                        continue
                                    seen_keys.add(db_key)
                                    with _sqt.connect(METRICS_DB_PATH) as _tc:
                                        rows = _tc.execute(
                                            "SELECT ts, value FROM metric_history "
                                            "WHERE stream=? AND metric='level_dbfs' AND ts>? ORDER BY ts",
                                            (db_key, cutoff)
                                        ).fetchall()
                                    if len(rows) < 10:
                                        self._chain_node_trend[db_key] = {"trend": "unknown", "slope": None, "ts": now}
                                        continue
                                    ts0 = rows[0][0]
                                    xs = [(r[0] - ts0) / 60.0 for r in rows]
                                    ys = [r[1] for r in rows]
                                    n  = len(xs)
                                    mx, my = sum(xs) / n, sum(ys) / n
                                    num = sum((xs[i] - mx) * (ys[i] - my) for i in range(n))
                                    den = sum((xs[i] - mx) ** 2 for i in range(n))
                                    slope = num / den if den != 0 else 0.0
                                    trend = ("down" if slope <= CHAIN_TREND_THRESH
                                             else "up" if slope >= abs(CHAIN_TREND_THRESH) else "stable")
                                    self._chain_node_trend[db_key] = {"trend": trend, "slope": round(slope, 3), "ts": now}
                                    # ── Change 6: Predictive / Degrading Alert ────────────────
                                    # Check each chain that references this stream node
                                    for _dch in cfg.signal_chains:
                                        _dcid = _dch.get("id", "")
                                        _trend_thresh = float(_dch.get("trend_alert_dbfs_per_min", 0.0) or 0.0)
                                        if _trend_thresh == 0.0 or not _dcid:
                                            continue
                                        # Only fire if slope is falling faster than the threshold (negative slope)
                                        if slope > _trend_thresh:
                                            continue
                                        # Find the node label for this stream in this chain
                                        _node_label_for_deg = _strm
                                        for _dn in _dch.get("nodes", []):
                                            _subs2 = _dn.get("nodes", []) if _dn.get("type") == "stack" else [_dn]
                                            for _ds in _subs2:
                                                if (_ds.get("site", "") == _site and
                                                        _ds.get("stream", "") == _strm):
                                                    _node_label_for_deg = _ds.get("label") or _strm
                                        _deg_key = f"{_dcid}:{_node_label_for_deg}"
                                        if self._chain_degrading_fired.get(_deg_key, False):
                                            continue
                                        # Only alert if chain is currently ok (not already faulted)
                                        if self._chain_fault_state.get(_dcid, "ok") in ("alerted", "pending"):
                                            continue
                                        self._chain_degrading_fired[_deg_key] = True
                                        # Compute projected time to silence
                                        _curr_level = ys[-1] if ys else None
                                        _node_thresh = next(
                                            (float(n.get("silence_threshold_dbfs", -55.0))
                                             for n in _dch.get("nodes", [])
                                             if n.get("stream") == _strm),
                                            -55.0
                                        )
                                        mins_to_silence = None
                                        if _curr_level is not None and slope < 0:
                                            _diff = _curr_level - _node_thresh
                                            if _diff > 0:
                                                mins_to_silence = _diff / abs(slope)
                                        _deg_msg = (
                                            f"Chain '{_dch.get('name', _dcid)}' degrading at node "
                                            f"'{_node_label_for_deg}': level trending at "
                                            f"{slope:.2f} dBFS/min"
                                            + (f", projected silence in ~{mins_to_silence:.0f} min"
                                               if mins_to_silence is not None else "")
                                        )
                                        _alert_log_append({
                                            "id":            str(uuid.uuid4()),
                                            "ts":            time.strftime("%Y-%m-%d %H:%M:%S"),
                                            "stream":        _dch.get("name", _dcid),
                                            "type":          "CHAIN_DEGRADING",
                                            "message":       _deg_msg,
                                            "level_dbfs":    _curr_level,
                                            "rtp_loss_pct":  None,
                                            "rtp_jitter_ms": None,
                                            "clip":          "",
                                            "ptp_state":     "",
                                            "ptp_offset_us": 0,
                                            "ptp_drift_us":  0,
                                            "ptp_jitter_us": 0,
                                            "ptp_gm":        "",
                                        })
                                        try:
                                            _deg_sender = AlertSender(cfg, monitor.log)
                                            _deg_sender.send(
                                                f"CHAIN DEGRADING — {_dch.get('name', _dcid)}",
                                                _deg_msg,
                                                alert_type="CHAIN_DEGRADING",
                                                stream=_dch.get("name", _dcid)
                                            )
                                            monitor.log(f"[Chain] DEGRADING: {_deg_msg}")
                                        except Exception as _de:
                                            monitor.log(f"[Chain] Degrading alert error: {_de}")
                    except Exception as _te:
                        monitor.log(f"[Chain] Trend compute error: {_te}")

                _state_rows: list = []   # batched chain_state metric writes for this pass

                for chain in cfg.signal_chains:
                    cid = chain.get("id", "")
                    if not cid:
                        continue
                    maint = self._chain_maintenance.get(cid, {})
                    result = self.eval_chain(chain, maintenance=maint)
                    self._check_watched_nodes(cid, result, now)
                    curr   = result["status"]   # "ok" | "fault" | "unknown"
                    min_fault_secs       = max(0, int(chain.get("min_fault_seconds", 0) or 0))
                    fault_shift_grace    = max(0, int(chain.get("fault_shift_grace_seconds", 0) or 0))
                    adbreak_gap_tol      = max(0, int(chain.get("adbreak_gap_tolerance_seconds", 5) or 5))

                    # Work out whether the confirmation window should apply.
                    #
                    # The delay only makes sense for nodes BEFORE the mix-in point
                    # (where silence could legitimately be an ad break). Faults AT or
                    # AFTER the mixin point mean the processed/TX output is silent —
                    # that is always a real fault and must alert immediately.
                    #
                    # Additionally bypass if the mixin node itself is down (no ads
                    # can fill silence if the mixin feed is also dead).
                    mixin_idx = chain.get("mixin_node_idx")
                    fault_idx  = result.get("fault_index")
                    mixin_is_down = False
                    fault_is_post_mixin = False
                    any_post_mixin_fault = False   # True if ANY node >= mixin_idx is faulted
                    if mixin_idx is not None:
                        _eval_nodes = result.get("nodes", [])
                        if 0 <= int(mixin_idx) < len(_eval_nodes):
                            mixin_is_down = _eval_nodes[int(mixin_idx)].get("status") in (
                                "down", "offline")
                        if fault_idx is not None and int(fault_idx) >= int(mixin_idx):
                            fault_is_post_mixin = True
                        # Scan ALL nodes at or after the mix-in point for a fault.
                        # The primary fault_idx may still point to a pre-mixin node when
                        # both a pre-mixin and a post-mixin node are faulted simultaneously
                        # (eval_chain returns the *first* fault).  A post-mixin fault must
                        # always bypass the confirmation window regardless.
                        for _pi, _pn in enumerate(_eval_nodes):
                            if _pi >= int(mixin_idx):
                                _ps = _pn.get("status")
                                if _ps == "down" or (
                                        _ps == "offline"
                                        and not _pn.get("offline_grace_active", False)):
                                    any_post_mixin_fault = True
                                    break

                    if not _warmed_up:
                        # Seed state silently so pre-existing faults don't re-fire.
                        #
                        # Chains WITH a confirmation delay (min_fault_secs > 0) are
                        # seeded as "pending" so the UI shows amber (not red) during
                        # startup.  We backdate 'since' so the confirmation window is
                        # already expired on the very first real evaluation, ensuring
                        # the alert fires promptly if the fault persists — rather than
                        # having to wait a full extra min_fault_secs window.
                        #
                        # Adbreak candidates always get a fresh window (since = now)
                        # because the silence might be a legitimate ad-break that
                        # started just before restart; we don't want to trigger
                        # spurious alerts.
                        #
                        # Chains with NO confirmation delay go straight to "alerted"
                        # (as before) to suppress duplicate notifications.
                        if curr == "fault" and result.get("adbreak_candidate") and min_fault_secs > 0:
                            # Adbreak candidate — start a fresh confirmation window
                            self._chain_fault_state[cid] = "pending"
                            self._chain_fault_since[cid] = now
                            self._set_pending_fault_meta(cid, result.get("fault_index"), result.get("adbreak_candidate", False))
                        elif curr == "fault" and min_fault_secs > 0 and not fault_is_post_mixin:
                            # Confirmation delay applies (pre-mixin fault only) — show
                            # amber on startup, fire on first real eval if still faulted.
                            self._chain_fault_state[cid] = "pending"
                            self._chain_fault_since[cid] = now - min_fault_secs
                            self._set_pending_fault_meta(cid, result.get("fault_index"), result.get("adbreak_candidate", False))
                        elif curr == "fault":
                            # No confirmation delay — suppress duplicate alert.
                            self._chain_fault_state[cid] = "alerted"
                        else:
                            self._chain_fault_state[cid] = "ok"
                        continue

                    prev = self._chain_fault_state.get(cid, "ok")

                    # ── Fault detection ──────────────────────────────────────
                    if curr == "fault":
                        if prev == "ok":
                            # Check post-recovery fast re-fault (Change 3)
                            _last_rec = self._chain_last_recovery.get(cid, 0)
                            _tail = float(chain.get("fault_tail_secs", 20.0))
                            _in_stability_window = (_last_rec > 0 and now - _last_rec < 2 * _tail)
                            # Never apply stability window to ad-break candidates —
                            # pre-mixin silence recurring within 40 s of a recovery is
                            # almost certainly back-to-back ad breaks, not a re-fault.
                            if (_in_stability_window and min_fault_secs > 0
                                    and not result.get("adbreak_candidate")):
                                monitor.log(
                                    f"[Chain] '{result['name']}' re-faulted within stability window "
                                    f"({round(now - _last_rec)}s < {round(2 * _tail)}s) — confirmation skipped.")
                                # Fall through with min_fault_secs treated as 0
                                min_fault_secs = 0
                            if min_fault_secs == 0 or mixin_is_down or fault_is_post_mixin or any_post_mixin_fault:
                                # Alert immediately:
                                #  - no confirmation delay configured, OR
                                #  - mix-in point itself is also silent (can't be an ad break), OR
                                #  - fault is at/after the mix-in point, OR
                                #  - any node at/after the mix-in point is faulted (even if
                                #    the primary fault_idx is pre-mixin)
                                if min_fault_secs > 0 and mixin_is_down:
                                    monitor.log(
                                        f"[Chain] '{result['name']}' — mix-in point also silent, "
                                        f"bypassing {min_fault_secs}s confirmation window.")
                                elif min_fault_secs > 0 and (fault_is_post_mixin or any_post_mixin_fault):
                                    monitor.log(
                                        f"[Chain] '{result['name']}' — post mix-in node faulted "
                                        f"(node {fault_idx}), bypassing {min_fault_secs}s confirmation window.")
                                self._chain_fault_state[cid] = "alerted"
                                self._chain_fault_since.pop(cid, None)
                                # Track flap events
                                flap_evts = self._chain_flap_events.setdefault(cid, [])
                                flap_evts[:] = [t for t in flap_evts if now - t < CHAIN_FLAP_WINDOW]
                                flap_evts.append(now)
                                # Clear any stale gap-stitching state — real fault fired
                                self._chain_adbreak_gap_start.pop(cid, None)
                                self._chain_adbreak_original_since.pop(cid, None)
                                # Update fault log ring buffer + DB
                                _flog_entry = self._append_fault_log_entry(cid, now, result)
                                if len(flap_evts) >= CHAIN_FLAP_COUNT and not self._chain_flapping.get(cid):
                                    # Flapping detected — suppress normal fault alert, fire CHAIN_FLAPPING
                                    self._chain_flapping[cid] = True
                                    self._fire_chain_flapping(result, chain, cfg, sender, now)
                                else:
                                    self._fire_chain_fault(result, chain, cfg, sender, now,
                                                           entry_id=_flog_entry.get("id", ""))
                            else:
                                # Start confirmation window.
                                # Gap stitching: if this re-fault is an adbreak candidate and
                                # occurs within adbreak_gap_tolerance_seconds of a brief
                                # inter-ad recovery, carry the original clock forward so that
                                # poorly-segued ad breaks (brief silence → brief audio → brief
                                # silence…) share one confirmation window rather than each
                                # getting a fresh countdown.
                                _gap_start   = self._chain_adbreak_gap_start.pop(cid, 0)
                                _orig_since  = self._chain_adbreak_original_since.pop(cid, 0)
                                _is_adbreak  = result.get("adbreak_candidate", False)
                                _in_gap      = (_gap_start > 0
                                                and adbreak_gap_tol > 0
                                                and (now - _gap_start) <= adbreak_gap_tol)
                                if _is_adbreak and _in_gap and _orig_since > 0:
                                    # Stitch: restore original fault clock
                                    self._chain_fault_state[cid] = "pending"
                                    self._chain_fault_since[cid] = _orig_since
                                    self._set_pending_fault_meta(cid, result.get("fault_index"), True)
                                    _stitched_elapsed = round(now - _orig_since, 1)
                                    monitor.log(
                                        f"[Chain] '{result['name']}' ad-break gap stitch — "
                                        f"brief inter-ad recovery ({round(now - _gap_start, 1)}s), "
                                        f"original clock restored ({_stitched_elapsed}s elapsed).")
                                else:
                                    # Normal fresh confirmation window
                                    self._chain_fault_state[cid] = "pending"
                                    self._chain_fault_since[cid] = now
                                    self._set_pending_fault_meta(cid, result.get("fault_index"), result.get("adbreak_candidate", False))
                                    monitor.log(
                                        f"[Chain] '{result['name']}' entered fault state — "
                                        f"waiting {min_fault_secs}s confirmation before alerting.")
                        elif prev == "pending":
                            # If the fault position has shifted since we entered
                            # pending (e.g. Node A recovered from ad break but
                            # Node B hasn't reported back yet due to heartbeat lag),
                            # reset the confirmation window so the new fault node
                            # gets its own full timer rather than inheriting the
                            # elapsed time from the previous position.
                            current_fault_idx = result.get("fault_index")
                            pending_meta = self._pending_fault_meta(cid)
                            stored_fault_idx  = pending_meta.get("fault_index")
                            if (current_fault_idx is not None
                                    and current_fault_idx != stored_fault_idx):
                                # Fault position shifted (e.g. a brief upstream program
                                # break coincided with the poll cycle).
                                self._set_pending_fault_meta(cid, current_fault_idx, pending_meta.get("adbreak_candidate", False))
                                if fault_shift_grace > 0:
                                    # Grace window configured: give the new fault position
                                    # fault_shift_grace_seconds of remaining time before firing.
                                    self._chain_fault_since[cid] = now - max(0.0, min_fault_secs - fault_shift_grace)
                                    monitor.log(
                                        f"[Chain] '{result['name']}' fault position shifted "
                                        f"(pos {stored_fault_idx} → {current_fault_idx}) — "
                                        f"applying {fault_shift_grace}s grace window.")
                                else:
                                    # Default (grace = 0): keep the original clock running.
                                    # The chain has been broken somewhere continuously;
                                    # resetting here would let intermittent upstream breaks
                                    # delay the alert indefinitely.
                                    _elapsed_so_far = round(now - self._chain_fault_since.get(cid, now))
                                    monitor.log(
                                        f"[Chain] '{result['name']}' fault position shifted "
                                        f"(pos {stored_fault_idx} → {current_fault_idx}) — "
                                        f"confirmation clock continues "
                                        f"({_elapsed_so_far}s / {min_fault_secs}s elapsed).")
                            elapsed = now - self._chain_fault_since.get(cid, now)
                            pending_adbreak = bool(pending_meta.get("adbreak_candidate", False))
                            # ── Ad-break schedule learning: dynamic confirmation window ──
                            # When we have enough history for this chain, shorten the window
                            # if the break time doesn't match any known schedule slot, or
                            # fire early if the break has run past the p95 duration.
                            if pending_adbreak:
                                try:
                                    _ab_stats = metrics_db.adbreak_stats(cid)
                                    if _ab_stats["count"] >= 5:
                                        import datetime as _dt2
                                        _fault_since = self._chain_fault_since.get(cid, now)
                                        _mod = int(_dt2.datetime.fromtimestamp(_fault_since).hour * 60
                                                   + _dt2.datetime.fromtimestamp(_fault_since).minute)
                                        _in_window = any(
                                            abs((_mod - _cm) % 1440) <= 4 or abs((_cm - _mod) % 1440) <= 4
                                            for _cm in _ab_stats["common_minutes"]
                                        )
                                        if not _in_window:
                                            # Not a known ad-break slot — shorten window aggressively
                                            min_fault_secs = max(20, int(min_fault_secs * 0.4))
                                        elif _ab_stats["p95"] > 0 and elapsed > _ab_stats["p95"] * 1.2:
                                            # Break has run longer than p95 * 1.2 — force alert now
                                            min_fault_secs = 0
                                            monitor.log(
                                                f"[Chain] '{result['name']}' ad-break overshoot: "
                                                f"{elapsed:.0f}s > p95 {_ab_stats['p95']:.0f}s — firing alert.")
                                except Exception:
                                    pass
                            # mixin_is_down and post-mixin faults always bypass regardless of
                            # whether the pending window started as an adbreak candidate —
                            # a post-mixin fault is never an ad break, and if the mix-in
                            # node itself is silent there can be no ad fill.
                            effective_mixin_is_down = mixin_is_down
                            effective_post_mixin = fault_is_post_mixin or any_post_mixin_fault
                            if elapsed >= min_fault_secs or effective_mixin_is_down or effective_post_mixin:
                                # Confirmation window elapsed, or a bypass condition is met
                                reason = ("mix-in point also silent"
                                          if effective_mixin_is_down and elapsed < min_fault_secs
                                          else "post mix-in node faulted during ad break window"
                                          if effective_post_mixin and pending_adbreak and elapsed < min_fault_secs
                                          else "fault shifted to post mix-in node"
                                          if effective_post_mixin and elapsed < min_fault_secs
                                          else f"{round(elapsed)}s elapsed")
                                monitor.log(
                                    f"[Chain] '{result['name']}' fault confirmed ({reason}).")
                                self._chain_fault_state[cid] = "alerted"
                                self._chain_fault_since.pop(cid, None)
                                self._chain_fault_index.pop(cid, None)
                                # Clear gap-stitching state — real fault confirmed
                                self._chain_adbreak_gap_start.pop(cid, None)
                                self._chain_adbreak_original_since.pop(cid, None)
                                # Track flap events
                                flap_evts = self._chain_flap_events.setdefault(cid, [])
                                flap_evts[:] = [t for t in flap_evts if now - t < CHAIN_FLAP_WINDOW]
                                flap_evts.append(now)
                                # Update fault log ring buffer + DB
                                _flog_entry = self._append_fault_log_entry(cid, now, result)
                                # Tag faults that fired because an adbreak-candidate window
                                # timed out — these are long ad breaks, not genuine faults,
                                # and should not count against health score or SLA.
                                if pending_adbreak:
                                    _flog_entry["adbreak_overshoot"] = True
                                    self._chain_fault_adbreak[cid] = True
                                else:
                                    self._chain_fault_adbreak.pop(cid, None)
                                if len(flap_evts) >= CHAIN_FLAP_COUNT and not self._chain_flapping.get(cid):
                                    self._chain_flapping[cid] = True
                                    self._fire_chain_flapping(result, chain, cfg, sender, now)
                                else:
                                    self._fire_chain_fault(result, chain, cfg, sender, now,
                                                           entry_id=_flog_entry.get("id", ""))
                            # else: still waiting — do nothing
                        # prev == "alerted": already notified, nothing to do

                    # ── Recovery detection ───────────────────────────────────
                    elif curr == "ok":
                        min_recovery_secs = max(0, int(chain.get("min_recovery_seconds", 0) or 0))
                        if prev == "alerted":
                            if min_recovery_secs > 0:
                                # Start recovery confirmation window
                                self._chain_fault_state[cid] = "pending_recovery"
                                self._chain_recovery_since[cid] = now
                                monitor.log(
                                    f"[Chain] '{result['name']}' recovery pending — "
                                    f"waiting {min_recovery_secs}s confirmation.")
                            else:
                                # Immediate recovery (existing behaviour)
                                self._do_chain_recovery(cid, result, chain, cfg, sender, now)
                        elif prev == "pending_recovery":
                            elapsed = now - self._chain_recovery_since.get(cid, now)
                            if elapsed >= min_recovery_secs:
                                self._chain_recovery_since.pop(cid, None)
                                self._do_chain_recovery(cid, result, chain, cfg, sender, now)
                            # else: still waiting — do nothing
                        elif prev == "pending":
                            # Fault resolved within confirmation window (e.g. ad break ended)
                            elapsed = round(now - self._chain_fault_since.get(cid, now), 1)
                            _pending_was_adbreak = self._pending_fault_meta(cid).get("adbreak_candidate", False)
                            monitor.log(
                                f"[Chain] '{result['name']}' recovered within confirmation "
                                f"window ({elapsed}s) — no alert sent (likely ad break).")
                            # Gap stitching: if this was an adbreak candidate, remember the
                            # original fault clock and when the brief recovery started.
                            # If the chain re-faults quickly (segue gap), we restore the
                            # clock so inter-ad silences eat one shared confirmation window.
                            if _pending_was_adbreak and adbreak_gap_tol > 0:
                                self._chain_adbreak_gap_start[cid]  = now
                                self._chain_adbreak_original_since[cid] = self._chain_fault_since.get(cid, now)
                            else:
                                self._chain_adbreak_gap_start.pop(cid, None)
                                self._chain_adbreak_original_since.pop(cid, None)
                            self._chain_fault_state[cid] = "ok"
                            self._chain_fault_since.pop(cid, None)
                            self._chain_fault_index.pop(cid, None)
                        # prev == "ok": already ok, nothing to do

                    # ── pending_recovery → fault: abort recovery ─────────────
                    elif curr == "fault" and prev == "pending_recovery":
                        monitor.log(
                            f"[Chain] '{result['name']}' re-faulted during recovery "
                            f"confirmation window — aborting recovery, state back to alerted.")
                        self._chain_fault_state[cid] = "alerted"
                        self._chain_recovery_since.pop(cid, None)

                    # ── Change 9: Node-level offline notification ────────────
                    if _warmed_up:
                        chain_state_now = self._chain_fault_state.get(cid, "ok")
                        _node_cfg_list = chain.get("nodes", [])
                        for _ni2, _ne in enumerate(result.get("nodes", [])):
                            _ncfg = _node_cfg_list[_ni2] if _ni2 < len(_node_cfg_list) else {}
                            # Flatten stack nodes
                            _subs3 = (list(zip(_ncfg.get("nodes", []), _ne.get("nodes", [])))
                                      if _ne.get("type") == "stack"
                                      else [(_ncfg, _ne)])
                            for (_scfg, _seval) in _subs3:
                                if not _scfg.get("offline_notify", False):
                                    continue
                                _ok_site   = _scfg.get("site", "")
                                _ok_stream = _scfg.get("stream", "")
                                _ok_key    = f"{cid}:{_ok_site}:{_ok_stream}"
                                if _seval.get("status") == "offline" and chain_state_now != "alerted":
                                    if not self._chain_node_offline_notified.get(_ok_key, False):
                                        self._chain_node_offline_notified[_ok_key] = True
                                        _ok_label = _scfg.get("label") or _ok_stream or "?"
                                        _ok_msg = (
                                            f"Node '{_ok_label}' in chain '{chain.get('name','?')}' "
                                            f"is offline (site: {_ok_site})"
                                        )
                                        _alert_log_append({
                                            "id":            str(uuid.uuid4()),
                                            "ts":            time.strftime("%Y-%m-%d %H:%M:%S"),
                                            "stream":        chain.get("name", "?"),
                                            "type":          "CHAIN_NODE_OFFLINE",
                                            "message":       _ok_msg,
                                            "level_dbfs":    None,
                                            "rtp_loss_pct":  None,
                                            "rtp_jitter_ms": None,
                                            "clip":          "",
                                            "ptp_state":     "",
                                            "ptp_offset_us": 0,
                                            "ptp_drift_us":  0,
                                            "ptp_jitter_us": 0,
                                            "ptp_gm":        "",
                                        })
                                        try:
                                            sender.send(
                                                f"NODE OFFLINE — {chain.get('name','?')}",
                                                _ok_msg,
                                                alert_type="CHAIN_NODE_OFFLINE",
                                                stream=chain.get("name", "?"),
                                            )
                                            monitor.log(f"[Chain] NODE OFFLINE: {_ok_msg}")
                                        except Exception as _oe:
                                            monitor.log(f"[Chain] Node offline notify error: {_oe}")
                                elif _seval.get("status") != "offline":
                                    if self._chain_node_offline_notified.get(_ok_key, False):
                                        self._chain_node_offline_notified[_ok_key] = False
                                        _ok_label = _scfg.get("label") or _ok_stream or "?"
                                        monitor.log(
                                            f"[Chain] Node '{_ok_label}' back online "
                                            f"in chain '{chain.get('name','?')}'")

                    # ── SLA metric write (every 60 s) ─────────────────────────
                    last_sla = self._chain_sla_last_write.get(cid, 0)
                    if _warmed_up and now - last_sla >= 60:
                        self._chain_sla_last_write[cid] = now
                        # Only count as downtime when an alert has actually fired,
                        # and the fault is NOT an adbreak-overshoot (long ad break
                        # that exceeded the confirmation window — genuine faults only).
                        _is_real_fault = (self._chain_fault_state.get(cid) == "alerted"
                                          and not self._chain_fault_adbreak.get(cid, False))
                        sla_val = 0.0 if _is_real_fault else 1.0
                        try:
                            metrics_db.write([(f"chain/{cid}", "chain_status", now, sla_val)])
                        except Exception:
                            pass

                    # ── chain_state metric (every pass, ~10 s) ────────────────
                    # Written on every evaluation cycle so the history view can
                    # reconstruct the exact alert state machine state at any
                    # point in time without having to guess from level_dbfs data.
                    if _warmed_up:
                        _state_rows.append((
                            f"chain/{cid}", "chain_state", now,
                            _STATE_VAL.get(self._chain_fault_state.get(cid, "ok"), 1.0),
                        ))

                # ── Batch-write chain_state rows for all chains ───────────────
                if _state_rows:
                    try:
                        metrics_db.write(_state_rows)
                    except Exception:
                        pass

                # ── A/B Group evaluation ─────────────────────────────────────────
                for grp in (cfg.ab_groups or []):
                    gid = grp.get("id", "")
                    if not gid:
                        continue
                    chain_a_id  = grp.get("chain_a_id", "")
                    chain_b_id  = grp.get("chain_b_id", "")
                    rx_node     = grp.get("rx_node") or {}

                    def _chain_ok(cid_):
                        return self._chain_fault_state.get(cid_, "ok") in ("ok", "pending_recovery")

                    a_ok = _chain_ok(chain_a_id) if chain_a_id else True
                    b_ok = _chain_ok(chain_b_id) if chain_b_id else True

                    # Evaluate RX node independently via a synthetic single-node chain
                    rx_ok = True
                    if rx_node.get("stream"):
                        try:
                            _rx_synth = {
                                "id": f"_rx_{gid}",
                                "name": rx_node.get("label", "Broadcast RX"),
                                "nodes": [rx_node],
                            }
                            rx_ok = self.eval_chain(_rx_synth, maintenance={})["status"] == "ok"
                        except Exception:
                            rx_ok = True

                    # Composite status
                    if not rx_ok and not a_ok and not b_ok:
                        new_gs = "off_air"
                    elif not rx_ok:
                        new_gs = "rx_fault"
                    elif not a_ok and not b_ok:
                        new_gs = "both_fault"
                    elif not a_ok:
                        new_gs = "a_fault"
                    elif not b_ok:
                        new_gs = "b_fault"
                    else:
                        new_gs = "ok"

                    prev_info = self._abgroup_states.get(gid, {})
                    prev_gs   = prev_info.get("status", "ok")
                    since     = prev_info.get("since", now) if new_gs == prev_gs else now
                    self._abgroup_states[gid] = {
                        "status": new_gs, "a_ok": a_ok, "b_ok": b_ok,
                        "rx_ok": rx_ok, "since": since, "ts": now,
                    }

                    if not _warmed_up or new_gs == prev_gs:
                        continue

                    # Fire alert on transition
                    grp_name    = grp.get("name", gid)
                    active_role = grp.get("active_role", "a")
                    try:
                        if new_gs == "ok":
                            _abg_msg = f"A/B Group '{grp_name}' fully recovered — all paths healthy"
                            _abg_type = "ABGROUP_RECOVERED"
                        elif new_gs == "off_air":
                            _abg_msg = (f"\u26a0 OFF AIR: '{grp_name}' — "
                                        f"both A & B paths AND broadcast RX are silent")
                            _abg_type = "ABGROUP_OFF_AIR"
                        elif new_gs == "rx_fault":
                            _abg_msg = (f"A/B Group '{grp_name}' — Broadcast RX silent "
                                        f"(signal paths appear ok — check RX/air monitor)")
                            _abg_type = "ABGROUP_RX_FAULT"
                        elif new_gs == "both_fault":
                            _abg_msg = (f"A/B Group '{grp_name}' — BOTH A and B paths faulted")
                            _abg_type = "ABGROUP_BOTH_FAULT"
                        elif new_gs == "a_fault":
                            _note = " — consider switching to B" if active_role == "a" else " (B is active)"
                            _abg_msg = (f"A/B Group '{grp_name}' — A path faulted, B path healthy{_note}")
                            _abg_type = "ABGROUP_A_FAULT"
                        else:  # b_fault
                            _note = " — consider switching to A" if active_role == "b" else " (A is active)"
                            _abg_msg = (f"A/B Group '{grp_name}' — B path faulted, A path healthy{_note}")
                            _abg_type = "ABGROUP_B_FAULT"
                        _alert_log_append({"type": _abg_type, "stream": grp_name,
                                           "message": _abg_msg, "_site": "(hub)"})
                        sender.send(f"{_abg_type.replace('_',' ')} — {grp_name}",
                                    _abg_msg, alert_type=_abg_type, stream=grp_name)
                        monitor.log(f"[ABGroup] {grp_name}: {prev_gs} → {new_gs}")
                    except Exception as _abge:
                        monitor.log(f"[ABGroup] Alert error: {_abge}")

            except Exception as e:
                try:
                    monitor.log(f"[Chain] Monitor loop error: {e}")
                except Exception:
                    pass
            _warmed_up = True
            stop_evt.wait(10)   # state machine runs every 10 s; trend gate stays at 30 s

    def _do_chain_recovery(self, cid: str, result: dict, chain: dict, cfg, sender, now: float):
        """Execute recovery actions: log, clip scheduling, notifications.
        Called from _chains_monitor_loop when recovery is confirmed (immediately or
        after min_recovery_seconds has elapsed).
        """
        # Record recovery in fault log + DB
        flog = self._chain_fault_log.setdefault(cid, [])
        if flog and flog[-1].get("ts_recovered") is None:
            flog[-1]["ts_recovered"] = now
            metrics_db.fault_log_set_recovered(flog[-1].get("id", ""), now)
            tail_secs = float(chain.get("fault_tail_secs", 20.0))
            if chain.get("record_all_nodes", True) and tail_secs >= 0:
                flog[-1]["ts_recovered"] = now
                self._schedule_chain_recovery_clips(chain, flog[-1], cfg, tail_secs)
        # Record last recovery time (used for fast re-fault detection, Change 3)
        self._chain_last_recovery[cid] = now
        # Log confirmed ad-break durations for schedule learning
        _flog_now = self._chain_fault_log.get(cid, [])
        _ab_ts = _flog_now[-1].get("ts_start", 0.0) if _flog_now else 0.0
        if self._chain_fault_adbreak.get(cid) and _ab_ts > 0:
            _ab_dur = now - _ab_ts
            if 5.0 < _ab_dur < 600.0:   # sanity: 5 s - 10 min
                try:
                    metrics_db.adbreak_log(cid, _ab_ts, _ab_dur)
                    monitor.log(f"[Chain] Logged ad-break for '{cid}': {_ab_dur:.0f}s at minute {int(_ab_ts % 3600 // 60)}")
                except Exception:
                    pass
        # Clear adbreak-overshoot flag now that the chain is ok
        self._chain_fault_adbreak.pop(cid, None)
        # Reset degrading-alert fired flags for all nodes in this chain (Change 6)
        _chain_name_pfx = cid + ":"
        for _k in list(self._chain_degrading_fired.keys()):
            if _k.startswith(_chain_name_pfx):
                self._chain_degrading_fired.pop(_k, None)
        # Check if chain was in flapping state
        if self._chain_flapping.get(cid):
            self._chain_flapping.pop(cid, None)
            try:
                flap_msg = f"Chain '{result['name']}' flapping has resolved — chain is now stable."
                sender.send(f"CHAIN STABLE — {result['name']}", flap_msg,
                            alert_type="CHAIN_FLAPPING", stream=result["name"])
                monitor.log(f"[Chain] {flap_msg}")
            except Exception as _fe:
                monitor.log(f"[Chain] Flap-resolved notify error: {_fe}")
        else:
            # Normal recovery notification — apply cooldown check (Change 4)
            cooldown_mins = int(chain.get("min_alert_interval_minutes", 0) or 0)
            suppress_notify = False
            if cooldown_mins > 0:
                last_alert = self._chain_last_alert_ts.get(cid, 0)
                if now - last_alert < cooldown_mins * 60:
                    suppress_notify = True
                    monitor.log(f"[Chain] '{result['name']}' recovery notification suppressed (cooldown {cooldown_mins}m)")
            rec_msg = f"Chain '{result['name']}' has recovered — all positions OK."
            # Check cascade suppression (Change 7)
            upstream_id = chain.get("upstream_chain_id", "")
            cascade_suppressed = False
            if upstream_id:
                upstream_state = self._chain_fault_state.get(upstream_id, "ok")
                if upstream_state in ("alerted", "pending_recovery"):
                    cascade_suppressed = True
                    up_name = next((c.get("name","?") for c in (monitor.app_cfg.signal_chains or [])
                                    if c.get("id") == upstream_id), upstream_id)
                    monitor.log(f"[Chain] '{result['name']}' recovery notification suppressed — cascaded from '{up_name}'")
            for node in result.get("nodes", []):
                local_nodes = (node.get("nodes", []) if node.get("type") == "stack" else [node])
                for n in local_nodes:
                    if n.get("site") == "local":
                        rc_cfg = next((i for i in cfg.inputs
                                       if i.name == n.get("stream", "") and i.enabled), None)
                        if rc_cfg:
                            _add_history(rc_cfg, "CHAIN_FAULT", rec_msg)
            _alert_log_append({
                "id":            str(uuid.uuid4()),
                "ts":            time.strftime("%Y-%m-%d %H:%M:%S"),
                "stream":        result["name"],
                "type":          "CHAIN_RECOVERED",
                "message":       rec_msg,
                "level_dbfs":    None,
                "rtp_loss_pct":  None,
                "rtp_jitter_ms": None,
                "clip":          "",
                "ptp_state":     "",
                "ptp_offset_us": 0,
                "ptp_drift_us":  0,
                "ptp_jitter_us": 0,
                "ptp_gm":        "",
            })
            if not suppress_notify and not cascade_suppressed:
                self._chain_last_alert_ts[cid] = now
                try:
                    sender.send(f"CHAIN RECOVERED — {result['name']}", rec_msg,
                                alert_type="CHAIN_RECOVERED", stream=result["name"])
                    monitor.log(f"[Chain] {rec_msg}")
                except Exception as e:
                    monitor.log(f"[Chain] Recovery notification error: {e}")
                _send_apns_push(
                    title=f"✅ Recovered: {result['name']}",
                    body=rec_msg[:180],
                    data={"chain_id": cid, "event": "recovered"},
                )
        self._chain_fault_state[cid] = "ok"

    def _schedule_chain_recovery_clips(self, chain: dict, fault_entry: dict,
                                        cfg, tail_secs: float = 20.0):
        """After `tail_secs` seconds post-recovery, save a clip from every chain node
        capturing the full fault event (fault_duration + tail) up to CHAIN_CLIP_MAX_SECS."""
        def _do():
            time.sleep(tail_secs)
            ts_start    = float(fault_entry.get("ts_start") or time.time())
            ts_recovered = float(fault_entry.get("ts_recovered") or time.time())
            fault_dur   = max(0.0, ts_recovered - ts_start)
            _chain_clip_min = float(chain.get("clip_seconds") or CHAIN_CLIP_MIN_SECS)
            _chain_clip_min = max(CHAIN_CLIP_MIN_SECS, min(_chain_clip_min, CHAIN_CLIP_MAX_SECS))
            clip_dur    = min(fault_dur + tail_secs + 10.0, CHAIN_CLIP_MAX_SECS)
            clip_dur    = max(clip_dur, _chain_clip_min)
            nodes       = chain.get("nodes", [])
            chain_label = chain.get("name", "")
            chain_id    = chain.get("id", "")
            entry_id    = fault_entry.get("id", "")
            cname_safe  = _safe_name(chain_label)
            new_clips   = []
            for _ci, _cnode in enumerate(nodes):
                _subs = _cnode.get("nodes", []) if _cnode.get("type") == "stack" else [_cnode]
                for _sn in _subs:
                    _site   = _sn.get("site", "")
                    _stream = _sn.get("stream", "")
                    _nlbl   = _sn.get("label", "") or f"pos{_ci+1}"
                    _clbl   = f"chain_{cname_safe}_recovery_pos{_ci}"
                    if not _site or _site == "local":
                        _lc = next((i for i in cfg.inputs if i.name == _stream and i.enabled), None)
                        if _lc:
                            _ensure_alert_buffer_capacity(_lc, clip_dur)
                            _clip = _save_alert_wav(_lc, _clbl, clip_dur, _skip_hub_queue=True)
                            # Shrink buffer back to normal after saving
                            _ensure_alert_buffer_capacity(_lc, None)
                            if _clip:
                                new_clips.append({
                                    "key":        _safe_name(_stream),
                                    "fname":      os.path.basename(_clip),
                                    "label":      f"recovery_pos{_ci}",
                                    "node_label": _nlbl,
                                    "pos":        _ci,
                                    "status":     "recovery",
                                })
                    else:
                        self.push_pending_command(_site, {
                            "type": "save_clip",
                            "payload": {
                                "stream":     _stream,
                                "label":      _clbl,
                                "chain_name": chain_label,
                                "chain_id":   chain_id,
                                "entry_id":   entry_id,
                                "node_label": _nlbl,
                                "pos":        _ci,
                                "status":     "recovery",
                                "duration":   clip_dur,
                            },
                        })
            if new_clips:
                flog = self._chain_fault_log.get(chain_id, [])
                _target = next((e for e in reversed(flog) if e.get("id") == entry_id), None)
                if _target:
                    existing = _target.setdefault("clips", [])
                    existing.extend(new_clips)
                    metrics_db.fault_log_update_clips(entry_id, existing)
                    monitor.log(f"[Chain] Recovery clips saved for '{chain_label}' "
                                f"({len(new_clips)} local, {tail_secs}s post-recovery) "
                                f"fault_dur={fault_dur:.0f}s clip_dur={clip_dur:.0f}s")
        threading.Thread(target=_do, daemon=True, name="ChainRecoveryClip").start()

    def _fire_chain_flapping(self, result: dict, chain: dict, cfg, sender, now: float):
        """Fire CHAIN_FLAPPING alert when a chain is fault-cycling rapidly."""
        chain_label = result["name"]
        fn = result.get("fault_node") or {}
        fn_label = fn.get("label", "?")
        msg = (f"Chain '{chain_label}' is flapping — it has faulted and recovered "
               f"{CHAIN_FLAP_COUNT}+ times in {CHAIN_FLAP_WINDOW // 60} minutes. "
               f"Current fault point: '{fn_label}'. Individual CHAIN_FAULT/CHAIN_RECOVERED "
               f"alerts are suppressed until the chain stabilises.")
        try:
            sender.send(f"CHAIN FLAPPING — {chain_label}", msg,
                        alert_type="CHAIN_FLAPPING", stream=chain_label)
            monitor.log(f"[Chain] {msg}")
        except Exception as e:
            monitor.log(f"[Chain] Flap alert error: {e}")

    def _fire_chain_fault(self, result: dict, chain: dict, cfg, sender, now: float,
                          entry_id: str = ""):
        """Send CHAIN_FAULT alert, save audio clips, and log to alert history.

        Handles both regular nodes and stack nodes (type=='stack').  For stacks
        the alert message describes which sub-streams are down vs still OK so
        the engineer immediately knows the scope of the failure.
        """
        fn          = result["fault_node"] or {}
        idx         = result.get("fault_index", 0) or 0
        nodes       = result.get("nodes", [])
        total       = len(nodes)
        chain_label = result["name"]

        # ── Build downstream note ──────────────────────────────────────────────
        # Distinguish nodes that are still producing audio from those also down.
        def _node_label(n):
            return n.get("label") or n.get("stream") or "?"
        def _node_is_ok(n):
            st = n.get("status")
            if st == "down": return False
            if st == "offline" and not n.get("offline_grace_active", False): return False
            return True
        downstream_nodes = nodes[idx + 1:] if idx + 1 < total else []
        if downstream_nodes:
            still_up  = [n for n in downstream_nodes if _node_is_ok(n)]
            also_down = [n for n in downstream_nodes if not _node_is_ok(n)]
            if still_up and not also_down:
                up_names = ", ".join(_node_label(n) for n in still_up)
                ds_note = f" Audio still present downstream: {up_names}."
            elif still_up and also_down:
                up_names   = ", ".join(_node_label(n) for n in still_up)
                down_names = ", ".join(_node_label(n) for n in also_down)
                ds_note = f" Audio still present at {up_names}; {down_names} also affected."
            else:
                ds_note = f" {len(also_down)} downstream position(s) also affected."
        else:
            ds_note = ""

        # ── Build the fault description ────────────────────────────────────────
        if fn.get("type") == "stack":
            # Stack fault — describe each sub-node's individual state,
            # distinguishing between silent streams and offline sites.
            sub_nodes    = fn.get("nodes", [])
            mode         = fn.get("mode", "all")
            n_total      = len(sub_nodes)
            silent_subs  = [n for n in sub_nodes if n.get("status") == "down"]
            offline_subs = [n for n in sub_nodes if n.get("status") == "offline"]
            faulted_subs = silent_subs + offline_subs
            ok_subs      = [n for n in sub_nodes if n.get("status") not in ("down", "offline")]
            n_down       = len(faulted_subs)
            pos_label    = fn.get("label") or f"position {idx + 1}"

            ok_names = ", ".join(n.get("label") or n.get("stream") or "?" for n in ok_subs)

            if n_down == n_total:
                # Every stream at this position is faulted
                if offline_subs and not silent_subs:
                    # All offline — site(s) not reporting
                    off_names = ", ".join(n.get("label") or n.get("stream") or "?" for n in offline_subs)
                    detail = (f"all {n_total} node(s) at '{pos_label}' are offline "
                              f"({off_names})")
                elif offline_subs and silent_subs:
                    # Mixed — some offline, some silent
                    off_names = ", ".join(n.get("label") or n.get("stream") or "?" for n in offline_subs)
                    sil_names = ", ".join(n.get("label") or n.get("stream") or "?" for n in silent_subs)
                    detail = (f"all {n_total} stream(s) at '{pos_label}' are faulted "
                              f"({off_names} offline; {sil_names} silent)")
                else:
                    # All silent
                    sil_names = ", ".join(n.get("label") or n.get("stream") or "?" for n in silent_subs)
                    detail = (f"all {n_total} stream(s) at '{pos_label}' are silent "
                              f"({sil_names})")
            else:
                # Partial failure — some streams still OK
                parts = []
                if offline_subs:
                    off_names = ", ".join(n.get("label") or n.get("stream") or "?" for n in offline_subs)
                    parts.append(f"{off_names} offline")
                if silent_subs:
                    sil_names = ", ".join(n.get("label") or n.get("stream") or "?" for n in silent_subs)
                    parts.append(f"{sil_names} silent")
                faulted_desc = "; ".join(parts)
                detail = (f"{n_down} of {n_total} stream(s) at '{pos_label}' "
                          f"{'is' if n_down == 1 else 'are'} faulted "
                          f"({faulted_desc}; {ok_names} OK)")
                if mode == "any":
                    detail += " — stack mode is ANY, so this triggers a fault"

            msg = (f"Chain fault in '{chain_label}' — {detail}. "
                   f"This is the first failed position in the chain.{ds_note}")
        else:
            # Regular single node — distinguish offline site from audio silence
            node_status = fn.get("status", "down")
            if node_status == "offline":
                offline_age = fn.get("offline_age_s")
                age_note = f", last seen {round(offline_age)}s ago" if offline_age else ""
                msg = (f"Chain fault in '{chain_label}' — node offline: "
                       f"'{fn.get('label', '?')}' (site: {fn.get('site', '?')}, "
                       f"stream: {fn.get('stream', '?')}) is not reporting{age_note}. "
                       f"This is the first failed point in the chain.{ds_note}")
            else:
                msg = (f"Chain fault in '{chain_label}' — signal lost at "
                       f"'{fn.get('label', '?')}' (site: {fn.get('site', '?')}, "
                       f"stream: {fn.get('stream', '?')}). "
                       f"This is the first failed point in the chain.{ds_note}")

        # ── Save clips from every node in the chain ────────────────────────────
        # Walk all positions; for local nodes save directly and collect into
        # _entry_clips; for remote nodes push save_clip commands.  The fault
        # position's first clip is used as the notification attachment.
        fault_clip   = None   # first local clip from the fault position
        _entry_clips = []     # built inline — no filesystem search needed

        _cname_safe = _safe_name(chain_label)
        for _ci, _cnode in enumerate(nodes):
            # Determine label suffix and human-readable status for this position
            if _ci == idx:
                _pos_label  = "fault"
                _pos_status = "fault"
            elif _ci == idx - 1:
                _pos_label  = "last_good"
                _pos_status = "last_good"
            else:
                _pos_label  = f"pos{_ci}"
                _pos_status = (_cnode.get("status") or "ok").lower()

            _node_label = (_cnode.get("label") or f"position {_ci + 1}")

            # Walk sub-nodes for stacks, or treat the node itself as the only sub
            _subs = _cnode.get("nodes", []) if _cnode.get("type") == "stack" else [_cnode]
            for _sn in _subs:
                _site   = _sn.get("site", "")
                _stream = _sn.get("stream", "")
                _clbl   = f"chain_{_cname_safe}_{_pos_label}"

                if not _site or _site == "local":
                    # ── Local stream: save WAV and collect the clip path ───
                    _lc = next(
                        (i for i in cfg.inputs if i.name == _stream and i.enabled),
                        None,
                    )
                    if _lc:
                        # Expand buffer NOW so we accumulate full fault audio
                        # from this point; recovery clip will cover the whole event.
                        _ensure_alert_buffer_capacity(_lc, CHAIN_CLIP_MAX_SECS)
                        # Onset clip: use chain-configured duration (default CHAIN_CLIP_MIN_SECS).
                        # Captured at fault time; recovery clip covers the full event.
                        _onset_dur = float(chain.get("clip_seconds") or CHAIN_CLIP_MIN_SECS)
                        _onset_dur = max(CHAIN_CLIP_MIN_SECS, min(_onset_dur, CHAIN_CLIP_MAX_SECS))
                        _clip = _save_alert_wav(_lc, _clbl, _onset_dur, _skip_hub_queue=True)
                        _lc_msg = (
                            f"Chain '{chain_label}' — '{_node_label}' "
                            f"({_pos_label.replace('_', ' ')}) clip."
                        )
                        _add_history(_lc, "CHAIN_FAULT", _lc_msg, clip_path=_clip or "")
                        if _clip:
                            if _ci == idx and fault_clip is None:
                                fault_clip = _clip  # attach to notification
                            _entry_clips.append({
                                "key":        _safe_name(_stream),
                                "fname":      os.path.basename(_clip),
                                "label":      _pos_label,
                                "node_label": _node_label,
                                "pos":        _ci,
                                "status":     _pos_status,
                            })
                else:
                    # ── Remote stream: ask the client to save and upload ───
                    _rem_dur = float(chain.get("clip_seconds") or CHAIN_CLIP_MIN_SECS)
                    _rem_dur = max(CHAIN_CLIP_MIN_SECS, min(_rem_dur, CHAIN_CLIP_MAX_SECS))
                    self.push_pending_command(_site, {
                        "type": "save_clip",
                        "payload": {
                            "stream":     _stream,
                            "label":      _clbl,
                            "chain_name": chain_label,
                            "chain_id":   chain.get("id", ""),
                            "entry_id":   entry_id,   # so the hub back-patch targets the right entry
                            "node_label": _node_label,
                            "pos":        _ci,
                            "status":     _pos_status,
                            "duration":   _rem_dur,
                        },
                    })

        # ── Back-patch local clips into the fault log entry + DB ─────────────
        # Use the known entry_id to find the exact entry rather than [-1],
        # which can be wrong if the chain recovered and re-faulted.
        cid = chain.get("id", "")
        _flog = self._chain_fault_log.get(cid, [])
        if _flog and _entry_clips:
            _target = (next((e for e in reversed(_flog) if e.get("id") == entry_id), None)
                       if entry_id else _flog[-1])
            if _target:
                existing = _target.setdefault("clips", [])
                existing.extend(_entry_clips)
                metrics_db.fault_log_update_clips(_target.get("id", ""), existing)

        # ── Check for shared fault across other chains (machine tag only) ─────
        # Only nodes with an explicit machine tag participate in cross-chain
        # shared-fault detection.  Site name is no longer used as a fallback.
        fault_machine = (fn.get("machine") or "").strip()
        _use_shared_aggregation = False
        if fault_machine:
            shared_names = []
            for _oc in (monitor.app_cfg.signal_chains or []):
                if _oc.get("id") == chain.get("id"):
                    continue
                for _on in _oc.get("nodes", []):
                    subs = _on.get("nodes", []) if _on.get("type") == "stack" else [_on]
                    if any((s.get("machine") or "").strip() == fault_machine for s in subs):
                        shared_names.append(_oc.get("name", "?"))
                        break
            if shared_names:
                msg += (f" NOTE: other chains share hardware '{fault_machine}': "
                        f"{', '.join(shared_names)} — those chains may also be affected.")
                _use_shared_aggregation = True

        # ── Check cascade suppression (Change 7) ─────────────────────────────
        cid = chain.get("id", "")
        upstream_id = chain.get("upstream_chain_id", "")
        cascade_suppressed = False
        _cascaded_from_name = ""
        if upstream_id:
            upstream_state = self._chain_fault_state.get(upstream_id, "ok")
            if upstream_state in ("alerted", "pending_recovery"):
                cascade_suppressed = True
                _cascaded_from_name = next((c.get("name","?") for c in (monitor.app_cfg.signal_chains or [])
                                if c.get("id") == upstream_id), upstream_id)
                monitor.log(f"[Chain] '{chain_label}' fault notification suppressed — cascaded from '{_cascaded_from_name}'")

        # ── Back-patch message + cascaded_from into the fault log entry + DB ──
        _flog2 = self._chain_fault_log.get(cid, [])
        _flog_target = (next((e for e in reversed(_flog2) if e.get("id") == entry_id), None)
                        if entry_id else (_flog2[-1] if _flog2 else None))
        if _flog_target:
            _flog_target["message"] = msg
            _flog_target["cascaded_from"] = _cascaded_from_name
            metrics_db.fault_log_update_meta(
                _flog_target.get("id", ""), msg, _cascaded_from_name,
                bool(_flog_target.get("adbreak_overshoot", False))
            )

        # ── Check per-chain notification cooldown (Change 4) ─────────────────
        cooldown_mins = int(chain.get("min_alert_interval_minutes", 0) or 0)
        suppress_notify = False
        if cooldown_mins > 0 and not cascade_suppressed:
            last_alert = self._chain_last_alert_ts.get(cid, 0)
            if now - last_alert < cooldown_mins * 60:
                suppress_notify = True
                monitor.log(f"[Chain] '{chain_label}' alert suppressed (cooldown {cooldown_mins}m)")

        # ── Write to alert log (always — even for hub-only chains with no local nodes) ──
        _alert_log_append({
            "id":            str(uuid.uuid4()),
            "ts":            time.strftime("%Y-%m-%d %H:%M:%S"),
            "stream":        chain_label,
            "type":          "CHAIN_FAULT",
            "message":       msg,
            "level_dbfs":    fn.get("level"),
            "rtp_loss_pct":  fn.get("rtp_loss_pct"),
            "rtp_jitter_ms": None,
            "clip":          os.path.basename(fault_clip) if fault_clip else "",
            "ptp_state":     "",
            "ptp_offset_us": 0,
            "ptp_drift_us":  0,
            "ptp_jitter_us": 0,
            "ptp_gm":        "",
        })

        # ── Send notification (skip if cascade-suppressed or cooldown active) ─
        if not cascade_suppressed and not suppress_notify:
            if _use_shared_aggregation:
                # Shared-fault aggregation (Change 5): defer notification via timer
                pending = self._chain_shared_fault_pending.get(fault_machine)
                chain_info = {
                    "cid": cid, "name": chain_label, "msg": msg,
                    "fault_clip": fault_clip,
                    "cooldown_mins": int(chain.get("min_alert_interval_minutes", 0) or 0),
                }
                if pending is None:
                    # Start new aggregation window
                    self._chain_shared_fault_pending[fault_machine] = {
                        "chains": [chain_info],
                        "ts":     now,
                    }
                    _t = threading.Timer(CHAIN_SHARED_FAULT_WINDOW,
                                         self._flush_shared_fault, args=[fault_machine])
                    _t.daemon = True
                    self._chain_shared_fault_pending[fault_machine]["timer"] = _t
                    _t.start()
                    monitor.log(f"[Chain] '{chain_label}' shared-fault window started for machine '{fault_machine}'")
                else:
                    # Add to existing aggregation; cancel and restart timer
                    pending["chains"].append(chain_info)
                    old_timer = pending.get("timer")
                    if old_timer:
                        old_timer.cancel()
                    _t = threading.Timer(CHAIN_SHARED_FAULT_WINDOW,
                                         self._flush_shared_fault, args=[fault_machine])
                    _t.daemon = True
                    pending["timer"] = _t
                    _t.start()
                    monitor.log(f"[Chain] '{chain_label}' added to shared-fault window for machine '{fault_machine}' ({len(pending['chains'])} chains)")
            else:
                self._chain_last_alert_ts[cid] = now
                try:
                    sender.send(f"CHAIN FAULT — {chain_label}", msg, fault_clip,
                                alert_type="CHAIN_FAULT", stream=chain_label)
                    monitor.log(f"[Chain] {msg}")
                except Exception as e:
                    monitor.log(f"[Chain] Alert send error: {e}")

                # ── Push notification (server relay or direct APNs/FCM) ───────────
                try:
                    _dispatch_push(
                        title=f"Fault: {chain_label}",
                        body=msg[:180],
                        data={"type": "chain_fault", "chain_id": cid},
                    )
                except Exception as e:
                    monitor.log(f"[Push] Push error in _fire_chain_fault: {e}")
        else:
            monitor.log(f"[Chain] Fault logged (no notification): {msg}")

    def _flush_shared_fault(self, machine_tag: str):
        """Called by timer after CHAIN_SHARED_FAULT_WINDOW seconds.
        If multiple chains faulted together, send one grouped notification.
        If only one chain faulted, send its individual notification.
        """
        try:
            pending = self._chain_shared_fault_pending.pop(machine_tag, None)
            if not pending:
                return
            chains_info = pending.get("chains", [])
            cfg = monitor.app_cfg
            sender = AlertSender(cfg, monitor.log)
            now = time.time()
            if len(chains_info) == 1:
                # Only one chain — send normal individual notification
                info = chains_info[0]
                chain_label = info.get("name", "?")
                msg = info.get("msg", "")
                cid = info.get("cid", "")
                fault_clip = info.get("fault_clip")
                cooldown_mins = int(info.get("cooldown_mins", 0) or 0)
                suppress_notify = False
                if cooldown_mins > 0:
                    last_alert = self._chain_last_alert_ts.get(cid, 0)
                    if now - last_alert < cooldown_mins * 60:
                        suppress_notify = True
                if not suppress_notify:
                    self._chain_last_alert_ts[cid] = now
                    try:
                        sender.send(f"CHAIN FAULT — {chain_label}", msg, fault_clip,
                                    alert_type="CHAIN_FAULT", stream=chain_label)
                        monitor.log(f"[Chain] {msg}")
                    except Exception as _e:
                        monitor.log(f"[Chain] Shared-fault single notify error: {_e}")
                    try:
                        _dispatch_push(title=f"Fault: {chain_label}", body=msg[:180],
                                       data={"type": "chain_fault", "chain_id": cid})
                    except Exception:
                        pass
            else:
                # Multiple chains — send grouped notification
                chain_names = ", ".join(c.get("name", "?") for c in chains_info)
                grouped_msg = (f"Shared fault on machine '{machine_tag}': "
                               f"{len(chains_info)} chains affected — {chain_names}")
                try:
                    sender.send(f"SHARED FAULT — {machine_tag}", grouped_msg,
                                alert_type="CHAIN_FAULT", stream=machine_tag)
                    monitor.log(f"[Chain] Shared fault grouped: {grouped_msg}")
                except Exception as _e:
                    monitor.log(f"[Chain] Shared-fault grouped notify error: {_e}")
                _alert_log_append({
                    "id":            str(uuid.uuid4()),
                    "ts":            time.strftime("%Y-%m-%d %H:%M:%S"),
                    "stream":        f"[Shared] {machine_tag}",
                    "type":          "CHAIN_FAULT",
                    "message":       grouped_msg,
                    "level_dbfs":    None,
                    "rtp_loss_pct":  None,
                    "rtp_jitter_ms": None,
                    "clip":          "",
                    "ptp_state":     "",
                    "ptp_offset_us": 0,
                    "ptp_drift_us":  0,
                    "ptp_jitter_us": 0,
                    "ptp_gm":        "",
                })
                try:
                    _dispatch_push(title=f"Shared Fault: {machine_tag}", body=grouped_msg[:180],
                                   data={"type": "chain_fault", "machine": machine_tag})
                except Exception:
                    pass
                for info in chains_info:
                    self._chain_last_alert_ts[info.get("cid", "")] = now
        except Exception as _fe:
            try:
                monitor.log(f"[Chain] _flush_shared_fault error: {_fe}")
            except Exception:
                pass

    def _check_watched_nodes(self, cid: str, result: dict, now: float):
        """Fire targeted APNs push for nodes that have just gone down (fault→ok
        transition reversed: ok→fault) for any device that has subscribed to
        that node label via ``watched_nodes``.

        Called every monitor loop iteration after ``eval_chain``.
        """
        try:
            nodes = result.get("nodes") or []
            chain_name = result.get("name", cid)

            # Flatten stack nodes to leaf sub-nodes for comparison
            def _iter_nodes(nodes_list):
                for n in nodes_list:
                    if n.get("type") == "stack":
                        for sn in n.get("nodes", []):
                            yield sn
                    else:
                        yield n

            ma = getattr(monitor.app_cfg, "mobile_api", None)
            if not ma:
                return
            with _apns_tokens_lock:
                all_entries = list(getattr(ma, "apns_device_tokens", []))

            for node in _iter_nodes(nodes):
                label  = (node.get("label") or "").strip()
                status = (node.get("status") or "ok").lower()
                if not label:
                    continue
                key = f"{cid}/{label}"
                prev = self._node_prev_state.get(key, "ok")
                self._node_prev_state[key] = status

                # Only fire on a fresh down-transition
                if prev == "ok" and status == "fault":
                    level   = node.get("level")
                    site    = (node.get("site") or "").strip()
                    level_str = f"{level:.0f} dBFS" if isinstance(level, (int, float)) else "below threshold"
                    site_str  = f" · {site}" if site else ""
                    title = f"Silence detected: {label}"
                    body  = f"{chain_name}{site_str} — {level_str}"

                    # Find all device token entries that are watching this node label
                    targeted = [e for e in all_entries
                                if label in (e.get("watched_nodes") or [])
                                if isinstance(e, dict)]

                    # FCM — find Android tokens watching this node
                    with _fcm_tokens_lock:
                        fcm_all = list(getattr(ma, "fcm_device_tokens", []))
                    fcm_targeted = [e for e in fcm_all
                                    if label in (e.get("watched_nodes") or [])
                                    if isinstance(e, dict)]

                    if targeted or fcm_targeted:
                        monitor.log(f"[Push] Node down '{label}' — "
                                    f"pushing to {len(targeted)} iOS / {len(fcm_targeted)} Android device(s)")
                        _dispatch_push(
                            title, body,
                            data={"type": "silence", "node": label},
                            ios_entries=targeted,
                            android_entries=fcm_targeted,
                        )
        except Exception as e:
            monitor.log(f"[APNs/FCM] _check_watched_nodes error: {e}")

    # ── Query ─────────────────────────────────────────────────────────────────
    def get_sites(self) -> List[dict]:
        now = time.time()
        with self._lock:
            result = []
            for name, data in self._sites.items():
                age    = now - data.get("_received", 0)
                _timeout = 90 if data.get("low_bw") else HUB_SITE_TIMEOUT
                online = age < _timeout
                # Health score: % of expected heartbeats received
                total_rx  = data.get("_total_received", 0)
                total_miss= data.get("_total_missed", 0)
                health    = round(total_rx / max(total_rx + total_miss, 1) * 100, 1)
                tx_ts = float(data.get("ts", 0) or 0)
                latency_ms = round(max(0.0, (data.get("_received", now) - tx_ts) * 1000), 1) if tx_ts else None
                result.append({**data, "online": online, "age_s": round(age, 1),
                                "health_pct": health,
                                "latency_ms": latency_ms,
                                "consecutive_missed": data.get("_consecutive_missed", 0)})
            return sorted(result, key=lambda x: x["site"])

    def get_site(self, name: str) -> Optional[dict]:
        now = time.time()
        with self._lock:
            data = self._sites.get(name)
            if data is None:
                return None
            age       = now - data.get("_received", 0)
            online    = age < HUB_SITE_TIMEOUT
            total_rx  = data.get("_total_received", 0)
            total_miss= data.get("_total_missed", 0)
            health    = round(total_rx / max(total_rx + total_miss, 1) * 100, 1)
            tx_ts     = float(data.get("ts", 0) or 0)
            latency_ms= round(max(0.0, (data.get("_received", now) - tx_ts) * 1000), 1) if tx_ts else None
            return {**data, "online": online, "age_s": round(age, 1),
                    "health_pct": health, "latency_ms": latency_ms,
                    "consecutive_missed": data.get("_consecutive_missed", 0)}


hub_server = HubServer()


# ─── Reverse audio relay — allows hub to request audio from NAT'd clients ─────

class ListenSlot:
    """
    Represents one browser listener waiting for audio from a remote client.
    The hub creates a slot when a browser hits a /hub/site/... audio route.
    The slot ID is sent to the client in the next heartbeat ACK.
    The client pushes bytes to /api/v1/audio_chunk/<slot_id>.
    The hub streams those bytes back to the browser.
    """
    SLOT_TIMEOUT = 30.0   # drop slot if no chunks arrive within this many seconds

    def __init__(self, slot_id: str, site: str, stream_idx: int,
                 kind: str = "live", seconds: float = 10.0,
                 stream_name: str = "", filename: str = "",
                 mimetype: str = "audio/mpeg",
                 freq_mhz: float = 0.0, sdr_serial: str = "",
                 ppm: int = 0, gain: "float | None" = None,
                 bitrate: str = "128k"):
        self.slot_id     = slot_id
        self.site        = site
        self.stream_idx  = stream_idx
        self.kind        = kind
        self.seconds     = float(seconds or 10.0)
        self.stream_name = stream_name or ""
        self.filename    = filename or ""
        self.mimetype    = mimetype or "application/octet-stream"
        self.created     = time.time()
        self.last_chunk  = time.time()
        self.q: queue.Queue = queue.Queue(maxsize=200)
        self.closed      = False
        self.rtt_ema: float = 0.0   # EMA of client POST RTT (s); 0 = unknown
        # Scanner-specific fields (kind == "scanner")
        self.freq_mhz   = float(freq_mhz or 0.0)
        self.sdr_serial = str(sdr_serial or "")
        self.ppm        = int(ppm or 0)
        self.gain       = gain  # None → auto
        self.bitrate    = str(bitrate or "128k")  # ffmpeg -b:a value, e.g. "64k","128k","192k"

    def put(self, data: bytes):
        self.last_chunk = time.time()
        try:
            self.q.put_nowait(data)
        except queue.Full:
            # Drop oldest chunk to make room
            try: self.q.get_nowait()
            except queue.Empty: pass
            try: self.q.put_nowait(data)
            except queue.Full: pass

    def get(self, timeout=5.0):
        return self.q.get(timeout=timeout)

    @property
    def stale(self):
        return time.time() - self.last_chunk > self.SLOT_TIMEOUT


class ListenSlotRegistry:
    """Thread-safe registry of active listen slots."""

    def __init__(self):
        self._slots: Dict[str, ListenSlot] = {}
        self._lock  = threading.Lock()
        # Start background reaper
        threading.Thread(target=self._reap, daemon=True, name="SlotReaper").start()

    def create(self, site: str, stream_idx: int, kind: str = "live",
               seconds: float = 10.0, stream_name: str = "",
               filename: str = "", mimetype: str = "audio/mpeg",
               freq_mhz: float = 0.0, sdr_serial: str = "",
               ppm: int = 0, gain: "float | None" = None,
               bitrate: str = "128k") -> ListenSlot:
        slot_id = hashlib.md5(f"{site}{stream_idx}{kind}{filename}{freq_mhz}{time.time()}".encode()).hexdigest()[:12]
        slot = ListenSlot(slot_id, site, stream_idx, kind=kind, seconds=seconds,
                          stream_name=stream_name, filename=filename, mimetype=mimetype,
                          freq_mhz=freq_mhz, sdr_serial=sdr_serial, ppm=ppm, gain=gain,
                          bitrate=bitrate)
        with self._lock:
            self._slots[slot_id] = slot
        return slot

    def get(self, slot_id: str) -> Optional[ListenSlot]:
        with self._lock:
            return self._slots.get(slot_id)

    def remove(self, slot_id: str):
        with self._lock:
            self._slots.pop(slot_id, None)

    def pending_for_site(self, site: str) -> List[dict]:
        """Return pending listen requests for a site awaiting a client push."""
        out = []
        with self._lock:
            for s in self._slots.values():
                if s.site != site or s.closed or s.stale:
                    continue
                d: dict = {
                    "slot_id":    s.slot_id,
                    "stream_idx": s.stream_idx,
                    "kind":       s.kind,
                    "seconds":    s.seconds,
                    "stream_name": s.stream_name,
                    "filename":   s.filename,
                    "mimetype":   s.mimetype,
                }
                if s.kind == "scanner":
                    d["freq_mhz"]   = s.freq_mhz
                    d["sdr_serial"] = s.sdr_serial
                    d["ppm"]        = s.ppm
                    d["bitrate"]    = s.bitrate
                    if s.gain is not None:
                        d["gain"] = s.gain
                out.append(d)
        return out

    def _reap(self):
        while True:
            time.sleep(10)
            with self._lock:
                stale = [sid for sid, s in self._slots.items() if s.stale or s.closed]
                for sid in stale:
                    self._slots.pop(sid, None)
            if stale:
                print(f"[SlotReaper] Reaped {len(stale)} stale slot(s)")


listen_registry = ListenSlotRegistry()

