# ─── Plugin registry ──────────────────────────────────────────────────────────
# Populated at startup by _load_plugins().  Each entry is a dict with at least:
#   id      – unique slug used as the nav active-page key
#   label   – text shown in the nav bar
#   url     – href for the nav link
#   icon    – (optional) emoji / short prefix  e.g. "📡"
_plugins: list[dict] = []
_PLUGINS_SUBDIR = "plugins"  # plugin files live here, relative to the app directory


def _load_plugins():
    """Discover, migrate, and load all plugins from the plugins/ subdirectory.

    Plugin files live in the ``plugins/`` subdirectory alongside signalscope.py:

        plugins/
            sdr.py
            logger.py
            icecast.py
            ...

    A plugin just needs two things:

        SIGNALSCOPE_PLUGIN = {
            "id":    "websdr",       # unique slug
            "label": "Web SDR",      # nav label
            "url":   "/hub/sdr",     # nav href
            "icon":  "📡",           # optional
        }

        def register(app, ctx):
            # ctx keys: app, monitor, hub_server, listen_registry,
            #           login_required, csrf_protect, BUILD
            @app.route("/hub/sdr")
            @ctx["login_required"]
            def sdr_page():
                return "<h1>Web SDR</h1>"

    **Migration from older versions**: If any plugin .py files are found in the
    app root directory on startup, they are automatically moved to plugins/ so
    that upgrading from a version that stored plugins in the root is seamless.
    Associated config files (e.g. icecast_config.json for icecast.py) are moved
    at the same time.
    """
    import importlib.util, pathlib, shutil as _shutil

    app_dir     = pathlib.Path(__file__).parent
    plugins_dir = app_dir / _PLUGINS_SUBDIR
    self_name   = pathlib.Path(__file__).name

    plugins_dir.mkdir(exist_ok=True)

    # ── Auto-migrate root-level plugin files to plugins/ ─────────────────────
    # This runs once after upgrading from an older SignalScope that kept plugins
    # alongside signalscope.py.  Safe to run on every startup — no-ops once done.
    migrated: list[str] = []
    for py in sorted(app_dir.glob("*.py")):
        if py.name == self_name:
            continue
        try:
            src = py.read_text(encoding="utf-8", errors="ignore")
        except OSError:
            continue
        if "SIGNALSCOPE_PLUGIN" not in src:
            continue
        dest_py = plugins_dir / py.name
        try:
            if dest_py.exists():
                # Already in plugins/ — remove the stale root copy
                py.unlink()
                migrated.append(f"{py.name} (root copy removed)")
            else:
                _shutil.move(str(py), str(dest_py))
                migrated.append(py.name)
            # Also migrate any associated config/data files ({stem}*.json)
            for cfg in sorted(app_dir.glob(f"{py.stem}*.json")):
                dest_cfg = plugins_dir / cfg.name
                if not dest_cfg.exists():
                    _shutil.move(str(cfg), str(dest_cfg))
        except Exception as exc:
            monitor.log(f"[Plugin] Migration failed for {py.name}: {exc}")
            print(f"[Plugin] WARNING: migration failed for {py.name}: {exc}")
    if migrated:
        monitor.log(f"[Plugin] Migrated to {_PLUGINS_SUBDIR}/: {', '.join(migrated)}")
        print(f"[Plugin] Migrated to {_PLUGINS_SUBDIR}/: {', '.join(migrated)}")

    # ── Load plugins from plugins/ ────────────────────────────────────────────
    ctx = {
        "app":                  app,
        "monitor":              monitor,
        "hub_server":           hub_server,
        "listen_registry":      listen_registry,
        "login_required":       login_required,
        "csrf_protect":         csrf_protect,
        "mobile_api_required":  mobile_api_required,
        "BUILD":                BUILD,
    }
    for py in sorted(plugins_dir.glob("*.py")):
        # Pre-flight: only import files that declare the plugin marker
        try:
            src = py.read_text(encoding="utf-8", errors="ignore")
        except OSError:
            continue
        if "SIGNALSCOPE_PLUGIN" not in src:
            continue
        try:
            spec = importlib.util.spec_from_file_location(py.stem, py)
            mod  = importlib.util.module_from_spec(spec)
            spec.loader.exec_module(mod)                          # type: ignore[union-attr]
            info = getattr(mod, "SIGNALSCOPE_PLUGIN", None)
            if not isinstance(info, dict) or not info.get("label") or not info.get("url"):
                monitor.log(f"[Plugin] {py.name}: SIGNALSCOPE_PLUGIN missing 'label'/'url' — skipped")
                continue
            info = dict(info)                    # don't mutate the module's dict
            info.setdefault("id",   py.stem)
            info.setdefault("icon", "")
            info["_src"] = py.name              # source filename — used by _scan_installed_plugins
            if hasattr(mod, "register"):
                mod.register(app, ctx)
            _plugins.append(info)
            monitor.log(f"[Plugin] Loaded '{info['label']}' from {_PLUGINS_SUBDIR}/{py.name}")
            print(f"[Plugin] {info['label']} loaded from {_PLUGINS_SUBDIR}/{py.name}")
        except Exception as e:
            monitor.log(f"[Plugin] Failed to load {py.name}: {e}")
            print(f"[Plugin] WARNING: failed to load {py.name}: {e}")

# ─── Plugin management helpers ────────────────────────────────────────────────

_PLUGIN_REGISTRY_URL = (
    "https://raw.githubusercontent.com/itconor/SignalScope/main/plugins.json"
)
_PLUGIN_ALLOWED_BASE = "https://raw.githubusercontent.com/itconor/SignalScope/"


def _scan_installed_plugins() -> list:
    """Return a list of dicts for every *.py plugin file found in plugins/.
    Each dict has at least: file, id, active, name, icon, description.
    'active' is True if the plugin was successfully loaded this session.
    """
    import pathlib
    plugins_dir = pathlib.Path(__file__).parent / _PLUGINS_SUBDIR
    result      = []
    if not plugins_dir.is_dir():
        return result
    for py in sorted(plugins_dir.glob("*.py")):
        try:
            src = py.read_text(encoding="utf-8", errors="ignore")
        except OSError:
            continue
        if "SIGNALSCOPE_PLUGIN" not in src:
            continue
        # Match by source filename (_src key set at load time) so that
        # plugins whose SIGNALSCOPE_PLUGIN id differs from their filename
        # (e.g. sdr.py with id="websdr") are still recognised as active.
        active = next((p for p in _plugins if p.get("_src") == py.name), None)
        info: dict = dict(active) if active else {"id": py.stem}
        info["file"]   = py.name
        info["active"] = active is not None
        info.setdefault("name",        py.stem)
        info.setdefault("icon",        "🔌")
        info.setdefault("description", "")
        # Extract version from file source for inactive (not-yet-loaded) plugins
        # so the panel can compare installed vs registry version correctly.
        if not active:
            import re as _re
            _m = _re.search(r'"version"\s*:\s*"([^"]+)"', src)
            if _m:
                info["version"] = _m.group(1)
        result.append(info)
    return result

# ─── Login brute-force protection ─────────────────────────────────────────────

class LoginLimiter:
    """Tracks failed login attempts per IP with lockout."""
    def __init__(self):
        self._attempts: Dict[str, list]  = {}  # ip → [timestamps]
        self._locked:   Dict[str, float] = {}  # ip → locked_until_ts
        self._lock = threading.Lock()

    def record_failure(self, ip: str, max_attempts: int, lockout_mins: int):
        now = time.time()
        with self._lock:
            hits = [t for t in self._attempts.get(ip,[]) if now - t < 3600]
            hits.append(now)
            self._attempts[ip] = hits
            if len(hits) >= max_attempts:
                self._locked[ip] = now + lockout_mins * 60
                _log_security(f"Login lockout: {ip} after {len(hits)} failures")

    def is_locked(self, ip: str) -> float:
        """Returns seconds remaining in lockout, or 0 if not locked."""
        now = time.time()
        with self._lock:
            until = self._locked.get(ip, 0)
            if until > now:
                return until - now
            if ip in self._locked:
                del self._locked[ip]
            return 0.0

    def clear(self, ip: str):
        with self._lock:
            self._attempts.pop(ip, None)
            self._locked.pop(ip, None)


login_limiter = LoginLimiter()
user_manager: "UserManager | None" = None


def _log_security(msg: str):
    print(f"[Security] {msg}", flush=True)


# ─── RBAC helpers ─────────────────────────────────────────────────────────────

def _current_user() -> "UserAccount | None":
    """Return the UserAccount for the currently logged-in user."""
    from flask import session
    uname = session.get("username", "")
    if not uname or not user_manager:
        return None
    return user_manager.get(uname)

def _current_user_role() -> str:
    from flask import session
    return session.get("role", "admin")

def _is_admin() -> bool:
    return _current_user_role() == "admin"

def _is_viewer() -> bool:
    return _current_user_role() == "viewer"

def _allowed_sites() -> list:
    """Returns the site whitelist for the current user. Empty list = all sites."""
    from flask import session
    return session.get("allowed_sites", [])

def _allowed_plugins() -> list:
    """Returns the plugin whitelist for the current user. Empty list = all plugins."""
    from flask import session
    return session.get("allowed_plugins", [])

def _site_permitted(site_name: str) -> bool:
    allowed = _allowed_sites()
    return not allowed or site_name in allowed

def _plugin_permitted(plugin_id: str) -> bool:
    allowed = _allowed_plugins()
    return not allowed or plugin_id in allowed

def _filter_sites(sites: list) -> list:
    """Filter a list of site dicts by the current user's site whitelist."""
    allowed = _allowed_sites()
    if not allowed:
        return sites
    return [s for s in sites if s.get("site", "") in allowed]


# ─── SDR Device Registry ──────────────────────────────────────────────────────



class SdrDeviceManager:
    """
    Manages exclusive access to RTL-SDR dongles by serial number.
    Serial numbers are stable across USB reconnects; device indices are not.

    Usage:
        with sdr_manager.claim(serial) as idx:
            # idx is the current device index for this serial
            subprocess.run(["rtl_fm", "-d", str(idx), ...])
        # device released automatically on exit

    If the dongle is already claimed, claim() raises SdrBusyError.
    If the serial is not found in connected hardware, raises SdrNotFoundError.
    """

    def __init__(self):
        self._lock      = threading.Lock()
        self._scan_lock = threading.Lock()      # serialises rtl_test calls — only one at a time
        self._owners: Dict[str, str] = {}       # serial → owner label  (FM/scanner exclusive claims)
        self._dab_owners: Dict[int, str] = {}   # device index → owner label (DAB session claims)
        self._index_cache: Dict[str, int] = {}  # serial → last known index
        self._cache_ts: float = 0.0

    # ── Hardware scanning ──────────────────────────────────────────────────────

    def scan(self, force: bool = False) -> List[Dict]:
        """
        Scan for connected RTL-SDR dongles.
        Returns list of dicts: {index, serial, name, manufacturer}
        Results are cached for 10 seconds unless force=True.

        Uses plain "rtl_test" (no -t flag) so only device 0 is ever opened.
        The "Found N device(s):" list is printed to stderr before any device
        is opened, so partial output captured from TimeoutExpired is sufficient.
        """
        import subprocess as _sp
        now = time.time()
        if not force and hasattr(self, '_scan_cache') and now - self._cache_ts < 10:
            return self._scan_cache

        with self._scan_lock:
            now = time.time()
            if not force and hasattr(self, '_scan_cache') and now - self._cache_ts < 10:
                return self._scan_cache

            devices = []
            if not _find_binary("rtl_test") and not _find_binary("rtl_eeprom"):
                self._scan_cache = devices
                self._cache_ts   = now
                return devices

            tool = "rtl_test" if _find_binary("rtl_test") else "rtl_eeprom"
            cmd  = [tool] if tool == "rtl_test" else [tool]
            output = ""
            timed_out = False
            try:
                result = _sp.run(cmd, capture_output=True, text=True, timeout=2)
                output = result.stderr + result.stdout
            except _sp.TimeoutExpired as exc:
                timed_out = True
                out_b = exc.stdout or b""
                err_b = exc.stderr or b""
                output = (
                    (err_b if isinstance(err_b, str) else err_b.decode(errors="ignore")) +
                    (out_b if isinstance(out_b, str) else out_b.decode(errors="ignore"))
                )
            except Exception as e:
                print(f"[SdrMgr] Scan error: {e}")

            if timed_out:
                time.sleep(0.3)   # let device 0 fully release before callers open it

            import re as _re
            for m in _re.finditer(
                    r'(\d+):\s+([^,]+),\s+([^,]+),\s+SN:\s*(\S*)', output):
                idx, mfr, name, serial = m.groups()
                serial = serial.strip() or f"unknown_{idx}"
                devices.append({
                    "index":        int(idx),
                    "serial":       serial,
                    "name":         name.strip(),
                    "manufacturer": mfr.strip(),
                })
                self._index_cache[serial] = int(idx)

            self._scan_cache = devices
            self._cache_ts   = now
            return devices

    def resolve_index(self, serial: str) -> int:
        """
        Return the current device index for a given serial number.
        Raises SdrNotFoundError if the dongle is not connected.
        """
        devices = self.scan()
        for d in devices:
            if d["serial"] == serial:
                return d["index"]
        # Try cache if scan gave nothing useful
        if serial in self._index_cache:
            raise SdrNotFoundError(
                f"Dongle '{serial}' was previously at index "
                f"{self._index_cache[serial]} but is not currently connected."
            )
        raise SdrNotFoundError(f"Dongle with serial '{serial}' not found.")

    # ── Exclusive access ───────────────────────────────────────────────────────

    def claim(self, serial: str, owner: str = "") -> "SdrLease":
        """
        Claim exclusive access to a dongle by serial number.
        Returns an SdrLease context manager that resolves the device index
        and releases the claim when exited.
        Raises SdrBusyError if the dongle is already in use.
        Raises SdrNotFoundError if the dongle is not connected.
        """
        with self._lock:
            existing = self._owners.get(serial)
            if existing:
                raise SdrBusyError(
                    f"Dongle '{serial}' is already in use by '{existing}'."
                )
            idx = self.resolve_index(serial)
            # Check whether a DAB session (welle-cli) is already holding this device
            existing_dab = self._dab_owners.get(idx)
            if existing_dab:
                raise SdrBusyError(
                    f"Dongle at index {idx} (serial '{serial}') is already in use by DAB stream "
                    f"'{existing_dab}'. Assign a dedicated dongle serial to each stream."
                )
            self._owners[serial] = owner or serial
        return SdrLease(self, serial, idx)

    def release(self, serial: str):
        """Release a previously claimed dongle."""
        with self._lock:
            self._owners.pop(serial, None)

    def claim_dab_device(self, idx: int, owner: str = "") -> None:
        """
        Register that a DAB (welle-cli) session is exclusively holding device index *idx*.
        Raises SdrBusyError if an FM stream already has that index claimed via claim().
        Safe to call again for the same index once already registered (idempotent update).
        """
        with self._lock:
            # Check if any FM stream already holds this index (via _index_cache populated by resolve_index)
            for serial, fm_owner in self._owners.items():
                if self._index_cache.get(serial) == idx:
                    raise SdrBusyError(
                        f"Device index {idx} (serial '{serial}') is already in use by FM stream "
                        f"'{fm_owner}'. Assign a dedicated dongle serial to each stream to avoid conflicts."
                    )
            self._dab_owners[idx] = owner or f"dab@{idx}"

    def release_dab_device(self, idx: int) -> None:
        """Release a DAB device claim by device index."""
        with self._lock:
            self._dab_owners.pop(idx, None)

    def status(self) -> Dict[str, str]:
        """Return dict of serial → current owner for all claimed dongles."""
        with self._lock:
            return dict(self._owners)

    def connected_serials(self) -> List[str]:
        """Return list of serials of currently connected dongles."""
        return [d["serial"] for d in self.scan()]

    def unregistered(self, registered_serials: List[str]) -> List[Dict]:
        """Return connected dongles whose serial is not in the registered list."""
        reg_set = set(registered_serials)
        return [d for d in self.scan() if d["serial"] not in reg_set]


class SdrLease:
    """Context manager returned by SdrDeviceManager.claim()."""
    def __init__(self, manager: SdrDeviceManager, serial: str, index: int):
        self._manager = manager
        self.serial   = serial
        self.index    = index

    def __enter__(self):
        return self.index

    def __exit__(self, *_):
        self._manager.release(self.serial)

    def __repr__(self):
        return f"SdrLease(serial={self.serial!r}, index={self.index})"


class RateLimitError(RuntimeError):
    """Raised when the hub returns HTTP 429 — client should back off."""


class SdrBusyError(RuntimeError):
    """Raised when a requested dongle is already claimed by another input."""

class SdrNotFoundError(RuntimeError):
    """Raised when a requested dongle serial is not found in connected hardware."""


# Global singleton
sdr_manager = SdrDeviceManager()


