def _set_csrf_cookie(response):
    """Set a JS-readable csrf_token cookie on every response so any page's JS
    can read it without needing a <meta> tag in the template."""
    try:
        token = session.get("_csrf", "")
        if token:
            response.set_cookie(
                "csrf_token", token,
                samesite="Strict",
                secure=request.is_secure,
                httponly=False,   # Must NOT be HttpOnly — JS needs to read it
                path="/",
            )
    except Exception:
        pass
    return response
app.after_request(_set_csrf_cookie)

@app.context_processor
def _inject_csrf():
    """Make csrf_token() and csp_nonce() available in all Jinja templates."""
    return {"csrf_token": _csrf_token, "csp_nonce": _csp_nonce}

# Secure session cookie config
