        compare_role=f.get("compare_role",""),
        compare_gain_alert_db=float(f.get("compare_gain_alert_db") or 3.0),
        nowplaying_station_id=f.get("nowplaying_station_id",""),
        alert_on_lufs_tp=bool(f.get("alert_on_lufs_tp")),
