@app.post("/ai/retrain/<int:idx>")
@login_required
@csrf_protect
def ai_retrain(idx):
    inps=monitor.app_cfg.inputs
    if 0<=idx<len(inps):
        name=inps[idx].name; monitor.request_retrain(name)
        if monitor.is_running():
            sender=AlertSender(monitor.app_cfg,monitor.log)
            ai=StreamAI(inps[idx],monitor.log,sender)
            monitor._stream_ais[name]=ai; ai.start()
            flash(f"Retraining started for '{name}'.")
        else:
            flash(f"Retrain flagged for '{name}' — starts on next monitoring start.")
    return redirect(url_for("index"))

@app.post("/settings/test-notify")
@login_required
@csrf_protect
def settings_test_notify():
    """Send a test notification on the requested channel."""
    channel = request.args.get("channel","email")
    cfg = monitor.app_cfg
    sender = AlertSender(cfg, monitor.log)
    subject = "SignalScope — Test Notification"
    body    = (f"This is a test notification from {cfg.hub.site_name or 'SignalScope'}. "
               f"If you received this, {channel} notifications are working correctly. "
               f"Sent at {time.strftime('%Y-%m-%d %H:%M:%S')}.")
    try:
        if channel == "email":
            if not cfg.email.enabled or not cfg.email.smtp_host:
                return jsonify({"ok":False,"message":"Email not configured"})
            sender._email(subject, body, None)
            return jsonify({"ok":True,"message":f"Test email sent to {cfg.email.to_addr}"})
        elif channel == "webhook":
            if not cfg.webhook.enabled and not cfg.webhook.routes:
                return jsonify({"ok":False,"message":"Webhook not configured"})
            sender._webhook(subject, body, alert_type="TEST", stream="test")
            return jsonify({"ok":True,"message":"Test webhook sent"})
        elif channel == "pushover":
            if not cfg.pushover.enabled or not cfg.pushover.user_key:
                return jsonify({"ok":False,"message":"Pushover not configured"})
            sender._pushover(subject, body)
            return jsonify({"ok":True,"message":"Test Pushover notification sent"})
        else:
            return jsonify({"ok":False,"message":f"Unknown channel: {channel}"})
    except Exception as e:
        return jsonify({"ok":False,"message":str(e)})


@app.route("/settings", methods=["GET","POST"])
@login_required
@admin_required
@csrf_protect
def settings():
    cfg=monitor.app_cfg
    if request.method=="POST":
        f=request.form
        cfg.email.enabled=bool(f.get("email_enabled")); cfg.email.smtp_host=f.get("smtp_host","").strip()
        cfg.email.smtp_port=int(f.get("smtp_port",587)); cfg.email.use_tls=bool(f.get("use_tls"))
        cfg.email.username=f.get("email_user","").strip(); cfg.email.password=f.get("email_pass","")
        cfg.email.from_addr=f.get("from_addr","").strip(); cfg.email.to_addr=f.get("to_addr","").strip()
        cfg.webhook.enabled     = bool(f.get("webhook_enabled"))
        cfg.webhook.url         = f.get("webhook_url","").strip()
        cfg.webhook.teams_style = bool(f.get("webhook_teams_style"))
        # Parse dynamic webhook routing rows
        routes = []
        i = 0
        while True:
            url = f.get(f"wr_url_{i}", "").strip()
            name = f.get(f"wr_name_{i}", "").strip()
            if url is None and name is None:
                break          # no more rows
            if url or name:    # skip completely empty rows
                streams_raw = f.get(f"wr_streams_{i}", "").strip()
                types_raw   = f.get(f"wr_types_{i}",   "").strip()
                sites_raw   = f.get(f"wr_sites_{i}",   "").strip()
                routes.append(WebhookRoute(
                    name     = name,
                    url      = url,
                    teams_style = f.get(f"wr_style_{i}","teams") == "teams",
                    filter_streams  = [s.strip() for s in streams_raw.split(",") if s.strip()],
                    filter_types    = [t.strip() for t in types_raw.split(",")   if t.strip()],
                    filter_sites    = [s.strip() for s in sites_raw.split(",")   if s.strip()],
                    filter_severity = f.get(f"wr_severity_{i}","").strip(),
                ))
            i += 1
            if i > 50: break   # safety cap
        cfg.webhook.routes = routes
        cfg.pushover.enabled=bool(f.get("pv_enabled"))
        cfg.pushover.user_key=f.get("pv_user_key","").strip()
        cfg.pushover.app_token=f.get("pv_app_token","").strip()
        cfg.pushover.priority_warn=int(f.get("pv_pri_warn",0))
        cfg.pushover.priority_alert=int(f.get("pv_pri_alert",1))
        cfg.network.audio_interface_ip=f.get("audio_ip","0.0.0.0").strip()
        cfg.network.management_interface_ip=f.get("mgmt_ip","0.0.0.0").strip()
        cfg.network.server_bind_host=f.get("server_bind_host","0.0.0.0").strip() or "0.0.0.0"
        cfg.hub.enabled=bool(f.get("hub_enabled")); cfg.hub.mode=f.get("hub_mode","client")
        cfg.hub.site_name=f.get("hub_site_name","").strip()
        _raw_url = f.get("hub_url","").strip()
        cfg.hub.hub_url = HubClient._normalise_url(_raw_url) if _raw_url else ""
        cfg.hub.secret_key=f.get("hub_secret","").strip()
        try: cfg.hub.relay_bitrate = int(f.get("hub_relay_bitrate", 128))
        except ValueError: pass
        cfg.hub.clip_auto_upload = bool(f.get("hub_clip_auto_upload"))
        cfg.hub.clip_sync        = bool(f.get("hub_clip_sync"))
        cfg.hub.low_bw           = bool(f.get("hub_low_bw"))
        # Auth
        cfg.auth.enabled  = bool(f.get("auth_enabled"))
        cfg.auth.username = f.get("auth_username","admin").strip() or "admin"
        new_pw         = f.get("auth_password","").strip()
        new_pw_confirm = f.get("auth_password_confirm","").strip()
        if new_pw:
            if new_pw != new_pw_confirm:
                flash("Passwords do not match — password not changed.")
                new_pw = ""
            elif len(new_pw) < 8:
                flash("Password must be at least 8 characters — not saved.")
                new_pw = ""
        if new_pw:
            cfg.auth.password_hash = _hash_password(new_pw)
            cfg.auth.first_login   = False
        # SDR devices
        serials = f.getlist("sdr_serial")
        roles   = f.getlist("sdr_role")
        ppms    = f.getlist("sdr_ppm")
        labels  = f.getlist("sdr_label")
        gains   = f.getlist("sdr_gain")
        # Pad gains list if a legacy form omits it
        while len(gains) < len(serials):
            gains.append("-1")
        cfg.sdr_devices = []
        for serial, role, ppm, label, gain in zip(serials, roles, ppms, labels, gains):
            serial = serial.strip()
            if serial:  # skip blank rows
                try: ppm_int = int(ppm)
                except: ppm_int = 0
                try: gain_int = int(gain)
                except: gain_int = -1
                cfg.sdr_devices.append(SdrDevice(
                    serial=serial, role=role,
                    ppm=ppm_int, label=label.strip(),
                    gain=gain_int))
        # PTP thresholds
        try: cfg.ptp_offset_warn_us  = max(100, int(f.get("ptp_offset_warn_us",  5000)))
        except: pass
        try: cfg.ptp_offset_alert_us = max(100, int(f.get("ptp_offset_alert_us", 50000)))
        except: pass
        try: cfg.ptp_jitter_warn_us  = max(100, int(f.get("ptp_jitter_warn_us",  2000)))
        except: pass
        try: cfg.ptp_jitter_alert_us = max(100, int(f.get("ptp_jitter_alert_us", 10000)))
        except: pass
        # Login security
        try: cfg.login_max_attempts = max(3,   int(f.get("login_max_attempts", 10)))
        except: pass
        try: cfg.login_lockout_mins = max(1,   int(f.get("login_lockout_mins", 15)))
        except: pass
        try: cfg.session_timeout_hrs= max(1,   int(f.get("session_timeout_hrs", 12)))
        except: pass
        # SLA + nowplaying
        try: cfg.sla_target_pct = float(f.get("sla_target", 99.9))
        except: pass
        cfg.nowplaying_country = f.get("nowplaying_country","GB").strip() or "GB"
        # Daily report
        rt = f.get("daily_report_time","06:00").strip()
        import re as _re
        if _re.match(r"^[0-2][0-9]:[0-5][0-9]$", rt): cfg.daily_report_time = rt
        # Maintenance
        try: cfg.alert_log_max = max(0, int(f.get("alert_log_max", 10000)))
        except: pass
        try: cfg.clip_max_age_days = max(0, int(f.get("clip_max_age_days", 30)))
        except: pass
        try: cfg.clip_max_per_stream = max(0, int(f.get("clip_max_per_stream", 200)))
        except: pass
        cfg.suppress_local_notifications = bool(f.get("hub_suppress_local"))
        # APNs push notification config
        cfg.mobile_api.apns_key_id    = f.get("apns_key_id",    "").strip()
        cfg.mobile_api.apns_team_id   = f.get("apns_team_id",   "").strip()
        cfg.mobile_api.apns_bundle_id = f.get("apns_bundle_id", "").strip()
        _apns_pem = f.get("apns_key_pem", "").strip()
        if _apns_pem:                       # only overwrite if something was pasted
            cfg.mobile_api.apns_key_pem = _apns_pem
        cfg.mobile_api.apns_sandbox = bool(f.get("apns_sandbox"))
        # FCM push notification config
        _fcm_pid = f.get("fcm_project_id", "").strip()
        if _fcm_pid:
            cfg.mobile_api.fcm_project_id = _fcm_pid
        _fcm_sa = f.get("fcm_service_account_json", "").strip()
        if _fcm_sa:
            cfg.mobile_api.fcm_service_account_json = _fcm_sa
        # Push server URL (route notifications via remote server instead of direct APNs/FCM)
        cfg.mobile_api.push_server_url = f.get("push_server_url", "").strip()
        save_config(cfg)
        # Invalidate both JWT caches so new credentials are used immediately
        _apns_jwt_cache.update({"token": "", "generated_at": 0.0, "cache_key": ""})
        _fcm_token_cache.update({"token": "", "generated_at": 0.0, "cache_key": ""})
        # If hub client mode and URL are now set, start the hub heartbeat client
        # immediately without requiring the monitor loop to be running first.
        # start_hub_client() is a no-op if the client is already running.
        monitor.start_hub_client()
        flash("Settings saved."); return redirect(url_for("settings"))
    _hub_sites = hub_server.get_sites() if hub_server else []
    return render_template_string(SETTINGS_TPL, cfg=cfg,
        hub_sites=_hub_sites,
        _hub_default_fwd=_HUB_DEFAULT_FORWARD_TYPES,
        _all_alert_types=_ALL_ALERT_TYPES,
        _installed_plugins=_scan_installed_plugins())

@app.post("/api/hub/site_rules")
@login_required
@csrf_protect
def api_hub_site_rules():
    """Save per-site alert forwarding rules for the hub."""
    try:
        data = request.get_json(force=True) or {}
        site_name = str(data.get("site_name", "")).strip()
        if not site_name:
            return jsonify({"ok": False, "error": "site_name required"}), 400
        enabled      = bool(data.get("enabled", True))
        forward_types = [str(t).strip().upper() for t in data.get("forward_types", _HUB_DEFAULT_FORWARD_TYPES)
                         if str(t).strip().upper() in _ALL_ALERT_TYPES]
        cfg = monitor.app_cfg
        if not isinstance(cfg.hub_site_rules, dict):
            cfg.hub_site_rules = {}
        cfg.hub_site_rules[site_name] = {"enabled": enabled, "forward_types": forward_types, "low_bw": bool(data.get("low_bw", False))}
        save_config(cfg)
        return jsonify({"ok": True})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)}), 500


@app.get("/api/settings/log")
@login_required
def api_settings_log():
    """Return recent log lines for the Settings → Log viewer.

    Query params:
      n      — number of lines to return (default 500, max 2000)
      filter — case-insensitive substring filter applied server-side
    """
    n    = min(int(request.args.get("n", 500)), 2000)
    filt = (request.args.get("filter") or "").lower().strip()
    lines = monitor.get_logs(n)
    if filt:
        lines = [l for l in lines if filt in l.lower()]
    return jsonify({"lines": lines, "count": len(lines)})


@app.get("/settings/backup")
@login_required
@admin_required
def settings_backup():
    """Stream a ZIP containing config, AI models, metrics DB, SLA data, alert log and hub state."""
    import zipfile, io as _io
    buf = _io.BytesIO()
    with zipfile.ZipFile(buf, "w", zipfile.ZIP_DEFLATED) as zf:
        # Config file
        if os.path.isfile(CONFIG_PATH):
            zf.write(CONFIG_PATH, "lwai_config.json")
        # AI models directory
        if os.path.isdir(MODELS_DIR):
            for root, _dirs, files in os.walk(MODELS_DIR):
                for fname in files:
                    full = os.path.join(root, fname)
                    arc  = os.path.relpath(full, BASE_DIR)
                    zf.write(full, arc)
        # Metrics history SQLite database
        if os.path.isfile(METRICS_DB_PATH):
            try:
                # Read via a fresh connection so WAL is checkpointed cleanly
                import sqlite3 as _sq3, tempfile as _tf, shutil as _sh
                tmp = _tf.NamedTemporaryFile(suffix=".db", delete=False)
                tmp.close()
                try:
                    src = _sq3.connect(METRICS_DB_PATH)
                    dst = _sq3.connect(tmp.name)
                    src.backup(dst)
                    dst.close()
                    src.close()
                    zf.write(tmp.name, "metrics_history.db")
                finally:
                    try: os.unlink(tmp.name)
                    except: pass
            except Exception:
                # Fallback: just include the file directly
                zf.write(METRICS_DB_PATH, "metrics_history.db")
        # SLA data
        if os.path.isfile(SLA_PATH):
            zf.write(SLA_PATH, "sla_data.json")
        # Alert log
        if os.path.isfile(ALERT_LOG_PATH):
            zf.write(ALERT_LOG_PATH, "alert_log.json")
        # Hub state
        if os.path.isfile(HUB_STATE_PATH):
            zf.write(HUB_STATE_PATH, "hub_state.json")
    buf.seek(0)
    import datetime as _dt
    ts = _dt.datetime.now().strftime("%Y%m%d_%H%M%S")
    dl_name = f"signalscope_backup_{ts}.zip"
    return Response(
        buf.read(),
        mimetype="application/zip",
        headers={"Content-Disposition": f'attachment; filename="{dl_name}"'},
    )

@app.post("/settings/restore")
@login_required
@admin_required
@csrf_protect
def settings_restore():
    """Restore config + AI models from an uploaded backup ZIP."""
    import zipfile, io as _io
    f = request.files.get("backup_zip")
    if not f or not f.filename:
        flash("No file uploaded."); return redirect(url_for("settings"))

    data = f.read(512 * 1024 * 1024)  # cap at 512 MB (metrics DB can be large)
    if not zipfile.is_zipfile(_io.BytesIO(data)):
        flash("Uploaded file is not a valid ZIP."); return redirect(url_for("settings"))

    restored_config  = False
    restored_models  = 0
    restored_db      = False
    restored_sla     = False
    restored_alerts  = False
    restored_hub     = False
    errors = []

    with zipfile.ZipFile(_io.BytesIO(data)) as zf:
        for entry in zf.infolist():
            # Zip-slip guard: reject any entry with path traversal
            entry_path = os.path.normpath(entry.filename)
            if entry_path.startswith("..") or os.path.isabs(entry_path):
                errors.append(f"Skipped unsafe path: {entry.filename}")
                continue

            if entry_path == "lwai_config.json":
                raw = zf.read(entry)
                try:
                    json.loads(raw)  # validate JSON before writing
                except Exception:
                    errors.append("lwai_config.json is not valid JSON — skipped.")
                    continue
                with open(CONFIG_PATH, "wb") as fh:
                    fh.write(raw)
                try:
                    os.chmod(CONFIG_PATH, 0o600)
                except OSError:
                    pass
                restored_config = True

            elif entry_path.startswith("ai_models" + os.sep) or entry_path.startswith("ai_models/"):
                dest = os.path.join(BASE_DIR, entry_path)
                dest = os.path.normpath(dest)
                # Confirm still inside BASE_DIR after normalization
                if not dest.startswith(os.path.abspath(BASE_DIR) + os.sep):
                    errors.append(f"Skipped unsafe model path: {entry.filename}")
                    continue
                os.makedirs(os.path.dirname(dest), exist_ok=True)
                if not entry.is_dir():
                    with open(dest, "wb") as fh:
                        fh.write(zf.read(entry))
                    restored_models += 1

            elif entry_path == "metrics_history.db":
                try:
                    raw = zf.read(entry)
                    # Close the shared metrics_db connection before overwriting
                    metrics_db._conn = None
                    with open(METRICS_DB_PATH, "wb") as fh:
                        fh.write(raw)
                    restored_db = True
                except Exception as e:
                    errors.append(f"metrics_history.db restore failed: {e}")

            elif entry_path == "sla_data.json":
                raw = zf.read(entry)
                try:
                    json.loads(raw)
                except Exception:
                    errors.append("sla_data.json is not valid JSON — skipped.")
                    continue
                with open(SLA_PATH, "wb") as fh:
                    fh.write(raw)
                restored_sla = True

            elif entry_path == "alert_log.json":
                raw = zf.read(entry)
                with _alert_log_lock:
                    with open(ALERT_LOG_PATH, "wb") as fh:
                        fh.write(raw)
                restored_alerts = True

            elif entry_path == "hub_state.json":
                raw = zf.read(entry)
                try:
                    json.loads(raw)
                except Exception:
                    errors.append("hub_state.json is not valid JSON — skipped.")
                    continue
                with open(HUB_STATE_PATH, "wb") as fh:
                    fh.write(raw)
                restored_hub = True

    if restored_config:
        # Reload config and restart monitoring with restored settings
        try:
            new_cfg = load_config()
            monitor.app_cfg = new_cfg
            monitor.stop_monitoring()
            monitor.start_monitoring()
        except Exception as e:
            errors.append(f"Config reloaded but monitor restart failed: {e}")

    parts = []
    if restored_config:  parts.append("config restored")
    if restored_models:  parts.append(f"{restored_models} AI model file(s) restored")
    if restored_db:      parts.append("metrics history DB restored")
    if restored_sla:     parts.append("SLA data restored")
    if restored_alerts:  parts.append("alert log restored")
    if restored_hub:     parts.append("hub state restored")
    if not parts:        parts.append("nothing recognised in ZIP")
    msg = "Restore complete: " + ", ".join(parts) + "."
    if errors:           msg += " Warnings: " + "; ".join(errors)
    flash(msg)
    return redirect(url_for("settings"))

@app.get("/stream/<int:idx>/audio.wav")
@login_required
def stream_audio(idx):
    inps=monitor.app_cfg.inputs
    if idx<0 or idx>=len(inps): return "Not found",404
    inp=inps[idx]
    if not inp._stream_buffer: return "No data — stream not yet receiving audio",503
    chunks=list(inp._stream_buffer)
    if not chunks: return "No data — buffer empty",503

    # ?seconds=N controls how much audio to return (max 20s = buffer size)
    try: secs = min(float(request.args.get("seconds", 10)), STREAM_BUFFER_SECONDS)
    except: secs = 10.0
    secs = max(1.0, secs)

    audio = np.concatenate(chunks)[-int(SAMPLE_RATE * secs):]
    safe  = _safe_name(inp.name)
    ts    = time.strftime("%Y%m%d-%H%M%S")
    fname = f"{safe}_{ts}_{int(secs)}s.wav"

    return Response(
        _make_wav_bytes(audio.astype(np.float32)),
        mimetype="audio/wav",
        headers={"Content-Disposition": f'attachment; filename="{fname}"'},
    )

# ─── Live audio stream (chunked WAV for browser <audio> tag) ─────────────────

@app.get("/stream/<int:idx>/live")
@login_required
def stream_live(idx):
    """
    Streams audio as a continuous MP3 response via a local ffmpeg encoder.
    MP3 is the only format all browsers play reliably as a live stream.
    The ffmpeg process reads raw PCM s16le from a pipe and outputs MP3 frames.
    """
    import subprocess, shutil
    inps = monitor.app_cfg.inputs
    if idx < 0 or idx >= len(inps):
        return "Not found", 404
    inp = inps[idx]

    # Fallback to WAV streaming if ffmpeg isn't available
    has_ffmpeg = _find_binary("ffmpeg") is not None

    if not has_ffmpeg:
        # WAV fallback (works in most browsers on a LAN, may stall in Chrome)
        def gen_wav():
            import struct as _struct, collections as _collections
            sr = SAMPLE_RATE; ch = 1; bps = 2
            yield (
                b'RIFF' + _struct.pack('<I', 0xFFFFFFFF) +
                b'WAVE' +
                b'fmt ' + _struct.pack('<IHHIIHH', 16, 1, ch, sr, sr*ch*bps, ch*bps, 16) +
                b'data' + _struct.pack('<I', 0xFFFFFFFF)
            )
            def _pcm(c): return (np.clip(c,-1.,1.)*32767).astype(np.int16).tobytes()

            prefill_n = max(2, int(LIVE_PLAYOUT_BUFFER_SECS / CHUNK_DURATION))
            q = _collections.deque()
            if inp._stream_buffer:
                seed_n = max(prefill_n, int(3.0 / CHUNK_DURATION))
                for c in list(inp._stream_buffer)[-seed_n:]:
                    q.append(c.copy())

            seen_seq = getattr(inp, '_live_chunk_seq', 0)
            next_send = time.monotonic()

            while True:
                cur = getattr(inp, '_live_chunk_seq', 0)
                if cur > seen_seq and inp._stream_buffer:
                    n = min(cur - seen_seq, 50)
                    for c in list(inp._stream_buffer)[-n:]:
                        q.append(c.copy())
                    seen_seq = cur

                if len(q) < prefill_n:
                    time.sleep(0.02)
                    next_send = time.monotonic() + 0.01
                    continue

                now = time.monotonic()
                if now < next_send:
                    time.sleep(min(0.02, next_send - now))
                    continue

                if q:
                    yield _pcm(q.popleft())
                    next_send += CHUNK_DURATION
                else:
                    time.sleep(0.02)
        return Response(gen_wav(), mimetype="audio/wav",
            headers={"Cache-Control":"no-cache","X-Accel-Buffering":"no"})

    def generate_mp3():
        sr = SAMPLE_RATE
        cmd = [
            "ffmpeg", "-hide_banner", "-loglevel", "error",
            "-f", "s16le", "-ar", str(sr), "-ac", "1", "-i", "pipe:0",
            "-f", "mp3", "-b:a", "128k", "-reservoir", "0", "pipe:1",
        ]
        proc = subprocess.Popen(cmd,
            stdin=subprocess.PIPE, stdout=subprocess.PIPE,
            stderr=subprocess.DEVNULL, bufsize=0)

        def _pcm_raw(c):
            return (np.clip(c, -1., 1.) * 32767).astype(np.int16).tobytes()

        def writer():
            import collections as _collections
            try:
                prefill_n = max(2, int(LIVE_PLAYOUT_BUFFER_SECS / CHUNK_DURATION))
                q = _collections.deque()

                # seed backlog so browser decoder starts immediately and playback stays
                # slightly behind the live edge, masking bursty packet arrival timing.
                if inp._stream_buffer:
                    seed_n = max(prefill_n, int(3.0 / CHUNK_DURATION))
                    for c in list(inp._stream_buffer)[-seed_n:]:
                        q.append(c.copy())

                seen_seq = getattr(inp, '_live_chunk_seq', 0)
                next_send = time.monotonic()

                while True:
                    cur = getattr(inp, '_live_chunk_seq', 0)
                    if cur > seen_seq and inp._stream_buffer:
                        n = min(cur - seen_seq, 50)
                        for c in list(inp._stream_buffer)[-n:]:
                            q.append(c.copy())
                        seen_seq = cur

                    if len(q) < prefill_n:
                        time.sleep(0.02)
                        next_send = time.monotonic() + 0.01
                        continue

                    now = time.monotonic()
                    if now < next_send:
                        time.sleep(min(0.02, next_send - now))
                        continue

                    if q:
                        proc.stdin.write(_pcm_raw(q.popleft()))
                        next_send += CHUNK_DURATION
                    else:
                        time.sleep(0.02)
            except Exception:
                pass
            finally:
                try: proc.stdin.close()
                except: pass

        import threading as _t
        wt = _t.Thread(target=writer, daemon=True)
        wt.start()

        try:
            while True:
                data = proc.stdout.read(4096)
                if not data:
                    break
                yield data
        finally:
            try: proc.kill(); proc.wait()
            except: pass

    return Response(
        generate_mp3(),
        mimetype="audio/mpeg",
        headers={
            "Cache-Control": "no-cache, no-store",
            "X-Accel-Buffering": "no",
            "icy-name": inp.name,
        },
    )

@app.get("/clips/<path:stream_name>")
@login_required
def clips_list(stream_name):
    """Return JSON list of saved alert clips for a stream."""
    snip_dir = os.path.join(BASE_DIR, "alert_snippets", _safe_name(stream_name))
    if not os.path.exists(snip_dir):
        return jsonify([])
    files = []
    for fn in sorted(os.listdir(snip_dir), reverse=True):
        if not fn.endswith(".wav"): continue
        path = os.path.join(snip_dir, fn)
        # Parse filename: YYYYMMDD-HHMMSS_StreamName_alerttype.wav
        parts = fn.replace(".wav","").split("_")
        ts_str = parts[0] if parts else ""
        alert_type = parts[-1] if len(parts) > 1 else "unknown"
        try:
            ts = time.mktime(time.strptime(ts_str, "%Y%m%d-%H%M%S"))
            ts_fmt = time.strftime("%d %b %Y %H:%M:%S", time.localtime(ts))
        except:
            ts_fmt = ts_str
        size_kb = os.path.getsize(path) // 1024
        files.append({
            "filename": fn,
            "ts": ts_fmt,
            "alert_type": alert_type.replace("_"," ").upper(),
            "size_kb": size_kb,
        })
    return jsonify(files)

def _serve_clip_wav(path: str, force_download: bool = False) -> "Response":
    """Serve a WAV clip with explicit Range-request handling.

    Reads the file into memory and handles Range requests manually so that
    browser <audio> elements receive a correct 206 Partial Content response.
    This is more reliable than delegating to Werkzeug's conditional machinery,
    which can behave inconsistently with certain browser/proxy combinations
    (Chrome issues a Range probe before playback; without a 206 the element
    errors immediately).

    Clip files are short (a few seconds of mono WAV ≈ 100–500 KB) so reading
    into memory is fine.
    """
    if not os.path.exists(path):
        try:
            monitor.log(f"[Clip] 404 — file not on disk: {os.path.basename(path)!r} "
                        f"(expected at {path!r})")
        except Exception:
            pass
        return Response("Not found", status=404)
    try:
        with open(path, "rb") as _f:
            data = _f.read()
    except OSError as _e:
        return Response(f"Read error: {_e}", status=500)

    total    = len(data)
    filename = os.path.basename(path)
    mime     = "audio/mpeg" if path.lower().endswith(".mp3") else "audio/wav"

    if force_download:
        return Response(
            data, status=200,
            headers={
                "Content-Type":        mime,
                "Content-Length":      str(total),
                "Content-Disposition": f'attachment; filename="{filename}"',
                "Cache-Control":       "no-store",
            },
        )

    # Inline playback — honour Range header so browsers can seek/pre-buffer
    range_hdr = request.headers.get("Range", "")
    if range_hdr and range_hdr.startswith("bytes="):
        try:
            parts = range_hdr[6:].split("-", 1)
            start = int(parts[0]) if parts[0] else 0
            end   = int(parts[1]) if len(parts) > 1 and parts[1] else total - 1
            start = max(0, min(start, total - 1))
            end   = max(start, min(end, total - 1))
            chunk = data[start : end + 1]
            return Response(
                chunk, status=206,
                headers={
                    "Content-Type":   mime,
                    "Content-Length": str(len(chunk)),
                    "Content-Range":  f"bytes {start}-{end}/{total}",
                    "Accept-Ranges":  "bytes",
                    "Cache-Control":  "no-store",
                },
            )
        except (ValueError, IndexError):
            pass  # fall through to full response

    return Response(
        data, status=200,
        headers={
            "Content-Type":        mime,
            "Content-Length":      str(total),
            "Content-Disposition": f'inline; filename="{filename}"',
            "Accept-Ranges":       "bytes",
            "Cache-Control":       "no-store",
        },
    )


@app.get("/clips/<path:stream_name>/<filename>")
@login_required
def clips_serve(stream_name, filename):
    """Serve a saved alert clip WAV file.

    Remote clips uploaded from hub clients are stored as
    alert_snippets/<_safe_name(site)>_<_safe_name(stream)>/.
    The alert log records stream as "site / stream" — we must split and
    re-join exactly as hub_clip_upload does, rather than safe-naming the
    full combined string (which collapses the joining underscore to nothing).
    """
    snip_dir = os.path.join(BASE_DIR, "alert_snippets")
    if " / " in stream_name:
        _sp, _st = stream_name.split(" / ", 1)
        safe_stream = f"{_safe_name(_sp)}_{_safe_name(_st)}"
    else:
        safe_stream = _safe_name(stream_name)
    safe_file = os.path.basename(filename)
    path = os.path.join(snip_dir, safe_stream, safe_file)
    if not os.path.abspath(path).startswith(os.path.abspath(snip_dir) + os.sep):
        return "Forbidden", 403
    return _serve_clip_wav(path)

@app.delete("/clips/<path:stream_name>/<filename>")
@login_required
@csrf_protect
def clips_delete(stream_name, filename):
    """Delete a saved alert clip."""
    snip_dir  = os.path.join(BASE_DIR, "alert_snippets")
    safe_stream = _safe_name(stream_name)
    safe_file   = os.path.basename(filename)   # strip any path components
    path = os.path.join(snip_dir, safe_stream, safe_file)
    # Security: must stay within snip_dir
    if not os.path.abspath(path).startswith(os.path.abspath(snip_dir) + os.sep):
        return jsonify({"error": "forbidden"}), 403
    try:
        os.remove(path)
        return jsonify({"ok": True})
    except FileNotFoundError:
        return jsonify({"error": "not found"}), 404
    except Exception as e:
        return jsonify({"error": str(e)}), 500

