@app.post("/api/dab/kill_orphans")
@login_required
@csrf_protect
def api_dab_kill_orphans():
    """Kill any orphaned welle-cli processes that may be holding the SDR dongle.

    Safe to call at any time — running welle-cli instances started by an
    active DAB session will reconnect automatically.  Call this if a channel
    scan or mux scan left the dongle claimed and it can no longer be opened.
    """
    import subprocess as _ksp, signal as _ksig
    killed = []
    errors = []
    try:
        result = _ksp.run(["pgrep", "-x", "welle-cli"],
                          capture_output=True, text=True)
        pids = [int(p.strip()) for p in result.stdout.splitlines() if p.strip().isdigit()]
    except Exception as e:
        # pgrep not available (Windows?) — fall back to psutil if installed
        try:
            import psutil as _psu
            pids = [p.pid for p in _psu.process_iter(["name"])
                    if (p.info["name"] or "").lower() in ("welle-cli", "welle-cli.exe")]
        except Exception:
            return jsonify({"error": f"Cannot enumerate processes: {e}"}), 500

    for pid in pids:
        try:
            os.kill(pid, _ksig.SIGKILL)
            killed.append(pid)
        except ProcessLookupError:
            pass  # already gone
        except Exception as ex:
            errors.append(f"pid {pid}: {ex}")

    # Brief settle so libusb releases the USB device before the caller retries
    if killed:
        time.sleep(1.0)

    msg = f"Killed {len(killed)} welle-cli process(es)."
    if errors:
        msg += f" Errors: {'; '.join(errors)}"
    monitor.log(f"[DAB] kill_orphans: {msg}")
    return jsonify({"ok": True, "killed": killed, "errors": errors, "message": msg})


@app.post("/api/admin/restart")
@login_required
@csrf_protect
def api_admin_restart():
    """Gracefully restart the SignalScope process.

    Replaces the running process with a fresh copy of itself using os.execv.
    Any systemd / supervisor watchdog will see the restart.  All active
    streams will be interrupted momentarily.
    """
    import sys as _sys, threading as _thr
    monitor.log("[Admin] Restart requested via web UI.")

    def _do_restart():
        time.sleep(1.5)   # let the HTTP response reach the browser first
        # Kill any welle-cli children before exec so they don't outlive the
        # old process and hold the dongle when the new process starts.
        try:
            import subprocess as _rsp, signal as _rsig
            _r = _rsp.run(["pgrep", "-x", "welle-cli"], capture_output=True, text=True)
            for _pid_str in _r.stdout.splitlines():
                try:
                    os.kill(int(_pid_str.strip()), _rsig.SIGKILL)
                except Exception:
                    pass
            if _r.stdout.strip():
                time.sleep(0.8)   # USB settle
        except Exception:
            pass
        os.execv(_sys.executable, [_sys.executable] + _sys.argv)

    _thr.Thread(target=_do_restart, daemon=True, name="AdminRestart").start()
    return jsonify({"ok": True, "note": "Restarting in ~1.5 s…"})


@app.get("/api/dab/scan")
@login_required
def api_dab_scan():
    """
    Scan a DAB multiplex using welle-cli in HTTP server mode.
    Query params:
        channel  — DAB channel name e.g. 5C  (required)
        serial   — dongle serial number       (optional, uses first available if omitted)
        ppm      — frequency correction       (optional, uses registry value if omitted)
    Returns JSON: {ensemble, snr, services: [{name, sid, bitrate, stereo, ok}]}
    """
    import shutil, subprocess as _sp, urllib.request as _ur

    channel = request.args.get("channel", "").strip().upper()
    serial  = request.args.get("serial",  "").strip()
    ppm     = request.args.get("ppm",     "").strip()

    if not channel:
        return jsonify({"error": "channel parameter required"}), 400

    _VALID_DAB_CHANNELS = {
        "5A","5B","5C","5D","6A","6B","6C","6D","7A","7B","7C","7D",
        "8A","8B","8C","8D","9A","9B","9C","9D","10A","10B","10C","10D",
        "11A","11B","11C","11D","12A","12B","12C","12D","13A","13B","13C","13D","13E","13F",
    }
    if channel not in _VALID_DAB_CHANNELS:
        return jsonify({"error": "invalid channel"}), 400

    if not _find_binary("welle-cli"):
        return jsonify({"error": "welle-cli not found — install welle.io"}), 503

    # Resolve device index
    device_idx = "0"
    if serial:
        try:
            device_idx = str(sdr_manager.resolve_index(serial))
        except SdrNotFoundError as e:
            return jsonify({"error": str(e)}), 404
        except SdrBusyError as e:
            return jsonify({"error": str(e)}), 409

    # Resolve PPM and gain from registry if not explicitly given
    gain = request.args.get("gain", "").strip()
    if serial:
        for dev in monitor.app_cfg.sdr_devices:
            if dev.serial == serial:
                if not ppm:
                    ppm = str(dev.ppm)
                if not gain:
                    gain = str(getattr(dev, "gain", -1))
                break
    gain_int = -1
    try:
        gain_int = int(gain) if gain else -1
    except (ValueError, TypeError):
        pass

    # Welle-cli scan port — use a fixed high port
    WELLE_PORT = 7979

    # Build command — avoid --no-stdout (not all builds support it)
    # Use -d (lowercase) for device index — standard across PPA and built versions
    # stdout → DEVNULL, capture stderr for diagnostics
    # Per welle-cli syntax: "welle-cli -w <port> [OPTION]" — -w MUST come first
    # -u disables coarse corrector, helps dongles with large frequency offsets
    welle_bin = _find_binary("welle-cli")
    if not welle_bin:
        return jsonify({"error": "welle-cli not found on system PATH or /usr/bin"}), 503
    cmd = [welle_bin, "-w", str(WELLE_PORT), "-c", channel, "-g", str(gain_int)]
    if device_idx and device_idx != "0":
        cmd += ["-F", f"rtl_sdr,{device_idx}"]
    else:
        cmd += ["-F", "rtl_sdr"]

    proc = None
    stderr_lines = []
    try:
        # Log exact command for diagnosis
        cmd_str = " ".join(cmd)
        print(f"[DABScan] Launching: {cmd_str}")

        proc = _sp.Popen(cmd, stdout=_sp.PIPE, stderr=_sp.PIPE)
        print(f"[DABScan] PID: {proc.pid}")

        # Read stderr in a background thread so it doesn't block
        import threading as _th
        def _read_stderr():
            for line in proc.stderr:
                decoded = line.decode(errors="ignore").strip()
                if decoded:
                    stderr_lines.append(decoded)
                    print(f"[DABScan stderr] {decoded}")
        _th.Thread(target=_read_stderr, daemon=True).start()

        # Also read stdout in background
        stdout_lines = []
        def _read_stdout():
            for line in proc.stdout:
                decoded = line.decode(errors="ignore").strip()
                if decoded:
                    stdout_lines.append(decoded)
                    print(f"[DABScan stdout] {decoded}")
        _th.Thread(target=_read_stdout, daemon=True).start()

        # Brief startup check — crash detection only
        time.sleep(2.0)
        poll_result = proc.poll()
        print(f"[DABScan] After 2s: poll={poll_result}, stderr={stderr_lines[-3:]}")
        if poll_result is not None:
            err_out = stderr_lines[-10:] if stderr_lines else ["unknown error"]
            return jsonify({"error": "welle-cli exited immediately",
                            "debug_stderr": err_out, "debug_cmd": cmd,
                            "returncode": poll_result}), 500

        available_urls = {}  # populated during polling

        # Poll for up to 60s — sync can take 15-20s on weaker signals.
        # We wait for the service list to stabilise (unchanged for 4 consecutive
        # polls) rather than breaking on the first result, so we capture all
        # services on the mux and not just the first few that respond.
        deadline        = time.time() + 60
        services        = []
        ensemble        = {}
        stable_count    = 0   # consecutive polls with same service count
        STABLE_NEEDED   = 4   # require 4 stable polls (~4s) before accepting
        MIN_WAIT        = 10  # always wait at least 10s for slower signals
        scan_start      = time.time()

        while time.time() < deadline:
            time.sleep(1)
            # Check welle-cli hasn't crashed
            if proc.poll() is not None:
                err_out = " | ".join(stderr_lines[-3:]) if stderr_lines else "crashed"
                return jsonify({"error": f"welle-cli crashed: {err_out}"}), 500
            try:
                # Try both API path variants (Ubuntu vs welle.io PPA)
                ensemble_urls = [
                    f"http://localhost:{WELLE_PORT}/mux.json",
                    f"http://localhost:{WELLE_PORT}/api/mux.json",
                ]
                mux_data = None
                for eurl in ensemble_urls:
                    try:
                        with _ur.urlopen(eurl, timeout=2) as r:
                            mux_data = json.loads(r.read())
                        break
                    except Exception:
                        continue

                if not mux_data:
                    stable_count = 0
                    continue  # not ready yet

                # Extract ensemble
                ens_obj = mux_data.get("ensemble", {})
                ens_lbl = ens_obj.get("label", {})
                ensemble = {
                    "ensembleLabel": (ens_lbl.get("label", "") or
                                     ens_lbl.get("shortlabel", "")).strip(),
                    "snr": mux_data.get("demodulator", {}).get("snr", 0),
                }

                # Build candidate service list from this poll
                candidate = []
                for svc in mux_data.get("services", []):
                    lbl  = svc.get("label", {})
                    name = (lbl.get("label", "") or lbl.get("shortlabel", "")).strip()
                    if not name:
                        continue
                    bitrate  = 0
                    is_audio = False
                    for c in svc.get("components", []):
                        if c.get("transportmode") == "audio":
                            is_audio = True
                            bitrate  = c.get("subchannel", {}).get("bitrate", 0)
                            break
                    if not is_audio and svc.get("components"):
                        continue  # data-only service
                    stereo = svc.get("channels", 1) > 1
                    active = svc.get("audiolevel", {}).get("left", -1) >= 0
                    candidate.append({
                        "name":    name,
                        "label":   lbl.get("label", name).strip(),
                        "sid":     svc.get("sid", ""),
                        "bitrate": bitrate,
                        "stereo":  stereo,
                        "mode":    svc.get("mode", ""),
                        "ok":      active,
                    })

                if len(candidate) == len(services) and candidate:
                    stable_count += 1
                else:
                    stable_count = 0
                    services = candidate

                elapsed = time.time() - scan_start
                if candidate and elapsed >= MIN_WAIT and stable_count >= STABLE_NEEDED:
                    services = candidate
                    break  # list is stable — done
            except Exception:
                stable_count = 0

        if not services:
            # Return full stderr for diagnosis
            err_detail = stderr_lines[-10:] if stderr_lines else ["(no stderr output)"]
            return jsonify({
                "error": f"No services found on channel {channel}",
                "debug_stderr": err_detail,
                "debug_cmd": cmd,
                "available_urls": available_urls,
                "hint": "Check signal and see debug_stderr + available_urls"
            }), 404

        return jsonify({
            "channel":  channel,
            "ensemble": ensemble.get("ensembleLabel") or ensemble.get("name", channel),
            "snr":      round(float(ensemble.get("snr", 0)), 1),
            "services": sorted(services, key=lambda s: s["name"].lower()),
        })

    except Exception as e:
        return jsonify({"error": f"Scan failed: {e}"}), 500

    finally:
        if proc:
            try: proc.terminate()
            except: pass
            try: proc.wait(timeout=3)
            except: proc.kill()



