# ─── Metric history API ───────────────────────────────────────────────────────

@app.get("/api/metrics/<path:stream_name>")
@login_required
def api_metrics(stream_name):
    """Return time-series data for one metric on one stream.

    Query params:
        metric  — metric name, e.g. level_dbfs, fm_signal_dbm, dab_snr (required)
        hours   — how many hours of history to return (default 24, max 168 / 7 days)

    Response:
        {"stream": "...", "metric": "...", "hours": 24,
         "points": [[ts, value], ...],
         "available_metrics": [...]}
    """
    metric = request.args.get("metric", "").strip()
    try:
        hours = min(float(request.args.get("hours", 24)), 168.0)
    except ValueError:
        hours = 24.0

    available = metrics_db.available_metrics(stream_name)

    if not metric:
        return jsonify({"stream": stream_name, "metric": None, "hours": hours,
                        "points": [], "available_metrics": available})

    points = metrics_db.query(stream_name, metric, hours)
    return jsonify({
        "stream":            stream_name,
        "metric":            metric,
        "hours":             hours,
        "points":            points,        # [[ts, value], ...]
        "available_metrics": available,
    })


@app.get("/api/timeline/<path:stream_name>")
@login_required
def api_timeline(stream_name):
    """Return a bucketed availability/silence timeline for one stream.

    Query params:
        hours  — hours of history (default 24, max 168)

    Response:
        {"stream": "...", "hours": 24, "bucket_secs": 300,
         "segments": [[ts, "ok"|"silence"|"dab_missing"|"nodata"], ...]}

    Buckets are coloured by the average level_dbfs in that window:
        nodata       — no metric rows in bucket
        silence      — avg level_dbfs < -80 dBFS (includes startup floor of -120)
        dab_missing  — DAB stream with avg dab_ok < 0.5
        ok           — signal present
    """
    try:
        hours = min(float(request.args.get("hours", 24)), 168.0)
    except ValueError:
        hours = 24.0

    bucket_secs = 60 if hours <= 2 else (300 if hours <= 12 else 900)
    now   = time.time()
    since = now - hours * 3600
    n_buckets = max(1, int(hours * 3600 / bucket_secs))

    level_pts = metrics_db.query(stream_name, "level_dbfs", hours)
    dab_pts   = metrics_db.query(stream_name, "dab_ok",     hours)

    # Accumulate sums per bucket
    sum_level = [0.0] * n_buckets
    cnt_level = [0]   * n_buckets
    sum_dab   = [0.0] * n_buckets
    cnt_dab   = [0]   * n_buckets

    for ts, val in level_pts:
        idx = int((ts - since) / bucket_secs)
        if 0 <= idx < n_buckets:
            sum_level[idx] += val
            cnt_level[idx] += 1

    for ts, val in dab_pts:
        idx = int((ts - since) / bucket_secs)
        if 0 <= idx < n_buckets:
            sum_dab[idx] += val
            cnt_dab[idx] += 1

    segments = []
    for i in range(n_buckets):
        ts = since + i * bucket_secs
        if cnt_level[i] == 0:
            status = "nodata"
        elif (sum_level[i] / cnt_level[i]) < -80.0:
            status = "silence"
        elif cnt_dab[i] > 0 and (sum_dab[i] / cnt_dab[i]) < 0.5:
            status = "dab_missing"
        else:
            status = "ok"
        segments.append([round(ts, 1), status])

    return jsonify({
        "stream":      stream_name,
        "hours":       hours,
        "bucket_secs": bucket_secs,
        "segments":    segments,
    })


@app.get("/api/trend/<path:stream_name>")
@login_required
def api_trend(stream_name):
    """Return trend analysis for a stream using a day-of-week + hour-of-day baseline.

    Strategy:
      1. Try (dow, hour) cell from 28-day baseline — if n >= MIN_SAMPLES use it.
      2. Fall back to hour-only cell from 14-day baseline if dow+hour is sparse.
      3. If neither has enough data, return "insufficient_data".

    Also computes a sustained_minutes score: how many consecutive minutes in the
    last 30 minutes have been deviating in the same direction at >1.5σ.
    A sustained deviation is more operationally significant than a single point.

    Response:
        {"stream": "...", "current_dow": 1, "current_hour": 14,
         "current_level": -14.2,
         "baseline": {"mean": -13.5, "std": 1.1, "n": 42},
         "baseline_type": "dow_hour" | "hour_only",
         "status": "normal"|"lower_than_usual"|"higher_than_usual"|"insufficient_data",
         "deviation": -0.64,
         "sustained_minutes": 12,
         "baselines": {"0_0": {...}, ...}   // all (dow,hour) cells, keys as "dow_hour"
        }
    """
    MIN_SAMPLES   = 10
    SUSTAIN_MINS  = 30   # look-back window for duration scoring
    lt = time.localtime()
    current_dow  = lt.tm_wday + 1 if lt.tm_wday < 6 else 0  # Mon=1…Sat=6, Sun=0 (match SQLite %w)
    current_hour = lt.tm_hour

    # Fetch both baseline tables in parallel (both are fast SQLite GROUP BY queries)
    dow_baselines  = metrics_db.dow_hourly_baseline(stream_name, "level_dbfs", days=28)
    hour_baselines = metrics_db.hourly_baseline(stream_name,     "level_dbfs", days=14)
    current_level  = metrics_db.last_value(stream_name, "level_dbfs")

    # Pick best available baseline for this moment
    dow_cell  = dow_baselines.get((current_dow, current_hour))
    hour_cell = hour_baselines.get(current_hour)

    if dow_cell and dow_cell["n"] >= MIN_SAMPLES:
        hour_data      = dow_cell
        baseline_type  = "dow_hour"
    elif hour_cell and hour_cell["n"] >= MIN_SAMPLES:
        hour_data      = hour_cell
        baseline_type  = "hour_only"
    else:
        hour_data      = hour_cell or dow_cell  # may be None
        baseline_type  = "insufficient"

    status    = "insufficient_data"
    deviation = None

    if (hour_data and hour_data["n"] >= MIN_SAMPLES
            and current_level is not None and current_level > -80.0):
        mean      = hour_data["mean"]
        std       = max(hour_data["std"], 0.5)
        deviation = (current_level - mean) / std
        if deviation < -1.5:
            status = "lower_than_usual"
        elif deviation > 1.5:
            status = "higher_than_usual"
        else:
            status = "normal"

    # Sustained deviation scoring — count consecutive minutes all deviating same way
    sustained_minutes = 0
    if status in ("lower_than_usual", "higher_than_usual") and hour_data:
        mean = hour_data["mean"]
        std  = max(hour_data["std"], 0.5)
        recent = metrics_db.recent_values(stream_name, "level_dbfs", minutes=SUSTAIN_MINS)
        # recent is newest-first; walk from newest backward counting sustained direction
        direction = 1 if status == "higher_than_usual" else -1
        prev_ts = None
        for ts, val in recent:
            if val <= -80.0:
                break   # silence floor interrupts the streak
            dev = (val - mean) / std
            if dev * direction < 1.5:
                break   # deviation ended
            if prev_ts is None:
                sustained_minutes = 1
            else:
                gap = prev_ts - ts
                sustained_minutes += max(1, round(gap / 60))
            prev_ts = ts

    # Serialise dow_baselines with string keys (JSON doesn't allow tuple keys)
    dow_baselines_serial = {
        f"{d}_{h}": v for (d, h), v in dow_baselines.items()
    }

    return jsonify({
        "stream":            stream_name,
        "current_dow":       current_dow,
        "current_hour":      current_hour,
        "current_level":     round(current_level, 1) if current_level is not None else None,
        "baseline":          hour_data,
        "baseline_type":     baseline_type,
        "status":            status,
        "deviation":         round(deviation, 2) if deviation is not None else None,
        "sustained_minutes": sustained_minutes,
        "baselines":         dow_baselines_serial,
    })


# ─── Reports routes ───────────────────────────────────────────────────────────

@app.get("/reports")
@login_required
def reports():
    events = _alert_log_load_with_feedback(2000)
    # Summary counts
    counts = {}
    for e in events:
        counts[e.get("type","")] = counts.get(e.get("type",""), 0) + 1
    streams = sorted(set(e.get("stream","") for e in events if e.get("stream")))
    types   = sorted(set(e.get("type","")   for e in events if e.get("type")))
    with_clips = sum(1 for e in events if e.get("clip"))
    return render_template_string(REPORTS_TPL,
        events=events, total=len(events), counts=counts,
        streams=streams, types=types, with_clips=with_clips, build=BUILD)

@app.get("/reports/data")
@login_required
def reports_data():
    """JSON endpoint for the reports page live refresh — returns events + summary counts."""
    events = _alert_log_load_with_feedback(2000)
    counts = {}
    for e in events:
        counts[e.get("type","")] = counts.get(e.get("type",""), 0) + 1
    with_clips = sum(1 for e in events if e.get("clip"))
    return jsonify({
        "events":     events,
        "total":      len(events),
        "counts":     counts,
        "with_clips": with_clips,
    })

@app.get("/reports.csv")
@login_required
def reports_csv():
    events = _alert_log_load(10000)
    cols = ["ts","stream","type","message","level_dbfs","rtp_loss_pct",
            "ptp_state","ptp_offset_us","ptp_drift_us","ptp_jitter_us","ptp_gm","clip"]
    lines = [",".join(cols)]
    for e in events:
        lines.append(",".join(
            f'"{str(e.get(c,"")).replace(chr(34), chr(39))}"' for c in cols
        ))
    return Response("\n".join(lines), mimetype="text/csv",
        headers={"Content-Disposition": f'attachment; filename="alerts_{time.strftime("%Y%m%d_%H%M")}.csv"'})

@app.post("/reports/clear")
@login_required
@csrf_protect
def reports_clear():
    try:
        with _alert_log_lock:
            open(ALERT_LOG_PATH, "w").close()
        # Also clear in-memory history
        for inp in monitor.app_cfg.inputs:
            inp._history.clear()
        flash("Alert log cleared.")
    except Exception as e:
        flash(f"Clear failed: {e}")
    return redirect(url_for("reports"))

# ─── Hub API routes (active when mode == hub or both) ────────────────────────

@app.post(f"/api/{HUB_API_VERSION}/heartbeat")
def hub_heartbeat():
    cfg    = monitor.app_cfg
    secret = cfg.hub.secret_key
    if cfg.hub.mode not in ("hub","both"):
        return jsonify({"error":"not a hub"}), 404

    # ── Rate limiting ─────────────────────────────────────────────────────────
    # Key by X-Forwarded-For if set (reverse proxy), else remote_addr
    # Site name extracted post-decryption for accurate per-site limiting
    forwarded = request.headers.get("X-Forwarded-For", "")
    client_ip = forwarded.split(",")[0].strip() if forwarded else (request.remote_addr or "")

    # ── Read raw body (may be encrypted) ─────────────────────────────────────
    raw_body = request.get_data()

    # ── Signature + timestamp verification (if secret configured) ────────────
    if secret:
        sig   = request.headers.get("X-Hub-Sig","")
        ts_h  = request.headers.get("X-Hub-Ts","0")
        nonce = request.headers.get("X-Hub-Nonce","")

        if not sig or not nonce:
            return jsonify({"error":"missing security headers"}), 403

        try:
            ts = float(ts_h)
        except ValueError:
            return jsonify({"error":"invalid timestamp"}), 403

        # Replay check
        if not hub_nonce_store.check_and_store(nonce):
            return jsonify({"error":"replay detected"}), 403

        # Decrypt if Content-Type says octet-stream
        ct = request.content_type or ""
        if "octet-stream" in ct:
            try:
                raw_body = hub_decrypt_payload(secret, raw_body)
            except Exception as e:
                return jsonify({"error":f"decryption failed: {e}"}), 403

        # Verify HMAC over decrypted body
        ok, reason = hub_verify_signature(secret, raw_body, sig, ts)
        if not ok:
            print(f"[HubSec] Signature rejected from {client_ip}: {reason}")
            return jsonify({"error":"forbidden","reason":reason}), 403

    # ── Parse JSON payload ────────────────────────────────────────────────────
    try:
        payload = json.loads(raw_body) if raw_body else {}
    except Exception:
        return jsonify({"error":"bad json"}), 400

    # ── Rate limiting — keyed by site name for accuracy across NAT ───────────
    # Use site name from payload (more reliable than IP when clients share NAT)
    site_key = payload.get("site", "") or client_ip
    if not hub_rate_limiter.allow(site_key):
        return jsonify({"error":"rate limit exceeded"}), 429

    # ── Ingest ────────────────────────────────────────────────────────────────
    hub_server.set_secret(secret)
    ingest_status = hub_server.ingest(payload, client_ip=client_ip)

    site_name = payload.get("site","")

    # ── Scanner RDS — client piggybacks RDS data on the heartbeat ────────────
    _scanner_rds = payload.get("scanner_rds")
    if isinstance(_scanner_rds, dict) and site_name and hub_server:
        _sess = hub_server._scanner_sessions.get(site_name)
        # Update session RDS whenever any real RDS field is present.
        # Fields prefixed with "_" (e.g. "_level") are internal and don't
        # count — previously only "ps" or "rt" were checked, which caused
        # stereo / tp / ta to be dropped when they arrived before any PS/RT.
        if _sess and any(k for k in _scanner_rds if not k.startswith("_")):
            _sess["rds"] = _scanner_rds

    # ── Post-update comeback detection ────────────────────────────────────────
    # If we pushed a self_update to this site, watch for its first heartbeat
    # after the restart.  When detected: push a 'start' command so monitoring
    # resumes, then wait 60 seconds for audio levels to settle before clearing
    # the auto-maintenance entries that were set when the update was triggered.
    if hub_server and site_name and site_name in hub_server._pending_updates:
        pushed_at  = hub_server._pending_updates[site_name]
        site_data  = hub_server._sites.get(site_name, {})
        came_back  = (
            site_data.get("online")
            and float(site_data.get("_received", 0)) > pushed_at
        )
        if came_back:
            del hub_server._pending_updates[site_name]
            # Push start so monitoring resumes immediately after the restart
            hub_server.push_pending_command(site_name, {"type": "start"})
            monitor.log(
                f"[Hub] Site '{site_name}' back online after update — "
                f"'start' command queued; maintenance clears in 60 s"
            )
            def _clear_maint_after_cooldown(sn: str = site_name) -> None:
                time.sleep(60)
                _set_site_chain_maintenance(sn, duration=0)
                monitor.log(f"[Hub] Auto-maintenance cleared for site '{sn}' (60-second post-update cooldown elapsed)")
            threading.Thread(
                target=_clear_maint_after_cooldown,
                daemon=True,
                name=f"UpdateMaintClear-{site_name}",
            ).start()

    # Pending approval — acknowledge receipt but send no commands
    if ingest_status == "pending":
        ack = {"ok": True, "status": "pending_approval",
               "message": "This site is awaiting approval on the hub dashboard."}
        ack_bytes = json.dumps(ack).encode()
        if secret:
            enc = hub_encrypt_payload(secret, ack_bytes)
            return Response(enc, content_type="application/octet-stream")
        return jsonify(ack)

    # ── Build ACK — encrypt if secret is set ─────────────────────────────────
    listen_reqs   = listen_registry.pending_for_site(site_name)
    relay_bitrate = hub_server.get_relay_bitrate(site_name)
    pending_cmds  = hub_server.pop_all_pending_commands(site_name)  # flush whole queue at once
    _site_rules   = cfg.hub_site_rules.get(site_name, {}) if isinstance(getattr(cfg, "hub_site_rules", None), dict) else {}
    _low_bw_ack   = bool(_site_rules.get("low_bw", False))
    ack = {"ok": True, "listen_requests": listen_reqs, "relay_bitrate": relay_bitrate, "low_bw": _low_bw_ack}
    if pending_cmds:
        # "commands" list — client processes all in one heartbeat cycle
        ack["commands"] = pending_cmds
        # "command" (singular) kept for backwards compat with older client builds
        ack["command"] = pending_cmds[0]
    ack_bytes = json.dumps(ack).encode()

    if secret:
        enc = hub_encrypt_payload(secret, ack_bytes)
        return Response(enc, content_type="application/octet-stream")
    return jsonify(ack)

@app.post("/hub/clip_upload")
def hub_clip_upload():
    """Receive a WAV clip (base64) uploaded from a client.

    Clips from any alert type (silence, clipping, hiss, RTP loss, chain fault,
    etc.) are saved into alert_snippets/<site>_<stream>/ on the hub so they can
    be played back locally from the hub's Reports page without streaming.
    """
    cfg    = monitor.app_cfg
    secret = cfg.hub.secret_key
    if cfg.hub.mode not in ("hub", "both"):
        return jsonify({"error": "not a hub"}), 404

    if not secret:
        return jsonify({"error": "forbidden"}), 403

    _MAX_CLIP_BYTES = 10 * 1024 * 1024  # 10 MB
    if request.content_length and request.content_length > _MAX_CLIP_BYTES:
        return jsonify({"error": "payload too large"}), 413

    raw_body = request.get_data()
    if secret:
        sig  = request.headers.get("X-Hub-Sig", "")
        ts_h = request.headers.get("X-Hub-Ts", "0")
        try:
            ts = float(ts_h)
        except ValueError:
            return jsonify({"error": "invalid timestamp"}), 403
        ct = request.content_type or ""
        if "octet-stream" in ct:
            try:
                raw_body = hub_decrypt_payload(secret, raw_body)
            except Exception as e:
                return jsonify({"error": f"decryption failed: {e}"}), 403
        ok, reason = hub_verify_signature(secret, raw_body, sig, ts)
        if not ok:
            return jsonify({"error": "forbidden", "reason": reason}), 403

    try:
        data = json.loads(raw_body)
    except Exception:
        return jsonify({"error": "bad json"}), 400

    site       = str(data.get("site",       "unknown")).strip()
    stream     = str(data.get("stream",     "unknown")).strip()
    label      = str(data.get("label",      "clip")).strip()
    chain_name = str(data.get("chain_name", "")).strip()
    chain_id   = str(data.get("chain_id",   "")).strip()
    entry_id   = str(data.get("entry_id",   "")).strip()
    node_label = str(data.get("node_label", "")).strip()
    clip_pos   = data.get("pos", None)
    clip_status= str(data.get("status",     "")).strip()
    data_b64   = data.get("data_b64", "")
    level_dbfs = data.get("level_dbfs", None)
    clip_ts    = data.get("ts", time.time())
    clip_ext   = str(data.get("ext", "wav")).strip(".")
    if clip_ext not in ("wav", "mp3"):
        clip_ext = "wav"
    # Client sends its original filename (includes stream name + embedded timestamp).
    # Sanitise and use it directly so the hub file matches what the operator sees
    # when they open the folder on the client.  Fall back to the legacy
    # {label}_{ts}.{ext} format for older clients that don't send this field.
    _raw_fname = str(data.get("filename", "")).strip()
    _raw_fname = os.path.basename(_raw_fname)   # strip any path components
    # Allow only safe filename characters
    import re as _re
    _raw_fname = _re.sub(r"[^a-zA-Z0-9._\-]", "_", _raw_fname)
    if _raw_fname and _raw_fname.endswith(f".{clip_ext}"):
        client_filename = _raw_fname
        # Try to recover the original clip time from the embedded timestamp
        # (format: YYYYMMDD-HHMMSS_StreamName_alerttype.ext)
        try:
            clip_ts = time.mktime(time.strptime(_raw_fname.split("_")[0], "%Y%m%d-%H%M%S"))
        except Exception:
            pass  # keep sender's ts
    else:
        client_filename = ""

    if not data_b64:
        return jsonify({"error": "no clip data"}), 400
    try:
        wav_bytes = base64.b64decode(data_b64)
    except Exception:
        return jsonify({"error": "bad base64"}), 400

    # Derive a human-readable alert type from the label
    _lbl_lower = label.lower()
    if "silence" in _lbl_lower:
        _alert_type = "SILENCE"
    elif "clip" in _lbl_lower and "chain" not in _lbl_lower:
        _alert_type = "CLIP_DISTORTION"
    elif "hiss" in _lbl_lower:
        _alert_type = "HISS"
    elif "rtp_loss" in _lbl_lower:
        _alert_type = "RTP_LOSS"
    elif "lufs_tp" in _lbl_lower:
        _alert_type = "LUFS_TP_EXCEEDED"
    elif "lufs_i" in _lbl_lower:
        _alert_type = "LUFS_INTEGRATED_EXCEEDED"
    elif "ai_" in _lbl_lower:
        _alert_type = "AI_ANOMALY"
    elif "compare" in _lbl_lower:
        _alert_type = "COMPARATOR"
    elif "glitch" in _lbl_lower:
        _alert_type = "GLITCH"
    else:
        _alert_type = "CHAIN_FAULT"

    # Save under alert_snippets/<site>_<stream>/ on the hub.
    # Use the sender's timestamp so the filename is stable across retries.
    safe_key = f"{_safe_name(site)}_{_safe_name(stream)}"
    out_dir  = os.path.join(BASE_DIR, "alert_snippets", safe_key)
    os.makedirs(out_dir, exist_ok=True)
    # Use the client's original filename when available (contains stream name +
    # embedded timestamp).  Fall back to the legacy format for older clients.
    fname = client_filename if client_filename else f"{label}_{int(clip_ts)}.{clip_ext}"
    fpath = os.path.join(out_dir, fname)
    if not os.path.exists(fpath):   # idempotent — don't overwrite on retry
        with open(fpath, "wb") as f:
            f.write(wav_bytes)
        monitor.log(f"[Hub] Clip saved: {safe_key}/{fname} ({len(wav_bytes)//1024} KB)")

    # Write to hub alert log so it appears on the Reports page.
    # Use the client's original entry_id (sent in the upload payload) so that
    # hub_reports() seen_ids deduplication suppresses this entry when the same
    # event is already present in the site's recent_alerts heartbeat data.
    # Generating a fresh UUID here (the old behaviour) caused every uploaded
    # clip to appear twice — once from recent_alerts (site row) and again from
    # the hub alert log (hub row).
    _alert_log_append({
        "id":            entry_id if entry_id else str(uuid.uuid4()),
        "ts":            time.strftime("%Y-%m-%d %H:%M:%S", time.localtime(clip_ts)),
        "stream":        f"{site} / {stream}",
        "type":          _alert_type,
        "message":       (f"Remote clip from '{site}' — '{stream}'"
                          + (f" (chain: {chain_name})" if chain_name else "") + "."),
        "level_dbfs":    level_dbfs,
        "rtp_loss_pct":  None,
        "rtp_jitter_ms": None,
        "clip":          fname,
        "ptp_state":     "",
        "ptp_offset_us": 0,
        "ptp_drift_us":  0,
        "ptp_jitter_us": 0,
        "ptp_gm":        "",
    })
    # Link clip back to the correct fault log entry for this chain.
    # entry_id is the UUID assigned when the fault fired — use it to find the
    # right entry directly.  If the client is older and didn't send entry_id,
    # fall back to flog[-1] as before.
    #
    # IMPORTANT: wrap the entire back-patch in try/except so that ANY exception
    # here (e.g. hub_server temporarily None at startup, DB contention, etc.)
    # does NOT cause a 500 response.  A 500 means the client never writes its
    # .hub marker, retries indefinitely, and adds duplicate Reports entries on
    # every retry while fault history stays empty forever.  The clip is already
    # safely on disk — a back-patch failure is recoverable; a 500 loop is not.
    if chain_id:
        if hub_server is None:
            monitor.log(f"[Hub] Clip back-patch skipped: hub_server not ready "
                        f"(chain_id={chain_id!r} {safe_key}/{fname})")
        else:
            try:
                # Derive a consistent clip label
                if clip_status in ("fault", "last_good"):
                    _clip_label = clip_status
                elif "last_good" in label:
                    _clip_label = "last_good"
                elif "fault" in label:
                    _clip_label = "fault"
                else:
                    _clip_label = label  # e.g. "pos0", "pos2"
                _clip_entry = {
                    "key":        safe_key,
                    "fname":      fname,
                    "label":      _clip_label,
                    "node_label": node_label or stream,
                    "pos":        clip_pos,
                    "status":     clip_status or _clip_label,
                }
                flog = hub_server._chain_fault_log.get(chain_id, [])
                monitor.log(f"[Hub] Clip back-patch: chain_id={chain_id!r} entry_id={entry_id!r} "
                            f"flog_len={len(flog)} known_chains={list(hub_server._chain_fault_log.keys())}")
                if flog:
                    if entry_id:
                        _target = next((e for e in reversed(flog) if e.get("id") == entry_id), None)
                        if _target is None:
                            flog_ids = [e.get("id","?") for e in flog]
                            monitor.log(f"[Hub] Clip back-patch: entry_id {entry_id!r} not found in "
                                        f"flog[{len(flog)}] ids={flog_ids} — falling back to flog[-1]")
                            _target = flog[-1]
                        else:
                            monitor.log(f"[Hub] Clip back-patch: matched entry_id {entry_id!r} directly")
                    else:
                        _target = flog[-1]
                        monitor.log(f"[Hub] Clip back-patch: no entry_id — using flog[-1] "
                                    f"id={_target.get('id','?')!r}")
                    if _target:
                        clips = _target.setdefault("clips", [])
                        clips.append(_clip_entry)
                        metrics_db.fault_log_update_clips(_target.get("id", ""), clips)
                        monitor.log(f"[Hub] Clip back-patched to fault log entry "
                                    f"{_target.get('id', '?')!r} for chain {chain_id!r} "
                                    f"({safe_key}/{fname}) — entry now has {len(clips)} clip(s)")
                else:
                    monitor.log(f"[Hub] Clip back-patch: flog EMPTY for chain {chain_id!r} — "
                                f"attempting DB fallback (entry_id={entry_id!r})")
                    _db_entries = metrics_db.fault_log_load(chain_id, limit=10)
                    monitor.log(f"[Hub] Clip back-patch DB fallback: found "
                                f"{len(_db_entries)} DB entries for chain {chain_id!r}")
                    if _db_entries:
                        if entry_id:
                            _db_target = next(
                                (e for e in reversed(_db_entries) if e.get("id") == entry_id), None)
                            if _db_target is None:
                                monitor.log(f"[Hub] Clip back-patch DB: entry_id {entry_id!r} "
                                            f"not found — falling back to most recent DB entry")
                                _db_target = _db_entries[-1]
                            else:
                                monitor.log(f"[Hub] Clip back-patch DB: matched entry_id {entry_id!r}")
                        else:
                            _db_target = _db_entries[-1]
                            monitor.log(f"[Hub] Clip back-patch DB: no entry_id — using most recent "
                                        f"DB entry id={_db_target.get('id','?')!r}")
                        if _db_target:
                            _db_clips = list(_db_target.get("clips") or [])
                            _db_clips.append(_clip_entry)
                            metrics_db.fault_log_update_clips(_db_target.get("id", ""), _db_clips)
                            monitor.log(f"[Hub] Clip written directly to DB for entry "
                                        f"{_db_target.get('id', '?')!r} (chain {chain_id!r}) "
                                        f"— entry now has {len(_db_clips)} clip(s)")
                            # Restore into in-memory flog so overlay works immediately
                            _new_flog = metrics_db.fault_log_load(chain_id, limit=25)
                            if _new_flog:
                                hub_server._chain_fault_log[chain_id] = _new_flog
                                monitor.log(f"[Hub] Restored {len(_new_flog)} entries to "
                                            f"in-memory flog for chain {chain_id!r}")
                    else:
                        monitor.log(f"[Hub] Clip back-patch FAILED: no DB entries for chain "
                                    f"{chain_id!r} — clip saved to disk only ({safe_key}/{fname})")
            except Exception as _bp_err:
                monitor.log(f"[Hub] Clip back-patch ERROR (chain {chain_id!r} "
                            f"entry {entry_id!r}): {_bp_err} — clip is saved, "
                            f"fault history link failed")
    else:
        monitor.log(f"[Hub] Clip received without chain_id — saved to Reports only "
                    f"({safe_key}/{fname}). This clip will NOT appear in fault history.")

    monitor.log(f"[Hub] Clip upload received: {site}/{stream}/{label} "
                f"({len(wav_bytes) // 1024}KB → {fname})")
    return jsonify({"ok": True, "saved": fname})


@app.post("/hub/backup_upload")
def hub_backup_upload():
    """Receive a full backup ZIP uploaded from a client site.

    The client POSTs raw ZIP bytes with X-Hub-Sig / X-Hub-Ts HMAC headers.
    The site name is identified via the X-Hub-Site header (or falls back to the
    'site' field in the payload, but since this is binary ZIP we use the header).
    The hub writes the latest backup to HUB_BACKUP_DIR/<site>/backup.zip and
    exposes it via GET /api/hub/site/<name>/backup for download.
    """
    cfg    = monitor.app_cfg
    secret = cfg.hub.secret_key
    if cfg.hub.mode not in ("hub", "both"):
        return jsonify({"error": "not a hub"}), 404

    if not secret:
        return jsonify({"error": "forbidden"}), 403

    raw_body = request.get_data()
    site_name = request.headers.get("X-Hub-Site", "").strip()

    if secret:
        sig   = request.headers.get("X-Hub-Sig", "")
        ts_h  = request.headers.get("X-Hub-Ts", "0")
        nonce = request.headers.get("X-Hub-Nonce", "")
        try:
            ts = float(ts_h)
        except ValueError:
            return jsonify({"error": "invalid timestamp"}), 403
        if not hub_nonce_store.check_and_store(nonce):
            return jsonify({"error": "replay detected"}), 403
        ok, reason = hub_verify_signature(secret, raw_body, sig, ts)
        if not ok:
            return jsonify({"error": "forbidden", "reason": reason}), 403

    if not site_name:
        return jsonify({"error": "missing X-Hub-Site header"}), 400

    if not hub_server or not hub_server._sites.get(site_name, {}).get("_approved"):
        return jsonify({"error": "forbidden"}), 403

    # Cap per-site backup at 200 MB
    MAX_BACKUP_BYTES = 200 * 1024 * 1024
    if len(raw_body) > MAX_BACKUP_BYTES:
        return jsonify({"error": "backup too large (>200 MB)"}), 413

    hub_server.set_secret(secret)
    hub_server.save_backup_to_disk(site_name, raw_body)
    return jsonify({"ok": True})


