@app.get("/hub")
@login_required
def hub_dashboard():
    cfg = monitor.app_cfg
    if cfg.hub.mode not in ("hub","both"):
        return "This instance is not configured as a hub. Set mode to 'hub' or 'both' in Settings.", 404
    hub_server.set_secret(cfg.hub.secret_key)
    wall_mode = str(request.args.get("wall", "")).strip().lower() in ("1", "true", "yes", "on")
    problems_only = str(request.args.get("problems", "")).strip().lower() in ("1", "true", "yes", "on")
    sites = hub_server.get_sites()
    sites = _filter_sites(sites)
    for s in sites:
        streams = s.get("streams", [])
        if not s.get("_approved", True):
            s["site_status"] = "WARN"   # pending sites use WARN colour (amber border)
            # Detect pre-approval-era builds so the hub can prompt an update
            import re as _re
            _bm = _re.search(r'SignalScope-(\d+)\.(\d+)\.(\d+)', s.get("build", "") or "")
            s["_needs_update"] = tuple(int(x) for x in _bm.groups()) < (3, 0, 3) if _bm else True
        elif not s["online"]:
            s["site_status"] = "offline"
        elif any("ALERT" in st.get("ai_status","") for st in streams):
            s["site_status"] = "ALERT"
        elif any("WARN" in st.get("ai_status","") for st in streams):
            s["site_status"] = "WARN"
        else:
            s["site_status"] = "OK"
        for st in streams:
            ai = st.get("ai_status","") or ""
            if "ALERT" in ai:
                st["_sort_pri"] = 0
            elif "WARN" in ai:
                st["_sort_pri"] = 1
            else:
                st["_sort_pri"] = 2
        streams.sort(key=lambda st: (st.get("_sort_pri", 2), st.get("name","").lower()))
        s["alert_count"] = sum(1 for st in streams if "ALERT" in (st.get("ai_status","") or ""))
        s["warn_count"]  = sum(1 for st in streams if "WARN" in (st.get("ai_status","") or ""))
        s["ok_count"]    = max(0, len(streams) - s["alert_count"] - s["warn_count"])
        s["problem_count"] = s["alert_count"] + s["warn_count"]
        # Guarantee fields the template accesses unconditionally so a newly-
        # approved site (stub only, no full heartbeat yet) never causes a 500.
        s.setdefault("streams",     [])
        s.setdefault("running",     False)
        s.setdefault("comparators", [])
        s.setdefault("ptp", {"state": "—", "offset_us": 0, "drift_us": 0,
                              "jitter_us": 0, "gm_id": "—", "last_sync": None})
    # Annotate each site with backup availability info
    with hub_server._lock:
        _backups_snap  = dict(hub_server._site_backups)
        _ping_snap     = dict(hub_server._ping_results)
    for s in sites:
        bk = _backups_snap.get(s.get("site", ""))
        s["_backup_ts"]   = bk["ts"]   if bk else None
        s["_backup_size"] = bk["size"] if bk else None
        s["_backup_age_s"] = round(time.time() - bk["ts"]) if bk else None
        pr = _ping_snap.get(s.get("site", ""))
        s["_ping_result"] = pr if pr else None

    if problems_only:
        # Always show pending sites — they always need attention
        sites = [s for s in sites if not s.get("_approved", True) or (not s.get("online")) or s.get("problem_count", 0) > 0]
    def _site_sort_key(s):
        status = s.get("site_status")
        pri = 0 if status == "offline" else 1 if status == "ALERT" else 2 if status == "WARN" else 3
        return (pri, -(s.get("problem_count", 0)), -(s.get("age_s", 0)), s.get("site","").lower())
    sites = sorted(sites, key=_site_sort_key)
    offline_count = sum(1 for s in sites if not s.get("online"))
    alert_site_count = sum(1 for s in sites if s.get("site_status") == "ALERT")
    warn_site_count = sum(1 for s in sites if s.get("site_status") == "WARN")
    stale_count = sum(1 for s in sites if s.get("online") and float(s.get("age_s", 0) or 0) >= HUB_HEARTBEAT_INTERVAL * 2)
    def _ago(s):
        s = int(s or 0)
        if s < 5:   return "just now"
        if s < 60:  return f"{s}s ago"
        return f"{s//60}m ago"
    def _fmt(ts):
        if not ts: return "—"
        return time.strftime("%H:%M:%S", time.localtime(ts))
    def _ai_class(s):
        s = s or ""
        if "ALERT" in s: return "ai-al"
        if "WARN"  in s: return "ai-wn"
        return "ai-ok"
    def _rtp_class(p):
        p = float(p or 0)
        if p >= 2:   return "rtp-al"
        if p >= 0.5: return "rtp-wn"
        return "rtp-ok"
    
    hub_cpu=None
    hub_mem=None
    try:
        import psutil
        hub_cpu=psutil.cpu_percent()
        hub_mem=psutil.virtual_memory().percent
    except Exception:
        pass

    if wall_mode:
        # Build chain evaluation results for the wall display
        wall_chains = []
        for chain in (cfg.signal_chains or []):
            try:
                wall_chains.append(hub_server.eval_chain(chain))
            except Exception:
                pass
        return render_template_string(HUB_WALL_TPL, sites=sites, chains=wall_chains,
            build=BUILD, now=time.time(), csp_nonce=_csp_nonce)

    return render_template_string(HUB_TPL, sites=sites, build=BUILD, now=time.time(),
        mode_both=(cfg.hub.mode=="both"), ago=_ago, fmt=_fmt,
        aiClass=_ai_class, rtpClass=_rtp_class,
        wall_mode=wall_mode, problems_only=problems_only,
        offline_count=offline_count, alert_site_count=alert_site_count,
        warn_site_count=warn_site_count, stale_count=stale_count, hub_cpu=hub_cpu, hub_mem=hub_mem,
    )

@app.post(f"/api/{HUB_API_VERSION}/audio_chunk/<slot_id>")
def hub_audio_chunk(slot_id):
    """Receive a signed audio chunk from a client and feed it to the waiting browser.

    Important: this route must NOT use the normal per-client hub rate limiter.
    Live relay audio arrives as many small POSTs per second, so generic API
    throttling breaks remote listening. Security here comes from:
      - valid relay slot ID
      - relay slot lifetime / expiry
      - signed requests when a hub secret is configured
    """
    cfg    = monitor.app_cfg
    secret = cfg.hub.secret_key
    client_ip = request.remote_addr or ""

    # Verify signature on audio chunks if secret is configured
    if secret:
        sig   = request.headers.get("X-Hub-Sig","")
        ts_h  = request.headers.get("X-Hub-Ts","0")
        nonce = request.headers.get("X-Hub-Nonce","")
        if not sig or not nonce:
            return jsonify({"error":"missing security headers"}), 403
        try:
            ts = float(ts_h)
        except ValueError:
            return jsonify({"error":"invalid timestamp"}), 403
        if not hub_nonce_store.check_and_store(nonce):
            return jsonify({"error":"replay detected"}), 403
        data = request.get_data()
        ok, reason = hub_verify_signature(secret, data, sig, ts)
        if not ok:
            return jsonify({"error":"forbidden","reason":reason}), 403
    else:
        data = request.get_data()

    slot = listen_registry.get(slot_id)
    if not slot:
        return jsonify({"error": "slot not found or expired"}), 404
    if data:
        slot.put(data)
        # Update RTT EMA so the relay generator can auto-tune keepalive threshold.
        rtt_hdr = request.headers.get("X-Client-Rtt", "")
        if rtt_hdr:
            try:
                rtt = float(rtt_hdr)
                if 0.01 <= rtt <= 10.0:
                    slot.rtt_ema = (0.2 * rtt + 0.8 * slot.rtt_ema) if slot.rtt_ema else rtt
            except ValueError:
                pass
    else:
        # Empty body = EOF signal from client — close the slot immediately so the
        # relay generator ends right away instead of waiting for the 30-second
        # stale timeout (which trips NGINX proxy_read_timeout when behind a proxy).
        slot.closed = True
    return jsonify({"ok": True, "queued": slot.q.qsize()})


@app.get("/hub/debug")
@login_required
def hub_debug():
    """Diagnostic: show raw stored site data as JSON."""
    cfg = monitor.app_cfg
    if cfg.hub.mode not in ("hub","both"):
        return jsonify({"error":"not a hub"}), 404
    hub_server.set_secret(cfg.hub.secret_key)
    sites = hub_server.get_sites()
    summary = []
    for s in sites:
        summary.append({
            "site":          s.get("site"),
            "online":        s.get("online"),
            "age_s":         s.get("age_s"),
            "running":       s.get("running"),
            "stream_count":  len(s.get("streams",[])),
            "streams":       [{"name": st.get("name"), "enabled": st.get("enabled"),
                               "level": st.get("level_dbfs")} for st in s.get("streams",[])],
            "payload_keys":  list(s.keys()),
        })
    return jsonify(summary)

@app.get("/hub/data")
@login_required
def hub_data():
    """JSON endpoint for hub page live refresh."""
    cfg = monitor.app_cfg
    if cfg.hub.mode not in ("hub","both"):
        return jsonify({"error":"not a hub"}), 404
    hub_server.set_secret(cfg.hub.secret_key)
    sites = hub_server.get_sites()
    sites = _filter_sites(sites)
    _site_rules = cfg.hub_site_rules if isinstance(getattr(cfg, "hub_site_rules", None), dict) else {}
    for s in sites:
        s["low_bw"] = bool(_site_rules.get(s.get("site", ""), {}).get("low_bw", False)) or bool(s.get("low_bw", False))
        streams = s.get("streams", [])
        if not s["online"]:
            s["site_status"] = "offline"
        elif any("ALERT" in st.get("ai_status","") for st in streams):
            s["site_status"] = "ALERT"
        elif any("WARN" in st.get("ai_status","") for st in streams):
            s["site_status"] = "WARN"
        else:
            s["site_status"] = "OK"
        for st in streams:
            ai = st.get("ai_status","") or ""
            if "ALERT" in ai:
                st["_sort_pri"] = 0
            elif "WARN" in ai:
                st["_sort_pri"] = 1
            else:
                st["_sort_pri"] = 2
        streams.sort(key=lambda st: (st.get("_sort_pri", 2), st.get("name","").lower()))
        s["alert_count"] = sum(1 for st in streams if "ALERT" in (st.get("ai_status","") or ""))
        s["warn_count"]  = sum(1 for st in streams if "WARN" in (st.get("ai_status","") or ""))
        s["ok_count"]    = max(0, len(streams) - s["alert_count"] - s["warn_count"])
        s["problem_count"] = s["alert_count"] + s["warn_count"]
    sites = sorted(sites, key=lambda s: (0 if s.get("site_status") == "offline" else 1 if s.get("site_status") == "ALERT" else 2 if s.get("site_status") == "WARN" else 3, -(s.get("problem_count", 0)), s.get("site","").lower()))
    resp = jsonify({"sites": sites, "hub_build": BUILD})
    resp.headers["Cache-Control"] = "no-store, must-revalidate"
    resp.headers["Pragma"] = "no-cache"
    return resp

@app.post("/hub/site/remove/<path:site_name>")
@login_required
@csrf_protect
def hub_remove_site(site_name):
    cfg = monitor.app_cfg
    if cfg.hub.mode not in ("hub","both"):
        return jsonify({"error":"not a hub"}), 404
    removed = False
    with hub_server._lock:
        if site_name in hub_server._sites:
            hub_server._sites.pop(site_name, None)
            removed = True
        snapshot = dict(hub_server._sites)
    threading.Thread(target=hub_server._save_snapshot, args=(snapshot,),
                     daemon=True, name="HubSave").start()
    return jsonify({"ok": True, "removed": removed, "site": site_name})

