@app.get("/chains")
@login_required
def broadcast_chains():
    cfg = monitor.app_cfg
    if cfg.hub.mode not in ("hub", "both"):
        return "Not a hub", 404
    chains    = cfg.signal_chains or []
    ab_groups = cfg.ab_groups or []
    # Resolve chain names for template
    chains_by_id = {c.get("id"): c.get("name", c.get("id","")) for c in chains}
    ab_groups_with_names = []
    for g in ab_groups:
        g2 = dict(g)
        g2["chain_a_name"] = chains_by_id.get(g.get("chain_a_id",""), g.get("chain_a_id",""))
        g2["chain_b_name"] = chains_by_id.get(g.get("chain_b_id",""), g.get("chain_b_id",""))
        ab_groups_with_names.append(g2)
    return render_template_string(BROADCAST_CHAINS_TPL,
                                  chains=chains,
                                  ab_groups=ab_groups_with_names,
                                  all_chains=chains)


@app.get("/api/chains/streams")
@login_required
def api_chains_streams():
    """Return all available site/stream options for the chain node builder."""
    cfg = monitor.app_cfg
    options = []
    # Local streams on this node
    for inp in cfg.inputs:
        if inp.enabled:
            options.append({"site": "local", "site_label": f"This node (local)", "stream": inp.name})
    # Remote hub sites
    if hub_server:
        for site in hub_server.get_sites():
            sname = site.get("site", "")
            for s in site.get("streams", []):
                options.append({"site": sname, "site_label": sname, "stream": s.get("name", "")})
    return jsonify({"options": options})


def _chain_correlate_nodes(node_a: dict, node_b: dict, minutes: int = 60) -> dict:
    """Compute stream-agreement confidence between two chain nodes using metrics history.

    Primary metric: first-difference Pearson correlation (delta_r) on all common
    1-minute level buckets.  Measures whether the *dynamics* (level changes) of
    both streams track together.  This works through AGC and limiting because it
    ignores absolute offsets and tracks only the shape of level movement.

    Secondary metric: raw-level Pearson (raw_r).  Useful for lightly-processed
    streams; blended with delta_r at 60/40 weight.

    Penalty: if both streams genuinely have silence events but disagree on *when*
    they occur (e.g. different programme schedules), the score is penalised by up
    to 50 pp proportional to the fraction of disagreeing buckets.  For continuous
    24/7 broadcast streams (no silence) this penalty is never applied.

    The old ``silence_pct``-as-primary-metric was incorrect: for continuous audio
    both streams are always "active" so silence_pct == 1.0 == 100% regardless of
    whether the streams carry the same content.
    """
    def _key(n):
        site   = n.get("site", "")
        stream = n.get("stream", "")
        return stream if site == "local" else f"{site}/{stream}"

    def _thresh(n):
        if n.get("site") == "local":
            inp = next((i for i in monitor.app_cfg.inputs
                        if i.name == n.get("stream", "")), None)
            return inp.silence_threshold_dbfs if inp else -55.0
        return -55.0

    ka, kb = _key(node_a), _key(node_b)
    ta, tb = _thresh(node_a), _thresh(node_b)

    # ── Local audio comparator shortcut ───────────────────────────────────────
    # If both nodes are on the same remote site, that client is already doing
    # real-time sample-accurate audio cross-correlation locally and reporting it
    # in its heartbeat payload.  Use that data when available — it is far richer
    # than 1-minute averaged levels from metric_history.
    site_a = node_a.get("site", "")
    site_b = node_b.get("site", "")
    if (site_a and site_a != "local" and site_a == site_b
            and hub_server is not None):
        site_data = hub_server._sites.get(site_a, {})
        remote_cmps = site_data.get("comparators", [])
        na = node_a.get("stream", "")
        nb = node_b.get("stream", "")
        matched = next(
            (c for c in remote_cmps
             if (c.get("pre_name") == na and c.get("post_name") == nb)
             or (c.get("pre_name") == nb and c.get("post_name") == na)),
            None
        )
        if matched is not None:
            corr = matched.get("correlation")
            if corr is not None:
                pct = max(0.0, min(100.0, float(corr) * 100.0))
                return {
                    "status":            "local_audio",
                    "r":                 round(float(corr), 3),
                    "pct":               round(pct, 1),
                    "silence_pct":       None,
                    "samples":           None,
                    "delay_ms":          matched.get("delay_ms"),
                    "gain_diff_db":      matched.get("gain_diff_db"),
                    "aligned":           matched.get("aligned"),
                    "processed":         matched.get("processed", False),
                    "compression_ratio": matched.get("compression_ratio"),
                }

    def _pearson_delta(sa, sb):
        """First-difference Pearson of two equal-length lists. Returns None if insufficient variance."""
        if len(sa) < 3: return None
        da = [sa[i+1] - sa[i] for i in range(len(sa)-1)]
        db = [sb[i+1] - sb[i] for i in range(len(sb)-1)]
        m = len(da); ma = sum(da)/m; mb = sum(db)/m
        num = sum((da[i]-ma)*(db[i]-mb) for i in range(m))
        va = sum((v-ma)**2 for v in da)**0.5
        vb = sum((v-mb)**2 for v in db)**0.5
        if va < 0.05 or vb < 0.05: return None   # near-zero variance → unreliable
        return max(-1.0, min(1.0, num / (va * vb)))

    def _pearson_raw(sa, sb):
        if len(sa) < 3: return None
        ma = sum(sa)/len(sa); mb = sum(sb)/len(sb)
        num = sum((sa[i]-ma)*(sb[i]-mb) for i in range(len(sa)))
        va = sum((v-ma)**2 for v in sa)**0.5
        vb = sum((v-mb)**2 for v in sb)**0.5
        if va < 0.05 or vb < 0.05: return None
        return max(-1.0, min(1.0, num / (va * vb)))

    try:
        import sqlite3 as _sq
        cutoff = time.time() - minutes * 60
        with _sq.connect(METRICS_DB_PATH) as conn:
            a_rows = conn.execute(
                "SELECT CAST(ts/60 AS INT)*60 AS t, AVG(value) FROM metric_history "
                "WHERE stream=? AND metric='level_dbfs' AND ts>? GROUP BY t ORDER BY t",
                (ka, cutoff)
            ).fetchall()
            b_rows = conn.execute(
                "SELECT CAST(ts/60 AS INT)*60 AS t, AVG(value) FROM metric_history "
                "WHERE stream=? AND metric='level_dbfs' AND ts>? GROUP BY t ORDER BY t",
                (kb, cutoff)
            ).fetchall()
            # LUFS-I rows — used when level correlation is unreliable (processed path)
            la_rows = conn.execute(
                "SELECT CAST(ts/60 AS INT)*60 AS t, AVG(value) FROM metric_history "
                "WHERE stream=? AND metric='lufs_i' AND ts>? GROUP BY t ORDER BY t",
                (ka, cutoff)
            ).fetchall()
            lb_rows = conn.execute(
                "SELECT CAST(ts/60 AS INT)*60 AS t, AVG(value) FROM metric_history "
                "WHERE stream=? AND metric='lufs_i' AND ts>? GROUP BY t ORDER BY t",
                (kb, cutoff)
            ).fetchall()

        if len(a_rows) < 10 or len(b_rows) < 10:
            return {"status": "no_data", "r": None, "pct": None, "silence_pct": None,
                    "samples": min(len(a_rows), len(b_rows))}
        a_d = {r[0]: r[1] for r in a_rows}
        b_d = {r[0]: r[1] for r in b_rows}
        common = sorted(set(a_d) & set(b_d))
        if len(common) < 10:
            return {"status": "no_overlap", "r": None, "pct": None, "silence_pct": None,
                    "samples": len(common)}
        av = [a_d[t] for t in common]
        bv = [b_d[t] for t in common]
        n  = len(av)

        # ── Activity / silence agreement ──────────────────────────────────────
        a_act = [v > ta for v in av]
        b_act = [v > tb for v in bv]
        silence_pct    = sum(1 for i in range(n) if a_act[i] == b_act[i]) / n
        a_silent_frac  = sum(1 for v in a_act if not v) / n
        b_silent_frac  = sum(1 for v in b_act if not v) / n

        # ── Processing gap detection ──────────────────────────────────────────
        # >8 dB mean level difference strongly indicates a loudness/AGC processor
        # in the path.  Level-based Pearson is unreliable in that case because the
        # processor compresses dynamics to near-zero variance.
        mean_a      = sum(av) / n
        mean_b      = sum(bv) / n
        level_gap   = abs(mean_a - mean_b)
        processed   = level_gap > 8.0

        # ── Lag compensation: try 0-3 minute offsets, keep best ───────────────
        # Accounts for STL/processing latency that can shift events between buckets.
        best_delta_r = None
        best_lag     = 0
        for lag in range(4):
            if lag == 0:
                r = _pearson_delta(av, bv)
            elif n > lag + 3:
                r = _pearson_delta(av[lag:], bv[:-lag])
            else:
                r = None
            if r is not None and (best_delta_r is None or r > best_delta_r):
                best_delta_r = r
                best_lag     = lag
        delta_r = best_delta_r

        raw_r = _pearson_raw(av, bv)

        if processed:
            # ── Processed path: LUFS-I correlation + silence alignment ────────
            # Level dynamics are unreliable through AGC/loudness processors.
            # LUFS-I is more stable and silence timing is the clearest indicator
            # that both feeds carry the same programme.
            lufs_r = None
            if len(la_rows) >= 10 and len(lb_rows) >= 10:
                la_d = {r[0]: r[1] for r in la_rows if r[1] is not None}
                lb_d = {r[0]: r[1] for r in lb_rows if r[1] is not None}
                lcommon = sorted(set(la_d) & set(lb_d))
                if len(lcommon) >= 10:
                    lav = [la_d[t] for t in lcommon]
                    lbv = [lb_d[t] for t in lcommon]
                    lufs_r = _pearson_delta(lav, lbv) or _pearson_raw(lav, lbv)

            has_silence = a_silent_frac > 0.03 or b_silent_frac > 0.03
            if has_silence:
                # Silence timing available — reliable indicator of same content
                base = silence_pct
                if lufs_r is not None:
                    pct = (base * 0.65 + max(0.0, lufs_r) * 0.35) * 100.0
                else:
                    pct = base * 100.0
                # Penalise silence timing disagreement
                if a_silent_frac > 0.05 and b_silent_frac > 0.05:
                    pct = max(0.0, pct - (1.0 - silence_pct) * 50.0)
            else:
                # 24/7 continuous — both always active; silence timing unavailable
                if lufs_r is not None:
                    pct = (0.60 + max(0.0, lufs_r) * 0.40) * 100.0
                else:
                    # No useful signal — report "monitoring" floor, not a false number
                    pct = 68.0

            return {
                "status":      "processed",
                "r":           round(lufs_r, 3) if lufs_r is not None else None,
                "pct":         round(pct, 1),
                "silence_pct": round(silence_pct * 100.0, 1),
                "samples":     n,
                "level_gap":   round(level_gap, 1),
                "best_lag":    best_lag,
            }

        # ── Normal path: level Pearson blend ─────────────────────────────────
        if delta_r is not None and raw_r is not None:
            pct = (max(0.0, delta_r) * 0.6 + max(0.0, raw_r) * 0.4) * 100.0
        elif delta_r is not None:
            pct = max(0.0, delta_r) * 100.0
        elif raw_r is not None:
            pct = max(0.0, raw_r) * 100.0
        else:
            pct = silence_pct * 100.0

        # Silence-schedule penalty (only when both have silence events)
        if a_silent_frac > 0.05 and b_silent_frac > 0.05:
            pct = max(0.0, pct - (1.0 - silence_pct) * 50.0)

        return {
            "status":      "ok",
            "r":           round(delta_r, 3) if delta_r is not None else None,
            "pct":         round(pct, 1),
            "silence_pct": round(silence_pct * 100.0, 1),
            "samples":     n,
            "best_lag":    best_lag,
        }
    except Exception as e:
        return {"status": "error", "error": str(e), "r": None, "pct": None,
                "silence_pct": None, "samples": 0}


@app.get("/api/chains/history")
@login_required
def api_chains_history():
    """Return chain state reconstructed from metric_history at a given epoch timestamp."""
    try:
        ts = float(request.args.get("ts", 0))
    except (TypeError, ValueError):
        return jsonify({"error": "invalid ts"}), 400
    if ts <= 0:
        return jsonify({"error": "ts required"}), 400

    cfg = monitor.app_cfg
    WINDOW = 600  # accept the nearest sample within 10 minutes before the requested time

    def _node_hist(site: str, stream: str) -> dict:
        """Query historical level_dbfs + dab_ok for one node."""
        if site == "local":
            db_key = stream
            inp = next((i for i in cfg.inputs if i.name == stream), None)
            thresh = inp.silence_threshold_dbfs if inp else -55.0
            is_dab = inp is not None and (inp.device_index or "").strip().lower().startswith("dab://")
        else:
            db_key = f"{site}/{stream}"
            thresh = -55.0
            is_dab = False  # we check dab_ok from the DB regardless

        level = None
        dab_ok_val = None
        try:
            import sqlite3 as _sq
            with _sq.connect(METRICS_DB_PATH) as conn:
                row = conn.execute(
                    "SELECT value FROM metric_history WHERE stream=? AND metric='level_dbfs'"
                    " AND ts<=? AND ts>=? ORDER BY ts DESC LIMIT 1",
                    (db_key, ts, ts - WINDOW)
                ).fetchone()
                level = row[0] if row else None

                drow = conn.execute(
                    "SELECT value FROM metric_history WHERE stream=? AND metric='dab_ok'"
                    " AND ts<=? AND ts>=? ORDER BY ts DESC LIMIT 1",
                    (db_key, ts, ts - WINDOW)
                ).fetchone()
                dab_ok_val = bool(drow[0]) if drow is not None else None
        except Exception:
            pass

        if level is None:
            return {"status": "unknown", "level": None}

        down = level <= thresh
        # For DAB nodes, also treat dab_ok=False as down
        if dab_ok_val is not None and not dab_ok_val and (is_dab or site != "local"):
            down = True
        return {"status": "down" if down else "ok", "level": round(level, 1)}

    def _node_thresh(site: str, stream: str) -> float:
        """Return the silence threshold for a node (for fault-duration calculation)."""
        if site == "local":
            inp = next((i for i in cfg.inputs if i.name == stream), None)
            return inp.silence_threshold_dbfs if inp else -55.0
        return -55.0

    def _fault_duration_at(site: str, stream: str, thresh: float, look_back: float) -> float:
        """Return how many seconds before `ts` the node has been continuously below `thresh`.
        Looks back up to `look_back` seconds.  Returns 0.0 if no DB data."""
        db_key = stream if site == "local" else f"{site}/{stream}"
        try:
            import sqlite3 as _sq
            with _sq.connect(METRICS_DB_PATH) as conn:
                rows = conn.execute(
                    "SELECT ts, value FROM metric_history WHERE stream=? AND metric='level_dbfs'"
                    " AND ts<=? AND ts>=? ORDER BY ts DESC",
                    (db_key, ts, ts - look_back)
                ).fetchall()
            if not rows:
                return 0.0
            # Walk backward from ts; find the first (most-recent-going-back) sample
            # that was ABOVE threshold — that marks when the fault started.
            for sample_ts, val in rows:
                if val > thresh:
                    return ts - sample_ts
            # All samples in the window were below threshold → been down >= look_back
            return look_back
        except Exception:
            return 0.0

    def _eval_hist_chain(chain: dict) -> dict:
        nodes_out = []
        for node in chain.get("nodes", []):
            if node.get("type") == "stack":
                mode = node.get("mode", "all")
                sub_eval = []
                for sub in node.get("nodes", []):
                    h = _node_hist(sub.get("site", ""), sub.get("stream", ""))
                    sub_eval.append({
                        "label":  sub.get("label") or f"{sub.get('site','')}/{sub.get('stream','')}",
                        "site":   sub.get("site", ""),
                        "stream": sub.get("stream", ""),
                        "status": h["status"],
                        "level":  h["level"],
                    })
                if sub_eval:
                    if mode == "any":
                        is_down = any(n["status"] == "down" for n in sub_eval)
                    else:
                        is_down = all(n["status"] in ("down", "unknown") for n in sub_eval) and any(n["status"] == "down" for n in sub_eval)
                else:
                    is_down = False
                levels = [n["level"] for n in sub_eval if n["level"] is not None]
                nodes_out.append({
                    "type":   "stack",
                    "mode":   mode,
                    "label":  node.get("label") or "Stack",
                    "status": "down" if is_down else "ok",
                    "level":  round(max(levels), 1) if levels else None,
                    "nodes":  sub_eval,
                })
            else:
                h = _node_hist(node.get("site", ""), node.get("stream", ""))
                nodes_out.append({
                    "label":  node.get("label") or f"{node.get('site','')}/{node.get('stream','')}",
                    "site":   node.get("site", ""),
                    "stream": node.get("stream", ""),
                    "status": h["status"],
                    "level":  h["level"],
                })

        fault_idx = next((i for i, n in enumerate(nodes_out) if n["status"] == "down"), None)
        chain_status = "fault" if fault_idx is not None else ("ok" if nodes_out else "unknown")

        min_fault_secs    = float(chain.get("min_fault_seconds") or 0)
        mixin_idx         = chain.get("mixin_node_idx")
        adbreak_candidate = False
        display_status    = chain_status
        adbreak_remaining = None

        # ── Reconstruct alert state machine state at time `ts` ───────────────
        #
        # Primary path: query the persisted `chain_state` metric written every
        # ~10 s by the monitor loop.  Values: 1.0=ok, 0.5=pending/adbreak, 0.0=alerted.
        # This gives the exact state machine decision with no timing ambiguity.
        #
        # Fallback path (for data written before 3.2.33): reconstruct from
        # level_dbfs history using `_fault_duration_at` — less precise (±60 s)
        # because metrics are written at 1-minute intervals.
        _cid = chain.get("id", "")
        _chain_state_val = None
        try:
            import sqlite3 as _sq
            with _sq.connect(METRICS_DB_PATH) as _hconn:
                _hr = _hconn.execute(
                    "SELECT value FROM metric_history WHERE stream=? AND metric='chain_state'"
                    " AND ts<=? AND ts>=? ORDER BY ts DESC LIMIT 1",
                    (f"chain/{_cid}", ts, ts - 300),   # 5-min lookback (30 × 10 s samples)
                ).fetchone()
            if _hr is not None:
                _chain_state_val = _hr[0]
        except Exception:
            pass

        def _hist_is_adbreak_stack(fi, nout):
            """Return True if the faulted node is an all-silent stack with healthy downstream."""
            if fi is None:
                return False
            _fn = nout[fi] if fi < len(nout) else None
            if not (_fn and _fn.get("type") == "stack" and _fn.get("mode", "all") == "all"):
                return False
            return not any(n.get("status") == "down" for n in nout[fi + 1:])

        if _chain_state_val is not None:
            # ── Primary path: use persisted state ────────────────────────────
            if chain_status == "fault":
                if _chain_state_val >= 0.4:   # 0.5 → still inside confirmation window
                    # Determine adbreak vs plain pending using node layout
                    if (mixin_idx is not None
                            and fault_idx is not None
                            and fault_idx < int(mixin_idx)
                            and nodes_out[int(mixin_idx)]["status"] not in ("down", "unknown")):
                        adbreak_candidate = True
                        display_status    = "adbreak"
                    elif _hist_is_adbreak_stack(fault_idx, nodes_out):
                        # "fault-if-ALL-silent" stack — treat as ad break candidate
                        adbreak_candidate = True
                        display_status    = "adbreak"
                    else:
                        display_status    = "pending"
                # else _chain_state_val ≈ 0.0 → alerted; display_status stays "fault"

        elif fault_idx is not None and min_fault_secs > 0:
            # ── Fallback path: reconstruct from level_dbfs history ────────────
            # Is the fault before the mixin node (mixin still up)? → adbreak candidate
            if (mixin_idx is not None
                    and fault_idx < int(mixin_idx)
                    and nodes_out[int(mixin_idx)]["status"] not in ("down",)):
                adbreak_candidate = True
            # Secondary: fault-if-ALL-silent stack with healthy downstream
            if not adbreak_candidate and _hist_is_adbreak_stack(fault_idx, nodes_out):
                adbreak_candidate = True

            # Find which node is at fault to query its metric history
            fn = nodes_out[fault_idx]
            if fn.get("type") == "stack":
                fault_sub = next(
                    (s for s in fn.get("nodes", []) if s["status"] == "down"), None)
                f_site   = fault_sub["site"]   if fault_sub else ""
                f_stream = fault_sub["stream"] if fault_sub else ""
            else:
                f_site   = fn.get("site", "")
                f_stream = fn.get("stream", "")

            f_thresh  = _node_thresh(f_site, f_stream)
            look_back = min_fault_secs + WINDOW  # search back far enough to cover the window
            dur = _fault_duration_at(f_site, f_stream, f_thresh, look_back)

            if dur < min_fault_secs:
                # At this moment in time the fault was still inside the confirmation window
                display_status    = "adbreak" if adbreak_candidate else "pending"
                adbreak_remaining = round(max(0.0, min_fault_secs - dur))

        return {
            "id":                chain.get("id", ""),
            "name":              chain.get("name", ""),
            "status":            chain_status,
            "display_status":    display_status,
            "fault_index":       fault_idx,
            "fault_node":        nodes_out[fault_idx] if fault_idx is not None else None,
            "nodes":             nodes_out,
            "mixin_node_idx":    mixin_idx,
            "min_fault_seconds": min_fault_secs,
            "adbreak_candidate": adbreak_candidate,
            "adbreak_remaining": adbreak_remaining,
            "comparators":       [],   # skip correlation for historical view
        }

    results = []
    for chain in cfg.signal_chains:
        try:
            results.append(_eval_hist_chain(chain))
        except Exception as e:
            results.append({
                "id": chain.get("id", ""), "name": chain.get("name", ""),
                "status": "unknown", "display_status": "unknown",
                "fault_index": None, "fault_node": None,
                "nodes": [], "comparators": [], "adbreak_remaining": None,
                "error": str(e),
            })
    return jsonify({"results": results, "ts": ts})


@app.get("/api/chains/status")
@login_required
def api_chains_status():
    """Evaluate all chains and return their current status including correlation data."""
    cfg = monitor.app_cfg
    now = time.time()

    # Build input-name → stream-index map for local live URLs
    local_idx = {inp.name: idx for idx, inp in enumerate(cfg.inputs)}

    # Build site → (stream-name → stream-index) for hub live URLs
    hub_idx: dict = {}
    if hub_server:
        with hub_server._lock:
            for sname, data in hub_server._sites.items():
                hub_idx[sname] = {s.get("name", ""): i
                                  for i, s in enumerate(data.get("streams", []))}

    def _live_url(node: dict) -> "str | None":
        """Return the live-audio URL for a single (non-stack) node, or None."""
        site   = node.get("site", "")
        stream = node.get("stream", "")
        if not stream:
            return None
        if site == "local":
            idx = local_idx.get(stream)
            return f"/stream/{idx}/live" if idx is not None else None
        else:
            sidx = hub_idx.get(site, {}).get(stream)
            return (f"/hub/site/{site}/stream/{sidx}/live"
                    if sidx is not None else None)

    def _annotate_nodes(nodes: list) -> None:
        """Add live_url to every node (and sub-node inside stacks) in-place."""
        for node in nodes:
            if node.get("type") == "stack":
                for sub in node.get("nodes", []):
                    sub["live_url"] = _live_url(sub)
            else:
                node["live_url"] = _live_url(node)

    results = []
    for chain in cfg.signal_chains:
        try:
            cid   = chain.get("id", "")
            maint = hub_server._chain_maintenance.get(cid, {})
            result = hub_server.eval_chain(chain, maintenance=maint)
            # Enrich with live pending/adbreak state from the monitor loop
            # Use sentinel None to distinguish "not yet evaluated" from explicit "ok"
            internal_state = hub_server._chain_fault_state.get(cid)
            since = hub_server._chain_fault_since.get(cid)
            min_fault_secs = result.get("min_fault_seconds", 0)
            adbreak_candidate = result.get("adbreak_candidate", False)
            chain_status = result.get("status", "unknown")

            if internal_state == "pending" and adbreak_candidate and since is not None:
                # Monitor loop has confirmed the pending/adbreak state — show countdown
                hub_server._chain_api_pre_pending_since.pop(cid, None)
                result["display_status"] = "adbreak"
                remaining = max(0.0, min_fault_secs - (now - since))
                result["adbreak_remaining"] = round(remaining)
            elif internal_state == "pending" and since is not None:
                # Pending but not an adbreak candidate
                hub_server._chain_api_pre_pending_since.pop(cid, None)
                result["display_status"] = "pending"
                remaining = max(0.0, min_fault_secs - (now - since))
                result["adbreak_remaining"] = round(remaining)
            elif internal_state in (None, "ok") and chain_status == "fault" and min_fault_secs > 0:
                # API is polled faster than the 10s monitor loop.  The eval already
                # shows a fault but the loop hasn't had a chance to set "pending" yet.
                # Jump straight to amber so the UI never flashes red first.
                # Track when we FIRST saw this fault at the API layer so the countdown
                # starts immediately rather than staying frozen at the full window.
                pre_since = hub_server._chain_api_pre_pending_since.get(cid)
                if pre_since is None:
                    hub_server._chain_api_pre_pending_since[cid] = now
                    pre_since = now
                if adbreak_candidate:
                    result["display_status"] = "adbreak"
                else:
                    result["display_status"] = "pending"
                result["adbreak_remaining"] = round(max(0.0, min_fault_secs - (now - pre_since)))
            else:
                result["display_status"] = chain_status
                result["adbreak_remaining"] = None
                # Clear pre-pending tracker when fault resolves or monitor loop takes over
                hub_server._chain_api_pre_pending_since.pop(cid, None)
            # Expose fault onset timestamp for mobile Live Activity duration timer
            if internal_state == "alerted" and since is not None:
                result["fault_since_ts"] = since
            elif internal_state == "pending" and since is not None:
                result["fault_since_ts"] = since
            else:
                result["fault_since_ts"] = None
            # Stamp live_url onto every node so the UI can wire up click-to-listen
            _annotate_nodes(result.get("nodes", []))
            # Compute correlation for each configured comparator pair
            chain_nodes = chain.get("nodes", [])
            corr_out = []

            def _resolve_stack(nd: dict, sub_idx=None) -> dict:
                """Stacks have no site/stream at top level.
                If sub_idx is given pick that specific member; otherwise use first."""
                if nd.get("type") == "stack":
                    subs = nd.get("nodes", [])
                    if sub_idx is not None and 0 <= sub_idx < len(subs):
                        return subs[sub_idx]
                    return subs[0] if subs else nd
                return nd

            for comp in chain.get("comparators", []):
                fi = int(comp.get("from_idx", 0))
                ti = int(comp.get("to_idx", 1))
                fs = comp.get("from_sub")
                ts = comp.get("to_sub")
                fs = int(fs) if fs is not None else None
                ts = int(ts) if ts is not None else None
                if fi < len(chain_nodes) and ti < len(chain_nodes) and (fi != ti or fs != ts):
                    node_a = _resolve_stack(chain_nodes[fi], fs)
                    node_b = _resolve_stack(chain_nodes[ti], ts)
                    # ── On-demand comparator request ──────────────────────────
                    # When both nodes are on the same remote site, ask the client
                    # to spawn a local StreamComparator for this pair.  The richer
                    # client-side data (real-time xcorr, delay_ms, gain_diff_db)
                    # arrives in the next heartbeat and is consumed by the
                    # local_audio shortcut in _chain_correlate_nodes.
                    _sa = node_a.get("site", "")
                    _sb = node_b.get("site", "")
                    if (_sa and _sa != "local" and _sa == _sb
                            and hub_server is not None):
                        _na = node_a.get("stream", "")
                        _nb = node_b.get("stream", "")
                        _cmp_key = (_sa, _na, _nb)
                        _now_cmp = time.time()
                        _last_req = _cmp_pair_requested.get(_cmp_key, 0.0)
                        _site_cmps = hub_server._sites.get(_sa, {}).get("comparators", [])
                        _already_live = any(
                            (c.get("pre_name") == _na and c.get("post_name") == _nb)
                            or (c.get("pre_name") == _nb and c.get("post_name") == _na)
                            for c in _site_cmps
                        )
                        if not _already_live and (_now_cmp - _last_req > _CMP_PAIR_RECHECK_SECS):
                            hub_server.push_pending_command(_sa, {
                                "type": "cmp_pair",
                                "payload": {"pre_name": _na, "post_name": _nb},
                            })
                            _cmp_pair_requested[_cmp_key] = _now_cmp
                    corr = _chain_correlate_nodes(node_a, node_b)
                    corr_out.append({"from_idx": fi, "from_sub": fs, "to_idx": ti, "to_sub": ts, **corr})
            result["comparators"] = corr_out

            # ── Maintenance state ──────────────────────────────────────────
            result["maintenance"] = {k: v for k, v in maint.items() if v > now}

            # ── Node trend annotation ──────────────────────────────────────
            def _stamp_trend(node_list):
                for nd in node_list:
                    if nd.get("type") == "stack":
                        _stamp_trend(nd.get("nodes", []))
                    else:
                        _s = nd.get("site", "")
                        _n = nd.get("stream", "")
                        dk = _n if _s == "local" else f"{_s}/{_n}"
                        tr = hub_server._chain_node_trend.get(dk)
                        nd["trend"] = tr.get("trend") if tr else None
                        nd["trend_slope"] = tr.get("slope") if tr else None
            _stamp_trend(result.get("nodes", []))

            # ── Glitch / flatness annotation on chain nodes ────────────────
            # Aggregates per-node health signals so the chain diagram can
            # show ⚡ glitch and 〰 static badges at the correct node.
            _chain_has_glitch   = False
            _chain_has_flatness = False
            def _stamp_health(node_list):
                nonlocal _chain_has_glitch, _chain_has_flatness
                _now_h = time.time()
                for nd in node_list:
                    if nd.get("type") == "stack":
                        _stamp_health(nd.get("nodes", []))
                    else:
                        _gr = nd.get("glitch_recent", [])
                        _g5 = [t for t in _gr if _now_h - float(t) < 300.0]
                        nd["glitch_5min"] = len(_g5)
                        nd["flatness_active"] = bool(nd.get("flatness_active", False))
                        if nd["glitch_5min"] > 0:
                            _chain_has_glitch = True
                        if nd["flatness_active"]:
                            _chain_has_flatness = True
            _stamp_health(result.get("nodes", []))
            result["has_glitch"]   = _chain_has_glitch
            result["has_flatness"] = _chain_has_flatness

            # ── SLA computation ────────────────────────────────────────────
            try:
                import sqlite3 as _sq2
                _sla_cutoff = now - 30 * 86400
                with _sq2.connect(METRICS_DB_PATH) as _sc:
                    _sla_row = _sc.execute(
                        "SELECT COUNT(*), SUM(value) FROM metric_history "
                        "WHERE stream=? AND metric='chain_status' AND ts>?",
                        (f"chain/{cid}", _sla_cutoff)
                    ).fetchone()
                if _sla_row and _sla_row[0] and _sla_row[0] > 0:
                    result["sla_pct"] = round((_sla_row[1] / _sla_row[0]) * 100, 2)
                    result["sla_samples"] = _sla_row[0]
                else:
                    result["sla_pct"] = None
                    result["sla_samples"] = 0
            except Exception:
                result["sla_pct"] = None
                result["sla_samples"] = 0

            # ── Flapping state ─────────────────────────────────────────────
            result["flapping"] = hub_server._chain_flapping.get(cid, False)

            # ── Chain Health Score (0–100) ──────────────────────────────────
            # Composite of SLA, recent fault frequency, stability, and trends.
            # Designed so a perfectly healthy chain converges toward 100 over
            # time as SLA approaches 100 % and fault history clears.
            try:
                _sla          = result.get("sla_pct")
                _is_flapping  = result.get("flapping", False)
                # Component 1: SLA (0–70 pts)  — primary long-run health driver
                _sla_pts      = min(70.0, float(_sla) * 0.70) if _sla is not None else 35.0
                # Component 2: Fault frequency last 7 d (0–20 pts)
                _7d_cutoff    = now - 7 * 86400
                _flog_entries = hub_server._chain_fault_log.get(cid, [])
                # Exclude adbreak-overshoot entries — these are long ad breaks that
                # exceeded the confirmation window, not genuine signal faults.
                _faults_7d    = sum(1 for e in _flog_entries
                                    if e.get("ts_start", 0) > _7d_cutoff
                                    and not e.get("adbreak_overshoot", False))
                _freq_pts     = max(0.0, 20.0 - _faults_7d * 4.0)
                # Component 3: Stability (0–10 pts) — flapping wipes this out
                _stab_pts     = 0.0 if _is_flapping else 10.0
                # Component 4: Trending-down node penalty (−5 per node, max −15)
                def _count_down_trends(nl):
                    t = 0
                    for nd in nl:
                        if nd.get("type") == "stack":
                            t += _count_down_trends(nd.get("nodes", []))
                        elif nd.get("trend") == "down":
                            t += 1
                    return t
                _down_nodes  = _count_down_trends(result.get("nodes", []))
                _trend_pen   = min(15.0, _down_nodes * 5.0)
                # Component 5: RTP packet loss penalty (0 → −10 pts)
                # Peak loss across all RTP-capable nodes (sub-nodes in stacks included).
                # Non-RTP streams (FM, DAB, HTTP, local sound) report rtp_loss_pct=None
                # and are excluded.  Scale: 0 % loss = 0 pts; 10 % loss = −10 pts (capped).
                def _peak_rtp_loss(nl):
                    peak = 0.0
                    for nd in nl:
                        if nd.get("type") == "stack":
                            peak = max(peak, _peak_rtp_loss(nd.get("nodes", [])))
                        else:
                            loss = nd.get("rtp_loss_pct")
                            if loss is not None:
                                peak = max(peak, float(loss))
                    return peak
                _max_rtp     = _peak_rtp_loss(result.get("nodes", []))
                _rtp_pen     = min(10.0, _max_rtp * 1.0)   # 1 pt per 1 % loss, capped at 10
                _hscore      = round(max(0, min(100,
                    _sla_pts + _freq_pts + _stab_pts - _trend_pen - _rtp_pen)))
                if _hscore >= 90:
                    _hlabel, _hcolor = "Healthy",  "#22c55e"
                elif _hscore >= 75:
                    _hlabel, _hcolor = "Watch",    "#f59e0b"
                elif _hscore >= 50:
                    _hlabel, _hcolor = "Degraded", "#f97316"
                else:
                    _hlabel, _hcolor = "Poor",     "#ef4444"
                result["health_score"]   = _hscore
                result["health_label"]   = _hlabel
                result["health_color"]   = _hcolor
                result["health_rtp_loss"] = round(_max_rtp, 1)  # peak RTP loss used in score
            except Exception:
                result["health_score"] = None
                result["health_label"] = "Unknown"
                result["health_color"] = "#8aa4c8"

            # ── Ad-break stats (expose p95 + count if enough history) ──────
            try:
                _abs = metrics_db.adbreak_stats(cid)
                if _abs["count"] >= 3:
                    result["adbreak_stats"] = {
                        "p95": round(_abs["p95"], 1),
                        "count": _abs["count"],
                    }
                else:
                    result["adbreak_stats"] = None
            except Exception:
                result["adbreak_stats"] = None

            results.append(result)
        except Exception as e:
            results.append({"id": chain.get("id", ""), "name": chain.get("name", ""),
                            "status": "unknown", "display_status": "unknown",
                            "fault_index": None, "fault_node": None,
                            "nodes": [], "comparators": [], "adbreak_remaining": None,
                            "error": str(e)})

    # ── Shared fault detection ─────────────────────────────────────────────────
    # Priority: 1) explicit machine tag (most precise — set by the user in the builder)
    #           2) hub site name (same server likely has common failure mode)
    #           3) local stream exact name
    def _fault_key(node: dict) -> "str | None":
        """Return a grouping key for shared-fault detection.
        Only nodes with an explicit machine tag are grouped — site name is
        no longer used as a fallback so nodes without a tag never produce
        spurious cross-chain shared-fault badges."""
        machine = (node.get("machine") or "").strip()
        return f"machine|{machine}" if machine else None

    fault_site_map: dict = {}   # machine-key → [chain_name, ...]
    for r in results:
        fn = r.get("fault_node")
        if fn:
            subs = fn.get("nodes", []) if fn.get("type") == "stack" else [fn]
            for s in subs:
                if s.get("status") in ("down", "offline"):
                    key = _fault_key(s)
                    if key:  # only group nodes that have a machine tag
                        fault_site_map.setdefault(key, []).append(r["name"])
    for r in results:
        fn = r.get("fault_node")
        shared: list = []
        if fn:
            subs = fn.get("nodes", []) if fn.get("type") == "stack" else [fn]
            for s in subs:
                if s.get("status") in ("down", "offline"):
                    key = _fault_key(s)
                    if key:
                        shared += [n for n in fault_site_map.get(key, [])
                                   if n != r["name"]]
        r["shared_fault_chains"] = list(dict.fromkeys(shared))  # dedup, preserve order

    return jsonify({"results": results})


def _mobile_live_url_from_node(node: dict) -> str:
    """Return the mobile-token protected live URL for a node."""
    raw = (node.get("live_url") or "").strip()
    if raw:
        if raw.startswith("/hub/site/"):
            return "/api/mobile" + raw
        if raw.startswith("/stream/"):
            return "/api/mobile" + raw
        return raw

    site = node.get("site", "")
    stream = node.get("stream", "")
    if not stream:
        return ""

    try:
        cfg = monitor.app_cfg
        local_idx = {inp.name: idx for idx, inp in enumerate(cfg.inputs)}
        hub_idx = {}
        if hub_server:
            with hub_server._lock:
                for sname, data in hub_server._sites.items():
                    hub_idx[sname] = {s.get("name", ""): i for i, s in enumerate(data.get("streams", []))}
        if site == "local":
            idx = local_idx.get(stream)
            return f"/api/mobile/stream/{idx}/live" if idx is not None else ""
        sidx = hub_idx.get(site, {}).get(stream)
        return f"/api/mobile/hub/site/{site}/stream/{sidx}/live" if sidx is not None else ""
    except Exception:
        return ""


def _mobile_node_summary(node: dict) -> dict:
    # eval_chain() populates node audio level under "level", while some other
    # code paths may already expose "level_dbfs". Prefer the explicit mobile
    # field when present, but fall back to the runtime chain-eval key so the
    # iPhone app always gets usable level data.
    level_dbfs = node.get("level_dbfs")
    if level_dbfs is None:
        level_dbfs = node.get("level")

    out = {
        "type": node.get("type", "node"),
        "label": node.get("label") or node.get("stream") or node.get("site") or "Node",
        "stream": node.get("stream", ""),
        "site": node.get("site", ""),
        "status": node.get("status", "unknown"),
        "reason": node.get("reason", ""),
        "machine": node.get("machine", ""),
        "live_url": _mobile_live_url_from_node(node),
        "level_dbfs": level_dbfs,
        "rtp_loss_pct": node.get("rtp_loss_pct"),
        "glitch_count": node.get("glitch_count") or 0,
        "ts": node.get("ts"),
    }
    if node.get("type") == "stack":
        out["mode"] = node.get("mode", "any")
        out["nodes"] = [_mobile_node_summary(n) for n in (node.get("nodes", []) or [])]
    return out

def _mobile_chain_summary(result: dict, now: float | None = None) -> dict:
    now = time.time() if now is None else now
    fault_node = result.get("fault_node") or {}
    fault_at = (
        fault_node.get("label")
        or fault_node.get("stream")
        or fault_node.get("site")
        or None
    )
    maintenance = result.get("maintenance") or {}
    updated_at = result.get("updated_at")
    if updated_at is None:
        updated_at = now
    try:
        updated_at = float(updated_at)
    except Exception:
        updated_at = now

    return {
        "id": result.get("id", ""),
        "name": result.get("name", ""),
        "status": result.get("status", "unknown"),
        "display_status": result.get("display_status", result.get("status", "unknown")),
        "fault_index": result.get("fault_index"),
        "fault_at": fault_at,
        "fault_reason": result.get("fault_reason") or fault_node.get("reason") or "",
        "pending": result.get("display_status") in ("pending", "adbreak"),
        "adbreak": result.get("display_status") == "adbreak",
        "adbreak_remaining": result.get("adbreak_remaining"),
        "maintenance": bool(maintenance),
        "maintenance_nodes": list(maintenance.keys()),
        "flapping": bool(result.get("flapping")),
        "shared_fault_chains": result.get("shared_fault_chains", []),
        "sla_pct": result.get("sla_pct"),
        "updated_at": updated_at,
        "age_secs": max(0, int(round(now - updated_at))),
        "nodes": [_mobile_node_summary(n) for n in (result.get("nodes", []) or [])],
        "fault_since_ts": result.get("fault_since_ts"),
        "health_score": result.get("health_score"),
        "health_label": result.get("health_label"),
    }


@app.get("/api/mobile/hub/overview")
@mobile_api_required
def api_mobile_hub_overview():
    """Aggregated hub state for the iOS Sites overview tab.

    Returns every connected site with per-site summary counts and a slim
    stream list (name, level, format, SLA, AI state).  Does NOT require
    the caller to be running in hub mode — if the server is a standalone
    node the response will have an empty sites list and mode='local'.
    """
    cfg = monitor.app_cfg
    now = time.time()
    mode = cfg.hub.mode if cfg.hub else "local"

    if mode not in ("hub", "both"):
        return jsonify({
            "ok": True, "generated_at": now,
            "mode": mode,
            "summary": {"total_sites": 0, "online_sites": 0, "offline_sites": 0,
                        "total_alert": 0, "total_warn": 0, "total_ok": 0,
                        "total_streams": 0},
            "sites": [],
        })

    raw_sites = hub_server.get_sites()
    total_alert = total_warn = total_ok = total_online = total_offline = 0
    result_sites = []

    for s in raw_sites:
        streams = s.get("streams") or []
        online  = s.get("online", False)

        if not online:
            site_status = "offline"
            total_offline += 1
        elif any(
            "ALERT" in (st.get("ai_status") or "") or
            st.get("status") in ("alert", "silence", "fault") or
            st.get("silence_active") or
            (st.get("glitch_count") or 0) > 0
            for st in streams
        ):
            site_status = "alert"
            total_online += 1
        elif any(
            "WARN" in (st.get("ai_status") or "") or
            st.get("status") == "warn"
            for st in streams
        ):
            site_status = "warn"
            total_online += 1
        else:
            site_status = "ok"
            total_online += 1

        s_alert = sum(1 for st in streams if (
            "ALERT" in (st.get("ai_status") or "") or
            st.get("status") in ("alert", "silence", "fault")
        ))
        s_warn  = sum(1 for st in streams if (
            "WARN" in (st.get("ai_status") or "") or
            st.get("status") == "warn"
        ))
        s_ok    = max(0, len(streams) - s_alert - s_warn)
        total_alert += s_alert
        total_warn  += s_warn
        total_ok    += s_ok

        mobile_streams = []
        _sorted_streams = sorted(streams, key=lambda x: (
            0 if "ALERT" in (x.get("ai_status") or "") else
            1 if "WARN"  in (x.get("ai_status") or "") else 2,
            (x.get("name") or "").lower()
        ))
        for _stream_idx, st in enumerate(_sorted_streams):
            if not st.get("enabled", True):
                continue
            ai_raw = (st.get("ai_status") or "").upper()
            if "ALERT"    in ai_raw: ai_state = "alert"
            elif "WARN"   in ai_raw: ai_state = "warn"
            elif "LEARNING" in ai_raw: ai_state = "learning"
            else:                    ai_state = "ok"
            _site_name_raw = s.get("site", "")
            _safe_site = urllib.parse.quote(_site_name_raw, safe="")
            mobile_streams.append({
                "name":        st.get("name", ""),
                "format":      st.get("format", ""),
                "level_dbfs":  st.get("level_dbfs"),
                "sla_pct":     st.get("sla_pct"),
                "ai_status":   ai_state,
                "ai_phase":    st.get("ai_phase", ""),
                "rtp_loss_pct":   st.get("rtp_loss_pct"),
                "rtp_jitter_ms":  st.get("rtp_jitter_ms"),
                "glitch_count":   st.get("glitch_count") or 0,
                "fm_rds_ps":   st.get("fm_rds_ps"),
                "fm_rds_rt":   st.get("fm_rds_rt"),
                "dab_service": st.get("dab_service"),
                "dab_dls":     st.get("dab_dls"),
                "dab_ensemble": st.get("dab_ensemble"),
                "live_url":    f"/api/mobile/hub/site/{_safe_site}/stream/{_stream_idx}/live",
            })

        result_sites.append({
            "site":         s.get("site", ""),
            "online":       online,
            "running":      s.get("running", False),
            "site_status":  site_status,
            "age_s":        s.get("age_s"),
            "latency_ms":   s.get("latency_ms"),
            "build":        s.get("build", ""),
            "health_pct":   s.get("health_pct"),
            "alert_count":  s_alert,
            "warn_count":   s_warn,
            "ok_count":     s_ok,
            "stream_count": len(streams),
            "streams":      mobile_streams,
        })

    # Sort: alert → warn → ok → offline, then alphabetically
    result_sites.sort(key=lambda x: (
        0 if x["site_status"] == "alert"   else
        1 if x["site_status"] == "warn"    else
        2 if x["site_status"] == "ok"      else 3,
        x["site"].lower()
    ))

    return jsonify({
        "ok":           True,
        "generated_at": now,
        "mode":         mode,
        "summary": {
            "total_sites":   len(result_sites),
            "online_sites":  total_online,
            "offline_sites": total_offline,
            "total_alert":   total_alert,
            "total_warn":    total_warn,
            "total_ok":      total_ok,
            "total_streams": total_alert + total_warn + total_ok,
        },
        "sites": result_sites,
    })


@app.get("/api/mobile/chains")
@mobile_api_required
def api_mobile_chains():
    base_resp = api_chains_status.__wrapped__()
    payload = base_resp.get_json(silent=True) or {}
    now = time.time()
    results = payload.get("results", []) or []
    return jsonify({
        "ok": True,
        "results": [_mobile_chain_summary(r, now=now) for r in results],
        "generated_at": now,
    })


@app.get("/api/mobile/chains/<cid>")
@mobile_api_required
def api_mobile_chain(cid: str):
    base_resp = api_chains_status.__wrapped__()
    payload = base_resp.get_json(silent=True) or {}
    now = time.time()
    for item in (payload.get("results", []) or []):
        if item.get("id") == cid:
            return jsonify({"ok": True, "chain": _mobile_chain_summary(item, now=now)})
    return jsonify({"ok": False, "error": "not found"}), 404


@app.get("/api/mobile/chains/<cid>/fault_log")
@mobile_api_required
def api_mobile_chain_fault_log(cid: str):
    """Return the fault log for a chain with engineer notes merged in.
    Used by the iPhone app to show fault history with notes per event.
    """
    entries = metrics_db.fault_log_load(cid, limit=50)
    notes = _load_chain_notes()
    result = []
    for entry in reversed(entries):  # newest first
        # Build mobile-friendly clip list with playback URL included
        raw_clips = entry.get("clips") or []
        mobile_clips = []
        for c in raw_clips:
            key   = c.get("key", "")
            fname = c.get("fname", "")
            if not fname:
                continue
            mobile_clips.append({
                "key":        key,
                "fname":      fname,
                "label":      c.get("label", ""),
                "node_label": c.get("node_label", key),
                "pos":        c.get("pos"),
                "status":     c.get("status", ""),
                # Relative URL the app appends to baseURL; uses mobile token auth
                "url":        f"/api/mobile/clip/{key}/{fname}",
            })
        row = {
            "id":               entry.get("id", ""),
            "chain_id":         entry.get("chain_id", ""),
            "ts_start":         entry.get("ts_start"),
            "ts_recovered":     entry.get("ts_recovered"),
            "fault_node_label": entry.get("fault_node_label", ""),
            "fault_site":       entry.get("fault_site", ""),
            "fault_stream":     entry.get("fault_stream", ""),
            "rtp_loss_pct":     entry.get("rtp_loss_pct"),
            "clips":            mobile_clips,
            "note":             None,
            "note_by":          None,
            "note_ts":          None,
        }
        fid = row["id"]
        if fid and fid in notes:
            row["note"]    = notes[fid]["text"]
            row["note_by"] = notes[fid]["by"]
            row["note_ts"] = notes[fid]["ts"]
        result.append(row)
    return jsonify({"ok": True, "chain_id": cid, "entries": result, "count": len(result)})


@app.post("/api/mobile/chain_notes/<fault_log_id>")
@mobile_api_required
def api_mobile_chain_note_save(fault_log_id: str):
    """Add or update an engineer note from the mobile app.

    Body JSON: {"text": "...", "site": "<site_name_if_hub>"}
    - When this node is a hub, the optional "site" field causes the note to
      also be forwarded to the originating client as a chain_note command.
    - The note is always stored locally (on the hub or on the standalone client).
    """
    fault_log_id = fault_log_id.strip()
    if not fault_log_id:
        return jsonify({"ok": False, "error": "missing fault_log_id"}), 400
    data = request.json or {}
    text = str(data.get("text", "")).strip()[:2000]
    site = str(data.get("site", "")).strip()
    if not text:
        return jsonify({"ok": False, "error": "note text cannot be empty"}), 400

    record = _save_chain_note(fault_log_id, text, by="app")

    # If this is a hub and the caller specified which client site, forward it
    cfg = monitor.app_cfg
    if site and hub_server and cfg.hub.mode in ("hub", "both"):
        try:
            hub_server.push_pending_command(site, {
                "type":    "chain_note",
                "payload": {"fault_log_id": fault_log_id, "text": text, "by": "app"},
            })
        except Exception:
            pass

    return jsonify({"ok": True, "fault_log_id": fault_log_id, "record": record})


@app.get("/api/mobile/active_faults")
@mobile_api_required
def api_mobile_active_faults():
    base_resp = api_chains_status.__wrapped__()
    payload = base_resp.get_json(silent=True) or {}
    now = time.time()
    active = []
    for item in (payload.get("results", []) or []):
        status = item.get("display_status", item.get("status", "unknown"))
        if status in ("fault", "pending", "adbreak"):
            active.append(_mobile_chain_summary(item, now=now))
    return jsonify({
        "ok": True,
        "results": active,
        "count": len(active),
        "generated_at": now,
    })


