@app.get("/api/mobile/scanner/status/<path:site_name>")
@mobile_api_required
def api_mobile_scanner_status(site_name: str):
    """Get scanner session status for a site."""
    if not hub_server:
        return jsonify({"ok": True, "active": False})
    sess = hub_server._scanner_sessions.get(site_name)
    if not sess:
        return jsonify({"ok": True, "active": False})
    slot = listen_registry.get(sess["slot_id"])
    streaming = bool(slot and not slot.closed and not slot.stale)
    if not streaming:
        hub_server._scanner_sessions.pop(site_name, None)
        return jsonify({"ok": True, "active": False})
    rds = sess.get("rds", {})
    return jsonify({
        "ok":        True,
        "active":    True,
        "freq_mhz":  sess["freq_mhz"],
        "streaming": slot.last_chunk > slot.created,
        "ps":        rds.get("ps", ""),
        "rt":        rds.get("rt", ""),
        "stereo":    bool(rds.get("stereo")),
        "pi":        rds.get("pi", ""),
        "stream_url": f"/hub/scanner/stream/{sess['slot_id']}",
        "mobile_stream_url": f"/api/mobile/hub/scanner/stream_wav/{sess['slot_id']}",
    })


@app.get("/api/mobile/hub/scanner/stream/<slot_id>")
@mobile_api_required
def api_mobile_hub_scanner_stream(slot_id: str):
    """Stream raw 16-bit LE PCM scanner audio for mobile clients.

    Accesses the listen slot directly (bypassing @login_required on the plugin
    view function) — the mobile token already authenticated the request.
    Format: raw 16-bit signed LE, mono, 48 kHz — matches PCMStreamPlayer.
    """
    import queue as _queue

    slot = listen_registry.get(slot_id)
    if not slot or slot.kind not in ("scanner",):
        return "Stream not found or expired", 404

    BLOCK     = 9600          # 0.1 s at 48 kHz, 16-bit mono
    SILENCE   = b"\x00" * BLOCK
    _BLK_DUR  = 0.10

    def generate():
        # Wait for first real chunk (startup timeout 20 s, fill with silence)
        startup_deadline = time.time() + 20.0
        next_sil_t = time.monotonic() + _BLK_DUR
        while True:
            try:
                chunk = slot.get(timeout=0.05)
                yield chunk
                break
            except _queue.Empty:
                if slot.closed or time.time() > startup_deadline:
                    return
                now = time.monotonic()
                if now >= next_sil_t:
                    yield SILENCE
                    next_sil_t += _BLK_DUR

        # Main relay loop — inject silence if gap > 1 s (WAN-friendly)
        _kp_threshold = 1.0
        next_kp_t = time.monotonic() + _kp_threshold
        while True:
            try:
                chunk = slot.get(timeout=0.30)
                next_kp_t = time.monotonic() + _kp_threshold
                yield chunk
            except _queue.Empty:
                if slot.closed or slot.stale:
                    return
                now = time.monotonic()
                if now >= next_kp_t:
                    yield SILENCE
                    next_kp_t += _kp_threshold

    return Response(
        generate(),
        mimetype="application/octet-stream",
        headers={
            "Cache-Control":     "no-cache, no-store",
            "X-Accel-Buffering": "no",
        },
    )


@app.get("/api/mobile/hub/scanner/stream_wav/<slot_id>")
@mobile_api_required
def api_mobile_hub_scanner_stream_wav(slot_id: str):
    """Stream scanner audio as WAV for iOS AVPlayer (prepends streaming WAV header).

    AVPlayer cannot play raw application/octet-stream PCM. This endpoint
    wraps the existing PCM relay with a standard streaming WAV header
    (RIFF/WAVE with 0xFFFFFFFF sizes) so iOS can decode it natively.
    Format: 16-bit signed LE, mono, 48 kHz — matches the scanner relay output.
    """
    import struct as _struct
    import queue  as _queue

    slot = listen_registry.get(slot_id)
    if not slot or slot.kind not in ("scanner",):
        return "Stream not found or expired", 404

    SR, CH, BPS   = 48000, 1, 16
    BLOCK         = SR * CH * BPS // 8 // 10   # 9600 bytes = 0.1 s
    SILENCE       = b"\x00" * BLOCK
    byte_rate     = SR * CH * BPS // 8          # 96000
    block_align   = CH * BPS // 8               # 2

    # Streaming WAV header — 0xFFFFFFFF signals unknown/infinite length
    wav_hdr = (
        b"RIFF" + _struct.pack("<I", 0xFFFFFFFF)
        + b"WAVE"
        + b"fmt " + _struct.pack("<IHHIIHH", 16, 1, CH, SR, byte_rate, block_align, BPS)
        + b"data" + _struct.pack("<I", 0xFFFFFFFF)
    )

    def generate():
        yield wav_hdr

        # Wait for first real chunk (startup timeout 20 s, fill with silence)
        startup_deadline = time.time() + 20.0
        _BLK_DUR   = 0.10
        next_sil_t = time.monotonic() + _BLK_DUR
        while True:
            try:
                chunk = slot.get(timeout=0.05)
                yield chunk
                break
            except _queue.Empty:
                if slot.closed or time.time() > startup_deadline:
                    return
                now = time.monotonic()
                if now >= next_sil_t:
                    yield SILENCE
                    next_sil_t += _BLK_DUR

        # Main relay loop — inject silence if gap > 1 s (WAN-friendly)
        _kp_threshold = 1.0
        next_kp_t = time.monotonic() + _kp_threshold
        while True:
            try:
                chunk = slot.get(timeout=0.30)
                next_kp_t = time.monotonic() + _kp_threshold
                yield chunk
            except _queue.Empty:
                if slot.closed or slot.stale:
                    return
                now = time.monotonic()
                if now >= next_kp_t:
                    yield SILENCE
                    next_kp_t += _kp_threshold

    return Response(
        generate(),
        mimetype="audio/wav",
        headers={
            "Cache-Control":     "no-cache, no-store",
            "X-Accel-Buffering": "no",
            "Content-Disposition": "inline",
        },
    )


