@app.route("/api/mobile/device_token", methods=["POST"])
@mobile_api_required
def api_mobile_device_token():
    """Register or unregister a device push token (APNs for iOS, FCM for Android).

    POST body: {
        "token":         "<hex/FCM token>",
        "action":        "register" | "unregister" | "update_nodes",
        "platform":      "ios" | "android"   (default: "ios"),
        "sandbox":       true | false         (iOS only),
        "watched_nodes": ["Node A", ...]      (optional)
    }
    """
    data  = request.get_json(force=True, silent=True) or {}
    token = str(data.get("token", "")).strip()
    if not token:
        return jsonify({"ok": False, "error": "token required"}), 400

    platform = str(data.get("platform", "ios")).lower()

    ma = getattr(monitor.app_cfg, "mobile_api", None)
    if ma is None:
        return jsonify({"ok": False, "error": "mobile api not configured"}), 500

    # ── Android FCM path ─────────────────────────────────────────────────────
    if platform == "android":
        with _fcm_tokens_lock:
            if not hasattr(ma, "fcm_device_tokens") or ma.fcm_device_tokens is None:
                ma.fcm_device_tokens = []
            raw_nodes    = data.get("watched_nodes")
            watched_nodes = [str(n) for n in raw_nodes] if isinstance(raw_nodes, list) else None
            action = str(data.get("action", "register")).lower()
            if action == "unregister":
                ma.fcm_device_tokens = [e for e in ma.fcm_device_tokens
                                        if (e.get("token") if isinstance(e, dict) else e) != token]
                save_config(monitor.app_cfg)
                return jsonify({"ok": True, "action": "unregistered",
                                "count": len(ma.fcm_device_tokens)})
            elif action == "update_nodes":
                updated = False
                for e in ma.fcm_device_tokens:
                    if isinstance(e, dict) and e.get("token") == token:
                        e["watched_nodes"] = watched_nodes or []
                        updated = True
                        break
                if not updated:
                    ma.fcm_device_tokens.append({"token": token,
                                                  "watched_nodes": watched_nodes or []})
                save_config(monitor.app_cfg)
                return jsonify({"ok": True, "action": "nodes_updated",
                                "count": len(ma.fcm_device_tokens)})
            else:
                # register / re-register
                existing = [e for e in ma.fcm_device_tokens
                            if (e.get("token") if isinstance(e, dict) else e) == token]
                new_entry: dict = {"token": token}
                if watched_nodes is not None:
                    new_entry["watched_nodes"] = watched_nodes
                elif existing and isinstance(existing[0], dict) and "watched_nodes" in existing[0]:
                    new_entry["watched_nodes"] = existing[0]["watched_nodes"]
                ma.fcm_device_tokens = [e for e in ma.fcm_device_tokens
                                        if (e.get("token") if isinstance(e, dict) else e) != token]
                ma.fcm_device_tokens.append(new_entry)
                save_config(monitor.app_cfg)
                return jsonify({"ok": True, "action": "registered",
                                "count": len(ma.fcm_device_tokens)})

    # ── iOS APNs path (existing logic) ───────────────────────────────────────
    with _apns_tokens_lock:
        if not hasattr(ma, "apns_device_tokens") or ma.apns_device_tokens is None:
            ma.apns_device_tokens = []

        # sandbox flag sent by iOS client: True for debug/Xcode, False for TestFlight/App Store
        sandbox = bool(data.get("sandbox", True))
        # watched_nodes: list of node labels this device wants silence/down alerts for
        raw_nodes = data.get("watched_nodes")
        watched_nodes = [str(n) for n in raw_nodes] if isinstance(raw_nodes, list) else None
        new_entry: dict = {"token": token, "sandbox": sandbox}
        if watched_nodes is not None:
            new_entry["watched_nodes"] = watched_nodes

        action = str(data.get("action", "register")).lower()
        if action == "unregister":
            # Remove any entry (dict or legacy string) matching this token
            ma.apns_device_tokens = [
                e for e in ma.apns_device_tokens if _apns_token_str(e) != token
            ]
            save_config(monitor.app_cfg)
            return jsonify({"ok": True, "action": "unregistered", "count": len(ma.apns_device_tokens)})
        elif action == "update_nodes":
            # Update only the watched_nodes list for an already-registered token
            updated = False
            for e in ma.apns_device_tokens:
                if isinstance(e, dict) and _apns_token_str(e) == token:
                    e["watched_nodes"] = watched_nodes or []
                    updated = True
                    break
            if not updated:
                # Token not yet registered — register it now
                ma.apns_device_tokens.append(new_entry)
            save_config(monitor.app_cfg)
            return jsonify({"ok": True, "action": "nodes_updated", "count": len(ma.apns_device_tokens)})
        else:
            # Replace any existing entry for this token (handles environment change)
            existing_tokens = [_apns_token_str(e) for e in ma.apns_device_tokens]
            if token in existing_tokens:
                # Merge: preserve existing watched_nodes if the new registration omits them
                merged = []
                for e in ma.apns_device_tokens:
                    if _apns_token_str(e) == token:
                        entry = dict(new_entry)
                        if watched_nodes is None and isinstance(e, dict) and "watched_nodes" in e:
                            entry["watched_nodes"] = e["watched_nodes"]
                        merged.append(entry)
                    else:
                        merged.append(e)
                ma.apns_device_tokens = merged
            else:
                ma.apns_device_tokens.append(new_entry)
            save_config(monitor.app_cfg)
            return jsonify({"ok": True, "action": "registered", "count": len(ma.apns_device_tokens)})


# ─── Mobile reports / clips API ──────────────────────────────────────────────

def _mobile_reports_stream_to_chains(chain_cfg) -> dict:
    stream_to_chains = {}
    for ch in (chain_cfg or []):
        cname = (ch or {}).get("name", "")
        for node in ((ch or {}).get("nodes", []) or []):
            subs = node.get("nodes", []) if node.get("type") == "stack" else [node]
            for sub in (subs or []):
                sname = (sub or {}).get("stream", "")
                if sname:
                    stream_to_chains.setdefault(sname, [])
                    if cname and cname not in stream_to_chains[sname]:
                        stream_to_chains[sname].append(cname)
    return stream_to_chains


def _mobile_reports_clip_id_encode(payload: dict) -> str:
    raw = json.dumps(payload, separators=(",", ":"), ensure_ascii=False).encode("utf-8")
    return base64.urlsafe_b64encode(raw).decode("ascii").rstrip("=")


def _mobile_reports_clip_id_decode(clip_id: str) -> dict | None:
    try:
        padded = clip_id + ("=" * (-len(clip_id) % 4))
        raw = base64.urlsafe_b64decode(padded.encode("ascii"))
        data = json.loads(raw.decode("utf-8"))
        return data if isinstance(data, dict) else None
    except Exception:
        return None


def _mobile_reports_normalize_ts(value):
    if value is None:
        return None, 0.0
    if isinstance(value, (int, float)):
        try:
            v = float(value)
            return v, v
        except Exception:
            return value, 0.0
    s = str(value).strip()
    if not s:
        return value, 0.0
    for fmt in ("%Y-%m-%d %H:%M:%S", "%Y%m%d-%H%M%S", "%d %b %Y %H:%M:%S"):
        try:
            ts = time.mktime(time.strptime(s, fmt))
            return ts, ts
        except Exception:
            pass
    try:
        v = float(s)
        return v, v
    except Exception:
        return s, 0.0


def _mobile_reports_event_from_local(ev: dict, site_name: str, stream_to_chains: dict) -> dict:
    ts_value, sort_ts = _mobile_reports_normalize_ts(ev.get("ts"))
    clip_name = ev.get("clip") or ""
    stream_name = ev.get("stream", "")
    chain_names = []
    if ev.get("type") == "CHAIN_FAULT":
        chain_value = stream_name
    else:
        chain_names = stream_to_chains.get(stream_name, [])
        chain_value = ", ".join(chain_names)
    clip_id = None
    clip_url = None
    if clip_name and stream_name:
        clip_id = _mobile_reports_clip_id_encode({
            "mode": "local",
            "stream": stream_name,
            "filename": clip_name,
        })
        clip_url = f"/api/mobile/reports/clip/{clip_id}"
    return {
        "id": ev.get("id") or f"local:{stream_name}:{clip_name}:{sort_ts}",
        "ts": ts_value,
        "sort_ts": sort_ts,
        "site": site_name,
        "chain": chain_value,
        "stream": stream_name,
        "type": ev.get("type", ""),
        "message": ev.get("message", ""),
        "level_dbfs": ev.get("level_dbfs", ev.get("level")),
        "rtp_loss_pct": ev.get("rtp_loss_pct"),
        "rtp_jitter_ms": ev.get("rtp_jitter_ms"),
        "ptp_state": ev.get("ptp_state"),
        "ptp_offset_us": ev.get("ptp_offset_us"),
        "ptp_drift_us": ev.get("ptp_drift_us"),
        "ptp_jitter_us": ev.get("ptp_jitter_us"),
        "ptp_gm": ev.get("ptp_gm"),
        "clip": bool(clip_name),
        "clip_name": clip_name or None,
        "clip_id": clip_id,
        "clip_url": clip_url,
        "online": True,
        "source": "local",
    }


def _mobile_reports_event_from_hub(ev: dict) -> dict:
    ts_value, sort_ts = _mobile_reports_normalize_ts(ev.get("ts"))
    clip_name = ev.get("clip") or ""
    stream_name = ev.get("stream", "")
    site_name = ev.get("_site", "?")
    clip_id = None
    clip_url = None
    if clip_name and stream_name and site_name:
        clip_id = _mobile_reports_clip_id_encode({
            "mode": "hub",
            "site": site_name,
            "stream": stream_name,
            "filename": clip_name,
        })
        clip_url = f"/api/mobile/reports/clip/{clip_id}"
    return {
        "id": ev.get("id") or f"hub:{site_name}:{stream_name}:{clip_name}:{sort_ts}",
        "ts": ts_value,
        "sort_ts": sort_ts,
        "site": site_name,
        "chain": ev.get("_chain", ""),
        "stream": stream_name,
        "type": ev.get("type", ""),
        "message": ev.get("message", ""),
        "level_dbfs": ev.get("level_dbfs", ev.get("level")),
        "rtp_loss_pct": ev.get("rtp_loss_pct"),
        "rtp_jitter_ms": ev.get("rtp_jitter_ms"),
        "ptp_state": ev.get("ptp_state"),
        "ptp_offset_us": ev.get("ptp_offset_us"),
        "ptp_drift_us": ev.get("ptp_drift_us"),
        "ptp_jitter_us": ev.get("ptp_jitter_us"),
        "ptp_gm": ev.get("ptp_gm"),
        "clip": bool(clip_name),
        "clip_name": clip_name or None,
        "clip_id": clip_id,
        "clip_url": clip_url,
        "online": bool(ev.get("_online", False)),
        "source": "hub",
    }


def _mobile_reports_events(limit: int = 100, site: str = "", stream: str = "", etype: str = "", chain: str = "", before=None):
    cfg = monitor.app_cfg
    results = []
    before_value = None
    if before not in (None, ""):
        try:
            before_value = float(before)
        except Exception:
            before_value, _ = _mobile_reports_normalize_ts(before)
            if not isinstance(before_value, (int, float, float)):
                before_value = None

    if cfg.hub.mode in ("hub", "both") and hub_server:
        hub_server.set_secret(cfg.hub.secret_key)
        sites = hub_server.get_sites()
        stream_to_chains = _mobile_reports_stream_to_chains(cfg.signal_chains if cfg.hub.mode in ("hub", "both") else [])
        for s in sites:
            site_name = s.get("site", "?")
            if site and site != site_name:
                continue
            for ev in (s.get("recent_alerts", []) or []):
                merged = dict(ev)
                merged["_site"] = site_name
                merged["_client_addr"] = s.get("_client_addr", "")
                merged["_online"] = s.get("online", False)
                ev_stream = merged.get("stream", "")
                if merged.get("type") == "CHAIN_FAULT":
                    merged["_chain"] = ev_stream
                else:
                    merged["_chain"] = ", ".join(stream_to_chains.get(ev_stream, []))
                item = _mobile_reports_event_from_hub(merged)
                if stream and item["stream"] != stream:
                    continue
                if etype and item["type"] != etype:
                    continue
                if chain and item.get("chain", "") != chain:
                    continue
                if before_value is not None and (item.get("sort_ts") or 0) >= before_value:
                    continue
                results.append(item)
    else:
        site_name = cfg.hub.site_name or socket.gethostname()
        stream_to_chains = _mobile_reports_stream_to_chains(cfg.signal_chains)
        for ev in _alert_log_load(max(limit * 5, 500)):
            item = _mobile_reports_event_from_local(ev, site_name, stream_to_chains)
            if site and item["site"] != site:
                continue
            if stream and item["stream"] != stream:
                continue
            if etype and item["type"] != etype:
                continue
            if chain and item.get("chain", "") != chain:
                continue
            if before_value is not None and (item.get("sort_ts") or 0) >= before_value:
                continue
            results.append(item)

    results.sort(key=lambda e: e.get("sort_ts", 0) or 0, reverse=True)
    return results[:max(1, min(int(limit or 100), 500))]


@app.get("/api/mobile/reports/events")
@mobile_api_required
def api_mobile_reports_events():
    limit = request.args.get("limit", default=100, type=int)
    site = (request.args.get("site", "") or "").strip()
    stream = (request.args.get("stream", "") or "").strip()
    etype = (request.args.get("type", "") or "").strip()
    chain = (request.args.get("chain", "") or "").strip()
    before = request.args.get("before")

    events = _mobile_reports_events(limit=limit, site=site, stream=stream, etype=etype, chain=chain, before=before)
    return jsonify({
        "ok": True,
        "results": events,
        "count": len(events),
        "generated_at": time.time(),
    })


@app.get("/api/mobile/reports/summary")
@mobile_api_required
def api_mobile_reports_summary():
    site = (request.args.get("site", "") or "").strip()
    stream = (request.args.get("stream", "") or "").strip()
    etype = (request.args.get("type", "") or "").strip()
    chain = (request.args.get("chain", "") or "").strip()

    events = _mobile_reports_events(limit=500, site=site, stream=stream, etype=etype, chain=chain)
    counts = {}
    site_counts = {}
    with_clips = 0
    for e in events:
        t = e.get("type", "") or "UNKNOWN"
        counts[t] = counts.get(t, 0) + 1
        s = e.get("site", "") or "?"
        site_counts[s] = site_counts.get(s, 0) + 1
        if e.get("clip"):
            with_clips += 1

    return jsonify({
        "ok": True,
        "total": len(events),
        "with_clips": with_clips,
        "counts": counts,
        "sites": [
            {"site": name, "count": count} for name, count in sorted(site_counts.items(), key=lambda kv: (-kv[1], kv[0]))
        ],
        "generated_at": time.time(),
    })


@app.get("/api/mobile/reports/clip/<clip_id>")
@mobile_api_required
def api_mobile_reports_clip(clip_id: str):
    payload = _mobile_reports_clip_id_decode(clip_id) or {}
    mode = (payload.get("mode") or "").strip()
    stream_name = (payload.get("stream") or "").strip()
    filename = os.path.basename((payload.get("filename") or "").strip())
    if not stream_name or not filename:
        return jsonify({"ok": False, "error": "invalid clip id"}), 400

    if mode == "hub":
        site_name = (payload.get("site") or "").strip()
        if not site_name:
            return jsonify({"ok": False, "error": "invalid clip id"}), 400
        return hub_proxy_alert_clip.__wrapped__(site_name, f"{stream_name}/{filename}")

    if mode == "local":
        return clips_serve.__wrapped__(stream_name, filename)

    return jsonify({"ok": False, "error": "invalid clip mode"}), 400


@app.get("/api/mobile/metrics/history")
@mobile_api_required
def api_mobile_metrics_history():
    """Return time-series metric data for one stream from metrics_history.db.

    Query parameters
    ----------------
    stream  : stream display name (required)
    site    : hub site name — when provided the DB key is '{site}/{stream}',
              which matches how _flush_site_metrics() stores remote streams.
              Omit for local streams (stored under the stream name alone).
    metric  : one of the allowlisted metric names (default: level_dbfs)
    hours   : history window in hours — 1, 6, or 24 (default: 6, clamped)
    """
    _ALLOWED_METRICS = {
        "level_dbfs", "lufs_m", "lufs_s", "lufs_i",
        "rtp_loss_pct", "rtp_jitter_ms",
        "fm_signal_dbm", "fm_snr_db",
        "dab_snr", "dab_sig", "dab_bitrate",
        "silence_flag",
    }
    stream = (request.args.get("stream", "") or "").strip()
    site   = (request.args.get("site",   "") or "").strip()
    metric = (request.args.get("metric", "level_dbfs") or "level_dbfs").strip()
    try:
        hours = max(1, min(24, int(request.args.get("hours", 6) or 6)))
    except (ValueError, TypeError):
        hours = 6

    if not stream:
        return jsonify({"ok": False, "error": "stream is required"}), 400
    if metric not in _ALLOWED_METRICS:
        return jsonify({"ok": False, "error": f"metric must be one of: {', '.join(sorted(_ALLOWED_METRICS))}"}), 400

    # Remote streams are stored as "{site}/{stream}"; local streams as "{stream}".
    db_key = f"{site}/{stream}" if site else stream

    cutoff = time.time() - hours * 3600
    try:
        import sqlite3 as _sq_h
        with _sq_h.connect(METRICS_DB_PATH) as _conn:
            rows = _conn.execute(
                "SELECT ts, value FROM metric_history "
                "WHERE stream=? AND metric=? AND ts>=? "
                "ORDER BY ts ASC",
                (db_key, metric, cutoff)
            ).fetchall()
        points = [{"ts": r[0], "value": r[1]} for r in rows]
        return jsonify({
            "ok":     True,
            "stream": stream,
            "site":   site,
            "metric": metric,
            "hours":  hours,
            "points": points,
            "count":  len(points),
        })
    except Exception as exc:
        return jsonify({"ok": False, "error": str(exc)}), 500


@app.get("/api/chains/<cid>/fault_log")
@login_required
def api_chains_fault_log(cid: str):
    """Return the fault log for a chain (up to 100 most recent faults).

    Reads from the SQLite DB then overlays the in-memory _chain_fault_log for
    any entries that are still in the recent window.  In-memory entries are
    always fresher — clips are back-patched into them synchronously, whereas
    the DB write may have a brief delay or may have failed transiently.
    """
    entries = metrics_db.fault_log_load(cid, limit=100)

    # Overlay in-memory entries so clips (and any other live state) are
    # reflected immediately without waiting for the next DB flush.
    if hub_server:
        mem_entries = hub_server._chain_fault_log.get(cid, [])
        if mem_entries:
            mem_by_id = {e["id"]: e for e in mem_entries if e.get("id")}
            for entry in entries:
                fid = entry.get("id", "")
                if fid and fid in mem_by_id:
                    # Merge DB clips with in-memory clips — take the longer
                    # list.  In-memory is fresher for clips that arrived after
                    # the last DB write, but DB can have more if in-memory was
                    # evicted (hub restart / 25-entry ring wrap).  Using the
                    # shorter in-memory list would silently lose already-uploaded
                    # clips.
                    mem_clips = mem_by_id[fid].get("clips") or []
                    db_clips  = entry.get("clips") or []
                    entry["clips"] = mem_clips if len(mem_clips) >= len(db_clips) else db_clips

    notes = _load_chain_notes()
    if notes:
        for entry in entries:
            fid = entry.get("id", "")
            if fid and fid in notes:
                entry["note"]        = notes[fid]["text"]
                entry["note_by"]     = notes[fid]["by"]
                entry["note_ts"]     = notes[fid]["ts"]
                entry["note_edited"] = notes[fid].get("edited_at")
    return jsonify({"entries": list(reversed(entries))})  # newest first


@app.post("/api/chains/notes/<fault_log_id>")
@login_required
@csrf_protect
def api_chain_note_save(fault_log_id: str):
    """Add or update an engineer note on a chain fault log entry.

    Body JSON: {"text": "...", "chain_id": "..."}
    Accepts up to 2000 characters. The chain_id is stored for future filtering but
    the primary key is always the fault_log_id (UUID).
    """
    from flask import session as _sess
    fault_log_id = fault_log_id.strip()
    if not fault_log_id:
        return jsonify({"ok": False, "error": "missing fault_log_id"}), 400
    data  = request.json or {}
    text  = str(data.get("text", "")).strip()[:2000]
    by    = _sess.get("user", "admin")
    if not text:
        return jsonify({"ok": False, "error": "note text cannot be empty"}), 400
    record = _save_chain_note(fault_log_id, text, by)
    return jsonify({"ok": True, "fault_log_id": fault_log_id, "record": record})


@app.get("/api/chains/clip/<clip_key>/<fname>")
@login_required
def api_chains_clip_download(clip_key: str, fname: str):
    """Serve a chain fault audio clip with full Range-request support.

    Pass ?dl=1 to force a download (Content-Disposition: attachment).
    Default serves inline so <audio> elements work in the browser.

    Uses _serve_clip_wav() rather than send_from_directory() so that
    Chrome/Safari Range requests (always sent before audio playback)
    receive a proper 206 Partial Content response.  send_from_directory
    relies on Werkzeug's conditional machinery which is version-sensitive
    and can silently return a 200 full response instead of 206, causing
    the <audio> element to error or stall.
    """
    if ".." in clip_key or ".." in fname or "/" in fname or "\\" in fname:
        return "Bad request", 400
    snip_dir = os.path.join(BASE_DIR, "alert_snippets")
    clip_dir = os.path.join(snip_dir, clip_key)
    # Containment check — clip_dir must be inside alert_snippets/
    if not os.path.abspath(clip_dir).startswith(os.path.abspath(snip_dir) + os.sep):
        return "Forbidden", 403
    path = os.path.join(clip_dir, fname)
    return _serve_clip_wav(path, force_download=request.args.get("dl") == "1")


@app.get("/api/mobile/ab_groups")
@mobile_api_required
def api_mobile_ab_groups():
    """Return all configured A/B groups with live status for the iOS app."""
    cfg    = monitor.app_cfg
    groups = cfg.ab_groups or []
    states = hub_server._abgroup_states if hub_server else {}
    chains_by_id = {c.get("id"): c.get("name", c.get("id", ""))
                    for c in (cfg.signal_chains or [])}
    result = []
    for grp in groups:
        gid = grp.get("id", "")
        st  = states.get(gid, {
            "status": "unknown", "a_ok": True, "b_ok": True,
            "rx_ok": True, "since": 0.0,
        })
        result.append({
            "id":           gid,
            "name":         grp.get("name", gid),
            "active_role":  grp.get("active_role", "a"),
            "notes":        grp.get("notes", ""),
            "chain_a_id":   grp.get("chain_a_id", ""),
            "chain_a_name": chains_by_id.get(grp.get("chain_a_id", ""),
                                             grp.get("chain_a_id", "")),
            "chain_b_id":   grp.get("chain_b_id", ""),
            "chain_b_name": chains_by_id.get(grp.get("chain_b_id", ""),
                                             grp.get("chain_b_id", "")),
            "status":  st.get("status", "unknown"),  # "ok"|"warn"|"fault"|"unknown"
            "a_ok":    st.get("a_ok", True),
            "b_ok":    st.get("b_ok", True),
            "rx_ok":   st.get("rx_ok", True),
            "since":   st.get("since", 0.0),
        })
    return jsonify({"ok": True, "results": result, "count": len(result)})


@app.get("/api/mobile/clip/<clip_key>/<fname>")
@mobile_api_required
def api_mobile_clip_download(clip_key: str, fname: str):
    """Serve a chain fault audio clip for the mobile app.

    Uses mobile token auth (Bearer / X-API-Key / ?token=) so the iOS
    app can stream or download the clip directly with AVPlayer.
    """
    if ".." in clip_key or ".." in fname or "/" in fname or "\\" in fname:
        return "Bad request", 400
    clip_dir = os.path.join(BASE_DIR, "alert_snippets", clip_key)
    if not os.path.isdir(clip_dir):
        return "Not found", 404
    # Stream inline (not as attachment) so AVPlayer can handle it
    return send_from_directory(clip_dir, fname, as_attachment=False)


@app.post("/api/chains/<cid>/maintenance_all")
@login_required
@csrf_protect
def api_chain_maintenance_all(cid: str):
    """Set or clear maintenance mode for ALL nodes in a chain at once.
    POST body: {"duration": <seconds>}  — duration=0 clears.
    """
    if not hub_server:
        return jsonify({"ok": False, "error": "No hub server"}), 400
    data     = request.get_json(silent=True) or {}
    duration = int(data.get("duration", 0))
    cfg      = monitor.app_cfg
    chains   = cfg.signal_chains or [] if cfg else []
    chain    = next((c for c in chains if c.get("id") == cid), None)
    if not chain:
        return jsonify({"ok": False, "error": "chain not found"}), 404
    maint  = hub_server._chain_maintenance.setdefault(cid, {})
    expiry = time.time() + duration if duration > 0 else 0
    count  = 0
    for node in _iter_chain_leaf_nodes(chain):
        site   = node.get("site", "")
        stream = node.get("stream", "")
        if not site or not stream:
            continue
        mkey = f"{site}|{stream}"
        if duration <= 0:
            maint.pop(mkey, None)
        else:
            maint[mkey] = expiry
        count += 1
    action = f"set ({duration}s)" if duration > 0 else "cleared"
    monitor.log(f"[Chain] Maintenance {action} for all {count} node(s) in chain {cid!r}")
    return jsonify({"ok": True, "nodes": count, "expiry": expiry})


@app.post("/api/chains/<cid>/maintenance")
@login_required
@csrf_protect
def api_chain_maintenance(cid: str):
    """Set or clear maintenance mode for a node in a chain.
    POST body: {"site": "...", "stream": "...", "duration": <seconds>}
    duration=0 clears maintenance.
    """
    if not hub_server:
        return jsonify({"ok": False, "error": "No hub server"}), 400
    data = request.get_json(silent=True) or {}
    site     = str(data.get("site", "")).strip()
    stream   = str(data.get("stream", "")).strip()
    duration = int(data.get("duration", 0))
    if not site or not stream:
        return jsonify({"ok": False, "error": "site and stream required"}), 400
    mkey = f"{site}|{stream}"
    maint = hub_server._chain_maintenance.setdefault(cid, {})
    if duration <= 0:
        maint.pop(mkey, None)
        monitor.log(f"[Chain] Maintenance cleared for {mkey} in chain {cid}")
    else:
        expiry = time.time() + duration
        maint[mkey] = expiry
        monitor.log(f"[Chain] Maintenance set for {mkey} in chain {cid} — expires in {duration}s")
    return jsonify({"ok": True, "expiry": maint.get(mkey, 0)})


@app.get("/api/chains/levels")
@login_required
def api_chains_levels():
    """Lightweight endpoint: return raw live level_dbfs for every known stream.

    Intentionally avoids eval_chain(), SQLite, and any fault-detection logic.
    Takes a single atomic snapshot of _sites under the lock so every node in
    every chain on the page sees data from the same instant — preventing the
    'stacks not in sync' visual artefact that occurs when the 5-second status
    poll evaluates chains sequentially.

    Response: { ok: true, levels: { site: { stream: { level, silence } } } }
    'local' site uses monitor.app_cfg.inputs directly.
    Offline remote sites appear as { site: { _offline: true } }.
    """
    cfg = monitor.app_cfg
    now = time.time()
    result: dict = {}

    # Local streams — read directly from the monitor input objects
    local: dict = {}
    for inp in cfg.inputs:
        if inp.enabled:
            lev = inp._last_level_dbfs
            local[inp.name] = {
                "level":   round(lev, 1),
                "silence": lev <= inp.silence_threshold_dbfs,
            }
    if local:
        result["local"] = local

    # Remote streams — one lock acquisition, single consistent snapshot
    if hub_server:
        with hub_server._lock:
            for sname, data in hub_server._sites.items():
                age    = now - data.get("_received", 0)
                online = age < HUB_SITE_TIMEOUT
                if not online:
                    result[sname] = {"_offline": True}
                    continue
                streams_out: dict = {}
                for st in data.get("streams", []):
                    name = st.get("name", "")
                    if not name:
                        continue
                    lev    = float(st.get("level_dbfs", -120.0))
                    thresh = st.get("silence_threshold_dbfs")
                    _thr   = float(thresh) if thresh is not None else -55.0
                    streams_out[name] = {
                        "level":   round(lev, 1),
                        "silence": lev <= _thr,
                    }
                result[sname] = streams_out

    resp = jsonify({"ok": True, "levels": result})
    resp.headers["Cache-Control"] = "no-store"
    return resp


@app.post("/api/chains/test_alert")
@login_required
@csrf_protect
def api_chains_test_alert():
    """Send a clearly-labelled [TEST] chain fault alert through all configured channels.

    Does NOT create a real fault log entry, modify chain state, or affect SLA tracking.
    Useful for verifying that email / webhook / Pushover / APNs notifications are working.
    """
    cfg = monitor.app_cfg
    chains = cfg.signal_chains or []

    # Pick a chain to reference in the test message — first one if any exist
    if chains:
        ref_chain = chains[0]
        chain_name = ref_chain.get("name", "Test Chain")
        chain_id   = ref_chain.get("id", "test")
    else:
        chain_name = "Test Chain"
        chain_id   = "test"

    title = f"[TEST] CHAIN FAULT — {chain_name}"
    msg   = (f"[TEST ALERT] This is a test notification sent from the SignalScope "
             f"Broadcast Chains page. If you received this, your alert channels are "
             f"working correctly. Chain: '{chain_name}'.")

    # Fire everything on a background thread so the HTTP response returns immediately
    # (email/SMTP can block for several seconds if the server is slow to respond)
    def _do_send():
        try:
            sender = AlertSender(cfg, monitor.log)
            sender.send(title, msg, None, alert_type="CHAIN_FAULT", stream=chain_name)
        except Exception as e:
            monitor.log(f"[Chain] Test alert send error: {e}")
        try:
            _dispatch_push(
                title=title,
                body=msg[:180],
                data={"type": "chain_fault", "chain_id": chain_id, "test": "1"},
            )
        except Exception as e:
            monitor.log(f"[Push] Test alert push error: {e}")

    threading.Thread(target=_do_send, daemon=True).start()
    monitor.log(f"[Chain] Test alert dispatched — chain='{chain_name}'")
    return jsonify({"ok": True})


@app.get("/api/chains/apns_status")
@login_required
def api_chains_apns_status():
    """Return APNs configuration and registered token diagnostic info."""
    ma = getattr(monitor.app_cfg, "mobile_api", None)
    tokens = []
    configured = False
    if ma:
        configured = bool(
            getattr(ma, "apns_key_id", "") and getattr(ma, "apns_team_id", "") and
            getattr(ma, "apns_bundle_id", "") and getattr(ma, "apns_key_pem", "")
        )
        for entry in getattr(ma, "apns_device_tokens", []):
            tok = _apns_token_str(entry)
            tokens.append({
                "token_prefix": tok[:12] + "…" if tok else "",
                "env": "sandbox" if _apns_token_is_sandbox(entry) else "production",
                "format": "dict" if isinstance(entry, dict) else "legacy_string",
            })
    # Probe both APNs endpoints with a dummy token to check key authorisation.
    # BadDeviceToken → key IS accepted by that endpoint (token is bad, but key is fine).
    # BadEnvironmentKeyInToken / InvalidProviderToken / Forbidden → key is NOT authorised.
    key_probe = {"sandbox": "not_tested", "production": "not_tested"}
    if configured and _HTTPX_HTTP2:
        try:
            import json as _j
            import httpx as _hx
            ma2 = getattr(monitor.app_cfg, "mobile_api", None)
            jwt = _get_apns_jwt(ma2)
            bundle = getattr(ma2, "apns_bundle_id", "").strip()
            dummy = "00" * 32   # 64-char hex dummy token
            hdrs = lambda: {
                "authorization": f"bearer {jwt}",
                "apns-topic": bundle,
                "apns-priority": "10",
                "apns-push-type": "alert",
                "content-type": "application/json",
            }
            payload = _j.dumps({"aps": {"alert": {"title": "probe", "body": "probe"}}}).encode()
            with _hx.Client(http2=True, timeout=8.0) as cl:
                for env_name, host in [("sandbox", "api.sandbox.push.apple.com"),
                                       ("production", "api.push.apple.com")]:
                    try:
                        r = cl.post(f"https://{host}/3/device/{dummy}",
                                    headers=hdrs(), content=payload)
                        try:
                            reason = r.json().get("reason", r.text[:60])
                        except Exception:
                            reason = r.text[:60]
                        key_probe[env_name] = f"HTTP {r.status_code} — {reason}"
                    except Exception as pe:
                        key_probe[env_name] = f"error: {pe}"
        except Exception as ex:
            key_probe = {"error": str(ex)}

    return jsonify({
        "httpx_http2": _HTTPX_HTTP2,
        "apns_configured": configured,
        "token_count": len(tokens),
        "tokens": tokens,
        "key_probe": key_probe,
    })


@app.post("/api/chains")
@login_required
@csrf_protect
def api_chains_save():
    """Create or update a signal chain."""
    import uuid as _uuid
    data = request.get_json(force=True) or {}
    name  = str(data.get("name", "")).strip()
    nodes = data.get("nodes", [])
    if not name:
        return jsonify({"ok": False, "error": "name required"}), 400
    # Sanitise nodes (supports regular nodes and stack nodes)
    def _clean_single_node(n):
        site    = str(n.get("site", "")).strip()
        stream  = str(n.get("stream", "")).strip()
        label   = str(n.get("label", "")).strip()
        machine = str(n.get("machine", "")).strip()
        if site and stream:
            node = {"site": site, "stream": stream, "label": label}
            if machine:
                node["machine"] = machine
            return node
        return None

    clean_nodes = []
    for n in nodes:
        if n.get("type") == "stack":
            sub_clean = [_clean_single_node(s) for s in n.get("nodes", [])]
            sub_clean = [s for s in sub_clean if s]
            if sub_clean:
                mode = n.get("mode", "all")
                if mode not in ("any", "all"):
                    mode = "all"
                clean_nodes.append({
                    "type":  "stack",
                    "mode":  mode,
                    "label": str(n.get("label", "")).strip(),
                    "nodes": sub_clean,
                })
        else:
            cn = _clean_single_node(n)
            if cn:
                clean_nodes.append(cn)
    # Sanitise comparators — validate indices are in range and not equal
    clean_comps = []
    for comp in data.get("comparators", []):
        try:
            fi = int(comp.get("from_idx", 0))
            ti = int(comp.get("to_idx",   1))
            if fi >= 0 and ti >= 0 and fi != ti and fi < len(clean_nodes) and ti < len(clean_nodes):
                clean_comps.append({"from_idx": fi, "to_idx": ti})
        except (TypeError, ValueError):
            pass
    cfg    = monitor.app_cfg
    chains = list(cfg.signal_chains)
    cid    = str(data.get("id", "")).strip()
    # Fault confirmation delay — clamp to 0–3600 s (0 = alert immediately)
    try:
        min_fault_seconds = max(0, min(3600, int(data.get("min_fault_seconds", 0) or 0)))
    except (TypeError, ValueError):
        min_fault_seconds = 0
    # Ad mix-in point — node index whose silence proves the fault is real (not an ad break)
    mixin_raw = data.get("mixin_node_idx")
    if mixin_raw is not None and mixin_raw != "":
        try:
            mixin_node_idx: "Optional[int]" = int(mixin_raw)
            if not (0 <= mixin_node_idx < len(clean_nodes)):
                mixin_node_idx = None   # out of range after node list was trimmed
        except (TypeError, ValueError):
            mixin_node_idx = None
    else:
        mixin_node_idx = None
    # fault_tail_secs: post-recovery tail before saving recovery clips (default 20.0)
    try:
        fault_tail_secs = float(data.get("fault_tail_secs", 20.0))
        if fault_tail_secs < 0:
            fault_tail_secs = 0.0
    except (TypeError, ValueError):
        fault_tail_secs = 20.0
    # record_all_nodes: save clips from every chain node on fault/recovery (default True)
    record_all_nodes = bool(data.get("record_all_nodes", True))
    # fault_shift_grace_seconds: when fault_index shifts during the confirmation window,
    # give the new position this many seconds before firing (0 = keep original clock)
    try:
        fault_shift_grace_seconds = max(0, min(300, int(data.get("fault_shift_grace_seconds", 0) or 0)))
    except (TypeError, ValueError):
        fault_shift_grace_seconds = 0
    # adbreak_gap_tolerance_seconds: max inter-ad silence gap to stitch into one
    # confirmation window (badly-segued ads). 0 = disable stitching. Default 5 s.
    try:
        adbreak_gap_tolerance_seconds = max(0, min(30, int(data.get("adbreak_gap_tolerance_seconds", 5) or 5)))
    except (TypeError, ValueError):
        adbreak_gap_tolerance_seconds = 5
    # min_recovery_seconds: how long the chain must stay ok before CHAIN_RECOVERED fires (Change 1)
    try:
        min_recovery_seconds = max(0, min(3600, int(data.get("min_recovery_seconds", 0) or 0)))
    except (TypeError, ValueError):
        min_recovery_seconds = 0
    # min_alert_interval_minutes: minimum time between notifications for this chain (Change 4)
    try:
        min_alert_interval_minutes = max(0, min(1440, int(data.get("min_alert_interval_minutes", 0) or 0)))
    except (TypeError, ValueError):
        min_alert_interval_minutes = 0
    # trend_alert_dbfs_per_min: fire CHAIN_DEGRADING when slope <= this value (Change 6); 0 = disabled
    try:
        trend_alert_dbfs_per_min = float(data.get("trend_alert_dbfs_per_min", 0.0) or 0.0)
    except (TypeError, ValueError):
        trend_alert_dbfs_per_min = 0.0
    # upstream_chain_id: suppress notifications if upstream chain is faulted (Change 7)
    upstream_chain_id = str(data.get("upstream_chain_id", "") or "").strip()
    # clip_seconds: duration for onset fault/recovery clips for this chain.
    # 0 / None = use CHAIN_CLIP_MIN_SECS default. Clamped to [10, 300].
    _clip_sec_raw = data.get("clip_seconds")
    try:
        clip_seconds = float(_clip_sec_raw) if _clip_sec_raw not in (None, "", 0) else 0.0
        if clip_seconds < 1:
            clip_seconds = 0.0   # treat as "use default"
        else:
            clip_seconds = max(CHAIN_CLIP_MIN_SECS, min(CHAIN_CLIP_MAX_SECS, clip_seconds))
    except (TypeError, ValueError):
        clip_seconds = 0.0
    chain_dict = {"id": cid if cid else "", "name": name,
                  "nodes": clean_nodes, "comparators": clean_comps,
                  "min_fault_seconds": min_fault_seconds,
                  "mixin_node_idx": mixin_node_idx,
                  "fault_tail_secs": fault_tail_secs,
                  "record_all_nodes": record_all_nodes,
                  "fault_shift_grace_seconds": fault_shift_grace_seconds,
                  "adbreak_gap_tolerance_seconds": adbreak_gap_tolerance_seconds,
                  "min_recovery_seconds": min_recovery_seconds,
                  "min_alert_interval_minutes": min_alert_interval_minutes,
                  "trend_alert_dbfs_per_min": trend_alert_dbfs_per_min,
                  "upstream_chain_id": upstream_chain_id,
                  "clip_seconds": clip_seconds}
    if cid:
        # Update existing
        for i, c in enumerate(chains):
            if c.get("id") == cid:
                chains[i] = chain_dict
                break
        else:
            chains.append(chain_dict)
    else:
        # New chain
        cid = str(_uuid.uuid4())
        chain_dict["id"] = cid
        chains.append(chain_dict)
    cfg.signal_chains = chains
    save_config(cfg)
    return jsonify({"ok": True, "id": cid})


