@app.post("/api/ab_groups/<group_id>/toggle_active")
@login_required
@csrf_protect
def api_ab_groups_toggle(group_id):
    """Toggle active role between a and b."""
    cfg    = monitor.app_cfg
    groups = list(cfg.ab_groups or [])
    for g in groups:
        if g.get("id") == group_id:
            g["active_role"] = "b" if g.get("active_role", "a") == "a" else "a"
            break
    cfg.ab_groups = groups
    save_config(cfg)
    active = next((g.get("active_role","a") for g in groups if g.get("id") == group_id), "a")
    return jsonify({"ok": True, "active_role": active})


@app.get("/hub/reports")
@login_required
def hub_reports():
    """Merged alert reports from all connected sites."""
    cfg = monitor.app_cfg
    if cfg.hub.mode not in ("hub","both"):
        return "Not a hub", 404
    hub_server.set_secret(cfg.hub.secret_key)
    sites = hub_server.get_sites()

    # Build stream→chain lookup from hub chain config
    # A stream may appear in multiple chains, so map to a list then join for display.
    chain_cfg = cfg.signal_chains if cfg.hub.mode in ("hub","both") else []
    stream_to_chains: dict = {}   # stream_name → [chain_name, ...]
    chain_names_list: list = []
    for ch in chain_cfg:
        cname = ch.get("name","")
        if cname and cname not in chain_names_list:
            chain_names_list.append(cname)
        for node in ch.get("nodes", []):
            # Expand stack nodes to their sub-nodes
            subs = node.get("nodes", []) if node.get("type") == "stack" else [node]
            for sub in subs:
                sname = sub.get("stream","")
                if sname:
                    stream_to_chains.setdefault(sname, [])
                    if cname not in stream_to_chains[sname]:
                        stream_to_chains[sname].append(cname)

    # Merge all sites' recent_alerts, tagging each with site name and chain membership
    all_events = []
    seen_ids: set = set()
    for s in sites:
        client_addr = s.get("_client_addr","")
        site_name   = s.get("site","?")
        for ev in s.get("recent_alerts", []):
            merged = dict(ev)
            merged["_site"]        = site_name
            merged["_client_addr"] = client_addr
            merged["_online"]      = s.get("online", False)
            ev_stream = merged.get("stream","")
            # CHAIN_FAULT events: stream field holds the chain name directly
            if merged.get("type") == "CHAIN_FAULT":
                merged["_chain"] = ev_stream
            else:
                merged["_chain"] = ", ".join(stream_to_chains.get(ev_stream, []))
            all_events.append(merged)
            if ev.get("id"):
                seen_ids.add(ev["id"])

    # Also merge the hub's own alert log.  CHAIN_FAULT events are written here
    # by _fire_chain_fault() but are never included in any site's recent_alerts
    # in pure hub-mode deployments, so they would always show as "0" above.
    # In both-mode nodes the hub IS a client site and its recent_alerts already
    # carries these events; seen_ids deduplication prevents double-counting.
    for ev in _alert_log_load(2000):
        eid = ev.get("id", "")
        if eid and eid in seen_ids:
            continue
        merged = dict(ev)
        merged["_site"]        = "(hub)"
        merged["_client_addr"] = ""
        merged["_online"]      = True
        ev_stream = merged.get("stream", "")
        if merged.get("type") == "CHAIN_FAULT":
            merged["_chain"] = ev_stream
        else:
            merged["_chain"] = ", ".join(stream_to_chains.get(ev_stream, []))
        all_events.append(merged)
        if eid:
            seen_ids.add(eid)

    # Sort newest first
    all_events.sort(key=lambda e: e.get("ts",""), reverse=True)

    # Merge in any hub-stored feedback labels so buttons show current state
    try:
        _hub_fb = _load_alert_feedback()
        if _hub_fb:
            for _ev in all_events:
                _aid = _ev.get("id","")
                if _aid and _aid in _hub_fb:
                    _ev["feedback"] = _hub_fb[_aid]["feedback"]
    except Exception:
        pass

    # Filter params
    f_site   = request.args.get("site","")
    f_stream = request.args.get("stream","")
    f_type   = request.args.get("type","")
    f_chain  = request.args.get("chain","")

    site_names  = sorted(set(e["_site"]   for e in all_events))
    stream_names= sorted(set(e.get("stream","") for e in all_events if e.get("stream")))
    # Always include silence-family types so the filter is stable even when no
    # recent silence events are in the current window (e.g. 50-event heartbeat
    # window displaced older silence events with newer non-silence events).
    _SILENCE_TYPES = {"SILENCE", "STUDIO_FAULT", "STL_FAULT", "TX_DOWN",
                      "DAB_AUDIO_FAULT", "RTP_FAULT",
                      "AUDIO_GLITCH", "AUDIO_GLITCH_SUSTAINED", "AUDIO_FLATNESS",
                      "ABGROUP_OFF_AIR", "ABGROUP_BOTH_FAULT", "ABGROUP_A_FAULT",
                      "ABGROUP_B_FAULT", "ABGROUP_RX_FAULT", "ABGROUP_RECOVERED"}
    type_names  = sorted(
        set(e.get("type","") for e in all_events if e.get("type")) | _SILENCE_TYPES
    )

    counts = {}
    for e in all_events:
        counts[e.get("type","")] = counts.get(e.get("type",""), 0) + 1
    with_clips = sum(1 for e in all_events if e.get("clip"))

    return render_template_string(HUB_REPORTS_TPL,
        events=all_events, total=len(all_events),
        counts=counts, site_names=site_names,
        stream_names=stream_names, type_names=type_names,
        chain_names=chain_names_list,
        with_clips=with_clips, build=BUILD,
        f_site=f_site, f_stream=f_stream, f_type=f_type, f_chain=f_chain,
    )


# Update heartbeat ingestion to record client IP
# client_ip is now passed directly in hub_heartbeat — no monkey-patch needed

HUB_REPORTS_TPL = r"""<!doctype html><html lang="en"><head><meta charset="utf-8">
<meta name="csrf-token" content="{{csrf_token()}}">
<title>Hub Alert Reports — SignalScope</title>
<style nonce="{{csp_nonce()}}">
:root{--bg:#07142b;--sur:#0d2346;--bor:#17345f;--acc:#17a8ff;--ok:#22c55e;--wn:#f59e0b;--al:#ef4444;--tx:#eef5ff;--mu:#8aa4c8}
*{box-sizing:border-box;margin:0;padding:0}
body{font-family:system-ui,sans-serif;background:radial-gradient(circle at top, #12376f 0%, var(--bg) 42%, #05101f 100%);color:var(--tx);font-size:13px;position:relative}
body::before{content:"";position:fixed;right:28px;bottom:22px;width:280px;height:280px;background:url("/static/signalscope_icon.png") no-repeat center/contain;opacity:.045;pointer-events:none;filter:drop-shadow(0 0 24px rgba(23,168,255,.10));z-index:0}
body>*{position:relative;z-index:1}
a{color:var(--acc);text-decoration:none}
header{background:linear-gradient(180deg, rgba(10,31,65,.96), rgba(9,24,48,.96));border-bottom:1px solid var(--bor);padding:12px 20px;display:flex;align-items:center;gap:10px;flex-wrap:wrap;box-shadow:0 10px 24px rgba(0,0,0,.18)}
nav{display:flex;gap:6px;margin-left:auto;flex-wrap:wrap;align-items:center}
.badge{font-size:11px;padding:2px 8px;border-radius:999px;background:#1e3a5f;color:var(--acc)}
.btn{display:inline-block;padding:5px 12px;border-radius:8px;font-size:13px;cursor:pointer;border:none;text-decoration:none;font-weight:600}.btn:hover{filter:brightness(1.05)}
.bg{background:var(--bor);color:var(--tx)}.bp{background:var(--acc);color:#fff}.bw{background:#7c2d12;color:#fca5a5}
.bd{background:var(--al);color:#fff}.bs{padding:3px 9px;font-size:12px}.nav-active{background:var(--acc)!important;color:#fff!important}
/* Hub reports uses the shared topnav/header styling from the main app */
main{padding:18px 20px 24px}
.report-hero{display:flex;gap:12px;align-items:center;justify-content:space-between;flex-wrap:wrap;padding:14px 18px;background:linear-gradient(180deg,#12305c,#10284f);border:1px solid var(--bor);border-radius:12px;margin-bottom:14px}
.report-title{font-size:20px;font-weight:800;line-height:1.1}
.report-sub{font-size:12px;color:var(--mu);margin-top:4px}
.hero-actions{display:flex;gap:8px;align-items:center;flex-wrap:wrap}
.filters{display:flex;gap:8px;margin-bottom:6px;flex-wrap:wrap;align-items:center;background:linear-gradient(180deg,#12305c,#10284f);border:1px solid var(--bor);border-radius:12px;padding:12px}
.filters select{background:#173a69;border:1px solid var(--bor);border-radius:6px;color:var(--tx);padding:6px 10px;font-size:12px;min-width:0;max-width:160px}
.filters label{color:var(--mu);font-size:12px;white-space:nowrap}
.filter-sub{display:flex;gap:12px;align-items:center;flex-wrap:wrap;margin-bottom:14px;padding:0 4px}
.filter-sub label{color:var(--mu);font-size:12px;white-space:nowrap}
.filter-sub input{background:#173a69;border:1px solid var(--bor);border-radius:6px;color:var(--tx);padding:5px 9px;font-size:12px}
.filter-sub span{color:var(--mu);font-size:12px;margin-left:auto}
.summary{display:grid;grid-template-columns:repeat(auto-fit,minmax(170px,1fr));gap:12px;margin-bottom:14px}
.sc{background:linear-gradient(180deg,#12305c,#10284f);border:1px solid var(--bor);border-radius:12px;padding:12px 14px;box-shadow:0 4px 10px rgba(0,0,0,.14);cursor:pointer;transition:border-color .15s,box-shadow .15s,background .15s;user-select:none}
.sc:hover{border-color:var(--acc);box-shadow:0 0 0 2px rgba(23,168,255,.18)}
.sc.sc-active{border-color:var(--acc);box-shadow:0 0 0 3px rgba(23,168,255,.35);background:linear-gradient(180deg,#153461,#102a54)}
.sc-val{font-size:24px;font-weight:800;line-height:1.1}.sc-lbl{font-size:11px;color:var(--mu);margin-top:4px;text-transform:uppercase;letter-spacing:.08em}
.metrics-strip{display:flex;gap:8px;flex-wrap:wrap;margin-bottom:14px}.metric-chip{padding:8px 10px;border:1px solid var(--bor);border-radius:999px;background:#12305c;font-size:12px}.metric-chip strong{color:var(--tx)}
.table-wrap{border:1px solid var(--bor);border-radius:12px;overflow-x:auto;overflow-y:visible;background:rgba(13,35,70,.96);box-shadow:0 4px 10px rgba(0,0,0,.14)}
table{width:100%;border-collapse:collapse}
thead th{text-align:left;padding:8px 10px;background:#12305c;border-bottom:2px solid var(--bor);font-size:11px;color:#c5dcff;text-transform:uppercase;letter-spacing:.05em;white-space:nowrap;position:sticky;top:0;z-index:2}
tbody td{padding:8px 10px;border-bottom:1px solid var(--bor);vertical-align:top}
tr:hover td{background:#123764}
.type-badge{display:inline-block;padding:2px 7px;border-radius:999px;font-size:11px;font-weight:600;white-space:nowrap}
.site-badge{display:inline-block;padding:2px 7px;border-radius:999px;font-size:11px;background:#1e2a3a;color:var(--acc);white-space:nowrap}
.offline-site{opacity:0.6}
.t-silence{background:#173a69;color:#93c5fd}.t-clip{background:#3a1e1e;color:#fca5a5}
.t-hiss{background:#2a2a1e;color:#fde68a}.t-rtp{background:#173a69;color:#c4b5fd}
.t-ai_alert{background:#3a1e1e;color:#fca5a5}.t-ai_warn{background:#3a2a0f;color:#fde68a}
.t-ptp{background:#1e3a2a;color:#86efac}.t-cmp{background:#2a1e3a;color:#d8b4fe}
.t-chain_fault{background:#4a1010;color:#fca5a5;font-weight:700}
.t-other{background:var(--bor);color:var(--mu)}
.chain-badge{display:inline-block;padding:2px 7px;border-radius:999px;font-size:11px;background:#1e2e1a;color:#86efac;white-space:nowrap;font-weight:600;max-width:180px;overflow:hidden;text-overflow:ellipsis;vertical-align:middle}
.chain-row td{border-left:3px solid var(--al)}
.level-bar{display:inline-block;width:60px;height:6px;background:var(--bor);border-radius:3px;vertical-align:middle;margin-left:4px}
.level-fill{height:6px;border-radius:3px}
/* Mini-player */
#mini-player{position:fixed;bottom:0;left:0;right:0;z-index:9999;background:linear-gradient(180deg,#0d2346 0%,#070f24 100%);border-top:2px solid var(--acc);padding:10px 18px;display:none;align-items:center;gap:14px;box-shadow:0 -6px 28px rgba(0,0,0,.5);flex-wrap:wrap}
#mp-info{min-width:0;flex:0 1 200px}
#mp-title{font-size:13px;font-weight:700;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;color:var(--tx)}
#mp-sub{font-size:11px;color:var(--mu);margin-top:2px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}
#mp-audio{flex:1;min-width:200px;height:32px;accent-color:var(--acc)}
#mp-dl{color:var(--acc);font-size:12px;white-space:nowrap;text-decoration:none;background:#1e3a5f;border:1px solid var(--bor);border-radius:6px;padding:5px 12px;display:inline-flex;align-items:center;gap:4px}
#mp-close{background:none;border:1px solid var(--bor);border-radius:6px;color:var(--mu);font-size:16px;cursor:pointer;padding:4px 9px;line-height:1;flex-shrink:0}
#mp-close:hover{border-color:var(--al);color:var(--al)}
.play-clip-btn{display:inline-flex;align-items:center;gap:5px;background:#17345f;border:1px solid var(--acc);border-radius:6px;color:var(--acc);font-size:11px;font-weight:600;cursor:pointer;padding:3px 9px;white-space:nowrap;line-height:1.4;transition:background .12s}
.play-clip-btn:hover{background:#1e4a80}
.play-clip-btn.mp-active{background:var(--acc);color:#fff;border-color:var(--acc)}
.no-data{text-align:center;padding:48px;color:var(--mu)}
.page-info{color:var(--mu);font-size:12px;margin-left:auto}
.fb-wrap{display:flex;gap:4px;align-items:center;margin-top:5px;flex-wrap:wrap}
.fb-btn{display:inline-flex;align-items:center;justify-content:center;width:26px;height:26px;border-radius:5px;font-size:13px;cursor:pointer;border:1px solid var(--bor);background:var(--sur);transition:background .12s,border-color .12s;line-height:1;padding:0}
.fb-btn:hover{filter:brightness(1.3)}
.fb-btn.fb-ok{background:#14532d;border-color:#22c55e}
.fb-btn.fb-bad{background:#450a0a;border-color:#ef4444}
.fb-lbl{font-size:10px;color:var(--mu)}
.fb-lbl.fb-lbl-ok{color:var(--ok)}.fb-lbl.fb-lbl-bad{color:var(--al)}
</style>
<link rel="icon" type="image/x-icon" href="/static/signalscope_icon.png"></head><body>
{{ topnav("hub_reports") }}
<main>
  <div style="display:flex;gap:8px;align-items:center;flex-wrap:wrap;margin-bottom:10px">
    <span class="badge">{{total}} events from {{site_names|length}} site{{"s" if site_names|length!=1 else ""}}</span>
  </div>
  <div class="summary">
    <div class="sc" data-ftypes="" onclick="filterByStat(this)" title="Show all events"><div class="sc-val" id="sc-total">{{total}}</div><div class="sc-lbl">Total Events</div></div>
    <div class="sc" data-ftypes="SILENCE,AI_ALERT,RTP_LOSS,CLIP,STUDIO_FAULT,STL_FAULT,TX_DOWN" onclick="filterByStat(this)" title="Filter: critical events"><div class="sc-val" id="sc-critical" style="color:var(--al)">{{counts.get('SILENCE',0)+counts.get('AI_ALERT',0)+counts.get('RTP_LOSS',0)+counts.get('STUDIO_FAULT',0)+counts.get('STL_FAULT',0)+counts.get('TX_DOWN',0)}}</div><div class="sc-lbl">🔴 Critical</div></div>
    <div class="sc" data-ftypes="CHAIN_FAULT" onclick="filterByStat(this)" title="Filter: chain fault events"><div class="sc-val" style="color:var(--al)">{{counts.get('CHAIN_FAULT',0)}}</div><div class="sc-lbl">⛓ Chain Faults</div></div>
    <div class="sc" data-ftypes="AI_WARN,RTP_LOSS_WARN,HISS,DAB_SERVICE_MISSING" onclick="filterByStat(this)" title="Filter: warnings"><div class="sc-val" id="sc-warn" style="color:var(--wn)">{{counts.get('AI_WARN',0)+counts.get('RTP_LOSS_WARN',0)+counts.get('HISS',0)+counts.get('DAB_SERVICE_MISSING',0)}}</div><div class="sc-lbl">🟡 Warnings</div></div>
    <div class="sc" data-ftypes="RTP_LOSS,RTP_LOSS_WARN" onclick="filterByStat(this)" title="Filter: RTP loss events"><div class="sc-val" style="color:var(--acc)">{{counts.get('RTP_LOSS',0)+counts.get('RTP_LOSS_WARN',0)}}</div><div class="sc-lbl">📦 RTP Loss</div></div>
    <div class="sc" data-ftypes="PTP_OFFSET,PTP_JITTER,PTP_LOST,PTP_GM_CHANGE" onclick="filterByStat(this)" title="Filter: PTP events"><div class="sc-val" style="color:#86efac">{{counts.get('PTP_OFFSET',0)+counts.get('PTP_JITTER',0)+counts.get('PTP_LOST',0)+counts.get('PTP_GM_CHANGE',0)}}</div><div class="sc-lbl">🕐 PTP Events</div></div>
    <div class="sc" data-ftypes="" data-fclips="1" onclick="filterByStat(this)" title="Filter: events with clips"><div class="sc-val">{{with_clips}}</div><div class="sc-lbl">🎵 With Clips</div></div>
  </div>

  <div class="metrics-strip">
    <div class="metric-chip"><strong>{{counts.get('SILENCE',0)}}</strong> Silence</div>
    <div class="metric-chip"><strong>{{counts.get('CLIP',0)}}</strong> Clip</div>
    <div class="metric-chip"><strong>{{counts.get('HISS',0)}}</strong> Hiss</div>
    <div class="metric-chip"><strong>{{counts.get('AI_ALERT',0)+counts.get('AI_WARN',0)}}</strong> AI Flags</div>
    <div class="metric-chip"><strong>{{counts.get('CMP_ALERT',0)}}</strong> Comparison</div>
  </div>

  <div class="filters">
    <label>Site
      <select id="f_site" onchange="applyFilters()">
        <option value="">All sites</option>
        {% for s in site_names %}<option value="{{s}}" {{'selected' if f_site==s}}>{{s}}</option>{% endfor %}
      </select>
    </label>
    <label>Stream
      <select id="f_stream" onchange="applyFilters()">
        <option value="">All streams</option>
        {% for s in stream_names %}<option value="{{s}}" {{'selected' if f_stream==s}}>{{s}}</option>{% endfor %}
      </select>
    </label>
    <label>Type
      <select id="f_type" onchange="applyFilters()">
        <option value="">All types</option>
        {% for t in type_names %}<option value="{{t}}" {{'selected' if f_type==t}}>{{t}}</option>{% endfor %}
      </select>
    </label>
    {% if chain_names %}
    <label>Chain
      <select id="f_chain" onchange="applyFilters()">
        <option value="">All chains</option>
        {% for c in chain_names %}<option value="{{c}}" {{'selected' if f_chain==c}}>{{c}}</option>{% endfor %}
      </select>
    </label>
    {% endif %}
  </div>
  <div class="filter-sub">
    <label>From <input type="datetime-local" id="f_from" onchange="applyFilters()"></label>
    <label>To <input type="datetime-local" id="f_to" onchange="applyFilters()"></label>
    <label style="cursor:pointer"><input type="checkbox" id="f_clips" onchange="applyFilters()"> Clips only</label>
    <span id="row_count"></span>
  </div>

  <div class="table-wrap">
  <table id="evt_table">
    <thead>
      <tr>
        <th style="width:130px">Time</th>
        <th style="width:110px">Site</th>
        <th style="width:120px">Stream</th>
        <th style="width:95px">Type</th>
        <th style="width:110px">Chain</th>
        <th>Detail</th>
        <th style="width:75px">Level</th>
        <th style="width:70px">RTP Loss</th>
        <th style="width:90px">Clip</th>
      </tr>
    </thead>
    <tbody id="evt_body">
    {% for e in events %}
    {% set tl = e.type.lower() if e.type else '' %}
    {% set tc = 'chain_fault' if tl=='chain_fault' else ('t-silence' if tl=='silence' else ('t-clip' if tl=='clip' else ('t-hiss' if tl=='hiss' else ('t-rtp' if 'rtp' in tl else ('t-ai_alert' if tl=='ai_alert' else ('t-ai_warn' if tl=='ai_warn' else ('t-ptp' if 'ptp' in tl else ('t-cmp' if 'cmp' in tl else 't-other')))))))) %}
    {% set is_chain_row = tl == 'chain_fault' %}
    <tr data-id="{{e.id or ''}}" data-site="{{e._site}}" data-stream="{{e.stream or ''}}" data-type="{{e.type or ''}}" data-ts="{{e.ts or ''}}" data-clip="{{e.clip or ''}}" data-chain="{{e._chain or ''}}" class="{{'chain-row ' if is_chain_row else ''}}{{'offline-site' if not e._online else ''}}">
      <td style="color:var(--mu);font-size:12px;white-space:nowrap">{{e.ts or ''}}</td>
      <td><span class="site-badge">{{e._site}}</span></td>
      <td><strong>{{e.stream or ''}}</strong></td>
      <td><span class="type-badge t-{{tc}}">{{e.type or ''}}</span></td>
      <td>{% if e._chain %}<span class="chain-badge" title="Broadcast chain">⛓ {{e._chain}}</span>{% else %}—{% endif %}</td>
      <td style="font-size:12px">{{e.message or ''}}</td>
      <td>
        {% if e.level_dbfs and e.level_dbfs > -120 %}
        <span style="font-size:12px;color:{{'var(--al)' if e.level_dbfs<=-55 else 'var(--ok)'}}">{{e.level_dbfs}} dB</span>
        <span class="level-bar"><span class="level-fill" style="width:{{[(e.level_dbfs+80)/80*100,100]|min|int}}%;background:{{'var(--al)' if e.level_dbfs<=-55 else 'var(--ok)'}}"></span></span>
        {% else %}—{% endif %}
      </td>
      <td>
        {% if e.rtp_loss_pct and e.rtp_loss_pct > 0 %}
        <span style="color:{{'var(--al)' if e.rtp_loss_pct>=2 else 'var(--wn)'}}">{{e.rtp_loss_pct}}%</span>
        {% else %}—{% endif %}
      </td>
      <td>
        {% if e.clip %}
        {% set clip_url = "/hub/site/" + (e._site|urlencode) + "/alerts/clip/" + (e.stream|urlencode) + "/" + e.clip %}
        <div style="display:flex;align-items:center;gap:6px;flex-wrap:wrap">
          <button class="play-clip-btn"
                  data-url="{{clip_url}}"
                  data-title="{{e.stream or e._site}}"
                  data-sub="{{e._site}} · {{e.ts}}"
                  data-fname="{{e.clip}}">▶ Play</button>
          <a href="{{clip_url}}?dl=1" download="{{e.clip}}" title="Download clip"
             style="color:var(--mu);font-size:14px;text-decoration:none;line-height:1" aria-label="Download">⬇</a>
        </div>
        {% else %}<span style="color:var(--mu);font-size:11px">—</span>{% endif %}
        {% if e.type in ('AI_ALERT','AI_WARN') and e.id %}
        <div class="fb-wrap">
          <button class="fb-btn{{' fb-ok' if e.feedback=='normal' else ''}}" data-fb-id="{{e.id}}" data-fb-site="{{e._site}}" data-fb-stream="{{e.stream or ''}}" data-fb-val="normal" title="False alarm — normal audio">👍</button>
          <button class="fb-btn{{' fb-bad' if e.feedback=='abnormal' else ''}}" data-fb-id="{{e.id}}" data-fb-site="{{e._site}}" data-fb-stream="{{e.stream or ''}}" data-fb-val="abnormal" title="Confirmed real fault">👎</button>
          {% if e.feedback == 'normal' %}<span class="fb-lbl fb-lbl-ok">False alarm</span>
          {% elif e.feedback == 'abnormal' %}<span class="fb-lbl fb-lbl-bad">Confirmed</span>
          {% else %}<span class="fb-lbl">AI feedback</span>{% endif %}
        </div>
        {% endif %}
      </td>
    </tr>
    {% else %}
    <tr><td colspan="9" class="no-data">No alert events from connected sites yet.</td></tr>
    {% endfor %}
    </tbody>
  </table>
  </div>
</main>

<script nonce="{{csp_nonce()}}">
var _statTypes  = [];   // types set by stat card click (empty = no group filter)
var _statClips  = false;

function filterByStat(el){
  var wasActive = el.classList.contains('sc-active');
  // Clear all active cards
  document.querySelectorAll('.sc.sc-active').forEach(function(c){c.classList.remove('sc-active');});
  if(wasActive){
    // Toggle off — show all
    _statTypes = []; _statClips = false;
  } else {
    el.classList.add('sc-active');
    var ft = el.dataset.ftypes || '';
    _statTypes = ft ? ft.split(',').map(function(t){return t.toLowerCase();}) : [];
    _statClips = el.dataset.fclips === '1';
    // Clear the manual type filter and clips checkbox so they don't double-filter
    document.getElementById('f_type').value = '';
    document.getElementById('f_clips').checked = false;
  }
  applyFilters();
}

function applyFilters(){
  var fs  = document.getElementById('f_site').value.toLowerCase();
  var fst = document.getElementById('f_stream').value.toLowerCase();
  var ft  = document.getElementById('f_type').value.toLowerCase();
  var fch = (document.getElementById('f_chain')||{}).value||'';
  fch = fch.toLowerCase();
  var ff  = document.getElementById('f_from').value;
  var ft2 = document.getElementById('f_to').value;
  var fc  = document.getElementById('f_clips').checked;
  var rows = document.querySelectorAll('#evt_body tr[data-stream]');
  var vis = 0;
  rows.forEach(function(r){
    var site  = (r.dataset.site||'').toLowerCase();
    var s     = (r.dataset.stream||'').toLowerCase();
    var t     = (r.dataset.type||'').toLowerCase();
    var chain = (r.dataset.chain||'').toLowerCase();
    var ts    = r.dataset.ts||'';
    var c     = r.dataset.clip||'';
    var show  = true;
    if(fs  && site!==fs) show=false;
    if(fst && s!==fst) show=false;
    if(ft  && !t.includes(ft)) show=false;
    if(fch && chain!==fch) show=false;
    if(ff  && ts < ff.replace('T',' ')) show=false;
    if(ft2 && ts > ft2.replace('T',' ')) show=false;
    if(fc  && !c) show=false;
    // Stat card group filter
    if(_statTypes.length && !_statTypes.includes(t)) show=false;
    if(_statClips && !c) show=false;
    r.style.display = show ? '' : 'none';
    if(show) vis++;
  });
  document.getElementById('row_count').textContent = vis+' event'+(vis!==1?'s':'')+' shown';
}
window.addEventListener('DOMContentLoaded', function(){
  // Pre-set filter dropdowns from URL params
  var p = new URLSearchParams(window.location.search);
  if(p.get('site'))   document.getElementById('f_site').value   = p.get('site');
  if(p.get('stream')) document.getElementById('f_stream').value = p.get('stream');
  if(p.get('type'))   document.getElementById('f_type').value   = p.get('type');
  if(p.get('chain') && document.getElementById('f_chain'))
    document.getElementById('f_chain').value = p.get('chain');
  applyFilters();
  // Clear stat card highlight if user manually changes a filter control
  ['f_site','f_stream','f_type','f_chain','f_clips','f_from','f_to'].forEach(function(id){
    var el=document.getElementById(id);
    if(el) el.addEventListener('change',function(){
      document.querySelectorAll('.sc.sc-active').forEach(function(c){c.classList.remove('sc-active');});
      _statTypes=[]; _statClips=false;
    });
  });
});

// ── AI feedback from hub ────────────────────────────────────────────────────
function sendHubFeedback(btn){
  var id=btn.dataset.fbId, site=btn.dataset.fbSite,
      stream=btn.dataset.fbStream, val=btn.dataset.fbVal;
  if(!id||!site||!stream||!val) return;
  var csrf=(document.querySelector('meta[name="csrf-token"]')||{}).content||'';
  btn.disabled=true;
  fetch('/hub/api/alerts/'+encodeURIComponent(id)+'/feedback',{
    method:'POST',
    headers:{'Content-Type':'application/json','X-CSRFToken':csrf},
    body:JSON.stringify({feedback:val,stream:stream,site:site})
  }).then(function(r){return r.json();}).then(function(d){
    btn.disabled=false;
    if(!d.ok) return;
    var wrap=btn.closest('.fb-wrap');
    if(!wrap) return;
    wrap.querySelectorAll('.fb-btn').forEach(function(b){b.classList.remove('fb-ok','fb-bad');});
    btn.classList.add(val==='normal'?'fb-ok':'fb-bad');
    var lbl=wrap.querySelector('.fb-lbl');
    if(!lbl){lbl=document.createElement('span');lbl.className='fb-lbl';wrap.appendChild(lbl);}
    if(val==='normal'){lbl.textContent='False alarm';lbl.className='fb-lbl fb-lbl-ok';}
    else{lbl.textContent='Confirmed';lbl.className='fb-lbl fb-lbl-bad';}
    // Show queued status briefly
    var row=btn.closest('tr');
    if(row){
      var siteBadge=row.querySelector('.site-badge');
      if(siteBadge){
        var orig=siteBadge.textContent;
        siteBadge.textContent=orig+' ✓';
        setTimeout(function(){siteBadge.textContent=orig;},2500);
      }
    }
  }).catch(function(){btn.disabled=false;});
}
document.addEventListener('click',function(e){
  var btn=e.target.closest('.fb-btn[data-fb-id]');
  if(btn) sendHubFeedback(btn);
});

// ── Mini audio player ────────────────────────────────────────────────────────
var _mpAudio   = null;
var _mpActive  = null;   // currently highlighted play button

function _closeMiniPlayer(){
  var mp=document.getElementById('mini-player');
  if(mp) mp.style.display='none';
  if(_mpAudio){ _mpAudio.pause(); _mpAudio.src=''; }
  if(_mpActive){ _mpActive.classList.remove('mp-active'); _mpActive=null; }
  document.body.style.paddingBottom='';
}

document.addEventListener('click',function(e){
  // Play button
  var pb=e.target.closest('.play-clip-btn');
  if(pb){
    var mp=document.getElementById('mini-player');
    if(!mp) return;
    var url=pb.dataset.url||'';
    var title=pb.dataset.title||'Clip';
    var sub=pb.dataset.sub||'';
    var fname=pb.dataset.fname||'clip.wav';
    // Update info labels
    var _mpt=document.getElementById('mp-title');
    _mpt.textContent=title; _mpt.title=title;
    var _mps=document.getElementById('mp-sub');
    _mps.textContent=sub; _mps.title=sub;
    // Set audio src
    _mpAudio=document.getElementById('mp-audio');
    _mpAudio.src=url;
    // Update download link
    var dl=document.getElementById('mp-dl');
    dl.href=url+'?dl=1';
    dl.download=fname;
    // Show player
    mp.style.display='flex';
    document.body.style.paddingBottom='72px';
    // Highlight active button
    if(_mpActive) _mpActive.classList.remove('mp-active');
    _mpActive=pb;
    pb.classList.add('mp-active');
    // Auto-play
    _mpAudio.play().catch(function(){});
    return;
  }
  // Close button
  var cb=e.target.closest('#mp-close');
  if(cb){ _closeMiniPlayer(); return; }
});

// When audio ends, remove active highlight from play button
document.addEventListener('DOMContentLoaded',function(){
  var audio=document.getElementById('mp-audio');
  if(audio){
    _mpAudio=audio;
    audio.addEventListener('ended',function(){
      if(_mpActive){ _mpActive.classList.remove('mp-active'); _mpActive=null; }
    });
  }
});
</script>

<!-- Mini audio player — fixed bottom bar -->
<div id="mini-player">
  <div id="mp-info">
    <div id="mp-title">—</div>
    <div id="mp-sub"></div>
  </div>
  <audio id="mp-audio" controls preload="none"></audio>
  <a id="mp-dl" href="#" download>⬇ Download</a>
  <button id="mp-close" title="Close player">✕</button>
</div>
</body></html>"""

# ─── Hub dashboard template ───────────────────────────────────────────────────

HUB_SITE_TPL = r"""<!doctype html>
<html lang="en"><head><meta charset="utf-8"><title>{{site.site}} — SignalScope Replica</title>
<meta name="viewport" content="width=device-width,initial-scale=1">
<meta name="csrf-token" content="{{csrf_token()}}">
<style nonce="{{csp_nonce()}}">
:root{--bg:#07142b;--sur:#0d2346;--bor:#17345f;--acc:#17a8ff;--ok:#22c55e;--wn:#f59e0b;--al:#ef4444;--tx:#eef5ff;--mu:#8aa4c8}
*{box-sizing:border-box;margin:0;padding:0}
body{font-family:system-ui,sans-serif;background:radial-gradient(circle at top, #12376f 0%, var(--bg) 38%, #05101f 100%);color:var(--tx);font-size:14px;position:relative}
body::before{content:"";position:fixed;right:28px;bottom:22px;width:280px;height:280px;background:url("/static/signalscope_icon.png") no-repeat center/contain;opacity:.045;pointer-events:none;filter:drop-shadow(0 0 24px rgba(23,168,255,.10));z-index:0}
body>*{position:relative;z-index:1}
a{color:var(--acc);text-decoration:none}
header{background:linear-gradient(180deg, rgba(10,31,65,.96), rgba(9,24,48,.96));border-bottom:1px solid var(--bor);padding:12px 20px;display:flex;align-items:center;gap:10px;flex-wrap:wrap;box-shadow:0 10px 24px rgba(0,0,0,.18)}
main{padding:18px;max-width:1500px;margin:0 auto}
.btn{display:inline-block;padding:6px 12px;border-radius:8px;font-size:13px;cursor:pointer;border:none;text-decoration:none;font-weight:600}
.bp{background:var(--acc);color:#fff}.bg{background:var(--bor);color:var(--tx)}
.badge{font-size:11px;padding:2px 8px;border-radius:999px;background:#1e3a5f;color:var(--acc)}
.site-card{background:var(--sur);border:1px solid var(--bor);border-radius:14px;overflow:hidden;box-shadow:0 6px 18px rgba(0,0,0,.18)}
.site-card.site-ok{border-left:4px solid var(--ok)}.site-card.site-warn{border-left:4px solid var(--wn)}.site-card.site-alert{border-left:4px solid var(--al)}.site-card.site-offline{border-left:4px solid var(--mu)}
.site-header{padding:12px 16px;display:flex;align-items:center;gap:10px;border-bottom:1px solid var(--bor);flex-wrap:wrap}
.site-name{font-size:18px;font-weight:700}
.site-meta{font-size:12px;color:var(--mu)}
.sum-pill{display:inline-flex;align-items:center;gap:6px;padding:7px 10px;border-radius:999px;background:linear-gradient(180deg,#143766,#102b54);border:1px solid var(--bor);font-size:12px}
.note{padding:10px 16px;border-bottom:1px solid var(--bor);background:linear-gradient(180deg,#12305c,#10284f);color:#b7d0f3;font-size:12px}
.offline-banner{padding:10px 16px;background:#2a1e1e;color:#fecaca;border-bottom:1px solid #3f2323}
.streams{display:grid;grid-template-columns:repeat(auto-fill,minmax(290px,1fr));gap:12px;padding:14px}
.sc{background:#123764;border:1px solid var(--bor);border-radius:10px;overflow:hidden;box-shadow:0 2px 8px rgba(0,0,0,.12)}
.sc.stats-alert{border-left:3px solid var(--al)}.sc.stats-warn{border-left:3px solid var(--wn)}
.dot{width:9px;height:9px;border-radius:999px;display:inline-block;flex-shrink:0}
.dok{background:var(--ok)}.dwn{background:var(--wn)}.dal{background:var(--al)}.dlr{background:#60a5fa}.dot-off{background:#64748b}
.sc-name{padding:9px 10px;border-bottom:1px solid var(--bor);display:flex;align-items:center;gap:7px}
.lbar-wrap{display:flex;align-items:center;gap:7px;padding:6px 10px}
.lbar-track{flex:1;height:8px;background:linear-gradient(180deg,#12305c,#10284f);border-radius:999px;overflow:hidden;border:1px solid var(--bor)}
.lbar-fill{height:100%}.lbar-val{font-size:11px;min-width:62px;text-align:right}
.sc-row{display:flex;justify-content:space-between;padding:4px 0;font-size:12px;border-bottom:1px solid rgba(255,255,255,.04)}
.sc-row:last-child{border-bottom:none}
.alert-badge{display:inline-flex;align-items:center;padding:2px 7px;border-radius:999px;font-size:10px;font-weight:700;letter-spacing:.04em;margin-left:4px}
.badge-silence{background:#102033;color:#93c5fd}.badge-hiss{background:#3a2f0f;color:#fde68a}.badge-clip{background:#381414;color:#fca5a5}.badge-ai{background:#14263a;color:#93c5fd}
.stats-block{margin-top:6px;border-top:1px solid var(--bor);padding-top:6px}
.stats-toggle{display:flex;align-items:center;justify-content:space-between;width:100%;background:none;border:none;color:var(--mu);font-size:11px;padding:4px 0;cursor:pointer}
.aib{padding:6px 10px;font-size:11px;font-weight:700;border-top:1px solid var(--bor)} .aok{background:#13261a;color:#86efac}.awn{background:#2f2410;color:#fde68a}.aal{background:#341313;color:#fca5a5}.aid{background:#1a2130;color:#94a3b8}.alr{background:#10263a;color:#93c5fd}
.pb{background:var(--bor);border-radius:4px;height:4px;margin:4px 13px 8px;overflow:hidden}.pbi{height:4px;border-radius:4px;background:var(--acc);transition:width .6s}
.np-strip{padding:7px 13px;border-top:1px solid var(--bor);display:flex;gap:9px;align-items:center;min-height:52px}
.np-art{width:38px;height:38px;border-radius:4px;object-fit:cover;display:none;flex-shrink:0}
.np-text{min-width:0}.np-title{font-size:12px;font-weight:600;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.np-sub{font-size:11px;color:var(--mu);white-space:nowrap;overflow:hidden;text-overflow:ellipsis}
.listen-strip{padding:7px 13px;border-top:1px solid var(--bor);display:flex;align-items:center;gap:6px;flex-wrap:wrap}
.listen-strip audio{flex:1;min-width:0;height:28px}
.hist-wrap{border-top:1px solid var(--bor)} .hist-toggle{width:100%;padding:5px 13px;background:none;border:none;color:var(--mu);font-size:11px;text-align:left;cursor:pointer;display:flex;justify-content:space-between}
.hist-toggle:hover{background:#123764} .hist{max-height:90px;overflow-y:auto;font-size:11px;color:var(--mu)} .hev{padding:3px 13px;border-bottom:1px solid var(--bor)}
.rtp-ok{color:var(--ok)}.rtp-wn{color:var(--wn)}.rtp-al{color:var(--al)}
.direct-banner{display:none;align-items:center;gap:12px;padding:10px 16px;background:linear-gradient(90deg,#0f3a1a,#0e2e14);border:1px solid #22c55e44;border-radius:10px;margin-bottom:12px;color:#86efac;font-size:13px}
.direct-banner a{color:#fff;background:var(--ok);padding:5px 12px;border-radius:6px;font-weight:600;text-decoration:none}
.ptp-strip{padding:8px 16px;border-bottom:1px solid var(--bor);display:flex;gap:16px;flex-wrap:wrap;font-size:12px;background:linear-gradient(180deg,#0f2845,#0c2237)}
.ptp-item{display:flex;flex-direction:column;gap:1px}.ptp-lbl{color:var(--mu);font-size:10px;text-transform:uppercase;letter-spacing:.04em}.ptp-val{font-weight:600}
.cmp-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(280px,1fr));gap:10px;padding:14px}
.cmp-card{background:#0f2845;border:1px solid var(--bor);border-radius:10px;padding:10px 12px}
.cmp-title{font-size:12px;font-weight:700;margin-bottom:6px;display:flex;align-items:center;gap:6px}
.alerts-section{border-top:1px solid var(--bor)}
.alerts-toggle{width:100%;padding:8px 16px;background:none;border:none;color:var(--mu);font-size:12px;text-align:left;cursor:pointer;display:flex;justify-content:space-between;align-items:center}
.alerts-toggle:hover{background:#0f2845}.alerts-list{max-height:220px;overflow-y:auto;font-size:11px}
.alert-row{padding:5px 16px;border-bottom:1px solid rgba(255,255,255,.04);display:flex;gap:10px;align-items:flex-start}
.alert-row-time{color:var(--mu);white-space:nowrap;flex-shrink:0}.alert-row-msg{flex:1;word-break:break-word}
.clip-badge{font-size:10px;padding:1px 6px;border-radius:999px;background:#381414;color:#fca5a5;margin-left:4px}
.refresh-bar{font-size:11px;color:var(--mu);display:flex;align-items:center;gap:8px}
.refresh-dot{width:7px;height:7px;border-radius:999px;background:var(--ok);display:inline-block;animation:rpulse 2s infinite}
@keyframes rpulse{0%,100%{opacity:1}50%{opacity:.3}}
</style><link rel="icon" type="image/x-icon" href="/static/signalscope_icon.png"></head><body>
{{ topnav("hub") }}
<main>
  <div style="display:flex;gap:10px;align-items:center;flex-wrap:wrap;margin-bottom:10px">
    <a class="btn bg" href="/hub">← Back to Hub</a>
    <span class="badge">Live replica</span>
    {% if direct_url %}<a class="btn bg" id="direct-link" href="{{direct_url}}" target="_blank" rel="noopener">Open Direct</a>{% endif %}
    <span class="refresh-bar" id="refresh-bar"><span class="refresh-dot"></span> <span id="refresh-countdown">Refreshing in 15s</span></span>
  </div>
  {% if direct_url %}
  <div class="direct-banner" id="direct-banner">
    <span>✅ Direct site access is available from your browser</span>
    <a href="{{direct_url}}" target="_blank" rel="noopener">Open Live Dashboard →</a>
    <button onclick="document.getElementById('direct-banner').style.display='none'" style="background:none;border:none;color:var(--mu);cursor:pointer;margin-left:auto">✕</button>
  </div>
  {% endif %}

  <div class="site-card site-{{'ok' if site.site_status=='OK' else 'warn' if site.site_status=='WARN' else 'alert' if site.site_status=='ALERT' else 'offline'}}">
    <div class="site-header">
      <span class="dot {{'dok' if site.site_status=='OK' else 'dwn' if site.site_status=='WARN' else 'dal' if site.site_status=='ALERT' else 'dot-off'}}"></span>
      <span class="site-name">{{site.site}}</span>
      <span class="badge">{{site.site_status}}</span>
      {% if site.running %}<span class="badge" style="background:#1e2a1e;color:#86efac">▶ Running</span>{% else %}<span class="badge" style="background:#2a2a1e;color:var(--mu)">⏸ Stopped</span>{% endif %}
      {% if site.online %}
      {% if site.running %}
      <button class="btn sc-cmd-btn" data-site="{{site.site|e}}" data-cmd="stop" style="background:#3a1e1e;color:#fca5a5;font-size:11px;padding:2px 10px">⏹ Stop</button>
      {% else %}
      <button class="btn sc-cmd-btn" data-site="{{site.site|e}}" data-cmd="start" style="background:#1e3a1e;color:#86efac;font-size:11px;padding:2px 10px">▶ Start</button>
      {% endif %}
      <button class="btn" data-action="hub-mgr-toggle" data-site="{{site.site|e}}" style="background:#1a3050;color:var(--acc);font-size:11px;padding:2px 10px">⚙ Sources</button>
      <button class="btn site-log-btn" data-site="{{site.site|e}}" style="background:#1a2a3a;color:#93c5fd;font-size:11px;padding:2px 10px">📋 Log</button>
      {% if site.running %}
      <button class="btn site-restart-btn" data-site="{{site.site|e}}" style="background:#2a1e3a;color:#c4b5fd;font-size:11px;padding:2px 10px">🔄 Restart</button>
      {% endif %}
      {% if site._backup_ts %}
      <a class="btn" href="/api/hub/site/{{site.site|urlencode}}/backup" style="background:#142514;color:#4ade80;font-size:11px;padding:2px 10px;text-decoration:none" title="Download backup — {{(site._backup_size // 1024) if site._backup_size else '?'}} KB, taken {{fmt(site._backup_ts)}}">⬇ Backup <span style="opacity:.7;font-size:10px">({{ago(site._backup_age_s)}})</span></a>
      <button class="btn site-backup-btn" data-site="{{site.site|e}}" style="background:#1a2e1a;color:#86efac;font-size:11px;padding:2px 10px" title="Request a fresh backup from this site now">↻ Backup Now</button>
      {% else %}
      <button class="btn site-backup-btn" data-site="{{site.site|e}}" style="background:#1a2e1a;color:#86efac;font-size:11px;padding:2px 10px" title="Request backup from this site">📥 Backup Now</button>
      {% endif %}
      <button class="btn site-ping-btn" data-site="{{site.site|e}}" style="background:#1a2040;color:#93c5fd;font-size:11px;padding:2px 10px" title="Run a network ping test from this site">🔍 Ping</button>
      {% if site._ping_result %}
      <span class="badge" style="background:{{'#163a1a' if site._ping_result.success else '#3a1616'}};color:{{'#86efac' if site._ping_result.success else '#fca5a5'}};font-size:10px" title="{{site._ping_result.target}} at {{fmt(site._ping_result.ts)}}">{{ '✓' if site._ping_result.success else '✗' }} {{site._ping_result.target}}</span>
      {% endif %}
      {% endif %}
      {% if site.build %}
      {% set _build_match = (site.build == build) %}
      <span class="badge site-version-badge"
            style="background:{{'#1e2433' if _build_match else '#3a2a0f'}};color:{{'var(--mu)' if _build_match else '#fbbf24'}}"
            title="{{'Version match' if _build_match else 'Version mismatch — hub is '+build}}">{{site.build}}</span>
      {% if site.online and not _build_match %}
      <button class="btn site-update-btn" data-site="{{site.site|e}}"
              style="background:#3a2a0f;color:#fbbf24;border:1px solid #b45309;font-size:11px;padding:2px 10px"
              title="Push update to this site">⬆ Update</button>
      {% endif %}
      {% endif %}
      <span class="site-meta">Last seen: {{ago(site.age_s)}}</span>
      {% if site.latency_ms is not none %}<span class="site-meta">Latency: {{site.latency_ms}} ms</span>{% endif %}
      {% if site.health_pct is defined %}<span class="site-meta" style="color:{{'var(--ok)' if site.health_pct>=99 else ('var(--wn)' if site.health_pct>=95 else 'var(--al)')}}">⚡ {{site.health_pct}}%</span>{% endif %}
    </div>
    <div style="padding:8px 16px;border-bottom:1px solid var(--bor);display:flex;gap:8px;flex-wrap:wrap;align-items:center;background:linear-gradient(180deg,#12305c,#10284f)">
      <span class="sum-pill">🎚 {{site.streams|length}} streams</span>
      <span class="sum-pill" style="color:var(--al)">🚨 {{site.alert_count}} alert</span>
      <span class="sum-pill" style="color:var(--wn)">⚠ {{site.warn_count}} warn</span>
      <span class="sum-pill" style="color:var(--ok)">✅ {{site.ok_count}} ok</span>
      {% set _sys = site.get('system') or {} %}
      {% if _sys %}
      {% set _dpct = _sys.get('disk_pct', 0)|float %}
      <span class="sum-pill" style="color:{{'#ef4444' if _dpct>=90 else ('#f59e0b' if _dpct>=70 else 'var(--ok)')}}">💾 {{_sys.get('disk_free_gb','?')}}GB free</span>
      {% if _sys.get('cpu_pct') is not none %}<span class="sum-pill" style="color:var(--mu)">CPU: {{_sys.get('cpu_pct')}}%</span>{% endif %}
      {% if _sys.get('ram_pct') is not none %}<span class="sum-pill" style="color:var(--mu)">RAM: {{_sys.get('ram_pct')}}%</span>{% endif %}
      {% set _upt = _sys.get('proc_uptime_s', 0)|int %}
      <span class="sum-pill" style="color:var(--mu)">⏱ {{(_upt//3600)}}h {{((_upt%3600)//60)}}m</span>
      {% endif %}
      <span class="sum-pill" style="margin-left:auto;display:flex;align-items:center;gap:6px;color:var(--mu)">
        📡 Relay
        <select data-site="{{site.site}}" onchange="setRelayBitrate(this)"
                style="background:#0d1117;border:1px solid var(--bor);border-radius:4px;color:var(--tx);font-size:11px;padding:2px 4px;cursor:pointer">
          {% for kbps in [32, 48, 64, 96, 128, 192] %}
          <option value="{{kbps}}" {{'selected' if site.get('_relay_bitrate', 128) == kbps}}>{{kbps}}k</option>
          {% endfor %}
        </select>
      </span>
    </div>
    {% set _ptp = site.get('ptp', {}) or {} %}
    {% if _ptp and _ptp.get('state') and _ptp.get('state') != 'idle' %}
    <div class="ptp-strip">
      <div class="ptp-item"><span class="ptp-lbl">PTP State</span><span class="ptp-val" style="color:{{'var(--ok)' if _ptp.get('state')=='locked' else 'var(--wn)'}}">{{_ptp.get('state','—')|upper}}</span></div>
      <div class="ptp-item"><span class="ptp-lbl">Offset</span><span class="ptp-val">{{_ptp.get('offset_us',0)}} µs</span></div>
      <div class="ptp-item"><span class="ptp-lbl">Drift</span><span class="ptp-val">{{_ptp.get('drift_us',0)}} µs</span></div>
      <div class="ptp-item"><span class="ptp-lbl">Jitter</span><span class="ptp-val">{{_ptp.get('jitter_us',0)}} µs</span></div>
      {% if _ptp.get('gm_id') %}<div class="ptp-item"><span class="ptp-lbl">GM ID</span><span class="ptp-val" style="font-size:11px">{{_ptp.get('gm_id','')}}</span></div>{% endif %}
      {% if _ptp.get('domain') %}<div class="ptp-item"><span class="ptp-lbl">Domain</span><span class="ptp-val">{{_ptp.get('domain',0)}}</span></div>{% endif %}
    </div>
    {% endif %}

    {% if not site.online %}
    <div class="offline-banner">⚠ No heartbeat received for {{site.age_s}}s — site may be down</div>
    {% else %}
    <div class="streams">
      {% for s in site.get('streams', []) %}
      {% set i = loop.index0 %}
      {% set ai = s.ai_status or 'Idle' %}
      {% set lev = s.level_dbfs %}
      {% set lpct = [(lev+80)/80*100, 100]|min|int %}
      {% set lcol = 'var(--al)' if lev<=-55 else ('var(--wn)' if lev<=-20 else 'var(--ok)') %}
      {% set ph = s.ai_phase or '' %}
      {% set dc = 'dok' %}
      {% if '[ALERT]' in ai %}{% set dc='dal' %}{% elif '[WARN]' in ai %}{% set dc='dwn' %}{% elif ph=='learning' %}{% set dc='dlr' %}{% endif %}
      <div class="sc {{'stats-alert' if '[ALERT]' in ai else ('stats-warn' if '[WARN]' in ai else '')}}">
        <div class="sc-name">
          <span class="dot {{dc}}"></span>
          <strong>{{s.name}}</strong>
          {% if s.get('clip_count') %}<span class="clip-badge" title="Saved alert clips">{{s.get('clip_count')}} clips</span>{% endif %}
          <span class="sc-dev">{{s.device_index or ''}}</span>
        </div>
        <div class="lbar-wrap">
          <span style="font-size:11px;color:var(--mu);width:28px">Lvl</span>
          <div class="lbar-track"><div class="lbar-fill" style="width:{{lpct}}%;background:{{lcol}}"></div></div>
          <span class="lbar-val" style="color:{{lcol}}">{{lev}} dB</span>
        </div>
        {% if s.lufs_m is not none and s.lufs_m > -69 %}
        {% set tpcol = 'var(--al)' if s.lufs_tp > -1 else ('var(--wn)' if s.lufs_tp > -3 else 'var(--mu)') %}
        <div class="lbar-wrap" style="padding-bottom:2px">
          <span style="font-size:11px;color:var(--mu);width:28px">LUFS</span>
          <span style="font-size:11px;font-family:monospace;color:var(--tx)">
            M&nbsp;<b>{{s.lufs_m}}</b>&nbsp;
            S&nbsp;<b>{{s.lufs_s}}</b>&nbsp;
            I&nbsp;<b>{{s.lufs_i}}</b>&nbsp;
            TP&nbsp;<b style="color:{{tpcol}}">{{s.lufs_tp}}</b>
          </span>
        </div>
        {% endif %}
        <div class="sc-tl-wrap" style="display:flex;align-items:center;gap:5px;padding:0 10px 4px">
          <span style="font-size:9px;color:var(--mu);width:28px;flex-shrink:0">24h</span>
          <canvas class="sc-tl" data-site="{{site.site|e}}" data-stream="{{s.name|e}}" data-hours="24"
                  height="16" style="flex:1;height:16px;border-radius:2px;cursor:pointer"
                  title="24h availability — click to cycle 1h/6h/24h"></canvas>
          <span style="font-size:9px;color:var(--mu);white-space:nowrap">
            <span style="color:#22c55e">■</span> <span style="color:#ef4444">■</span> <span style="color:#f59e0b">■</span> <span style="color:#374151">■</span>
          </span>
        </div>
        <div style="padding:0 10px 4px">
          <div class="sc-row">Format <span style="font-size:11px;color:var(--mu)">{{s.format or '—'}}</span></div>
          {% set _sdev = (s.device_index or '').lower() %}
          {% if not (_sdev.startswith('dab://') or _sdev.startswith('fm://') or _sdev.startswith('http://') or _sdev.startswith('https://')) %}
          <div class="sc-row">RTP Loss <span class="sc-rtp {{rtpClass(s.rtp_loss_pct)}}">{{s.rtp_loss_pct}}% <span style="color:var(--mu);font-size:11px">{{s.rtp_total or 0}} pkts</span></span></div>
          {% if s.rtp_jitter_ms and s.rtp_jitter_ms > 0 %}
          <div class="sc-row">RTP Jitter <span class="sc-jitter" style="color:{{'var(--wn)' if s.rtp_jitter_ms > 5 else 'var(--ok)'}}">{{s.rtp_jitter_ms}} ms</span></div>
          {% else %}
          <div class="sc-row" style="display:none">RTP Jitter <span class="sc-jitter">0 ms</span></div>
          {% endif %}
          {% endif %}
          {% if s.sla_pct is not none %}<div class="sc-row">SLA <span style="color:{{'var(--ok)' if s.sla_pct>=99 else 'var(--wn)'}}">{{s.sla_pct}}%</span></div>{% endif %}
          <div class="sc-row">Alerts
            <span style="font-size:12px">
              {%if s.alert_on_silence%}<span class="alert-badge badge-silence">SIL</span>{%endif%}
              {%if s.alert_on_hiss%}<span class="alert-badge badge-hiss">HISS</span>{%endif%}
              {%if s.alert_on_clip%}<span class="alert-badge badge-clip">CLIP</span>{%endif%}
              {%if s.ai_monitor%}<span class="alert-badge badge-ai">AI</span>{%endif%}
            </span>
          </div>
          {% if s.device_index and s.device_index.lower().startswith('dab://') %}
          <details class="stats-block">
            <summary class="stats-toggle">DAB stats <span>▼</span></summary>
            <div class="sc-row">SNR <span style="color:{{'var(--ok)' if s.dab_snr>=12 else 'var(--wn)' if s.dab_snr>=6 else 'var(--al)'}}">{{s.dab_snr}} dB</span></div>
            <div class="sc-row">Signal <span>{{s.dab_sig}} dBm</span></div>
            <div class="sc-row">Ensemble <span style="font-size:11px">{{s.dab_ensemble or '—'}}</span></div>
            <div class="sc-row">Service <span style="font-size:11px;display:flex;align-items:center;gap:5px">
              <span>{{s.dab_service or '—'}}</span>
              {% if s.dab_service %}
                {% if not s.expected_dab_service %}
                  <button class="btn bg bs set-expected-btn" style="padding:1px 6px;font-size:10px" title="Pin '{{s.dab_service}}' as expected service name" data-site="{{site.site|e}}" data-stream="{{s.name|e}}" data-field="expected_dab_service" data-value="{{s.dab_service|e}}">📌 Set</button>
                {% elif s.expected_dab_service.lower() == s.dab_service.lower() %}
                  <span style="color:var(--ok);font-size:10px" title="Expected: {{s.expected_dab_service}}">✓</span>
                {% else %}
                  <span style="color:var(--al);font-size:10px" title="Expected: {{s.expected_dab_service}}">⚠ {{s.expected_dab_service}}</span>
                  <button class="btn bg bs set-expected-btn" style="padding:1px 6px;font-size:10px" title="Update expected to '{{s.dab_service}}'" data-site="{{site.site|e}}" data-stream="{{s.name|e}}" data-field="expected_dab_service" data-value="{{s.dab_service|e}}">📌 Update</button>
                {% endif %}
              {% endif %}
            </span></div>
            <div class="sc-row">Mode <span style="font-size:11px">{{s.dab_mode or '—'}}</span></div>
            <div class="sc-row">Bitrate <span>{% if s.dab_bitrate %}{{s.dab_bitrate}} kbps{% else %}—{% endif %}</span></div>
            <div class="sc-row">Audio <span style="color:{{'var(--ok)' if s.dab_stereo else 'var(--mu)'}}">{% if s.dab_stereo %}Stereo{% else %}Mono{% endif %}</span></div>
            {% if s.dab_dls %}
            <div class="sc-row sc-rt-row" style="align-items:center">DLS
              <span class="rds-rt-wrap sc-rt-wrap" style="font-size:11px;color:var(--mu)" title="{{s.dab_dls}}">
                {% if s.dab_dls|length > 28 %}<span class="rds-rt-scroll sc-rt-text"><span>🎵 {{s.dab_dls}}</span><span aria-hidden="true">🎵 {{s.dab_dls}}</span></span>
                {% else %}<span class="rds-rt-static sc-rt-text">🎵 {{s.dab_dls}}</span>{% endif %}
              </span>
            </div>
            {% endif %}
          </details>
          {% endif %}
          {% if s.device_index and s.device_index.lower().startswith('fm://') %}
          <details class="stats-block">
            <summary class="stats-toggle">FM / RDS stats <span>▼</span></summary>
            <div class="sc-row">Signal <span>📶 {{s.fm_signal_dbm}} dBFS</span></div>
            <div class="sc-row">Pilot <span style="color:{{'var(--ok)' if s.fm_snr_db>=12 else 'var(--wn)' if s.fm_snr_db>=6 else 'var(--al)'}}">{{s.fm_snr_db}} dB</span></div>
            <div class="sc-row">Audio <span>{% if s.fm_stereo %}🔊 Stereo{% else %}🔈 Mono{% endif %}</span></div>
            <div class="sc-row">RDS <span style="color:{{'var(--ok)' if s.fm_rds_ok else 'var(--mu)'}};display:flex;align-items:center;gap:5px">
              {% if s.fm_rds_ok %}
                <span>📡 {{s.fm_rds_ps or 'Locked'}}</span>
                {% if s.fm_rds_ps %}
                  {% if not s.expected_fm_rds_ps %}
                    <button class="btn bg bs set-expected-btn" style="padding:1px 6px;font-size:10px;color:var(--tx)" title="Pin '{{s.fm_rds_ps}}' as expected RDS name" data-site="{{site.site|e}}" data-stream="{{s.name|e}}" data-field="expected_fm_rds_ps" data-value="{{s.fm_rds_ps|e}}">📌 Set</button>
                  {% elif s.expected_fm_rds_ps == s.fm_rds_ps %}
                    <span style="color:var(--ok);font-size:10px" title="Expected: {{s.expected_fm_rds_ps}}">✓</span>
                  {% else %}
                    <span style="color:var(--al);font-size:10px" title="Expected: {{s.expected_fm_rds_ps}}">⚠ {{s.expected_fm_rds_ps}}</span>
                    <button class="btn bg bs set-expected-btn" style="padding:1px 6px;font-size:10px;color:var(--tx)" title="Update expected to '{{s.fm_rds_ps}}'" data-site="{{site.site|e}}" data-stream="{{s.name|e}}" data-field="expected_fm_rds_ps" data-value="{{s.fm_rds_ps|e}}">📌 Update</button>
                  {% endif %}
                {% endif %}
              {% else %}
                <span>— No RDS</span>
              {% endif %}
            </span></div>
            {% if s.fm_rds_rt %}
            <div class="sc-row sc-rt-row" style="align-items:center">Text
              <span class="rds-rt-wrap sc-rt-wrap" style="font-size:11px" title="{{s.fm_rds_rt}}">
                {% if s.fm_rds_rt|length > 28 %}<span class="rds-rt-scroll sc-rt-text"><span>🎵 {{s.fm_rds_rt}}</span><span aria-hidden="true">🎵 {{s.fm_rds_rt}}</span></span>
                {% else %}<span class="rds-rt-static sc-rt-text">🎵 {{s.fm_rds_rt}}</span>{% endif %}
              </span>
            </div>
            {% endif %}
            {% if s.get('fm_rds_status') %}<div class="sc-row">Lock <span style="font-size:11px;color:var(--mu)">{{s.fm_rds_status}}</span></div>{% endif %}
            {% if s.get('fm_rds_valid') %}<div class="sc-row">Groups <span style="font-size:11px">{{s.fm_rds_valid}}</span></div>{% endif %}
          </details>
          {% endif %}
        </div>
        {% if s.ai_monitor %}
        {% set ac = 'alr' if ph=='learning' else ('aal' if '[ALERT]' in ai else ('awn' if '[WARN]' in ai else ('aok' if '[OK]' in ai else 'aid'))) %}
        <div class="aib {{ac}}">🤖 {{ai if ai else ('Waiting…' if site.running else 'Not running')}}</div>
        {% if ph=='learning' and s.ai_learn_start %}
          {% set pct = [(now - s.ai_learn_start) / site.learn_dur * 100, 100]|min|int %}
          <div class="pb"><div class="pbi" style="width:{{pct}}%"></div></div>
        {% endif %}
        {% endif %}
        {% if s.nowplaying_station_id %}
        <div class="np-strip" id="rnp_{{i}}">
          <img class="np-art" id="rnpa_{{i}}" src="" alt="" style="display:none">
          <div class="np-text">
            <div class="np-title" id="rnpt_{{i}}">Loading…</div>
            <div class="np-sub" id="rnpar_{{i}}"></div>
            <div class="np-sub" id="rnps_{{i}}" style="color:var(--acc)"></div>
          </div>
        </div>
        <script nonce="{{csp_nonce()}}">(function(){
          var si='{{i}}', rpuid='{{s.nowplaying_station_id}}';
          function fnp(){fetch('/api/nowplaying/'+rpuid).then(r=>r.json()).then(function(d){
            document.getElementById('rnpt_'+si).textContent=d.title||'—';
            document.getElementById('rnpar_'+si).textContent=d.artist||'';
            document.getElementById('rnps_'+si).textContent=d.show||'';
            var a=document.getElementById('rnpa_'+si);
            if(d.artwork){a.src='/api/nowplaying_art/'+encodeURIComponent(rpuid)+'?ts='+Date.now();a.style.display='block';} else {a.removeAttribute('src'); a.style.display='none';}
          }).catch(()=>{});}
          fnp(); setInterval(fnp,30000);
        })();</script>
        {% endif %}
        <div class="listen-strip">
          <select id="rhdur_{{i}}" style="padding:3px 5px;font-size:11px;background:#173a69;border:1px solid var(--bor);border-radius:4px;color:var(--tx)">
            <option value="5">5s</option><option value="10" selected>10s</option><option value="20">20s</option><option value="30">30s</option>
          </select>
          {% set ci = s._client_idx if s._client_idx is not none else i %}
          <a class="btn bg" href="/hub/site/{{site.site|urlencode}}/stream/{{ci}}/clip?seconds=10" download>⬇ Clip</a>
          <button class="btn bp" data-rep-live="{{ci}}" data-url="/hub/site/{{site.site|urlencode}}/stream/{{ci}}/live">▶ Live</button>
          <audio id="rep_live_{{i}}" style="display:none;flex:1;min-width:0;height:24px" controls></audio>
        </div>
        {% if s.history %}
        <div class="hist-wrap">
          <button class="hist-toggle" onclick="this.nextElementSibling.style.display=this.nextElementSibling.style.display==='block'?'none':'block'">Recent events <span>▼</span></button>
          <div class="hist" style="display:none">
            {% for h in s.history[:8] %}
            <div class="hev">{{h.ts or ''}} — {{h.msg or h.text or h.type or 'Event'}}</div>
            {% endfor %}
          </div>
        </div>
        {% endif %}
        <!-- Signal History chart -->
        <div class="sc-hist" data-site="{{site.site|e}}" data-stream="{{s.name|e}}">
          <button class="hist-toggle" onclick="scHistToggle(this)">📈 Signal History <span>▼</span></button>
          <div class="sc-hist-body" style="display:none">
            <div style="display:flex;gap:4px;padding:6px 10px 2px;flex-wrap:wrap;align-items:center">
              <span style="font-size:10px;color:var(--mu)">Range:</span>
              <button class="btn sc-hr active" data-h="1" style="font-size:10px;padding:1px 7px">1h</button>
              <button class="btn sc-hr" data-h="6" style="font-size:10px;padding:1px 7px">6h</button>
              <button class="btn sc-hr" data-h="24" style="font-size:10px;padding:1px 7px">24h</button>
              <select class="sc-hm" style="margin-left:8px;font-size:11px;background:#0d1117;border:1px solid var(--bor);border-radius:4px;color:var(--tx);padding:2px 4px">
                <option value="level_dbfs">Level dBFS</option>
                <option value="silence_flag">Silence Flag</option>
                <option value="clip_count">Clip Count</option>
                {%if _sdev.startswith('fm://')%}<option value="fm_signal_dbm">FM Signal dBm</option>{%endif%}
                {%if _sdev.startswith('fm://')%}<option value="fm_snr_db">FM SNR dB</option>{%endif%}
                {%if _sdev.startswith('fm://')%}<option value="fm_stereo">FM Stereo</option>{%endif%}
                {%if _sdev.startswith('fm://')%}<option value="fm_rds_ok">FM RDS Lock</option>{%endif%}
                {%if _sdev.startswith('dab://')%}<option value="dab_snr">DAB SNR dB</option>{%endif%}
                {%if _sdev.startswith('dab://')%}<option value="dab_sig">DAB Signal dBm</option>{%endif%}
                {%if _sdev.startswith('dab://')%}<option value="dab_bitrate">DAB Bitrate kbps</option>{%endif%}
                <option value="lufs_m">LUFS Momentary</option>
                <option value="lufs_s">LUFS Short-term</option>
                <option value="lufs_i">LUFS Integrated</option>
                {%if not _sdev.startswith('fm://') and not _sdev.startswith('dab://') and not _sdev.startswith('http')%}
                <option value="rtp_jitter_ms">RTP Jitter ms</option>
                <option value="rtp_loss_pct">RTP Loss %</option>
                {%endif%}
              </select>
            </div>
            <canvas class="sc-hc" height="110" style="display:block;width:100%;height:110px"></canvas>
            <div class="sc-hs" style="display:none;font-size:11px;color:var(--mu);text-align:center;padding:4px 0 6px"></div>
          </div>
        </div>
        {% if site.online %}
        <div style="padding:4px 10px 6px;display:flex;gap:6px;border-top:1px solid var(--bor);background:#080f1f">
          <button class="btn" data-action="hub-remove-input" data-site="{{site.site|e}}" data-name="{{s.name|e}}"
                  style="font-size:10px;padding:2px 8px;background:#2a1010;color:#fca5a5">🗑 Remove</button>
          {% if s.enabled %}
          <button class="btn" data-action="hub-disable-input" data-site="{{site.site|e}}" data-name="{{s.name|e}}"
                  style="font-size:10px;padding:2px 8px;background:#1a2a10;color:#86efac">⏸ Disable</button>
          {% else %}
          <button class="btn" data-action="hub-enable-input" data-site="{{site.site|e}}" data-name="{{s.name|e}}"
                  style="font-size:10px;padding:2px 8px;background:#2a2a10;color:#fde68a">▶ Enable</button>
          {% endif %}
          <button class="btn hub-retrain-btn" data-site="{{site.site|e}}" data-stream="{{s.name|e}}"
                  style="font-size:10px;padding:2px 8px;background:#1a2a3a;color:#93c5fd">🔄 Retrain AI</button>
          <button class="btn hub-calibrate-btn" data-site="{{site.site|e}}" data-stream="{{s.name|e}}"
                  style="font-size:10px;padding:2px 8px;background:#2a1a3a;color:#d8b4fe">🎚 Calibrate Silence</button>
        </div>
        {% endif %}
      </div>
      {% endfor %}
    </div>

    <!-- ── Source management panel (hidden by default) ──────────────────── -->
    <div id="hub-mgr-{{site.site|e}}" style="display:none;border-top:2px solid var(--acc);background:#080f1f;padding:12px 16px">
      <div style="font-size:12px;font-weight:700;color:var(--acc);margin-bottom:10px">⚙ Source Management — {{site.site}}</div>
      <!-- Add source form -->
      <div style="background:#0d2346;border:1px solid var(--bor);border-radius:8px;padding:12px;margin-bottom:10px">
        <div style="font-size:11px;font-weight:700;color:var(--mu);margin-bottom:8px">➕ Add Source</div>
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:8px">
          <div class="hub-mgr-name-wrap" data-site="{{site.site|e}}">
            <label style="font-size:11px;color:var(--mu)">Name</label>
            <input class="hub-mgr-name" data-site="{{site.site|e}}" placeholder="e.g. BBC R4" style="width:100%;padding:5px 8px;background:#173a69;border:1px solid var(--bor);border-radius:5px;color:var(--tx);font-size:12px">
          </div>
          <div>
            <label style="font-size:11px;color:var(--mu)">Source Type</label>
            <select class="hub-mgr-type" data-site="{{site.site|e}}" style="width:100%;padding:5px 8px;background:#173a69;border:1px solid var(--bor);border-radius:5px;color:var(--tx);font-size:12px">
              <option value="rtp">Livewire / AES67 (RTP)</option>
              <option value="http">HTTP Audio Stream</option>
              <option value="fm">FM via RTL-SDR</option>
              <option value="dab">DAB via RTL-SDR</option>
            </select>
          </div>
          <div class="hub-mgr-dev-wrap" data-site="{{site.site|e}}" style="grid-column:1/-1">
            <label class="hub-mgr-dev-lbl" data-site="{{site.site|e}}" style="font-size:11px;color:var(--mu)">Device Address</label>
            <input class="hub-mgr-dev" data-site="{{site.site|e}}" placeholder="e.g. 239.192.0.1:5004" style="width:100%;padding:5px 8px;background:#173a69;border:1px solid var(--bor);border-radius:5px;color:var(--tx);font-size:12px">
          </div>
          <!-- FM fields (shown only when type=fm) -->
          <div class="hub-mgr-fm-fields" data-site="{{site.site|e}}" style="display:none;grid-column:1/-1">
            <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:6px;align-items:end">
              <div>
                <label style="font-size:11px;color:var(--mu)">Frequency (MHz)</label>
                <input class="hub-mgr-fm-freq" data-site="{{site.site|e}}" type="number" step="0.1" min="64" max="108" placeholder="e.g. 96.7" style="width:100%;padding:5px 8px;background:#173a69;border:1px solid var(--bor);border-radius:5px;color:var(--tx);font-size:12px">
              </div>
              <div>
                <label style="font-size:11px;color:var(--mu)">PPM Offset</label>
                <input class="hub-mgr-fm-ppm" data-site="{{site.site|e}}" type="number" value="0" style="width:100%;padding:5px 8px;background:#173a69;border:1px solid var(--bor);border-radius:5px;color:var(--tx);font-size:12px">
              </div>
              <div>
                <label style="font-size:11px;color:var(--mu)">Dongle Serial (opt.)</label>
                <input class="hub-mgr-fm-serial" data-site="{{site.site|e}}" placeholder="auto" style="width:100%;padding:5px 8px;background:#173a69;border:1px solid var(--bor);border-radius:5px;color:var(--tx);font-size:12px">
              </div>
            </div>
          </div>
          <!-- DAB scan fields (shown only when type=dab) -->
          <div class="hub-mgr-dab-fields" data-site="{{site.site|e}}" style="display:none;grid-column:1/-1;display:none">
            <div style="display:grid;grid-template-columns:1fr 1fr 1fr auto;gap:6px;align-items:end">
              <div>
                <label style="font-size:11px;color:var(--mu)">Channel</label>
                <select class="hub-mgr-dab-ch" data-site="{{site.site|e}}" style="width:100%;padding:5px 8px;background:#173a69;border:1px solid var(--bor);border-radius:5px;color:var(--tx);font-size:12px">
                  {% for ch in ['5A','5B','5C','5D','6A','6B','6C','6D','7A','7B','7C','7D','8A','8B','8C','8D','9A','9B','9C','9D','10A','10B','10C','10D','11A','11B','11C','11D','12A','12B','12C','12D','13A','13B','13C','13D','13E','13F'] %}
                  <option value="{{ch}}" {{'selected' if ch=='12C'}}>{{ch}}</option>
                  {% endfor %}
                </select>
              </div>
              <div>
                <label style="font-size:11px;color:var(--mu)">PPM Offset</label>
                <input class="hub-mgr-dab-ppm" data-site="{{site.site|e}}" type="number" value="0" style="width:100%;padding:5px 8px;background:#173a69;border:1px solid var(--bor);border-radius:5px;color:var(--tx);font-size:12px">
              </div>
              <div>
                <label style="font-size:11px;color:var(--mu)">Dongle Serial (opt.)</label>
                <input class="hub-mgr-dab-serial" data-site="{{site.site|e}}" placeholder="auto" style="width:100%;padding:5px 8px;background:#173a69;border:1px solid var(--bor);border-radius:5px;color:var(--tx);font-size:12px">
              </div>
              <button class="btn bp hub-mgr-dab-scan-btn" data-site="{{site.site|e}}" style="font-size:12px;padding:5px 12px;white-space:nowrap">🔍 Scan Mux</button>
            </div>
            <!-- Scan results area -->
            <div class="hub-mgr-dab-results" data-site="{{site.site|e}}" style="margin-top:8px;display:none">
              <div style="font-size:11px;color:var(--mu);margin-bottom:6px">Select services to add:</div>
              <div class="hub-mgr-dab-svc-list" data-site="{{site.site|e}}" style="display:flex;flex-wrap:wrap;gap:6px;margin-bottom:8px"></div>
              <button class="btn hub-mgr-dab-add-sel" data-site="{{site.site|e}}" style="background:#166534;color:#fff;font-size:12px;padding:4px 14px">➕ Add Selected Services</button>
            </div>
          </div>
        </div>
        <div style="display:flex;gap:8px;align-items:center;flex-wrap:wrap">
          <label style="font-size:11px;color:var(--mu)"><input type="checkbox" class="hub-mgr-sil" data-site="{{site.site|e}}" checked style="margin-right:4px">Silence alert</label>
          <label style="font-size:11px;color:var(--mu)"><input type="checkbox" class="hub-mgr-clip" data-site="{{site.site|e}}" checked style="margin-right:4px">Clip alert</label>
          <label style="font-size:11px;color:var(--mu)"><input type="checkbox" class="hub-mgr-ai" data-site="{{site.site|e}}" checked style="margin-right:4px">AI monitor</label>
          <button class="btn hub-mgr-add-btn" data-site="{{site.site|e}}" style="background:#166534;color:#fff;font-size:12px;padding:4px 14px;margin-left:auto" data-site-add="{{site.site|e}}">➕ Add Source</button>
        </div>
        <div class="hub-mgr-msg" data-site="{{site.site|e}}" style="font-size:12px;margin-top:6px;display:none"></div>
      </div>
    </div>

    {% set _cmps = site.get('comparators', []) or [] %}
    {% if _cmps %}
    <div style="border-top:1px solid var(--bor);padding:8px 16px 4px">
      <div style="font-size:12px;font-weight:700;color:var(--mu);margin-bottom:6px">COMPARATORS</div>
      <div class="cmp-grid">
        {% for c in _cmps %}
        {% set cs = c.get('status','') or '' %}
        {% set c_col = 'var(--al)' if 'ALERT' in cs else ('var(--wn)' if 'WARN' in cs else 'var(--ok)') %}
        <div class="cmp-card">
          <div class="cmp-title">
            <span class="dot" style="background:{{c_col}}"></span>
            <span>{{c.get('pre_name','?')}} → {{c.get('post_name','?')}}</span>
          </div>
          <div class="sc-row">Status <span style="color:{{c_col}}">{{cs or 'Unknown'}}</span></div>
          <div class="sc-row">Aligned <span style="color:{{'var(--ok)' if c.get('aligned') else 'var(--wn)'}}">{% if c.get('aligned') %}✓ Yes{% else %}✗ No{% endif %}</span></div>
          <div class="sc-row">Delay <span>{{c.get('delay_ms',0)|int}} ms</span></div>
          <div class="sc-row">Correlation <span>{{c.get('correlation',0)}}</span></div>
          <div class="sc-row">Gain Diff <span style="color:{{'var(--al)' if c.get('gain_diff_db',0)|abs > c.get('gain_alert_db',3) else 'var(--ok)'}}">{{c.get('gain_diff_db',0)}} dB</span></div>
        </div>
        {% endfor %}
      </div>
    </div>
    {% endif %}

    {% set _alerts = site.get('recent_alerts', []) or [] %}
    {% if _alerts %}
    <div class="alerts-section">
      <button class="alerts-toggle" onclick="var d=this.nextElementSibling;d.style.display=d.style.display==='block'?'none':'block'">
        Recent Alerts ({{_alerts|length}}) <span>▼</span>
      </button>
      <div class="alerts-list" style="display:none">
        {% for a in _alerts %}
        <div class="alert-row">
          <span class="alert-row-time">{{a.get('ts_str') or a.get('ts','')[:19] or '—'}}</span>
          <span class="alert-row-msg" style="color:{{'var(--al)' if a.get('level','')=='ALERT' else ('var(--wn)' if a.get('level','')=='WARN' else 'var(--tx)')}}">
            {% if a.get('stream') %}<strong>{{a.get('stream')}}</strong> — {% endif %}{{a.get('msg') or a.get('message') or a.get('type') or 'Event'}}
          </span>
        </div>
        {% endfor %}
      </div>
    </div>
    {% endif %}

    {% endif %}
  </div>
</main>

<!-- ── Ping modal ─────────────────────────────────────────────────────────── -->
<div id="hub-ping-modal" style="display:none;position:fixed;inset:0;background:rgba(0,0,0,.8);z-index:9001;align-items:center;justify-content:center">
  <div style="background:#0d1117;border:1px solid var(--bor);border-radius:10px;width:min(640px,95vw);max-height:80vh;display:flex;flex-direction:column;padding:16px;gap:10px">
    <div style="display:flex;align-items:center;justify-content:space-between">
      <span id="hub-ping-modal-title" style="font-weight:700;color:var(--acc);font-size:14px">🔍 Ping Test</span>
      <button id="hub-ping-modal-close" style="background:none;border:none;color:var(--mu);font-size:20px;cursor:pointer;line-height:1">✕</button>
    </div>
    <div style="display:flex;gap:6px;align-items:center">
      <input id="hub-ping-target" type="text" placeholder="IP or hostname (e.g. 10.0.0.1)" style="flex:1;background:#0a1020;border:1px solid var(--bor);border-radius:5px;color:var(--tx);font-size:12px;padding:5px 8px">
      <button id="hub-ping-send-btn" style="background:#1a3050;color:var(--acc);border:1px solid var(--bor);border-radius:5px;font-size:12px;padding:5px 12px;cursor:pointer">Send</button>
    </div>
    <pre id="hub-ping-modal-body" style="overflow-y:auto;flex:1;min-height:120px;font-size:11px;color:#d1fae5;font-family:monospace;white-space:pre-wrap;word-break:break-all;background:#060c18;border:1px solid var(--bor);border-radius:6px;padding:10px;margin:0">(enter a target and press Send)</pre>
  </div>
</div>

<!-- ── Remote log modal ───────────────────────────────────────────────────── -->
<div id="hub-log-modal" style="display:none;position:fixed;inset:0;background:rgba(0,0,0,.8);z-index:9000;align-items:center;justify-content:center">
  <div style="background:#0d1117;border:1px solid var(--bor);border-radius:10px;width:min(860px,95vw);max-height:80vh;display:flex;flex-direction:column;padding:16px;gap:10px">
    <div style="display:flex;align-items:center;justify-content:space-between;gap:8px;flex-wrap:wrap">
      <span id="hub-log-modal-title" style="font-weight:700;color:var(--acc);font-size:14px">📋 Remote Log</span>
      <div style="display:flex;align-items:center;gap:8px;margin-left:auto">
        <span id="hub-log-modal-meta" style="font-size:10px;color:var(--mu)"></span>
        <button id="hub-log-modal-pull" style="background:#1a2a3a;color:#93c5fd;border:1px solid var(--bor);border-radius:6px;font-size:11px;padding:3px 10px;cursor:pointer">↻ Pull fresh log</button>
        <button id="hub-log-modal-close" style="background:none;border:none;color:var(--mu);font-size:20px;cursor:pointer;line-height:1">✕</button>
      </div>
    </div>
    <pre id="hub-log-modal-body" style="overflow-y:auto;flex:1;font-size:11px;color:#d1fae5;font-family:monospace;white-space:pre-wrap;word-break:break-all;background:#060c18;border:1px solid var(--bor);border-radius:6px;padding:10px;margin:0"></pre>
  </div>
</div>

<script nonce="{{csp_nonce()}}">
// ── Remote start/stop command ─────────────────────────────────────────────────
function sendSiteCommand(site, command, btn){
  var csrfToken=(document.querySelector('meta[name="csrf-token"]')||{}).content||document.cookie.match(/(?:^|;\s*)csrf_token=([^;]+)/)?.[1]||'';
  btn.disabled = true;
  btn.textContent = 'Sending…';
  fetch('/api/hub/site/' + encodeURIComponent(site) + '/command', {
    method: 'POST',
    headers: {'Content-Type':'application/json','X-CSRFToken': csrfToken},
    body: JSON.stringify({command: command})
  }).then(function(r){ return r.json(); }).then(function(d){
    if(d.ok){
      btn.textContent = '✓ Queued';
      btn.style.background = '#1e3a5f';
      btn.style.color = 'var(--acc)';
    } else {
      btn.disabled = false;
      btn.textContent = command === 'start' ? '▶ Start' : '⏹ Stop';
      alert('Failed: ' + (d.error||'unknown error'));
    }
  }).catch(function(){
    btn.disabled = false;
    btn.textContent = command === 'start' ? '▶ Start' : '⏹ Stop';
  });
}
document.addEventListener('click', function(e){
  var btn = e.target.closest('.sc-cmd-btn');
  if(!btn) return;
  var site = btn.getAttribute('data-site');
  var cmd  = btn.getAttribute('data-cmd');
  if(site && cmd) sendSiteCommand(site, cmd, btn);
});
document.addEventListener('click', function(e){
  var btn = e.target.closest('.site-update-btn');
  if(!btn) return;
  var site = btn.getAttribute('data-site');
  if(!site) return;
  // Inline confirmation — avoid confirm() which is blocked on LAN HTTP origins
  var anchor = btn.closest('.site-header') || btn.parentElement;
  var existingConf = anchor.querySelector('.site-update-confirm');
  if(existingConf){ existingConf.remove(); return; }
  var bar = document.createElement('div');
  bar.className = 'site-update-confirm';
  bar.style.cssText = 'padding:8px 16px;background:#2a1e08;border-top:1px solid #b45309;display:flex;align-items:center;gap:10px;font-size:13px;color:#fbbf24;flex-wrap:wrap';
  bar.innerHTML = 'Push update to <strong>'+site+'</strong>? Site will restart briefly. '
    +'<button class="btn bs" style="background:#166534;color:#fff;margin-left:auto" data-confirm-update="1">⬆ Yes, Update</button>'
    +'<button class="btn bg bs" data-confirm-cancel="1">Cancel</button>';
  bar.querySelector('[data-confirm-cancel]').addEventListener('click', function(){ bar.remove(); });
  bar.querySelector('[data-confirm-update]').addEventListener('click', function(){
    bar.innerHTML = '<span>⏳ Sending update command…</span>';
    hubPost('/api/hub/site/'+encodeURIComponent(site)+'/update',{})
      .then(function(d){
        if(d.ok){
          bar.innerHTML='<span style="color:#86efac">✓ Update command sent — site will restart shortly</span>';
          setTimeout(function(){ bar.remove(); btn.textContent='\u2713 Sent'; btn.style.color='var(--ok)'; btn.style.borderColor='var(--ok)'; btn.disabled=true; }, 2000);
        } else {
          bar.innerHTML='<span style="color:#fca5a5">\u2717 Failed: '+(d.error||'unknown error')+'</span>'
            +'<button class="btn bg bs" style="margin-left:auto" data-confirm-cancel="1">Dismiss</button>';
          bar.querySelector('[data-confirm-cancel]').addEventListener('click', function(){ bar.remove(); });
        }
      }).catch(function(err){
        bar.innerHTML='<span style="color:#fca5a5">\u2717 Error: '+(err.message||err)+'</span>'
          +'<button class="btn bg bs" style="margin-left:auto" data-confirm-cancel="1">Dismiss</button>';
        bar.querySelector('[data-confirm-cancel]').addEventListener('click', function(){ bar.remove(); });
      });
  });
  anchor.insertAdjacentElement('afterend', bar);
});

// ── Source management ─────────────────────────────────────────────────────────
function _hubCsrf(){return (document.querySelector('meta[name="csrf-token"]')||{}).content||document.cookie.match(/(?:^|;\s*)csrf_token=([^;]+)/)?.[1]||'';}
function hubPost(url,body){return fetch(url,{method:'POST',headers:{'Content-Type':'application/json','X-CSRFToken':_hubCsrf()},body:JSON.stringify(body)}).then(function(r){return r.json();});}
function setExpectedName(site,stream,field,value,btn){
  if(btn){btn.disabled=true;btn.textContent='...';}
  var csrfTok=(document.querySelector('meta[name="csrf-token"]')||{}).content||document.cookie.match(/(?:^|;\s*)csrf_token=([^;]+)/)?.[1]||'';
  fetch('/api/hub/site/'+encodeURIComponent(site)+'/set_expected_name',{
    method:'POST',
    headers:{'Content-Type':'application/json','X-CSRFToken':csrfTok},
    body:JSON.stringify({stream:stream,field:field,value:value})
  }).then(function(r){
    if(!r.ok){return r.text().then(function(t){throw new Error('Server error '+r.status+': '+t.substring(0,120));});}
    return r.json();
  }).then(function(d){
    if(d.ok){
      if(btn){var sp=document.createElement('span');sp.style.cssText='color:var(--ok);font-size:10px';sp.textContent='✓ Saved';btn.replaceWith(sp);}
    } else {
      if(btn){btn.disabled=false;btn.textContent='📌 Set';}
      alert('Set name failed: '+(d.error||'unknown error'));
    }
  }).catch(function(err){
    if(btn){btn.disabled=false;btn.textContent='📌 Set';}
    alert('Set name error: '+(err.message||err));
  });
}
// Delegated listener for set-expected buttons (avoids CSP inline-handler hash requirement)
document.addEventListener('click',function(e){
  var btn=e.target.closest('.set-expected-btn');
  if(!btn)return;
  setExpectedName(btn.dataset.site,btn.dataset.stream,btn.dataset.field,btn.dataset.value,btn);
});
function hubMgrMsg(site,txt,ok){var el=document.querySelector('.hub-mgr-msg[data-site="'+site+'"]');if(!el)return;el.style.display='';el.style.color=ok?'var(--ok)':'var(--al)';el.textContent=txt;if(ok)setTimeout(function(){el.style.display='none';},5000);}

document.addEventListener('click',function(e){
  var btn=e.target.closest('[data-action="hub-mgr-toggle"]');if(!btn)return;
  var panel=document.getElementById('hub-mgr-'+btn.dataset.site);
  if(panel)panel.style.display=panel.style.display==='none'?'block':'none';
});
document.addEventListener('change',function(e){
  var sel=e.target.closest('.hub-mgr-type');if(!sel)return;
  var site=sel.dataset.site, t=sel.value;
  var dw=document.querySelector('.hub-mgr-dev-wrap[data-site="'+site+'"]');
  var lbl=document.querySelector('.hub-mgr-dev-lbl[data-site="'+site+'"]');
  var ff=document.querySelector('.hub-mgr-fm-fields[data-site="'+site+'"]');
  var df=document.querySelector('.hub-mgr-dab-fields[data-site="'+site+'"]');
  var nw=document.querySelector('.hub-mgr-name-wrap[data-site="'+site+'"]');
  var ab=document.querySelector('.hub-mgr-add-btn[data-site-add="'+site+'"]');
  if(dw)dw.style.display=(t==='fm'||t==='dab')?'none':'block';
  if(ff)ff.style.display=t==='fm'?'block':'none';
  if(df)df.style.display=t==='dab'?'block':'none';
  if(lbl)lbl.textContent=t==='http'?'Stream URL':'Device Address';
  // For DAB, station names come from the scan — hide the manual name field and
  // generic Add button; the "Add Selected Services" button inside the scan
  // results is the correct control.
  if(nw)nw.style.display=t==='dab'?'none':'';
  if(ab)ab.style.display=t==='dab'?'none':'';
});
document.addEventListener('click',function(e){
  var btn=e.target.closest('.hub-mgr-dab-scan-btn');if(!btn)return;
  var site=btn.dataset.site;
  var ch=(document.querySelector('.hub-mgr-dab-ch[data-site="'+site+'"]')||{}).value||'';
  var ppm=parseInt((document.querySelector('.hub-mgr-dab-ppm[data-site="'+site+'"]')||{}).value||0);
  var serial=(document.querySelector('.hub-mgr-dab-serial[data-site="'+site+'"]')||{}).value||'';
  var resArea=document.querySelector('.hub-mgr-dab-results[data-site="'+site+'"]');
  var svcList=document.querySelector('.hub-mgr-dab-svc-list[data-site="'+site+'"]');
  btn.disabled=true;btn.textContent='Scanning…';if(resArea)resArea.style.display='none';
  hubPost('/api/hub/site/'+encodeURIComponent(site)+'/dab/scan',{channel:ch,ppm:ppm,serial:serial})
  .then(function(d){
    if(!d.ok){btn.disabled=false;btn.textContent='🔍 Scan Mux';hubMgrMsg(site,'Scan failed: '+(d.error||'unknown'));return;}
    hubMgrMsg(site,'Scan queued — waiting for client (~60s)…',true);
    var polls=0,max=75;
    function poll(){fetch('/api/hub/site/'+encodeURIComponent(site)+'/dab/scan_result').then(function(r){return r.json();}).then(function(r){
      if(r.ready){
        btn.disabled=false;btn.textContent='🔍 Scan Mux';
        if(r.error){hubMgrMsg(site,'Scan error: '+r.error);return;}
        if(svcList){svcList.innerHTML='';(r.services||[]).forEach(function(s){var lbl=document.createElement('label');lbl.style.cssText='display:flex;align-items:center;gap:4px;font-size:11px;background:#0d2346;border:1px solid var(--bor);border-radius:5px;padding:3px 8px;cursor:pointer;color:var(--tx)';lbl.innerHTML='<input type="checkbox" checked data-svc-name="'+s.name+'" style="margin-right:2px"><span>'+s.name+(s.bitrate?' <span style="color:var(--mu)">'+s.bitrate+'k</span>':'')+'</span>';svcList.appendChild(lbl);});}
        if(resArea){resArea.style.display='';hubMgrMsg(site,'Found '+(r.services||[]).length+' services on '+(r.channel||ch)+(r.ensemble?' — '+r.ensemble:''),true);}
      } else if(polls++<max){setTimeout(poll,2000);}
      else{btn.disabled=false;btn.textContent='🔍 Scan Mux';hubMgrMsg(site,'Scan timed out');}
    }).catch(function(){if(polls++<max)setTimeout(poll,2000);});}
    setTimeout(poll,3000);
  }).catch(function(){btn.disabled=false;btn.textContent='🔍 Scan Mux';hubMgrMsg(site,'Request failed');});
});
document.addEventListener('click',function(e){
  var btn=e.target.closest('.hub-mgr-dab-add-sel');if(!btn)return;
  var site=btn.dataset.site;
  var ch=(document.querySelector('.hub-mgr-dab-ch[data-site="'+site+'"]')||{}).value||'';
  var ppm=parseInt((document.querySelector('.hub-mgr-dab-ppm[data-site="'+site+'"]')||{}).value||0);
  var serial=(document.querySelector('.hub-mgr-dab-serial[data-site="'+site+'"]')||{}).value||'';
  var svcList=document.querySelector('.hub-mgr-dab-svc-list[data-site="'+site+'"]');
  var checked=[].slice.call(svcList?svcList.querySelectorAll('input[type=checkbox]:checked'):[]);
  if(!checked.length){hubMgrMsg(site,'No services selected');return;}
  btn.disabled=true;var done=0;
  checked.forEach(function(cb){
    var sn=cb.dataset.svcName||'';
    var diParams=['channel='+encodeURIComponent(ch)];
    if(serial)diParams.push('serial='+encodeURIComponent(serial));
    if(ppm)diParams.push('ppm='+ppm);
    var di='dab://'+encodeURIComponent(sn)+'?'+diParams.join('&');
    hubPost('/api/hub/site/'+encodeURIComponent(site)+'/input/add',{name:sn,device_index:di,alert_on_silence:true,alert_on_clip:false,ai_monitor:true})
    .then(function(){if(++done===checked.length){btn.disabled=false;hubMgrMsg(site,done+' service(s) queued for add',true);}})
    .catch(function(){if(++done===checked.length)btn.disabled=false;});
  });
});
document.addEventListener('click',function(e){
  var btn=e.target.closest('.hub-mgr-add-btn');if(!btn)return;
  var site=btn.dataset.site;
  var name=(document.querySelector('.hub-mgr-name[data-site="'+site+'"]')||{}).value||'';
  var type=(document.querySelector('.hub-mgr-type[data-site="'+site+'"]')||{}).value||'rtp';
  var sil=!!(document.querySelector('.hub-mgr-sil[data-site="'+site+'"]')||{}).checked;
  var clip=!!(document.querySelector('.hub-mgr-clip[data-site="'+site+'"]')||{}).checked;
  var ai=!!(document.querySelector('.hub-mgr-ai[data-site="'+site+'"]')||{}).checked;
  if(!name){hubMgrMsg(site,'Name is required');return;}
  var dev='';
  if(type==='fm'){
    var freq=parseFloat((document.querySelector('.hub-mgr-fm-freq[data-site="'+site+'"]')||{}).value||'');
    if(!freq||isNaN(freq)||freq<64||freq>108){hubMgrMsg(site,'Enter a valid FM frequency (64–108 MHz)');return;}
    var fppm=parseInt((document.querySelector('.hub-mgr-fm-ppm[data-site="'+site+'"]')||{}).value||0)||0;
    var fserial=((document.querySelector('.hub-mgr-fm-serial[data-site="'+site+'"]')||{}).value||'').trim();
    dev='fm://'+freq;
    var fparams=[];
    if(fserial)fparams.push('serial='+encodeURIComponent(fserial));
    if(fppm)fparams.push('ppm='+fppm);
    if(fparams.length)dev+='?'+fparams.join('&');
  } else {
    dev=((document.querySelector('.hub-mgr-dev[data-site="'+site+'"]')||{}).value||'').trim();
    if(!dev){hubMgrMsg(site,type==='http'?'Stream URL is required':'Device address is required');return;}
  }
  btn.disabled=true;
  hubPost('/api/hub/site/'+encodeURIComponent(site)+'/input/add',{name:name,device_index:dev,alert_on_silence:sil,alert_on_clip:clip,ai_monitor:ai})
  .then(function(d){btn.disabled=false;if(d.ok)hubMgrMsg(site,'✓ Add queued',true);else hubMgrMsg(site,'Failed: '+(d.error||'unknown'));})
  .catch(function(){btn.disabled=false;hubMgrMsg(site,'Request failed');});
});
document.addEventListener('click',function(e){
  var btn=e.target.closest('[data-action="hub-remove-input"]');if(!btn)return;
  if(!confirm('Remove "'+btn.dataset.name+'" from '+btn.dataset.site+'? Monitoring will restart.'))return;
  btn.disabled=true;
  hubPost('/api/hub/site/'+encodeURIComponent(btn.dataset.site)+'/input/remove',{name:btn.dataset.name})
  .then(function(d){btn.disabled=false;if(d.ok)btn.textContent='✓ Queued';else alert('Failed: '+(d.error||'unknown'));})
  .catch(function(){btn.disabled=false;});
});
document.addEventListener('click',function(e){
  var btn=e.target.closest('[data-action="hub-enable-input"],[data-action="hub-disable-input"]');if(!btn)return;
  var ep=btn.dataset.action==='hub-enable-input'?'enable':'disable';
  btn.disabled=true;
  hubPost('/api/hub/site/'+encodeURIComponent(btn.dataset.site)+'/input/'+ep,{name:btn.dataset.name})
  .then(function(d){btn.disabled=false;if(d.ok)btn.textContent='✓ Queued';else alert('Failed: '+(d.error||'unknown'));})
  .catch(function(){btn.disabled=false;});
});

// ── Log button ────────────────────────────────────────────────────────────────
var _logModalSite='';
function _showLog(site,pull){
  var modal=document.getElementById('hub-log-modal');
  var body=document.getElementById('hub-log-modal-body');
  var title=document.getElementById('hub-log-modal-title');
  var meta=document.getElementById('hub-log-modal-meta');
  var pullBtn=document.getElementById('hub-log-modal-pull');
  if(!modal)return;
  _logModalSite=site;
  title.textContent='📋 Log — '+site;
  if(pull){
    body.textContent='Requesting fresh log from client…';
    meta.textContent='';
    if(pullBtn){pullBtn.disabled=true;pullBtn.textContent='Pulling…';}
    hubPost('/api/hub/site/'+encodeURIComponent(site)+'/pull_log',{})
    .catch(function(){})
    .finally(function(){
      // Poll for the fresh dump (client has up to ~10s to respond via heartbeat)
      var polls=0;
      function waitForFresh(){
        fetch('/api/hub/site/'+encodeURIComponent(site)+'/log')
        .then(function(r){return r.json();})
        .then(function(d){
          if(d.fresh || polls>=6){
            var ts=d.ts?new Date(d.ts*1000).toLocaleTimeString():'';
            meta.textContent=d.fresh?('Fresh — '+ts):'Heartbeat cache';
            body.textContent=(d.lines||[]).slice().reverse().join('\n')||'(no log lines)';
            if(pullBtn){pullBtn.disabled=false;pullBtn.textContent='↻ Pull fresh log';}
          } else {
            polls++;
            setTimeout(waitForFresh,2000);
          }
        })
        .catch(function(){
          if(pullBtn){pullBtn.disabled=false;pullBtn.textContent='↻ Pull fresh log';}
        });
      }
      setTimeout(waitForFresh,2000);
    });
  } else {
    body.textContent='Loading…';
    meta.textContent='';
    fetch('/api/hub/site/'+encodeURIComponent(site)+'/log')
    .then(function(r){return r.json();})
    .then(function(d){
      var ts=d.ts?new Date(d.ts*1000).toLocaleTimeString():'';
      meta.textContent=d.fresh?('Fresh — '+ts):'Heartbeat cache (30 lines) — use ↻ to pull full log';
      body.textContent=(d.lines||[]).slice().reverse().join('\n')||'(no log lines)';
    })
    .catch(function(err){body.textContent='Error: '+(err.message||err);});
  }
  modal.style.display='flex';
}
document.addEventListener('click',function(e){
  var btn=e.target.closest('.site-log-btn');if(!btn)return;
  _showLog(btn.dataset.site,false);
});
document.getElementById('hub-log-modal-pull').addEventListener('click',function(){
  if(_logModalSite)_showLog(_logModalSite,true);
});
document.getElementById('hub-log-modal-close').addEventListener('click',function(){
  document.getElementById('hub-log-modal').style.display='none';
});
document.getElementById('hub-log-modal').addEventListener('click',function(e){
  if(e.target===this)this.style.display='none';
});

// ── Backup Now button ─────────────────────────────────────────────────────────
document.addEventListener('click',function(e){
  var btn=e.target.closest('.site-backup-btn');if(!btn)return;
  var site=btn.dataset.site;
  var origText=btn.textContent;
  btn.disabled=true;btn.textContent='Requesting…';
  hubPost('/api/hub/site/'+encodeURIComponent(site)+'/backup',{})
  .then(function(){
    // Poll backup_status until a fresh backup arrives (up to ~30s)
    var polls=0;var prevTs=null;
    // capture any existing backup ts so we know when a NEW one lands
    fetch('/api/hub/site/'+encodeURIComponent(site)+'/backup_status')
    .then(function(r){return r.json();})
    .then(function(d){prevTs=d.ts||null;})
    .catch(function(){})
    .finally(function(){
      function waitForBackup(){
        fetch('/api/hub/site/'+encodeURIComponent(site)+'/backup_status')
        .then(function(r){return r.json();})
        .then(function(d){
          var arrived=(d.ts&&(!prevTs||d.ts>prevTs));
          if(arrived||polls>=10){
            if(arrived){
              btn.textContent='✓ Backed up';btn.style.color='var(--ok)';
              setTimeout(function(){location.reload();},1500);
            } else {
              btn.disabled=false;btn.textContent=origText;
              alert('Backup request sent — the site will upload its backup at the next heartbeat (every 30s). Reload the page in a minute to see the download link.');
            }
          } else {
            polls++;
            setTimeout(waitForBackup,3000);
          }
        })
        .catch(function(){btn.disabled=false;btn.textContent=origText;});
      }
      setTimeout(waitForBackup,3000);
    });
  })
  .catch(function(){btn.disabled=false;btn.textContent=origText;});
});

// ── Restart button ────────────────────────────────────────────────────────────
document.addEventListener('click',function(e){
  var btn=e.target.closest('.site-restart-btn');if(!btn)return;
  var site=btn.dataset.site;
  if(!confirm('Send restart command to "'+site+'"?\n\nThe remote process will restart in ~1 second. Monitoring will be interrupted briefly.'))return;
  btn.disabled=true;btn.textContent='⏳';
  hubPost('/api/hub/site/'+encodeURIComponent(site)+'/restart',{})
  .then(function(d){
    if(d.ok){btn.textContent='✓ Restarting…';btn.style.color='var(--ok)';}
    else{btn.disabled=false;btn.textContent='🔄 Restart';alert('Restart failed: '+(d.error||'unknown'));}
  }).catch(function(err){btn.disabled=false;btn.textContent='🔄 Restart';alert('Error: '+(err.message||err));});
});

// Backup is now a direct download link — no JS handler needed.

// ── Ping button / modal ───────────────────────────────────────────────────────
(function(){
  var _pingSite='';
  var modal=document.getElementById('hub-ping-modal');
  var body=document.getElementById('hub-ping-modal-body');
  var title=document.getElementById('hub-ping-modal-title');
  var input=document.getElementById('hub-ping-target');
  var sendBtn=document.getElementById('hub-ping-send-btn');
  var closeBtn=document.getElementById('hub-ping-modal-close');
  var _pollTimer=null;

  function openModal(site){
    _pingSite=site;
    title.textContent='\uD83D\uDD0D Ping Test \u2014 '+site;
    input.value='';
    body.textContent='(enter a target and press Send)';
    modal.style.display='flex';
    input.focus();
  }
  function closeModal(){
    modal.style.display='none';
    if(_pollTimer){clearTimeout(_pollTimer);_pollTimer=null;}
  }

  document.addEventListener('click',function(e){
    var btn=e.target.closest('.site-ping-btn');if(!btn)return;
    openModal(btn.dataset.site);
  });
  if(closeBtn)closeBtn.addEventListener('click',closeModal);
  if(modal)modal.addEventListener('click',function(e){if(e.target===modal)closeModal();});

  function doPing(){
    var target=(input.value||'').trim();
    if(!target){alert('Enter a target IP or hostname first.');return;}
    if(_pollTimer){clearTimeout(_pollTimer);_pollTimer=null;}
    body.textContent='Sending ping command to '+_pingSite+'\u2026';
    sendBtn.disabled=true;sendBtn.textContent='Sending\u2026';
    hubPost('/api/hub/site/'+encodeURIComponent(_pingSite)+'/ping',{target:target}).then(function(d){
      if(!d.ok){body.textContent='Command failed: '+(d.error||'unknown');sendBtn.disabled=false;sendBtn.textContent='Send';return;}
      body.textContent='Command queued. Waiting for result\u2026';
      var polls=0,max=40;
      function poll(){
        fetch('/api/hub/site/'+encodeURIComponent(_pingSite)+'/ping')
        .then(function(r){return r.json();})
        .then(function(r){
          if(r.ready&&r.target===target){
            sendBtn.disabled=false;sendBtn.textContent='Send';
            var ts=r.ts?new Date(r.ts*1000).toLocaleTimeString():'?';
            body.textContent=(r.success?'\u2713 Success':'\u2717 Failed')+' \u2014 '+r.target+' at '+ts+'\n\n'+r.output;
          }else if(polls++<max){
            _pollTimer=setTimeout(poll,1500);
          }else{
            sendBtn.disabled=false;sendBtn.textContent='Send';
            body.textContent='Timed out waiting for result.';
          }
        }).catch(function(){if(polls++<max)_pollTimer=setTimeout(poll,1500);});
      }
      setTimeout(poll,2000);
    }).catch(function(err){body.textContent='Request error: '+(err.message||err);sendBtn.disabled=false;sendBtn.textContent='Send';});
  }

  if(sendBtn)sendBtn.addEventListener('click',doPing);
  if(input)input.addEventListener('keydown',function(e){if(e.key==='Enter')doPing();});
})();

// ── Retrain AI button ─────────────────────────────────────────────────────────
document.addEventListener('click',function(e){
  var btn=e.target.closest('.hub-retrain-btn');if(!btn)return;
  var site=btn.dataset.site,stream=btn.dataset.stream;
  btn.disabled=true;btn.textContent='⏳';
  hubPost('/api/hub/site/'+encodeURIComponent(site)+'/retrain',{stream:stream})
  .then(function(d){
    if(d.ok){btn.textContent='✓ Queued';btn.style.color='var(--ok)';}
    else{btn.disabled=false;btn.textContent='🔄 Retrain AI';alert('Failed: '+(d.error||'unknown'));}
  }).catch(function(err){btn.disabled=false;btn.textContent='🔄 Retrain AI';alert('Error: '+(err.message||err));});
});

// ── Calibrate Silence button ──────────────────────────────────────────────────
document.addEventListener('click',function(e){
  var btn=e.target.closest('.hub-calibrate-btn');if(!btn)return;
  var site=btn.dataset.site,stream=btn.dataset.stream;
  var hd=parseFloat(prompt('Headroom (dB) above current level for silence threshold (default 6):','6'));
  if(isNaN(hd))return;
  btn.disabled=true;btn.textContent='⏳';
  hubPost('/api/hub/site/'+encodeURIComponent(site)+'/calibrate_silence',{stream:stream,headroom_db:hd})
  .then(function(d){
    if(d.ok){btn.textContent='✓ Queued';btn.style.color='var(--ok)';}
    else{btn.disabled=false;btn.textContent='🎚 Calibrate Silence';alert('Failed: '+(d.error||'unknown'));}
  }).catch(function(err){btn.disabled=false;btn.textContent='🎚 Calibrate Silence';alert('Error: '+(err.message||err));});
});

// ── Per-site relay bitrate control ───────────────────────────────────────────
function setRelayBitrate(sel){
  var site    = sel.getAttribute('data-site');
  var bitrate = parseInt(sel.value, 10);
  var orig    = sel.value;
  sel.disabled = true;
  var csrfToken=(document.querySelector('meta[name="csrf-token"]')||{}).content||document.cookie.match(/(?:^|;\s*)csrf_token=([^;]+)/)?.[1]||'';
  fetch('/api/hub/site/' + encodeURIComponent(site) + '/relay_bitrate', {
    method: 'POST',
    headers: {'Content-Type':'application/json','X-CSRFToken': csrfToken},
    body: JSON.stringify({bitrate: bitrate})
  }).then(function(r){ return r.json(); }).then(function(d){
    sel.disabled = false;
    if(!d.ok){ sel.value = orig; alert('Failed to set relay bitrate: ' + (d.error||'unknown error')); }
  }).catch(function(){ sel.disabled = false; sel.value = orig; });
}
// ── Live audio toggle ────────────────────────────────────────────────────────
document.addEventListener('click', function(ev){
  var btn = ev.target.closest('button[data-rep-live]');
  if(!btn) return;
  var idx = btn.getAttribute('data-rep-live');
  var url = btn.getAttribute('data-url');
  var audio = document.getElementById('rep_live_'+idx);
  if(!audio) return;
  if(audio.style.display === 'none'){
    audio.src = url;
    audio.style.display = 'block';
    audio.play().catch(function(){});
    btn.textContent = '⏹ Stop';
  }else{
    audio.pause(); audio.removeAttribute('src'); audio.load();
    audio.style.display = 'none';
    btn.textContent = '▶ Live';
  }
});
// ── Clip duration selector updates URL ──────────────────────────────────────
document.addEventListener('change', function(ev){
  var sel = ev.target;
  if(!sel.id || !sel.id.startsWith('rhdur_')) return;
  var a = sel.parentElement.querySelector('a[href*="/clip?seconds="]');
  if(a){ a.href = a.href.replace(/seconds=\d+/, 'seconds=' + encodeURIComponent(sel.value)); }
});
// ── Auto-refresh: reload the page every 15s unless something needs keeping ───
(function(){
  var countdown = 15;
  var label = document.getElementById('refresh-countdown');
  function tick(){
    countdown--;
    if(label) label.textContent = 'Refreshing in ' + countdown + 's';
    if(countdown <= 0){
      var anyPlaying = false;
      document.querySelectorAll('audio').forEach(function(a){ if(!a.paused) anyPlaying = true; });
      // Pause if a source management panel or modal is open
      var panelOpen = false;
      document.querySelectorAll('[id^="hub-mgr-"]').forEach(function(p){
        if(p.style.display && p.style.display !== 'none') panelOpen = true;
      });
      var pingModal=document.getElementById('hub-ping-modal');
      if(pingModal && pingModal.style.display && pingModal.style.display !== 'none') panelOpen=true;
      // Pause if the user has typed something into a management input
      var inputDirty = false;
      document.querySelectorAll('.hub-mgr-name,.hub-mgr-dev,.hub-mgr-fm-freq,.hub-mgr-dab-serial').forEach(function(i){
        if(i.value && i.value.trim()) inputDirty = true;
      });
      // Pause if any stats accordion (DAB/FM details) is open
      var detailsOpen = false;
      document.querySelectorAll('details').forEach(function(d){ if(d.open) detailsOpen = true; });
      if(!anyPlaying && !panelOpen && !inputDirty && !detailsOpen){
        location.reload();
      } else {
        countdown = 15;
        if(label){
          if(anyPlaying) label.textContent = 'Paused (audio playing)';
          else label.textContent = 'Paused (panel open)';
        }
      }
    }
  }
  setInterval(tick, 1000);
})();
// ── Direct access probe: check if client URL is reachable from this browser ──
(function(){
  var directUrl = {{direct_url|tojson}};
  if(!directUrl) return;
  fetch(directUrl, {mode:'no-cors', cache:'no-store'})
    .then(function(){
      var banner = document.getElementById('direct-banner');
      if(banner) banner.style.display = 'flex';
    })
    .catch(function(){
      // Not reachable from this browser — stay on replica
    });
})();
// ── Signal history charts ──────────────────────────────────────────────────────
function drawMetricChart(canvas, points, color) {
  var W = canvas.offsetWidth || 400, H = 110;
  canvas.width = W; canvas.height = H;
  var ctx = canvas.getContext('2d');
  var pad = {t:8, r:8, b:24, l:44};
  var cw = W - pad.l - pad.r, ch = H - pad.t - pad.b;
  ctx.clearRect(0,0,W,H);
  if (!points || points.length < 2) {
    ctx.fillStyle = 'rgba(255,255,255,0.25)';
    ctx.font = '11px sans-serif'; ctx.textAlign = 'center';
    ctx.fillText(points && points.length === 1 ? 'Only 1 point — wait for more data' : 'No data', W/2, H/2);
    return;
  }
  var vals = points.map(function(p){return p[1];});
  var times = points.map(function(p){return p[0];});
  var minV = Math.min.apply(null,vals), maxV = Math.max.apply(null,vals);
  var rng = maxV - minV || 1;
  minV -= rng*0.08; maxV += rng*0.08; rng = maxV - minV;
  var minT = times[0], maxT = times[times.length-1], tRng = maxT - minT || 1;
  ctx.strokeStyle='rgba(255,255,255,0.06)'; ctx.lineWidth=1;
  ctx.fillStyle='rgba(255,255,255,0.35)'; ctx.font='9px monospace'; ctx.textAlign='right';
  for(var g=0;g<=4;g++){
    var gy=pad.t+ch*g/4;
    ctx.beginPath();ctx.moveTo(pad.l,gy);ctx.lineTo(pad.l+cw,gy);ctx.stroke();
    ctx.fillText((maxV-rng*g/4).toFixed(1), pad.l-3, gy+3);
  }
  ctx.fillStyle='rgba(255,255,255,0.3)'; ctx.textAlign='center';
  for(var tx=0;tx<=4;tx++){
    var gx=pad.l+cw*tx/4, gt=minT+tRng*tx/4, d=new Date(gt*1000);
    ctx.fillText(('0'+d.getHours()).slice(-2)+':'+('0'+d.getMinutes()).slice(-2), gx, H-4);
  }
  ctx.beginPath();
  points.forEach(function(p,i){
    var x=pad.l+(p[0]-minT)/tRng*cw, y=pad.t+(1-(p[1]-minV)/rng)*ch;
    i===0?ctx.moveTo(x,y):ctx.lineTo(x,y);
  });
  var lx=pad.l+(points[points.length-1][0]-minT)/tRng*cw;
  ctx.lineTo(lx,pad.t+ch); ctx.lineTo(pad.l,pad.t+ch); ctx.closePath();
  ctx.fillStyle=color.replace(/^#/,'').length===6
    ? 'rgba('+parseInt(color.slice(1,3),16)+','+parseInt(color.slice(3,5),16)+','+parseInt(color.slice(5,7),16)+',0.13)'
    : 'rgba(96,165,250,0.13)';
  ctx.fill();
  ctx.beginPath();
  points.forEach(function(p,i){
    var x=pad.l+(p[0]-minT)/tRng*cw, y=pad.t+(1-(p[1]-minV)/rng)*ch;
    i===0?ctx.moveTo(x,y):ctx.lineTo(x,y);
  });
  ctx.strokeStyle=color; ctx.lineWidth=1.5; ctx.lineJoin='round'; ctx.stroke();
}
function _scHistLoad(section) {
  var canvas=section.querySelector('.sc-hc'), status=section.querySelector('.sc-hs');
  var metric=section.querySelector('.sc-hm').value;
  var hours=parseFloat((section.querySelector('.sc-hr.active')||{dataset:{h:1}}).dataset.h);
  var site=section.dataset.site, stream=section.dataset.stream;
  var colorMap={fm_signal_dbm:'#34d399',fm_snr_db:'#6ee7b7',fm_stereo:'#a7f3d0',fm_rds_ok:'#34d399',dab_snr:'#a78bfa',dab_sig:'#c4b5fd',dab_bitrate:'#818cf8',lufs_m:'#fbbf24',lufs_s:'#fb923c',lufs_i:'#f87171',rtp_jitter_ms:'#e879f9',rtp_loss_pct:'#f472b6',silence_flag:'#64748b',clip_count:'#ef4444'};
  status.textContent='Loading…'; status.style.display='block';
  fetch('/api/metrics/'+encodeURIComponent(site)+'/'+encodeURIComponent(stream)+'?metric='+encodeURIComponent(metric)+'&hours='+hours)
    .then(function(r){return r.json();})
    .then(function(d){status.style.display='none'; drawMetricChart(canvas,d.points,colorMap[metric]||'#60a5fa');})
    .catch(function(){status.textContent='Failed to load'; status.style.display='block';});
}
function scHistToggle(btn) {
  var body=btn.nextElementSibling, open=body.style.display==='block';
  body.style.display=open?'none':'block';
  btn.querySelector('span').textContent=open?'▼':'▲';
  if(!open) _scHistLoad(btn.parentElement);
}
document.addEventListener('click',function(e){
  var rb=e.target.closest('.sc-hr'); if(!rb) return;
  var section=rb.closest('.sc-hist'); if(!section) return;
  section.querySelectorAll('.sc-hr').forEach(function(b){b.classList.remove('active');});
  rb.classList.add('active');
  if(rb.closest('.sc-hist-body').style.display==='block') _scHistLoad(section);
});
document.addEventListener('change',function(e){
  var sel=e.target.closest('.sc-hm'); if(!sel) return;
  var section=sel.closest('.sc-hist'); if(!section) return;
  if(sel.closest('.sc-hist-body').style.display==='block') _scHistLoad(section);
});
// ── Availability timeline ──────────────────────────────────────────────────────
var _TL_HOURS = [24, 1, 6];
var _TL_COLORS = {ok:'#22c55e', silence:'#ef4444', dab_missing:'#f59e0b', nodata:'#1e2a3a'};
function drawTimeline(canvas, segments, hours) {
  var W = canvas.offsetWidth || 400, H = 16;
  canvas.width = W; canvas.height = H;
  var ctx = canvas.getContext('2d');
  var n = segments.length, sw = W / n;
  segments.forEach(function(seg, i) {
    ctx.fillStyle = _TL_COLORS[seg[1]] || '#1e2a3a';
    ctx.fillRect(Math.floor(i*sw), 0, Math.ceil(sw)+1, H);
  });
  // Start/end time labels
  if (segments.length > 1) {
    ctx.fillStyle = 'rgba(255,255,255,0.45)';
    ctx.font = '8px monospace';
    var d0=new Date(segments[0][0]*1000), d1=new Date(segments[segments.length-1][0]*1000);
    ctx.textAlign='left';  ctx.fillText(('0'+d0.getHours()).slice(-2)+':'+('0'+d0.getMinutes()).slice(-2), 2, H-2);
    ctx.textAlign='right'; ctx.fillText(('0'+d1.getHours()).slice(-2)+':'+('0'+d1.getMinutes()).slice(-2), W-2, H-2);
  }
}
function _tlLoad(canvas) {
  var site=canvas.dataset.site, stream=canvas.dataset.stream, hours=canvas.dataset.hours||24;
  var label=canvas.previousElementSibling;
  fetch('/api/timeline/'+encodeURIComponent(site)+'/'+encodeURIComponent(stream)+'?hours='+hours)
    .then(function(r){return r.json();})
    .then(function(d){
      if(label) label.textContent=hours+'h';
      drawTimeline(canvas, d.segments, hours);
    }).catch(function(){});
}
function _tlLoadAll() {
  document.querySelectorAll('canvas.sc-tl').forEach(function(c){ _tlLoad(c); });
}
document.addEventListener('click',function(e){
  var c=e.target.closest('canvas.sc-tl'); if(!c) return;
  var cur=parseInt(c.dataset.hours)||24;
  var idx=(_TL_HOURS.indexOf(cur)+1)%_TL_HOURS.length;
  c.dataset.hours=_TL_HOURS[idx];
  _tlLoad(c);
});
// Auto-load timelines after a short delay (let page render first)
setTimeout(_tlLoadAll, 600);
</script>
<footer style="padding:14px 20px;text-align:center;font-size:11px;color:var(--mu);border-top:1px solid var(--bor);background:rgba(6,18,34,.86)">SignalScope {{build}} • Broadcast Signal Intelligence • <a href="/privacy" style="color:inherit;text-decoration:none;opacity:.7">Privacy Policy</a></footer>
</body></html>"""

HUB_WALL_TPL = r"""<!DOCTYPE html>
<html lang="en">
<head><meta charset="utf-8"><title>SignalScope Wall</title>
<meta name="viewport" content="width=device-width,initial-scale=1">
<link rel="icon" type="image/x-icon" href="/static/signalscope_icon.png">
<style>
:root{--ok:#22c55e;--wn:#f59e0b;--al:#ef4444;--mu:#6b7280;--bg:#060d1a;--bg2:#0d1629;--bg3:#111f35;--bor:#1e3048;--tx:#f0f4ff;--acc:#3b82f6}
*{box-sizing:border-box;margin:0;padding:0}
body{background:var(--bg);color:var(--tx);font-family:'Segoe UI',system-ui,sans-serif;min-height:100vh;overflow-x:hidden}
/* ── Header ─────────────────────────────────────────────── */
.wall-hdr{display:flex;align-items:center;gap:14px;padding:8px 20px;background:var(--bg2);border-bottom:2px solid var(--bor);position:sticky;top:0;z-index:100}
.wall-logo{font-size:16px;font-weight:800;letter-spacing:1.5px;color:var(--acc);white-space:nowrap;flex-shrink:0}
.wall-logo span{color:var(--tx)}
.wall-pills{display:flex;gap:8px;flex-wrap:wrap}
.wall-pill{display:flex;align-items:center;gap:5px;padding:3px 11px;border-radius:20px;font-size:12px;font-weight:700}
.wall-pill.ok{background:rgba(34,197,94,.15);color:var(--ok);border:1px solid rgba(34,197,94,.3)}
.wall-pill.warn{background:rgba(245,158,11,.15);color:var(--wn);border:1px solid rgba(245,158,11,.3)}
.wall-pill.alert{background:rgba(239,68,68,.15);color:var(--al);border:1px solid rgba(239,68,68,.3)}
.wall-clock{font-size:24px;font-weight:700;font-variant-numeric:tabular-nums;letter-spacing:3px;margin-left:auto;color:var(--ok);flex-shrink:0}
.wall-exit{padding:4px 12px;border-radius:6px;font-size:12px;font-weight:600;background:var(--bg3);color:var(--mu);text-decoration:none;border:1px solid var(--bor);flex-shrink:0}
.wall-exit:hover{color:var(--tx)}
/* ── Section chrome ─────────────────────────────────────── */
.wall-section{padding:12px 20px 4px}
.wall-sep{height:1px;background:var(--bor);margin:10px 20px 0}
.wall-section-hdr{font-size:9px;font-weight:800;letter-spacing:2.5px;color:var(--mu);text-transform:uppercase;margin-bottom:8px}
/* ── Sites strip ─────────────────────────────────────────── */
.sites-strip{display:flex;gap:8px;flex-wrap:wrap}
.site-pill{display:flex;align-items:center;gap:6px;padding:5px 13px;border-radius:8px;font-size:13px;font-weight:700;border:1.5px solid}
.site-pill.ok{background:rgba(34,197,94,.1);border-color:rgba(34,197,94,.4);color:var(--ok)}
.site-pill.warn{background:rgba(245,158,11,.1);border-color:rgba(245,158,11,.4);color:var(--wn)}
.site-pill.alert{background:rgba(239,68,68,.12);border-color:rgba(239,68,68,.4);color:var(--al)}
.site-pill.offline{background:rgba(107,114,128,.08);border-color:var(--bor);color:var(--mu)}
.site-pill .sdot{width:8px;height:8px;border-radius:50%;background:currentColor;flex-shrink:0}
.site-pill .sc-cnt{font-size:10px;opacity:.7;margin-left:2px}
/* ── Broadcast Chains ────────────────────────────────────── */
.chains-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(460px,1fr));gap:12px}
.chain-card{background:var(--bg2);border:2px solid var(--bor);border-radius:12px;overflow:hidden;transition:border-color .5s,box-shadow .5s}
.chain-card.ok{border-color:rgba(34,197,94,.35)}
.chain-card.fault{border-color:rgba(239,68,68,.7);box-shadow:0 0 22px rgba(239,68,68,.14)}
.chain-card.adbreak{border-color:rgba(245,158,11,.45)}
.chain-card.maintenance{border-color:rgba(59,130,246,.4)}
.chain-card-hdr{display:flex;align-items:center;gap:8px;padding:8px 12px;background:rgba(0,0,0,.25);border-bottom:1px solid var(--bor)}
.chain-card-dot{width:9px;height:9px;border-radius:50%;flex-shrink:0}
.chain-card-dot.ok{background:var(--ok)}.chain-card-dot.fault{background:var(--al);animation:dotPulse 1.2s infinite}
.chain-card-dot.adbreak{background:var(--wn)}.chain-card-dot.unknown,.chain-card-dot.maintenance{background:#3b82f6}
.chain-card-name{font-size:13px;font-weight:800;flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}
.chain-card-badge{padding:3px 10px;border-radius:8px;font-size:10px;font-weight:800;letter-spacing:.5px;white-space:nowrap;flex-shrink:0}
.chain-card-badge.ok{background:rgba(34,197,94,.18);color:var(--ok)}
.chain-card-badge.fault{background:rgba(239,68,68,.22);color:var(--al)}
.chain-card-badge.adbreak{background:rgba(245,158,11,.18);color:var(--wn)}
.chain-card-badge.unknown,.chain-card-badge.maintenance{background:rgba(59,130,246,.15);color:#93c5fd}
/* Node flow — horizontal scroll, always left→right */
.chain-flow{display:flex;align-items:center;flex-wrap:nowrap;overflow-x:auto;gap:2px;padding:8px 12px 10px;scrollbar-width:thin;scrollbar-color:var(--bor) transparent}
.chain-flow::-webkit-scrollbar{height:4px}.chain-flow::-webkit-scrollbar-track{background:transparent}.chain-flow::-webkit-scrollbar-thumb{background:var(--bor);border-radius:2px}
.wc-arrow{color:var(--mu);font-size:14px;padding:0 4px;flex-shrink:0;line-height:1;user-select:none;align-self:center;opacity:.55}
/* Position column wrapper */
.wc-pos{display:flex;flex-direction:column;align-items:center;gap:3px;flex-shrink:0}
.wc-pos-num{font-size:8px;font-weight:800;letter-spacing:1.5px;color:var(--mu);opacity:.45;text-transform:uppercase}
/* Individual node (single-stream position) */
.wc-node{display:flex;flex-direction:column;align-items:center;padding:6px 8px;border-radius:8px;border:1.5px solid;min-width:80px;max-width:120px;text-align:center;transition:all .4s;position:relative;flex-shrink:0}
.wc-node.ok{background:rgba(34,197,94,.08);border-color:rgba(34,197,94,.4);color:var(--ok)}
.wc-node.down{background:rgba(239,68,68,.12);border-color:var(--al);color:var(--al);animation:nodePulse 1.4s infinite}
.wc-node.offline{background:rgba(107,114,128,.07);border-color:var(--bor);color:var(--mu)}
.wc-node.unknown{background:rgba(59,130,246,.07);border-color:rgba(59,130,246,.25);color:#93c5fd}
.wc-node.maintenance{background:rgba(29,78,216,.1);border-color:rgba(59,130,246,.45);color:#93c5fd}
.wc-node.downstream{opacity:.32;border-color:var(--bor);background:transparent;color:var(--mu);animation:none}
.wc-node-lbl{font-size:11px;font-weight:700;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;max-width:108px;line-height:1.2}
.wc-node-site{font-size:9px;opacity:.55;margin-top:1px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;max-width:108px}
.wc-node-bar{width:100%;height:3px;background:rgba(255,255,255,.08);border-radius:2px;margin-top:5px;overflow:hidden}
.wc-node-fill{height:100%;border-radius:2px;transition:width .9s}
.wc-node-lev{font-size:9px;margin-top:2px;font-variant-numeric:tabular-nums;opacity:.85}
.wc-fault-tag{position:absolute;top:-9px;left:50%;transform:translateX(-50%);background:var(--al);color:#fff;font-size:8px;font-weight:800;padding:1px 5px;border-radius:3px;white-space:nowrap;letter-spacing:.3px}
/* Stack group (redundancy position) */
.wc-stack{display:flex;flex-direction:column;gap:3px;border:1.5px solid;border-radius:9px;padding:5px 7px;position:relative;flex-shrink:0;min-width:170px;max-width:230px}
.wc-stack.ok{border-color:rgba(34,197,94,.35)}.wc-stack.down{border-color:rgba(239,68,68,.6);animation:nodePulse 1.4s infinite}
.wc-stack.offline{border-color:var(--bor)}.wc-stack.unknown{border-color:rgba(59,130,246,.28)}
.wc-stack.downstream{opacity:.32;border-color:var(--bor);animation:none}
.wc-stack-mode{font-size:8px;text-align:left;color:var(--mu);margin-bottom:3px;letter-spacing:.5px;opacity:.75;font-weight:700;text-transform:uppercase;border-bottom:1px solid rgba(255,255,255,.06);padding-bottom:3px}
/* Compact sub-node row inside stack */
.wc-srow{display:flex;align-items:center;gap:5px;padding:4px 6px;border-radius:6px;border:1px solid;transition:all .4s;position:relative}
.wc-srow.ok{background:rgba(34,197,94,.07);border-color:rgba(34,197,94,.35);color:var(--ok)}
.wc-srow.down{background:rgba(239,68,68,.11);border-color:var(--al);color:var(--al);animation:nodePulse 1.4s infinite}
.wc-srow.offline{background:rgba(107,114,128,.06);border-color:var(--bor);color:var(--mu)}
.wc-srow.unknown{background:rgba(59,130,246,.06);border-color:rgba(59,130,246,.22);color:#93c5fd}
.wc-srow.maintenance{background:rgba(29,78,216,.09);border-color:rgba(59,130,246,.42);color:#93c5fd}
.wc-srow.downstream{opacity:.28;border-color:var(--bor);background:transparent;color:var(--mu);animation:none}
.wc-srow-dot{width:7px;height:7px;border-radius:50%;background:currentColor;flex-shrink:0}
.wc-srow-lbl{font-size:11px;font-weight:700;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;flex:1;min-width:0}
.wc-srow-site{font-size:9px;opacity:.5;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;flex-shrink:0;max-width:60px}
.wc-srow-bar{flex:0 0 44px;height:4px;background:rgba(255,255,255,.08);border-radius:2px;overflow:hidden;flex-shrink:0}
.wc-srow-fill{height:100%;border-radius:2px;transition:width .9s}
.wc-srow-lev{font-size:9px;font-variant-numeric:tabular-nums;opacity:.82;white-space:nowrap;flex-shrink:0;width:38px;text-align:right}
/* Animations */
@keyframes nodePulse{0%,100%{box-shadow:0 0 0 0 rgba(239,68,68,0)}50%{box-shadow:0 0 12px 3px rgba(239,68,68,.3)}}
@keyframes dotPulse{0%,100%{opacity:1;transform:scale(1)}50%{opacity:.5;transform:scale(.8)}}
/* ── Stream grid ─────────────────────────────────────────── */
.streams-wall{display:grid;grid-template-columns:repeat(auto-fill,minmax(210px,1fr));gap:8px}
.sw-card{background:var(--bg2);border-radius:10px;border:2px solid;padding:10px 12px;display:flex;flex-direction:column;gap:5px}
.sw-card.ok{border-color:rgba(34,197,94,.28)}
.sw-card.warn{border-color:rgba(245,158,11,.4)}
.sw-card.alert{border-color:rgba(239,68,68,.5)}
.sw-card.down{border-color:rgba(239,68,68,.4);background:rgba(239,68,68,.04)}
.sw-card.offline{border-color:var(--bor);opacity:.55}
.sw-top{display:flex;align-items:center;gap:6px}
.sw-dot{width:10px;height:10px;border-radius:50%;flex-shrink:0}
.sw-dot.ok{background:var(--ok)}.sw-dot.warn{background:var(--wn)}
.sw-dot.alert,.sw-dot.down{background:var(--al);box-shadow:0 0 6px rgba(239,68,68,.5)}
.sw-dot.offline{background:var(--mu)}
.sw-name{font-size:13px;font-weight:700;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}
.sw-site{font-size:10px;color:var(--mu);margin-left:auto;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;max-width:80px;text-align:right}
.sw-bar-wrap{display:flex;align-items:center;gap:6px}
.sw-bar-track{flex:1;height:7px;background:var(--bg3);border-radius:4px;overflow:hidden}
.sw-bar-fill{height:100%;border-radius:4px}
.sw-bar-val{font-size:11px;font-variant-numeric:tabular-nums;width:46px;text-align:right;flex-shrink:0}
.sw-meta{font-size:11px;color:var(--mu);overflow:hidden;text-overflow:ellipsis;white-space:nowrap;display:flex;align-items:center;gap:5px}
.sw-type{display:inline-block;padding:1px 5px;border-radius:3px;font-size:9px;font-weight:800;letter-spacing:.5px;flex-shrink:0}
.sw-type.dab{background:rgba(59,130,246,.2);color:#93c5fd}
.sw-type.fm{background:rgba(168,85,247,.2);color:#c084fc}
.sw-type.lw{background:rgba(20,184,166,.2);color:#2dd4bf}
.sw-type.other{background:rgba(107,114,128,.2);color:var(--mu)}
</style>
</head>
<body>

<!-- ── Header ─────────────────────────────────────────────────────── -->
<div class="wall-hdr">
  <div class="wall-logo">📡 Signal<span>Scope</span></div>
  <div class="wall-pills">
    {% set n_alert = sites|selectattr('site_status','eq','ALERT')|list|length %}
    {% set n_warn  = sites|selectattr('site_status','eq','WARN')|list|length %}
    {% set n_off   = sites|rejectattr('online')|list|length %}
    {% if n_alert %}
      <div class="wall-pill alert">⚠ {{n_alert}} Alert{{'s' if n_alert>1}}</div>
    {% endif %}
    {% if n_warn %}
      <div class="wall-pill warn">⚡ {{n_warn}} Warning{{'s' if n_warn>1}}</div>
    {% endif %}
    {% if n_off %}
      <div class="wall-pill alert">✗ {{n_off}} Site{{'s' if n_off>1}} Offline</div>
    {% endif %}
    {% if not n_alert and not n_warn and not n_off %}
      <div class="wall-pill ok">✓ All Systems OK</div>
    {% endif %}
  </div>
  <div class="wall-clock" id="wallClock">--:--:--</div>
  <a href="/hub" class="wall-exit">🧰 Exit Wall Mode</a>
</div>

<!-- ── Sites strip ───────────────────────────────────────────────── -->
<div class="wall-section">
  <div class="wall-section-hdr">Connected Sites</div>
  <div class="sites-strip">
    {% for s in sites %}
    {% set sc = 'offline' if not s.online else ('alert' if s.site_status=='ALERT' else ('warn' if s.site_status=='WARN' else 'ok')) %}
    <div class="site-pill {{sc}}">
      <div class="sdot"></div>
      {{s.site}}
      {% if s.alert_count %}<span class="sc-cnt">{{s.alert_count}}⚠</span>{% endif %}
      {% if s.warn_count and not s.alert_count %}<span class="sc-cnt">{{s.warn_count}}⚡</span>{% endif %}
      {% if not s.online %}<span class="sc-cnt">offline</span>{% endif %}
    </div>
    {% endfor %}
  </div>
</div>

<div class="wall-sep"></div>

{% if chains %}
<!-- ── Broadcast Chains ───────────────────────────────────────────── -->
<div class="wall-section">
  <div class="wall-section-hdr">Broadcast Chains</div>
  <div class="chains-grid">
    {% for chain in chains %}
    {% set cs = 'ok' if chain.status=='ok' else ('fault' if chain.status=='fault' else 'unknown') %}
    <div class="chain-card {{cs}}" id="wc_card_{{chain.id|e}}">
      <div class="chain-card-hdr">
        <div class="chain-card-dot {{cs}}" id="wc_dot_{{chain.id|e}}"></div>
        <div class="chain-card-name" title="{{chain.name|e}}">{{chain.name|e}}</div>
        {% if chain.has_maintenance %}<span style="font-size:10px;color:#93c5fd;flex-shrink:0">🔧</span>{% endif %}
        <div class="chain-card-badge {{cs}}" id="wc_badge_{{chain.id|e}}">
          {{'ALL OK' if chain.status=='ok' else ('FAULT' if chain.status=='fault' else '…')}}
        </div>
      </div>
      <div class="chain-flow" id="wc_flow_{{chain.id|e}}">
        {% for node in chain.nodes %}
        {% set ni = loop.index0 %}
        {% if not loop.first %}<div class="wc-arrow">→</div>{% endif %}
        <div class="wc-pos">
          <div class="wc-pos-num">P{{loop.index}}</div>
          {% if node.get('type') == 'stack' %}
          <div class="wc-stack unknown" id="wc_node_{{chain.id|e}}_{{ni}}">
            <div class="wc-stack-mode">{{(node.get('mode') or 'all')|upper}} silent = fault</div>
            {% for sub in node.nodes %}
            {% set si = loop.index0 %}
            <div class="wc-srow unknown" id="wc_sub_{{chain.id|e}}_{{ni}}_{{si}}">
              <div class="wc-srow-dot"></div>
              <div class="wc-srow-lbl" title="{{(sub.get('label') or sub.get('stream',''))|e}}">{{(sub.get('label') or sub.get('stream',''))|e}}</div>
              {% if sub.get('site') %}<div class="wc-srow-site" title="{{sub.get('site','')|e}}">{{sub.get('site','')|e}}</div>{% endif %}
              <div class="wc-srow-bar"><div class="wc-srow-fill" style="width:0%;background:currentColor"></div></div>
              <div class="wc-srow-lev">…</div>
            </div>
            {% endfor %}
          </div>
          {% else %}
          <div class="wc-node unknown" id="wc_node_{{chain.id|e}}_{{ni}}">
            <div class="wc-node-lbl" title="{{(node.get('label') or node.get('stream',''))|e}}">{{(node.get('label') or node.get('stream',''))|e}}</div>
            <div class="wc-node-site">{{node.get('site','')|e}}</div>
            <div class="wc-node-bar"><div class="wc-node-fill" style="width:0%;background:var(--ok)"></div></div>
            <div class="wc-node-lev">…</div>
          </div>
          {% endif %}
        </div>
        {% endfor %}
      </div>
    </div>
    {% endfor %}
  </div>
</div>

<div class="wall-sep"></div>
{% endif %}

<!-- ── Stream Status ──────────────────────────────────────────────── -->
<div class="wall-section" style="padding-bottom:18px">
  <div class="wall-section-hdr">Stream Status</div>
  <div class="streams-wall">
    {% set ns = namespace(found=false) %}
    {% for s in sites %}
    {% for st in s.get('streams',[]) %}
    {% set ns.found = true %}
    {% set ai  = st.get('ai_status','') or '' %}
    {% set lev = st.get('level_dbfs', -120.0) %}
    {% set lpct = [(lev+80)/80*100, 100]|min|int %}
    {% set is_down = lev <= -55.0 %}
    {% if not s.online %}
      {% set card_cls='offline' %}{% set dot_cls='offline' %}{% set lcol='#4b5563' %}
    {% elif is_down %}
      {% set card_cls='down' %}{% set dot_cls='down' %}{% set lcol='var(--al)' %}
    {% elif '[ALERT]' in ai %}
      {% set card_cls='alert' %}{% set dot_cls='alert' %}{% set lcol='var(--al)' %}
    {% elif '[WARN]' in ai %}
      {% set card_cls='warn' %}{% set dot_cls='warn' %}{% set lcol='var(--wn)' %}
    {% else %}
      {% set card_cls='ok' %}{% set dot_cls='ok' %}{% set lcol='var(--ok)' %}
    {% endif %}
    {% set dev = (st.get('device_index','') or '').lower() %}
    {% if dev.startswith('dab://') %}{% set dtype='dab' %}
    {% elif dev.startswith('fm://') %}{% set dtype='fm' %}
    {% elif dev.startswith('rtp://') or dev.startswith('livewire') or dev|int(-1) >= 0 %}{% set dtype='lw' %}
    {% else %}{% set dtype='other' %}{% endif %}
    <div class="sw-card {{card_cls}}">
      <div class="sw-top">
        <div class="sw-dot {{dot_cls}}"></div>
        <div class="sw-name" title="{{st.name|e}}">{{st.name|e}}</div>
        <div class="sw-site" title="{{s.site|e}}">{{s.site|e}}</div>
      </div>
      <div class="sw-bar-wrap">
        <div class="sw-bar-track"><div class="sw-bar-fill" style="width:{{lpct}}%;background:{{lcol}}"></div></div>
        <div class="sw-bar-val" style="color:{{lcol}}">{{lev}} dB</div>
      </div>
      <div class="sw-meta">
        <span class="sw-type {{dtype}}">{{dtype|upper}}</span>
        {% if dtype=='dab' and st.get('dab_service') %}{{st.dab_service}}{% endif %}
        {% if dtype=='fm' and st.get('fm_rds_ps') %}📡 {{st.fm_rds_ps}}{% endif %}
        {% if dtype=='lw' and st.get('rtp_loss_pct') %}RTP loss {{st.rtp_loss_pct}}%{% endif %}
        {% if not s.online %}Offline{% elif is_down %}Signal Lost{% endif %}
      </div>
    </div>
    {% endfor %}
    {% endfor %}
    {% if not ns.found %}
    <div style="color:var(--mu);font-size:13px;grid-column:1/-1">No streams reporting yet.</div>
    {% endif %}
  </div>
</div>

<script nonce="{{csp_nonce()}}">
// ── Clock ──────────────────────────────────────────────────────────
(function tick(){
  var n=new Date(),pad=function(x){return String(x).padStart(2,'0');};
  var el=document.getElementById('wallClock');
  if(el)el.textContent=pad(n.getHours())+':'+pad(n.getMinutes())+':'+pad(n.getSeconds());
  setTimeout(tick,1000);
})();

// ── Chain status polling ───────────────────────────────────────────
var _wcFaultSince={};  // chain id -> epoch ms when fault first seen client-side

function _fmtDur(ms){
  var s=Math.floor(ms/1000);
  if(s<60)return s+'s';
  var m=Math.floor(s/60),rs=s%60;
  return m+'m'+(rs?(' '+rs+'s'):'');
}

function _applyWcNode(el,st,level,isFaultPt,isStack){
  // Detect element type from existing class (wc-stack / wc-node / wc-srow)
  var isSrow=(el.className||'').indexOf('wc-srow')>=0;
  var cls=isStack?'wc-stack':(isSrow?'wc-srow':'wc-node');
  el.className=cls+' '+st;
  // level bar + value (nodes and compact rows, not stack containers)
  if(!isStack){
    var fill=el.querySelector('.wc-node-fill')||el.querySelector('.wc-srow-fill');
    var lev=el.querySelector('.wc-node-lev')||el.querySelector('.wc-srow-lev');
    if(level!==null&&level!==undefined){
      var pct=Math.max(0,Math.min(100,Math.round((level+80)/80*100)));
      var col=st==='ok'?'var(--ok)':st==='down'?'var(--al)':'var(--mu)';
      if(fill){fill.style.width=pct+'%';if(!isSrow)fill.style.background=col;}
      if(lev)lev.textContent=level+' dB';
    } else {
      if(fill)fill.style.width='0%';
      if(lev)lev.textContent=st==='offline'?'Offline':'—';
    }
  }
  // fault point tag (single nodes only)
  var old=el.querySelector('.wc-fault-tag');if(old)old.remove();
  if(isFaultPt&&!isStack&&!isSrow){
    var tag=document.createElement('div');tag.className='wc-fault-tag';tag.textContent='FAULT';
    el.appendChild(tag);
  }
}

function pollChains(){
  fetch('/api/chains/status').then(function(r){return r.json();}).then(function(data){
    var now=Date.now();
    (data.results||[]).forEach(function(chain){
      var cid=chain.id;
      var fi=chain.fault_index;
      var ds=chain.display_status||chain.status;
      var isAdbreak=(ds==='adbreak'||ds==='pending');
      var cardCls=isAdbreak?'adbreak':(chain.status==='ok'?'ok':(chain.status==='fault'?'fault':'unknown'));
      if(chain.has_maintenance)cardCls='maintenance';

      // Track fault duration client-side
      if(chain.status==='fault'){
        if(!_wcFaultSince[cid])_wcFaultSince[cid]=now;
      } else {
        _wcFaultSince[cid]=null;
      }

      // Card border class
      var card=document.getElementById('wc_card_'+cid);
      if(card)card.className='chain-card '+cardCls;

      // Dot
      var dot=document.getElementById('wc_dot_'+cid);
      if(dot)dot.className='chain-card-dot '+cardCls;

      // Badge text
      var badge=document.getElementById('wc_badge_'+cid);
      if(badge){
        var txt='…';
        if(isAdbreak){txt='AD BREAK';}
        else if(chain.status==='ok'){txt='ALL OK';}
        else if(chain.status==='fault'){
          txt='FAULT';
          if(_wcFaultSince[cid])txt+=' '+_fmtDur(now-_wcFaultSince[cid]);
        }
        badge.textContent=txt;
        badge.className='chain-card-badge '+cardCls;
      }

      // Nodes
      (chain.nodes||[]).forEach(function(node,idx){
        var isDown=(fi!==null&&fi!==undefined&&idx===fi);
        var isDnstr=(fi!==null&&fi!==undefined&&idx>fi);
        if(node.type==='stack'){
          // Update stack container
          var stackEl=document.getElementById('wc_node_'+cid+'_'+idx);
          var stackSt=isDnstr?'downstream':(node.status||'unknown');
          if(stackEl)stackEl.className='wc-stack '+stackSt;
          // Update each sub-node
          (node.nodes||[]).forEach(function(sub,si){
            var subEl=document.getElementById('wc_sub_'+cid+'_'+idx+'_'+si);
            if(!subEl)return;
            var subSt=isDnstr?'downstream':(sub.status||'unknown');
            _applyWcNode(subEl,subSt,sub.level,false,false);
          });
        } else {
          var el=document.getElementById('wc_node_'+cid+'_'+idx);
          if(!el)return;
          var st=isDnstr?'downstream':(node.status||'unknown');
          _applyWcNode(el,st,node.level,isDown,false);
        }
      });
    });
  }).catch(function(){});
}
pollChains();
setInterval(pollChains,5000);

// ── Page refresh every 60s to pick up new streams/sites ────────────
setTimeout(function(){location.reload();},60000);
</script>
</body></html>"""

HUB_TPL = r"""<!doctype html>
<html lang="en"><head><meta charset="utf-8"><title>SignalScope — Hub</title>
<meta name="viewport" content="width=device-width,initial-scale=1">
<meta name="csrf-token" content="{{csrf_token()}}">
<style nonce="{{csp_nonce()}}">
:root{--bg:#07142b;--sur:#0d2346;--bor:#17345f;--acc:#17a8ff;--ok:#22c55e;--wn:#f59e0b;--al:#ef4444;--tx:#eef5ff;--mu:#8aa4c8;--fs-xs:10px;--fs-sm:11px;--fs-md:12px;--fs-base:13px;--fs-lg:15px;--lh:1.45;--sp-xs:4px;--sp-sm:8px;--sp-md:13px;--sp-lg:18px;--r-sm:5px;--r:8px;--r-lg:12px}
*{box-sizing:border-box;margin:0;padding:0}body{font-family:system-ui,sans-serif;background:radial-gradient(circle at top, #12376f 0%, var(--bg) 38%, #05101f 100%);color:var(--tx);font-size:14px;line-height:var(--lh);position:relative}body::before{content:"";position:fixed;right:28px;bottom:22px;width:280px;height:280px;background:url("/static/signalscope_icon.png") no-repeat center/contain;opacity:.045;pointer-events:none;filter:drop-shadow(0 0 24px rgba(23,168,255,.10));z-index:0}body>*{position:relative;z-index:1}
header{background:linear-gradient(180deg, rgba(10,31,65,.96), rgba(9,24,48,.96));border-bottom:1px solid var(--bor);padding:12px 20px;display:flex;align-items:center;gap:10px;flex-wrap:wrap;box-shadow:0 10px 24px rgba(0,0,0,.18)}
header h1{font-size:17px;font-weight:700}.badge{font-size:11px;padding:2px 8px;border-radius:999px;background:#1e3a5f;color:var(--acc)}
.nav-active{background:var(--acc)!important;color:#fff!important}
nav a{color:var(--tx);font-size:13px;padding:5px 10px;border-radius:6px;background:var(--bor);text-decoration:none}
main{padding:18px;max-width:1600px;margin:0 auto}
body.wall-mode header, body.wall-mode .hub-topbar{display:none}
body.wall-mode main{padding:10px;max-width:none}
.hub-summary{display:flex;gap:10px;align-items:center;flex-wrap:wrap;margin-bottom:12px}
.sum-pill{display:inline-flex;align-items:center;gap:6px;padding:7px 10px;border-radius:999px;background:linear-gradient(180deg,#143766,#102b54);border:1px solid var(--bor);font-size:12px}
.hub-toolbar{display:flex;gap:10px;align-items:center;flex-wrap:wrap;margin-bottom:14px}
.search{min-width:280px;flex:1;max-width:460px;padding:9px 11px;background:#12305c;border:1px solid var(--bor);border-radius:8px;color:var(--tx)}
.site-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(420px,1fr));gap:16px;align-items:start}
body.wall-mode .site-grid{grid-template-columns:repeat(auto-fit,minmax(480px,1fr));gap:14px}
.site-card{background:var(--sur);border:1px solid var(--bor);border-radius:14px;margin-bottom:0;overflow:hidden;box-shadow:0 6px 18px rgba(0,0,0,.18);transition:transform .14s, box-shadow .14s}
.site-card:hover{transform:translateY(-1px);box-shadow:0 10px 24px rgba(0,0,0,.24)}
.site-card.site-ok{border-left:4px solid var(--ok)}.site-card.site-warn{border-left:4px solid var(--wn)}.site-card.site-alert{border-left:4px solid var(--al)}.site-card.site-offline{border-left:4px solid var(--mu)}
.site-header{padding:12px 16px;display:flex;align-items:center;gap:10px;border-bottom:1px solid var(--bor);flex-wrap:wrap}
.site-name{font-size:16px;font-weight:700}
body.wall-mode .site-card{border-radius:10px}
body.wall-mode .site-header{padding:10px 14px;background:linear-gradient(180deg,#143766,#102b54)}
body.wall-mode .site-name{font-size:18px}
body.wall-mode .site-meta{font-size:13px}
.site-meta{color:var(--mu);font-size:12px;margin-left:auto}
.dot{width:10px;height:10px;border-radius:50%;display:inline-block;flex-shrink:0}
.dot-ok{background:var(--ok)}.dot-wn{background:var(--wn)}.dot-al{background:var(--al)}.dot-off{background:var(--mu)}
.dok{background:var(--ok)}.dwn{background:var(--wn)}.dal{background:var(--al)}.dlr{background:var(--acc)}.did{background:var(--mu)}
.streams{display:grid;grid-template-columns:repeat(auto-fill,minmax(290px,1fr));gap:12px;padding:14px}

@keyframes alertPulse {
  0% { box-shadow:0 0 0 0 rgba(239,68,68,0.7); }
  70% { box-shadow:0 0 0 10px rgba(239,68,68,0); }
  100% { box-shadow:0 0 0 0 rgba(239,68,68,0); }
}
.alert-flash{
  animation:alertPulse 1.2s ease-out;
}

body.wall-mode .streams{grid-template-columns:repeat(auto-fill,minmax(250px,1fr));gap:10px;padding:10px}
.sc{background:#123764;border:1px solid var(--bor);border-radius:10px;overflow:hidden;box-shadow:0 2px 8px rgba(0,0,0,.12)}
body.wall-mode .sc{}
.sc.stats-alert{border-left:3px solid var(--al)}.sc.stats-warn{border-left:3px solid var(--wn)}
.alert-badge{display:inline-flex;align-items:center;padding:2px 7px;border-radius:999px;font-size:10px;font-weight:700;letter-spacing:.04em;margin-left:4px}
.badge-silence{background:#102033;color:#93c5fd}.badge-hiss{background:#3a2f0f;color:#fde68a}.badge-clip{background:#381414;color:#fca5a5}.badge-ai{background:#14263a;color:#93c5fd}
.stats-block{margin-top:6px;border-top:1px solid var(--bor);padding-top:6px}
.stats-toggle{display:flex;align-items:center;justify-content:space-between;width:100%;background:none;border:none;color:var(--mu);font-size:11px;padding:4px 0;cursor:pointer}
.stats-toggle:hover{color:var(--tx)}
.site-card.dragging{opacity:.55}.site-card.skeleton{position:relative}
.site-card.skeleton::after{content:"";position:absolute;inset:0;background:linear-gradient(90deg,transparent,rgba(255,255,255,.05),transparent);transform:translateX(-100%);animation:hubshimmer 1.2s infinite}
@keyframes hubshimmer{100%{transform:translateX(100%)}}
.sc-name{font-weight:600;font-size:13px;padding:10px 10px 4px;display:flex;align-items:center;gap:6px}
.sc-dev{font-size:10px;color:var(--mu);margin-left:auto;overflow:hidden;text-overflow:ellipsis;max-width:110px;white-space:nowrap}
.sc-name strong{font-size:12px}
.ic{display:inline-block;vertical-align:-2px;flex-shrink:0}
.sc-row{display:flex;justify-content:space-between;font-size:var(--fs-md);color:var(--mu);margin-top:5px;line-height:var(--lh)}
.sc-row span{color:var(--tx)}
.rtp-ok{color:var(--ok)}.rtp-wn{color:var(--wn)}.rtp-al{color:var(--al)}
.ai-ok{color:var(--ok)}.ai-wn{color:var(--wn)}.ai-al{color:var(--al)}
.lbar-wrap{display:flex;align-items:center;gap:6px}
.lbar-track{flex:1;height:6px;background:var(--bor);border-radius:3px;overflow:hidden}
.lbar-fill{height:6px;border-radius:3px;transition:width .4s}
.lbar-val{font-size:12px;font-weight:600;width:64px;text-align:right}
.aib{margin:6px 10px;padding:5px 8px;border-radius:5px;font-size:12px}
.aok{background:#1e3a1e;color:var(--ok)}.awn{background:#3a2a0f;color:var(--wn)}.aal{background:#3a0f0f;color:var(--al)}.alr{background:#1e2a3a;color:var(--acc)}.aid{background:var(--bor);color:var(--mu)}
.pb{height:4px;background:var(--bor);margin:0 10px 4px;border-radius:2px}
.pbi{height:4px;background:var(--acc);border-radius:2px;transition:width .5s}
.np-strip{display:flex;align-items:center;gap:8px;padding:6px 10px;border-top:1px solid var(--bor);background:linear-gradient(180deg,#12305c,#10284f)}
.np-art{width:36px;height:36px;border-radius:4px;object-fit:cover}
.np-text{flex:1;min-width:0}
.np-title{font-size:12px;font-weight:600;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}
.np-sub{font-size:11px;color:var(--mu);white-space:nowrap;overflow:hidden;text-overflow:ellipsis}
.listen-strip{display:flex;align-items:center;gap:5px;padding:6px 10px;border-top:1px solid var(--bor);flex-wrap:wrap}
.hist-wrap{border-top:1px solid var(--bor)}
.hist-toggle{width:100%;text-align:left;background:none;border:none;color:var(--mu);font-size:12px;padding:6px 10px;cursor:pointer}
.hist-toggle:hover{color:var(--tx)}
.hev{padding:4px 10px;border-bottom:1px solid var(--bor);font-size:var(--fs-sm);color:var(--mu);line-height:var(--lh)}
.hSILENCE,.hsilence{color:#93c5fd}.hCLIP,.hclip{color:#fca5a5}.hHISS,.hhiss{color:#fde68a}
.hAI_ALERT,.hai_alert{color:#fca5a5}.hAI_WARN,.hai_warn{color:#fde68a}
.hRTP_LOSS,.hrtp_loss{color:#c4b5fd}.hPTP,.hptp{color:#86efac}
.btn{display:inline-block;padding:4px 10px;border-radius:5px;font-size:11px;cursor:pointer;border:none;text-decoration:none}
.bp{background:var(--acc);color:#fff}.bg{background:var(--bor);color:var(--tx)}.bd{background:var(--al);color:#fff}.bw{background:#7c2d12;color:#fca5a5}.bs{padding:3px 9px;font-size:12px}.nav-active{background:var(--acc)!important;color:#fff!important}
.ptp-bar{padding:10px 16px;border-top:1px solid var(--bor);display:flex;gap:16px;flex-wrap:wrap;font-size:12px;color:var(--mu)}
.ptp-bar span{color:var(--tx)}
.offline-banner{padding:18px;text-align:center;color:var(--al);font-size:13px;background:#1a0a0a;border-radius:6px;margin:10px 14px}
.hist{display:none;padding:10px 16px;border-top:1px solid var(--bor);font-size:12px}
.hist.open{display:block}
.hist-entry{padding:4px 0;border-bottom:1px solid var(--bor);color:var(--mu)}
.hist-entry b{color:var(--tx)}
.no-sites{padding:60px;text-align:center;color:var(--mu)}
.rtp-ok{color:var(--ok)}.rtp-wn{color:var(--wn)}.rtp-al{color:var(--al)}
.rds-rt-wrap{display:block;max-width:170px;overflow:hidden;white-space:nowrap;text-align:right}
.rds-rt-static{display:block;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}
.rds-rt-scroll{display:inline-flex;align-items:center;white-space:nowrap;min-width:max-content;animation:rds-rt-marquee 14s linear infinite}
.rds-rt-scroll span{display:inline-block;padding-right:2.5rem}
@keyframes rds-rt-marquee{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}
.sc-detail{display:none}.sc-detail.open{display:block}
.sc-expand-btn{background:none;border:none;color:var(--mu);padding:2px 5px;font-size:13px;cursor:pointer;line-height:1;transition:transform .2s,color .15s;flex-shrink:0}
.sc-expand-btn:hover{color:var(--tx)}.sc-expand-btn.open{transform:rotate(180deg)}
</style>
<script nonce="{{csp_nonce()}}">
function aiClass(s){return s.includes('ALERT')?'ai-al':s.includes('WARN')?'ai-wn':'ai-ok';}
function rtpClass(p){return p>=2?'rtp-al':p>=0.5?'rtp-wn':'rtp-ok';}
function dotClass(s){return s==='OK'?'dot-ok':s.includes('WARN')?'dot-wn':s.includes('ALERT')?'dot-al':'dot-off';}
function siteStatus(streams){
  if(streams.some(s=>s.ai_status.includes('ALERT')))return 'ALERT';
  if(streams.some(s=>s.ai_status.includes('WARN')))return 'WARN';
  return 'OK';
}
function escapeHtml(s){return String(s).replace(/[&<>"']/g,function(c){return({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]);});}
function fmt(ts){if(!ts)return'—';const d=new Date(ts*1000);return d.toLocaleTimeString();}
function ago(s){if(s<5)return'just now';if(s<60)return s+'s ago';return Math.round(s/60)+'m ago';}
function toggleHist(id){const el=document.getElementById(id);el.classList.toggle('open');}
var lastAlertState={};
function playAlertSound(){try{new Audio('/static/alert.wav').play();}catch(e){}}
var _levelMode=localStorage.getItem('ss_level_mode')||'rms';
(function(){document.querySelectorAll('.sc-lbar-label').forEach(function(el){el.textContent=_levelMode==='peak'?'Peak':'RMS';});})();
document.addEventListener('click',function(e){
  if(!e.target.classList.contains('sc-lbar-label'))return;
  _levelMode=_levelMode==='rms'?'peak':'rms';
  localStorage.setItem('ss_level_mode',_levelMode);
  document.querySelectorAll('.sc-lbar-label').forEach(function(el){el.textContent=_levelMode==='peak'?'Peak':'RMS';});
});
var _hmpActive = null; // currently active Live button
function _closeHubMiniPlayer(){
  var mp=document.getElementById('hub-mini-player');
  if(mp) mp.style.display='none';
  var audio=document.getElementById('hmp-audio');
  if(audio){audio.pause();audio.src='';}
  if(_hmpActive){_hmpActive.textContent='▶ Live';_hmpActive.className='btn bp bs';_hmpActive=null;}
  document.body.style.paddingBottom='';
  try{sessionStorage.removeItem('hmp_live');}catch(e){}
}
function toggleLive(siteIdx,streamIdx,btn){
  // Tapping the active button again stops playback
  if(_hmpActive===btn){_closeHubMiniPlayer();return;}
  // Stop any previous stream
  if(_hmpActive){_hmpActive.textContent='▶ Live';_hmpActive.className='btn bp bs';}
  var mp=document.getElementById('hub-mini-player');
  var audio=document.getElementById('hmp-audio');
  if(!mp||!audio) return;
  var url=btn.dataset.url;
  var name=btn.dataset.name||('Stream '+streamIdx);
  var site=btn.dataset.siteName||'';
  var _hmpt=document.getElementById('hmp-title');
  _hmpt.textContent=name; _hmpt.title=name;
  var _hmps=document.getElementById('hmp-sub');
  _hmps.textContent=site; _hmps.title=site;
  audio.src=url;audio.type='audio/mpeg';audio.load();audio.play().catch(function(){});
  mp.style.display='flex';
  document.body.style.paddingBottom='72px';
  btn.textContent='⏹ Stop';btn.className='btn bd bs';
  _hmpActive=btn;
  try{sessionStorage.setItem('hmp_live',JSON.stringify({url:url,title:name,sub:site}));}catch(e){}
}// ── Hub AJAX refresh ──────────────────────────────────────────
var _hubTimer = null;
var _hubLastReload = 0; // epoch ms — guard against reload loops
function _hubSchedule(){ _hubTimer = setTimeout(hubRefresh, 5000); }
function hubRefresh(){
  clearTimeout(_hubTimer);
  fetch('/hub/data?_='+Date.now(),{cache:'no-store'}).then(r=>r.json()).then(data=>{
    data.sites.forEach(function(site){
      // Alert sound + flash for new alerts
      (site.streams||[]).forEach(function(st){
        var key=site.site+"_"+st.name;
        var state=(st.ai_status||"");
        if((state.includes("ALERT")||state.includes("WARN")) && lastAlertState[key]!==state){
          playAlertSound();
          var card=document.querySelector('[data-name="'+st.name+'"]');
          if(card){card.classList.add('alert-flash');setTimeout(()=>card.classList.remove('alert-flash'),1200);}
        }
        lastAlertState[key]=state;
      });
      var sid = 'site-' + site.site.replace(/ /g,'_').replace(/[.]/g,'_').replace(/-/g,'_');
      var card = document.getElementById(sid);
      if(!card) return;
      var dot = card.querySelector('.site-header .dot');
      if(dot) dot.className='dot dot-'+(site.site_status==='OK'?'ok':site.site_status==='WARN'?'wn':site.site_status==='ALERT'?'al':'off');
      card.className='site-card site-'+(site.site_status==='OK'?'ok':site.site_status==='WARN'?'warn':site.site_status==='ALERT'?'alert':'offline');
      card.classList.remove('skeleton');
      var meta = card.querySelector('.site-meta');
      if(meta) meta.textContent = 'Last seen: ' + agoJS(site.age_s);
      var latency = card.querySelector('.site-meta-latency');
      if(latency && site.latency_ms != null) latency.textContent = 'Latency: ' + site.latency_ms + ' ms';
      // Update version badge colour and update button against hub build
      var lbwBadge = card.querySelector('.site-lowbw-badge');
      if(site.low_bw && !lbwBadge){
        var nb=document.createElement('span');
        nb.className='badge site-lowbw-badge';
        nb.title='Low-bandwidth mode — heartbeat every 30 s, clips on demand';
        nb.style.cssText='background:#1a2a1a;color:#6ee7b7;border:1px solid #166534';
        nb.textContent='📶 Low BW';
        var siteHeader=card.querySelector('.site-header');
        if(siteHeader) siteHeader.appendChild(nb);
      } else if(!site.low_bw && lbwBadge){
        lbwBadge.remove();
      }
      var vbadge = card.querySelector('.site-version-badge');
      if(vbadge && site.build){
        var match = (site.build === data.hub_build);
        vbadge.style.background = match ? '#1e2433' : '#3a2a0f';
        vbadge.style.color = match ? 'var(--mu)' : '#fbbf24';
        vbadge.title = match ? 'Version match' : 'Version mismatch — hub is '+data.hub_build;
        var ubtn = card.querySelector('.site-update-btn');
        if(!match && site.online && !ubtn){
          ubtn = document.createElement('button');
          ubtn.className='btn site-update-btn';
          ubtn.dataset.site = site.site;
          ubtn.style.cssText='background:#3a2a0f;color:#fbbf24;border:1px solid #b45309;font-size:11px;padding:2px 10px';
          ubtn.title='Push update to this site';
          ubtn.textContent='⬆ Update';
          vbadge.insertAdjacentElement('afterend', ubtn);
        } else if(match && ubtn){
          ubtn.remove();
        }
      }
      (site.streams||[]).forEach(function(s, i){
        var sc = card.querySelector('.sc[data-idx="'+i+'"]');
        if(!sc) return;
        // Keep stream name and listen URL in sync with heartbeat (handles post-upgrade reorders)
        var sname = sc.querySelector('.sc-name strong');
        if(sname && sname.textContent.trim() !== (s.name||'').trim()) sname.textContent = s.name||'';
        var liveBtn = sc.querySelector('[data-action="live"]');
        var ci = (s._client_idx != null) ? s._client_idx : i;
        if(liveBtn){ liveBtn.dataset.url = '/hub/site/'+encodeURIComponent(site.site)+'/stream/'+ci+'/live';
                     liveBtn.dataset.site = ci; }
        var ai = s.ai_status || '';
        var ph = s.ai_phase  || '';
        var sdot = sc.querySelector('.dot');
        if(sdot){ var dc='did'; if(ai.includes('[ALERT]'))dc='dal'; else if(ai.includes('[WARN]'))dc='dwn'; else if(ph==='learning')dc='dlr'; else if(s.enabled)dc='dok'; sdot.className='dot '+dc; }
        var rmsLev = s.level_dbfs;
        var pkLev  = s.peak_dbfs !== undefined ? s.peak_dbfs : rmsLev;
        var lbwrap = sc.querySelector('.lbar-wrap');
        if(lbwrap){ lbwrap.dataset.rms=rmsLev; lbwrap.dataset.peak=pkLev; }
        var lev = (_levelMode==='peak') ? pkLev : rmsLev;
        var lpct = Math.min(Math.max((lev+80)/80*100,0),100);
        var lcol = lev<=-55?'var(--al)':lev<=-20?'var(--wn)':'var(--ok)';
        var lbar = sc.querySelector('.sc-lbar'); if(lbar){lbar.style.width=lpct+'%';lbar.style.background=lcol;}
        var lval = sc.querySelector('.sc-level'); if(lval){lval.textContent=lev+' dB';lval.style.color=lcol;}
        var fmt = sc.querySelector('.sc-fmt'); if(fmt) fmt.textContent=s.format||'—';
        var rtRow = sc.querySelector('.sc-rt-row');
        var rtWrap = sc.querySelector('.sc-rt-wrap');
        var rtText = sc.querySelector('.sc-rt-text');
        var rtVal = (s.fm_rds_rt || s.dab_dls || '').trim();
        if(rtRow && rtWrap){
          rtRow.style.display = rtVal ? '' : 'none';
          rtWrap.title = rtVal;
          if(rtText){
            if(rtVal.length > 40){
              rtText.className = 'rds-rt-scroll sc-rt-text';
              rtText.innerHTML = '<span>🎵 '+escapeHtml(rtVal)+'</span><span aria-hidden="true">🎵 '+escapeHtml(rtVal)+'</span>';
            }else{
              rtText.className = 'rds-rt-static sc-rt-text';
              rtText.textContent = rtVal ? '🎵 ' + rtVal : '—';
            }
          }
        }
        var rtp = sc.querySelector('.sc-rtp');
        if(rtp){ rtp.textContent=s.rtp_loss_pct+'%'; rtp.className='sc-rtp '+(s.rtp_loss_pct>=2?'rtp-al':s.rtp_loss_pct>=0.5?'rtp-wn':'rtp-ok'); }
        var jitterEl = sc.querySelector('.sc-jitter');
        if(jitterEl){
          var jms = s.rtp_jitter_ms || 0;
          jitterEl.textContent = jms.toFixed(2)+' ms';
          jitterEl.style.color = jms > 5 ? 'var(--wn)' : 'var(--ok)';
          var jRow = jitterEl.closest('.sc-row');
          if(jRow) jRow.style.display = jms > 0 ? '' : 'none';
        }
        var sla = sc.querySelector('.sc-sla');
        if(sla && s.sla_pct!=null){ sla.textContent=s.sla_pct+'%'; sla.style.color=s.sla_pct>=99?'var(--ok)':'var(--wn)'; }
        var aib = sc.querySelector('.aib');
        if(aib){
          var ac='aid'; if(ph==='learning')ac='alr'; else if(ai.includes('[ALERT]'))ac='aal'; else if(ai.includes('[WARN]'))ac='awn'; else if(ai.includes('[OK]'))ac='aok';
          aib.className='aib '+ac;
          aib.textContent='🤖 '+(ai||'Waiting…');
        }
      });
      var banner = card.querySelector('.offline-banner');
      var streams = card.querySelector('.streams');
      if(!site.online){
        if(!banner){ banner=document.createElement('div'); banner.className='offline-banner'; var sh=card.querySelector('.site-header'); if(sh) sh.after(banner); }
        banner.textContent = '⚠ No heartbeat for '+Math.round(site.age_s)+'s — site may be down';
        if(streams) streams.style.opacity='0.35';
      } else {
        if(banner) banner.remove();
        if(streams) streams.style.opacity='';
      }
    });
    var knownIds = Array.from(document.querySelectorAll('.site-card')).map(c=>c.id);
    var incoming = data.sites.map(s=>'site-'+s.site.replace(/ /g,'_').replace(/[.]/g,'_').replace(/-/g,'_'));
    // Reload when a new site appears OR stream count changes.
    // Also reload when page has 0 cards but sites exist (first-site-connects case).
    // Guard: at least 30 s since last reload to prevent storms.
    var hasNew = incoming.some(id=>!knownIds.includes(id));
    var streamCountChanged = !hasNew && data.sites.some(function(site){
      var sid='site-'+site.site.replace(/ /g,'_').replace(/[.]/g,'_').replace(/-/g,'_');
      var c=document.getElementById(sid);
      if(!c) return false;
      var domN=c.querySelectorAll('.sc[data-idx]').length;
      return domN>0 && domN!==(site.streams||[]).length;
    });
    if((hasNew||streamCountChanged) && (Date.now() - _hubLastReload) > 30000){
      _hubLastReload = Date.now();
      location.reload();
      return;
    }
    // Re-apply active search filter after card content updates
    var _si = document.getElementById('hubSearch');
    if(_si && _si._searchApply && ((_si.value||'').trim())) _si._searchApply();
  }).catch(function(e){console.warn('[hubRefresh]',e);}).finally(function(){ _hubSchedule(); });
}
function agoJS(s){ s=Math.round(s||0); if(s<5)return'just now'; if(s<60)return s+'s ago'; return Math.round(s/60)+'m ago'; }
function _csrfFetch(url,opts){
  opts=opts||{};
  if(!opts.headers) opts.headers={};
  var t=(document.querySelector('meta[name="csrf-token"]')||{}).content||document.cookie.match(/(?:^|;\s*)csrf_token=([^;]+)/)?.[1]||"";
  opts.headers["X-CSRFToken"]=t;
  return fetch(url,opts);
}
function initCardSearch(inputId, gridId, itemSelector){
  var input=document.getElementById(inputId), grid=document.getElementById(gridId);
  if(!input || !grid) return;
  function apply(){
    var q=(input.value||'').toLowerCase().trim();
    var shown=0, hidden=0;
    grid.querySelectorAll(itemSelector).forEach(function(card){
      // Use textContent (not innerText) so hidden elements like .sc-detail
      // (format, alert history, etc.) are included in the match.
      var hay=(card.textContent||'').toLowerCase();
      var match=!q || hay.indexOf(q)!==-1;
      card.style.display=match?'':'none';
      match?shown++:hidden++;
    });
    // Show a "no results" hint if everything is hidden
    var hint=document.getElementById('hub-search-hint');
    if(q && shown===0){
      if(!hint){hint=document.createElement('div');hint.id='hub-search-hint';hint.style.cssText='color:var(--mu);font-size:13px;padding:18px 4px;grid-column:1/-1';grid.insertBefore(hint,grid.firstChild);}
      hint.textContent='No sites or streams matching "'+q+'"';
    } else if(hint){hint.remove();}
  }
  input.addEventListener('input', apply);
  // Expose so hubRefresh can re-apply after updates
  input._searchApply = apply;
}
function initDragGrid(gridId, storageKey, itemSelector){
  var grid=document.getElementById(gridId);
  if(!grid) return;
  var dragEl=null;
  function saveOrder(){
    var ids=Array.from(grid.querySelectorAll(itemSelector)).map(function(el){return el.id;}).filter(Boolean);
    localStorage.setItem(storageKey, JSON.stringify(ids));
  }
  function restoreOrder(){
    try{
      var ids=JSON.parse(localStorage.getItem(storageKey)||'[]');
      ids.forEach(function(id){
        var el=document.getElementById(id);
        if(el) grid.appendChild(el);
      });
    }catch(e){}
  }
  restoreOrder();
  grid.querySelectorAll(itemSelector).forEach(function(card){
    card.addEventListener('dragstart', function(){dragEl=card; card.classList.add('dragging');});
    card.addEventListener('dragend', function(){card.classList.remove('dragging'); saveOrder();});
    card.addEventListener('dragover', function(e){
      e.preventDefault();
      if(!dragEl || dragEl===card) return;
      var rect=card.getBoundingClientRect();
      var before=(e.clientY - rect.top) < rect.height/2;
      grid.insertBefore(dragEl, before ? card : card.nextSibling);
    });
  });
}
function sendSiteCommand(site, command, btn){
  var csrfToken=(document.querySelector('meta[name="csrf-token"]')||{}).content||document.cookie.match(/(?:^|;\s*)csrf_token=([^;]+)/)?.[1]||'';
  btn.disabled = true;
  btn.textContent = '…';
  fetch('/api/hub/site/' + encodeURIComponent(site) + '/command', {
    method: 'POST',
    headers: {'Content-Type':'application/json','X-CSRFToken': csrfToken},
    body: JSON.stringify({command: command})
  }).then(function(r){ return r.json(); }).then(function(d){
    if(d.ok){
      btn.textContent = '✓';
      btn.style.background = '#1e3a5f';
      btn.style.color = 'var(--acc)';
      setTimeout(function(){ btn.textContent = command==='start'?'▶ Start':'⏹ Stop'; btn.disabled=false; btn.style.background=''; btn.style.color=''; }, 8000);
    } else {
      btn.disabled = false;
      btn.textContent = command==='start'?'▶ Start':'⏹ Stop';
      alert('Failed: '+(d.error||'unknown error'));
    }
  }).catch(function(){
    btn.disabled = false;
    btn.textContent = command==='start'?'▶ Start':'⏹ Stop';
  });
}
document.addEventListener('click', function(e){
  var btn = e.target.closest('.sc-cmd-btn');
  if(!btn) return;
  var site = btn.getAttribute('data-site');
  var cmd  = btn.getAttribute('data-cmd');
  if(site && cmd) sendSiteCommand(site, cmd, btn);
});
function pushSiteUpdate(siteName, btn){
  // Inline confirmation — confirm() is blocked on LAN HTTP origins in modern browsers
  var card = btn.closest('.site-card');
  if(!card) return;
  var existingConf = card.querySelector('.site-update-confirm');
  if(existingConf){ existingConf.remove(); return; }
  var bar = document.createElement('div');
  bar.className = 'site-update-confirm';
  bar.style.cssText = 'padding:8px 16px;background:#2a1e08;border-top:1px solid #b45309;display:flex;align-items:center;gap:10px;font-size:13px;color:#fbbf24';
  bar.innerHTML = 'Push update to <strong>'+siteName+'</strong>? Site will restart briefly. '
    +'<button class="btn bs" style="background:#166534;color:#fff;margin-left:auto" data-confirm-update="1">⬆ Yes, Update</button>'
    +'<button class="btn bg bs" data-confirm-cancel="1">Cancel</button>';
  bar.querySelector('[data-confirm-cancel]').addEventListener('click', function(){ bar.remove(); });
  bar.querySelector('[data-confirm-update]').addEventListener('click', function(){
    bar.innerHTML = '<span>⏳ Sending update command…</span>';
    _csrfFetch('/api/hub/site/'+encodeURIComponent(siteName)+'/update', {
      method:'POST', headers:{'Content-Type':'application/json'}, body:'{}'
    }).then(function(r){return r.json();})
      .then(function(d){
        if(d.ok){
          bar.innerHTML = '<span style="color:#86efac">✓ Update command sent — site will restart shortly</span>';
          setTimeout(function(){ bar.remove(); btn.textContent='✓ Sent'; btn.style.color='var(--ok)'; btn.style.borderColor='var(--ok)'; btn.disabled=true; }, 2000);
        } else {
          bar.innerHTML = '<span style="color:#fca5a5">✗ Failed: '+(d.error||'unknown error')+'</span>'
            +'<button class="btn bg bs" style="margin-left:auto" data-confirm-cancel="1">Dismiss</button>';
          bar.querySelector('[data-confirm-cancel]').addEventListener('click', function(){ bar.remove(); });
        }
      }).catch(function(err){
        bar.innerHTML = '<span style="color:#fca5a5">✗ Error: '+(err.message||err)+'</span>'
          +'<button class="btn bg bs" style="margin-left:auto" data-confirm-cancel="1">Dismiss</button>';
        bar.querySelector('[data-confirm-cancel]').addEventListener('click', function(){ bar.remove(); });
      });
  });
  card.insertBefore(bar, card.firstChild);
}
document.addEventListener('click', function(e){
  var btn = e.target.closest('.site-update-btn');
  if(!btn) return;
  pushSiteUpdate(btn.getAttribute('data-site'), btn);
});
function removeSite(siteName, btn){
  // Inline confirmation — confirm() is blocked on LAN HTTP origins in modern browsers
  var card = btn.closest('.site-card');
  if(!card) return;
  var existingConf = card.querySelector('.site-remove-confirm');
  if(existingConf){ existingConf.remove(); return; }
  var bar = document.createElement('div');
  bar.className = 'site-remove-confirm';
  bar.style.cssText = 'padding:8px 16px;background:#2a1010;border-top:1px solid var(--al);display:flex;align-items:center;gap:10px;font-size:13px;color:#fca5a5';
  bar.innerHTML = 'Remove <strong>'+siteName+'</strong> from hub? '
    +'<button class="btn bd bs" data-confirm-remove="1" style="margin-left:auto">✓ Yes, Remove</button>'
    +'<button class="btn bg bs" data-confirm-cancel="1">Cancel</button>';
  bar.querySelector('[data-confirm-cancel]').addEventListener('click', function(){ bar.remove(); });
  bar.querySelector('[data-confirm-remove]').addEventListener('click', function(){
    _csrfFetch('/hub/site/remove/'+encodeURIComponent(siteName), {method:'POST'})
      .then(function(r){return r.json();})
      .then(function(d){ if(d.ok && card){ card.remove(); } else { bar.remove(); } })
      .catch(function(){ bar.remove(); });
  });
  card.insertBefore(bar, card.firstChild);
}

// Delegated listeners for approve/remove actions on hub site cards
document.addEventListener('click', function(e){
  var btn = e.target.closest('[data-action="hub-approve-site"]');
  if(btn){
    var site = btn.dataset.site;
    btn.disabled = true; btn.textContent = 'Approving…';
    _csrfFetch('/hub/site/approve/'+encodeURIComponent(site), {method:'POST'})
      .then(function(r){return r.json();})
      .then(function(d){
        if(d.ok){ location.reload(); }
        else { btn.disabled=false; btn.textContent='✓ Approve'; }
      }).catch(function(){ btn.disabled=false; btn.textContent='✓ Approve'; });
    return;
  }
  var rbtn = e.target.closest('[data-action="hub-remove-site"]');
  if(rbtn){ removeSite(rbtn.dataset.site, rbtn); }
});
function toggleFullscreen(){
  if(!document.fullscreenElement){
    document.documentElement.requestFullscreen && document.documentElement.requestFullscreen();
  }else{
    document.exitFullscreen && document.exitFullscreen();
  }
}
function tickClock(){
  var el=document.getElementById('wallClock');
  if(!el) return;
  var d=new Date();
  el.textContent=d.toLocaleTimeString();
}

function _syncExpandAllBtn(siteCard){
  var allBtn = siteCard.querySelector('[data-action="sc-expand-all"]');
  if(!allBtn) return;
  var details = siteCard.querySelectorAll('.sc-detail');
  var allOpen = details.length > 0 && Array.from(details).every(function(d){ return d.classList.contains('open'); });
  allBtn.textContent = allOpen ? '⊟ Collapse All' : '⊞ Expand All';
}

// CSP-safe button wiring for hub listen buttons + mini-player close
document.addEventListener('click', function(e){
  if(e.target.closest('#hmp-close')){ _closeHubMiniPlayer(); return; }
  var btn = e.target.closest('[data-action]');
  if(!btn) return;
  if(btn.dataset.action === 'sc-expand'){
    var key = btn.dataset.scKey;
    var detail = document.getElementById('sc_detail_'+key);
    if(!detail) return;
    var open = detail.classList.toggle('open');
    btn.classList.toggle('open', open);
    try{ localStorage.setItem('hub_sc_expand_'+key, open ? '1' : '0'); }catch(ex){}
    // Keep the "Expand All" button label in sync
    var siteCard = btn.closest('.site-card');
    if(siteCard) _syncExpandAllBtn(siteCard);
    return;
  }
  if(btn.dataset.action === 'sc-expand-all'){
    var siteCard = btn.closest('.site-card');
    if(!siteCard) return;
    var details = siteCard.querySelectorAll('.sc-detail');
    var expandBtns = siteCard.querySelectorAll('[data-action="sc-expand"]');
    var anyCollapsed = Array.from(details).some(function(d){ return !d.classList.contains('open'); });
    details.forEach(function(d){ d.classList.toggle('open', anyCollapsed); });
    expandBtns.forEach(function(b){
      b.classList.toggle('open', anyCollapsed);
      try{ localStorage.setItem('hub_sc_expand_'+b.dataset.scKey, anyCollapsed ? '1' : '0'); }catch(ex){}
    });
    _syncExpandAllBtn(siteCard);
    return;
  }
  if(btn.dataset.action !== 'live') return;
  e.preventDefault();
  toggleLive(btn.dataset.sidx, btn.dataset.site, btn);
});

// Only start polling after the DOM is fully rendered
document.addEventListener('DOMContentLoaded', function(){
  initCardSearch('hubSearch', 'site-grid', '.site-card');
  initDragGrid('site-grid', 'signalscope.hub.order', '.site-card');
  // Restore sc-detail expand state from localStorage
  document.querySelectorAll('[data-action="sc-expand"]').forEach(function(btn){
    var key = btn.dataset.scKey;
    var saved = null;
    try{ saved = localStorage.getItem('hub_sc_expand_'+key); }catch(ex){}
    if(saved === '1'){
      var detail = document.getElementById('sc_detail_'+key);
      if(detail){ detail.classList.add('open'); btn.classList.add('open'); }
    }
  });
  // Sync Expand All button labels after restore
  document.querySelectorAll('.site-card').forEach(function(sc){ _syncExpandAllBtn(sc); });
  tickClock();
  setInterval(tickClock, 1000);
  setTimeout(function(){
    document.querySelectorAll('.site-card').forEach(function(el){el.classList.remove('skeleton');});
    hubRefresh(); // starts the self-rescheduling loop via .finally()
  }, 800);
  // When the tab becomes visible again after being hidden, fire immediately
  document.addEventListener('visibilitychange', function(){
    if(!document.hidden){
      clearTimeout(_hubTimer);
      hubRefresh();
    }
  });
});

// ── Signal history charts ──────────────────────────────────────────────────────
function drawMetricChart(canvas, points, color, refBand) {
  var W = canvas.offsetWidth || 400, H = 110;
  canvas.width = W; canvas.height = H;
  var ctx = canvas.getContext('2d');
  var pad = {t:8, r:8, b:24, l:44};
  var cw = W - pad.l - pad.r, ch = H - pad.t - pad.b;
  ctx.clearRect(0,0,W,H);
  if (!points || points.length < 2) {
    ctx.fillStyle = 'rgba(255,255,255,0.25)';
    ctx.font = '11px sans-serif'; ctx.textAlign = 'center';
    ctx.fillText(points && points.length === 1 ? 'Only 1 point — wait for more data' : 'No data', W/2, H/2);
    return;
  }
  var vals = points.map(function(p){return p[1];});
  var times = points.map(function(p){return p[0];});
  var minV = Math.min.apply(null,vals), maxV = Math.max.apply(null,vals);
  if(refBand){ minV=Math.min(minV,refBand.mean-refBand.std*2); maxV=Math.max(maxV,refBand.mean+refBand.std*2); }
  var rng = maxV - minV || 1;
  minV -= rng*0.08; maxV += rng*0.08; rng = maxV - minV;
  var minT = times[0], maxT = times[times.length-1], tRng = maxT - minT || 1;
  // Grid + Y labels
  ctx.strokeStyle='rgba(255,255,255,0.06)'; ctx.lineWidth=1;
  ctx.fillStyle='rgba(255,255,255,0.35)'; ctx.font='9px monospace'; ctx.textAlign='right';
  for(var g=0;g<=4;g++){
    var gy=pad.t+ch*g/4;
    ctx.beginPath();ctx.moveTo(pad.l,gy);ctx.lineTo(pad.l+cw,gy);ctx.stroke();
    ctx.fillText((maxV-rng*g/4).toFixed(1), pad.l-3, gy+3);
  }
  // X labels
  ctx.fillStyle='rgba(255,255,255,0.3)'; ctx.textAlign='center';
  for(var tx=0;tx<=4;tx++){
    var gx=pad.l+cw*tx/4, gt=minT+tRng*tx/4, d=new Date(gt*1000);
    ctx.fillText(('0'+d.getHours()).slice(-2)+':'+('0'+d.getMinutes()).slice(-2), gx, H-4);
  }
  // Reference band — ±1σ baseline for current hour
  if(refBand && refBand.n >= 10){
    var meanY=pad.t+(1-(refBand.mean-minV)/rng)*ch;
    var loY  =pad.t+(1-((refBand.mean-refBand.std)-minV)/rng)*ch;
    var hiY  =pad.t+(1-((refBand.mean+refBand.std)-minV)/rng)*ch;
    ctx.fillStyle='rgba(250,204,21,0.09)';
    ctx.fillRect(pad.l, Math.min(loY,hiY), cw, Math.abs(hiY-loY));
    ctx.save(); ctx.setLineDash([4,4]);
    ctx.strokeStyle='rgba(250,204,21,0.35)'; ctx.lineWidth=1;
    ctx.beginPath(); ctx.moveTo(pad.l,meanY); ctx.lineTo(pad.l+cw,meanY); ctx.stroke();
    ctx.restore();
    ctx.fillStyle='rgba(250,204,21,0.6)'; ctx.font='8px monospace'; ctx.textAlign='left';
    ctx.fillText('usual: '+refBand.mean.toFixed(1)+'±'+refBand.std.toFixed(1), pad.l+3, meanY-2);
  }
  // Fill + line
  ctx.beginPath();
  points.forEach(function(p,i){
    var x=pad.l+(p[0]-minT)/tRng*cw, y=pad.t+(1-(p[1]-minV)/rng)*ch;
    i===0?ctx.moveTo(x,y):ctx.lineTo(x,y);
  });
  var lx=pad.l+(points[points.length-1][0]-minT)/tRng*cw;
  ctx.lineTo(lx,pad.t+ch); ctx.lineTo(pad.l,pad.t+ch); ctx.closePath();
  ctx.fillStyle=color.replace(/^#/,'').length===6
    ? 'rgba('+parseInt(color.slice(1,3),16)+','+parseInt(color.slice(3,5),16)+','+parseInt(color.slice(5,7),16)+',0.13)'
    : 'rgba(96,165,250,0.13)';
  ctx.fill();
  ctx.beginPath();
  points.forEach(function(p,i){
    var x=pad.l+(p[0]-minT)/tRng*cw, y=pad.t+(1-(p[1]-minV)/rng)*ch;
    i===0?ctx.moveTo(x,y):ctx.lineTo(x,y);
  });
  ctx.strokeStyle=color; ctx.lineWidth=1.5; ctx.lineJoin='round'; ctx.stroke();
}

function _scHistLoad(section) {
  var canvas = section.querySelector('.sc-hc');
  var status = section.querySelector('.sc-hs');
  var metric = section.querySelector('.sc-hm').value;
  var hours  = parseFloat((section.querySelector('.sc-hr.active')||{}).dataset&&section.querySelector('.sc-hr.active').dataset.h||1);
  var site   = section.dataset.site, stream = section.dataset.stream;
  var colorMap = {fm_signal_dbm:'#34d399',fm_snr_db:'#6ee7b7',fm_stereo:'#a7f3d0',fm_rds_ok:'#34d399',dab_snr:'#a78bfa',dab_sig:'#c4b5fd',dab_bitrate:'#818cf8',lufs_m:'#fbbf24',lufs_s:'#fb923c',lufs_i:'#f87171',rtp_jitter_ms:'#e879f9',rtp_loss_pct:'#f472b6',silence_flag:'#64748b',clip_count:'#ef4444'};
  var color  = colorMap[metric] || '#60a5fa';
  status.textContent='Loading…'; status.style.display='block';
  var metricUrl = '/api/metrics/'+encodeURIComponent(site)+'/'+encodeURIComponent(stream)+'?metric='+encodeURIComponent(metric)+'&hours='+hours;
  var trendUrl  = metric==='level_dbfs' ? '/api/trend/'+encodeURIComponent(site)+'/'+encodeURIComponent(stream) : null;
  Promise.all([
    fetch(metricUrl).then(function(r){return r.json();}),
    trendUrl ? fetch(trendUrl).then(function(r){return r.json();}).catch(function(){return null;}) : Promise.resolve(null)
  ]).then(function(res){
    var d=res[0], trend=res[1];
    status.style.display='none';
    var refBand=(trend && trend.baseline && metric==='level_dbfs') ? trend.baseline : null;
    drawMetricChart(canvas, d.points, color, refBand);
  }).catch(function(){status.textContent='Failed to load'; status.style.display='block';});
}

function scHistToggle(btn) {
  var body=btn.nextElementSibling, open=body.style.display==='block';
  body.style.display=open?'none':'block';
  btn.querySelector('span').textContent=open?'▼':'▲';
  if(!open) _scHistLoad(btn.parentElement);
}

document.addEventListener('click',function(e){
  var rb=e.target.closest('.sc-hr');
  if(!rb) return;
  var section=rb.closest('.sc-hist'); if(!section) return;
  section.querySelectorAll('.sc-hr').forEach(function(b){b.classList.remove('active');});
  rb.classList.add('active');
  if(rb.closest('.sc-hist-body').style.display==='block') _scHistLoad(section);
});
document.addEventListener('change',function(e){
  var sel=e.target.closest('.sc-hm');
  if(!sel) return;
  var section=sel.closest('.sc-hist'); if(!section) return;
  if(sel.closest('.sc-hist-body').style.display==='block') _scHistLoad(section);
});
// ── Availability timeline ──────────────────────────────────────────────────────
var _TL_HOURS = [24, 1, 6];
var _TL_COLORS = {ok:'#22c55e', silence:'#ef4444', dab_missing:'#f59e0b', nodata:'#1e2a3a'};
function drawTimeline(canvas, segments) {
  var W = canvas.offsetWidth || 400, H = 16;
  canvas.width = W; canvas.height = H;
  var ctx = canvas.getContext('2d');
  var n = segments.length, sw = W / n;
  segments.forEach(function(seg, i) {
    ctx.fillStyle = _TL_COLORS[seg[1]] || '#1e2a3a';
    ctx.fillRect(Math.floor(i*sw), 0, Math.ceil(sw)+1, H);
  });
  if (segments.length > 1) {
    ctx.fillStyle = 'rgba(255,255,255,0.45)';
    ctx.font = '8px monospace';
    var d0=new Date(segments[0][0]*1000), d1=new Date(segments[segments.length-1][0]*1000);
    ctx.textAlign='left';  ctx.fillText(('0'+d0.getHours()).slice(-2)+':'+('0'+d0.getMinutes()).slice(-2), 2, H-2);
    ctx.textAlign='right'; ctx.fillText(('0'+d1.getHours()).slice(-2)+':'+('0'+d1.getMinutes()).slice(-2), W-2, H-2);
  }
}
function _tlLoad(canvas) {
  var site=canvas.dataset.site, stream=canvas.dataset.stream, hours=canvas.dataset.hours||24;
  var label=canvas.previousElementSibling;
  fetch('/api/timeline/'+encodeURIComponent(site)+'/'+encodeURIComponent(stream)+'?hours='+hours)
    .then(function(r){return r.json();})
    .then(function(d){
      if(label) label.textContent=hours+'h';
      drawTimeline(canvas, d.segments);
    }).catch(function(){});
}
document.addEventListener('click',function(e){
  var c=e.target.closest('canvas.sc-tl'); if(!c) return;
  var cur=parseInt(c.dataset.hours)||24;
  c.dataset.hours=_TL_HOURS[(_TL_HOURS.indexOf(cur)+1)%_TL_HOURS.length];
  _tlLoad(c);
});
setTimeout(function(){ document.querySelectorAll('canvas.sc-tl').forEach(_tlLoad); }, 600);
// ── Trend / pattern indicators ────────────────────────────────────────────────
var _trendCache = {};  // keyed by "site/stream"
function _applyTrend(site, stream, data) {
  var key = site + '/' + stream;
  _trendCache[key] = data;
  document.querySelectorAll('.sc[data-site][data-stream]').forEach(function(sc){
    if(sc.dataset.site !== site || sc.dataset.stream !== stream) return;
    var row = sc.querySelector('.sc-trend-row');
    var val = sc.querySelector('.sc-trend-val');
    if(!row || !val) return;
    var s = data.status, dev = data.deviation, mins = data.sustained_minutes || 0;
    var btype = data.baseline_type === 'dow_hour' ? ' ·dow' : '';
    var durStr = mins >= 2 ? ', ' + mins + ' min' : '';
    if(s === 'lower_than_usual'){
      val.textContent = '📉 Lower than usual (' + (dev>0?'+':'') + dev.toFixed(1) + 'σ' + durStr + btype + ')';
      val.style.color = mins >= 10 ? 'var(--al)' : 'var(--wn)';
      row.style.display = '';
    } else if(s === 'higher_than_usual'){
      val.textContent = '📈 Higher than usual (+' + dev.toFixed(1) + 'σ' + durStr + btype + ')';
      val.style.color = '#60a5fa';
      row.style.display = '';
    } else {
      row.style.display = 'none';
    }
  });
}
function _loadTrends() {
  document.querySelectorAll('.sc[data-site][data-stream]').forEach(function(sc){
    var site=sc.dataset.site, stream=sc.dataset.stream;
    if(!site || !stream) return;
    fetch('/api/trend/'+encodeURIComponent(site)+'/'+encodeURIComponent(stream))
      .then(function(r){return r.json();})
      .then(function(d){ _applyTrend(site, stream, d); })
      .catch(function(){});
  });
}
// Re-apply cached trends after each hubRefresh (survives AJAX card updates)
var _origHubRefresh = hubRefresh;
hubRefresh = function(){
  return _origHubRefresh.apply(this, arguments).then
    ? _origHubRefresh.apply(this, arguments)
    : _origHubRefresh.apply(this, arguments);
};
// Load trends once on page ready, then every 5 minutes
setTimeout(_loadTrends, 1200);
setInterval(_loadTrends, 300000);
// Re-apply cached values immediately after each hubRefresh completes
(function(){
  var orig = hubRefresh;
  hubRefresh = function(){
    var p = orig.apply(this, arguments);
    if(p && p.finally) p.finally(function(){
      Object.keys(_trendCache).forEach(function(k){
        var parts=k.split('/'), site=parts[0], stream=parts.slice(1).join('/');
        _applyTrend(site, stream, _trendCache[k]);
      });
    });
    return p;
  };
})();
</script>
<link rel="icon" type="image/x-icon" href="/static/signalscope_icon.png"></head><body>
{{ topnav("hub") }}
<div class="hub-topbar" style="padding:8px 20px;background:var(--sur);border-bottom:1px solid var(--bor);display:flex;gap:7px;align-items:center">
  <span style="font-size:13px;font-weight:600">🛰 Hub Dashboard</span>
  <span class="badge">{{sites|length}} site{{"s" if sites|length!=1 else ""}}</span>
  <div style="margin-left:auto;display:flex;gap:6px;align-items:center;flex-wrap:wrap">
    <a href="/hub?wall={{'0' if wall_mode else '1'}}{% if problems_only %}&problems=1{% endif %}" class="btn bg bs">{{'🧰 Normal Mode' if wall_mode else '🖥 Wall Mode'}}</a>
    <button type="button" class="btn bg bs" onclick="toggleFullscreen()">⛶ Fullscreen</button>
    <a href="/hub?{% if wall_mode %}wall=1&{% endif %}problems={{'0' if problems_only else '1'}}" class="btn bg bs">{{'Show all sites' if problems_only else 'Show only problem sites'}}</a>
    <a href="/hub/reports" class="btn bp bs">📋 Hub Reports</a>
  </div>
</div>
<main>
  <div class="hub-summary">
    <div id="alertTicker" style="width:100%;margin-top:6px;font-size:12px;color:var(--wn)"></div>
    <span class="sum-pill">🕒 <span id="wallClock">{{fmt(now)}}</span></span>
    <span class="sum-pill">🏗 {{build}}</span>
    <span class="sum-pill">📡 {{sites|length}} site{{"s" if sites|length!=1 else ""}}</span>
    <span class="sum-pill" style="color:var(--al)">⛔ {{offline_count}} offline</span>
    <span class="sum-pill" style="color:var(--al)">🚨 {{alert_site_count}} alert</span>
    <span class="sum-pill" style="color:var(--wn)">⚠ {{warn_site_count}} warn</span>
    <span class="sum-pill" style="color:var(--acc)">⏳ {{stale_count}} stale</span>
    {%- if hub_cpu is not none %}<span class="sum-pill" style="color:var(--mu)">🖥 CPU {{hub_cpu}}%</span>{% endif %}
    {%- if hub_mem is not none %}<span class="sum-pill" style="color:var(--mu)">💾 RAM {{hub_mem}}%</span>{% endif %}
  </div>

  <div class="hub-toolbar">
    <input id="hubSearch" class="search" type="text" placeholder="Search sites, streams, FM, DAB, alerts…">
    <span class="badge">Drag site cards to reorder</span>
  </div>
{% if not sites %}
  <div class="no-sites">
    <div style="font-size:48px;margin-bottom:12px">📡</div>
    <div style="font-size:18px;font-weight:600;margin-bottom:8px">Waiting for sites</div>
    <div>No heartbeats received yet. Configure each site to point to this hub and enable hub reporting in their Settings.</div>
  </div>
{% else %}
<div class="site-grid" id="site-grid">
{% for site in sites %}
{% set st = site.site_status %}
{% set _pending = not site.get('_approved', True) %}
<div class="site-card site-{{'ok' if st=='OK' else 'warn' if st=='WARN' else 'alert' if st=='ALERT' else 'offline'}} skeleton" draggable="true" id="site-{{site.site|replace(' ','_')|replace('.','_')|replace('-','_')}}">
  {% if _pending %}
  {% set _nu = site.get('_needs_update', False) %}
  <div style="padding:10px 16px;background:{{'#2a1a00' if _nu else '#1a2a10'}};border-bottom:2px solid var(--wn);display:flex;align-items:center;gap:10px;flex-wrap:wrap">
    {% if _nu %}
    <span style="color:#fb923c;font-weight:700;font-size:13px">⚠ Update Required</span>
    <span style="font-size:12px;color:var(--mu)">
      <strong>{{site.site}}</strong> (build: {{site.get('build') or 'unknown'}}) is running a version that predates the hub approval system.
      Update this site to SignalScope 3.0.3 or later, then reconnect and approve it here.
    </span>
    <button class="btn bd bs" data-action="hub-remove-site" data-site="{{site.site|e}}" style="margin-left:auto">✕ Dismiss</button>
    {% else %}
    <span style="color:#fde68a;font-weight:700;font-size:13px">⏳ Pending Approval</span>
    <span style="font-size:12px;color:var(--mu)">{{site.site}} is requesting to connect from {{site.get('_client_addr') or site.get('_verified_ip','unknown')}}</span>
    <button class="btn" style="background:#166534;color:#fff;font-size:12px;padding:3px 12px;margin-left:auto"
            data-action="hub-approve-site" data-site="{{site.site|e}}">✓ Approve</button>
    <button class="btn bd bs" data-action="hub-remove-site" data-site="{{site.site|e}}">✕ Reject</button>
    {% endif %}
  </div>
  {% endif %}
  <div class="site-header">
    <span class="dot {{'dot-ok' if st=='OK' else 'dot-wn' if st=='WARN' else 'dot-al' if st=='ALERT' else 'dot-off'}}"></span>
    <span class="site-name">{{site.site}}</span>
    {% if _pending %}
      <span class="badge" style="background:#3a3010;color:#fde68a">PENDING</span>
    {% elif site.online %}
      <span class="badge" style="background:{{'#1e3a5f' if st=='OK' else '#3a2a0f' if st=='WARN' else '#3a0f0f'}}">
        {{st}}
      </span>
      {% if site.running %}
      <span class="badge" style="background:#1e2a1e">▶ Running</span>
      <button class="btn sc-cmd-btn" data-site="{{site.site|e}}" data-cmd="stop" style="background:#3a1e1e;color:#fca5a5;font-size:10px;padding:2px 8px">⏹ Stop</button>
      {% else %}
      <span class="badge" style="background:#2a2a1e;color:var(--mu)">⏸ Stopped</span>
      <button class="btn sc-cmd-btn" data-site="{{site.site|e}}" data-cmd="start" style="background:#1e3a1e;color:#86efac;font-size:10px;padding:2px 8px">▶ Start</button>
      {% endif %}
      {% if site.build %}
      <span class="badge site-version-badge" style="background:{{' #1e2433' if site.build==build else '#3a2a0f'}};font-size:10px"
            title="{{'Version match' if site.build==build else 'Version mismatch — hub is '+build}}">{{site.build}}</span>
      {% endif %}
    {% else %}
      <span class="badge" style="background:#2a1e1e;color:var(--al)">OFFLINE</span>
    {% endif %}
    <span class="site-meta">Last seen: {{ago(site.age_s)}}</span>
    {% if site.latency_ms is not none %}<span class="site-meta site-meta-latency" title="Heartbeat latency">Latency: {{site.latency_ms}} ms</span>{% endif %}
    {% if not _pending %}<a class="btn bg bs" href="/hub/site/{{site.site|urlencode}}/open">Open Dashboard</a>{% endif %}
    <button class="btn bd bs" data-action="hub-remove-site" data-site="{{site.site|e}}">✕ Remove</button>
    {% if site.health_pct is defined %}
    <span class="site-meta" style="margin-left:8px;color:{{'var(--ok)' if site.health_pct>=99 else ('var(--wn)' if site.health_pct>=95 else 'var(--al)')}}" title="Heartbeat reliability">⚡ {{site.health_pct}}%</span>
    {% endif %}
    {% if site.consecutive_missed > 0 %}
    <span class="site-meta" style="color:var(--wn);margin-left:4px" title="Consecutive missed heartbeats">⚠ {{site.consecutive_missed}} missed</span>
    {% endif %}
    {% if site.online and site.age_s >= (60 if site.low_bw else 10) %}
    <span class="badge" style="background:#2a2412;color:var(--wn)">STALE</span>
    {% endif %}
    {% if site.low_bw %}
    <span class="badge site-lowbw-badge" title="Low-bandwidth mode — heartbeat every 30 s, clips on demand" style="background:#1a2a1a;color:#6ee7b7;border:1px solid #166534">📶 Low BW</span>
    {% endif %}
  </div>
  {% if not _pending %}
  <div style="padding:8px 16px;border-bottom:1px solid var(--bor);display:flex;gap:8px;flex-wrap:wrap;align-items:center;background:linear-gradient(180deg,#12305c,#10284f)">
    <span class="sum-pill" style="padding:4px 8px">🎚 {{site.streams|length}} streams</span>
    <span class="sum-pill" style="padding:4px 8px;color:var(--al)">🚨 {{site.alert_count}} alert</span>
    <span class="sum-pill" style="padding:4px 8px;color:var(--wn)">⚠ {{site.warn_count}} warn</span>
    <span class="sum-pill" style="padding:4px 8px;color:var(--ok)">✅ {{site.ok_count}} ok</span>
    <button class="btn bg bs sc-expand-all-btn" style="margin-left:auto;font-size:11px;padding:3px 10px"
            data-action="sc-expand-all" data-site-id="site-{{site.site|replace(' ','_')|replace('.','_')|replace('-','_')}}">⊞ Expand All</button>
  </div>

  {% if not site.online %}
    <div class="offline-banner">⚠ No heartbeat received for {{site.age_s}}s — site may be down</div>
  {% else %}
    <div class="streams">
    {% for s in site.streams %}
    {% set i = loop.index0 %}
    {% set ai = s.ai_status or 'Idle' %}
    {% set lev = s.level_dbfs %}
    {% set lpct = [(lev+80)/80*100, 100]|min|int %}
    {% set lcol = 'var(--al)' if lev<=-55 else ('var(--wn)' if lev<=-20 else 'var(--ok)') %}
    {% set ai  = s.ai_status or '' %}
    {% set ph  = s.ai_phase  or '' %}
    {% set dc  = 'dok' %}
    {% if '[ALERT]' in ai %}{% set dc='dal' %}{% elif '[WARN]' in ai %}{% set dc='dwn' %}{% elif ph=='learning' %}{% set dc='dlr' %}{% endif %}
    <div class="sc {{'stats-alert' if '[ALERT]' in ai else ('stats-warn' if '[WARN]' in ai else '')}}" data-idx="{{i}}" data-site="{{site.site|e}}" data-stream="{{s.name|e}}">

      {# Header #}
      <div class="sc-name">
        <span class="dot {{dc}}"></span>
        <strong>{{s.name}}</strong>
        <span class="sc-dev">{{s.device_index or ''}}</span>
        <button class="sc-expand-btn" data-action="sc-expand" data-sc-key="{{site.site|replace(' ','_')|replace('.','_')|replace('-','_')}}__{{i}}" title="Expand / Collapse">&#9662;</button>
      </div>

      {# Level bar #}
      <div class="lbar-wrap" style="padding:4px 10px" data-rms="{{lev}}" data-peak="{{s.get('peak_dbfs', lev)}}">
        <span class="sc-lbar-label" style="font-size:11px;color:var(--acc);width:28px;cursor:pointer;user-select:none" title="Click to toggle RMS / Peak">RMS</span>
        <div class="lbar-track"><div class="lbar-fill sc-lbar" style="width:{{lpct}}%;background:{{lcol}}"></div></div>
        <span class="sc-level lbar-val" style="color:{{lcol}}">{{lev}} dB</span>
      </div>
      <div class="sc-tl-wrap" style="display:flex;align-items:center;gap:5px;padding:0 10px 4px">
        <span style="font-size:9px;color:var(--mu);width:28px;flex-shrink:0">24h</span>
        <canvas class="sc-tl" data-site="{{site.site|e}}" data-stream="{{s.name|e}}" data-hours="24"
                height="16" style="flex:1;height:16px;border-radius:2px;cursor:pointer"
                title="24h availability — click to cycle 1h/6h/24h"></canvas>
        <span style="font-size:9px;color:var(--mu);white-space:nowrap">
          <span style="color:#22c55e">■</span> <span style="color:#ef4444">■</span> <span style="color:#f59e0b">■</span> <span style="color:#374151">■</span>
        </span>
      </div>

      {# Collapsible detail #}
      <div class="sc-detail" id="sc_detail_{{site.site|replace(' ','_')|replace('.','_')|replace('-','_')}}__{{i}}">

      {# Info rows #}
      <div style="padding:0 10px 4px">
        <div class="sc-row">Format <span class="sc-fmt" style="font-size:11px;color:var(--mu)">{{s.format or '—'}}</span></div>
        <div class="sc-row sc-trend-row" style="display:none">Trend <span class="sc-trend-val" style="font-size:11px"></span></div>
        {% set _edev = (s.device_index or '').lower() %}
        {% if not (_edev.startswith('dab://') or _edev.startswith('fm://') or _edev.startswith('http://') or _edev.startswith('https://')) %}
        <div class="sc-row">RTP Loss
          <span class="sc-rtp {{rtpClass(s.rtp_loss_pct)}}">{{s.rtp_loss_pct}}%
            <span style="color:var(--mu);font-size:11px"> {{s.rtp_total or 0}} pkts</span>
          </span>
        </div>
        {% endif %}
        {% if s.sla_pct is not none %}
        <div class="sc-row">SLA <span class="sc-sla" style="color:{{'var(--ok)' if s.sla_pct>=99 else 'var(--wn)'}}">{{s.sla_pct}}%</span></div>
        {% endif %}
        <div class="sc-row">Alerts
          <span style="font-size:12px">
            {%if s.alert_on_silence%}<span class="alert-badge badge-silence" title="Silence">SIL</span>{%endif%}
            {%if s.alert_on_hiss%}<span class="alert-badge badge-hiss" title="Hiss">HISS</span>{%endif%}
            {%if s.alert_on_clip%}<span class="alert-badge badge-clip" title="Clip">CLIP</span>{%endif%}
            {%if s.ai_monitor%}<span class="alert-badge badge-ai" title="AI">AI</span>{%endif%}
          </span>
        </div>
        {% if s.device_index and s.device_index.lower().startswith('dab://') %}
        <details class="stats-block">
          <summary class="stats-toggle">DAB stats <span>▼</span></summary>
          <div class="sc-row">SNR <span style="color:{{'var(--ok)' if s.dab_snr>=12 else 'var(--wn)' if s.dab_snr>=6 else 'var(--al)'}}">{{s.dab_snr}} dB</span></div>
          <div class="sc-row">Signal  <span>
            {% set db = s.dab_sig|default(-120) %}
            {% set bars = 0 %}
            {% if db >= -55 %}{% set bars = 5 %}
            {% elif db >= -65 %}{% set bars = 4 %}
            {% elif db >= -75 %}{% set bars = 3 %}
            {% elif db >= -85 %}{% set bars = 2 %}
            {% elif db >= -95 %}{% set bars = 1 %}
            {% endif %}
            📶{{"▮"*bars}}{{"▯"*(5-bars)}} {{s.dab_sig}} dBm
          </span></div>
          <div class="sc-row">Ensemble <span style="font-size:11px">{{s.dab_ensemble or '—'}}</span></div>
          <div class="sc-row">Service <span style="font-size:11px;display:flex;align-items:center;gap:5px">
            <span>{{s.dab_service or '—'}}</span>
            {% if s.dab_service and s.expected_dab_service %}
              {% if s.expected_dab_service.lower() == s.dab_service.lower() %}
                <span style="color:var(--ok);font-size:10px" title="Expected: {{s.expected_dab_service}}">✓</span>
              {% else %}
                <span style="color:var(--al);font-size:10px" title="Expected: {{s.expected_dab_service}}">⚠ {{s.expected_dab_service}}</span>
              {% endif %}
            {% endif %}
          </span></div>
          <div class="sc-row">Mode <span style="font-size:11px">{{s.dab_mode or '—'}}</span></div>
          <div class="sc-row">Bitrate <span>{% if s.dab_bitrate %}{{s.dab_bitrate}} kbps{% else %}—{% endif %}</span></div>
          <div class="sc-row">Audio <span style="color:{{'var(--ok)' if s.dab_stereo else 'var(--mu)'}}">{% if s.dab_stereo %}Stereo{% else %}Mono{% endif %}</span></div>
          {% if s.dab_dls %}
          <div class="sc-row sc-rt-row" style="align-items:center">DLS
            <span class="rds-rt-wrap sc-rt-wrap" style="font-size:11px;color:var(--mu)" title="{{s.dab_dls}}">
              {% if s.dab_dls|length > 28 %}<span class="rds-rt-scroll sc-rt-text"><span>🎵 {{s.dab_dls}}</span><span aria-hidden="true">🎵 {{s.dab_dls}}</span></span>
              {% else %}<span class="rds-rt-static sc-rt-text">🎵 {{s.dab_dls}}</span>{% endif %}
            </span>
          </div>
          {% endif %}
        </details>
        {% endif %}
        {% if s.device_index and s.device_index.lower().startswith('fm://') %}
        <details class="stats-block">
          <summary class="stats-toggle">FM / RDS stats <span>▼</span></summary>
          <div class="sc-row">Signal  <span>
            {% set db = s.fm_signal_dbm|default(-120) %}
            {% set bars = 0 %}
            {% if db >= -55 %}{% set bars = 5 %}
            {% elif db >= -65 %}{% set bars = 4 %}
            {% elif db >= -75 %}{% set bars = 3 %}
            {% elif db >= -85 %}{% set bars = 2 %}
            {% elif db >= -95 %}{% set bars = 1 %}
            {% endif %}
            📶{{"▮"*bars}}{{"▯"*(5-bars)}} {{s.fm_signal_dbm}} dBFS
          </span></div>
          <div class="sc-row">Pilot <span style="color:{{'var(--ok)' if s.fm_snr_db>=12 else 'var(--wn)' if s.fm_snr_db>=6 else 'var(--al)'}}">{{s.fm_snr_db}} dB</span></div>
          <div class="sc-row">Audio <span>{% if s.fm_stereo %}🔊 Stereo{% else %}🔈 Mono{% endif %}</span></div>
          <div class="sc-row">RDS <span style="color:{{'var(--ok)' if s.fm_rds_ok else 'var(--mu)'}};display:flex;align-items:center;gap:5px">
            {% if s.fm_rds_ok %}
              <span>📡 {{s.fm_rds_ps or 'Locked'}}</span>
              {% if s.fm_rds_ps and s.expected_fm_rds_ps %}
                {% if s.expected_fm_rds_ps == s.fm_rds_ps %}
                  <span style="color:var(--ok);font-size:10px" title="Expected: {{s.expected_fm_rds_ps}}">✓</span>
                {% else %}
                  <span style="color:var(--al);font-size:10px" title="Expected: {{s.expected_fm_rds_ps}}">⚠ {{s.expected_fm_rds_ps}}</span>
                {% endif %}
              {% endif %}
            {% else %}<span>— No RDS</span>{% endif %}
          </span></div>
          {% set rt_text = s.fm_rds_rt or s.dab_dls or '' %}
          <div class="sc-row sc-rt-row" {% if not rt_text %}style="display:none"{% endif %}>Text
            <span class="rds-rt-wrap sc-rt-wrap" style="font-size:11px" title="{{rt_text}}">
              {% if rt_text|length > 40 %}
              <span class="rds-rt-scroll sc-rt-text">
                <span>🎵 {{rt_text}}</span>
                <span aria-hidden="true">🎵 {{rt_text}}</span>
              </span>
              {% else %}
              <span class="rds-rt-static sc-rt-text">{% if rt_text %}🎵 {{rt_text}}{% else %}—{% endif %}</span>
              {% endif %}
            </span>
          </div>
        </details>
        {% endif %}
      </div>

      {# AI status bar #}
      {% if s.ai_monitor %}
      {% set ac = 'alr' if ph=='learning' else ('aal' if '[ALERT]' in ai else ('awn' if '[WARN]' in ai else ('aok' if '[OK]' in ai else 'aid'))) %}
      <div class="aib {{ac}} sc-ai">🤖 {{ai if ai else ('Waiting…' if site.running else 'Not running')}}</div>
      {% if ph=='learning' and s.ai_learn_start %}
        {% set pct = [(now - s.ai_learn_start) / site.learn_dur * 100, 100]|min|int %}
        <div class="pb"><div class="pbi" style="width:{{pct}}%"></div></div>
      {% endif %}
      {% endif %}

      {# Now Playing — fetched from remote site's API via hub proxy #}
      {% if s.nowplaying_station_id %}
      <div class="np-strip" id="np_{{loop.index0}}_{{i}}">
        <img class="np-art" id="npa_{{loop.index0}}_{{i}}" src="" alt="" style="display:none">
        <div class="np-text">
          <div class="np-title" id="npt_{{loop.index0}}_{{i}}">Loading…</div>
          <div class="np-sub"   id="npar_{{loop.index0}}_{{i}}"></div>
          <div class="np-sub"   id="nps_{{loop.index0}}_{{i}}" style="color:var(--acc)"></div>
        </div>
      </div>
      <script nonce="{{csp_nonce()}}">(function(){
        var sid='{{loop.index0}}',si='{{i}}',rpuid='{{s.nowplaying_station_id}}';
        function fnp(){fetch('/api/nowplaying/'+rpuid).then(r=>r.json()).then(function(d){
          document.getElementById('npt_'+sid+'_'+si).textContent=d.title||'—';
          document.getElementById('npar_'+sid+'_'+si).textContent=d.artist||'';
          document.getElementById('nps_'+sid+'_'+si).textContent=d.show||'';
          var a=document.getElementById('npa_'+sid+'_'+si);
          if(d.artwork){a.src='/api/nowplaying_art/'+encodeURIComponent(rpuid)+'?ts='+Date.now();a.style.display='block';} else { a.removeAttribute('src'); a.style.display='none'; }
        }).catch(()=>{});}
        fnp();setInterval(fnp,30000);
      })();</script>
      {% endif %}

      {# Listen / Clip strip #}
      <div class="listen-strip">
        <select id="hdur_{{loop.index0}}_{{i}}" style="padding:3px 5px;font-size:11px;background:#173a69;border:1px solid var(--bor);border-radius:4px;color:var(--tx)">
          <option value="5">5s</option><option value="10" selected>10s</option>
          <option value="20">20s</option><option value="30">30s</option>
        </select>
        {% set ci = s._client_idx if s._client_idx is not none else i %}
        <a class="btn bg bs" href="/hub/site/{{site.site|urlencode}}/stream/{{ci}}/clip?seconds=10" download>⬇ Clip</a>
        <button class="btn bp bs" data-sidx="{{loop.index0}}" data-site="{{ci}}" data-action="live"
          data-url="/hub/site/{{site.site|urlencode}}/stream/{{ci}}/live"
          data-name="{{s.name}}" data-site-name="{{site.site}}">▶ Live</button>
      </div>

      {# Clip count badge #}
      {% if s.clip_count %}
      <div style="padding:4px 10px;font-size:11px;color:var(--mu);border-top:1px solid var(--bor)">
        💾 {{s.clip_count}} saved clip{{"s" if s.clip_count!=1 else ""}} on site
        <a href="/hub/reports?site={{site.site|urlencode}}&stream={{s.name|urlencode}}" style="color:var(--acc);margin-left:6px">View in reports →</a>
      </div>
      {% endif %}

      {# Recent events #}
      {% if s.history %}
      <div class="hist-wrap">
        <button class="hist-toggle" onclick="this.nextElementSibling.style.display=this.nextElementSibling.style.display?'':'block'">
          📋 Recent Events ({{s.history|length}})
        </button>
        <div style="display:none">
          {% for ev in s.history|reverse %}
          <div class="hev h{{ev.type|lower}}">
            <span style="color:var(--mu)">{{ev.ts[-8:] if ev.ts else ''}}</span>
            <span style="margin:0 4px;opacity:.5">[{{ev.type}}]</span>
            {{ev.message[:90] if ev.message else ''}}
          </div>
          {% endfor %}
        </div>
      </div>
      {% endif %}
      <!-- Signal History chart -->
      {% set _sdev = (s.device_index or '').lower() %}
      <div class="sc-hist" data-site="{{site.site|e}}" data-stream="{{s.name|e}}">
        <button class="hist-toggle" onclick="scHistToggle(this)">📈 Signal History <span>▼</span></button>
        <div class="sc-hist-body" style="display:none">
          <div style="display:flex;gap:4px;padding:6px 10px 2px;flex-wrap:wrap;align-items:center">
            <span style="font-size:10px;color:var(--mu)">Range:</span>
            <button class="btn sc-hr active" data-h="1" style="font-size:10px;padding:1px 7px">1h</button>
            <button class="btn sc-hr" data-h="6" style="font-size:10px;padding:1px 7px">6h</button>
            <button class="btn sc-hr" data-h="24" style="font-size:10px;padding:1px 7px">24h</button>
            <select class="sc-hm" style="margin-left:8px;font-size:11px;background:#0d1117;border:1px solid var(--bor);border-radius:4px;color:var(--tx);padding:2px 4px">
              <option value="level_dbfs">Level dBFS</option>
              <option value="silence_flag">Silence Flag</option>
              <option value="clip_count">Clip Count</option>
              {%if _sdev.startswith('fm://')%}<option value="fm_signal_dbm">FM Signal dBm</option>{%endif%}
              {%if _sdev.startswith('fm://')%}<option value="fm_snr_db">FM SNR dB</option>{%endif%}
              {%if _sdev.startswith('fm://')%}<option value="fm_stereo">FM Stereo</option>{%endif%}
              {%if _sdev.startswith('fm://')%}<option value="fm_rds_ok">FM RDS Lock</option>{%endif%}
              {%if _sdev.startswith('dab://')%}<option value="dab_snr">DAB SNR dB</option>{%endif%}
              {%if _sdev.startswith('dab://')%}<option value="dab_sig">DAB Signal dBm</option>{%endif%}
              {%if _sdev.startswith('dab://')%}<option value="dab_bitrate">DAB Bitrate kbps</option>{%endif%}
              <option value="lufs_m">LUFS Momentary</option>
              <option value="lufs_s">LUFS Short-term</option>
              <option value="lufs_i">LUFS Integrated</option>
              {%if not _sdev.startswith('fm://') and not _sdev.startswith('dab://') and not _sdev.startswith('http')%}
              <option value="rtp_jitter_ms">RTP Jitter ms</option>
              <option value="rtp_loss_pct">RTP Loss %</option>
              {%endif%}
            </select>
          </div>
          <canvas class="sc-hc" height="110" style="display:block;width:100%;height:110px"></canvas>
          <div class="sc-hs" style="display:none;font-size:11px;color:var(--mu);text-align:center;padding:4px 0 6px"></div>
        </div>
      </div>

      </div>{# /sc-detail #}
    </div>
    {% else %}
    <div style="padding:20px;text-align:center;color:var(--mu);font-size:13px">
      {% if not site.running %}
      ⏸ Monitoring not started on this site
      {% else %}
      No inputs configured on this site
      {% endif %}
    </div>
    {% endfor %}
    </div>


    {# Comparators #}
    {% if site.comparators %}
    <div style="padding:10px 16px 14px;border-top:1px solid var(--bor)">
      <div style="font-size:11px;color:var(--mu);margin-bottom:8px;font-weight:600;letter-spacing:.04em">🔀 STREAM COMPARATORS</div>
      {% for c in site.comparators %}
      {% set c_ok   = c.status.startswith('OK') %}
      {% set c_find = c.status.startswith('Find') %}
      {% set c_col  = 'var(--ok)' if c_ok else ('var(--mu)' if c_find else 'var(--al)') %}
      <div style="background:#123764;border:1px solid var(--bor);border-left:3px solid {{c_col}};border-radius:10px;overflow:hidden;margin-bottom:8px;font-size:12px;box-shadow:0 2px 8px rgba(0,0,0,.12)">
        {# Header row #}
        <div style="padding:8px 12px;border-bottom:1px solid var(--bor);display:flex;align-items:center;gap:8px">
          <span style="width:8px;height:8px;border-radius:999px;background:{{c_col}};flex-shrink:0;display:inline-block"></span>
          <strong style="color:var(--tx)">{{c.pre_name}}</strong>
          <span style="color:var(--mu);font-size:11px">→</span>
          <strong style="color:var(--tx)">{{c.post_name}}</strong>
          <span style="margin-left:auto;font-size:11px;color:{{c_col}};white-space:nowrap">{{c.status}}</span>
        </div>
        {# Stats grid #}
        <div style="padding:8px 12px">
          <div style="display:grid;grid-template-columns:1fr 1fr;gap:4px 16px;color:var(--mu)">
            <span>Pre level <span style="color:var(--tx)">{{c.pre_dbfs}} dBFS</span></span>
            <span>Post level <span style="color:var(--tx)">{{c.post_dbfs}} dBFS</span></span>
            <span>Gain diff <span style="color:{{'#fb923c' if c.gain_diff_db|abs > c.gain_alert_db else 'var(--tx)'}}">{{'+' if c.gain_diff_db>=0 else ''}}{{c.gain_diff_db}} dB</span></span>
            <span>Delay <span style="color:var(--tx)">{{c.delay_ms}} ms</span></span>
          </div>
          {# Correlation bar — uses processed-aware thresholds so a healthy
             processed path shows green, not misleading orange #}
          {% if c.aligned %}
          <div style="display:flex;align-items:center;gap:8px;margin-top:8px">
            <span style="font-size:11px;color:var(--mu);flex-shrink:0">Correlation</span>
            {% set cc = c.correlation %}
            {% set cw = (cc * 100)|int %}
            {% if c.processed %}
              {% set ccol = 'var(--ok)' if cc>=0.75 else ('var(--ok)' if cc>=0.50 else ('var(--wn)' if cc>=0.30 else 'var(--al)')) %}
            {% else %}
              {% set ccol = 'var(--ok)' if cc>=0.85 else ('var(--ok)' if cc>=0.65 else ('var(--wn)' if cc>=0.40 else 'var(--al)')) %}
            {% endif %}
            <div style="flex:1;max-width:120px;background:var(--bor);border-radius:4px;height:7px">
              <div style="width:{{cw}}%;height:7px;border-radius:4px;background:{{ccol}}"></div>
            </div>
            <span style="color:{{ccol}};font-weight:600;min-width:32px">{{(cc*100)|round(0)|int}}%</span>
          </div>
          {% endif %}
          {# Event history #}
          {% if c.cmp_history %}
          <div style="margin-top:8px;padding-top:6px;border-top:1px solid var(--bor);font-size:11px;color:var(--mu)">
            {% for ev in c.cmp_history|reverse %}
            <div style="padding:1px 0">{{ev}}</div>
            {% endfor %}
          </div>
          {% endif %}
        </div>
      </div>
      {% endfor %}
    </div>
    {% endif %}

    {# PTP bar #}
    {% set ptp = site.ptp %}
    {% set ptp_col = 'var(--ok)' if ptp.state=='ok' else ('var(--al)' if ptp.state in ('alert','lost') else 'var(--wn)') %}
    <div class="ptp-bar">
      <span style="color:var(--mu)">🕐 PTP:</span>
      <span>State <span style="color:{{ptp_col}}">{{ptp.state}}</span>{% if not ptp.pmc_mode %}<span style="color:var(--mu);font-size:10px"> passive</span>{% endif %}</span>
      <span>{{'Offset' if ptp.pmc_mode else 'Offset~'}} <span title="{{'Accurate offset from ptp4l via pmc' if ptp.pmc_mode else 'Passive estimate — includes uncompensated path delay'}}">{{(ptp.offset_us/1000)|round(1)}} ms</span></span>
      <span>Drift <span style="color:{{'var(--ok)' if ptp.drift_us|abs < 1000 else ptp_col}}">{{(ptp.drift_us/1000)|round(1)}} ms</span></span>
      <span>Jitter <span>{{(ptp.jitter_us/1000)|round(1)}} ms</span></span>
      {% if ptp.pmc_mode and ptp.path_delay_us %}<span>Path delay <span>{{(ptp.path_delay_us/1000)|round(1)}} ms</span></span>{% endif %}
      <span>GM <span style="font-size:11px">{{ptp.gm_id or '—'}}</span></span>
      <span>Last sync <span>{{fmt(ptp.last_sync)}}</span></span>
    </div>
  {% endif %}
  {% endif %}{# end if not _pending #}
</div>
{% endfor %}
</div>
{% endif %}
</main><footer style="padding:14px 20px;text-align:center;font-size:11px;color:var(--mu);border-top:1px solid var(--bor);background:rgba(6,18,34,.86)">SignalScope {{build if build is defined else ""}} • Broadcast Signal Intelligence • <a href="/privacy" style="color:inherit;text-decoration:none;opacity:.7">Privacy Policy</a></footer></body></html>"""

# ─── Error handlers ──────────────────────────────────────────────────────────

@app.errorhandler(404)
def _err_404(e):
    if request.path.startswith("/api/"):
        return jsonify({"error": "Not found"}), 404
    _safe_path = request.path.replace("&", "&amp;").replace("<", "&lt;").replace(">", "&gt;").replace('"', "&quot;")
    return f"<html><body style='font-family:sans-serif;background:#06121e;color:#e2e8f0;padding:40px'>" \
           f"<h2>404 — Page not found</h2><p>{_safe_path}</p>" \
           f"<a href='/' style='color:#17a8ff'>← Dashboard</a></body></html>", 404

@app.errorhandler(500)
def _err_500(e):
    monitor.log(f"[HTTP 500] {request.method} {request.path} — {e}")
    if request.path.startswith("/api/"):
        return jsonify({"error": "Internal server error"}), 500
    return f"<html><body style='font-family:sans-serif;background:#06121e;color:#e2e8f0;padding:40px'>" \
           f"<h2>500 — Internal server error</h2><p>An internal error occurred.</p>" \
           f"<a href='/' style='color:#17a8ff'>← Dashboard</a></body></html>", 500

# ─── Hub site names (for user form checkboxes) ────────────────────────────────

@app.get("/api/hub/site_names")
@login_required
@admin_required
def api_hub_site_names():
    """Return sorted list of known site names for the user-form site-access checkboxes."""
    if hub_server is None:
        return jsonify({"sites": []})
    sites = sorted(s["site"] for s in hub_server.get_sites()
                   if s.get("site"))
    return jsonify({"sites": sites})

# ─── User Management API (admin only) ─────────────────────────────────────────

@app.get("/api/users")
@login_required
@admin_required
def api_users_list():
    """List all user accounts (admin only). Password hashes are omitted."""
    if not user_manager:
        return jsonify({"error": "User manager not available"}), 503
    users = [
        {"username": u.username, "role": u.role, "sites": u.sites,
         "plugins": u.plugins, "enabled": u.enabled, "first_login": u.first_login}
        for u in user_manager.all()
    ]
    return jsonify({"users": users})


@app.post("/api/users")
@login_required
@admin_required
@csrf_protect
def api_users_create():
    """Create a new user account (admin only)."""
    import re as _re
    if not user_manager:
        return jsonify({"error": "User manager not available"}), 503
    body     = request.get_json(force=True) or {}
    username = str(body.get("username", "")).strip()
    password = str(body.get("password", "")).strip()
    role     = str(body.get("role", "viewer")).strip()
    sites    = [s.strip() for s in body.get("sites", []) if str(s).strip()]
    plugins  = [p.strip() for p in body.get("plugins", []) if str(p).strip()]
    enabled  = bool(body.get("enabled", True))

    if not username or not _re.match(r"^[\w\-\.@]+$", username):
        return jsonify({"error": "Invalid username (letters, numbers, -_.@ only)"}), 400
    if len(username) > 64:
        return jsonify({"error": "Username too long (max 64 chars)"}), 400
    if role not in ("admin", "operator", "viewer"):
        return jsonify({"error": "Invalid role"}), 400
    if user_manager.get(username):
        return jsonify({"error": "Username already exists"}), 409
    if not password:
        # Create account with first_login = True (user sets password on first login)
        ua = UserAccount(username=username, password_hash="", role=role,
                         sites=sites, plugins=plugins, enabled=enabled, first_login=True)
    else:
        if len(password) < 8:
            return jsonify({"error": "Password must be at least 8 characters"}), 400
        ua = UserAccount(username=username, password_hash=_hash_password(password),
                         role=role, sites=sites, plugins=plugins,
                         enabled=enabled, first_login=False)
    user_manager.add_or_update(ua)
    _log_security(f"User '{username}' created (role={role}) by '{session.get('username','?')}'")
    return jsonify({"ok": True, "username": username})


@app.put("/api/users/<username>")
@login_required
@admin_required
@csrf_protect
def api_users_update(username):
    """Update an existing user account (admin only)."""
    if not user_manager:
        return jsonify({"error": "User manager not available"}), 503
    ua = user_manager.get(username)
    if not ua:
        return jsonify({"error": "User not found"}), 404

    body    = request.get_json(force=True) or {}
    new_role    = str(body.get("role",    ua.role)).strip()
    new_sites   = [s.strip() for s in body.get("sites",   ua.sites)   if str(s).strip()]
    new_plugins = [p.strip() for p in body.get("plugins", ua.plugins) if str(p).strip()]
    new_enabled = bool(body.get("enabled", ua.enabled))
    new_pw      = str(body.get("password", "")).strip()

    if new_role not in ("admin", "operator", "viewer"):
        return jsonify({"error": "Invalid role"}), 400

    # Prevent removing the last admin
    if ua.role == "admin" and new_role != "admin":
        if user_manager.count_admins() <= 1:
            return jsonify({"error": "Cannot demote the only admin account"}), 400

    ua.role    = new_role
    ua.sites   = new_sites
    ua.plugins = new_plugins
    ua.enabled = new_enabled

    if new_pw:
        if len(new_pw) < 8:
            return jsonify({"error": "Password must be at least 8 characters"}), 400
        ua.password_hash = _hash_password(new_pw)
        ua.first_login   = False

    user_manager.add_or_update(ua)
    _log_security(f"User '{username}' updated by '{session.get('username','?')}'")
    return jsonify({"ok": True})


@app.delete("/api/users/<username>")
@login_required
@admin_required
@csrf_protect
def api_users_delete(username):
    """Delete a user account (admin only). Cannot delete yourself or the last admin."""
    if not user_manager:
        return jsonify({"error": "User manager not available"}), 503
    if username == session.get("username"):
        return jsonify({"error": "Cannot delete your own account"}), 400
    ua = user_manager.get(username)
    if not ua:
        return jsonify({"error": "User not found"}), 404
    if ua.role == "admin" and user_manager.count_admins() <= 1:
        return jsonify({"error": "Cannot delete the only admin account"}), 400
    user_manager.delete(username)
    _log_security(f"User '{username}' deleted by '{session.get('username','?')}'")
    return jsonify({"ok": True})


@app.post("/api/users/me/password")
@login_required
@csrf_protect
def api_users_me_password():
    """Allow any user to change their own password."""
    if not user_manager:
        return jsonify({"error": "User manager not available"}), 503
    uname = session.get("username", "")
    ua    = user_manager.get(uname)
    if not ua:
        return jsonify({"error": "User not found"}), 404

    body    = request.get_json(force=True) or {}
    current = str(body.get("current_password", "")).strip()
    new_pw  = str(body.get("new_password", "")).strip()

    # Require current password unless this is a first_login password set
    if not ua.first_login:
        if not current or not _check_password(current, ua.password_hash):
            return jsonify({"error": "Current password is incorrect"}), 403
    if len(new_pw) < 8:
        return jsonify({"error": "Password must be at least 8 characters"}), 400

    ua.password_hash = _hash_password(new_pw)
    ua.first_login   = False
    user_manager.add_or_update(ua)
    # Update session so the user doesn't get logged out
    session["role"]            = ua.role
    session["allowed_sites"]   = ua.sites
    session["allowed_plugins"] = ua.plugins
    _log_security(f"User '{uname}' changed their own password")
    return jsonify({"ok": True})


# ─── Entry point ─────────────────────────────────────────────────────────────

if __name__=="__main__":
    # Load any plugin files found alongside signalscope.py
    _load_plugins()

    ort=_try_import("onnxruntime")
    if ort is None:
        print("[!] onnxruntime not found — AI disabled.  pip install onnxruntime")
    else:
        print(f"[OK] onnxruntime {ort.__version__}")

    # Start now playing poller immediately so dropdown works before monitoring starts
    nowplaying_poller.start(monitor.app_cfg.nowplaying_country or "GB")
    print(f"[NowPlaying] Poller started (country={monitor.app_cfg.nowplaying_country or 'GB'})")

    # Start hub client immediately (independent of monitoring start)
    monitor.start_hub_client()

    cfg  = monitor.app_cfg
    mode = cfg.hub.mode

    if mode in ("hub", "both"):
        suffix = "/hub" if mode == "hub" else "  (hub at /hub)"
        label  = "HUB" if mode == "hub" else "CLIENT+HUB"
        print(f"[{BUILD}] {label} mode — http://0.0.0.0:5000{suffix}")
        _chains_stop = threading.Event()
        _chains_t = threading.Thread(target=hub_server._chains_monitor_loop,
                                     args=(_chains_stop,), daemon=True)
        _chains_t.start()
    else:
        print(f"[{BUILD}] CLIENT mode — http://0.0.0.0:5000")

    _bind_host = cfg.network.server_bind_host or "0.0.0.0"
    print(f"[{BUILD}] HTTPS/SSL is handled by nginx — app binds port 5000 on {_bind_host}")

    try:
        from waitress import serve
        print(f"[{BUILD}] Starting waitress WSGI server on {_bind_host}:5000 (threads=24)")
        serve(app,
              host=_bind_host,
              port=5000,
              threads=24,
              channel_timeout=120,
              asyncore_use_poll=True,
              ident=BUILD)
    except ImportError:
        print(f"[{BUILD}] waitress not found — using Flask dev server")
        print(f"[{BUILD}] Install for better performance:  pip install waitress")
        app.run(host=_bind_host, port=5000, debug=False, threaded=True)